```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Cat</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 50);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.5, 0);
controls.enableDamping = true;

// ── Lights ──
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(5, 10, 7);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x6688ff, 0.4);
rimLight.position.set(-3, 5, -5);
scene.add(rimLight);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(15, 64),
  new THREE.MeshStandardMaterial({ color: 0x2a2a4a, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Materials ──
const furMat = new THREE.MeshStandardMaterial({ color: 0xf4a460, roughness: 0.8 });
const darkFurMat = new THREE.MeshStandardMaterial({ color: 0x8b6914, roughness: 0.8 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0xff6b8a, roughness: 0.4 });
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x22cc88, roughness: 0.2, metalness: 0.3 });
const pupilMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.1 });
const whiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 });
const innerEarMat = new THREE.MeshStandardMaterial({ color: 0xffb6c1, roughness: 0.6 });

// ── Cat Group ──
const cat = new THREE.Group();

// Body
const body = new THREE.Mesh(new THREE.SphereGeometry(1, 32, 32), furMat);
body.scale.set(1, 0.85, 1.3);
body.position.set(0, 1.3, 0);
body.castShadow = true;
cat.add(body);

// Chest (lighter fur)
const chest = new THREE.Mesh(new THREE.SphereGeometry(0.55, 32, 32), whiteMat);
chest.position.set(0, 1.2, 0.7);
chest.scale.set(1.1, 1, 0.8);
cat.add(chest);

// Head
const head = new THREE.Mesh(new THREE.SphereGeometry(0.7, 32, 32), furMat);
head.position.set(0, 2.35, 0.85);
head.castShadow = true;
cat.add(head);

// Forehead stripes
for (let i = -1; i <= 1; i++) {
  const stripe = new THREE.Mesh(
    new THREE.BoxGeometry(0.06, 0.35, 0.05),
    darkFurMat
  );
  stripe.position.set(i * 0.15, 2.75, 1.48);
  stripe.rotation.x = -0.2;
  cat.add(stripe);
}

// Ears
function makeEar(x) {
  const ear = new THREE.Group();
  const outer = new THREE.Mesh(new THREE.ConeGeometry(0.22, 0.45, 4), furMat);
  outer.castShadow = true;
  const inner = new THREE.Mesh(new THREE.ConeGeometry(0.13, 0.3, 4), innerEarMat);
  inner.position.z = 0.03;
  ear.add(outer, inner);
  ear.position.set(x, 2.95, 0.85);
  ear.rotation.z = x > 0 ? -0.3 : 0.3;
  ear.rotation.x = -0.15;
  return ear;
}
cat.add(makeEar(-0.4), makeEar(0.4));

// Eyes
function makeEye(x) {
  const eyeGroup = new THREE.Group();
  const eyeWhite = new THREE.Mesh(new THREE.SphereGeometry(0.13, 16, 16), whiteMat);
  eyeWhite.scale.set(1.2, 1, 0.7);
  const eye = new THREE.Mesh(new THREE.SphereGeometry(0.1, 16, 16), eyeMat);
  eye.position.z = 0.05;
  const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.055, 16, 16), pupilMat);
  pupil.position.z = 0.1;
  const highlight = new THREE.Mesh(
    new THREE.SphereGeometry(0.025, 8, 8),
    new THREE.MeshBasicMaterial({ color: 0xffffff })
  );
  highlight.position.set(0.03, 0.03, 0.12);
  eyeGroup.add(eyeWhite, eye, pupil, highlight);
  eyeGroup.position.set(x, 2.4, 1.48);
  return eyeGroup;
}
cat.add(makeEye(-0.25), makeEye(0.25));

// Nose
const nose = new THREE.Mesh(new THREE.SphereGeometry(0.06, 16, 16), noseMat);
nose.position.set(0, 2.22, 1.52);
cat.add(nose);

// Mouth (tiny line)
const mouthGeo = new THREE.BufferGeometry().setFromPoints([
  new THREE.Vector3(-0.08, 2.17, 1.53),
  new THREE.Vector3(0, 2.19, 1.55),
  new THREE.Vector3(0.08, 2.17, 1.53),
]);
const mouth = new THREE.Line(mouthGeo, new THREE.LineBasicMaterial({ color: 0x8b4513 }));
cat.add(mouth);

// Whiskers
function makeWhisker(side) {
  const whiskers = new THREE.Group();
  for (let i = -1; i <= 1; i++) {
    const points = [
      new THREE.Vector3(0, i * 0.04, 0),
      new THREE.Vector3(side * 0.6, i * 0.06 + 0.02, 0.05),
    ];
    const geo = new THREE.BufferGeometry().setFromPoints(points);
    const line = new THREE.Line(geo, new THREE.LineBasicMaterial({ color: 0xdddddd }));
    whiskers.add(line);
  }
  whiskers.position.set(side * 0.2, 2.2, 1.5);
  return whiskers;
}
cat.add(makeWhisker(-1), makeWhisker(1));

// Legs
function makeLeg(x, z, scaleY) {
  const leg = new THREE.Mesh(new THREE.CylinderGeometry(0.14, 0.12, 0.8, 12), furMat);
  leg.position.set(x, 0.5, z);
  leg.scale.y = scaleY || 1;
  leg.castShadow = true;
  return leg;
}
cat.add(makeLeg(-0.45, 0.5, 1));
cat.add(makeLeg(0.45, 0.5, 1));
cat.add(makeLeg(-0.45, -0.4, 0.9));
cat.add(makeLeg(0.45, -0.4, 0.9));

// Paws
function makePaw(x, z) {
  const paw = new THREE.Mesh(new THREE.SphereGeometry(0.14, 12, 12), whiteMat);
  paw.position.set(x, 0.12, z);
  paw.scale.y = 0.5;
  return paw;
}
cat.add(makePaw(-0.45, 0.5), makePaw(0.45, 0.5));
cat.add(makePaw(-0.45, -0.4), makePaw(0.45, -0.4));

// Tail
const tailCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 1.0, -1.1),
  new THREE.Vector3(0, 1.5, -1.6),
  new THREE.Vector3(0.1, 2.2, -1.7),
  new THREE.Vector3(0.3, 2.7, -1.5),
  new THREE.Vector3(0.4, 3.0, -1.2),
]);
const tail = new THREE.Mesh(
  new THREE.TubeGeometry(tailCurve, 20, 0.1, 12, false),
  furMat
);
tail.castShadow = true;
cat.add(tail);

scene.add(cat);

// ── Floating particles (dust motes) ──
const particleCount = 60;
const particles = new THREE.Group();
for (let i = 0; i < particleCount; i++) {
  const p = new THREE.Mesh(
    new THREE.SphereGeometry(0.02, 6, 6),
    new THREE.MeshBasicMaterial({ color: 0xffeedd, transparent: true, opacity: 0.4 })
  );
  p.position.set(
    (Math.random() - 0.5) * 12,
    Math.random() * 6,
    (Math.random() - 0.5) * 12
  );
  particles.add(p);
}
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Breathing
  body.scale.y = 0.85 + Math.sin(t * 1.5) * 0.015;
  body.scale.x = 1 + Math.sin(t * 1.5) * 0.01;
  head.position.y = 2.35 + Math.sin(t * 1.5) * 0.02;

  // Ear twitch
  cat.children.forEach(child => {
    if (child.rotation && child.position.y > 2.8) {
      child.rotation.z += Math.sin(t * 3) * 0.001;
    }
  });

  // Tail wag
  tail.rotation.y = Math.sin(t * 2) * 0.15;

  // Subtle head tilt
  head.rotation.z = Math.sin(t * 0.8) * 0.03;

  // Particles float
  particles.children.forEach((p, i) => {
    p.position.y += Math.sin(t + i) * 0.001;
    p.position.x += Math.cos(t * 0.5 + i) * 0.0005;
  });

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's Inside

| Feature | Details |
|---|---|
| **Cat body** | Scaled sphere with chest patch |
| **Head** | Sphere with forehead stripes, ears (cone pairs), eyes (layered spheres with highlights), nose, mouth line, and whiskers |
| **Legs & paws** | Cylinders + flattened spheres |
| **Tail** | `TubeGeometry` along a CatmullRom spline |
| **Lighting** | Warm directional + cool rim + ambient |
| **Shadows** | PCF soft shadow map on the ground plane |
| **Animation** | Breathing scale, head bob, ear twitch, tail wag, floating dust particles |
| **Controls** | `OrbitControls` — drag to rotate, scroll to zoom |

Just save it as `index.html` and open in any modern browser — no build step needed.

Here's a complete, self-contained `index.html` that builds a simple procedural car using Three.js primitives. Just save it and open in a browser (a local server is recommended for ES modules, but it often works directly in modern browsers).

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Car</title>
  <style>
    body { margin: 0; overflow: hidden; background: #111; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="module">
    import * as THREE from 'https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js';

    // Scene & Camera
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87CEEB);
    scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

    const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 4);
    camera.lookAt(0, 0, 0);

    // Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // Lights
    scene.add(new THREE.AmbientLight(0xffffff, 0.6));
    const sun = new THREE.DirectionalLight(0xffffff, 1.2);
    sun.position.set(5, 10, 5);
    sun.castShadow = true;
    sun.shadow.mapSize.set(1024, 1024);
    scene.add(sun);

    // Ground
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(40, 40),
      new THREE.MeshStandardMaterial({ color: 0x33aa33 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // Car Group
    const car = new THREE.Group();

    // Chassis
    const chassis = new THREE.Mesh(
      new THREE.BoxGeometry(2, 0.4, 1),
      new THREE.MeshStandardMaterial({ color: 0xd63031 })
    );
    chassis.position.y = 0.5;
    chassis.castShadow = true;
    car.add(chassis);

    // Cabin
    const cabin = new THREE.Mesh(
      new THREE.BoxGeometry(1.2, 0.35, 0.85),
      new THREE.MeshStandardMaterial({ color: 0x2d3436, roughness: 0.2 })
    );
    cabin.position.set(-0.1, 0.9, 0);
    cabin.castShadow = true;
    car.add(cabin);

    // Wheels
    const wheelGeo = new THREE.CylinderGeometry(0.25, 0.25, 0.2, 16);
    const wheelMat = new THREE.MeshStandardMaterial({ color: 0x111111 });
    const wheelPos = [
      { x: 0.6, z: 0.55 }, { x: 0.6, z: -0.55 },
      { x: -0.6, z: 0.55 }, { x: -0.6, z: -0.55 }
    ];
    wheelPos.forEach(p => {
      const wheel = new THREE.Mesh(wheelGeo, wheelMat);
      wheel.rotation.x = Math.PI / 2;
      wheel.position.set(p.x, 0.25, p.z);
      wheel.castShadow = true;
      car.add(wheel);
    });

    scene.add(car);

    // Animation Loop
    function animate(time) {
      requestAnimationFrame(animate);
      car.rotation.y = time * 0.0005; // Gentle spin
      renderer.render(scene, camera);
    }
    animate(0);

    // Resize Handler
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

### Features:
- **Procedural Car**: Built from basic geometries (boxes for body/cabin, cylinders for wheels)
- **Lighting & Shadows**: Directional light with soft shadows + ambient fill
- **Responsive**: Automatically adjusts to window size
- **Animated**: Slowly rotates to showcase the model
- **Zero dependencies**: Only pulls Three.js from a reliable CDN

💡 *Tip: For the best experience, serve it via a simple local server (e.g., `npx serve .` or VS Code's Live Server) to avoid CORS restrictions with ES modules.*

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>3D Tree — Three.js</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
#info {
  position: absolute; top: 12px; left: 50%; transform: translateX(-50%);
  color: #fff; font-family: 'Segoe UI', sans-serif; font-size: 14px;
  background: rgba(0,0,0,0.55); padding: 8px 18px; border-radius: 20px;
  pointer-events: none; letter-spacing: 0.3px;
}
</style>
</head>
<body>
<div id="info">🌳 Drag to orbit · Scroll to zoom</div>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ───────────── Renderer ───────────── */
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ───────────── Scene & Camera ───────────── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.012);

const camera = new THREE.PerspectiveCamera(50, window.innerWidth / window.innerHeight, 0.1, 500);
camera.position.set(8, 6, 12);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 4, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 4;
controls.maxDistance = 40;
controls.update();

/* ───────────── Lighting ───────────── */
const ambientLight = new THREE.AmbientLight(0x8899aa, 0.6);
scene.add(ambientLight);

const hemiLight = new THREE.HemisphereLight(0xfff4e0, 0x446622, 0.8);
scene.add(hemiLight);

const sunLight = new THREE.DirectionalLight(0xfff5e0, 2.2);
sunLight.position.set(10, 20, 8);
sunLight.castShadow = true;
sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.near = 1;
sunLight.shadow.camera.far = 50;
sunLight.shadow.camera.left = -15;
sunLight.shadow.camera.right = 15;
sunLight.shadow.camera.top = 15;
sunLight.shadow.camera.bottom = -5;
sunLight.shadow.bias = -0.001;
scene.add(sunLight);

const fillLight = new THREE.DirectionalLight(0x88aacc, 0.4);
fillLight.position.set(-8, 10, -6);
scene.add(fillLight);

/* ───────────── Ground ───────────── */
const groundGeo = new THREE.CircleGeometry(60, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x4a8c3f,
  roughness: 0.95,
  metalness: 0.0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt patch around tree base
const dirtGeo = new THREE.CircleGeometry(2.5, 32);
const dirtMat = new THREE.MeshStandardMaterial({ color: 0x6b4e31, roughness: 1.0 });
const dirt = new THREE.Mesh(dirtGeo, dirtMat);
dirt.rotation.x = -Math.PI / 2;
dirt.position.y = 0.01;
dirt.receiveShadow = true;
scene.add(dirt);

// Grass blades (simple instanced cones)
const grassCount = 3000;
const grassGeo = new THREE.ConeGeometry(0.04, 0.35, 4);
const grassMat = new THREE.MeshStandardMaterial({ color: 0x5aa040, roughness: 1 });
const grassMesh = new THREE.InstancedMesh(grassGeo, grassMat, grassCount);
const dummy = new THREE.Object3D();
for (let i = 0; i < grassCount; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 2 + Math.random() * 25;
  dummy.position.set(Math.cos(angle) * radius, 0.17, Math.sin(angle) * radius);
  dummy.scale.set(0.8 + Math.random() * 0.8, 0.6 + Math.random() * 1.0, 0.8 + Math.random() * 0.8);
  dummy.rotation.y = Math.random() * Math.PI;
  dummy.updateMatrix();
  grassMesh.setMatrixAt(i, dummy.matrix);
}
grassMesh.receiveShadow = true;
grassMesh.castShadow = true;
scene.add(grassMesh);

/* ───────────── Tree Generation ───────────── */
const treeGroup = new THREE.Group();
scene.add(treeGroup);

// Materials
const trunkMat = new THREE.MeshStandardMaterial({
  color: 0x5c3a1e,
  roughness: 0.9,
  metalness: 0.0
});

const branchMat = new THREE.MeshStandardMaterial({
  color: 0x6b4423,
  roughness: 0.85,
  metalness: 0.0
});

const leafMats = [
  new THREE.MeshStandardMaterial({ color: 0x2d8a3e, roughness: 0.8 }),
  new THREE.MeshStandardMaterial({ color: 0x3da34a, roughness: 0.8 }),
  new THREE.MeshStandardMaterial({ color: 0x4db85a, roughness: 0.8 }),
  new THREE.MeshStandardMaterial({ color: 0x267a34, roughness: 0.8 }),
  new THREE.MeshStandardMaterial({ color: 0x5cc46a, roughness: 0.8 }),
];

// Shared geometries
const trunkGeo = new THREE.CylinderGeometry(0.12, 0.22, 1, 8);
const branchGeo = new THREE.CylinderGeometry(0.03, 0.08, 1, 6);
const leafGeo1 = new THREE.IcosahedronGeometry(1, 1);
const leafGeo2 = new THREE.IcosahedronGeometry(1, 0);
const leafGeo3 = new THREE.DodecahedronGeometry(1, 0);

const leafGeos = [leafGeo1, leafGeo2, leafGeo3];

function createBranch(parent, origin, direction, length, radius, depth, maxDepth) {
  if (depth > maxDepth || length < 0.15) return;

  const mat = depth <= 1 ? trunkMat : branchMat;
  const geo = depth <= 1 ? trunkGeo : branchGeo;

  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.copy(origin).add(direction.clone().multiplyScalar(length / 2));
  mesh.scale.set(radius * 3, length, radius * 3);

  // Orient the cylinder along the direction
  const up = new THREE.Vector3(0, 1, 0);
  const quat = new THREE.Quaternion().setFromUnitVectors(up, direction.clone().normalize());
  mesh.quaternion.copy(quat);

  mesh.castShadow = true;
  mesh.receiveShadow = true;
  parent.add(mesh);

  const endPos = origin.clone().add(direction.clone().multiplyScalar(length));

  if (depth >= maxDepth - 1) {
    // Add leaf clusters at tips
    addLeafCluster(parent, endPos, depth, maxDepth);
    return;
  }

  const numBranches = depth === 0 ? 3 : (depth === 1 ? 4 : 3);
  const newLength = length * (0.62 + Math.random() * 0.12);
  const newRadius = radius * 0.65;

  for (let i = 0; i < numBranches; i++) {
    const spread = depth === 0 ? 0.7 : (depth === 1 ? 0.85 : 0.95);
    const angle = (i / numBranches) * Math.PI * 2 + (Math.random() - 0.5) * 0.4;
    const tilt = spread * (0.3 + Math.random() * 0.35);

    const newDir = direction.clone();
    const axis = new THREE.Vector3(
      Math.random() - 0.5,
      Math.random() - 0.5,
      Math.random() - 0.5
    ).normalize();

    // Rotate upward and outward
    const perpAxis = new THREE.Vector3().crossVectors(direction, axis).normalize();
    if (perpAxis.length() < 0.01) {
      perpAxis.set(1, 0, 0);
    }
    newDir.applyAxisAngle(perpAxis, tilt);
    newDir.applyAxisAngle(direction, angle);
    newDir.normalize();

    createBranch(parent, endPos, newDir, newLength, newRadius, depth + 1, maxDepth);
  }
}

function addLeafCluster(parent, position, depth, maxDepth) {
  const clusterCount = 4 + Math.floor(Math.random() * 5);

  for (let i = 0; i < clusterCount; i++) {
    const geo = leafGeos[Math.floor(Math.random() * leafGeos.length)];
    const mat = leafMats[Math.floor(Math.random() * leafMats.length)].clone();

    const scale = 0.4 + Math.random() * 0.7;
    const mesh = new THREE.Mesh(geo, mat);

    const offset = new THREE.Vector3(
      (Math.random() - 0.5) * 1.2,
      Math.random() * 0.8,
      (Math.random() - 0.5) * 1.2
    );

    mesh.position.copy(position).add(offset);
    mesh.scale.setScalar(scale);
    mesh.rotation.set(
      Math.random() * Math.PI,
      Math.random() * Math.PI,
      Math.random() * Math.PI
    );

    mesh.castShadow = true;
    mesh.receiveShadow = true;
    parent.add(mesh);
  }
}

// Build the tree
const trunkDir = new THREE.Vector3(0, 1, 0);
createBranch(treeGroup, new THREE.Vector3(0, 0, 0), trunkDir, 2.2, 0.22, 0, 5);

// Add some extra leaf blobs in the canopy for fullness
for (let i = 0; i < 30; i++) {
  const geo = leafGeos[Math.floor(Math.random() * leafGeos.length)];
  const mat = leafMats[Math.floor(Math.random() * leafMats.length)].clone();
  const mesh = new THREE.Mesh(geo, mat);

  const angle = Math.random() * Math.PI * 2;
  const r = Math.random() * 2.5;
  const h = 3.5 + Math.random() * 3;

  mesh.position.set(
    Math.cos(angle) * r,
    h,
    Math.sin(angle) * r
  );

  const scale = 0.6 + Math.random() * 1.0;
  mesh.scale.setScalar(scale);
  mesh.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, 0);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  treeGroup.add(mesh);
}

/* ───────────── Small Flowers on Ground ───────────── */
const flowerColors = [0xff6b8a, 0xffd166, 0xff85a1, 0xa8dadc, 0xf4a261];
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 3 + Math.random() * 15;
  const x = Math.cos(angle) * radius;
  const z = Math.sin(angle) * radius;

  // Stem
  const stemGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.3, 4);
  const stemMat = new THREE.MeshStandardMaterial({ color: 0x3a7a2a });
  const stem = new THREE.Mesh(stemGeo, stemMat);
  stem.position.set(x, 0.15, z);
  stem.castShadow = true;
  scene.add(stem);

  // Flower head
  const headGeo = new THREE.SphereGeometry(0.06, 6, 6);
  const headMat = new THREE.MeshStandardMaterial({
    color: flowerColors[Math.floor(Math.random() * flowerColors.length)],
    roughness: 0.5
  });
  const head = new THREE.Mesh(headGeo, headMat);
  head.position.set(x, 0.35, z);
  head.castShadow = true;
  scene.add(head);
}

/* ───────────── Animation ───────────── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle wind sway
  treeGroup.children.forEach((child, i) => {
    if (child.isMesh && child.geometry.type !== 'CylinderGeometry') {
      const y = child.position.y;
      const swayAmount = y * 0.003;
      child.rotation.z = Math.sin(t * 1.2 + i * 0.5) * swayAmount;
      child.rotation.x = Math.cos(t * 0.9 + i * 0.3) * swayAmount * 0.7;
    }
  });

  // Sway trunk slightly
  treeGroup.rotation.z = Math.sin(t * 0.8) * 0.008;
  treeGroup.rotation.x = Math.cos(t * 0.6) * 0.005;

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ───────────── Resize ───────────── */
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
</body>
</html>
```

