const pageMat  = new THREE.MeshStandardMaterial({ color: 0xFFF8F0, roughness: 0.9 });
const spineMat = new THREE.MeshStandardMaterial({ color: 0x6B0000, roughness: 0.5 });
const goldMat  = new THREE.MeshStandardMaterial({ color: 0xDAA520, roughness: 0.3, metalness: 0.7 });

// Dimensions
