// Front cover
const front = new THREE.Mesh(new THREE.BoxGeometry(w, h, 0.05), coverMat);
front.position.z = d / 2;
front.castShadow = true;
book.add(front);

// Back cover
const back = new THREE.Mesh(new THREE.BoxGeometry(w, h, 0.05), coverMat);
back.position.z = -d / 2;
back.castShadow = true;
book.add(back);

// Pages block
const pages = new THREE.Mesh(new THREE.BoxGeometry(w - 0.1, h - 0.1, d - 0.06), pageMat);
pages.castShadow = true;
book.add(pages);

// Spine
const spine = new THREE.Mesh(new THREE.BoxGeometry(0.05, h, d), spineMat);
spine.position.x = -w / 2;
spine.castShadow = true;
book.add(spine);

// Gold title band on cover
