    const baseBottom = new THREE.Mesh(new THREE.CylinderGeometry(0.6, 0.65, 0.06, 48), baseMat);
    baseBottom.position.y = 0.03;
    baseBottom.castShadow = true;
    baseBottom.receiveShadow = true;
    lamp.add(baseBottom);

    // Base – top disc
    const baseTop = new THREE.Mesh(new THREE.CylinderGeometry(0.5, 0.55, 0.05, 48), baseMat);
    baseTop.position.y = 0.08;
    baseTop.castShadow = true;
