      const t = clock.getElapsedTime();

      // Gentle light flicker
      lampLight.intensity = 15 + Math.sin(t * 3.2) * 0.3 + Math.sin(t * 7.1) * 0.15;
      bulbMat.emissiveIntensity = 2.0 + Math.sin(t * 3.2) * 0.1;
