      // Subtle chain sway
      chain.rotation.z = Math.sin(t * 1.5) * 0.08;
      chainBall.position.x = 0.35 + Math.sin(t * 1.5) * 0.015;

      controls.update();
      renderer.render(scene, camera);
    }

