    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    dirLight.shadow.camera.near = 0.5;
    dirLight.shadow.camera.far = 20;
    dirLight.shadow.camera.left = -5;
    dirLight.shadow.camera.right = 5;
    dirLight.shadow.camera.top = 5;
    dirLight.shadow.camera.bottom = -5;
    dirLight.shadow.bias = -0.001;
    scene.add(dirLight);

    const fillLight = new THREE.DirectionalLight(0x4466aa, 0.4);
    fillLight.position.set(-4, 3, -3);
    scene.add(fillLight);

    // ── Materials ──────────────────────────────────────────
    const woodMat = new THREE.MeshStandardMaterial({
      color: 0x8B5E3C,
      roughness: 0.7,
      metalness: 0.0,
    });

    const darkWoodMat = new THREE.MeshStandardMaterial({
      color: 0x5C3A1E,
      roughness: 0.75,
      metalness: 0.0,
    });

    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x22223a,
      roughness: 0.9,
      metalness: 0.0,
    });

    // ── Table ──────────────────────────────────────────────
    const table = new THREE.Group();

    // Tabletop
    const topGeo = new THREE.BoxGeometry(2.4, 0.08, 1.4);
    const tabletop = new THREE.Mesh(topGeo, woodMat);
    tabletop.position.y = 1.6;
    tabletop.castShadow = true;
    tabletop.receiveShadow = true;
    table.add(tabletop);

    // Table edge trim
    const trimGeo = new THREE.BoxGeometry(2.5, 0.04, 1.5);
    const trim = new THREE.Mesh(trimGeo, darkWoodMat);
    trim.position.y = 1.54;
    trim.castShadow = true;
    table.add(trim);

    // Legs
    const legGeo = new THREE.BoxGeometry(0.08, 1.5, 0.08);
    const legPositions = [
      [-1.05, 0.75, -0.55],
      [ 1.05, 0.75, -0.55],
      [-1.05, 0.75,  0.55],
      [ 1.05, 0.75,  0.55],
    ];

    legPositions.forEach(pos => {
      const leg = new THREE.Mesh(legGeo, darkWoodMat);
      leg.position.set(...pos);
      leg.castShadow = true;
      leg.receiveShadow = true;
      table.add(leg);
    });

    // Cross supports
    const supportGeoX = new THREE.BoxGeometry(2.1, 0.06, 0.06);
    const supportGeoZ = new THREE.BoxGeometry(0.06, 0.06, 1.1);

    const support1 = new THREE.Mesh(supportGeoX, darkWoodMat);
    support1.position.set(0, 0.6, -0.55);
    support1.castShadow = true;
    table.add(support1);

    const support2 = new THREE.Mesh(supportGeoX, darkWoodMat);
    support2.position.set(0, 0.6, 0.55);
    support2.castShadow = true;
    table.add(support2);

    const support3 = new THREE.Mesh(supportGeoZ, darkWoodMat);
    support3.position.set(-1.05, 0.6, 0);
    support3.castShadow = true;
    table.add(support3);

    const support4 = new THREE.Mesh(supportGeoZ, darkWoodMat);
    support4.position.set(1.05, 0.6, 0);
    support4.castShadow = true;
    table.add(support4);

    scene.add(table);

    // ── Ground ─────────────────────────────────────────────
    const groundGeo = new THREE.PlaneGeometry(30, 30);
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Grid helper (subtle) ───────────────────────────────
    const grid = new THREE.GridHelper(20, 40, 0x333355, 0x222244);
    grid.position.y = 0.005;
    scene.add(grid);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Gentle floating rotation
      table.rotation.y = Math.sin(elapsed * 0.3) * 0.15;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's included

| Feature | Detail |
|---|---|
| **Tabletop** | `BoxGeometry` with warm wood material |
| **4 legs** | Dark wood, positioned at each corner |
| **Cross supports** | Horizontal and vertical braces under the top |
| **Shadow map** | `PCFSoftShadowMap` from a directional light |
| **OrbitControls** | Click-drag to rotate, scroll to zoom |
| **Gentle animation** | Slow sinusoidal sway so it feels alive |
| **Responsive** | Handles window resize automatically |

