- **No external assets needed**: Uses procedural geometry and materials
- **Modern Three.js**: Uses ES modules with `importmap` (supported in all modern browsers)
- **Realistic lighting**: Directional light simulates the sun, ambient light prevents pure black shadows
- **Responsive**: Automatically adapts to window size and high-DPI screens
- To run: Simply open the file in a browser, or use a local server (e.g., `npx serve` or VS Code's Live Server) for best compatibility with ES modules.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Mountain</title>
  <style>
    * { margin: 0; padding: 0; }
    body { overflow: hidden; background: #000; }
  </style>
</head>
<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
        "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // --- Scene setup ---
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87ceeb);
    scene.fog = new THREE.Fog(0x87ceeb, 60, 120);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
    camera.position.set(0, 25, 50);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    renderer.shadowMap.enabled = true;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 5, 0);
    controls.enableDamping = true;

    // --- Simple value noise ---
    function hash(x, z) {
      let h = x * 374761393 + z * 668265263;
      h = (h ^ (h >> 13)) * 1274126177;
      return ((h ^ (h >> 16)) & 0x7fffffff) / 0x7fffffff;
    }

    function noise(x, z) {
      const ix = Math.floor(x), iz = Math.floor(z);
      const fx = x - ix, fz = z - iz;
      const sx = fx * fx * (3 - 2 * fx), sz = fz * fz * (3 - 2 * fz);
      return (
        hash(ix, iz) * (1 - sx) * (1 - sz) +
        hash(ix + 1, iz) * sx * (1 - sz) +
        hash(ix, iz + 1) * (1 - sx) * sz +
        hash(ix + 1, iz + 1) * sx * sz
      );
    }

    function fbm(x, z, octaves = 6) {
      let value = 0, amplitude = 0.5, frequency = 1;
      for (let i = 0; i < octaves; i++) {
        value += amplitude * noise(x * frequency, z * frequency);
        amplitude *= 0.5;
        frequency *= 2;
      }
      return value;
    }

    // --- Mountain geometry ---
    const size = 80, segments = 128;
    const geometry = new THREE.PlaneGeometry(size, size, segments, segments);
    geometry.rotateX(-Math.PI / 2);

    const positions = geometry.attributes.position;
    const colors = new Float32Array(positions.count * 3);
    const waterLevel = 0;

    for (let i = 0; i < positions.count; i++) {
      const x = positions.getX(i), z = positions.getZ(i);

      // Height from layered noise, falloff to edges
      const dist = Math.sqrt(x * x + z * z) / (size * 0.5);
      const falloff = Math.max(0, 1 - dist * dist);
      let height = fbm(x * 0.06, z * 0.06, 6) * 28 * falloff;
      height -= waterLevel;

      positions.setY(i, Math.max(height, waterLevel));

      // Vertex colors: snow caps → rock → grass → water
      const c = new THREE.Color();
      if (height < waterLevel + 0.5) {
        c.setHex(0x2a6e9e);        // water
      } else if (height < 4) {
        c.setHex(0x4a8c3f);        // grass
      } else if (height < 14) {
        c.lerpColors(new THREE.Color(0x4a8c3f), new THREE.Color(0x8b7355), (height - 4) / 10);
      } else if (height < 22) {
        c.lerpColors(new THREE.Color(0x8b7355), new THREE.Color(0x6b6b6b), (height - 14) / 8);
      } else {
        c.lerpColors(new THREE.Color(0x6b6b6b), new THREE.Color(0xffffff), (height - 22) / 6);
      }
      colors[i * 3] = c.r;
      colors[i * 3 + 1] = c.g;
      colors[i * 3 + 2] = c.b;
    }

    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    geometry.computeVertexNormals();

    const mountain = new THREE.Mesh(geometry, new THREE.MeshStandardMaterial({
      vertexColors: true,
      flatShading: true,
      roughness: 0.85,
      metalness: 0.1,
    }));
    mountain.castShadow = true;
    mountain.receiveShadow = true;
    scene.add(mountain);

    // --- Water plane ---
    const water = new THREE.Mesh(
      new THREE.PlaneGeometry(200, 200),
      new THREE.MeshStandardMaterial({ color: 0x2a6e9e, transparent: true, opacity: 0.6, roughness: 0.2 })
    );
    water.rotation.x = -Math.PI / 2;
    water.position.y = waterLevel;
    water.receiveShadow = true;
    scene.add(water);

    // --- Lighting ---
    scene.add(new THREE.AmbientLight(0x6688aa, 0.8));

    const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
    sun.position.set(30, 40, 20);
    sun.castShadow = true;
    sun.shadow.mapSize.set(2048, 2048);
    sun.shadow.camera.left = -50;
    sun.shadow.camera.right = 50;
    sun.shadow.camera.top = 50;
    sun.shadow.camera.bottom = -50;
    scene.add(sun);

    // --- Animate ---
    function animate() {
      requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // --- Resize ---
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

**What this gives you:**

- **Procedural mountain** — heightmap generated via fractal Brownian motion (layered value noise) with radial falloff so peaks rise from the center
- **Vertex-colored terrain** — automatic biome coloring: water → grass → dirt → rock → snow caps
- **Water plane** — a semi-transparent blue plane at sea level
- **Shadows & fog** — directional sunlight casts shadows; sky-blue fog fades distant geometry
- **Orbit controls** — click-drag to rotate, scroll to zoom, right-drag to pan

Just save it as `index.html` and open in any browser — no build step needed.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Leaf</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #1a1a2e; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
        "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    /* ── Scene, Camera, Renderer ── */
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.06);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 1, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    /* ── Lighting ── */
    const ambientLight = new THREE.AmbientLight(0x406040, 0.8);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    dirLight.position.set(5, 8, 4);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    scene.add(dirLight);

    const rimLight = new THREE.DirectionalLight(0x88ccff, 1.0);
    rimLight.position.set(-4, 2, -3);
    scene.add(rimLight);

    const pointLight = new THREE.PointLight(0x44ff88, 0.6, 15);
    pointLight.position.set(0, 3, 2);
    scene.add(pointLight);

    /* ── Leaf Shape ── */
    function createLeafShape() {
      const shape = new THREE.Shape();

      // Start at base (bottom center)
      shape.moveTo(0, -1.8);

      // Right edge — wavy curve up to tip
      shape.bezierCurveTo(0.6, -1.4, 1.4, -0.4, 1.1, 0.6);
      shape.bezierCurveTo(0.9, 1.0, 0.5, 1.6, 0, 2.2);

      // Left edge — wavy curve back to base
      shape.bezierCurveTo(-0.5, 1.6, -0.9, 1.0, -1.1, 0.6);
      shape.bezierCurveTo(-1.4, -0.4, -0.6, -1.4, 0, -1.8);

      return shape;
    }

    /* ── Extrude leaf ── */
    const leafShape = createLeafShape();
    const extrudeSettings = {
      depth: 0.05,
      bevelEnabled: true,
      bevelThickness: 0.02,
      bevelSize: 0.02,
      bevelSegments: 3,
      curveSegments: 32,
    };

    const leafGeo = new THREE.ExtrudeGeometry(leafShape, extrudeSettings);
    leafGeo.center();

    // Slightly curve the leaf by displacing vertices
    const pos = leafGeo.attributes.position;
    for (let i = 0; i < pos.count; i++) {
      const x = pos.getX(i);
      const y = pos.getY(i);
      // Gentle downward curl
      pos.setZ(i, pos.getZ(i) - Math.abs(x) * 0.15 + y * 0.05);
    }
    pos.needsUpdate = true;
    leafGeo.computeVertexNormals();

    /* ── Leaf material ── */
    const leafMat = new THREE.MeshStandardMaterial({
      color: 0x2d8a4e,
      roughness: 0.6,
      metalness: 0.05,
      side: THREE.DoubleSide,
      flatShading: false,
    });

    // Secondary darker green for underside (we'll use a second mesh)
    const leafBackMat = new THREE.MeshStandardMaterial({
      color: 0x1e6b3a,
      roughness: 0.7,
      metalness: 0.05,
      side: THREE.BackSide,
    });

    const leafMesh = new THREE.Mesh(leafGeo, leafMat);
    leafMesh.castShadow = true;
    leafMesh.receiveShadow = true;

    const leafBackMesh = new THREE.Mesh(leafGeo, leafBackMat);
    leafBackMesh.scale.setScalar(0.999); // Slightly smaller to avoid z-fighting

    const leafGroup = new THREE.Group();
    leafGroup.add(leafMesh);
    leafGroup.add(leafBackMesh);

    /* ── Stem ── */
    const stemCurve = new THREE.CatmullRomCurve3([
      new THREE.Vector3(0, -1.8, 0),
      new THREE.Vector3(0, -2.2, 0.05),
      new THREE.Vector3(0, -2.6, 0.1),
      new THREE.Vector3(0.02, -3.0, 0.15),
    ]);

    const stemGeo = new THREE.TubeGeometry(stemCurve, 12, 0.04, 8, false);
    const stemMat = new THREE.MeshStandardMaterial({
      color: 0x3a7a3a,
      roughness: 0.8,
    });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.castShadow = true;

    /* ── Veins ── */
    function createVein(points, radius = 0.015) {
      const curve = new THREE.CatmullRomCurve3(points);
      const geo = new THREE.TubeGeometry(curve, 16, radius, 5, false);
      const mat = new THREE.MeshStandardMaterial({
        color: 0x1a5c30,
        roughness: 0.9,
        emissive: 0x0a2a15,
        emissiveIntensity: 0.1,
      });
      return new THREE.Mesh(geo, mat);
    }

    // Main central vein
    const centralVein = createVein([
      new THREE.Vector3(0, -1.7, 0.06),
      new THREE.Vector3(0, -0.5, 0.06),
      new THREE.Vector3(0, 0.7, 0.06),
      new THREE.Vector3(0, 1.5, 0.06),
      new THREE.Vector3(0, 2.0, 0.06),
    ], 0.02);

    // Side veins — right
    const veinsRight = [
      [new THREE.Vector3(0, -0.8, 0.06), new THREE.Vector3(0.5, -0.6, 0.06), new THREE.Vector3(0.85, 0.0, 0.06)],
      [new THREE.Vector3(0, 0.0, 0.06), new THREE.Vector3(0.55, 0.2, 0.06), new THREE.Vector3(0.8, 0.7, 0.06)],
      [new THREE.Vector3(0, 0.7, 0.06), new THREE.Vector3(0.4, 0.85, 0.06), new THREE.Vector3(0.55, 1.2, 0.06)],
      [new THREE.Vector3(0, 1.3, 0.06), new THREE.Vector3(0.25, 1.4, 0.06), new THREE.Vector3(0.35, 1.65, 0.06)],
    ];

    // Side veins — left
    const veinsLeft = [
      [new THREE.Vector3(0, -0.8, 0.06), new THREE.Vector3(-0.5, -0.6, 0.06), new THREE.Vector3(-0.85, 0.0, 0.06)],
      [new THREE.Vector3(0, 0.0, 0.06), new THREE.Vector3(-0.55, 0.2, 0.06), new THREE.Vector3(-0.8, 0.7, 0.06)],
      [new THREE.Vector3(0, 0.7, 0.06), new THREE.Vector3(-0.4, 0.85, 0.06), new THREE.Vector3(-0.55, 1.2, 0.06)],
      [new THREE.Vector3(0, 1.3, 0.06), new THREE.Vector3(-0.25, 1.4, 0.06), new THREE.Vector3(-0.35, 1.65, 0.06)],
    ];

    const allVeins = [...veinsRight, ...veinsLeft];
    allVeins.forEach(pts => leafGroup.add(createVein(pts)));
    leafGroup.add(centralVein);

    leafGroup.add(stem);

    /* ── Position & tilt ── */
    leafGroup.rotation.z = -0.15;
    leafGroup.rotation.x = 0.1;
    scene.add(leafGroup);

    /* ── Subtle floating particles ── */
    const particleCount = 60;
    const particleGeo = new THREE.BufferGeometry();
    const particlePositions = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      particlePositions[i * 3]     = (Math.random() - 0.5) * 12;
      particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 12;
      particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 12;
    }
    particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
    const particleMat = new THREE.PointsMaterial({
      color: 0x88ffaa,
      size: 0.03,
      transparent: true,
      opacity: 0.5,
      sizeAttenuation: true,
    });
    const particles = new THREE.Points(particleGeo, particleMat);
    scene.add(particles);

    /* ── Animation ── */
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle sway
      leafGroup.rotation.y = Math.sin(t * 0.5) * 0.15;
      leafGroup.rotation.x = 0.1 + Math.sin(t * 0.3) * 0.05;
      leafGroup.position.y = Math.sin(t * 0.7) * 0.08;

      // Particles drift
      particles.rotation.y = t * 0.02;
      particles.rotation.x = t * 0.01;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    /* ── Resize ── */
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What this creates

| Feature | Details |
|---|---|
| **Leaf shape** | Defined with `THREE.Shape` + cubic Bézier curves for organic wavy edges, then `ExtrudeGeometry` for subtle 3D thickness with bevel |
| **Vertex curl** | Z-coordinates are displaced based on X/Y to give a gentle natural curl |
| **Double-sided** | Two meshes — a brighter green front face and a darker green back face |
| **Stem** | A `TubeGeometry` along a CatmullRom curve extending downward |
| **Veins** | A central vein + 4 pairs of side veins using thin `TubeGeometry` tubes |
| **Lighting** | Ambient + directional (warm key light) + blue rim light + green point light for atmosphere |
| **Animation** | Gentle sinusoidal sway on rotation/position, plus floating particles |
| **Controls** | `OrbitControls` with damping — drag to rotate, scroll to zoom |

Just save it as `index.html` and open in any modern browser — no build step needed.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Pencil</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
