<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 18);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0, 0);

// Lights
const ambient = new THREE.AmbientLight(0xffffff, 0.4);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xfff4e0, 2.5);
key.position.set(5, 8, 5);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
scene.add(key);

const fill = new THREE.DirectionalLight(0xc0d0ff, 0.8);
fill.position.set(-4, 3, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffc080, 0.6);
rim.position.set(-2, -1, -5);
scene.add(rim);

// Pencil group
const pencil = new THREE.Group();
const BODY_LEN = 4, BODY_R = 0.22, TIP_LEN = 0.9;

// Materials
const woodMat = new THREE.MeshStandardMaterial({ color: 0xf5c542, roughness: 0.6, metalness: 0.0 });
const graphiteMat = new THREE.MeshStandardMaterial({ color: 0x2a2a2a, roughness: 0.8 });
const ferruleMat = new THREE.MeshStandardMaterial({ color: 0xc0c0c0, roughness: 0.2, metalness: 0.9 });
const eraserMat = new THREE.MeshStandardMaterial({ color: 0xe8a0b4, roughness: 0.7 });
const labelMat = new THREE.MeshStandardMaterial({ color: 0x1a3a6a, roughness: 0.5 });

// Hexagonal body
const bodyGeo = new THREE.CylinderGeometry(BODY_R, BODY_R, BODY_LEN, 6);
const body = new THREE.Mesh(bodyGeo, woodMat);
body.castShadow = true;
body.position.y = 0;
pencil.add(body);

// Color bands on body
for (let i = 0; i < 6; i++) {
  const bandGeo = new THREE.CylinderGeometry(BODY_R + 0.001, BODY_R + 0.001, 0.04, 6);
  const band = new THREE.Mesh(bandGeo, labelMat);
  band.position.y = -BODY_LEN / 2 + 0.5 + i * 0.6;
  pencil.add(band);
}

// Wood tip (cone)
const woodTipGeo = new THREE.ConeGeometry(BODY_R, TIP_LEN, 6);
const woodTip = new THREE.Mesh(woodTipGeo, woodMat);
woodTip.position.y = BODY_LEN / 2 + TIP_LEN / 2;
woodTip.castShadow = true;
pencil.add(woodTip);

// Graphite tip
const graphiteGeo = new THREE.ConeGeometry(0.05, TIP_LEN * 0.5, 6);
const graphite = new THREE.Mesh(graphiteGeo, graphiteMat);
graphite.position.y = BODY_LEN / 2 + TIP_LEN * 0.75;
graphite.castShadow = true;
pencil.add(graphite);

// Ferrule
const ferruleGeo = new THREE.CylinderGeometry(BODY_R + 0.01, BODY_R + 0.01, 0.25, 6);
const ferrule = new THREE.Mesh(ferruleGeo, ferruleMat);
ferrule.position.y = -BODY_LEN / 2 - 0.125;
ferrule.castShadow = true;
pencil.add(ferrule);

// Ferrule ridges
for (let i = 0; i < 3; i++) {
  const ridgeGeo = new THREE.CylinderGeometry(BODY_R + 0.02, BODY_R + 0.02, 0.015, 6);
  const ridge = new THREE.Mesh(ridgeGeo, ferruleMat);
  ridge.position.y = -BODY_LEN / 2 - 0.05 + i * 0.08;
  pencil.add(ridge);
}

// Eraser
const eraserGeo = new THREE.CylinderGeometry(BODY_R - 0.01, BODY_R - 0.01, 0.35, 6);
const eraser = new THREE.Mesh(eraserGeo, eraserMat);
eraser.position.y = -BODY_LEN / 2 - 0.25 - 0.175;
eraser.castShadow = true;
pencil.add(eraser);

// Eraser dome
const domeGeo = new THREE.SphereGeometry(BODY_R - 0.01, 6, 4, 0, Math.PI * 2, 0, Math.PI / 2);
const dome = new THREE.Mesh(domeGeo, eraserMat);
dome.position.y = -BODY_LEN / 2 - 0.25 - 0.35;
pencil.add(dome);

// Tilt the pencil nicely
pencil.rotation.z = Math.PI / 6;
pencil.rotation.x = Math.PI / 12;
scene.add(pencil);

// Ground plane
const groundGeo = new THREE.CircleGeometry(6, 48);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x16213e, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.8;
ground.receiveShadow = true;
scene.add(ground);

// Subtle ring on ground
const ringGeo = new THREE.RingGeometry(1.8, 1.85, 48);
const ringMat = new THREE.MeshBasicMaterial({ color: 0x0f3460, side: THREE.DoubleSide });
const ring = new THREE.Mesh(ringGeo, ringMat);
ring.rotation.x = -Math.PI / 2;
ring.position.y = -2.79;
scene.add(ring);

// Animation
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  pencil.rotation.y = Math.sin(t * 0.5) * 0.3;
  pencil.position.y = Math.sin(t * 0.8) * 0.15;
  controls.update();
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
