```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>🍕 Three.js Pizza</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #1a1a2e; }
    canvas { display: block; }
    #info {
      position: absolute;
      top: 16px;
      width: 100%;
      text-align: center;
      color: #fff;
      font-family: system-ui, sans-serif;
      font-size: 1.2rem;
      pointer-events: none;
      text-shadow: 0 2px 8px rgba(0,0,0,.6);
    }
  </style>
</head>
<body>
  <div id="info">🍕 Pizza — drag to orbit · scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from "three";
    import { OrbitControls } from "three/addons/controls/OrbitControls.js";

    /* ── scene, camera, renderer ── */
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.Fog(0x1a1a2e, 8, 18);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 5, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.1;
    document.body.appendChild(renderer.domElement);

    /* ── controls ── */
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.maxPolarAngle = Math.PI / 2.1;
    controls.minDistance = 3;
    controls.maxDistance = 14;

    /* ── lights ── */
    const ambient = new THREE.AmbientLight(0xffeedd, 0.5);
    scene.add(ambient);

    const dir = new THREE.DirectionalLight(0xffffff, 1.8);
    dir.position.set(4, 8, 4);
    dir.castShadow = true;
    dir.shadow.mapSize.set(1024, 1024);
    dir.shadow.camera.near = 1;
    dir.shadow.camera.far = 20;
    dir.shadow.camera.left = -5;
    dir.shadow.camera.right = 5;
    dir.shadow.camera.top = 5;
    dir.shadow.camera.bottom = -5;
    scene.add(dir);

    const rim = new THREE.PointLight(0xff6633, 1.2, 12);
    rim.position.set(-3, 3, -3);
    scene.add(rim);

    /* ── helpers ── */
    function mat(color, roughness = 0.8, metalness = 0.0) {
      return new THREE.MeshStandardMaterial({ color, roughness, metalness });
    }

    function placePepperonis(group, count = 8) {
      const geo = new THREE.CylinderGeometry(0.18, 0.18, 0.04, 16);
      const pepperoniMat = mat(0xcc2200, 0.6);
      for (let i = 0; i < count; i++) {
        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.5;
        const radius = 0.3 + Math.random() * 0.8;
        const p = new THREE.Mesh(geo, pepperoniMat);
        p.position.set(Math.cos(angle) * radius, 0.16, Math.sin(angle) * radius);
        p.rotation.x = Math.PI / 2;
        p.rotation.z = Math.random() * 0.3;
        p.castShadow = true;
        group.add(p);
      }
    }

    function placeCheeseDroplets(group, count = 12) {
      const geo = new THREE.SphereGeometry(0.06, 8, 8);
      const cheeseMat = mat(0xffdd44, 0.5);
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = 0.2 + Math.random() * 0.9;
        const q = new THREE.Mesh(geo, cheeseMat);
        q.position.set(Math.cos(angle) * radius, 0.15 + Math.random() * 0.04, Math.sin(angle) * radius);
        q.scale.set(1, 0.5 + Math.random() * 0.3, 1);
        group.add(q);
      }
    }

    function placeBasil(group, count = 5) {
      const geo = new THREE.SphereGeometry(0.07, 6, 4);
      geo.scale(1, 0.15, 0.7);
      const basilMat = mat(0x338833, 0.7);
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = 0.3 + Math.random() * 0.7;
        const b = new THREE.Mesh(geo, basilMat);
        b.position.set(Math.cos(angle) * radius, 0.17, Math.sin(angle) * radius);
        b.rotation.set(Math.random(), Math.random(), Math.random());
        group.add(b);
      }
    }

    /* ── build pizza ── */
    const pizza = new THREE.Group();

    // Outer crust (torus ring)
    const crustRing = new THREE.Mesh(
      new THREE.TorusGeometry(1.15, 0.18, 12, 32),
      mat(0xd4a030, 0.9)
    );
    crustRing.rotation.x = Math.PI / 2;
    crustRing.position.y = 0.08;
    crustRing.castShadow = true;
    pizza.add(crustRing);

    // Crust top cap (donut top)
    const crustTop = new THREE.Mesh(
      new THREE.RingGeometry(0.97, 1.33, 32),
      mat(0xc8962c, 0.85)
    );
    crustTop.rotation.x = -Math.PI / 2;
    crustTop.position.y = 0.18;
    crustTop.receiveShadow = true;
    pizza.add(crustTop);

    // Crust bottom
    const crustBottom = new THREE.Mesh(
      new THREE.RingGeometry(0.97, 1.33, 32),
      mat(0x8b6914, 0.95)
    );
    crustBottom.rotation.x = Math.PI / 2;
    crustBottom.position.y = 0.02;
    crustBottom.receiveShadow = true;
    pizza.add(crustBottom);

    // Sauce layer
    const sauce = new THREE.Mesh(
      new THREE.CircleGeometry(1.0, 32),
      mat(0xcc3311, 0.75)
    );
    sauce.rotation.x = -Math.PI / 2;
    sauce.position.y = 0.155;
    sauce.receiveShadow = true;
    pizza.add(sauce);

    // Cheese layer (slightly smaller, melted look)
    const cheese = new THREE.Mesh(
      new THREE.CircleGeometry(0.95, 32),
      mat(0xffcc33, 0.55)
    );
    cheese.rotation.x = -Math.PI / 2;
    cheese.position.y = 0.16;
    cheese.receiveShadow = true;
    pizza.add(cheese);

    // Toppings
    placePepperonis(pizza, 9);
    placeCheeseDroplets(pizza, 14);
    placeBasil(pizza, 5);

    // Slight uneven crust bumps
    for (let i = 0; i < 6; i++) {
      const bump = new THREE.Mesh(
        new THREE.SphereGeometry(0.08 + Math.random() * 0.06, 8, 6),
        mat(0xc8962c, 0.85)
      );
      const a = (i / 6) * Math.PI * 2;
      bump.position.set(Math.cos(a) * 1.15, 0.12 + Math.random() * 0.06, Math.sin(a) * 1.15);
      bump.scale.y = 0.6;
      pizza.add(bump);
    }

    // Tilt the pizza slightly for a nice angle
    pizza.rotation.x = -0.15;
    scene.add(pizza);

    /* ── simple ground plane ── */
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(30, 30),
      new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 1 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.5;
    ground.receiveShadow = true;
    scene.add(ground);

    /* ── steam particles ── */
    const steamCount = 30;
    const steamGeo = new THREE.BufferGeometry();
    const steamPositions = new Float32Array(steamCount * 3);
    const steamVelocities = [];
    for (let i = 0; i < steamCount; i++) {
      steamPositions[i * 3] = (Math.random() - 0.5) * 1.2;
      steamPositions[i * 3 + 1] = 0.2 + Math.random() * 1.5;
      steamPositions[i * 3 + 2] = (Math.random() - 0.5) * 1.2;
      steamVelocities.push(0.003 + Math.random() * 0.006);
    }
    steamGeo.setAttribute("position", new THREE.BufferAttribute(steamPositions, 3));
    const steamMat = new THREE.PointsMaterial({
      color: 0xffffff,
      size: 0.08,
      transparent: true,
      opacity: 0.15,
      sizeAttenuation: true,
    });
    const steam = new THREE.Points(steamGeo, steamMat);
    scene.add(steam);

    /* ── animate ── */
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle rotation
      pizza.rotation.y = t * 0.3;

      // Steam rise
      const pos = steam.geometry.attributes.position.array;
      for (let i = 0; i < steamCount; i++) {
        pos[i * 3 + 1] += steamVelocities[i];
        if (pos[i * 3 + 1] > 2.5) {
          pos[i * 3] = (Math.random() - 0.5) * 1.2;
          pos[i * 3 + 1] = 0.2;
          pos[i * 3 + 2] = (Math.random() - 0.5) * 1.2;
        }
      }
      steam.geometry.attributes.position.needsUpdate = true;
      steamMat.opacity = 0.1 + Math.sin(t * 2) * 0.04;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    /* ── resize ── */
    window.addEventListener("resize", () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's in the scene

| Element | Geometry | Details |
|---|---|---|
| **Crust ring** | `TorusGeometry` | Golden-brown outer rim |
| **Crust top/bottom** | `RingGeometry` | Slightly darker underside |
| **Sauce** | `CircleGeometry` | Red tomato layer |
| **Cheese** | `CircleGeometry` | Yellow melted layer + random droplet spheres |
| **Pepperoni** | `CylinderGeometry` ×9 | Scattered with random offsets |
| **Basil** | Squashed `SphereGeometry` ×5 | Green leaf accents |
| **Crust bumps** | `SphereGeometry` ×6 | Irregular puffy spots |
| **Steam** | `Points` ×30 | Rising semi-transparent particles |

**Interactions:** drag to orbit, scroll to zoom, auto-rotates gently. Shadows, fog, ACES tone mapping, and a rim light give it a warm restaurant-vibe look.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Tent Demo</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script src="https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.min.js"></script>
  <script>
    // ── Scene, Camera, Renderer ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87ceeb);
    scene.fog = new THREE.Fog(0x87ceeb, 40, 90);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 4, 12);
    camera.lookAt(0, 1.5, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // ── Lights ──
    scene.add(new THREE.AmbientLight(0x8899bb, 0.6));
    const sun = new THREE.DirectionalLight(0xffeedd, 1.8);
    sun.position.set(8, 15, 10);
    sun.castShadow = true;
    sun.shadow.mapSize.set(2048, 2048);
    sun.shadow.camera.near = 1;
    sun.shadow.camera.far = 40;
    sun.shadow.camera.left = -15;
    sun.shadow.camera.right = 15;
    sun.shadow.camera.top = 15;
    sun.shadow.camera.bottom = -15;
    scene.add(sun);

    const fill = new THREE.DirectionalLight(0x6688cc, 0.4);
    fill.position.set(-5, 3, -5);
    scene.add(fill);

    // ── Materials ──
    const tentFabric = new THREE.MeshStandardMaterial({
      color: 0xf5f0e0,
      roughness: 0.85,
      side: THREE.DoubleSide,
    });
    const tentTrim = new THREE.MeshStandardMaterial({
      color: 0x4a6741,
      roughness: 0.7,
      side: THREE.DoubleSide,
    });
    const tentDark = new THREE.MeshStandardMaterial({
      color: 0x3a3a3a,
      roughness: 0.9,
    });
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x4a7c3f,
      roughness: 1.0,
    });
    const doorMat = new THREE.MeshStandardMaterial({
      color: 0x2a2a2a,
      roughness: 0.95,
    });

    // ── Tent Geometry (A-frame / triangular prism) ──
    function createTent() {
      const group = new THREE.Group();
      const W = 4.0;    // width (X)
      const D = 3.0;    // depth (Z)
      const H = 2.8;    // peak height (Y)
      const Hmid = 0.6; // valley height (Y)

      // Helper: triangle vertices (front face, centered)
      const tri = (offsetZ) => [
        // apex
        [0, H, offsetZ],
        // bottom-left
        [-W / 2, Hmid, offsetZ],
        // bottom-right
        [ W / 2, Hmid, offsetZ],
      ];

      // ── Front wall (triangle) ──
      const front = tri(0);
      group.add(makeTriangleMesh(front, tentFabric));

      // ── Back wall (triangle) ──
      const back = tri(-D);
      group.add(makeTriangleMesh(back, tentFabric));

      // ── Left roof plane ──
      const leftRoof = [
        [-W / 2, Hmid, 0],
        [0, H, 0],
        [0, H, -D],
        [-W / 2, Hmid, -D],
      ];
      group.add(makePlaneMesh(leftRoof, tentFabric));

      // ── Right roof plane ──
      const rightRoof = [
        [0, H, 0],
        [W / 2, Hmid, 0],
        [W / 2, Hmid, -D],
        [0, H, -D],
      ];
      group.add(makePlaneMesh(rightRoof, tentFabric));

      // ── Floor ──
      const floor = [
        [-W / 2, Hmid, 0],
        [ W / 2, Hmid, 0],
        [ W / 2, Hmid, -D],
        [-W / 2, Hmid, -D],
      ];
      group.add(makePlaneMesh(floor, tentTrim));

      // ── Door flap (opening in front wall) ──
      const doorW = 0.8, doorH = 1.2;
      const doorGeo = new THREE.PlaneGeometry(doorW, doorH);
      const door = new THREE.Mesh(doorGeo, doorMat);
      door.position.set(0, Hmid + doorH / 2, 0.01);
      door.castShadow = true;
      group.add(door);

      // ── Trim lines (edges along the roof peaks) ──
      const ridgeGeo = new THREE.BoxGeometry(0.06, 0.06, D);
      const ridge = new THREE.Mesh(ridgeGeo, tentTrim);
      ridge.position.set(0, H, -D / 2);
      group.add(ridge);

      // ── Tent poles ──
      const poleMat = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.6, roughness: 0.3 });
      const poleGeo = new THREE.CylinderGeometry(0.025, 0.025, H + 0.3, 8);

      const pole1 = new THREE.Mesh(poleGeo, poleMat);
      pole1.position.set(-0.01, H / 2 + 0.15, 0.1);
      group.add(pole1);

      const pole2 = new THREE.Mesh(poleGeo, poleMat);
      pole2.position.set(-0.01, H / 2 + 0.15, -D + 0.1);
      group.add(pole2);

      // ── Guy lines (simple thin cylinders at angles) ──
      const guyGeo = new THREE.CylinderGeometry(0.01, 0.01, 3.5, 4);

      const guy1 = new THREE.Mesh(guyGeo, tentTrim);
      guy1.position.set(-W / 2 - 0.8, Hmid + 0.5, 0.5);
      guy1.rotation.z = Math.PI / 3;
      group.add(guy1);

      const guy2 = new THREE.Mesh(guyGeo, tentTrim);
      guy2.position.set(W / 2 + 0.8, Hmid + 0.5, 0.5);
      guy2.rotation.z = -Math.PI / 3;
      group.add(guy2);

      // ── Stakes ──
      const stakeGeo = new THREE.ConeGeometry(0.04, 0.35, 6);
      const stakeMat = new THREE.MeshStandardMaterial({ color: 0x666666, metalness: 0.5 });

      [[-W / 2 - 1.2, Hmid - 0.1, 0.5], [W / 2 + 1.2, Hmid - 0.1, 0.5]].forEach(p => {
        const stake = new THREE.Mesh(stakeGeo, stakeMat);
        stake.position.set(...p);
        stake.rotation.z = p[0] > 0 ? -0.3 : 0.3;
        group.add(stake);
      });

      return group;
    }

    function makeTriangleMesh(vertices, material) {
      const geo = new THREE.BufferGeometry();
      const v = [];
      vertices.forEach(p => v.push(p[0], p[1], p[2]));
      geo.setAttribute('position', new THREE.Float32BufferAttribute(v, 3));
      geo.computeVertexNormals();
      const mesh = new THREE.Mesh(geo, material);
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      return mesh;
    }

    function makePlaneMesh(vertices, material) {
      const geo = new THREE.BufferGeometry();
      const v = [];
      // two triangles from quad
      [0, 1, 2, 0, 2, 3].forEach(i => v.push(vertices[i][0], vertices[i][1], vertices[i][2]));
      geo.setAttribute('position', new THREE.Float32BufferAttribute(v, 3));
      geo.computeVertexNormals();
      const mesh = new THREE.Mesh(geo, material);
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      return mesh;
    }

    const tent = createTent();
    scene.add(tent);

    // ── Ground ──
    const groundGeo = new THREE.CircleGeometry(30, 64);
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = 0.59;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Scattered rocks ──
    const rockMat = new THREE.MeshStandardMaterial({ color: 0x777777, roughness: 1 });
    for (let i = 0; i < 12; i++) {
      const s = 0.15 + Math.random() * 0.35;
      const rock = new THREE.Mesh(new THREE.DodecahedronGeometry(s, 0), rockMat);
      const angle = Math.random() * Math.PI * 2;
      const dist = 3 + Math.random() * 12;
      rock.position.set(Math.cos(angle) * dist, 0.59 + s * 0.4, Math.sin(angle) * dist);
      rock.rotation.set(Math.random(), Math.random(), Math.random());
      rock.castShadow = true;
      rock.receiveShadow = true;
      scene.add(rock);
    }

    // ── Simple trees ──
    function makeTree(x, z) {
      const g = new THREE.Group();
      const trunkMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 1 });
      const trunk = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.18, 2, 6), trunkMat);
      trunk.position.y = 1;
      trunk.castShadow = true;
      g.add(trunk);

      const leafMat = new THREE.MeshStandardMaterial({ color: 0x2d6b1e, roughness: 0.9 });
      for (let i = 0; i < 3; i++) {
        const cone = new THREE.Mesh(
          new THREE.ConeGeometry(1.2 - i * 0.3, 1.5, 8),
          leafMat
        );
        cone.position.y = 2.2 + i * 0.9;
        cone.castShadow = true;
        g.add(cone);
      }
      g.position.set(x, 0.59, z);
      return g;
    }

    scene.add(makeTree(-7, -4));
    scene.add(makeTree(-9, 1));
    scene.add(makeTree(8, -6));
    scene.add(makeTree(6, 3));
    scene.add(makeTree(-5, -9));

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle camera orbit
      camera.position.x = Math.sin(t * 0.15) * 12;
      camera.position.z = Math.cos(t * 0.15) * 12;
      camera.position.y = 4 + Math.sin(t * 0.1) * 0.5;
      camera.lookAt(0, 1.5, -1.5);

      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's included

| Feature | Details |
|---|---|
| **Tent geometry** | A-frame triangular prism built from custom `BufferGeometry` — front/back triangle walls, two sloped roof planes, floor, ridge trim, door flap, poles, guy lines, and stakes |
| **Environment** | Green ground plane, scattered rocks (`DodecahedronGeometry`), 5 procedural pine trees (trunk + stacked cones) |
| **Lighting** | Ambient + directional sun (with soft shadow maps) + blue fill light |
| **Camera** | Slow auto-orbit around the tent with gentle vertical bob |
| **Materials** | `MeshStandardMaterial` throughout — off-white canvas, green trim, dark door, metallic poles/stakes |
| **Responsive** | Handles window resize; uses `devicePixelRatio` for crisp rendering |

Open the file in any modern browser — no build step needed.

