// --- Canopy underside (slightly darker) ---
const underGeo = new THREE.SphereGeometry(2.98, 32, 16, 0, Math.PI * 2, 0, Math.PI * 0.42);
const underMat = new THREE.MeshStandardMaterial({
  color: 0x991133,
  side: THREE.BackSide,
  roughness: 0.7
});
umbrella.add(new THREE.Mesh(underGeo, underMat));

// --- Ribs on canopy surface ---
const ribMat = new THREE.MeshStandardMaterial({ color: 0xD4A843, roughness: 0.4, metalness: 0.3 });
const ribCount = 8;
for (let i = 0; i < ribCount; i++) {
  const angle = (i / ribCount) * Math.PI * 2;
  const ribGeo = new THREE.CylinderGeometry(0.025, 0.025, 3.1, 6);
  const rib = new THREE.Mesh(ribGeo, ribMat);
  rib.position.set(
    Math.sin(angle) * 1.5,
    1.2,
    Math.cos(angle) * 1.5
  );
  rib.rotation.z = Math.cos(angle) * 0.65;
  rib.rotation.x = -Math.sin(angle) * 0.65;
  rib.castShadow = true;
  umbrella.add(rib);
}

// --- Top tip ---
const tipGeo = new THREE.ConeGeometry(0.06, 0.3, 8);
const tipMat = new THREE.MeshStandardMaterial({ color: 0xD4A843, metalness: 0.6, roughness: 0.2 });
const tip = new THREE.Mesh(tipGeo, tipMat);
tip.position.y = 3.15;
umbrella.add(tip);

// --- Shaft ---
const shaftGeo = new THREE.CylinderGeometry(0.05, 0.05, 4.5, 8);
const shaftMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.3, metalness: 0.5 });
const shaft = new THREE.Mesh(shaftGeo, shaftMat);
shaft.position.y = -1.5;
shaft.castShadow = true;
umbrella.add(shaft);

// --- Curved handle (J-shape via Torus segment) ---
const handleCurve = new THREE.Curve();
const handlePath = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, -3.75, 0),
  new THREE.Vector3(0.15, -3.9, 0),
  new THREE.Vector3(0.4, -3.85, 0),
  new THREE.Vector3(0.55, -3.7, 0),
  new THREE.Vector3(0.5, -3.5, 0),
  new THREE.Vector3(0.3, -3.4, 0),
]);
const handleGeo = new THREE.TubeGeometry(handlePath, 20, 0.055, 8, false);
const handleMat = new THREE.MeshStandardMaterial({ color: 0x5C3317, roughness: 0.6, metalness: 0.1 });
const handle = new THREE.Mesh(handleGeo, handleMat);
handle.castShadow = true;
umbrella.add(handle);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(20, 32);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x4A7C59, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -5;
ground.receiveShadow = true;
scene.add(ground);

// --- Rain drops (simple falling particles) ---
const rainCount = 300;
const rainGeo = new THREE.BufferGeometry();
const rainPos = new Float32Array(rainCount * 3);
const rainVel = [];
for (let i = 0; i < rainCount; i++) {
  rainPos[i * 3] = (Math.random() - 0.5) * 20;
  rainPos[i * 3 + 1] = Math.random() * 20 - 5;
  rainPos[i * 3 + 2] = (Math.random() - 0.5) * 20;
  rainVel.push(0.05 + Math.random() * 0.1);
}
rainGeo.setAttribute('position', new THREE.BufferAttribute(rainPos, 3));
const rainMat = new THREE.PointsMaterial({ color: 0xAACCEE, size: 0.04, transparent: true, opacity: 0.6 });
const rain = new THREE.Points(rainGeo, rainMat);
scene.add(rain);

// --- Animation ---
umbrella.rotation.y = 0;
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  umbrella.rotation.y = Math.sin(t * 0.3) * 0.15;
  umbrella.position.y = Math.sin(t * 0.8) * 0.15;

  // Rain
  const positions = rainGeo.attributes.position.array;
  for (let i = 0; i < rainCount; i++) {
    positions[i * 3 + 1] -= rainVel[i];
    if (positions[i * 3 + 1] < -5) {
      positions[i * 3 + 1] = 15;
      positions[i * 3] = (Math.random() - 0.5) * 20;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
    }
  }
  rainGeo.attributes.position.needsUpdate = true;

  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

