<body>
  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 1, 4);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    document.body.appendChild(renderer.domElement);

    new OrbitControls(camera, renderer.domElement);

    // ── Lighting ──
    scene.add(new THREE.AmbientLight(0xffffff, 0.4));
    const dir = new THREE.DirectionalLight(0xffffff, 1.5);
    dir.position.set(3, 5, 4);
    scene.add(dir);
    const rim = new THREE.DirectionalLight(0xff6666, 0.6);
    rim.position.set(-3, 2, -2);
    scene.add(rim);

    // ── Apple group ──
    const apple = new THREE.Group();

    // Body — slightly flattened sphere
    const bodyGeo = new THREE.SphereGeometry(1, 64, 64);
    // Dimple top and bottom to look more apple-like
    const pos = bodyGeo.attributes.position;
    for (let i = 0; i < pos.count; i++) {
      const y = pos.getY(i);
      const topDimple = Math.max(0, (y - 0.55) * 3);
      const bottomDimple = Math.max(0, (-y - 0.55) * 3);
      const scale = 1 - topDimple * 0.18 - bottomDimple * 0.12;
      pos.setX(i, pos.getX(i) * scale);
      pos.setZ(i, pos.getZ(i) * scale);
    }
    bodyGeo.computeVertexNormals();

    const bodyMat = new THREE.MeshStandardMaterial({
      color: 0xcc2233,
      roughness: 0.35,
      metalness: 0.05,
    });
    apple.add(new THREE.Mesh(bodyGeo, bodyMat));

    // Highlight patch
    const patchGeo = new THREE.SphereGeometry(0.28, 32, 32);
    patchGeo.scale(1, 1.4, 0.6);
    const patchMat = new THREE.MeshStandardMaterial({
      color: 0xff8844,
      roughness: 0.4,
      transparent: true,
      opacity: 0.35,
    });
    const patch = new THREE.Mesh(patchGeo, patchMat);
    patch.position.set(0.35, 0.25, 0.75);
    patch.rotation.z = -0.4;
    apple.add(patch);

    // Stem
    const stemGeo = new THREE.CylinderGeometry(0.03, 0.045, 0.4, 12);
    const stemMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.8 });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.position.set(0, 1.05, 0);
    stem.rotation.z = 0.15;
    apple.add(stem);

    // Leaf
    const leafShape = new THREE.Shape();
    leafShape.moveTo(0, 0);
    leafShape.bezierCurveTo(0.15, 0.15, 0.25, 0.35, 0.12, 0.5);
    leafShape.bezierCurveTo(0.02, 0.42, -0.08, 0.3, 0, 0);
    const leafGeo = new THREE.ShapeGeometry(leafShape, 16);
    const leafMat = new THREE.MeshStandardMaterial({
      color: 0x3a8c3f,
      roughness: 0.6,
      side: THREE.DoubleSide,
    });
    const leaf = new THREE.Mesh(leafGeo, leafMat);
    leaf.position.set(0.04, 1.18, 0);
    leaf.rotation.set(0.3, -0.5, 0.8);
    apple.add(leaf);

    scene.add(apple);

    // ── Animate ──
    const clock = new THREE.Clock();
    (function loop() {
      requestAnimationFrame(loop);
      const t = clock.getElapsedTime();
      apple.position.y = Math.sin(t * 0.8) * 0.15;
      apple.rotation.y = t * 0.3;
      renderer.render(scene, camera);
    })();

    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
