const ambientLight = new THREE.AmbientLight(0xffeedd, 0.3);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
keyLight.position.set(4, 6, 3);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 0.5;
keyLight.shadow.camera.far = 20;
keyLight.shadow.camera.left = -3;
keyLight.shadow.camera.right = 3;
keyLight.shadow.camera.top = 3;
keyLight.shadow.camera.bottom = -3;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-3, 2, -2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffaa44, 1.5, 10);
rimLight.position.set(-2, 3, 2);
scene.add(rimLight);

const bottomLight = new THREE.PointLight(0x4466aa, 0.5, 6);
bottomLight.position.set(0, -1, 0);
scene.add(bottomLight);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle swing
  bell.rotation.z = Math.sin(t * 1.2) * 0.08;
  clapper.rotation.z = -Math.sin(t * 1.2) * 0.15;

  // Clapper swing (pendulum-like, slightly delayed)
  clapper.position.x = Math.sin(t * 1.2) * 0.12;
  clapper.position.y = 0.25 - Math.abs(Math.sin(t * 1.2)) * 0.03;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this does:**

- **Bell shape** — Built with `LatheGeometry` from a hand-crafted 2D profile that's revolved 360° around the Y axis, giving a realistic bell silhouette with a flared rim, curved body, and a looped handle at the top.

- **Clapper** — A small golden sphere on a thin rod inside the bell that swings like a pendulum.

- **Material** — Bronze/gold `MeshStandardMaterial` with high metalness and low roughness for a polished metallic look.

- **Lighting** — A warm key light, cool blue fill light, orange rim light, and soft ambient light for dramatic three-point illumination with shadows.

- **Animation** — The bell gently sways side-to-side, and the clapper swings in opposition (like a real bell being rung).

- **Interaction** — `OrbitControls` lets you drag to rotate, scroll to zoom, and right-drag to pan.

