renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 12, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.maxPolarAngle = Math.PI / 2.05;
controls.update();

// ── Lights ───────────────────────────────────────────────────
const ambient = new THREE.AmbientLight(0x8899bb, 0.8);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 2.2);
sun.position.set(50, 80, 40);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.left = -120;
sun.shadow.camera.right = 120;
sun.shadow.camera.top = 80;
sun.shadow.camera.bottom = -80;
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 250;
sun.shadow.bias = -0.0005;
scene.add(sun);

const hemi = new THREE.HemisphereLight(0x87ceeb, 0x556b2f, 0.5);
scene.add(hemi);

// ── Materials ────────────────────────────────────────────────
const matSteel = new THREE.MeshStandardMaterial({ color: 0x6b6b6b, metalness: 0.8, roughness: 0.35 });
const matTower = new THREE.MeshStandardMaterial({ color: 0xcc4422, metalness: 0.5, roughness: 0.4 });
const matDeck  = new THREE.MeshStandardMaterial({ color: 0x555555, metalness: 0.3, roughness: 0.7 });
const matRoad  = new THREE.MeshStandardMaterial({ color: 0x333333, metalness: 0.1, roughness: 0.9 });
const matCable = new THREE.MeshStandardMaterial({ color: 0xaaaaaa, metalness: 0.9, roughness: 0.2 });
const matWater = new THREE.MeshStandardMaterial({ color: 0x2266aa, metalness: 0.6, roughness: 0.15, transparent: true, opacity: 0.8 });
const matGround= new THREE.MeshStandardMaterial({ color: 0x4a7c3f, metalness: 0.0, roughness: 1.0 });
const matBarrier = new THREE.MeshStandardMaterial({ color: 0xdddddd, metalness: 0.2, roughness: 0.6 });

// ── Helpers ──────────────────────────────────────────────────
const deckY = 18;
const span = 100;          // distance between towers
const towerHeight = 65;
const towerWidth = 4;
const towerDepth = 6;
const deckWidth = 14;
const suspenderCount = 40;

// ── Water ────────────────────────────────────────────────────
const waterGeo = new THREE.PlaneGeometry(600, 600);
const water = new THREE.Mesh(waterGeo, matWater);
water.rotation.x = -Math.PI / 2;
water.position.y = -2;
water.receiveShadow = true;
scene.add(water);

// ── Ground / Banks ───────────────────────────────────────────
function makeBank(x) {
  const geo = new THREE.BoxGeometry(80, 6, 120);
  const m = new THREE.Mesh(geo, matGround);
  m.position.set(x, -3, 0);
  m.receiveShadow = true;
  scene.add(m);
}
makeBank(-span / 2 - 40);
makeBank(span / 2 + 40);

// ── Towers ───────────────────────────────────────────────────
function createTower(x) {
  const group = new THREE.Group();

  // Two columns
  for (const dz of [-3, 3]) {
    const col = new THREE.Mesh(new THREE.BoxGeometry(towerWidth, towerHeight, towerWidth), matTower);
    col.position.set(x, towerHeight / 2, dz);
    col.castShadow = true;
    col.receiveShadow = true;
    group.add(col);
  }

  // Cross beams
  for (const y of [12, 24, 36, 48, 58]) {
    const beam = new THREE.Mesh(new THREE.BoxGeometry(towerWidth + 0.5, 1.2, towerDepth + 1), matSteel);
    beam.position.set(x, y, 0);
    beam.castShadow = true;
    group.add(beam);
  }

  // Top cap
  const cap = new THREE.Mesh(new THREE.BoxGeometry(towerWidth + 1, 1.5, towerDepth + 2), matTower);
  cap.position.set(x, towerHeight, 0);
  cap.castShadow = true;
  group.add(cap);

  scene.add(group);
}
createTower(-span / 2);
createTower(span / 2);

// ── Deck ─────────────────────────────────────────────────────
// Main span
const mainDeck = new THREE.Mesh(new THREE.BoxGeometry(span, 1.5, deckWidth), matDeck);
mainDeck.position.set(0, deckY, 0);
mainDeck.castShadow = true;
mainDeck.receiveShadow = true;
scene.add(mainDeck);

// Road surface
const road = new THREE.Mesh(new THREE.BoxGeometry(span, 0.15, deckWidth - 2), matRoad);
road.position.set(0, deckY + 0.85, 0);
scene.add(road);

// Center line dashes
for (let i = -span / 2 + 3; i < span / 2; i += 6) {
  const dash = new THREE.Mesh(
    new THREE.BoxGeometry(3, 0.05, 0.3),
    new THREE.MeshStandardMaterial({ color: 0xffcc00, metalness: 0, roughness: 0.8 })
  );
  dash.position.set(i, deckY + 0.95, 0);
  scene.add(dash);
}

// Barriers (railings)
for (const z of [-deckWidth / 2 + 0.3, deckWidth / 2 - 0.3]) {
  const barrier = new THREE.Mesh(new THREE.BoxGeometry(span, 1.2, 0.3), matBarrier);
  barrier.position.set(0, deckY + 1.35, z);
  barrier.castShadow = true;
  scene.add(barrier);
}

// Approach spans
for (const side of [-1, 1]) {
  const approach = new THREE.Mesh(new THREE.BoxGeometry(40, 1.5, deckWidth), matDeck);
  approach.position.set(side * (span / 2 + 20), deckY - 2, 0);
  approach.castShadow = true;
  approach.receiveShadow = true;
  scene.add(approach);

  const aRoad = new THREE.Mesh(new THREE.BoxGeometry(40, 0.15, deckWidth - 2), matRoad);
  aRoad.position.set(side * (span / 2 + 20), deckY - 1.15, 0);
  scene.add(aRoad);

  // Approach barriers
  for (const z of [-deckWidth / 2 + 0.3, deckWidth / 2 - 0.3]) {
    const ab = new THREE.Mesh(new THREE.BoxGeometry(40, 1.0, 0.3), matBarrier);
    ab.position.set(side * (span / 2 + 20), deckY + 0.15, z);
    scene.add(ab);
  }

  // Approach piers
  for (let i = 1; i <= 3; i++) {
    const pier = new THREE.Mesh(new THREE.BoxGeometry(2, deckY - 2, 3), matSteel);
    pier.position.set(side * (span / 2 + i * 12), (deckY - 2) / 2 - 1, 0);
    pier.castShadow = true;
    scene.add(pier);
  }
}

// ── Main Suspension Cables (catenary shape) ──────────────────
function catenarySag(x, towerX) {
  const d = Math.abs(x - towerX);
  return 8 + 3 * Math.pow(d / (span / 2), 2);
}

function createMainCable(z) {
  const points = [];
  const steps = 120;
  const totalLen = span + 80;
  for (let i = 0; i <= steps; i++) {
    const x = -totalLen / 2 + (totalLen / steps) * i;
    let y;
    if (Math.abs(x) <= span / 2) {
      // Between towers: catenary sag
      y = towerHeight - 8 - 10 * Math.pow(x / (span / 2), 2);
    } else {
      // Anchor spans: slope down to anchor
      const side = x > 0 ? 1 : -1;
      const anchorX = side * (span / 2 + 40);
      const t = Math.abs(x - side * span / 2) / 40;
      y = (towerHeight - 18) * (1 - t);
    }
    points.push(new THREE.Vector3(x, Math.max(y, 2), z));
  }
  const curve = new THREE.CatmullRomCurve3(points);
  const tubeGeo = new THREE.TubeGeometry(curve, 120, 0.25, 8, false);
  const mesh = new THREE.Mesh(tubeGeo, matCable);
  mesh.castShadow = true;
  scene.add(mesh);
}
createMainCable(-2.5);
createMainCable(2.5);

// ── Suspender Cables ─────────────────────────────────────────
function createSuspenders() {
  const cableZ = [-2.5, 2.5];
  for (let i = 0; i <= suspenderCount; i++) {
    const t = i / suspenderCount;
    const x = -span / 2 + t * span;
    const cableY = towerHeight - 8 - 10 * Math.pow(x / (span / 2), 2);
    const len = cableY - deckY;
    if (len <= 0) continue;

    for (const z of cableZ) {
      const suspender = new THREE.Mesh(
        new THREE.CylinderGeometry(0.06, 0.06, len, 4),
        matCable
      );
      suspender.position.set(x, deckY + len / 2, z);
      suspender.castShadow = true;
      scene.add(suspender);
    }
  }
}
createSuspenders();

// ── Anchor Blocks ────────────────────────────────────────────
for (const side of [-1, 1]) {
  const anchor = new THREE.Mesh(
    new THREE.BoxGeometry(10, 10, 14),
    new THREE.MeshStandardMaterial({ color: 0x777777, metalness: 0.2, roughness: 0.8 })
  );
  anchor.position.set(side * (span / 2 + 38), 3, 0);
  anchor.castShadow = true;
  anchor.receiveShadow = true;
  scene.add(anchor);
}

// ── Animated Clouds ──────────────────────────────────────────
const clouds = [];
function makeCloud(x, y, z, scale) {
  const group = new THREE.Group();
  const mat = new THREE.MeshStandardMaterial({ color: 0xffffff, flatShading: true, roughness: 1 });
  for (let i = 0; i < 5; i++) {
    const r = 2 + Math.random() * 3;
    const m = new THREE.Mesh(new THREE.SphereGeometry(r, 7, 5), mat);
    m.position.set(i * 4 - 8, Math.random() * 1.5, Math.random() * 2);
    m.scale.y = 0.5;
    group.add(m);
  }
  group.position.set(x, y, z);
  group.scale.setScalar(scale);
  scene.add(group);
  clouds.push({ mesh: group, speed: 0.02 + Math.random() * 0.03 });
}
makeCloud(-80, 70, -60, 1.5);
makeCloud(40, 60, -80, 1.2);
makeCloud(100, 75, -50, 1.8);
makeCloud(-30, 65, 70, 1.0);
makeCloud(70, 55, 60, 1.3);

// ── Animation Loop ───────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle water animation
  water.position.y = -2 + Math.sin(t * 0.5) * 0.15;

  // Drifting clouds
  for (const c of clouds) {
    c.mesh.position.x += c.speed;
    if (c.mesh.position.x > 200) c.mesh.position.x = -200;
  }

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ───────────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
