    ctx.fillRect(0, 0, 170.67, 320);
    // White
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(170.67, 0, 170.67, 320);
    // Red
    ctx.fillStyle = '#ED2939';
    ctx.fillRect(341.33, 0, 170.67, 320);

    const flagTexture = new THREE.CanvasTexture(flagCanvas);
    flagTexture.colorSpace = THREE.SRGBColorSpace;

    // ── Flag geometry ────────────────────────────────
    const segmentsW = 60;
    const segmentsH = 30;
    const flagGeo = new THREE.PlaneGeometry(8, 5, segmentsW, segmentsH);

    // Shift geometry so pivot is at the pole edge
    flagGeo.translate(4, 0, 0);

    const flagMat = new THREE.MeshStandardMaterial({
      map: flagTexture,
      side: THREE.DoubleSide,
      roughness: 0.8,
      metalness: 0.0,
    });

