* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.008);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 500);
camera.position.set(12, 8, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;

// ── Lights ──
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.5);
sun.position.set(15, 25, 10);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 60;
sun.shadow.camera.left = -20;
sun.shadow.camera.right = 20;
sun.shadow.camera.top = 20;
sun.shadow.camera.bottom = -20;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8ec5fc, 0.4);
fill.position.set(-10, 5, -10);
scene.add(fill);

// ── Materials ──
const bodyMat = new THREE.MeshStandardMaterial({ color: 0x2c3e50, roughness: 0.3, metalness: 0.6 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x1a252f, roughness: 0.4, metalness: 0.5 });
const glassMat = new THREE.MeshStandardMaterial({ color: 0x88ccff, transparent: true, opacity: 0.45, roughness: 0.05, metalness: 0.1 });
const rotorMat = new THREE.MeshStandardMaterial({ color: 0x95a5a6, roughness: 0.5, metalness: 0.8 });
const skidMat = new THREE.MeshStandardMaterial({ color: 0x34495e, roughness: 0.6, metalness: 0.7 });
const accentMat = new THREE.MeshStandardMaterial({ color: 0xe74c3c, roughness: 0.3, metalness: 0.4 });
const tailFinMat = new THREE.MeshStandardMaterial({ color: 0xe74c3c, roughness: 0.3, metalness: 0.4 });

// ── Helicopter Group ──
const helicopter = new THREE.Group();

// Fuselage (main body)
const fuselageGeo = new THREE.BoxGeometry(2.2, 1.6, 5);
const fuselage = new THREE.Mesh(fuselageGeo, bodyMat);
fuselage.position.y = 2.8;
fuselage.castShadow = true;
helicopter.add(fuselage);

// Nose cone (tapered front)
const noseGeo = new THREE.CylinderGeometry(0.6, 1.1, 2, 8);
noseGeo.rotateX(Math.PI / 2);
const nose = new THREE.Mesh(noseGeo, bodyMat);
nose.position.set(0, 2.8, -3.4);
nose.castShadow = true;
helicopter.add(nose);

// Nose tip
const tipGeo = new THREE.SphereGeometry(0.55, 8, 6);
const tip = new THREE.Mesh(tipGeo, bodyMat);
tip.position.set(0, 2.8, -4.3);
helicopter.add(tip);

// Cockpit window
const cockpitGeo = new THREE.BoxGeometry(1.9, 0.8, 2.2);
const cockpit = new THREE.Mesh(cockpitGeo, glassMat);
cockpit.position.set(0, 3.3, -1.6);
helicopter.add(cockpit);

// Side windows
for (let side of [-1, 1]) {
  const winGeo = new THREE.BoxGeometry(0.05, 0.6, 2.5);
  const win = new THREE.Mesh(winGeo, glassMat);
  win.position.set(side * 1.12, 3.0, -0.2);
  helicopter.add(win);
}

// Door lines (decorative)
for (let side of [-1, 1]) {
  const doorGeo = new THREE.BoxGeometry(0.06, 1.4, 1.8);
  const door = new THREE.Mesh(doorGeo, darkMat);
  door.position.set(side * 1.13, 2.6, 0.3);
  helicopter.add(door);
}

// Tail boom
const tailGeo = new THREE.CylinderGeometry(0.25, 0.45, 6, 8);
tailGeo.rotateX(Math.PI / 2);
const tail = new THREE.Mesh(tailGeo, bodyMat);
tail.position.set(0, 2.8, 4.8);
tail.castShadow = true;
helicopter.add(tail);

// Tail fin (vertical stabilizer)
const finShape = new THREE.Shape();
finShape.moveTo(0, 0);
finShape.lineTo(0.3, 0);
finShape.lineTo(0.15, 2.2);
finShape.lineTo(-0.1, 2.2);
finShape.closePath();

const finExtrudeSettings = { depth: 0.08, bevelEnabled: false };
const finGeo = new THREE.ExtrudeGeometry(finShape, finExtrudeSettings);
const fin = new THREE.Mesh(finGeo, tailFinMat);
fin.position.set(-0.04, 3.2, 7.2);
fin.castShadow = true;
helicopter.add(fin);

// Rudder (horizontal stabilizer)
for (let side of [-1, 1]) {
  const rudGeo = new THREE.BoxGeometry(1.2, 0.08, 0.6);
  const rud = new THREE.Mesh(rudGeo, tailFinMat);
  rud.position.set(side * 0.6, 3.4, 7.4);
  rud.castShadow = true;
  helicopter.add(rud);
}

// ── Tail Rotor ──
const tailRotorGroup = new THREE.Group();
tailRotorGroup.position.set(1.0, 3.6, 7.4);

const tailHubGeo = new THREE.CylinderGeometry(0.08, 0.08, 0.3, 8);
const tailHub = new THREE.Mesh(tailHubGeo, darkMat);
tailHub.rotation.x = Math.PI / 2;
tailRotorGroup.add(tailHub);

for (let i = 0; i < 2; i++) {
  const bladeGeo = new THREE.BoxGeometry(0.06, 1.4, 0.12);
  const blade = new THREE.Mesh(bladeGeo, rotorMat);
  blade.position.y = (i === 0 ? 0.7 : -0.7);
  tailRotorGroup.add(blade);
}
helicopter.add(tailRotorGroup);

// ── Main Rotor Mast ──
const mastGeo = new THREE.CylinderGeometry(0.12, 0.15, 0.6, 8);
const mast = new THREE.Mesh(mastGeo, darkMat);
mast.position.set(0, 3.9, -0.2);
helicopter.add(mast);

// Rotor dome
const domeGeo = new THREE.SphereGeometry(0.5, 12, 8, 0, Math.PI * 2, 0, Math.PI / 2);
const dome = new THREE.Mesh(domeGeo, darkMat);
dome.position.set(0, 3.9, -0.2);
helicopter.add(dome);

// ── Main Rotor ──
const mainRotorGroup = new THREE.Group();
mainRotorGroup.position.set(0, 4.2, -0.2);

const hubGeo = new THREE.CylinderGeometry(0.18, 0.18, 0.15, 12);
const hub = new THREE.Mesh(hubGeo, darkMat);
mainRotorGroup.add(hub);

for (let i = 0; i < 4; i++) {
  const bladeGeo = new THREE.BoxGeometry(0.12, 0.06, 5.5);
  const blade = new THREE.Mesh(bladeGeo, rotorMat);
  blade.position.z = 2.75;
  blade.castShadow = true;
  const arm = new THREE.Group();
  arm.add(blade);
  arm.rotation.y = (Math.PI / 2) * i;
  mainRotorGroup.add(arm);
}
helicopter.add(mainRotorGroup);

// ── Landing Skids ──
for (let side of [-1, 1]) {
  // Horizontal skid bar
  const skidGeo = new THREE.CylinderGeometry(0.06, 0.06, 4.5, 8);
  skidGeo.rotateZ(Math.PI / 2);
  const skid = new THREE.Mesh(skidGeo, skidMat);
  skid.position.set(side * 0.9, 0.8, -0.5);
  skid.castShadow = true;
  helicopter.add(skid);

  // Struts connecting skid to body
  for (let z of [-2.2, 0.8, 1.5]) {
    const strutGeo = new THREE.CylinderGeometry(0.04, 0.04, 1.5, 6);
    const strut = new THREE.Mesh(strutGeo, skidMat);
    strut.position.set(side * 0.9, 1.8, z);
    helicopter.add(strut);

    // Small cross brace
    if (z === -2.2 || z === 0.8) {
      const braceGeo = new THREE.CylinderGeometry(0.025, 0.025, 1.8, 6);
      braceGeo.rotateZ(Math.PI / 2);
      const brace = new THREE.Mesh(braceGeo, skidMat);
      brace.position.set(0, 1.5, z);
      helicopter.add(brace);
    }
  }
}

// ── Lights / Beacons ──
const beaconGeo = new THREE.SphereGeometry(0.08, 8, 8);
const beaconL = new THREE.Mesh(beaconGeo, new THREE.MeshStandardMaterial({ color: 0x00ff00, emissive: 0x00ff00, emissiveIntensity: 2 }));
beaconL.position.set(-1.5, 0.85, -2.2);
helicopter.add(beaconL);

const beaconR = new THREE.Mesh(beaconGeo, new THREE.MeshStandardMaterial({ color: 0xff0000, emissive: 0xff0000, emissiveIntensity: 2 }));
beaconR.position.set(1.5, 0.85, -2.2);
helicopter.add(beaconR);

// ── Scene ──
scene.add(helicopter);

// Ground
const groundGeo = new THREE.CircleGeometry(80, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x3a7d44, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Grid pattern on ground
const gridHelper = new THREE.GridHelper(80, 40, 0x2d6b35, 0x2d6b35);
gridHelper.position.y = 0.01;
gridHelper.material.opacity = 0.15;
gridHelper.material.transparent = true;
scene.add(gridHelper);

// Heli pad
const padGeo = new THREE.CylinderGeometry(4, 4, 0.05, 32);
const padMat = new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.8 });
const pad = new THREE.Mesh(padGeo, padMat);
pad.position.y = 0.025;
pad.receiveShadow = true;
scene.add(pad);

// H on pad
const hShape = new THREE.Shape();
hShape.moveTo(-0.8, -1); hShape.lineTo(-0.8, 1);
hShape.lineTo(-0.4, 1); hShape.lineTo(-0.4, -1);
hShape.moveTo(0.8, -1); hShape.lineTo(0.8, 1);
hShape.lineTo(0.4, 1); hShape.lineTo(0.4, -1);
hShape.moveTo(-0.4, 0); hShape.lineTo(0.4, 0);
hShape.lineTo(0.4, -0.3); hShape.lineTo(-0.4, -0.3);
hShape.closePath();
const hGeo = new THREE.ExtrudeGeometry(hShape, { depth: 0.06, bevelEnabled: false });
const hMesh = new THREE.Mesh(hGeo, new THREE.MeshStandardMaterial({ color: 0xffffff }));
hMesh.rotation.x = -Math.PI / 2;
hMesh.position.y = 0.055;
scene.add(hMesh);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Rotor speeds
  mainRotorGroup.rotation.y = t * 12;
  tailRotorGroup.rotation.y = t * 25;

  // Gentle hover
  helicopter.position.y = Math.sin(t * 1.5) * 0.2 + 0.5;
  helicopter.rotation.z = Math.sin(t * 0.7) * 0.015;
  helicopter.rotation.x = Math.sin(t * 0.5) * 0.01;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
