    canvas { display: block; }
  </style>
</head>
<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
        "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene, Camera, Renderer ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.shadowMap.enabled = true;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;

    // ── Lighting ──
    scene.add(new THREE.AmbientLight(0xffffff, 0.6));
    const dir = new THREE.DirectionalLight(0xffffff, 1);
    dir.position.set(5, 10, 7);
    dir.castShadow = true;
    scene.add(dir);

    // ── Ladder Parameters ──
    const ladder = {
      rungs: 10,
      height: 6,
      width: 1.4,
      railThickness: 0.1,
      rungThickness: 0.08,
      depth: 0.06,
      color: 0x8B4513
    };

    const { rungs, height, width, railThickness: rt, rungThickness: rtt, depth, color } = ladder;

    // ── Materials ──
    const woodMat = new THREE.MeshStandardMaterial({ color, roughness: 0.8 });
    const floorMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.9 });

    // ── Floor ──
    const floor = new THREE.Mesh(new THREE.PlaneGeometry(20, 20), floorMat);
    floor.rotation.x = -Math.PI / 2;
    floor.receiveShadow = true;
    scene.add(floor);

    // ── Build Ladder ──
    const ladderGroup = new THREE.Group();

    // Side rails
    const railGeo = new THREE.BoxGeometry(rt, height, depth);
    const leftRail = new THREE.Mesh(railGeo, woodMat);
    leftRail.position.set(-width / 2, height / 2, 0);
    leftRail.castShadow = true;
    ladderGroup.add(leftRail);

    const rightRail = new THREE.Mesh(railGeo, woodMat);
    rightRail.position.set(width / 2, height / 2, 0);
    rightRail.castShadow = true;
    ladderGroup.add(rightRail);

    // Rungs
    const rungGeo = new THREE.BoxGeometry(width + rt, rtt, depth * 1.5);
    const spacing = height / (rungs + 1);
    for (let i = 1; i <= rungs; i++) {
      const rung = new THREE.Mesh(rungGeo, woodMat);
      rung.position.set(0, spacing * i, 0);
      rung.castShadow = true;
      ladderGroup.add(rung);
    }

    // Tilt ladder slightly so it leans
    ladderGroup.rotation.z = -Math.PI / 12;
    ladderGroup.position.y = 0;
    scene.add(ladderGroup);

    // ── Animate ──
    function animate() {
      requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

**What this creates:**

- **A wooden ladder** with 2 side rails and 10 rungs, tilted at ~15° to simulate leaning
- **Shadows** cast onto a dark floor plane
- **OrbitControls** — click and drag to rotate, scroll to zoom
- **Responsive** — adapts to window resizing
- **Single file** — just open `index.html` in any modern browser

