<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Kangaroo</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
    #info {
      position: absolute; top: 12px; width: 100%; text-align: center;
      font-family: sans-serif; color: #fff; pointer-events: none;
      text-shadow: 0 1px 3px rgba(0,0,0,.6); font-size: 14px;
    }
  </style>
</head>
<body>
  <div id="info">🦘 Drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    /* ── Scene, Camera, Renderer ── */
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87CEEB);
    scene.fog = new THREE.FogExp2(0x87CEEB, 0.012);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
    camera.position.set(6, 4, 8);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 2, 0);
    controls.enableDamping = true;

    /* ── Lights ── */
    const hemi = new THREE.HemisphereLight(0xffeedd, 0x444422, 0.8);
    scene.add(hemi);

    const sun = new THREE.DirectionalLight(0xffffff, 1.6);
    sun.position.set(5, 10, 5);
    sun.castShadow = true;
    sun.shadow.mapSize.set(1024, 1024);
    sun.shadow.camera.near = 1;
    sun.shadow.camera.far = 30;
    sun.shadow.camera.left = -8;
    sun.shadow.camera.right = 8;
    sun.shadow.camera.top = 8;
    sun.shadow.camera.bottom = -8;
    scene.add(sun);

    const fill = new THREE.DirectionalLight(0xaaccff, 0.4);
    fill.position.set(-4, 3, -3);
    scene.add(fill);

    /* ── Ground ── */
    const groundGeo = new THREE.CircleGeometry(30, 64);
    const groundMat = new THREE.MeshStandardMaterial({ color: 0x8B7355, roughness: 1 });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // Grass tufts
    const grassMat = new THREE.MeshStandardMaterial({ color: 0x6B8E3A, roughness: 1 });
    for (let i = 0; i < 120; i++) {
      const g = new THREE.Mesh(new THREE.ConeGeometry(0.08, 0.3 + Math.random() * 0.2, 4), grassMat);
      g.position.set((Math.random() - 0.5) * 20, 0.12, (Math.random() - 0.5) * 20);
      g.rotation.y = Math.random() * Math.PI;
      g.castShadow = true;
      scene.add(g);
    }

    /* ── Kangaroo Materials ── */
    const bodyMat   = new THREE.MeshStandardMaterial({ color: 0xA0722A, roughness: 0.85 });
    const darkMat   = new THREE.MeshStandardMaterial({ color: 0x7A5420, roughness: 0.85 });
    const lightMat  = new THREE.MeshStandardMaterial({ color: 0xC89B5B, roughness: 0.8 });
    const noseMat   = new THREE.MeshStandardMaterial({ color: 0x3A2010, roughness: 0.6 });
    const eyeMat    = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.3 });
    const eyeWhite  = new THREE.MeshStandardMaterial({ color: 0xEEEEEE, roughness: 0.3 });
    const innerEar  = new THREE.MeshStandardMaterial({ color: 0xD4956A, roughness: 0.7 });
    const footMat   = new THREE.MeshStandardMaterial({ color: 0x5C3A1E, roughness: 0.9 });

    /* ── Kangaroo Group ── */
    const kangaroo = new THREE.Group();
    scene.add(kangaroo);

    // Helper
    function addMesh(geo, mat, parent, pos, rot, scl, castShadow = true) {
      const m = new THREE.Mesh(geo, mat);
      if (pos) m.position.set(...pos);
      if (rot) m.rotation.set(...rot);
      if (scl) m.scale.set(...scl);
      if (castShadow) { m.castShadow = true; m.receiveShadow = true; }
      (parent || kangaroo).add(m);
      return m;
    }

    /* ── Body ── */
    const bodyGroup = new THREE.Group();
    bodyGroup.position.set(0, 2.0, 0);
    kangaroo.add(bodyGroup);

    // Torso
    addMesh(new THREE.SphereGeometry(1, 24, 18), bodyMat, bodyGroup, [0, 0, 0], null, [1, 1.15, 0.85]);
    // Chest (lighter)
    addMesh(new THREE.SphereGeometry(0.7, 18, 14), lightMat, bodyGroup, [0, 0.1, 0.55], null, [0.9, 1, 0.6]);

    /* ── Tail ── */
    const tailGroup = new THREE.Group();
    tailGroup.position.set(0, 1.2, -0.6);
    kangaroo.add(tailGroup);

    // Tail segments (curved)
    const tailSegments = 8;
    for (let i = 0; i < tailSegments; i++) {
      const t = i / tailSegments;
      const r = 0.35 * (1 - t * 0.55);
      const seg = addMesh(
        new THREE.SphereGeometry(1, 12, 10),
        darkMat, tailGroup,
        [Math.sin(t * 0.3) * 0.2, -t * 2.2, -t * 1.8],
        null, [r, r * 0.9, r * 0.7]
      );
    }

    /* ── Head ── */
    const headGroup = new THREE.Group();
    headGroup.position.set(0, 3.1, 0.55);
    kangaroo.add(headGroup);

    // Skull
    addMesh(new THREE.SphereGeometry(1, 20, 16), bodyMat, headGroup, [0, 0, 0], null, [0.65, 0.6, 0.7]);
    // Snout
    addMesh(new THREE.SphereGeometry(1, 16, 12), lightMat, headGroup, [0, -0.15, 0.45], null, [0.45, 0.35, 0.5]);
    // Nose
    addMesh(new THREE.SphereGeometry(0.14, 10, 8), noseMat, headGroup, [0, -0.1, 0.82], null, [1, 0.7, 0.8]);
    // Mouth line
    addMesh(new THREE.BoxGeometry(0.3, 0.03, 0.02), noseMat, headGroup, [0, -0.25, 0.72]);

    // Eyes
    addMesh(new THREE.SphereGeometry(0.12, 10, 8), eyeWhite, headGroup, [-0.32, 0.12, 0.42]);
    addMesh(new THREE.SphereGeometry(0.08, 8, 6), eyeMat, headGroup, [-0.32, 0.12, 0.5]);
    addMesh(new THREE.SphereGeometry(0.12, 10, 8), eyeWhite, headGroup, [0.32, 0.12, 0.42]);
    addMesh(new THREE.SphereGeometry(0.08, 8, 6), eyeMat, headGroup, [0.32, 0.12, 0.5]);

    // Ears
    addMesh(new THREE.CylinderGeometry(0.08, 0.14, 0.5, 8), bodyMat, headGroup, [-0.35, 0.55, 0], [0.3, 0, -0.2]);
    addMesh(new THREE.CylinderGeometry(0.05, 0.1, 0.35, 8), innerEar, headGroup, [-0.35, 0.53, 0.02], [0.3, 0, -0.2]);
    addMesh(new THREE.CylinderGeometry(0.08, 0.14, 0.5, 8), bodyMat, headGroup, [0.35, 0.55, 0], [0.3, 0, 0.2]);
    addMesh(new THREE.CylinderGeometry(0.05, 0.1, 0.35, 8), innerEar, headGroup, [0.35, 0.53, 0.02], [0.3, 0, 0.2]);

    /* ── Hind Legs (powerful!) ── */
    const leftLegGroup = new THREE.Group();
    leftLegGroup.position.set(-0.45, 0.8, 0.2);
    kangaroo.add(leftLegGroup);

    const rightLegGroup = new THREE.Group();
    rightLegGroup.position.set(0.45, 0.8, 0.2);
    kangaroo.add(rightLegGroup);

    function buildLeg(legGroup, side) {
      // Upper thigh
      addMesh(new THREE.CylinderGeometry(0.28, 0.22, 1.2, 10), bodyMat, legGroup, [0, 0.5, 0], [side * 0.15, 0, 0]);
      // Lower shin
      addMesh(new THREE.CylinderGeometry(0.2, 0.15, 1.0, 10), darkMat, legGroup, [side * 0.05, -0.15, 0.25], [side * 0.2, 0, 0]);
      // Foot
      addMesh(new THREE.BoxGeometry(0.28, 0.12, 0.6), footMat, legGroup, [side * 0.05, -0.68, 0.45]);
      // Toes
      for (let i = -1; i <= 1; i++) {
        addMesh(new THREE.CylinderGeometry(0.04, 0.03, 0.15, 6), footMat,
          legGroup, [side * 0.05 + i * 0.08, -0.78, 0.55], [Math.PI / 2, 0, 0]);
      }
    }

    buildLeg(leftLegGroup, -1);
    buildLeg(rightLegGroup, 1);

    /* ── Front Arms ── */
    const leftArmGroup = new THREE.Group();
    leftArmGroup.position.set(-0.55, 2.2, 0.5);
    kangaroo.add(leftArmGroup);

    const rightArmGroup = new THREE.Group();
    rightArmGroup.position.set(0.55, 2.2, 0.5);
    kangaroo.add(rightArmGroup);

    function buildArm(armGroup, side) {
      addMesh(new THREE.CylinderGeometry(0.08, 0.06, 0.8, 8), darkMat, armGroup, [0, -0.3, 0.1], [side * 0.3, 0, 0]);
      addMesh(new THREE.CylinderGeometry(0.06, 0.05, 0.6, 8), bodyMat, armGroup, [side * 0.05, -0.7, 0.25], [side * 0.4, 0, 0]);
      // Hand/claw
      addMesh(new THREE.SphereGeometry(0.07, 8, 6), footMat, armGroup, [side * 0.05, -1.0, 0.35]);
    }

    buildArm(leftArmGroup, -1);
    buildArm(rightArmGroup, 1);

    /* ── Animation ── */
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle hop
      const hop = Math.abs(Math.sin(t * 2.5)) * 0.15;
      const hopVel = Math.cos(t * 2.5) * 2.5;

      kangaroo.position.y = hop;

      // Subtle body tilt
      bodyGroup.rotation.x = Math.sin(t * 2.5) * 0.05;
      headGroup.rotation.x = Math.sin(t * 2.5) * 0.03;

      // Tail sway
      tailGroup.rotation.z = Math.sin(t * 1.8) * 0.08;

      // Ear twitch
      const twitch = Math.sin(t * 8) > 0.95 ? 0.15 : 0;
      headGroup.children[6].rotation.z = -0.2 + twitch; // left ear
      headGroup.children[8].rotation.z = 0.2 - twitch;  // right ear

      // Breathing
      bodyGroup.scale.y = 1 + Math.sin(t * 3) * 0.015;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    /* ── Resize ── */
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's Inside

| Feature | Details |
|---|---|
| **Procedural kangaroo** | Built entirely from `SphereGeometry`, `CylinderGeometry`, and `BoxGeometry`

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Kite</title>
<style>
* { margin: 0; padding: 0; overflow: hidden; }
body { background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.012);

const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 2, 12);
camera.lookAt(0, 0, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

// Lighting
const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xfff4e0, 1.2);
sunLight.position.set(10, 20, 10);
sunLight.castShadow = true;
scene.add(sunLight);

const backLight = new THREE.DirectionalLight(0x8ec8f0, 0.4);
backLight.position.set(-5, 5, -10);
scene.add(backLight);

// ── Kite Group ──
const kite = new THREE.Group();
scene.add(kite);

// Diamond kite body (thin extruded diamond)
const kiteShape = new THREE.Shape();
kiteShape.moveTo(0, 3.5);
kiteShape.lineTo(2.2, 0);
kiteShape.lineTo(0, -4.5);
kiteShape.lineTo(-2.2, 0);
kiteShape.closePath();

const extrudeSettings = { depth: 0.25, bevelEnabled: true, bevelThickness: 0.15, bevelSize: 0.15, bevelSegments: 3 };
const kiteGeom = new THREE.ExtrudeGeometry(kiteShape, extrudeSettings);
kiteGeom.center();

const kiteMat = new THREE.MeshStandardMaterial({
  color: 0xff4466,
  roughness: 0.4,
  metalness: 0.1,
  side: THREE.DoubleSide,
  transparent: true,
  opacity: 0.92
});
const kiteMesh = new THREE.Mesh(kiteGeom, kiteMat);
kiteMesh.castShadow = true;
kite.add(kiteMesh);

// Back face (slightly different shade)
const backMat = new THREE.MeshStandardMaterial({
  color: 0xee2244,
  roughness: 0.5,
  side: THREE.BackSide,
  transparent: true,
  opacity: 0.85
});

// Cross sticks
const stickMat = new THREE.MeshStandardMaterial({ color: 0xc8a050, roughness: 0.7 });

const vStick = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 8, 8), stickMat);
vStick.position.z = 0.1;
kite.add(vStick);

const hStick = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 4.4, 8), stickMat);
hStick.rotation.z = Math.PI / 2;
hStick.position.set(0, 0.2, 0.1);
kite.add(hStick);

// String attachment point (small ring)
const ringGeom = new THREE.TorusGeometry(0.12, 0.025, 8, 16);
const ringMat = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.8, roughness: 0.2 });
const ring = new THREE.Mesh(ringGeom, ringMat);
ring.position.set(0, 3.5, 0.1);
kite.add(ring);

// ── Tail ──
const tailSegments = 24;
const tailPoints = [];
const tailGroup = new THREE.Group();
kite.add(tailGroup);

for (let i = 0; i < tailSegments; i++) {
  const t = i / tailSegments;
  const size = 0.35 * (1 - t * 0.7);
  const colors = [0xff6633, 0xffcc00, 0x33cc33, 0x3399ff, 0xcc33ff];
  const color = colors[i % colors.length];

  const seg = new THREE.Mesh(
    new THREE.SphereGeometry(size, 8, 6),
    new THREE.MeshStandardMaterial({ color, roughness: 0.5 })
  );
  seg.position.y = -4.5 - i * 0.55;
  seg.castShadow = true;
  tailGroup.add(seg);
  tailPoints.push(seg);
}

// Connecting tail string
const tailCurve = new THREE.CatmullRomCurve3(tailPoints.map(p => p.position));
const tailLineGeom = new THREE.TubeGeometry(tailCurve, 48, 0.02, 6, false);
const tailLine = new THREE.Mesh(tailLineGeom, new THREE.MeshStandardMaterial({ color: 0x555555 }));
kite.add(tailLine);

// ── Main String ──
const stringCurve = new THREE.QuadraticBezierCurve3(
  new THREE.Vector3(0, 3.5, 0),
  new THREE.Vector3(0.5, 8, 0),
  new THREE.Vector3(0, 18, 0)
);
const stringGeom = new THREE.TubeGeometry(stringCurve, 32, 0.015, 6, false);
const stringMesh = new THREE.Mesh(stringGeom, new THREE.MeshStandardMaterial({ color: 0xdddddd }));
kite.add(stringMesh);

// ── Clouds ──
function makeCloud(x, y, z, scale) {
  const cloud = new THREE.Group();
  const mat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 1, flatShading: true });
  const blobs = [
    { r: 1.5, p: [0, 0, 0] },
    { r: 1.2, p: [1.5, 0.2, 0.3] },
    { r: 1.0, p: [-1.3, -0.1, -0.2] },
    { r: 0.9, p: [0.8, 0.6, -0.1] },
    { r: 1.1, p: [-0.6, 0.4, 0.2] },
  ];
  blobs.forEach(b => {
    const m = new THREE.Mesh(new THREE.SphereGeometry(b.r, 8, 6), mat);
    m.position.set(...b.p);
    cloud.add(m);
  });
  cloud.position.set(x, y, z);
  cloud.scale.setScalar(scale);
  return cloud;
}

const clouds = [];
[
  [15, 12, -20, 2], [-18, 16, -15, 1.5], [10, 8, -30, 1.8],
  [-12, 20, -25, 2.2], [25, 14, -18, 1.3]
].forEach(c => {
  const cl = makeCloud(...c);
  scene.add(cl);
  clouds.push(cl);
});

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(200, 200),
  new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -12;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle kite swaying
  kite.rotation.z = Math.sin(t * 0.7) * 0.08;
  kite.rotation.x = Math.sin(t * 0.5) * 0.04;
  kite.position.y = Math.sin(t * 0.9) * 0.3;
  kite.position.x = Math.sin(t * 0.3) * 0.2;

  // Tail wave
  tailPoints.forEach((seg, i) => {
    const phase = i * 0.4;
    seg.position.x = Math.sin(t * 1.5 + phase) * 0.6;
    seg.position.z = Math.cos(t * 1.2 + phase) * 0.3;
  });

  // Update tail curve
  tailLine.geometry.dispose();
  const updatedCurve = new THREE.CatmullRomCurve3(tailPoints.map(p => p.position));
  tailLine.geometry = new THREE.TubeGeometry(updatedCurve, 48, 0.02, 6, false);

  // Drift clouds
  clouds.forEach((cl, i) => {
    cl.position.x += 0.008 + i * 0.002;
    if (cl.position.x > 40) cl.position.x = -40;
  });

  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

- **Diamond kite body** — an extruded 2D diamond shape with bevel, semi-transparent red material
- **Cross sticks** — vertical and horizontal wooden-colored cylinders
- **Attachment ring** — small metallic torus at the top
- **Flowing tail** — 24 colorful sphere segments connected by a dynamically updated tube string
- **Main string** — quadratic Bézier curve extending upward
- **Clouds** — clustered sphere puffs that drift across the sky
- **Ground plane** — green surface below
- **Animation** — gentle swaying/rocking of the kite, sinusoidal tail wave, drifting clouds
- **Lighting** — ambient + directional sun + back fill light with fog

