* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.5, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;

// ── Lighting ──
const ambient = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(5, 8, 3);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 20;
sun.shadow.camera.left = -5;
sun.shadow.camera.right = 5;
sun.shadow.camera.top = 5;
sun.shadow.camera.bottom = -5;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8899ff, 0.6);
fill.position.set(-4, 3, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff9944, 1.5, 10);
rim.position.set(-2, 2, -3);
scene.add(rim);

// ── Materials ──
const twigMats = [
  new THREE.MeshStandardMaterial({ color: 0x8B6914, roughness: 0.9, metalness: 0.0 }),
  new THREE.MeshStandardMaterial({ color: 0x6B4F1D, roughness: 0.85, metalness: 0.0 }),
  new THREE.MeshStandardMaterial({ color: 0x9B7934, roughness: 0.95, metalness: 0.0 }),
  new THREE.MeshStandardMaterial({ color: 0x7B5B2D, roughness: 0.88, metalness: 0.0 }),
  new THREE.MeshStandardMaterial({ color: 0xA08030, roughness: 0.92, metalness: 0.0 }),
];

const mossMat = new THREE.MeshStandardMaterial({ color: 0x4a6b2f, roughness: 1.0, metalness: 0.0 });
const eggMat = new THREE.MeshStandardMaterial({ color: 0xf5f0e0, roughness: 0.3, metalness: 0.05 });
const eggMat2 = new THREE.MeshStandardMaterial({ color: 0xe8ddd0, roughness: 0.35, metalness: 0.05 });
const groundMat = new THREE.MeshStandardMaterial({ color: 0x2a3a1a, roughness: 1.0, metalness: 0.0 });

// ── Nest Building ──
const nestGroup = new THREE.Group();
scene.add(nestGroup);

function createTwig(length, radius, material) {
  const geo = new THREE.CylinderGeometry(radius * 0.7, radius, length, 6, 1);
  const mesh = new THREE.Mesh(geo, material);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  return mesh;
}

// Concentric ring layers
const rings = 6;
const twigsPerRing = [12, 16, 20, 22, 18, 14];
const ringRadii = [1.0, 1.1, 1.15, 1.1, 1.0, 0.85];
const ringHeights = [0.0, 0.12, 0.22, 0.28, 0.2, 0.1];

for (let r = 0; r < rings; r++) {
  const count = twigsPerRing[r];
  const radius = ringRadii[r];
  const yBase = ringHeights[r];
  const wallTilt = 0.3 + r * 0.08;

  for (let i = 0; i < count; i++) {
    const angle = (i / count) * Math.PI * 2 + (r % 2) * (Math.PI / count);
    const jitter = (Math.random() - 0.5) * 0.08;
    const rJitter = radius + jitter;

    const twigLen = 0.45 + Math.random() * 0.25;
    const twigRad = 0.015 + Math.random() * 0.02;
    const mat = twigMats[Math.floor(Math.random() * twigMats.length)];

    const twig = createTwig(twigLen, twigRad, mat);

    const x = Math.cos(angle) * rJitter;
    const z = Math.sin(angle) * rJitter;
    const y = yBase + (Math.random() - 0.3) * 0.08;

    twig.position.set(x, y, z);

    // Tilt outward to form bowl shape
    twig.rotation.z = Math.cos(angle) * wallTilt + (Math.random() - 0.5) * 0.2;
    twig.rotation.x = -Math.sin(angle) * wallTilt + (Math.random() - 0.5) * 0.2;
    twig.rotation.y = angle + (Math.random() - 0.5) * 0.4;

    nestGroup.add(twig);
  }
}

// Cross-weave twigs (horizontal overlaps)
for (let i = 0; i < 30; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 0.3 + Math.random() * 0.7;
  const y = 0.05 + Math.random() * 0.25;

  const twigLen = 0.3 + Math.random() * 0.4;
  const twigRad = 0.01 + Math.random() * 0.015;
  const mat = twigMats[Math.floor(Math.random() * twigMats.length)];

  const twig = createTwig(twigLen, twigRad, mat);
  twig.position.set(
    Math.cos(angle) * radius,
    y,
    Math.sin(angle) * radius
  );
  twig.rotation.set(
    (Math.random() - 0.5) * 1.2,
    angle + Math.random() * 0.5,
    (Math.random() - 0.5) * 0.8
  );
  nestGroup.add(twig);
}

// Moss/vegetation accents
for (let i = 0; i < 25; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 0.8 + Math.random() * 0.35;
  const y = 0.15 + Math.random() * 0.15;

  const size = 0.04 + Math.random() * 0.06;
  const geo = new THREE.SphereGeometry(size, 5, 4);
  const moss = new THREE.Mesh(geo, mossMat);
  moss.position.set(
    Math.cos(angle) * radius,
    y,
    Math.sin(angle) * radius
  );
  moss.scale.y = 0.5;
  moss.castShadow = true;
  nestGroup.add(moss);
}

// ── Eggs ──
const eggGeo = new THREE.SphereGeometry(1, 16, 12);
eggGeo.scale(0.65, 0.9, 0.65);

const eggs = [
  { pos: [-0.25, 0.15, 0.15], rot: [0.3, 0.2, -0.2], mat: eggMat, scale: 0.18 },
  { pos: [0.2, 0.14, -0.1], rot: [-0.2, -0.3, 0.3], mat: eggMat2, scale: 0.16 },
  { pos: [0.05, 0.16, 0.3], rot: [0.15, 0.5, 0.1], mat: eggMat, scale: 0.17 },
];

eggs.forEach(e => {
  const egg = new THREE.Mesh(eggGeo, e.mat);
  egg.position.set(...e.pos);
  egg.rotation.set(...e.rot);
  egg.scale.setScalar(e.scale);
  egg.castShadow = true;
  egg.receiveShadow = true;
  nestGroup.add(egg);
});

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(8, 32),
  groundMat
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.3;
ground.receiveShadow = true;
scene.add(ground);

// ── Branch the nest sits on ──
const branchGeo = new THREE.CylinderGeometry(0.12, 0.15, 6, 8);
const branch = new THREE.Mesh(branchGeo, twigMats[1]);
branch.rotation.z = Math.PI / 2;
branch.rotation.y = 0.15;
branch.position.set(0, -0.2, 0);
branch.castShadow = true;
branch.receiveShadow = true;
scene.add(branch);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle nest sway
  nestGroup.rotation.z = Math.sin(t * 0.5) * 0.015;
  nestGroup.rotation.x = Math.cos(t * 0.3) * 0.01;
  nestGroup.position.y = Math.sin(t * 0.8) * 0.02;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
