import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.012);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 3, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.5, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.update();

// ── Lighting ──
scene.add(new THREE.AmbientLight(0x406040, 0.8));
const dirLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
dirLight.position.set(5, 10, 7);
scene.add(dirLight);
const fillLight = new THREE.DirectionalLight(0x80c0ff, 0.6);
fillLight.position.set(-4, 3, -5);
scene.add(fillLight);
const rimLight = new THREE.PointLight(0xff9944, 1.0, 20);
rimLight.position.set(-3, 6, -4);
scene.add(rimLight);

// ── Helpers ──
const GOLDEN_ANGLE = Math.PI * (3 - Math.sqrt(5)); // ~137.5°
function fibonacciPoint(i, total) {
  const y = 1 - (i / (total - 1)) * 2; // -1 to 1
  const radius = Math.sqrt(1 - y * y);
  const theta = GOLDEN_ANGLE * i;
  return {
    x: Math.cos(theta) * radius,
    y: y,
    z: Math.sin(theta) * radius,
  };
}

function leafShape(depth) {
  const s = new THREE.Shape();
  const w = 0.12 + depth * 0.06;
  const h = 1.0 + depth * 0.4;
  const tip = 0.03 + depth * 0.02;
  s.moveTo(0, h);
  s.bezierCurveTo(tip, h * 0.7, w * 0.9, h * 0.5, w * 0.85, h * 0.2);
  s.bezierCurveTo(w * 0.7, -h * 0.1, w * 0.3, -h * 0.3, 0, -h * 0.35);
  s.bezierCurveTo(-w * 0.3, -h * 0.3, -w * 0.7, -h * 0.1, -w * 0.85, h * 0.2);
  s.bezierCurveTo(-w * 0.9, h * 0.5, -tip, h * 0.7, 0, h);
  return s;
}

function makeBract(depth) {
  const shape = leafShape(depth);
  const extrudeSettings = {
    depth: 0.03 + depth * 0.015,
    bevelEnabled: true,
    bevelThickness: 0.02,
    bevelSize: 0.02,
    bevelSegments: 2,
    curveSegments: 8,
  };
  const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);
  geo.center();
  return geo;
}

// ── Artichoke Group ──
const artichoke = new THREE.Group();
scene.add(artichoke);

// Body (inner heart)
const bodyGeo = new THREE.SphereGeometry(1, 32, 32);
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0x5a8a3a, roughness: 0.7, metalness: 0.05,
});
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.scale.set(0.85, 1.1, 0.85);
body.position.y = 1.2;
artichoke.add(body);

// ── Bracts in layers ──
const bractMaterials = [];
for (let i = 0; i < 5; i++) {
  const g = 0.18 + i * 0.06;
  const r = 0.12 + i * 0.04;
  bractMaterials.push(new THREE.MeshStandardMaterial({
    color: new THREE.Color(r, g, r * 0.5),
    roughness: 0.65,
    metalness: 0.02,
    side: THREE.DoubleSide,
  }));
}

const LAYERS = [
  { count: 10, radius: 0.95,  depth: 0,  spread: 0.35 },
  { count: 14, radius: 1.05,  depth: 0.4, spread: 0.55 },
  { count: 18, radius: 1.15,  depth: 0.7, spread: 0.75 },
  { count: 22, radius: 1.25,  depth: 1.0, spread: 1.0  },
  { count: 26, radius: 1.38,  depth: 1.3, spread: 1.25 },
];

const bractGeos = LAYERS.map(l => makeBract(l.depth));

LAYERS.forEach((layer, li) => {
  for (let i = 0; i < layer.count; i++) {
    const p = fibonacciPoint(i, layer.count);

    const bract = new THREE.Mesh(bractGeos[li], bractMaterials[li]);

    const r = layer.radius;
    const pos = new THREE.Vector3(p.x * r, p.y * r * 1.1 + 1.2, p.z * r);
    bract.position.copy(pos);

    // Orient outward from center
    const normal = new THREE.Vector3(p.x, p.y * 1.1, p.z).normalize();
    bract.lookAt(pos.clone().add(normal));

    // Tilt outward based on layer
    const tilt = layer.spread * (0.3 + Math.abs(p.y) * 0.5);
    bract.rotateX(tilt * (p.y > 0 ? 1 : -1));

    // Slight random rotation for organic feel
    bract.rotateZ((Math.random() - 0.5) * 0.15);

    artichoke.add(bract);
  }
});

// ── Stem ──
const stemGeo = new THREE.CylinderGeometry(0.15, 0.22, 2.5, 12);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x4a7a30, roughness: 0.8, metalness: 0.05,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.y = -0.05;
artichoke.add(stem);

// Stem leaf
const stemLeafGeo = leafShape(0.6);
const stemLeafMat = new THREE.MeshStandardMaterial({
  color: 0x5a9a3a, roughness: 0.6, side: THREE.DoubleSide,
});
const stemLeaf = new THREE.Mesh(
  new THREE.ExtrudeGeometry(stemLeafGeo, {
    depth: 0.025, bevelEnabled: true, bevelThickness: 0.015,
    bevelSize: 0.015, bevelSegments: 2, curveSegments: 6,
  }),
  stemLeafMat
);
stemLeaf.position.set(0.2, 0.3, 0);
stemLeaf.rotation.set(-0.5, 0.8, 0.6);
stemLeaf.scale.setScalar(0.7);
artichoke.add(stemLeaf);

// ── Small base leaves ──
for (let i = 0; i < 3; i++) {
  const angle = (i / 3) * Math.PI * 2 + 0.5;
  const leafGeo = leafShape(0.3 + Math.random() * 0.3);
  const leaf = new THREE.Mesh(
    new THREE.ExtrudeGeometry(leafGeo, {
      depth: 0.02, bevelEnabled: true, bevelThickness: 0.012,
      bevelSize: 0.012, bevelSegments: 2, curveSegments: 6,
    }),
    new THREE.MeshStandardMaterial({
      color: new THREE.Color(0.2 + Math.random() * 0.05, 0.35 + Math.random() * 0.1, 0.12),
      roughness: 0.7, side: THREE.DoubleSide,
    })
  );
  leaf.position.set(Math.cos(angle) * 0.3, -0.2 + i * 0.15, Math.sin(angle) * 0.3);
  leaf.rotation.set(-0.8 - Math.random() * 0.3, angle, 0.4);
  leaf.scale.setScalar(0.5 + Math.random() * 0.2);
  artichoke.add(leaf);
}

// ── Ground shadow ──
const shadowGeo = new THREE.CircleGeometry(2.5, 32);
const shadowMat = new THREE.MeshBasicMaterial({
  color: 0x000000, transparent: true, opacity: 0.25,
});
const shadow = new THREE.Mesh(shadowGeo, shadowMat);
shadow.rotation.x = -Math.PI / 2;
shadow.position.y = -1.3;
scene.add(shadow);

// ── Ground plane ──
const groundGeo = new THREE.PlaneGeometry(60, 60);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a2a1a, roughness: 1, metalness: 0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.35;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  artichoke.rotation.y = Math.sin(t * 0.15) * 0.15;
  artichoke.position.y = Math.sin(t * 0.4) * 0.08;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single-file demo features:

- **Procedural artichoke** built from a central heart (ellipsoid) surrounded by **5 layers of bracts** (10→26 per layer) arranged using the **Fibonacci golden angle** (137.5°), mimicking real phyllotaxis
- **Leaf-shaped bracts** created with `THREE.Shape` + bezier curves, extruded for thickness with beveled edges
- **A stem** with small base leaves for realism
- **Three-point lighting** (key, fill, rim) with ACES filmic tone mapping
- **Gentle floating animation** — the artichoke slowly bobs and sways
- **OrbitControls** — drag to rotate, scroll to zoom
- **Ground plane** with a soft shadow disc

