<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// Renderer
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// Scene
const scene = new THREE.Scene();

// Camera
const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
camera.position.set(0, 0, 3.2);

// Controls
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.minDistance = 1.5;
controls.maxDistance = 8;
controls.enablePan = false;

// Stars
const starGeo = new THREE.BufferGeometry();
const starCount = 6000;
const starPos = new Float32Array(starCount * 3);
for (let i = 0; i < starCount * 3; i++) starPos[i] = (Math.random() - 0.5) * 200;
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
const starMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.15, sizeAttenuation: true });
scene.add(new THREE.Points(starGeo, starMat));

// Earth
const loader = new THREE.TextureLoader();
const earthGroup = new THREE.Group();
scene.add(earthGroup);

const earthGeo = new THREE.SphereGeometry(1, 64, 64);

// Load textures with procedural fallback
const earthTexture = loader.load(
  'https://unpkg.com/three-globe@2.31.1/example/img/earth-blue-marble.jpg',
  null, null, () => {
    // Fallback: procedural earth texture
    const canvas = document.createElement('canvas');
    canvas.width = 1024; canvas.height = 512;
    const ctx = canvas.getContext('2d');
    const grad = ctx.createLinearGradient(0, 0, 0, 512);
    grad.addColorStop(0, '#1a3a5c');
    grad.addColorStop(0.3, '#1565C0');
    grad.addColorStop(0.5, '#1976D2');
    grad.addColorStop(0.7, '#1565C0');
    grad.addColorStop(1, '#1a3a5c');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 1024, 512);
    // Simple continent shapes
    ctx.fillStyle = '#2E7D32';
    const continents = [
      [250,120,120,100],[400,100,80,60],[550,80,100,120],
      [200,250,100,80],[450,200,60,100],[600,220,80,60],
      [300,320,150,50],[500,300,100,80],[700,150,60,80]
    ];
    continents.forEach(([x,y,w,h]) => {
      ctx.beginPath();
      ctx.ellipse(x, y, w/2, h/2, Math.random()*0.5, 0, Math.PI*2);
      ctx.fill();
    });
    earthTexture.image = canvas;
    earthTexture.needsUpdate = true;
  }
);

const bumpTexture = loader.load(
  'https://unpkg.com/three-globe@2.31.1/example/img/earth-topology.png',
  null, null, () => {
    const canvas = document.createElement('canvas');
    canvas.width = 512; canvas.height = 256;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#808080';
    ctx.fillRect(0, 0, 512, 256);
    bumpTexture.image = canvas;
    bumpTexture.needsUpdate = true;
  }
);

const earthMat = new THREE.MeshPhongMaterial({
  map: earthTexture,
  bumpMap: bumpTexture,
  bumpScale: 0.03,
  specular: new THREE.Color(0x333333),
  shininess: 15,
});

const earth = new THREE.Mesh(earthGeo, earthMat);
earthGroup.add(earth);

// Atmosphere glow
const atmosphereVertexShader = `
  varying vec3 vNormal;
  varying vec3 vPosition;
  void main() {
    vNormal = normalize(normalMatrix * normal);
    vPosition = (modelViewMatrix * vec4(position, 1.0)).xyz;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const atmosphereFragmentShader = `
  varying vec3 vNormal;
  varying vec3 vPosition;
  void main() {
    vec3 viewDir = normalize(-vPosition);
    float intensity = pow(0.72 - dot(vNormal, viewDir), 3.0);
    gl_FragColor = vec4(0.3, 0.6, 1.0, 1.0) * intensity * 1.5;
  }
`;

const atmosphereMat = new THREE.ShaderMaterial({
  vertexShader: atmosphereVertexShader,
  fragmentShader: atmosphereFragmentShader,
  side: THREE.FrontSide,
  blending: THREE.AdditiveBlending,
  transparent: true,
  depthWrite: false,
});

const atmosphere = new THREE.Mesh(
  new THREE.SphereGeometry(1.15, 64, 64),
  atmosphereMat
);
earthGroup.add(atmosphere);

// Outer glow
const outerGlowShader = `
  varying vec3 vNormal;
  varying vec3 vPosition;
  void main() {
    vNormal = normalize(normalMatrix * normal);
    vPosition = (modelViewMatrix * vec4(position, 1.0)).xyz;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;
const outerGlowFrag = `
  varying vec3 vNormal;
  varying vec3 vPosition;
  void main() {
    vec3 viewDir = normalize(-vPosition);
    float rim = 1.0 - max(0.0, dot(viewDir, vNormal));
    float glow = pow(rim, 2.0) * 0.8;
    gl_FragColor = vec4(0.3, 0.6, 1.0, glow);
  }
`;

const outerGlow = new THREE.Mesh(
  new THREE.SphereGeometry(1.35, 64, 64),
  new THREE.ShaderMaterial({
    vertexShader: outerGlowShader,
    fragmentShader: outerGlowFrag,
    side: THREE.BackSide,
    blending: THREE.AdditiveBlending,
    transparent: true,
    depthWrite: false,
  })
);
earthGroup.add(outerGlow);

// Lighting
const ambientLight = new THREE.AmbientLight(0x333344, 1.5);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xffffff, 3);
sunLight.position.set(5, 3, 5);
scene.add(sunLight);

const fillLight = new THREE.DirectionalLight(0x4466aa, 0.5);
fillLight.position.set(-5, -2, -3);
scene.add(fillLight);

// Grid lines (latitude/longitude)
const gridMat = new THREE.LineBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.06 });

for (let lat = -60; lat <= 60; lat += 30) {
  const r = Math.cos(lat * Math.PI / 180);
  const y = Math.sin(lat * Math.PI / 180);
  const points = [];
  for (let i = 0; i <= 128; i++) {
    const a = (i / 128) * Math.PI * 2;
    points.push(new THREE.Vector3(Math.cos(a) * r, y, Math.sin(a) * r));
  }
  earthGroup.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(points), gridMat));
}

for (let lon = 0; lon < 360; lon += 30) {
  const points = [];
  for (let i = 0; i <= 128; i++) {
    const a = (i / 128) * Math.PI * 2;
    points.push(new THREE.Vector3(
      Math.cos(a) * Math.cos(lon * Math.PI / 180),
      Math.sin(a),
      Math.cos(a) * Math.sin(lon * Math.PI / 180)
    ));
  }
  earthGroup.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(points), gridMat));
}

// Tilt earth axis
earthGroup.rotation.x = 23.5 * Math.PI / 180;

// Animation
function animate() {
  requestAnimationFrame(animate);
  earth.rotation.y += 0.001;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// Resize
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
