<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js", "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/" } }
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 3, 4);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// --- Lighting ---
const ambient = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0xff8844, 1.0);
rimLight.position.set(-4, 2, -3);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffcc88, 0.8, 10);
pointLight.position.set(0, 3, 0);
scene.add(pointLight);

// --- Bagel ---
const bagelGroup = new THREE.Group();
scene.add(bagelGroup);

// Main torus
const bagelGeo = new THREE.TorusGeometry(1.2, 0.5, 64, 128);
const bagelMat = new THREE.MeshStandardMaterial({
  color: 0xc4813a,
  roughness: 0.75,
  metalness: 0.0,
  bumpScale: 0.02,
});

// Procedural bump texture for bagel surface
const bumpCanvas = document.createElement('canvas');
bumpCanvas.width = 512; bumpCanvas.height = 512;
const bCtx = bumpCanvas.getContext('2d');
bCtx.fillStyle = '#808080';
bCtx.fillRect(0, 0, 512, 512);
for (let i = 0; i < 8000; i++) {
  const x = Math.random() * 512, y = Math.random() * 512;
  const r = Math.random() * 3 + 1;
  const v = Math.floor(Math.random() * 60 + 98);
  bCtx.fillStyle = `rgb(${v},${v},${v})`;
  bCtx.beginPath();
  bCtx.arc(x, y, r, 0, Math.PI * 2);
  bCtx.fill();
}
const bumpTex = new THREE.CanvasTexture(bumpCanvas);
bumpTex.wrapS = bumpTex.wrapT = THREE.RepeatWrapping;
bumpTex.repeat.set(4, 2);
bagelMat.bumpMap = bumpTex;

const bagel = new THREE.Mesh(bagelGeo, bagelMat);
bagel.rotation.x = Math.PI * 0.15;
bagelGroup.add(bagel);

// --- Seeds (sesame) ---
const seedGeo = new THREE.SphereGeometry(0.025, 6, 4);
const seedMat = new THREE.MeshStandardMaterial({ color: 0xf5deb3, roughness: 0.9 });
const seedMesh = new THREE.InstancedMesh(seedGeo, seedMat, 300);

const dummy = new THREE.Object3D();
const color = new THREE.Color();

for (let i = 0; i < 300; i++) {
  // Parametric torus: u goes around the ring, v goes around the tube cross-section
  const u = Math.random() * Math.PI * 2;
  const v = Math.random() * Math.PI * 2;

  // Only place seeds on top half of the bagel surface
  const vFiltered = v;
  const sinV = Math.sin(vFiltered);
  if (sinV < 0.15) { i--; continue; }

  const R = 1.2, r = 0.5;
  const px = (R + r * Math.cos(vFiltered)) * Math.cos(u);
  const py = r * sinV;
  const pz = (R + r * Math.cos(vFiltered)) * Math.sin(u);

  // Apply the same tilt as the bagel
  const tilt = Math.PI * 0.15;
  const tpy = py * Math.cos(tilt) - pz * Math.sin(tilt);
  const tpz = py * Math.sin(tilt) + pz * Math.cos(tilt);

  dummy.position.set(px, tpy, tpz);

  // Orient seeds roughly along surface
  dummy.lookAt(
    px + px * 0.1,
    tpy + 1,
    tpz + pz * 0.1
  );

  // Randomize seed size slightly
  const s = 0.6 + Math.random() * 0.8;
  dummy.scale.set(s, s * 0.4, s);
  dummy.rotation.z = Math.random() * Math.PI;

  dummy.updateMatrix();
  seedMesh.setMatrixAt(i, dummy.matrix);

  // Slight color variation
  color.setHSL(0.08 + Math.random() * 0.04, 0.3 + Math.random() * 0.2, 0.75 + Math.random() * 0.15);
  seedMesh.setColorAt(i, color);
}

seedMesh.instanceMatrix.needsUpdate = true;
if (seedMesh.instanceColor) seedMesh.instanceColor.needsUpdate = true;
bagelGroup.add(seedMesh);

// --- Plate ---
const plateGeo = new THREE.CylinderGeometry(2.2, 2.0, 0.08, 64);
const plateMat = new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.3, metalness: 0.1 });
const plate = new THREE.Mesh(plateGeo, plateMat);
plate.position.y = -0.6;
