// ── Balloon Body (custom lathe profile) ────────────────
const profile = [];
const steps = 30;
for (let i = 0; i <= steps; i++) {
  const t = i / steps;
  const angle = t * Math.PI;
  // Shape: wide balloon that tapers at top and bottom
  let r = Math.sin(angle) * Math.sin(angle) * 1.6;
  // Slight elongation
  const y = (t - 0.5) * 2.8;
  profile.push(new THREE.Vector2(r, y));
}

const balloonGeo = new THREE.LatheGeometry(profile, 48);
const balloonMat = new THREE.MeshPhysicalMaterial({
  color: 0xe63946,
  roughness: 0.15,
  metalness: 0.0,
  clearcoat: 0.8,
  clearcoatRoughness: 0.1,
  reflectivity: 0.6,
