// ── String ─────────────────────────────────────────────
const stringPoints = [];
for (let i = 0; i <= 20; i++) {
  const t = i / 20;
  const x = Math.sin(t * Math.PI * 1.5) * 0.15;
  const z = Math.cos(t * Math.PI * 1.2) * 0.08;
  stringPoints.push(new THREE.Vector3(x, -1.5 - t * 2.5, z));
}
const stringCurve = new THREE.CatmullRomCurve3(stringPoints);
const stringGeo = new THREE.TubeGeometry(stringCurve, 32, 0.008, 8, false);
const stringMat = new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.8 });
const string = new THREE.Mesh(stringGeo, stringMat);
scene.add(string);

// ── Highlight / shine patch ────────────────────────────
