  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 6);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0.5, 0);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffffff, 2.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0xffaa44, 1.0);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffdd88, 1.5, 15);
pointLight.position.set(0, 3, 2);
scene.add(pointLight);

// --- Banana Geometry ---
function createBananaShape() {
  const curve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(-1.6, 0.0, 0.0),
    new THREE.Vector3(-1.2, 0.35, 0.0),
    new THREE.Vector3(-0.5, 0.75, 0.0),
    new THREE.Vector3(0.3, 0.95, 0.0),
    new THREE.Vector3(1.0, 0.85, 0.0),
    new THREE.Vector3(1.5, 0.55, 0.0),
    new THREE.Vector3(1.75, 0.2, 0.0),
  ]);

  const tubeSegments = 128;
  const radialSegments = 16;

  // Custom flattened cross-section shape
  const shape = new THREE.Shape();
  const w = 0.22, h = 0.30;
  shape.moveTo(0, h);
  shape.bezierCurveTo(w * 1.2, h * 0.8, w * 1.2, -h * 0.8, 0, -h);
  shape.bezierCurveTo(-w * 1.2, -h * 0.8, -w * 1.2, h * 0.8, 0, h);

  const extrudeSettings = {
    steps: tubeSegments,
    extrudePath: curve,
    bevelEnabled: false,
  };

  // Use a TubeGeometry with a custom radius profile
  const points = curve.getPoints(tubeSegments);
  const geometry = new THREE.TubeGeometry(curve, tubeSegments, 0.25, radialSegments, false);

  // Modify vertices for banana shape
  const pos = geometry.attributes.position;
  const uv = geometry.attributes.uv;
  const colors = new Float32Array(pos.count * 3);

  for (let i = 0; i < pos.count; i++) {
    const u = uv.getX(i); // 0..1 along the curve
    const v = uv.getY(i); // 0..1 around the cross-section

    // Taper at both ends
    const taper = Math.sin(u * Math.PI);
    const taper2 = Math.pow(taper, 0.6);

    // Flatten the cross-section slightly
    const angle = v * Math.PI * 2;
    let x = pos.getX(i);
    let y = pos.getY(i);
    let z = pos.getZ(i);

    // Get the normal direction in local cross-section
    const localY = Math.cos(angle);
    const localZ = Math.sin(angle);

    // Flatten: squash in one direction
    const flatten = 0.75;
    const radius = 0.25 * taper2;

    // Rebuild position relative to curve point
    const curvePoint = curve.getPoint(u);
    const tangent = curve.getTangent(u);

    // Simple flattening: scale Y more than Z
    pos.setY(i, curvePoint.y + localY * radius * 1.15);
    pos.setZ(i, curvePoint.z + localZ * radius * 0.7);
    pos.setX(i, curvePoint.x);

    // Add subtle ridges
    const ridge = Math.sin(angle * 3) * 0.015 * taper;
    pos.setY(i, pos.getY(i) + localY * ridge);
    pos.setZ(i, pos.getZ(i) + localZ * ridge);

    // Color: yellow body, green tips, brown spots
    const tipFactor = Math.pow(1 - taper, 3);
    const green = new THREE.Color(0.25, 0.6, 0.1);
    const yellow = new THREE.Color(1.0, 0.85, 0.15);
    const darkYellow = new THREE.Color(0.85, 0.7, 0.05);
    const brown = new THREE.Color(0.4, 0.25, 0.1);

    let color;
    if (u < 0.08 || u > 0.92) {
      color = green.clone().lerp(yellow, 1 - tipFactor * 2);
    } else {
      color = yellow.clone().lerp(darkYellow, Math.abs(localY) * 0.3);
    }

    // Add some brown spots
    const spotNoise = Math.sin(u * 47.0) * Math.cos(v * 31.0 + u * 13.0);
    if (spotNoise > 0.82 && u > 0.1 && u < 0.9) {
      color.lerp(brown, (spotNoise - 0.82) * 5);
    }

    // Darken the stem area
    if (u < 0.05) {
      color.lerp(new THREE.Color(0.15, 0.3, 0.08), 1 - u * 20);
    }

    colors[i * 3] = color.r;
    colors[i * 3 + 1] = color.g;
    colors[i * 3 + 2] = color.b;
  }

  geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));
  geometry.computeVertexNormals();
  return geometry;
}

// --- Banana Mesh ---
const bananaGeometry = createBananaShape();
const bananaMaterial = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.45,
  metalness: 0.05,
  side: THREE.DoubleSide,
});

const banana = new THREE.Mesh(bananaGeometry, bananaMaterial);
banana.castShadow = true;
banana.receiveShadow = true;
banana.rotation.z = 0.15;
scene.add(banana);

// --- Stem ---
