  new THREE.Vector3(-1.6, 0.0, 0.0),
  new THREE.Vector3(-1.75, -0.05, 0.0),
  new THREE.Vector3(-1.95, -0.12, 0.0),
  new THREE.Vector3(-2.1, -0.15, 0.02),
]);
const stemGeo = new THREE.TubeGeometry(stemCurve, 20, 0.04, 8, false);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x3a6b18,
  roughness: 0.7,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
stem.rotation.z = 0.15;
scene.add(stem);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x16213e,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.2;
ground.receiveShadow = true;
scene.add(ground);

// --- Floating particles ---
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3] = (Math.random() - 0.5) * 12;
  particlePositions[i * 3 + 1] = Math.random() * 6 - 1;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 12;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xffdd88,
  size: 0.04,
  transparent: true,
  opacity: 0.5,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  banana.rotation.y = Math.sin(t * 0.5) * 0.3;
  banana.position.y = Math.sin(t * 0.8) * 0.1;
  stem.rotation.y = banana.rotation.y;
  stem.position.y = banana.position.y;

  // Particles drift
  particles.rotation.y = t * 0.05;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single HTML file creates a procedurally generated banana with Three.js featuring:

- **Curved tube geometry** shaped along a CatmullRom spline to mimic the banana's crescent form
- **Tapered ends** that narrow at both tips
- **Flattened cross-section** (not a perfect cylinder) for realism
- **Vertex colors** — yellow body, green tips, brown spots, and a dark stem
- **Subtle ridges** along the surface
- **A separate green stem** piece
- **Three-point lighting** (ambient, directional, rim) with soft shadows
- **Gentle floating animation** — the banana slowly bobs and rotates
- **Floating golden particles** in the background for atmosphere
- **OrbitControls** — drag to rotate, scroll to zoom
- **Responsive** to window resizing

