// --- Bamboo Builder ---
function createBambooStalk(height, baseX, baseZ, lean) {
  const group = new THREE.Group();
  const segments = Math.floor(height / 1.8);
  const segHeight = 1.5;
  const nodeRadius = 0.22;
  const stalkRadius = 0.18;
  let y = 0;

  const greenMat = new THREE.MeshStandardMaterial({
    color: 0x4a8c3f,
    roughness: 0.5,
    metalness: 0.1,
  });
  const nodeMat = new THREE.MeshStandardMaterial({
    color: 0x3a7030,
    roughness: 0.4,
    metalness: 0.15,
  });

  for (let i = 0; i < segments; i++) {
    const t = i / segments;
    const r = stalkRadius * (1 - t * 0.3);

    // Segment
    const segGeo = new THREE.CylinderGeometry(r, r, segHeight, 12);
    const seg = new THREE.Mesh(segGeo, greenMat.clone());
    seg.position.y = y + segHeight / 2;
    seg.castShadow = true;
    seg.receiveShadow = true;
