    if (i > 0) {
      const nodeGeo = new THREE.TorusGeometry(r + 0.04, 0.04, 8, 16);
      const node = new THREE.Mesh(nodeGeo, nodeMat);
      node.position.y = y;
      node.rotation.x = Math.PI / 2;
      node.castShadow = true;
      group.add(node);
    }

    y += segHeight;

    // Leaves at some nodes
    if (i > 0 && Math.random() > 0.25) {
      const leafCount = 2 + Math.floor(Math.random() * 3);
      for (let l = 0; l < leafCount; l++) {
        const leaf = createLeaf();
        leaf.position.y = y;
        const angle = (l / leafCount) * Math.PI * 2 + Math.random() * 0.5;
        leaf.rotation.y = angle;
        leaf.rotation.z = (Math.random() - 0.5) * 0.8 - 0.3;
        leaf.rotation.x = (Math.random() - 0.5) * 0.6;
        leaf.castShadow = true;
        group.add(leaf);
      }
    }
  }

  // Top leaves
  for (let l = 0; l < 5; l++) {
    const leaf = createLeaf();
    leaf.position.y = y;
    leaf.rotation.y = (l / 5) * Math.PI * 2;
    leaf.rotation.z = -0.5 - Math.random() * 0.8;
    leaf.rotation.x = (Math.random() - 0.5) * 0.5;
    leaf.scale.setScalar(0.7 + Math.random() * 0.5);
    leaf.castShadow = true;
    group.add(leaf);
  }

  group.position.set(baseX, 0, baseZ);
  group.rotation.z = lean;
  return group;
}

function createLeaf() {
  const shape = new THREE.Shape();
  const len = 1.2 + Math.random() * 0.8;
  const wid = 0.12 + Math.random() * 0.06;
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(wid, len * 0.4, 0, len);
  shape.quadraticCurveTo(-wid, len * 0.4, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 4);
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28 + Math.random() * 0.08, 0.6, 0.35 + Math.random() * 0.15),
    side: THREE.DoubleSide,
    roughness: 0.7,
    metalness: 0.0,
  });
  return new THREE.Mesh(geo, mat);
}

// --- Create Grove ---
const stalks = [];
const bambooData = [
  { h: 14, x: 0, z: 0, lean: -0.02 },
  { h: 11, x: -2.5, z: 1.5, lean: 0.04 },
  { h: 13, x: 2.8, z: -1, lean: -0.03 },
  { h: 9, x: -4, z: -2, lean: 0.05 },
  { h: 12, x: 4.5, z: 2, lean: -0.04 },
  { h: 10, x: 1.5, z: 3.5, lean: 0.03 },
  { h: 8, x: -1, z: -4, lean: -0.02 },
  { h: 15, x: -5.5, z: 0.5, lean: 0.01 },
  { h: 11, x: 6, z: -2.5, lean: -0.03 },
  { h: 10, x: -3, z: 4, lean: 0.04 },
  { h: 13, x: 3, z: -4, lean: -0.02 },
  { h: 9, x: -6, z: -3, lean: 0.03 },
];

bambooData.forEach(d => {
  const stalk = createBambooStalk(d.h, d.x, d.z, d.lean);
  scene.add(stalk);
  stalks.push(stalk);
});

// --- Small grass tufts ---
for (let i = 0; i < 200; i++) {
  const angle = Math.random() * Math.PI * 2;
  const dist = 2 + Math.random() * 20;
  const x = Math.cos(angle) * dist;
  const z = Math.sin(angle) * dist;

  const bladeGeo = new THREE.PlaneGeometry(0.06, 0.3 + Math.random() * 0.4);
  const bladeMat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.25 + Math.random() * 0.1, 0.5, 0.3 + Math.random() * 0.15),
    side: THREE.DoubleSide,
    roughness: 0.9,
  });
  const blade = new THREE.Mesh(bladeGeo, bladeMat);
  blade.position.set(x, 0.15, z);
  blade.rotation.y = Math.random() * Math.PI;
  blade.rotation.z = (Math.random() - 0.5) * 0.4;
  scene.add(blade);
}

// --- Falling leaves particles ---
const leafCount = 30;
const leafParticles = [];
for (let i = 0; i < leafCount; i++) {
  const geo = new THREE.PlaneGeometry(0.15, 0.06);
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28, 0.5, 0.35),
    side: THREE.DoubleSide,
    transparent: true,
    opacity: 0.8,
  });
  const leaf = new THREE.Mesh(geo, mat);
  resetLeaf(leaf, true);
  scene.add(leaf);
  leafParticles.push(leaf);
}

function resetLeaf(leaf, init = false) {
  leaf.position.set(
    (Math.random() - 0.5) * 20,
    init ? Math.random() * 15 : 10 + Math.random() * 8,
    (Math.random() - 0.5) * 20
  );
  leaf.userData.speed = 0.3 + Math.random() * 0.5;
  leaf.userData.wobble = Math.random() * Math.PI * 2;
  leaf.userData.wobbleSpeed = 1 + Math.random() * 2;
  leaf.userData.rotSpeed = (Math.random() - 0.5) * 3;
}

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Sway bamboo
  stalks.forEach((stalk, i) => {
    const phase = i * 0.7;
    stalk.rotation.z = stalk.userData.lean + Math.sin(t * 0.8 + phase) * 0.015;
    stalk.rotation.x = Math.sin(t * 0.6 + phase + 1) * 0.01;
  });

  // Animate falling leaves
  leafParticles.forEach(leaf => {
    leaf.position.y -= leaf.userData.speed * 0.016;
    leaf.userData.wobble += leaf.userData.wobbleSpeed * 0.016;
    leaf.position.x += Math.sin(leaf.userData.wobble) * 0.005;
    leaf.rotation.z += leaf.userData.rotSpeed * 0.016;
    leaf.rotation.y += leaf.userData.rotSpeed * 0.5 * 0.016;

    if (leaf.position.y < 0) {
      resetLeaf(leaf);
    }
  });

  controls.update();
  renderer.render(scene, camera);
}

// Store lean for animation
stalks.forEach((s, i) => {
  s.userData.lean = bambooData[i].lean;
});

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **serene bamboo grove** scene with:

- **12 bamboo stalks** of varying heights, each built from green cylindrical segments with torus node rings
- **Dozens of curved leaves** sprouting from nodes and the top of each stalk
- **Gentle swaying animation** — each stalk sways with a slightly different phase
- **Falling leaf particles** that drift and wobble down through the air
- **A dirt path** through the grove and **200 grass tufts** scattered on the ground
- **Cinematic lighting** — warm sun with soft shadows, cool blue fill light, and ambient green
- **Fog** for atmospheric depth
- **OrbitControls** — drag to rotate, scroll to zoom
- **ACES filmic tone mapping** for a rich, natural look

