  barrelGroup.add(r);
});
scene.children.filter(c => c.geometry && c.geometry.type === 'BoxGeometry').forEach(s => {
  scene.remove(s);
  barrelGroup.add(s);
});
scene.children.filter(c => c.geometry && c.geometry.type === 'CircleGeometry').forEach(cp => {
  scene.remove(cp);
  barrelGroup.add(cp);
});
scene.children.filter(c => c.geometry && c.geometry.type === 'CylinderGeometry').forEach(b => {
  scene.remove(b);
  barrelGroup.add(b);
});

scene.add(barrelGroup);

function animate2() {
  requestAnimationFrame(animate2);
  const t = clock.getElapsedTime();
  barrelGroup.rotation.y = t * 0.2;
  controls.update();
  renderer.render(scene, camera);
}

animate2();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</html>
```

## What's in the barrel

| Part | Geometry | Details |
|---|---|---|
| **Body** | `LatheGeometry` | 11-point profile creates the classic bulging barrel curve, 32 segments |
| **Metal hoops** | `TorusGeometry` | 5 hoops of varying radius/tube to match the bulge, with 8 rivets each (`SphereGeometry`) |
| **Stave lines** | `BoxGeometry` | 12 subtle vertical grooves suggesting wooden staves |
| **End caps** | `CircleGeometry` | Flat dark wood top & bottom |
| **Bung** | `CylinderGeometry` | Small plug on top |

