```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Basket</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 25);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3.5, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.8, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

// ── Lights ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(2048, 2048);
dirLight.shadow.camera.near = 0.5;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.4);
fillLight.position.set(-3, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffaa44, 1.0, 10);
rimLight.position.set(-2, 3, -2);
scene.add(rimLight);

// ── Basket Group ──
const basket = new THREE.Group();
scene.add(basket);

const weaveMat = new THREE.MeshStandardMaterial({
  color: 0xc4956a,
  roughness: 0.85,
  metalness: 0.0,
});

const darkWeaveMat = new THREE.MeshStandardMaterial({
  color: 0x9a7450,
  roughness: 0.85,
  metalness: 0.0,
});

const baseMat = new THREE.MeshStandardMaterial({
  color: 0x7a5c3a,
  roughness: 0.9,
  metalness: 0.0,
});

// ── Basket Base ──
const baseGeo = new THREE.CylinderGeometry(1.0, 0.95, 0.08, 32);
const base = new THREE.Mesh(baseGeo, baseMat);
base.position.y = 0.04;
base.castShadow = true;
base.receiveShadow = true;
basket.add(base);

// ── Vertical Strands ──
const NUM_V = 24;
const BASKET_H = 1.6;
const TOP_R = 1.05;
const BOT_R = 0.85;

for (let i = 0; i < NUM_V; i++) {
  const angle = (i / NUM_V) * Math.PI * 2;
  const x = Math.cos(angle);
  const z = Math.sin(angle);

  const strandGeo = new THREE.BoxGeometry(0.04, BASKET_H, 0.04);
  const strand = new THREE.Mesh(strandGeo, i % 2 === 0 ? weaveMat : darkWeaveMat);

  const midR = (TOP_R + BOT_R) / 2;
  strand.position.set(x * midR, BASKET_H / 2 + 0.08, z * midR);

  // Tilt outward to match basket shape
  const tilt = Math.atan2(TOP_R - BOT_R, BASKET_H);
  strand.rotation.z = tilt;
  strand.rotation.x = -tilt * (z / midR) * 0.5;

  strand.castShadow = true;
  strand.receiveShadow = true;
  basket.add(strand);
}

// ── Horizontal Weave Rings ──
const NUM_H = 12;
const weaveStripGeo = new THREE.BoxGeometry(0.035, 0.025, 0.035);

for (let j = 0; j < NUM_H; j++) {
  const t = (j + 1) / (NUM_H + 1);
  const y = 0.08 + t * BASKET_H;
  const r = BOT_R + (TOP_R - BOT_R) * t;
  const segments = 36;

  for (let i = 0; i < segments; i++) {
    const a1 = (i / segments) * Math.PI * 2;
    const a2 = ((i + 1) / segments) * Math.PI * 2;

    const x1 = Math.cos(a1) * r;
    const z1 = Math.sin(a1) * r;
    const x2 = Math.cos(a2) * r;
    const z2 = Math.sin(a2) * r;

    const strip = new THREE.Mesh(
      weaveStripGeo,
      (i + j) % 2 === 0 ? weaveMat : darkWeaveMat
    );

    strip.position.set((x1 + x2) / 2, y, (z1 + z2) / 2);
    strip.lookAt(x2, y, z2);
    strip.rotateX(Math.PI / 2);

    strip.castShadow = true;
    strip.receiveShadow = true;
    basket.add(strip);
  }
}

// ── Top Rim ──
const rimGeo = new THREE.TorusGeometry(TOP_R, 0.045, 8, 48);
const rimMat = new THREE.MeshStandardMaterial({
  color: 0x8b6914,
  roughness: 0.6,
  metalness: 0.1,
});
const rim = new THREE.Mesh(rimGeo, rimMat);
rim.position.y = BASKET_H + 0.08;
rim.rotation.x = Math.PI / 2;
rim.castShadow = true;
basket.add(rim);

// ── Handle ──
const handlePath = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-TOP_R * 0.95, BASKET_H + 0.08, 0),
  new THREE.Vector3(-TOP_R * 0.7, BASKET_H + 0.6, 0),
  new THREE.Vector3(0, BASKET_H + 1.0, 0),
  new THREE.Vector3(TOP_R * 0.7, BASKET_H + 0.6, 0),
  new THREE.Vector3(TOP_R * 0.95, BASKET_H + 0.08, 0),
]);

const handleGeo = new THREE.TubeGeometry(handlePath, 32, 0.035, 8, false);
const handle = new THREE.Mesh(handleGeo, rimMat);
handle.castShadow = true;
basket.add(handle);

// ── Handle Attachments ──
for (const side of [-1, 1]) {
  const attachGeo = new THREE.CylinderGeometry(0.05, 0.05, 0.12, 12);
  const attach = new THREE.Mesh(attachGeo, rimMat);
  attach.position.set(side * TOP_R * 0.95, BASKET_H + 0.14, 0);
  attach.rotation.z = Math.PI / 2 * side;
  attach.castShadow = true;
  basket.add(attach);
}

// ── Ground Plane ──
const groundGeo = new THREE.PlaneGeometry(30, 30);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e,
  roughness: 0.95,
  metalness: 0.0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Decorative Items in Basket ──
const fruitColors = [0xff4444, 0xff6633, 0xffcc00, 0x44aa22, 0xff5555];
const fruitGroup = new THREE.Group();
fruitGroup.position.y = BASKET_H * 0.55 + 0.08;
basket.add(fruitGroup);

for (let i = 0; i < 7; i++) {
  const size = 0.12 + Math.random() * 0.12;
  const fruitGeo = new THREE.SphereGeometry(size, 16, 16);
  const fruitMat = new THREE.MeshStandardMaterial({
    color: fruitColors[i % fruitColors.length],
    roughness: 0.4,
    metalness: 0.05,
  });
  const fruit = new THREE.Mesh(fruitGeo, fruitMat);

  const angle = Math.random() * Math.PI * 2;
  const r = Math.random() * 0.5;
  fruit.position.set(
    Math.cos(angle) * r,
    size + Math.random() * 0.2,
    Math.sin(angle) * r
  );
  fruit.castShadow = true;
  fruit.receiveShadow = true;
  fruitGroup.add(fruit);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle basket sway
  basket.rotation.y = Math.sin(elapsed * 0.3) * 0.05;

  // Subtle fruit bob
  fruitGroup.children.forEach((fruit, i) => {
    fruit.position.y += Math.sin(elapsed * 1.5 + i) * 0.0002;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **woven 3D basket** with:

- **Vertical strands** — 24 alternating-toned strips that tilt outward to form the basket walls
- **Horizontal weave** — 12 rings of small segments creating a checkerboard weave pattern
- **Torus top rim** — a polished golden rim around the opening
- **Curved handle** — a tube following a catenary curve with attachment points
- **Solid base** — a flat bottom disc
- **Fruit inside** — 7 colorful spheres nestled in the basket for visual interest
- **Cinematic lighting** — directional key light with soft shadows, blue fill light, and warm rim light
- **Subtle animation** — gentle sway and fruit bobbing
- **OrbitControls** — drag to rotate, scroll to zoom

