shape.moveTo(0, 0);
// Upper mandible top (culmen)
shape.bezierCurveTo(0.6, 0.55, 1.6, 0.65, 2.4, 0.2);
shape.bezierCurveTo(2.6, 0.1, 2.75, 0.02, 2.85, 0);
// Tip point
shape.lineTo(2.9, 0);
// Lower mandible bottom
shape.bezierCurveTo(2.6, -0.08, 2.0, -0.25, 1.2, -0.3);
shape.bezierCurveTo(0.6, -0.32, 0.3, -0.28, 0, -0.22);
// Back edge
shape.lineTo(0, 0);

const extSettings = {
  depth: 0.35,
  bevelEnabled: true,
  bevelThickness: 0.06,
  bevelSize: 0.05,
  bevelOffset: 0,
  bevelSegments: 6
};

const geo = new THREE.ExtrudeGeometry(shape, extSettings);
geo.center();

// Gradient-like material via vertex colors
const count = geo.attributes.position.count;
const colors = new Float32Array(count * 3);
const pos = geo.attributes.position;
for (let i = 0; i < count; i++) {
  const x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
  const t = (x + 1.5) / 3; // 0 at base, ~1 at tip
  const r = 0.95 - t * 0.2;
  const g = 0.55 - t * 0.15;
  const b = 0.1 + t * 0.05;
  colors[i * 3] = r;
  colors[i * 3 + 1] = g;
  colors[i * 3 + 2] = b;
}
geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));

const mat = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.35,
  metalness: 0.05,
  side: THREE.DoubleSide
});

const beak = new THREE.Mesh(geo, mat);
beak.castShadow = true;
beak.receiveShadow = true;
