// ── Ridge line along upper mandible ──
const ridge = new THREE.Shape();
ridge.moveTo(0.25, 0.03);
ridge.bezierCurveTo(0.8, 0.12, 1.5, 0.1, 2.3, 0.02);
ridge.lineTo(2.3, 0.005);
ridge.bezierCurveTo(1.5, 0.08, 0.8, 0.1, 0.25, 0.015);
ridge.lineTo(0.25, 0.03);

const ridgeGeo = new THREE.ExtrudeGeometry(ridge, {
  depth: 0.38,
  bevelEnabled: true,
  bevelThickness: 0.015,
  bevelSize: 0.015,
  bevelSegments: 2
});
ridgeGeo.center();

const ridgeMat = new THREE.MeshStandardMaterial({
  color: 0xd4720a,
  roughness: 0.3,
  metalness: 0.05
});
const ridgeMesh = new THREE.Mesh(ridgeGeo, ridgeMat);
ridgeMesh.position.z = 0.015;
beak.add(ridgeMesh);

// ── Nostril ──
const nostrilGeo = new THREE.SphereGeometry(0.035, 12, 8);
const nostrilMat = new THREE.MeshStandardMaterial({ color: 0x2a1a0a, roughness: 0.8 });
const nostril = new THREE.Mesh(nostrilGeo, nostrilMat);
nostril.position.set(1.05, 0.16, 0.2);
beak.add(nostril);

// ── Subtle ground plane ──
const groundGeo = new THREE.PlaneGeometry(30, 30);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x6ab04c, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// ── Animate ──
function animate() {
  requestAnimationFrame(animate);
  const t = Date.now() * 0.001;
  beak.rotation.y = Math.sin(t * 0.6) * 0.35;
  beak.rotation.x = Math.sin(t * 0.4) * 0.08;
  beak.position.y = Math.sin(t * 0.7) * 0.15;
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
