scene.add(amb);
const dir = new THREE.DirectionalLight(0xffeedd, 1.0);
dir.position.set(3, 5, 4);
dir.castShadow = true;
scene.add(dir);
const rim = new THREE.PointLight(0x4488ff, 0.5, 10);
rim.position.set(-3, 1, -2);
scene.add(rim);

// Head
const headGeo = new THREE.SphereGeometry(1, 32, 32);
const headMat = new THREE.MeshStandardMaterial({ color: 0xf4c28f, roughness: 0.8 });
const head = new THREE.Mesh(headGeo, headMat);
head.scale.set(0.9, 1.1, 0.85);
head.castShadow = true;
scene.add(head);

// Eyes
const eyeGeo = new THREE.SphereGeometry(0.07, 16, 16);
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x222222 });
[-0.3, 0.3].forEach(x => {
  const eye = new THREE.Mesh(eyeGeo, eyeMat);
  eye.position.set(x, 0.25, 0.78);
  scene.add(eye);
  // Eye whites
  const white = new THREE.Mesh(
    new THREE.SphereGeometry(0.1, 16, 16),
    new THREE.MeshStandardMaterial({ color: 0xffffff })
  );
  white.position.set(x, 0.25, 0.74);
  scene.add(white);
});

// Eyebrows
[-0.3, 0.3].forEach(x => {
  const brow = new THREE.Mesh(
    new THREE.BoxGeometry(0.22, 0.04, 0.06),
    new THREE.MeshStandardMaterial({ color: 0x3a2a1a })
  );
  brow.position.set(x, 0.42, 0.8);
  brow.rotation.z = x > 0 ? -0.1 : 0.1;
  scene.add(brow);
});

// Nose
const nose = new THREE.Mesh(
  new THREE.SphereGeometry(0.1, 16, 16),
  new THREE.MeshStandardMaterial({ color: 0xe8b080 })
);
nose.position.set(0, -0.05, 0.85);
nose.scale.set(0.7, 0.9, 0.8);
scene.add(nose);

// Mouth
const mouth = new THREE.Mesh(
  new THREE.BoxGeometry(0.25, 0.04, 0.05),
  new THREE.MeshStandardMaterial({ color: 0xcc6666 })
);
mouth.position.set(0, -0.3, 0.78);
scene.add(mouth);

// === BEARD ===
const beardGroup = new THREE.Group();
scene.add(beardGroup);

const beardColors = [0x2a1a0a, 0x3a2a1a, 0x1a0f05, 0x4a3525, 0x2c1f14];

function makeHair(x, y, z, count, length, spread) {
  for (let i = 0; i < count; i++) {
    const ox = x + (Math.random() - 0.5) * spread.x;
    const oy = y + (Math.random() - 0.5) * spread.y;
    const oz = z + (Math.random() - 0.5) * spread.z;

    const endY = oy - length * (0.6 + Math.random() * 0.6);
    const endX = ox + (Math.random() - 0.5) * 0.3;
    const endZ = oz + 0.1 + Math.random() * 0.15;

    const mid1Y = oy - length * 0.3;
    const mid1X = ox + (Math.random() - 0.5) * 0.15;
    const mid1Z = oz + 0.05 + Math.random() * 0.1;

    const mid2Y = oy - length * 0.6;
    const mid2X = endX * 0.5 + (Math.random() - 0.5) * 0.1;
    const mid2Z = (oz + endZ) * 0.5 + (Math.random() - 0.5) * 0.05;

    const curve = new THREE.CatmullRomCurve3([
      new THREE.Vector3(ox, oy, oz),
      new THREE.Vector3(mid1X, mid1Y, mid1Z),
      new THREE.Vector3(mid2X, mid2Y, mid2Z),
      new THREE.Vector3(endX, endY, endZ),
    ]);

    const tubeGeo = new THREE.TubeGeometry(curve, 8, 0.008 + Math.random() * 0.006, 4, false);
    const color = beardColors[Math.floor(Math.random() * beardColors.length)];
    const mat = new THREE.MeshStandardMaterial({
      color,
      roughness: 0.9,
      metalness: 0.05,
    });
    const hair = new THREE.Mesh(tubeGeo, mat);
    hair.castShadow = true;
    beardGroup.add(hair);
  }
}

// Main beard (chin area)
makeHair(0, -0.55, 0.72, 80, 1.8, { x: 0.5, y: 0.15, z: 0.1 });

// Mustache
makeHair(0, -0.32, 0.82, 40, 0.6, { x: 0.4, y: 0.05, z: 0.05 });

// Sideburns left
makeHair(-0.7, 0.15, 0.55, 30, 1.0, { x: 0.08, y: 0.25, z: 0.12 });

// Sideburns right
makeHair(0.7, 0.15, 0.55, 30, 1.0, { x: 0.08, y: 0.25, z: 0.12 });

// Cheek left
makeHair(-0.5, -0.2, 0.7, 35, 1.2, { x: 0.12, y: 0.2, z: 0.08 });

// Cheek right
makeHair(0.5, -0.2, 0.7, 35, 1.2, { x: 0.12, y: 0.2, z: 0.08 });

// Extra long wispy hairs
for (let i = 0; i < 15; i++) {
  const x = (Math.random() - 0.5) * 0.6;
  const y = -0.55 + (Math.random() - 0.5) * 0.1;
  const z = 0.72 + Math.random() * 0.08;
  makeHair(x, y, z, 1, 2.2 + Math.random() * 0.6, { x: 0.01, y: 0.01, z: 0.01 });
}

// Ear hints
[-0.95, 0.95].forEach(x => {
  const ear = new THREE.Mesh(
    new THREE.SphereGeometry(0.12, 12, 12),
    new THREE.MeshStandardMaterial({ color: 0xf0b888 })
  );
  ear.position.set(x, 0.1, 0.3);
  ear.scale.set(0.5, 1, 0.7);
  scene.add(ear);
});

// Subtle sparkle particles
const sparkleGeo = new THREE.BufferGeometry();
const sparkleCount = 60;
const sparklePos = new Float32Array(sparkleCount * 3);
for (let i = 0; i < sparkleCount; i++) {
  sparklePos[i * 3] = (Math.random() - 0.5) * 6;
  sparklePos[i * 3 + 1] = (Math.random() - 0.5) * 6;
  sparklePos[i * 3 + 2] = (Math.random() - 0.5) * 6;
}
sparkleGeo.setAttribute('position', new THREE.BufferAttribute(sparklePos, 3));
const sparkleMat = new THREE.PointsMaterial({ color: 0xffeedd, size: 0.02, transparent: true, opacity: 0.6 });
const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
scene.add(sparkles);

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  beardGroup.rotation.y = Math.sin(t * 0.3) * 0.15;
  head.rotation.y = Math.sin(t * 0.3) * 0.15;

  // Slight hair sway
  beardGroup.children.forEach((hair, i) => {
    hair.rotation.z = Math.sin(t * 1.5 + i * 0.1) * 0.01;
  });

  sparkles.rotation.y = t * 0.05;
  sparkles.rotation.x = t * 0.02;

  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
