</head>
<body>
<div id="info">🛏️ Drag to orbit · Scroll to zoom</div>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.018);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 5, 8);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 3;
controls.maxDistance = 20;
controls.update();

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 4);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(2048, 2048);
keyLight.shadow.camera.near = 0.5;
keyLight.shadow.camera.far = 25;
keyLight.shadow.camera.left = -8;
keyLight.shadow.camera.right = 8;
keyLight.shadow.camera.top = 8;
keyLight.shadow.camera.bottom = -8;
keyLight.shadow.bias = -0.0005;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.4);
fillLight.position.set(-4, 4, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff9966, 1.5, 15);
rimLight.position.set(-3, 3, -4);
scene.add(rimLight);

// ── Materials ──
const mat = {
  wood:      new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.7, metalness: 0.05 }),
  woodLight: new THREE.MeshStandardMaterial({ color: 0x8b6914, roughness: 0.6, metalness: 0.05 }),
  mattress:  new THREE.MeshStandardMaterial({ color: 0xf5f0e8, roughness: 0.9, metalness: 0 }),
  pillow:    new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.95, metalness: 0 }),
  blanket:   new THREE.MeshStandardMaterial({ color: 0x3b5998, roughness: 0.85, metalness: 0 }),
  sheet:     new THREE.MeshStandardMaterial({ color: 0xe8e0d4, roughness: 0.9, metalness: 0 }),
  floor:     new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 0.85, metalness: 0.1 }),
};

// ── Helpers ──
function box(w, h, d, material, x, y, z, ry = 0) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), material);
  m.position.set(x, y, z);
  m.rotation.y = ry;
  m.castShadow = true;
  m.receiveShadow = true;
  return m;
}

const bed = new THREE.Group();

// ── Floor / Rug ──
scene.add(box(20, 0.05, 20, mat.floor, 0, -0.025, 0));
scene.add(box(5, 0.01, 4, new THREE.MeshStandardMaterial({ color: 0x3a2a1a, roughness: 0.95 }), 0, 0.005, 0));

// ── Bed Frame Base ──
const frameW = 2.2, frameD = 3.6, frameH = 0.15;
bed.add(box(frameW, frameH, frameD, mat.wood, 0, 0.45, 0));

// ── Side Rails ──
const railH = 0.25, railT = 0.08;
bed.add(box(railT, railH, frameD - 0.1, mat.wood, -frameW / 2 + railT / 2, 0.55, 0));
bed.add(box(railT, railH, frameD - 0.1, mat.wood,  frameW / 2 - railT / 2, 0.55, 0));

// ── Headboard ──
const hbW = frameW + 0.1, hbH = 1.4, hbD = 0.1;
bed.add(box(hbW, hbH, hbD, mat.woodLight, 0, 0.45 + hbH / 2, -frameD / 2 + hbD / 2));
// Headboard panels
bed.add(box(hbW - 0.2, hbH - 0.3, 0.02, mat.wood, 0, 0.45 + hbH / 2, -frameD / 2 + hbD / 2 + 0.04));

// ── Footboard ──
const fbH = 0.6;
bed.add(box(frameW, fbH, 0.08, mat.woodLight, 0, 0.45 + fbH / 2, frameD / 2 - 0.04));

// ── Legs ──
const legR = 0.06, legH = 0.4;
const legPositions = [
  [-frameW / 2 + 0.15, legH / 2, -frameD / 2 + 0.15],
  [ frameW / 2 - 0.15, legH / 2, -frameD / 2 + 0.15],
  [-frameW / 2 + 0.15, legH / 2,  frameD / 2 - 0.15],
  [ frameW / 2 - 0.15, legH / 2,  frameD / 2 - 0.15],
];
legPositions.forEach(([x, y, z]) => {
  const leg = new THREE.Mesh(new THREE.CylinderGeometry(legR, legR * 1.1, legH, 12), mat.wood);
  leg.position.set(x, y, z);
  leg.castShadow = true;
  bed.add(leg);
});

// ── Mattress ──
const mattW = frameW - 0.2, mattD = frameD - 0.3, mattH = 0.25;
bed.add(box(mattW, mattH, mattD, mat.mattress, 0, 0.45 + frameH + mattH / 2, 0));

// ── Sheet (thin layer on mattress) ──
bed.add(box(mattW - 0.05, 0.02, mattD - 0.05, mat.sheet, 0, 0.45 + frameH + mattH + 0.01, 0));

// ── Blanket / Comforter ──
const blW = mattW - 0.1, blD = mattD * 0.55, blH = 0.08;
bed.add(box(blW, blH, blD, mat.blanket, 0, 0.45 + frameH + mattH + 0.04, mattD / 2 - blD / 2 + 0.3));

// Blanket fold at foot
bed.add(box(blW - 0.05, 0.04, 0.15, mat.blanket, 0, 0.45 + frameH + mattH + 0.03, mattD / 2 - 0.1));

// ── Pillows ──
const pW = 0.65, pH = 0.12, pD = 0.4;
const pillowGeo = new THREE.BoxGeometry(pW, pH, pD, 4, 2, 4);
// Round pillow edges slightly
const pos = pillowGeo.attributes.position;
for (let i = 0; i < pos.count; i++) {
  let x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
  const r = 0.08;
  x = Math.sign(x) * Math.max(Math.abs(x) - r * 0.3, 0) + Math.sign(x) * r * 0.3 * Math.min(Math.abs(x) / (pW / 2), 1);
  y = Math.sign(y) * Math.max(Math.abs(y) - r * 0.5, 0) + Math.sign(y) * r * 0.5 * Math.min(Math.abs(y) / (pH / 2), 1);
  pos.setXYZ(i, x, y, z);
}
pillowGeo.computeVertexNormals();

const p1 = new THREE.Mesh(pillowGeo, mat.pillow);
p1.position.set(-0.45, 0.45 + frameH + mattH + 0.07, -mattD / 2 + pD / 2 + 0.15);
p1.castShadow = true;
bed.add(p1);

const p2 = new THREE.Mesh(pillowGeo, mat.pillow);
p2.position.set(0.45, 0.45 + frameH + mattH + 0.07, -mattD / 2 + pD / 2 + 0.15);
p2.castShadow = true;
bed.add(p2);

// ── Small side table ──
const table = new THREE.Group();
table.add(box(0.5, 0.04, 0.5, mat.woodLight, 0, 0.5, 0));
table.add(box(0.04, 0.5, 0.04, mat.woodLight, -0.2, 0.25, -0.2));
table.add(box(0.04, 0.5, 0.04, mat.woodLight,  0.2, 0.25, -0.2));
table.add(box(0.04, 0.5, 0.04, mat.woodLight, -0.2, 0.25,  0.2));
table.add(box(0.04, 0.5, 0.04, mat.woodLight,  0.2, 0.25,  0.2));
table.position.set(frameW / 2 + 0.6, 0, -frameD / 2 + 0.5);
table.children.forEach(c => { c.castShadow = true; c.receiveShadow = true; });
scene.add(table);

// ── Lamp on table ──
const lamp = new THREE.Group();
lamp.add(new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.15, 0.04, 16), mat.wood));
lamp.add(new THREE.Mesh(new THREE.CylinderGeometry(0.015, 0.015, 0.4, 8), mat.woodLight));
const shade = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.18, 0.2, 16, 1, true),
  new THREE.MeshStandardMaterial({ color: 0xfff5e0, roughness: 0.9, side: THREE.DoubleSide }));
shade.position.y = 0.3;
lamp.add(shade);
lamp.position.set(frameW / 2 + 0.6, 0.52, -frameD / 2 + 0.5);
lamp.children.forEach(c => c.castShadow = true);
scene.add(lamp);

const lampLight = new THREE.PointLight(0xffddaa, 1.2, 6);
lampLight.position.set(frameW / 2 + 0.6, 0.9, -frameD / 2 + 0.5);
lampLight.castShadow = true;
scene.add(lampLight);

// ── Assemble ──
scene.add(bed);

// ── Animate ──
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  // Subtle lamp flicker
  lampLight.intensity = 1.2 + Math.sin(t * 2) * 0.05 + Math.sin(t * 3.7) * 0.03;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

- **Bed frame** — wooden base with side rails, headboard (with panel detail), footboard, and tapered legs
- **Mattress & sheet** — layered on top with a fitted sheet
- **Blanket/comforter** — draped over the lower half with a fold at the foot
- **Two pillows** — with slightly rounded edges via vertex manipulation
- **Side table & lamp** — with a working point light that has subtle flicker
- **Floor & rug** — for grounding the scene
- **Lighting** — ACES filmic tone mapping, 3-point lighting (key/fill/rim), soft shadows
- **OrbitControls** — drag to rotate, scroll to zoom, with damping

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Beetle</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://unpkg.com/three@0.163.0/build/three.module.js",
    "three/addons/": "https://unpkg.com/three@0.163.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.5, 0);
controls.enableDamping = true;

// ── Lights ─────────────────────────────────────────────
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const dir = new THREE.DirectionalLight(0xffeedd, 2);
dir.position.set(3, 6, 4);
dir.castShadow = true;
dir.shadow.mapSize.set(1024, 1024);
scene.add(dir);

const rim = new THREE.PointLight(0x4488ff, 1.5, 12);
rim.position.set(-3, 2, -2);
scene.add(rim);

// ── Materials ──────────────────────────────────────────
const shellMat = new THREE.MeshStandardMaterial({
  color: 0x1a0a00, roughness: 0.2, metalness: 0.8,
  envMapIntensity: 1.0
});
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0x2a1500, roughness: 0.5, metalness: 0.3
});
const legMat = new THREE.MeshStandardMaterial({
  color: 0x1a0a00, roughness: 0.6, metalness: 0.4
});
const eyeMat = new THREE.MeshStandardMaterial({
  color: 0x111111, roughness: 0.1, metalness: 0.9
});
const accentMat = new THREE.MeshStandardMaterial({
  color: 0xcc4400, roughness: 0.3, metalness: 0.6,
  emissive: 0x331100, emissiveIntensity: 0.3
});

// ── Beetle Builder ─────────────────────────────────────
const beetle = new THREE.Group();

// Abdomen (large back shell)
const abdomen = new THREE.Mesh(
  new THREE.SphereGeometry(0.65, 32, 24),
  shellMat
);
abdomen.scale.set(1, 0.65, 1.5);
abdomen.position.set(0, 0.35, -0.3);
abdomen.castShadow = true;
beetle.add(abdomen);

// Shell ridge line
const ridge = new THREE.Mesh(
  new THREE.BoxGeometry(0.04, 0.08, 1.6),
  accentMat
);
ridge.position.set(0, 0.72, -0.25);
beetle.add(ridge);

// Shell hemispheres (wing covers)
for (const side of [-1, 1]) {
  const wing = new THREE.Mesh(
    new THREE.SphereGeometry(0.64, 32, 24, 0, Math.PI * 2, 0, Math.PI / 2),
    shellMat
  );
  wing.scale.set(0.5, 0.5, 1.45);
  wing.position.set(side * 0.28, 0.36, -0.28);
  wing.castShadow = true;
  beetle.add(wing);
}

// Thorax
const thorax = new THREE.Mesh(
  new THREE.SphereGeometry(0.38, 32, 24),
  bodyMat
);
thorax.scale.set(1, 0.7, 1);
thorax.position.set(0, 0.3, 0.55);
thorax.castShadow = true;
beetle.add(thorax);

// Head
const head = new THREE.Mesh(
  new THREE.SphereGeometry(0.22, 32, 24),
  bodyMat
);
head.scale.set(1, 0.8, 1);
head.position.set(0, 0.25, 1.05);
head.castShadow = true;
beetle.add(head);

// Mandibles
for (const side of [-1, 1]) {
  const mandible = new THREE.Mesh(
    new THREE.ConeGeometry(0.03, 0.2, 8),
    legMat
  );
  mandible.rotation.z = side * 0.4;
  mandible.position.set(side * 0.08, 0.15, 1.28);
  beetle.add(mandible);
}

// Eyes
for (const side of [-1, 1]) {
  const eye = new THREE.Mesh(
    new THREE.SphereGeometry(0.07, 16, 16),
    eyeMat
  );
  eye.position.set(side * 0.18, 0.32, 1.15);
  beetle.add(eye);
}

// ── Legs ───────────────────────────────────────────────
const legs = [];
function createLeg(side, x, y, z) {
  const group = new THREE.Group();
  group.position.set(side * x, y, z);

  const segments = [
    { r: 0.035, len: 0.35, angle: 0 },
    { r: 0.028, len: 0.3, angle: side * 0.6 },
    { r: 0.02,  len: 0.25, angle: side * -0.4 },
  ];

  let parent = group;
  segments.forEach((seg) => {
    const mesh = new THREE.Mesh(
      new THREE.CylinderGeometry(seg.r * 0.7, seg.r, seg.len, 8),
      legMat
    );
    mesh.position.y = -seg.len / 2;
    mesh.castShadow = true;

    const joint = new THREE.Group();
    joint.add(mesh);
    joint.position.y = -seg.len;

    parent.add(joint);
    parent = joint;
  });

  beetle.add(group);
  legs.push(group);
  return group;
}

// 3 pairs of legs
const legPositions = [
  [0.32, 0.12, 0.75],
  [0.38, 0.08, 0.15],
  [0.35, 0.08, -0.45],
];
legPositions.forEach(([x, y, z]) => {
  createLeg(1, x, y, z);
  createLeg(-1, x, y, z);
});

// ── Antennae ───────────────────────────────────────────
const antennae = [];
for (const side of [-1, 1]) {
  const group = new THREE.Group();
  group.position.set(side * 0.12, 0.35, 1.2);

  const segments = [0.2, 0.18, 0.15, 0.12, 0.09, 0.06];
  let parent = group;
  segments.forEach((len, i) => {
    const mesh = new THREE.Mesh(
      new THREE.CylinderGeometry(0.008, 0.012, len, 6),
      legMat
    );
    mesh.position.y = -len / 2;

    const joint = new THREE.Group();
    joint.add(mesh);
    joint.position.y = -len;

    parent.add(joint);
    parent = joint;
  });

  beetle.add(group);
  antennae.push(group);
}

// ── Position & Ground ──────────────────────────────────
beetle.position.y = 0.15;
scene.add(beetle);

// Ground
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(12, 64),
  new THREE.MeshStandardMaterial({ color: 0x0d1117, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Subtle ground ring
const ring = new THREE.Mesh(
  new THREE.RingGeometry(1.8, 2.0, 64),
  new THREE.MeshStandardMaterial({
    color: 0x332211, roughness: 0.8, side: THREE.DoubleSide
  })
);
ring.rotation.x = -Math.PI / 2;
ring.position.y = 0.005;
scene.add(ring);

// ── Animation ──────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle walk bob
  beetle.position.y = 0.15 + Math.sin(t * 3) * 0.015;
  beetle.rotation.y = Math.sin(t * 0.5) * 0.15;

  // Leg walk cycle
  legs.forEach((leg, i) => {
    const phase = (i % 2 === 0 ? 1 : -1) * Math.sin(t * 4 + Math.floor(i / 2) * 2);
    leg.rotation.z = phase * 0.15;
    leg.rotation.x = Math.sin(t * 4 + i * 0.8) * 0.08;
  });

  // Antenna twitch
  antennae.forEach((ant, i) => {
    ant.rotation.z = Math.sin(t * 2 + i * Math.PI) * 0.1;
    ant.rotation.x = Math.sin(t * 1.5 + i * 2) * 0.05;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the beetle

| Part | Geometry | Details |
|---|---|---|
| **Abdomen** | Scaled sphere | Dark metallic shell with orange ridge line |
| **Wing covers** | Hemisphere shells | Two half-spheres flanking the ridge |
| **Thorax** | Scaled sphere | Connects abdomen to head |
| **Head** | Scaled sphere | With two cone mandibles |
| **Eyes** | Small spheres | Shiny dark on each side |
| **6 legs** | 3-segment chains | Hinged cylinders with walk animation |
| **2 antennae** | 6-segment chains | Segmented, gently twitching |

**Animations:** gentle body bob, walking leg cycle, antenna twitch, slow body sway. **OrbitControls** lets you drag to rotate and scroll to zoom.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Bell</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #1a1a2e; }
    canvas { display: block; }
    #info {
      position: absolute; top: 12px; width: 100%; text-align: center;
      color: #ccc; font-family: sans-serif; font-size: 14px; pointer-events: none;
    }
  </style>
</head>
<body>
  <div id="info">Drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.018);

    // ── Camera ─────────────────────────────────────────────
    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 5);

    // ── Renderer ───────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.2, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.update();

    // ── Lighting ───────────────────────────────────────────
    const ambient = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambient);

    const dir = new THREE.DirectionalLight(0xffeedd, 2.5);
    dir.position.set(5, 8, 4);
    dir.castShadow = true;
    dir.shadow.mapSize.set(1024, 1024);
    dir.shadow.camera.near = 1;
    dir.shadow.camera.far = 20;
    dir.shadow.camera.left = -5;
    dir.shadow.camera.right = 5;
    dir.shadow.camera.top = 5;
    dir.shadow.camera.bottom = -5;
    scene.add(dir);

    const rim = new THREE.PointLight(0x4488ff, 1.5, 12);
    rim.position.set(-3, 2, -2);
    scene.add(rim);

    const warm = new THREE.PointLight(0xffaa44, 1.0, 10);
    warm.position.set(3, 0.5, 2);
    scene.add(warm);

    // ── Bell Profile (for LatheGeometry) ───────────────────
    // Each point is [radius, height]. We trace the right-half cross-section.
    const points = [
      // Bottom rim — outer edge
      new THREE.Vector2(0.02, 0.00),
      new THREE.Vector2(0.12, 0.00),
      new THREE.Vector2(0.28, 0.01),
      new THREE.Vector2(0.42, 0.03),
      // Flared rim — outer curve
      new THREE.Vector2(0.52, 0.06),
      new THREE.Vector2(0.58, 0.10),
      new THREE.Vector2(0.60, 0.14),
      // Rim thickness — step inward
      new THREE.Vector2(0.56, 0.18),
      new THREE.Vector2(0.52, 0.20),
      // Lower body — sweeping inward
      new THREE.Vector2(0.48, 0.28),
      new THREE.Vector2(0.44, 0.38),
      new THREE.Vector2(0.40, 0.50),
      new THREE.Vector2(0.37, 0.62),
      new THREE.Vector2(0.35, 0.74),
      // Waist — narrowest point
      new THREE.Vector2(0.34, 0.82),
      new THREE.Vector2(0.35, 0.90),
      // Upper body — slight flare
      new THREE.Vector2(0.37, 0.98),
      new THREE.Vector2(0.40, 1.05),
      new THREE.Vector2(0.42, 1.10),
      // Shoulders — curve to dome
      new THREE.Vector2(0.43, 1.14),
      new THREE.Vector2(0.41, 1.18),
      new THREE.Vector2(0.37, 1.22),
      new THREE.Vector2(0.31, 1.26),
      new THREE.Vector2(0.24, 1.29),
      new THREE.Vector2(0.16, 1.31),
      // Dome top
      new THREE.Vector2(0.08, 1.32),
      new THREE.Vector2(0.02, 1.31),
      new THREE.Vector2(0.00, 1.30),
    ];

    const bellGeo = new THREE.LatheGeometry(points, 64);
    bellGeo.computeVertexNormals();

    const bellMat = new THREE.MeshStandardMaterial({
      color: 0xd4a843,
      metalness: 0.85,
      roughness: 0.22,
    });

    const bell = new THREE.Mesh(bellGeo, bellMat);
    bell.castShadow = true;
    bell.receiveShadow = true;
    scene.add(bell);

    // ── Handle / Loop on top ───────────────────────────────
    const handleCurve = new THREE.CatmullRomCurve3([
      new THREE.Vector3(0, 1.30, 0),
      new THREE.Vector3(0, 1.45, 0),
      new THREE.Vector3(0.10, 1.55, 0),
      new THREE.Vector3(0.12, 1.65, 0),
      new THREE.Vector3(0.00, 1.70, 0),
      new THREE.Vector3(-0.12, 1.65, 0),
      new THREE.Vector3(-0.10, 1.55, 0),
      new THREE.Vector3(0, 1.45, 0),
      new THREE.Vector3(0, 1.30, 0),
    ]);

    const handleGeo = new THREE.TubeGeometry(handleCurve, 48, 0.025, 12, false);
    const handle = new THREE.Mesh(handleGeo, bellMat);
    handle.castShadow = true;
    scene.add(handle);

    // ── Clapper (internal rod + ball) ──────────────────────
    const clapperRodGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.5, 12);
    const clapperMat = new THREE.MeshStandardMaterial({
      color: 0xb8862d, metalness: 0.8, roughness: 0.3
    });
    const clapperRod = new THREE.Mesh(clapperRodGeo, clapperMat);
    clapperRod.position.set(0, 0.45, 0);
    scene.add(clapperRod);

    const clapperBallGeo = new THREE.SphereGeometry(0.07, 24, 24);
    const clapperBall = new THREE.Mesh(clapperBallGeo, clapperMat);
    clapperBall.position.set(0, 0.18, 0);
    clapperBall.castShadow = true;
    scene.add(clapperBall);

    // ── Ground Plane ───────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(6, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x2a2a3e, metalness: 0.1, roughness: 0.8
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Subtle pedestal ring ───────────────────────────────
    const ringGeo = new THREE.TorusGeometry(0.65, 0.03, 16, 64);
    const ringMat = new THREE.MeshStandardMaterial({
      color: 0x888899, metalness: 0.6, roughness: 0.3
    });
    const ring = new THREE.Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = 0.005;
    ring.receiveShadow = true;
    scene.add(ring);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle sway
      bell.rotation.z = Math.sin(t * 0.8) * 0.04;
      handle.rotation.z = Math.sin(t * 0.8) * 0.04;
      clapperRod.rotation.z = Math.sin(t * 0.8) * 0.04;

      // Clapper swings opposite
      clapperBall.rotation.x = Math.sin(t * 1.2) * 0.3;
      clapperBall.position.z = Math.sin(t * 1.2) * 0.06;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

