<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.08);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0.3, 0);

// Lighting
const ambient = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xffeedd, 2);
key.position.set(3, 5, 4);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
scene.add(key);

const fill = new THREE.DirectionalLight(0x8888ff, 0.4);
fill.position.set(-3, 2, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff6688, 1.5, 10);
rim.position.set(-2, 1, -3);
scene.add(rim);

// Berry group
const berryGroup = new THREE.Group();
scene.add(berryGroup);

// --- Raspberry-like body using clustered bumps ---
const bodyMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x8b1a2b,
  roughness: 0.45,
  metalness: 0.0,
  clearcoat: 0.3,
  clearcoatRoughness: 0.4,
  sheen: 0.5,
  sheenRoughness: 0.8,
  sheenColor: new THREE.Color(0xcc2244),
});

// Create drupelets as small spheres clustered on a base shape
const drupelets = [];
const baseShape = new THREE.SphereGeometry(1, 1, 1);

// Fibonacci sphere distribution for drupelet centers
const goldenAngle = Math.PI * (3 - Math.sqrt(5));
const numDrupelets = 120;

for (let i = 0; i < numDrupelets; i++) {
  const y = 1 - (i / (numDrupelets - 1)) * 1.6;
  const radiusAtY = Math.sqrt(1 - y * y) * 0.95;
  const theta = goldenAngle * i;

  const dx = Math.cos(theta) * radiusAtY;
  const dz = Math.sin(theta) * radiusAtY;
  const dy = y * 0.85;

  const size = 0.12 + Math.random() * 0.08;

  const drupeletGeo = new THREE.SphereGeometry(size, 8, 6);
  const drupelet = new THREE.Mesh(drupeletGeo, bodyMaterial);

  drupelet.position.set(dx, dy, dz);
  drupelet.castShadow = true;
  drupelet.receiveShadow = true;

  // Slight color variation per drupelet
  const hueShift = (Math.random() - 0.5) * 0.05;
  const lightnessShift = (Math.random() - 0.5) * 0.15;
  drupelet.material = bodyMaterial.clone();
  drupelet.material.color.setRGB(
    Math.min(1, 0.55 + hueShift + lightnessShift * 0.3),
    Math.min(1, 0.1 + lightnessShift * 0.2),
    Math.min(1, 0.17 + lightnessShift * 0.3)
  );

  berryGroup.add(drupelet);
  drupelets.push(drupelet);
}

// Hollow center (slightly visible through gaps)
const coreGeo = new THREE.SphereGeometry(0.35, 16, 16);
const coreMat = new THREE.MeshStandardMaterial({
  color: 0x3a0a12,
  roughness: 0.9,
});
const core = new THREE.Mesh(coreGeo, coreMat);
core.position.y = 0.1;
berryGroup.add(core);

// --- Calyx (green leafy crown) ---
const calyxGroup = new THREE.Group();
berryGroup.add(calyxGroup);

const leafMat = new THREE.MeshPhysicalMaterial({
  color: 0x2d6b30,
  roughness: 0.6,
  metalness: 0.0,
  side: THREE.DoubleSide,
  clearcoat: 0.1,
});

for (let i = 0; i < 5; i++) {
  const angle = (i / 5) * Math.PI * 2 + Math.random() * 0.3;
  const leafGeo = new THREE.SphereGeometry(0.25, 6, 4, 0, Math.PI * 2, 0, Math.PI * 0.45);
  const leaf = new THREE.Mesh(leafGeo, leafMat);

  leaf.position.set(
    Math.cos(angle) * 0.15,
    0.75 + Math.random() * 0.1,
    Math.sin(angle) * 0.15
  );

  leaf.scale.set(1, 0.3, 1.8);
  leaf.rotation.set(
    -0.3 + Math.random() * 0.2,
    angle,
    (Math.random() - 0.5) * 0.4
  );
  leaf.castShadow = true;
  calyxGroup.add(leaf);
}

// Stem
const stemCurve = new THREE.QuadraticBezierCurve3(
  new THREE.Vector3(0, 0.85, 0),
  new THREE.Vector3(0.05, 1.15, 0.05),
  new THREE.Vector3(0.1, 1.4, 0)
);
const stemGeo = new THREE.TubeGeometry(stemCurve, 8, 0.03, 6, false);
const stemMat = new THREE.MeshStandardMaterial({ color: 0x3a7a3a, roughness: 0.7 });
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
berryGroup.add(stem);

// --- Ground plane ---
const groundGeo = new THREE.CircleGeometry(4, 48);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e,
  roughness: 0.8,
  metalness: 0.2,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.8;
ground.receiveShadow = true;
scene.add(ground);

// Subtle ring light on ground
const ringGeo = new THREE.RingGeometry(1.5, 2, 48);
const ringMat = new THREE.MeshBasicMaterial({
  color: 0xff2255,
  transparent: true,
  opacity: 0.03,
  side: THREE.DoubleSide,
});
const ring = new THREE.Mesh(ringGeo, ringMat);
ring.rotation.x = -Math.PI / 2;
ring.position.y = -0.79;
scene.add(ring);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating
  berryGroup.position.y = Math.sin(t * 0.8) * 0.1;
  berryGroup.rotation.y = t * 0.15;

  // Subtle drupelet pulsing
  drupelets.forEach((d, i) => {
    const pulse = 1 + Math.sin(t * 1.5 + i * 0.3) * 0.02;
    d.scale.setScalar(pulse);
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
