<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// Scene
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

// Camera
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 6);

// Renderer
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

// Controls
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0.5, 0);

// Lights
const ambient = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 0.8);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xff8866, 1, 15);
pointLight.position.set(2, 3, 3);
scene.add(pointLight);

// --- Build the Bib ---

// Main bib body: custom shaped plane (curved bottom like a real bib)
function createBibShape() {
  const shape = new THREE.Shape();
  const w = 1.6, h = 1.4;
  shape.moveTo(-w * 0.5, h * 0.45);
  shape.lineTo(w * 0.5, h * 0.45);
  shape.quadraticCurveTo(w * 0.55, h * 0.15, w * 0.5, -h * 0.1);
  shape.quadraticCurveTo(w * 0.3, -h * 0.55, 0, -h * 0.55);
  shape.quadraticCurveTo(-w * 0.3, -h * 0.55, -w * 0.5, -h * 0.1);
  shape.quadraticCurveTo(-w * 0.55, h * 0.15, -w * 0.5, h * 0.45);
  return shape;
}

const bibShape = createBibShape();
const bibGeo = new THREE.ShapeGeometry(bibShape, 64);

// Bend the bib slightly outward for a 3D drape effect
const pos = bibGeo.attributes.position;
for (let i = 0; i < pos.count; i++) {
  const x = pos.getX(i);
  const y = pos.getY(i);
  const bulge = Math.max(0, -y * 0.15) * (1 - x * x / (1.6 * 1.6));
  pos.setZ(i, bulge);
}
bibGeo.computeVertexNormals();

const bibMat = new THREE.MeshStandardMaterial({
  color: 0xe8e0d4,
  roughness: 0.7,
  metalness: 0.0,
  side: THREE.DoubleSide,
});

const bib = new THREE.Mesh(bibGeo, bibMat);
bib.castShadow = true;
bib.position.y = 0.6;
scene.add(bib);

// Bib trim / border
const trimMat = new THREE.MeshStandardMaterial({
  color: 0x5b8c5a,
  roughness: 0.6,
  side: THREE.DoubleSide,
});

function createTrimCurve() {
  const curve = new THREE.CurvePath();
  const pts = bibShape.getPoints(80);
  const path = new THREE.CatmullRomCurve3(
    pts.map(p => new THREE.Vector3(p.x, p.y, 0.01))
  );
  curve.add(path);
  return curve;
}

const trimCurve = createTrimCurve();
const trimGeo = new THREE.TubeGeometry(trimCurve, 200, 0.015, 8, false);
const trim = new THREE.Mesh(trimGeo, trimMat);
trim.position.y = 0.6;
scene.add(trim);

// Neck straps (two)
const strapMat = new THREE.MeshStandardMaterial({
  color: 0xe8e0d4,
  roughness: 0.7,
  side: THREE.DoubleSide,
});

function createStrap(side) {
  const curve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(side * 0.75, 1.05, 0),
    new THREE.Vector3(side * 0.9, 1.15, 0.05),
    new THREE.Vector3(side * 1.1, 1.12, 0.15),
    new THREE.Vector3(side * 1.25, 1.0, 0.2),
    new THREE.Vector3(side * 1.3, 0.85, 0.18),
  ]);
  const geo = new THREE.TubeGeometry(curve, 32, 0.035, 8, false);
  const mesh = new THREE.Mesh(geo, strapMat);
  mesh.castShadow = true;
  return mesh;
}

scene.add(createStrap(1));
scene.add(createStrap(-1));

// Strap trim
const strapTrimMat = new THREE.MeshStandardMaterial({ color: 0x5b8c5a, roughness: 0.6 });
function createStrapTrim(side) {
  const curve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(side * 0.75, 1.05, 0.015),
    new THREE.Vector3(side * 0.9, 1.15, 0.065),
    new THREE.Vector3(side * 1.1, 1.12, 0.165),
    new THREE.Vector3(side * 1.25, 1.0, 0.215),
    new THREE.Vector3(side * 1.3, 0.85, 0.195),
  ]);
  const geo = new THREE.TubeGeometry(curve, 32, 0.045, 8, false);
  return new THREE.Mesh(geo, strapTrimMat);
}
scene.add(createStrapTrim(1));
scene.add(createStrapTrim(-1));

// Snap / button at top center
const buttonGeo = new THREE.SphereGeometry(0.04, 16, 16);
const buttonMat = new THREE.MeshStandardMaterial({ color: 0xc0c0c0, metalness: 0.8, roughness: 0.2 });
const button = new THREE.Mesh(buttonGeo, buttonMat);
button.position.set(0, 1.05, 0.02);
scene.add(button);

// Small cute pattern: embroidered heart on bib
function createHeartShape() {
  const s = new THREE.Shape();
  s.moveTo(0, 0.08);
  s.bezierCurveTo(0, 0.12, -0.1, 0.14, -0.15, 0.08);
  s.bezierCurveTo(-0.2, 0.02, -0.15, -0.06, 0, 0.1);
  s.bezierCurveTo(0.15, -0.06, 0.2, 0.02, 0.15, 0.08);
  s.bezierCurveTo(0.1, 0.14, 0, 0.12, 0, 0.08);
  return s;
}

const heartGeo = new THREE.ShapeGeometry(createHeartShape(), 16);
const heartMat = new THREE.MeshStandardMaterial({ color: 0xcc6666, side: THREE.DoubleSide, roughness: 0.8 });
const heart = new THREE.Mesh(heartGeo, heartMat);
heart.position.set(0, 0.45, 0.04);
scene.add(heart);

// Ground plane
const groundGeo = new THREE.CircleGeometry(10, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1;
ground.receiveShadow = true;
scene.add(ground);

// Floating particles
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const pPositions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  pPositions[i * 3] = (Math.random() - 0.5) * 12;
  pPositions[i * 3 + 1] = Math.random() * 6 - 1;
  pPositions[i * 3 + 2] = (Math.random() - 0.5) * 12;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(pPositions, 3));
const particleMat = new THREE.PointsMaterial({ color: 0x8888aa, size: 0.02, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// Animate
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle bobbing
  bib.position.y = 0.6 + Math.sin(t * 0.8) * 0.05;
  trim.position.y = 0.6 + Math.sin(t * 0.8) * 0.05;
  heart.position.y = 0.45 + Math.sin(t * 0.8) * 0.05;
  button.position.y = 1.05 + Math.sin(t * 0.8) * 0.05;

  // Subtle sway
  bib.rotation.z = Math.sin(t * 0.5) * 0.02;
  trim.rotation.z = bib.rotation.z;
  heart.rotation.z = bib.rotation.z;
  button.rotation.z = bib.rotation.z;

  // Particle drift
  particles.rotation.y = t * 0.02;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
