new OrbitControls(c,r.domElement).autoRotate=true;

// Bobbin profile — revolved around Y axis
const pts=[
  new T.Vector2(0,-1.6),
  new T.Vector2(1.3,-1.6),
  new T.Vector2(1.3,-1.35),
  new T.Vector2(0.65,-1.2),
