  new T.Vector2(1.3,1.35),
  new T.Vector2(1.3,1.6),
  new T.Vector2(0,1.6),
];

const geo=new T.LatheGeometry(pts,48);

// Wood-like material
const mat=new T.MeshStandardMaterial({
  color:0x8B5E3C,
  roughness:0.55,
  metalness:0.1,
  side:T.DoubleSide,
});

const bobbin=new T.Mesh(geo,mat);
bobbin.castShadow=true;
s.add(bobbin);

// Thread wraps (torus rings)
const threadMat=new T.MeshStandardMaterial({color:0xE8D5B7,roughness:0.8});
for(let i=-1;i<=1;i+=0.25){
  const ring=new T.Mesh(new T.TorusGeometry(0.53,0.03,8,32),threadMat);
  ring.rotation.x=Math.PI/2;
  ring.position.y=i;
  s.add(ring);
}

// Lighting
s.add(new T.AmbientLight(0xffffff,0.4));
const dl=new T.DirectionalLight(0xffffff,1.5);
dl.position.set(5,8,6);s.add(dl);
const pl=new T.PointLight(0xffa040,0.8,20);
pl.position.set(-4,3,-2);s.add(pl);

// Subtle ground reflection
const gnd=new T.Mesh(
  new T.PlaneGeometry(30,30),
  new T.MeshStandardMaterial({color:0x111111,roughness:0.3,metalness:0.5})
);
gnd.rotation.x=-Math.PI/2;gnd.position.y=-2;
s.add(gnd);

(function anim(){
  requestAnimationFrame(anim);
  r.render(s,c);
})();

addEventListener('resize',()=>{
  c.aspect=innerWidth/innerHeight;
  c.updateProjectionMatrix();
  r.setSize(innerWidth,innerHeight);
});
</script>
</body>
</html>
