<title>Three.js Board Demo</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; font-family: system-ui; }
canvas { display: block; }
#info {
  position: absolute; top: 16px; left: 50%; transform: translateX(-50%);
  color: #fff; background: rgba(0,0,0,.5); padding: 8px 20px;
  border-radius: 20px; font-size: 14px; pointer-events: none;
  backdrop-filter: blur(8px);
}
</style>
</head>
<body>
<div id="info">🪵 Drag to orbit · Scroll to zoom</div>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

// ── Camera ─────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 5, 6);

// ── Renderer ───────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ───────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0, 0);

// ── Lighting ───────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
dirLight.shadow.bias = -0.001;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6633, 1.5, 15);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

// ── Wood Material ──────────────────────────────────
const woodMaterial = new THREE.MeshStandardMaterial({
  color: 0x8B5E3C,
  roughness: 0.7,
  metalness: 0.05,
});

const darkWoodMaterial = new THREE.MeshStandardMaterial({
  color: 0x5C3A1E,
  roughness: 0.8,
  metalness: 0.05,
});

// ── Board Group ────────────────────────────────────
const boardGroup = new THREE.Group();

// Main board body
const boardShape = new THREE.Shape();
const W = 2.4, H = 1.6, R = 0.15;
boardShape.moveTo(-W/2 + R, -H/2);
boardShape.lineTo( W/2 - R, -H/2);
boardShape.quadraticCurveTo( W/2, -H/2,  W/2, -H/2 + R);
boardShape.lineTo( W/2,  H/2 - R);
boardShape.quadraticCurveTo( W/2,  H/2,  W/2 - R,  H/2);
boardShape.lineTo(-W/2 + R,  H/2);
boardShape.quadraticCurveTo(-W/2,  H/2, -W/2,  H/2 - R);
boardShape.lineTo(-W/2, -H/2 + R);
boardShape.quadraticCurveTo(-W/2, -H/2, -W/2 + R, -H/2);

const boardExtrudeSettings = { depth: 0.12, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02, bevelSegments: 4 };
const boardGeometry = new THREE.ExtrudeGeometry(boardShape, boardExtrudeSettings);
const boardMesh = new THREE.Mesh(boardGeometry, woodMaterial);
boardMesh.rotation.x = -Math.PI / 2;
boardMesh.position.y = 0;
boardMesh.castShadow = true;
boardMesh.receiveShadow = true;
boardGroup.add(boardMesh);

// Handle
const handleShape = new THREE.Shape();
const hw = 0.5, hh = 0.25, hr = 0.12;
handleShape.moveTo(-hw/2 + hr, -hh/2);
handleShape.lineTo( hw/2 - hr, -hh/2);
handleShape.quadraticCurveTo( hw/2, -hh/2,  hw/2, -hh/2 + hr);
handleShape.lineTo( hw/2,  hh/2 - hr);
handleShape.quadraticCurveTo( hw/2,  hh/2,  hw/2 - hr,  hh/2);
handleShape.lineTo(-hw/2 + hr,  hh/2);
handleShape.quadraticCurveTo(-hw/2,  hh/2, -hw/2,  hh/2 - hr);
handleShape.lineTo(-hw/2, -hh/2 + hr);
handleShape.quadraticCurveTo(-hw/2, -hh/2, -hw/2 + hr, -hh/2);

// Handle hole
const holePath = new THREE.Path();
const holeR = 0.1;
holePath.absarc(0, 0, holeR, 0, Math.PI * 2, true);
handleShape.holes.push(holePath);

const handleExtrudeSettings = { depth: 0.1, bevelEnabled: true, bevelThickness: 0.015, bevelSize: 0.015, bevelSegments: 3 };
const handleGeometry = new THREE.ExtrudeGeometry(handleShape, handleExtrudeSettings);
const handleMesh = new THREE.Mesh(handleGeometry, darkWoodMaterial);
handleMesh.rotation.x = -Math.PI / 2;
handleMesh.position.set(0, 0, -H/2 - 0.15);
handleMesh.castShadow = true;
handleMesh.receiveShadow = true;
boardGroup.add(handleMesh);

// Juice groove (circular ring inset)
const grooveTorus = new THREE.Mesh(
  new THREE.TorusGeometry(0.55, 0.03, 8, 48),
  darkWoodMaterial
);
grooveTorus.rotation.x = -Math.PI / 2;
grooveTorus.position.y = 0.075;
boardGroup.add(grooveTorus);

// Inner groove ring
const innerGroove = new THREE.Mesh(
  new THREE.TorusGeometry(0.45, 0.02, 8, 48),
  woodMaterial
);
innerGroove.rotation.x = -Math.PI / 2;
innerGroove.position.y = 0.078;
boardGroup.add(innerGroove);

// Measurement marks
const markGeo = new THREE.BoxGeometry(0.008, 0.005, 0.06);
for (let i = 0; i < 12; i++) {
  const mark = new THREE.Mesh(markGeo, darkWoodMaterial);
  const x = -0.9 + i * 0.16;
  mark.position.set(x, 0.08, -0.65);
  mark.rotation.y = Math.PI / 2;
  boardGroup.add(mark);
}

boardGroup.position.y = 0.06;
scene.add(boardGroup);

// ── Ground Plane ───────────────────────────────────
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating Particles ─────────────────────────────
const particleCount = 60;
const particlesGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3]     = (Math.random() - 0.5) * 10;
  positions[i * 3 + 1] = Math.random() * 6 + 0.5;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 10;
}
particlesGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particlesMat = new THREE.PointsMaterial({ color: 0xffaa44, size: 0.03, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(particlesGeo, particlesMat);
scene.add(particles);

// ── Animation ──────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle board float
  boardGroup.position.y = 0.06 + Math.sin(t * 0.8) * 0.05;
  boardGroup.rotation.y = Math.sin(t * 0.3) * 0.1;

  // Particle drift
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(t + i) * 0.0003;
    if (pos.array[i * 3 + 1] > 7) pos.array[i * 3 + 1] = 0.5;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ─────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## Features

| Feature | Details |
|---|---|
| **Board** | Rounded extruded shape with beveled edges, dark wood handle with a finger hole |
| **Details** | Juice-groove torus rings, measurement tick marks along one edge |
| **Materials** | `MeshStandardMaterial` with warm wood tones, roughness & slight metalness |
| **Lighting** | Directional key light with soft shadows, blue fill light, warm rim point light, ambient |
| **Environment** | Dark ground plane receiving shadows, floating amber particles |
| **Animation** | Gentle sinusoidal float + sway on the board, particle drift |
| **Interaction** | `OrbitControls` — drag to orbit, scroll to zoom, damped smoothing |
| **Rendering** | ACES filmic tone mapping, PCF soft shadow maps, pixel-ratio capped at 2 |

Save as `index.html` and open in any modern browser — no build step needed.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Bomb</title>
<style>
* { margin: 0; padding: 0; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x110505, 0.02);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

// --- Bomb Group ---
const bomb = new THREE.Group();

// Body
const bodyGeo = new THREE.SphereGeometry(1.2, 32, 32);
bodyGeo.scale(1, 1.15, 1);
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, roughness: 0.3, metalness: 0.8
});
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.castShadow = true;
bomb.add(body);

// Danger stripe
const stripeGeo = new THREE.TorusGeometry(1.22, 0.12, 8, 48);
const stripeMat = new THREE.MeshStandardMaterial({ color: 0xcc2200, roughness: 0.5, metalness: 0.3 });
const stripe = new THREE.Mesh(stripeGeo, stripeMat);
stripe.rotation.x = Math.PI / 2;
bomb.add(stripe);

// Fins
const finMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.4, metalness: 0.9 });
for (let i = 0; i < 4; i++) {
  const fin = new THREE.Mesh(new THREE.BoxGeometry(0.15, 1.0, 0.6), finMat);
  fin.position.set(0, -1.5, 0);
  fin.rotation.y = (Math.PI / 2) * i;
  fin.castShadow = true;
  bomb.add(fin);
}

// Nose cap
const noseGeo = new THREE.SphereGeometry(0.45, 16, 16, 0, Math.PI * 2, 0, Math.PI / 2);
const noseMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.2, metalness: 0.95 });
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.y = 1.2;
nose.rotation.x = Math.PI;
nose.castShadow = true;
bomb.add(nose);

// Fuse base
const fuseBase = new THREE.Mesh(
  new THREE.CylinderGeometry(0.15, 0.2, 0.3, 12),
  new THREE.MeshStandardMaterial({ color: 0x666666, metalness: 0.9, roughness: 0.3 })
);
fuseBase.position.y = 1.75;
bomb.add(fuseBase);

// Fuse stick
const fuseStick = new THREE.Mesh(
  new THREE.CylinderGeometry(0.04, 0.04, 0.8, 8),
  new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.9 })
);
fuseStick.position.y = 2.2;
bomb.add(fuseStick);

// Spark tip
const sparkGeo = new THREE.SphereGeometry(0.08, 8, 8);
const sparkMat = new THREE.MeshBasicMaterial({ color: 0xffaa00 });
const spark = new THREE.Mesh(sparkGeo, sparkMat);
spark.position.y = 2.62;
bomb.add(spark);

// Spark glow
const glowGeo = new THREE.SphereGeometry(0.2, 8, 8);
const glowMat = new THREE.MeshBasicMaterial({ color: 0xff6600, transparent: true, opacity: 0.4 });
const glow = new THREE.Mesh(glowGeo, glowMat);
glow.position.y = 2.62;
bomb.add(glow);

// Spark particles
const sparkCount = 40;
const sparkPositions = new Float32Array(sparkCount * 3);
const sparkVelocities = [];
const sparkLife = new Float32Array(sparkCount);
for (let i = 0; i < sparkCount; i++) {
  sparkPositions[i * 3] = 0;
  sparkPositions[i * 3 + 1] = 2.62;
  sparkPositions[i * 3 + 2] = 0;
  sparkVelocities.push(new THREE.Vector3(
    (Math.random() - 0.5) * 0.04,
    Math.random() * 0.06 + 0.02,
    (Math.random() - 0.5) * 0.04
  ));
  sparkLife[i] = Math.random();
}
const sparkParticlesGeo = new THREE.BufferGeometry();
sparkParticlesGeo.setAttribute('position', new THREE.BufferAttribute(sparkPositions, 3));
const sparkParticlesMat = new THREE.PointsMaterial({
  color: 0xffcc44, size: 0.06, transparent: true, opacity: 0.9
});
const sparkParticles = new THREE.Points(sparkParticlesGeo, sparkParticlesMat);
bomb.add(sparkParticles);

scene.add(bomb);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x221111, 0.5);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xffeedd, 1.2);
mainLight.position.set(5, 5, 5);
mainLight.castShadow = true;
scene.add(mainLight);

const rimLight = new THREE.PointLight(0xff4400, 2, 10);
rimLight.position.set(-3, 2, -2);
scene.add(rimLight);

const sparkLight = new THREE.PointLight(0xff8800, 1.5, 4);
sparkLight.position.set(0, 2.6, 0);
bomb.add(sparkLight);

// Ground
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -3;
ground.receiveShadow = true;
scene.add(ground);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Slow rotation
  bomb.rotation.y = t * 0.3;

  // Spark flicker
  const flicker = 0.7 + Math.sin(t * 20) * 0.3;
  spark.scale.setScalar(flicker);
  glow.scale.setScalar(1 + Math.sin(t * 15) * 0.5);
  glowMat.opacity = 0.2 + Math.sin(t * 12) * 0.2;
  sparkLight.intensity = 1 + Math.sin(t * 18) * 0.8;

  // Update spark particles
  const positions = sparkParticlesGeo.attributes.position.array;
  for (let i = 0; i < sparkCount; i++) {
    sparkLife[i] -= 0.015;
    if (sparkLife[i] <= 0) {
      sparkLife[i] = 1;
      positions[i * 3] = 0;
      positions[i * 3 + 1] = 2.62;
      positions[i * 3 + 2] = 0;
      sparkVelocities[i].set(
        (Math.random() - 0.5) * 0.04,
        Math.random() * 0.06 + 0.02,
        (Math.random() - 0.5) * 0.04
      );
    }
    positions[i * 3] += sparkVelocities[i].x;
    positions[i * 3 + 1] += sparkVelocities[i].y;
    positions[i * 3 + 2] += sparkVelocities[i].z;
    sparkVelocities[i].y += 0.001; // slight upward drift
  }
  sparkParticlesGeo.attributes.position.needsUpdate = true;

  // Subtle camera bob
  camera.position.y = 1 + Math.sin(t * 0.5) * 0.2;
  camera.lookAt(0, 0, 0);

  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**Features:**

- **Bomb body** — dark metallic sphere with a red danger stripe
- **4 fins** — box geometries arranged radially at the base
- **Nose cap** — metallic half-sphere tip
- **Fuse** — wooden stick with a flickering spark tip and glow
- **Spark particles** — 40 particles that eject upward and reset
- **Dynamic lighting** — warm directional light, red rim light, and a pulsing spark point light
- **Animation** — slow rotation, camera bob, spark flicker, and particle physics
- **Ground plane** — dark surface with shadow reception
- **Fog** — subtle red-tinted atmospheric fog

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Three.js Boat Scene</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { overflow: hidden; background: #000; }
        canvas { display: block; }
    </style>
</head>
<body>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>
    <script>
        // --- Scene Setup ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB);
        scene.fog = new THREE.FogExp2(0x87CEEB, 0.0015);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 2000);
        camera.position.set(30, 20, 40);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.setPixelRatio(window.devicePixelRatio);
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        renderer.toneMapping = THREE.ACESFilmicToneMapping;
        renderer.toneMappingExposure = 1.2;
        document.body.appendChild(renderer.domElement);

        const controls = new THREE.OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.target.set(0, 5, 0);
        controls.maxPolarAngle = Math.PI / 2 + 0.1;

        // --- Lighting ---
        const ambientLight = new THREE.AmbientLight(0x4488bb, 0.5);
        scene.add(ambientLight);

        const sunLight = new THREE.DirectionalLight(0xffffee, 1.5);
        sunLight.position.set(50, 80, 30);
        sunLight.castShadow = true;
        sunLight.shadow.mapSize.width = 2048;
        sunLight.shadow.mapSize.height = 2048;
        sunLight.shadow.camera.near = 0.5;
        sunLight.shadow.camera.far = 200;
        sunLight.shadow.camera.left = -50;
        sunLight.shadow.camera.right = 50;
        sunLight.shadow.camera.top = 50;
        sunLight.shadow.camera.bottom = -50;
        scene.add(sunLight);

        const hemiLight = new THREE.HemisphereLight(0x87CEEB, 0x362907, 0.4);
        scene.add(hemiLight);

        // --- Water ---
        const waterGeometry = new THREE.PlaneGeometry(2000, 2000, 128, 128);
        const waterMaterial = new THREE.MeshPhongMaterial({
            color: 0x1a6b8a,
            specular: 0x444444,
            shininess: 80,
            transparent: true,
            opacity: 0.85,
            flatShading: true,
        });
        const water = new THREE.Mesh(waterGeometry, waterMaterial);
        water.rotation.x = -Math.PI / 2;
        water.receiveShadow = true;
        scene.add(water);

        // --- Boat Group ---
        const boat = new THREE.Group();

        // Hull
        const hullShape = new THREE.Shape();
        hullShape.moveTo(-10, 0);
        hullShape.quadraticCurveTo(-10, 3, -8, 4);
        hullShape.lineTo(8, 4);
        hullShape.quadraticCurveTo(10, 3, 10, 0);
        hullShape.lineTo(-10, 0);

        const extrudeSettings = { depth: 6, bevelEnabled: true, bevelThickness: 0.5, bevelSize: 0.5, bevelSegments: 3 };
        const hullGeometry = new THREE.ExtrudeGeometry(hullShape, extrudeSettings);
        const hullMaterial = new THREE.MeshPhongMaterial({ color: 0x8B4513, flatShading: true });
        const hull = new THREE.Mesh(hullGeometry, hullMaterial);
        hull.rotation.x = -Math.PI / 2;
        hull.position.set(0, 0, -3);
        hull.castShadow = true;
        hull.receiveShadow = true;
        boat.add(hull);

        // Deck
        const deckGeometry = new THREE.BoxGeometry(16, 0.3, 5.5);
        const deckMaterial = new THREE.MeshPhongMaterial({ color: 0xD2A679, flatShading: true });
        const deck = new THREE.Mesh(deckGeometry, deckMaterial);
        deck.position.set(0, 4.2, 0);
        deck.receiveShadow = true;
        deck.castShadow = true;
        boat.add(deck);

        // Cabin
        const cabinGeometry = new THREE.BoxGeometry(4, 3, 4);
        const cabinMaterial = new THREE.MeshPhongMaterial({ color: 0xF5F5DC, flatShading: true });
        const cabin = new THREE.Mesh(cabinGeometry, cabinMaterial);
        cabin.position.set(-2, 5.85, 0);
        cabin.castShadow = true;
        cabin.receiveShadow = true;
        boat.add(cabin);

        // Cabin roof
        const roofGeometry = new THREE.BoxGeometry(4.6, 0.3, 4.6);
        const roofMaterial = new THREE.MeshPhongMaterial({ color: 0x8B0000, flatShading: true });
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.set(-2, 7.4, 0);
        roof.castShadow = true;
        boat.add(roof);

        // Mast
        const mastGeometry = new THREE.CylinderGeometry(0.2, 0.3, 18, 8);
        const mastMaterial = new THREE.MeshPhongMaterial({ color: 0x654321, flatShading: true });
        const mast = new THREE.Mesh(mastGeometry, mastMaterial);
        mast.position.set(2, 13, 0);
        mast.castShadow = true;
        boat.add(mast);

        // Main Sail
        const sailShape = new THREE.Shape();
        sailShape.moveTo(0, 0);
        sailShape.quadraticCurveTo(5, 4, 3, 10);
        sailShape.lineTo(0, 10);
        sailShape.lineTo(0, 0);

        const sailGeometry = new THREE.ShapeGeometry(sailShape);
        const sailMaterial = new THREE.MeshPhongMaterial({
            color: 0xFAF0E6,
            side: THREE.DoubleSide,
            flatShading: true,
            transparent: true,
            opacity: 0.92
        });
        const sail = new THREE.Mesh(sailGeometry, sailMaterial);
        sail.position.set(2.2, 7, 0);
        sail.castShadow = true;
        boat.add(sail);

        // Front sail
        const frontSailShape = new THREE.Shape();
        frontSailShape.moveTo(0, 0);
        frontSailShape.quadraticCurveTo(3, 3, 2, 7);
        frontSailShape.lineTo(0, 7);
        frontSailShape.lineTo(0, 0);

        const frontSailGeometry = new THREE.ShapeGeometry(frontSailShape);
        const frontSail = new THREE.Mesh(frontSailGeometry, sailMaterial);
        frontSail.position.set(2.2, 7, 2.5);
        frontSail.castShadow = true;
        boat.add(frontSail);

        // Back sail
        const backSail = new THREE.Mesh(frontSailGeometry, sailMaterial);
        backSail.position.set(2.2, 7, -2.5);
        backSail.castShadow = true;
        boat.add(backSail);

        // Railing
        const railingMaterial = new THREE.MeshPhongMaterial({ color: 0x4a3728 });
        for (let i = -7; i <= 7; i += 2) {
            const post = new THREE.Mesh(
                new THREE.CylinderGeometry(0.08, 0.08, 1.5, 6),
                railingMaterial
            );
            post.position.set(i, 5.1, 2.5);
            boat.add(post);
            const post2 = post.clone();
            post2.position.z = -2.5;
            boat.add(post2);
        }

        // Rail bars
        const railBarGeo1 = new THREE.CylinderGeometry(0.05, 0.05, 14.5, 6);
        const railBar1 = new THREE.Mesh(railBarGeo1, railingMaterial);
        railBar1.rotation.z = Math.PI / 2;
        railBar1.position.set(0, 5.5, 2.5);
        boat.add(railBar1);
        const railBar2 = railBar1.clone();
        railBar2.position.z = -2.5;
        boat.add(railBar2);

        // Bow ornament (figurehead)
        const ornamentGeo = new THREE.SphereGeometry(0.4, 8, 8);
        const ornamentMat = new THREE.MeshPhongMaterial({ color: 0xFFD700, flatShading: true });
        const ornament = new THREE.Mesh(ornamentGeo, ornamentMat);
        ornament.position.set(10.5, 3, 0);
        boat.add(ornament);

        boat.position.set(0, 0, 0);
        scene.add(boat);

        // --- Clouds ---
        const cloudGroup = new THREE.Group();
        function createCloud(x, y, z) {
            const group = new THREE.Group();
            const cloudMat = new THREE.MeshPhongMaterial({ color: 0xffffff, flatShading: true, transparent: true, opacity: 0.85 });
            const count = 3 + Math.floor(Math.random() * 4);
            for (let i = 0; i < count; i++) {
                const size = 2 + Math.random() * 4;
                const geo = new THREE.SphereGeometry(size, 7, 5);
                const mesh = new THREE.Mesh(geo, cloudMat);
                mesh.position.set(Math.random() * 8 - 4, Math.random() * 2, Math.random() * 4 - 2);
                mesh.scale.y = 0.5;
                group.add(mesh);
            }
            group.position.set(x, y, z);
            return group;
        }

        const clouds = [];
        for (let i = 0; i < 12; i++) {
            const cloud = createCloud(
                Math.random() * 400 - 200,
                40 + Math.random() * 30,
                Math.random() * 400 - 200
            );
            clouds.push(cloud);
            cloudGroup.add(cloud);
        }
        scene.add(cloudGroup);

        // --- Sun ---
        const sunGeo = new THREE.SphereGeometry(5, 16, 16);
        const sunMat = new THREE.MeshBasicMaterial({ color: 0xFFEE88 });
        const sunMesh = new THREE.Mesh(sunGeo, sunMat);
        sunMesh.position.copy(sunLight.position);
        scene.add(sunMesh);

        // --- Animation ---
        const clock = new THREE.Clock();

        function animate() {
            requestAnimationFrame(animate);
            const t = clock.getElapsedTime();

            // Boat bobbing
            boat.position.y = Math.sin(t * 0.8) * 0.5;
            boat.rotation.z = Math.sin(t * 0.5) * 0.02;
            boat.rotation.x = Math.sin(t * 0.3) * 0.01;
            boat.rotation.y = Math.sin(t * 0.15) * 0.05;

            // Water wave animation
            const positions = waterGeometry.attributes.position;
            for (let i = 0; i < positions.count; i++) {
                const x = positions.getX(i);
                const y = positions.getY(i);
                const z = Math.sin(x * 0.05 + t * 0.8) * 0.8 +
                          Math.cos(y * 0.03 + t * 0.6) * 0.5 +
                          Math.sin((x + y) * 0.02 + t * 1.2) * 0.3;
                positions.setZ(i, z);
            }
            positions.needsUpdate = true;
            waterGeometry.computeVertexNormals();

            // Cloud drift
            clouds.forEach((cloud, i) => {
                cloud.position.x += 0.02 + i * 0.005;
                if (cloud.position.x > 250) cloud.position.x = -250;
            });

            controls.update();
            renderer.render(scene, camera);
        }

        animate();

        // --- Resize ---
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });
    </script>
</body>
</html>
```

