import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(4, 3.5, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Environment (for reflections) ---
const pmremGenerator = new THREE.PMREMGenerator(renderer);
pmremGenerator.compileEquirectangularShader();
const envTexture = pmremGenerator.fromScene(new RoomEnvironment(), 0.04).texture;
scene.environment = envTexture;

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0.8, 0);
controls.minDistance = 3;
controls.maxDistance = 15;
controls.maxPolarAngle = Math.PI / 2 + 0.1;

// --- Bowl Geometry (Lathe) ---
function createBowlProfile() {
  const points = [];
  const segments = 40;

  // Profile points from bottom to rim
  // Starting at bottom center (on axis)
  for (let i = 0; i <= segments; i++) {
    const t = i / segments;

    // Create a nice bowl curve
    let x, y;

    if (t < 0.05) {
      // Rounded bottom
      const bt = t / 0.05;
      x = 0.15 * Math.sin(bt * Math.PI / 2);
      y = 0.02 + 0.08 * (1 - Math.cos(bt * Math.PI / 2));
    } else if (t < 0.5) {
      // Lower bowl body - curves outward
      const bt = (t - 0.05) / 0.45;
      x = 0.15 + 0.85 * Math.pow(bt, 0.6);
      y = 0.1 + bt * 1.2;
    } else if (t < 0.85) {
      // Upper bowl body - flares out
      const bt = (t - 0.5) / 0.35;
      x = 1.0 + 0.35 * Math.pow(bt, 0.5);
      y = 1.3 + bt * 0.5;
    } else {
      // Rim - slight lip
      const bt = (t - 0.85) / 0.15;
      const rimX = 1.35 + 0.08 * Math.sin(bt * Math.PI);
      const rimY = 1.8 + 0.05 * Math.sin(bt * Math.PI);
      x = rimX;
      y = rimY;
    }

    points.push(new THREE.Vector2(x, y));
  }

  return points;
}

function createBowlInnerProfile() {
  const points = [];
  const segments = 40;

  for (let i = 0; i <= segments; i++) {
    const t = i / segments;

    let x, y;

    if (t < 0.02) {
      const bt = t / 0.02;
      x = 0.05 * Math.sin(bt * Math.PI / 2);
      y = 0.06 + 0.03 * (1 - Math.cos(bt * Math.PI / 2));
    } else if (t < 0.55) {
      const bt = (t - 0.02) / 0.53;
      x = 0.05 + 0.7 * Math.pow(bt, 0.55);
      y = 0.09 + bt * 1.15;
    } else if (t < 0.9) {
      const bt = (t - 0.55) / 0.35;
      x = 0.75 + 0.3 * Math.pow(bt, 0.5);
      y = 1.24 + bt * 0.45;
    } else {
      const bt = (t - 0.9) / 0.1;
      x = 1.05 + 0.05 * Math.sin(bt * Math.PI);
      y = 1.69 + 0.03 * Math.sin(bt * Math.PI);
    }

    points.push(new THREE.Vector2(x, y));
  }

  return points;
}

// --- Build Bowl ---
const bowlGroup = new THREE.Group();

// Outer bowl
const outerProfile = createBowlProfile();
const outerGeometry = new THREE.LatheGeometry(outerProfile, 64);
outerGeometry.computeVertexNormals();

// Inner bowl (hole)
const innerProfile = createBowlInnerProfile();
const innerGeometry = new THREE.LatheGeometry(innerProfile, 64);
innerGeometry.computeVertexNormals();

