outerMesh.castShadow = true;
outerMesh.receiveShadow = true;

const innerMesh = new THREE.Mesh(innerGeometry, innerMaterial);
innerMesh.castShadow = true;
innerMesh.receiveShadow = true;

bowlGroup.add(outerMesh);
bowlGroup.add(innerMesh);

// Rim ring for extra detail
const rimCurve = new THREE.EllipseCurve(0, 0, 1.4, 1.4, 0, 2 * Math.PI, false, 0);
const rimPoints = rimCurve.getPoints(64);
const rimGeometry3D = new THREE.BufferGeometry().setFromPoints(
  rimPoints.map(p => new THREE.Vector3(p.x, 1.82, p.y))
);
const rimTubeGeo = new THREE.TubeGeometry(
  new THREE.CatmullRomCurve3(
    Array.from({ length: 64 }, (_, i) => {
      const angle = (i / 64) * Math.PI * 2;
      return new THREE.Vector3(
        Math.cos(angle) * 1.4,
        1.82,
        Math.sin(angle) * 1.4
      );
    })
  ),
  128, 0.025, 16, true
);
const rimMesh = new THREE.Mesh(rimTubeGeo, outerMaterial);
rimMesh.castShadow = true;
bowlGroup.add(rimMesh);

scene.add(bowlGroup);

// --- Ground Plane ---
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x12121e,
  roughness: 0.85,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// --- Decorative: Small table surface ---
const tableGeo = new THREE.CylinderGeometry(2.5, 2.7, 0.08, 64);
const tableMat = new THREE.MeshPhysicalMaterial({
  color: 0x1e1510,
  roughness: 0.6,
  metalness: 0.05,
  clearcoat: 0.1,
});
const table = new THREE.Mesh(tableGeo, tableMat);
table.position.y = -0.04;
table.receiveShadow = true;
table.castShadow = true;
scene.add(table);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xffeedd, 3);
mainLight.position.set(4, 8, 3);
mainLight.castShadow = true;
mainLight.shadow.mapSize.width = 2048;
mainLight.shadow.mapSize.height = 2048;
mainLight.shadow.camera.near = 0.5;
mainLight.shadow.camera.far = 25;
mainLight.shadow.camera.left = -5;
mainLight.shadow.camera.right = 5;
mainLight.shadow.camera.top = 5;
mainLight.shadow.camera.bottom = -5;
mainLight.shadow.bias = -0.001;
