scene.add(mainLight);

const fillLight = new THREE.DirectionalLight(0x8888cc, 0.8);
fillLight.position.set(-3, 4, -2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffaa44, 1.5, 10);
rimLight.position.set(-2, 3, 2);
scene.add(rimLight);

const bottomLight = new THREE.PointLight(0x4466aa, 0.4, 8);
bottomLight.position.set(0, -1, 0);
scene.add(bottomLight);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle floating animation
  bowlGroup.position.y = Math.sin(elapsed * 0.5) * 0.03;
  bowlGroup.rotation.y = elapsed * 0.1;

  // Subtle light animation
