</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.015);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 3, 14);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;

// Lighting
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const sun = new THREE.DirectionalLight(0xffeedd, 2.5);
sun.position.set(5, 10, 5);
scene.add(sun);

const rim = new THREE.DirectionalLight(0x4488ff, 0.6);
rim.position.set(-5, 3, -5);
scene.add(rim);

// Materials
const barkMat = new THREE.MeshStandardMaterial({
  color: 0x5c3a1e,
  roughness: 0.95,
  metalness: 0.0,
});

const leafMat = new THREE.MeshStandardMaterial({
  color: 0x2d6b30,
  roughness: 0.7,
  metalness: 0.0,
});

const branchGroup = new THREE.Group();
scene.add(branchGroup);

// Procedural branch generation
function createBranch(origin, direction, length, radius, depth, maxDepth) {
  if (depth > maxDepth || radius < 0.015) return;

  const segments = 5;
  const geometry = new THREE.CylinderGeometry(
    radius * 0.7, radius, length, segments
  );
  geometry.translate(0, length / 2, 0);

  const mesh = new THREE.Mesh(geometry, barkMat);
  mesh.position.copy(origin);

  // Orient along direction
  const up = new THREE.Vector3(0, 1, 0);
  const quat = new THREE.Quaternion().setFromUnitVectors(up, direction.clone().normalize());
  mesh.quaternion.copy(quat);
  branchGroup.add(mesh);

  const tip = origin.clone().add(direction.clone().normalize().multiplyScalar(length));

  if (depth < maxDepth) {
    const numBranches = depth < 2 ? 3 : 2;
    const spread = 0.5 + Math.random() * 0.3;

    for (let i = 0; i < numBranches; i++) {
      const newDir = direction.clone().normalize();

      // Create perpendicular offsets
      const perp1 = new THREE.Vector3();
      const perp2 = new THREE.Vector3();
      newDir.clone().crossVectors(
        newDir, new THREE.Vector3(Math.random() - 0.5, Math.random() - 0.5, Math.random() - 0.5)
      ).normalize();
      perp1.crossVectors(newDir, perp1).normalize();
      perp2.crossVectors(newDir, perp1).normalize();

      const angle = spread * (0.6 + Math.random() * 0.4) * (i / (numBranches - 1 || 1));
      const tilt = (Math.random() - 0.5) * spread * 0.8;

      newDir.applyAxisAngle(perp1, angle);
      newDir.applyAxisAngle(perp2, tilt);

      // Slight upward bias
      newDir.y += 0.1;
      newDir.normalize();

      const newLength = length * (0.65 + Math.random() * 0.15);
      const newRadius = radius * (0.55 + Math.random() * 0.1);
      const branchOrigin = tip.clone().add(
        new THREE.Vector3(
          (Math.random() - 0.5) * 0.05,
          (Math.random() - 0.5) * 0.05,
          (Math.random() - 0.5) * 0.05
        )
      );

      createBranch(branchOrigin, newDir, newLength, newRadius, depth + 1, maxDepth);
    }

    // Add leaf clusters at tips
    if (depth >= maxDepth - 1) {
      const leafSize = 0.15 + Math.random() * 0.2;
      for (let j = 0; j < 3 + Math.floor(Math.random() * 4); j++) {
        const leafGeo = new THREE.SphereGeometry(leafSize * (0.5 + Math.random() * 0.5), 5, 4);
        const leaf = new THREE.Mesh(leafGeo, leafMat);
        leaf.position.copy(tip).add(
          new THREE.Vector3(
            (Math.random() - 0.5) * 0.8,
            (Math.random() - 0.5) * 0.8,
            (Math.random() - 0.5) * 0.8
          )
        );
        leaf.scale.set(1, 0.4 + Math.random() * 0.3, 1);
        branchGroup.add(leaf);
      }
    }
  }
}

// Seed the main trunk
const seed = 42;
createBranch(
  new THREE.Vector3(0, -1, 0),
  new THREE.Vector3(0.1, 1, 0.05),
  3.5, 0.22, 0, 5
);

// Small secondary stump
createBranch(
  new THREE.Vector3(0.3, -0.5, 0.1),
  new THREE.Vector3(0.3, 0.9, -0.2),
  2.0, 0.12, 0, 4
);

// Ground plane
const groundGeo = new THREE.CircleGeometry(12, 32);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x1a2a1a, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1;
scene.add(ground);

// Subtle particles (dust/pollen)
const particleCount = 150;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 16;
  positions[i * 3 + 1] = Math.random() * 8;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 16;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xaacc88,
  size: 0.04,
  transparent: true,
  opacity: 0.6,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// Animate
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  branchGroup.rotation.y = Math.sin(t * 0.3) * 0.02;
  branchGroup.rotation.z = Math.sin(t * 0.2) * 0.01;

  // Float particles
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(t + i) * 0.001;
    pos.array[i * 3] += Math.cos(t * 0.5 + i * 0.1) * 0.0005;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
