// --- Brain Geometry ---
const simplex = new SimplexNoise(42);
const simplex2 = new SimplexNoise(137);

function createBrainGeometry() {
  const geo = new THREE.IcosahedronGeometry(1, 64);
  const pos = geo.attributes.position;
  const vec = new THREE.Vector3();

  for (let i = 0; i < pos.count; i++) {
    vec.fromBufferAttribute(pos, i);
    const x = vec.x, y = vec.y, z = vec.z;

    // Brain shape deformation
    // Flatten slightly on z-axis, elongate on x
    let bx = x * 1.3;
    let by = y * 0.9;
    let bz = z * 0.85;

    // Create two hemispheres with a gap in the middle
    const midGap = Math.exp(-bx * bx * 20) * 0.15;
    bz -= midGap;

    // Taper the front (frontal lobe) and back (occipital)
    const frontTaper = 1.0 - Math.max(0, (bx - 0.5) * 0.3);
    const backTaper = 1.0 - Math.max(0, (-bx - 0.5) * 0.3);
    const taper = frontTaper * backTaper;

    // Taper top/bottom
    const topTaper = 1.0 - Math.max(0, (by - 0.3) * 0.4);
    const bottomTaper = 1.0 - Math.max(0, (-by - 0.4) * 0.5);

    // Cerebellum bulge at the back-bottom
    const cerebellum = Math.exp(-((bx + 0.8)**2 + (by - 0.3)**2 + bz**2) * 8) * 0.25;

    const scale = (taper * topTaper * bottomTaper) + cerebellum;

    vec.set(
      bx * scale,
      by * scale,
      bz * scale
    );

    // Gyri/sulci displacement using layered noise
    const freq1 = 6.0, freq2 = 12.0, freq3 = 24.0;
    let n = 0;
    n += simplex.noise3D(bx * freq1, by * freq1, bz * freq1) * 0.06;
    n += simplex.noise3D(bx * freq2, by * freq2, bz * freq2) * 0.03;
    n += simplex.noise3D(bx * freq3, by * freq3, bz * freq3) * 0.015;
    n += simplex2.noise3D(bx * freq2 * 1.5, by * freq2 * 1.5, bz * freq2 * 1.5) * 0.02;

    // Directional noise for ridge-like gyri patterns
    const ridgeAngle = Math.atan2(by, bz);
    const ridge = simplex.noise3D(
      bx * 4 + Math.cos(ridgeAngle) * 3,
      by * 4 + Math.sin(ridgeAngle) * 3,
      bz * 4
    );
    n += (1.0 - Math.abs(ridge)) * 0.025;

    // Reduce displacement at edges
    const dist = vec.length();
    const edgeFade = Math.max(0, 1.0 - Math.pow(dist / 1.2, 3));
    n *= edgeFade;

    const normal = vec.clone().normalize();
    vec.add(normal.multiplyScalar(n));

    pos.setXYZ(i, vec.x, vec.y, vec.z);
  }

  geo.computeVertexNormals();
  return geo;
}

