    uniform float uTime;
    uniform vec3 uColor1, uColor2, uColor3;
    uniform vec3 uLightPos1, uLightPos2;
    uniform vec3 uLightColor1, uLightColor2;

    varying vec3 vNormal;
    varying vec3 vWorldPos;
    varying vec3 vViewDir;
