      vec3 H1 = normalize(L1 + V);
      vec3 H2 = normalize(L2 + V);

      float diff1 = max(dot(N, L1), 0.0);
      float diff2 = max(dot(N, L2), 0.0) * 0.4;
      float spec1 = pow(max(dot(N, H1), 0.0), 40.0);
      float spec2 = pow(max(dot(N, H2), 0.0), 20.0);

      // Color blending based on displacement (ridges lighter, valleys darker)
      float t = smoothstep(-0.06, 0.06, vDisplacement);
      vec3 baseColor = mix(uColor2, uColor1, t);
      baseColor = mix(baseColor, uColor3, pow(max(dot(N, H1), 0.0), 8.0) * 0.5);

      // Subtle pulsing
      float pulse = 1.0 + sin(uTime * 1.5) * 0.03;

      // Fresnel rim
      float rim = fresnel(V, N, 3.0);

      vec3 ambient = baseColor * 0.25 * pulse;
      vec3 diffuse = baseColor * (diff1 * 0.8 + diff2) * pulse;
      vec3 specular = (uLightColor1 * spec1 + uLightColor2 * spec2 * 0.3) * 0.6;
      vec3 rimLight = uLightColor2 * rim * 0.35;

      vec3 finalColor = ambient + diffuse + specular + rimLight;

      // Tone mapping
      finalColor = finalColor / (finalColor + vec3(1.0));

      gl_FragColor = vec4(finalColor, 1.0);
    }
  `
});

