function buildFlorets() {
  const clusters = [];

  // Main crown clusters — positions on a hemisphere
  const crownRadius = 1.6;
  const crownCenter = new THREE.Vector3(0, 3.4, 0);

  // Distribute cluster centers using fibonacci sphere (upper hemisphere)
  const numClusters = 28;
  const goldenAngle = Math.PI * (3 - Math.sqrt(5));

  for (let i = 0; i < numClusters; i++) {
    const y = 1 - (i / (numClusters - 1)) * 0.95; // 0.05 to 1
    const radiusAtY = Math.sqrt(1 - y * y);
    const theta = goldenAngle * i;
    const cx = radiusAtY * Math.cos(theta);
    const cz = radiusAtY * Math.sin(theta);
    const cy = y;

    clusters.push({
      pos: new THREE.Vector3(cx * crownRadius, cy * crownRadius * 0.7 + 3.0, cz * crownRadius),
      scale: 0.25 + Math.random() * 0.15,
      tip: i < numClusters * 0.4
    });
  }

  // Add some outer/edge clusters
  for (let i = 0; i < 12; i++) {
    const angle = (i / 12) * Math.PI * 2;
    const r = crownRadius * (0.85 + Math.random() * 0.2);
    clusters.push({
      pos: new THREE.Vector3(
        Math.cos(angle) * r,
        2.8 + Math.random() * 0.5,
        Math.sin(angle) * r
      ),
      scale: 0.18 + Math.random() * 0.1,
      tip: false
    });
  }

  // For each cluster, create multiple floret spheres
  const mainFlorets = [];
  const tipFlorets = [];

  for (const cluster of clusters) {
    const numSpheres = 4 + Math.floor(Math.random() * 4);
    for (let j = 0; j < numSpheres; j++) {
      const spread = cluster.scale * 0.6;
      const offset = new THREE.Vector3(
        (Math.random() - 0.5) * spread,
        (Math.random() - 0.5) * spread * 0.6,
        (Math.random() - 0.5) * spread
      );
      const pos = cluster.pos.clone().add(offset);
      const s = cluster.scale * (0.5 + Math.random() * 0.5);

      if (cluster.tip) {
