  roughness: 0.85,
  metalness: 0.0,
});

const darkStrawMat = new THREE.MeshStandardMaterial({
  color: 0xB8922E,
  roughness: 0.9,
  metalness: 0.0,
});

const bindingMat = new THREE.MeshStandardMaterial({
  color: 0x3A2A0A,
  roughness: 0.6,
  metalness: 0.1,
});

const metalMat = new THREE.MeshStandardMaterial({
  color: 0x888888,
  roughness: 0.3,
  metalness: 0.8,
});

// ── Broom Group ────────────────────────────────────────
const broom = new THREE.Group();

// ── Handle ─────────────────────────────────────────────
const handleGeo = new THREE.CylinderGeometry(0.06, 0.07, 5.5, 12);
const handle = new THREE.Mesh(handleGeo, woodMat);
handle.position.y = 5.2;
handle.castShadow = true;
broom.add(handle);

// Handle cap (top knob)
const capGeo = new THREE.SphereGeometry(0.09, 12, 12);
const cap = new THREE.Mesh(capGeo, darkWoodMat);
cap.position.y = 7.98;
cap.castShadow = true;
broom.add(cap);

// ── Brush Head (top platform) ──────────────────────────
const headGeo = new THREE.CylinderGeometry(0.35, 0.25, 0.15, 16);
const head = new THREE.Mesh(headGeo, darkWoodMat);
head.position.y = 2.65;
head.castShadow = true;
broom.add(head);

// ── Binding rings ──────────────────────────────────────
for (let i = 0; i < 3; i++) {
  const ringGeo = new THREE.TorusGeometry(0.28 - i * 0.02, 0.025, 8, 24);
  const ring = new THREE.Mesh(ringGeo, bindingMat);
  ring.rotation.x = Math.PI / 2;
  ring.position.y = 2.55 - i * 0.08;
  ring.castShadow = true;
  broom.add(ring);
}

// ── Bristles ───────────────────────────────────────────
const BRISTLE_COUNT = 120;
const bristleGroup = new THREE.Group();
bristleGroup.position.y = 2.55;

for (let i = 0; i < BRISTLE_COUNT; i++) {
  const angle = (i / BRISTLE_COUNT) * Math.PI * 2 + (Math.random() - 0.5) * 0.15;
  const radius = 0.1 + Math.random() * 0.22;
  const length = 1.2 + Math.random() * 0.8;

  const bristleGeo = new THREE.CylinderGeometry(0.008, 0.004, length, 5);
  const mat = Math.random() > 0.4 ? strawMat : darkStrawMat;
  const bristle = new THREE.Mesh(bristleGeo, mat);

  // Position at base circle
  bristle.position.x = Math.cos(angle) * radius;
  bristle.position.z = Math.sin(angle) * radius;
  bristle.position.y = -length / 2 + 0.1;

  // Tilt outward
  const tiltAngle = 0.15 + Math.random() * 0.3;
  bristle.rotation.z = Math.cos(angle) * tiltAngle;
  bristle.rotation.x = -Math.sin(angle) * tiltAngle;

  // Slight random twist
  bristle.rotation.y = Math.random() * Math.PI * 2;

  bristle.castShadow = true;
  bristleGroup.add(bristle);
}

broom.add(bristleGroup);

// ── Extra: inner bristle cluster for density ───────────
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = Math.random() * 0.18;
  const length = 1.0 + Math.random() * 0.6;

  const bristleGeo = new THREE.CylinderGeometry(0.006, 0.003, length, 4);
  const mat = Math.random() > 0.3 ? strawMat : darkStrawMat;
  const bristle = new THREE.Mesh(bristleGeo, mat);

  bristle.position.x = Math.cos(angle) * radius;
  bristle.position.z = Math.sin(angle) * radius;
  bristle.position.y = -length / 2 + 0.05;

  const tiltAngle = 0.05 + Math.random() * 0.2;
  bristle.rotation.z = Math.cos(angle) * tiltAngle;
  bristle.rotation.x = -Math.sin(angle) * tiltAngle;
  bristle.rotation.y = Math.random() * Math.PI * 2;

  bristle.castShadow = true;
  bristleGroup.add(bristle);
}

// ── Position broom ─────────────────────────────────────
broom.rotation.z = 0.15;
broom.rotation.x = -0.05;
broom.position.y = 0;
scene.add(broom);

// ── Ground ─────────────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Grid helper (subtle)
const grid = new THREE.GridHelper(20, 40, 0x333355, 0x222244);
grid.position.y = 0.005;
scene.add(grid);

// ── Floating particles (dust) ──────────────────────────
const particleCount = 80;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
const particleSpeeds = [];

for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3] = (Math.random() - 0.5) * 10;
  particlePositions[i * 3 + 1] = Math.random() * 8;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 10;
  particleSpeeds.push(0.002 + Math.random() * 0.005);
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0xffddaa,
  size: 0.04,
  transparent: true,
  opacity: 0.5,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  broom.rotation.z = 0.15 + Math.sin(t * 0.5) * 0.02;
  broom.rotation.x = -0.05 + Math.cos(t * 0.3) * 0.01;

  // Animate particles
  const positions = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    positions[i * 3 + 1] += particleSpeeds[i];
    positions[i * 3] += Math.sin(t + i) * 0.001;
    if (positions[i * 3 + 1] > 8) {
      positions[i * 3 + 1] = 0;
    }
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
