  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';

// — Scene, camera, renderer —
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x000000, 0.04);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// — Controls —
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 1.2, 0);

// — Post-processing bloom —
const composer = new EffectComposer(renderer);
composer.addPass(new RenderPass(scene, camera));
const bloom = new UnrealBloomPass(
  new THREE.Vector2(innerWidth, innerHeight), 1.5, 0.4, 0.85
);
bloom.threshold = 0.2;
bloom.strength = 2.0;
bloom.radius = 0.8;
composer.addPass(bloom);

// — Bulb group —
const bulb = new THREE.Group();
bulb.position.y = 0;

// Glass bulb (sphere, slightly elongated)
const glassGeo = new THREE.SphereGeometry(1, 64, 64);
glassGeo.scale(1, 1.15, 1);
const glassMat = new THREE.MeshPhysicalMaterial({
  color: 0xffffee,
  transparent: true,
  opacity: 0.15,
  roughness: 0.0,
  metalness: 0.0,
  transmission: 0.95,
  thickness: 0.5,
  ior: 1.5,
  emissive: 0xffdd88,
  emissiveIntensity: 0.3,
});
const glass = new THREE.Mesh(glassGeo, glassMat);
glass.position.y = 1.6;
bulb.add(glass);

// Filament wireframe (inner glow source)
const filamentGeo = new THREE.CylinderGeometry(0.02, 0.02, 0.6, 8);
const filamentMat = new THREE.MeshBasicMaterial({ color: 0xffeeaa });
const filament = new THREE.Mesh(filamentGeo, filamentMat);
filament.position.y = 1.5;
bulb.add(filament);

// Filament support wires
const wireMat = new THREE.MeshBasicMaterial({ color: 0xffddaa, transparent: true, opacity: 0.6 });
for (let i = 0; i < 6; i++) {
  const angle = (i / 6) * Math.PI * 2;
  const wireGeo = new THREE.CylinderGeometry(0.008, 0.008, 0.5, 6);
  const wire = new THREE.Mesh(wireGeo, wireMat);
  wire.position.set(
    Math.cos(angle) * 0.12,
    1.3,
    Math.sin(angle) * 0.12
  );
  wire.rotation.z = Math.cos(angle) * 0.4;
  wire.rotation.x = Math.sin(angle) * 0.4;
  bulb.add(wire);
}

// Metal screw base
const baseGeo = new THREE.CylinderGeometry(0.45, 0.45, 0.5, 32);
const baseMat = new THREE.MeshStandardMaterial({
  color: 0x888888,
  metalness: 0.9,
  roughness: 0.2,
});
const base = new THREE.Mesh(baseGeo, baseMat);
base.position.y = 0.55;
bulb.add(base);

// Base ridges
for (let i = 0; i < 5; i++) {
  const ridgeGeo = new THREE.TorusGeometry(0.46, 0.02, 8, 32);
  const ridge = new THREE.Mesh(ridgeGeo, baseMat);
  ridge.position.y = 0.35 + i * 0.07;
  ridge.rotation.x = Math.PI / 2;
  bulb.add(ridge);
}

// Bottom contact tip
const tipGeo = new THREE.CylinderGeometry(0.15, 0.1, 0.15, 16);
const tipMat = new THREE.MeshStandardMaterial({
  color: 0x555555,
  metalness: 0.8,
  roughness: 0.4,
});
const tip = new THREE.Mesh(tipGeo, tipMat);
tip.position.y = 0.22;
bulb.add(tip);

// Insulating ring
const ringGeo = new THREE.TorusGeometry(0.18, 0.03, 8, 16);
const ringMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.8 });
const ring = new THREE.Mesh(ringGeo, ringMat);
ring.position.y = 0.3;
ring.rotation.x = Math.PI / 2;
bulb.add(ring);

scene.add(bulb);

// — Inner point light —
const innerLight = new THREE.PointLight(0xffddaa, 80, 20, 1.5);
innerLight.position.set(0, 1.5, 0);
bulb.add(innerLight);

// Ambient
scene.add(new THREE.AmbientLight(0x111122, 0.3));

// — Floor —
const floorGeo = new THREE.PlaneGeometry(30, 30);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x111111,
  roughness: 0.6,
  metalness: 0.3,
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -0.01;
scene.add(floor);

// — Ceiling (to bounce light) —
const ceiling = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.9 })
);
ceiling.rotation.x = Math.PI / 2;
ceiling.position.y = 5;
scene.add(ceiling);

// — Dust particles —
const dustCount = 300;
const dustGeo = new THREE.BufferGeometry();
const dustPos = new Float32Array(dustCount * 3);
for (let i = 0; i < dustCount; i++) {
  dustPos[i * 3]     = (Math.random() - 0.5) * 10;
  dustPos[i * 3 + 1] = Math.random() * 5;
  dustPos[i * 3 + 2] = (Math.random() - 0.5) * 10;
}
dustGeo.setAttribute('position', new THREE.BufferAttribute(dustPos, 3));
const dustMat = new THREE.PointsMaterial({
  color: 0xffddaa,
  size: 0.03,
  transparent: true,
  opacity: 0.4,
  blending: THREE.AdditiveBlending,
  depthWrite: false,
});
const dust = new THREE.Points(dustGeo, dustMat);
scene.add(dust);

// — Animation —
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Subtle flicker
  innerLight.intensity = 80 + Math.sin(t * 8) * 2 + Math.sin(t * 13.7) * 1.5;
  glassMat.emissiveIntensity = 0.3 + Math.sin(t * 8) * 0.02;

  // Gently rotate dust
  dust.rotation.y = t * 0.02;
  const positions = dust.geometry.attributes.position.array;
  for (let i = 0; i < dustCount; i++) {
    positions[i * 3 + 1] += Math.sin(t + i) * 0.0003;
  }
  dust.geometry.attributes.position.needsUpdate = true;

  controls.update();
  composer.render();
}

animate();

// — Resize —
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
  composer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's in the scene:**

- **Glass bulb** — a slightly elongated sphere with `MeshPhysicalMaterial` (transmission, IOR, transparency) for realistic glass
- **Filament** — a glowing cylinder inside with support wires
- **Screw base** — metal cylinder with torus ridges, insulating ring, and bottom contact tip
- **Point light** — inside the bulb with subtle flicker animation
- **UnrealBloomPass** — post-processing glow that makes the filament bloom beautifully
- **Dust particles** — floating particles with additive blending for atmosphere
- **Floor & ceiling** — dark surfaces that catch the light reflections
- **OrbitControls** — drag to rotate, scroll to zoom

