// Snout
const snoutGeo = new THREE.SphereGeometry(0.32, 24, 24);
snoutGeo.scale(1, 0.75, 0.8);
const snout = new THREE.Mesh(snoutGeo, furMat);
snout.position.set(0, 2.52, 0.78);
bunny.add(snout);

// Nose
const noseGeo = new THREE.SphereGeometry(0.065, 16, 16);
noseGeo.scale(1.3, 1, 0.8);
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.set(0, 2.58, 0.95);
bunny.add(nose);

// Eyes
const eyeGeo = new THREE.SphereGeometry(0.09, 16, 16);
const leftEye = new THREE.Mesh(eyeGeo, eyeMat);
leftEye.position.set(-0.28, 2.72, 0.82);
bunny.add(leftEye);

const rightEye = new THREE.Mesh(eyeGeo, eyeMat);
rightEye.position.set(0.28, 2.72, 0.82);
bunny.add(rightEye);

// Eye highlights
const highlightGeo = new THREE.SphereGeometry(0.03, 8, 8);
const highlightMat = new THREE.MeshBasicMaterial({ color: 0xffffff });
const lh1 = new THREE.Mesh(highlightGeo, highlightMat);
lh1.position.set(-0.26, 2.75, 0.89);
bunny.add(lh1);
const lh2 = new THREE.Mesh(highlightGeo, highlightMat);
lh2.position.set(0.30, 2.75, 0.89);
bunny.add(lh2);

// Ears
function createEar(side) {
  const earGroup = new THREE.Group();
  const outerGeo = new THREE.CapsuleGeometry(0.15, 0.85, 8, 16);
  const outer = new THREE.Mesh(outerGeo, furMat);
  outer.castShadow = true;
  earGroup.add(outer);

  const innerGeo = new THREE.CapsuleGeometry(0.09, 0.7, 8, 12);
  const inner = new THREE.Mesh(innerGeo, earInnerMat);
  inner.position.set(0, 0, 0.06);
  earGroup.add(inner);

  earGroup.position.set(side * 0.35, 3.55, 0.15);
  earGroup.rotation.z = side * 0.18;
  earGroup.rotation.x = -0.15;
  return earGroup;
}

const leftEar = createEar(-1);
const rightEar = createEar(1);
bunny.add(leftEar);
bunny.add(rightEar);

// Front paws
const pawGeo = new THREE.SphereGeometry(0.14, 16, 16);
