}));
tail.position.set(0, 1.25, -0.85);
tail.castShadow = true;
bunny.add(tail);

scene.add(bunny);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x7ec850,
