  blade.rotation.z = (Math.random() - 0.5) * 0.3;
  blade.castShadow = true;
  scene.add(blade);
}

// Flowers
const flowerColors = [0xff6b8a, 0xffd700, 0xff8c69, 0xe879a8, 0xffffff];
for (let i = 0; i < 15; i++) {
  const angle = Math.random() * Math.PI * 2;
