controls.target.set(0, 1.5, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;

// ── Lights ──
const ambient = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
dirLight.position.set(5, 10, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x7788ff, 0.4);
rimLight.position.set(-3, 4, -5);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffaa44, 0.5, 10);
pointLight.position.set(0, 4, 0);
scene.add(pointLight);

// ── Materials ──
const plateMat = new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.3, metalness: 0.1 });
const bottomCakeMat = new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.8 });
const topCakeMat = new THREE.MeshStandardMaterial({ color: 0xD2691E, roughness: 0.8 });
const frostingMat = new THREE.MeshStandardMaterial({ color: 0xfff0f5, roughness: 0.4 });
const dripMat = new THREE.MeshStandardMaterial({ color: 0xff69b4, roughness: 0.3, metalness: 0.05 });
const candleMat = new THREE.MeshStandardMaterial({ color: 0xff4466, roughness: 0.5 });
const candleStripMat = new THREE.MeshStandardMaterial({ color: 0xffdd44, roughness: 0.5 });
const flameMat = new THREE.MeshStandardMaterial({ color: 0xffaa00, emissive: 0xff6600, emissiveIntensity: 2, roughness: 1 });
const cherryMat = new THREE.MeshStandardMaterial({ color: 0xcc0000, roughness: 0.2, metalness: 0.1 });
const sprinklesMats = [
  new THREE.MeshStandardMaterial({ color: 0xff4444, roughness: 0.5 }),
  new THREE.MeshStandardMaterial({ color: 0x44ff44, roughness: 0.5 }),
  new THREE.MeshStandardMaterial({ color: 0x4444ff, roughness: 0.5 }),
  new THREE.MeshStandardMaterial({ color: 0xffff44, roughness: 0.5 }),
  new THREE.MeshStandardMaterial({ color: 0xff44ff, roughness: 0.5 }),
];

// ── Cake Group ──
const cake = new THREE.Group();
scene.add(cake);

// Plate
const plate = new THREE.Mesh(new THREE.CylinderGeometry(2.8, 2.6, 0.15, 64), plateMat);
plate.position.y = 0.075;
plate.receiveShadow = true;
cake.add(plate);

// Bottom cake layer
const bottomCake = new THREE.Mesh(new THREE.CylinderGeometry(1.8, 1.8, 1.2, 64), bottomCakeMat);
bottomCake.position.y = 0.75;
bottomCake.castShadow = true;
bottomCake.receiveShadow = true;
cake.add(bottomCake);

// Bottom frosting
const bottomFrosting = new THREE.Mesh(new THREE.CylinderGeometry(1.85, 1.85, 0.15, 64), frostingMat);
bottomFrosting.position.y = 1.38;
bottomFrosting.castShadow = true;
cake.add(bottomFrosting);

// Pink drips on bottom layer
for (let i = 0; i < 16; i++) {
  const angle = (i / 16) * Math.PI * 2;
  const dripLen = 0.2 + Math.random() * 0.5;
  const drip = new THREE.Mesh(new THREE.SphereGeometry(0.12, 12, 12), dripMat);
  drip.position.set(
    Math.cos(angle) * 1.78,
    1.3 - dripLen * 0.5,
    Math.sin(angle) * 1.78
  );
  drip.scale.set(1, dripLen * 2, 1);
  drip.castShadow = true;
  cake.add(drip);
}

// Top cake layer
const topCake = new THREE.Mesh(new THREE.CylinderGeometry(1.3, 1.3, 1.0, 64), topCakeMat);
topCake.position.y = 1.75;
topCake.castShadow = true;
topCake.receiveShadow = true;
cake.add(topCake);

// Top frosting
const topFrosting = new THREE.Mesh(new THREE.CylinderGeometry(1.35, 1.35, 0.18, 64), frostingMat);
topFrosting.position.y = 2.33;
topFrosting.castShadow = true;
cake.add(topFrosting);

// Frosting top dome
const dome = new THREE.Mesh(
  new THREE.SphereGeometry(1.3, 64, 32, 0, Math.PI * 2, 0, Math.PI * 0.4),
  frostingMat
);
dome.position.y = 2.33;
dome.castShadow = true;
cake.add(dome);

// Pink drips on top layer
for (let i = 0; i < 12; i++) {
  const angle = (i / 12) * Math.PI * 2 + 0.2;
  const dripLen = 0.15 + Math.random() * 0.4;
  const drip = new THREE.Mesh(new THREE.SphereGeometry(0.1, 12, 12), dripMat);
  drip.position.set(
    Math.cos(angle) * 1.28,
    2.25 - dripLen * 0.5,
    Math.sin(angle) * 1.28
  );
  drip.scale.set(1, dripLen * 2, 1);
  drip.castShadow = true;
  cake.add(drip);
}

// Sprinkles on top frosting
for (let i = 0; i < 40; i++) {
  const angle = Math.random() * Math.PI * 2;
  const r = Math.random() * 1.0;
  const sprinkle = new THREE.Mesh(
    new THREE.BoxGeometry(0.06, 0.02, 0.12),
    sprinklesMats[Math.floor(Math.random() * sprinklesMats.length)]
  );
  sprinkle.position.set(
    Math.cos(angle) * r,
    2.44 + Math.random() * 0.05,
    Math.sin(angle) * r
  );
  sprinkle.rotation.y = Math.random() * Math.PI;
  sprinkle.rotation.z = (Math.random() - 0.5) * 0.5;
  cake.add(sprinkle);
}

// ── Candles ──
const candles = [];
const flameMeshes = [];
const flameLights = [];
const candlePositions = [
  { x: 0, z: 0 },
  { x: 0.5, z: 0.3 },
  { x: -0.5, z: 0.3 },
  { x: 0.3, z: -0.5 },
  { x: -0.3, z: -0.5 },
];

candlePositions.forEach((pos, i) => {
  const candleGroup = new THREE.Group();

  // Candle body
  const candle = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.06, 0.7, 16), candleMat);
  candle.position.y = 2.75;
  candle.castShadow = true;
  candleGroup.add(candle);

  // Candle stripes
  for (let j = 0; j < 3; j++) {
    const stripe = new THREE.Mesh(
      new THREE.CylinderGeometry(0.065, 0.065, 0.03, 16),
      candleStripMat
    );
    stripe.position.y = 2.55 + j * 0.2;
    candleGroup.add(stripe);
  }

  // Flame
  const flame = new THREE.Mesh(new THREE.SphereGeometry(0.08, 12, 12), flameMat);
  flame.position.y = 3.18;
  flame.scale.set(1, 1.8, 1);
  candleGroup.add(flame);
  flameMeshes.push(flame);

  // Flame light
  const fLight = new THREE.PointLight(0xff8800, 0.3, 2);
  fLight.position.y = 3.2;
  candleGroup.add(fLight);
  flameLights.push(fLight);

  candleGroup.position.set(pos.x, 0, pos.z);
  candles.push(candleGroup);
  cake.add(candleGroup);
});

// Cherry on top
const cherry = new THREE.Mesh(new THREE.SphereGeometry(0.15, 24, 24), cherryMat);
cherry.position.set(0, 2.55, 0);
cherry.castShadow = true;
cake.add(cherry);

const cherryStem = new THREE.Mesh(
  new THREE.CylinderGeometry(0.01, 0.01, 0.2, 8),
  new THREE.MeshStandardMaterial({ color: 0x228B22 })
);
cherryStem.position.set(0, 2.68, 0);
cherryStem.rotation.z = 0.3;
cake.add(cherryStem);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Rotate cake slowly
  cake.rotation.y = t * 0.3;

  // Flicker flames
  flameMeshes.forEach((flame, i) => {
    const flicker = Math.sin(t * 8 + i * 2) * 0.15 + Math.sin(t * 13 + i) * 0.1;
    flame.scale.y = 1.8 + flicker;
    flame.scale.x = 1 + flicker * 0.5;
    flame.scale.z = 1 + flicker * 0.5;
  });

  flameLights.forEach((light, i) => {
    light.intensity = 0.3 + Math.sin(t * 10 + i * 3) * 0.1 + Math.sin(t * 15 + i) * 0.05;
  });

  // Subtle candle glow on pointLight
  pointLight.intensity = 0.5 + Math.sin(t * 6) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

- **Two-tier cake** with chocolate layers, white frosting, and a domed top
- **Pink frosting drips** cascading down both layers
- **Colorful sprinkles** scattered on top
- **5 striped candles** with animated flickering flames and dynamic point lights
- **Red cherry** with a green stem on top
- **Ceramic plate** underneath
- **OrbitControls** — drag to rotate, scroll to zoom
- **ACES filmic tone mapping**, soft shadows, and fog for atmosphere
- **Responsive** — handles window resizing

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>3D Calendar</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #0a0a1a; font-family: sans-serif; }
canvas { display: block; }
#info {
  position: absolute; top: 20px; width: 100%; text-align: center;
  color: #fff; font-size: 28px; font-weight: 300; letter-spacing: 6px;
  text-transform: uppercase; pointer-events: none;
  text-shadow: 0 0 20px rgba(100,180,255,0.5);
}
</style>
</head>
<body>
<div id="info"></div>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const now = new Date();
const year = now.getFullYear(), month = now.getMonth(), today = now.getDate();
const firstDay = new Date(year, month, 1).getDay();
const daysInMonth = new Date(year, month + 1, 0).getDate();
const monthNames = ["January","February","March","April","May","June",
  "July","August","September","October","November","December"];

document.getElementById('info').textContent = `${monthNames[month]} ${year}`;

const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 4, 14);
camera.lookAt(0, 0, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// Lights
const ambLight = new THREE.AmbientLight(0x334466, 0.6);
scene.add(ambLight);

const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
dirLight.position.set(5, 10, 7);
dirLight.castShadow = true;
scene.add(dirLight);

const pointLight = new THREE.PointLight(0x4488ff, 1.5, 30);
pointLight.position.set(-3, 6, 3);
scene.add(pointLight);

const pointLight2 = new THREE.PointLight(0xff6644, 0.8, 25);
pointLight2.position.set(4, 4, -2);
scene.add(pointLight2);

// Helpers
function makeTextTexture(text, color, bgColor, size = 128) {
  const c = document.createElement('canvas');
  c.width = c.height = size;
  const ctx = c.getContext('2d');
  ctx.fillStyle = bgColor;
  ctx.fillRect(0, 0, size, size);
  ctx.fillStyle = color;
  ctx.font = `bold ${size * 0.55}px Helvetica, Arial, sans-serif`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(text, size / 2, size / 2);
  const tex = new THREE.CanvasTexture(c);
  tex.minFilter = THREE.LinearFilter;
  return tex;
}

function makeGlowTexture(color) {
  const c = document.createElement('canvas');
  c.width = c.height = 64;
  const ctx = c.getContext('2d');
  const g = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
  g.addColorStop(0, color);
  g.addColorStop(1, 'transparent');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, 64, 64);
  return new THREE.CanvasTexture(c);
}

// Day cubes
const cubeGeo = new THREE.BoxGeometry(0.85, 0.85, 0.85);
const edgeGeo = new THREE.EdgesGeometry(cubeGeo);
const cubes = [];
const group = new THREE.Group();
scene.add(group);

const pastColor = '#1a2a4a';
const futureColor = '#1a1a2e';
const todayColor = '#ff6633';
const weekendColor = '#2a1a3a';

for (let d = 1; d <= daysInMonth; d++) {
  const col = (firstDay + d - 1) % 7;
  const row = Math.floor((firstDay + d - 1) / 7);
  const isWeekend = col === 0 || col === 6;
  const isToday = d === today;
  const isPast = d < today;

  let baseColor, textColor, emissiveColor, emissiveIntensity;
  if (isToday) {
    baseColor = todayColor;
    textColor = '#ffffff';
    emissiveColor = todayColor;
    emissiveIntensity = 0.6;
  } else if (isWeekend) {
    baseColor = weekendColor;
    textColor = '#8866aa';
    emissiveColor = '#442266';
    emissiveIntensity = 0.1;
  } else if (isPast) {
    baseColor = pastColor;
    textColor = '#5588bb';
    emissiveColor = '#224466';
    emissiveIntensity = 0.15;
  } else {
    baseColor = futureColor;
    textColor = '#667799';
    emissiveColor = '#112233';
    emissiveIntensity = 0.05;
  }

  const mat = new THREE.MeshStandardMaterial({
    color: baseColor,
    emissive: emissiveColor,
    emissiveIntensity: emissiveIntensity,
    metalness: 0.4,
    roughness: 0.3,
  });

  const mesh = new THREE.Mesh(cubeGeo, mat);
  mesh.castShadow = true;
  mesh.receiveShadow = true;

  // Number texture on top face
  const numTex = makeTextTexture(String(d), textColor, baseColor);
  const topMat = new THREE.MeshStandardMaterial({
    map: numTex,
    emissive: emissiveColor,
    emissiveIntensity: emissiveIntensity,
    metalness: 0.3,
    roughness: 0.3,
  });
  mesh.material = [
    mat.clone(), mat.clone(), topMat, mat.clone(), mat.clone(), mat.clone()
  ];

  // Edge wireframe
  const edgeMat = new THREE.LineBasicMaterial({
    color: isToday ? 0xffaa66 : (isWeekend ? 0x443366 : 0x334466),
    transparent: true,
    opacity: isToday ? 0.8 : 0.3
  });
  const edges = new THREE.LineSegments(edgeGeo, edgeMat);
  mesh.add(edges);

  // Glow sprite for today
  if (isToday) {
    const spriteMat = new THREE.SpriteMaterial({
      map: makeGlowTexture('rgba(255,102,51,0.6)'),
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false
    });
    const sprite = new THREE.Sprite(spriteMat);
    sprite.scale.set(3, 3, 1);
    sprite.position.y = 1.2;
    mesh.add(sprite);
  }

  const x = (col - 3) * 1.1;
  const z = (row - 2) * 1.1;
  const y = isToday ? 0.3 : 0;

  mesh.position.set(x, y, z);
  mesh.userData = { targetY: y, baseY: y, day: d, isToday, phase: Math.random() * Math.PI * 2 };
  group.add(mesh);
  cubes.push(mesh);
}

// Day-of-week labels
const dayLabels = ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'];
dayLabels.forEach((label, i) => {
  const tex = makeTextTexture(label, '#556688', '#0a0a1a', 96);
  const mat = new THREE.MeshBasicMaterial({ map: tex, transparent: true, opacity: 0.7 });
  const plane = new THREE.Mesh(new THREE.PlaneGeometry(0.9, 0.9), mat);
  plane.position.set((i - 3) * 1.1, 0, (Math.floor((firstDay + daysInMonth - 1) / 7) - 1) * 1.1 - 1.1);
  plane.rotation.x = -Math.PI / 2;
  scene.add(plane);
});

// Ground plane
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x0a0a1a, metalness: 0.8, roughness: 0.4
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.5;
ground.receiveShadow = true;
scene.add(ground);

// Grid helper
const grid = new THREE.GridHelper(20, 20, 0x112233, 0x0a1520);
grid.position.y = -0.49;
scene.add(grid);

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  cubes.forEach(cube => {
    const d = cube.userData;
    if (d.isToday) {
      cube.position.y = d.baseY + Math.sin(t * 2) * 0.2;
      cube.rotation.y = Math.sin(t * 1.5) * 0.15;
    } else {
      cube.position.y = d.baseY + Math.sin(t * 0.8 + d.phase) * 0.05;
    }
  });

  // Gentle camera orbit
  camera.position.x = Math.sin(t * 0.15) * 3;
  camera.position.z = 14 + Math.cos(t * 0.15) * 2;
  camera.lookAt(0, 0, 0);

  pointLight.position.x = Math.sin(t * 0.5) * 5;
  pointLight2.position.z = Math.cos(t * 0.4) * 5;

  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates an interactive 3D calendar visualization featuring:

- **Cube grid** — each day of the current month is a 3D cube arranged in a 7-column (Sun–Sat) layout
- **Color coding** — past days are blue-toned, future days are dark, weekends are purple-tinted, and **today** glows bright orange
- **Floating animation** — today's cube gently bobs and rotates; other days have subtle breathing motion
- **Glowing sprite** — today has an additive-blended glow halo above it
- **Day numbers** — rendered on the top face of each cube via canvas textures
- **Day-of-week labels** — sun/sat labels along the bottom
- **Dynamic lighting** — two colored point lights slowly orbit the scene
- **Gentle camera orbit** — the camera slowly circles the calendar
- **Responsive** — adapts to window resizing

