const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;

// ── Lights ──
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xfff4e0, 1.8);
sunLight.position.set(10, 15, 8);
sunLight.castShadow = true;
sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.near = 1;
sunLight.shadow.camera.far = 40;
sunLight.shadow.camera.left = -10;
sunLight.shadow.camera.right = 10;
sunLight.shadow.camera.top = 10;
sunLight.shadow.camera.bottom = -10;
scene.add(sunLight);

const fillLight = new THREE.DirectionalLight(0x8899cc, 0.3);
fillLight.position.set(-5, 3, -5);
scene.add(fillLight);

// ── Materials ──
const camelMat = new THREE.MeshStandardMaterial({ color: 0xC4A46C, roughness: 0.85, metalness: 0.0 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x8B7355, roughness: 0.9 });
const hoofMat = new THREE.MeshStandardMaterial({ color: 0x3B2F2F, roughness: 0.7 });
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.3 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0x7A6548, roughness: 0.8 });

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(40, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0xD2B48C, roughness: 1.0 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Sand dunes
function addDune(x, z, sx, sz, h) {
  const geo = new THREE.SphereGeometry(1, 16, 8, 0, Math.PI * 2, 0, Math.PI / 2);
  const dune = new THREE.Mesh(geo, groundMat);
  dune.position.set(x, -0.1, z);
  dune.scale.set(sx, h, sz);
  dune.receiveShadow = true;
  scene.add(dune);
}
addDune(-12, -8, 8, 6, 1.5);
addDune(14, -10, 7, 5, 1.2);
addDune(10, 12, 9, 6, 1.8);
addDune(-10, 10, 6, 4, 1.0);

// ── Camel Group ──
const camel = new THREE.Group();

// Body — main torso
const bodyGeo = new THREE.CapsuleGeometry(0.9, 2.2, 16, 32);
const body = new THREE.Mesh(bodyGeo, camelMat);
body.rotation.z = Math.PI / 2;
body.position.set(0, 2.2, 0);
body.castShadow = true;
camel.add(body);

// Second body segment (slightly smaller, connects to neck area)
const body2Geo = new THREE.CapsuleGeometry(0.75, 1.0, 12, 24);
const body2 = new THREE.Mesh(body2Geo, camelMat);
body2.rotation.z = Math.PI / 2;
body2.position.set(1.6, 2.3, 0);
body2.castShadow = true;
camel.add(body2);

// Hump — large rounded shape on back
const humpGeo = new THREE.SphereGeometry(0.85, 24, 24);
const hump = new THREE.Mesh(humpGeo, camelMat);
hump.scale.set(0.8, 1.0, 0.9);
hump.position.set(-0.3, 3.45, 0);
hump.castShadow = true;
camel.add(hump);

// Second smaller hump (Bactrian camel)
const hump2Geo = new THREE.SphereGeometry(0.7, 24, 24);
const hump2 = new THREE.Mesh(hump2Geo, camelMat);
hump2.scale.set(0.75, 0.9, 0.85);
hump2.position.set(0.9, 3.3, 0);
hump2.castShadow = true;
camel.add(hump2);

// Neck — long and curved
const neckGroup = new THREE.Group();
const neckSegments = 6;
for (let i = 0; i < neckSegments; i++) {
  const t = i / (neckSegments - 1);
  const r = 0.45 - t * 0.12;
  const segGeo = new THREE.SphereGeometry(r, 12, 12);
  const seg = new THREE.Mesh(segGeo, camelMat);
  seg.position.set(
    2.0 + t * 1.8,
    2.3 + t * 2.2,
    0
  );
  seg.castShadow = true;
  neckGroup.add(seg);
}
camel.add(neckGroup);

// Head
const headGroup = new THREE.Group();
headGroup.position.set(4.0, 4.6, 0);

// Main head shape
const headGeo = new THREE.BoxGeometry(1.2, 0.65, 0.6, 2, 2, 2);
// Deform vertices for a more snout-like shape
const headPos = headGeo.attributes.position;
for (let i = 0; i < headPos.count; i++) {
  const x = headPos.getX(i);
  const y = headPos.getY(i);
  const z = headPos.getZ(i);
  // Taper front
  const taper = x > 0 ? 1.0 - x * 0.15 : 1.0;
  headPos.setY(i, y * taper);
  headPos.setZ(i, z * taper);
}
headGeo.computeVertexNormals();
const head = new THREE.Mesh(headGeo, camelMat);
head.castShadow = true;
headGroup.add(head);

// Snout
const snoutGeo = new THREE.BoxGeometry(0.5, 0.5, 0.5);
const snout = new THREE.Mesh(snoutGeo, noseMat);
snout.position.set(0.75, -0.05, 0);
snout.castShadow = true;
headGroup.add(snout);

// Nostrils
const nostrilGeo = new THREE.SphereGeometry(0.06, 8, 8);
[-0.12, 0.12].forEach(z => {
  const nostril = new THREE.Mesh(nostrilGeo, darkMat);
  nostril.position.set(0.98, -0.05, z);
  headGroup.add(nostril);
});

// Eyes
const eyeGeo = new THREE.SphereGeometry(0.1, 12, 12);
[-0.25, 0.25].forEach(z => {
  const eye = new THREE.Mesh(eyeGeo, eyeMat);
  eye.position.set(0.2, 0.25, z);
  eye.scale.set(1, 0.7, 0.5);
  headGroup.add(eye);
  // Eyelash hint
  const lashGeo = new THREE.BoxGeometry(0.15, 0.02, 0.02);
  const lash = new THREE.Mesh(lashGeo, darkMat);
  lash.position.set(0.18, 0.32, z);
  lash.rotation.z = z > 0 ? -0.3 : 0.3;
  headGroup.add(lash);
});

// Ears
const earGeo = new THREE.ConeGeometry(0.12, 0.35, 8);
[-0.3, 0.3].forEach(z => {
  const ear = new THREE.Mesh(earGeo, camelMat);
  ear.position.set(-0.1, 0.5, z);
  ear.rotation.z = z > 0 ? -0.3 : 0.3;
