});

// Mouth line
const mouthGeo = new THREE.BoxGeometry(0.35, 0.025, 0.025);
const mouth = new THREE.Mesh(mouthGeo, darkMat);
mouth.position.set(0.7, -0.2, 0);
headGroup.add(mouth);

camel.add(headGroup);

// Legs
function createLeg(x, z, isFront) {
  const legGroup = new THREE.Group();
  const upperLen = 1.4;
  const lowerLen = 1.2;
  const kneeAngle = isFront ? 0.15 : -0.1;

  // Upper leg
  const upperGeo = new THREE.CapsuleGeometry(0.2, upperLen, 8, 12);
  const upper = new THREE.Mesh(upperGeo, camelMat);
  upper.position.set(0, -upperLen / 2 - 0.1, 0);
  upper.castShadow = true;
  legGroup.add(upper);

  // Knee joint
  const kneeGeo = new THREE.SphereGeometry(0.22, 10, 10);
  const knee = new THREE.Mesh(kneeGeo, camelMat);
  knee.position.set(kneeAngle * 0.3, -upperLen - 0.1, 0);
  knee.castShadow = true;
  legGroup.add(knee);

  // Lower leg
  const lowerGeo = new THREE.CapsuleGeometry(0.15, lowerLen, 8, 12);
  const lower = new THREE.Mesh(lowerGeo, camelMat);
  lower.position.set(kneeAngle * 0.5, -upperLen - 0.1 - lowerLen / 2, 0);
  lower.castShadow = true;
  legGroup.add(lower);

  // Hoof / foot
  const footGeo = new THREE.BoxGeometry(0.45, 0.15, 0.3);
  const foot = new THREE.Mesh(footGeo, hoofMat);
  foot.position.set(kneeAngle * 0.6, -upperLen - lowerLen - 0.15, 0.05);
  foot.castShadow = true;
  legGroup.add(foot);

  legGroup.position.set(x, 2.2, z);
  return legGroup;
}

const legPositions = [
  { x: -0.9, z: -0.55, front: false },
  { x: -0.9, z: 0.55, front: false },
  { x: 1.0, z: -0.55, front: true },
  { x: 1.0, z: 0.55, front: true },
];

legPositions.forEach(({ x, z, front }) => {
  const leg = createLeg(x, z, front);
