});

// Tail
const tailGroup = new THREE.Group();
const tailSegments = 8;
for (let i = 0; i < tailSegments; i++) {
  const t = i / (tailSegments - 1);
  const r = 0.06 * (1 - t * 0.7);
  const segGeo = new THREE.SphereGeometry(r, 6, 6);
  const seg = new THREE.Mesh(segGeo, i > tailSegments * 0.7 ? darkMat : camelMat);
  seg.position.set(-2.2 - t * 1.2, 2.5 - t * 0.8 + Math.sin(t * 2) * 0.15, 0);
  seg.castShadow = true;
  tailGroup.add(seg);
}
camel.add(tailGroup);

scene.add(camel);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle breathing
  body.scale.y = 1 + Math.sin(t * 1.5) * 0.015;
  body.scale.x = 1 + Math.sin(t * 1.5 + Math.PI) * 0.008;
  hump.position.y = 3.45 + Math.sin(t * 1.5) * 0.02;
