  // Subtle head bob
  headGroup.rotation.z = Math.sin(t * 0.8) * 0.02;
  headGroup.position.y = 4.6 + Math.sin(t * 1.2) * 0.03;

  // Tail sway
  tailGroup.children.forEach((seg, i) => {
    const phase = i * 0.4;
    seg.position.x += Math.sin(t * 1.5 + phase) * 0.001;
    seg.position.z = Math.sin(t * 1.2 + phase) * 0.15;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
