const breechGeo = new THREE.SphereGeometry(0.52, 24, 16, 0, Math.PI * 2, 0, Math.PI / 2);
const breech = new THREE.Mesh(breechGeo, ironMat);
breech.rotation.z = Math.PI;
breech.position.set(-1.0, 2.6, 0);
breech.castShadow = true;
cannon.add(breech);

// Breech plug (back cylinder)
const plugGeo = new THREE.CylinderGeometry(0.3, 0.3, 0.15, 24);
const plug = new THREE.Mesh(plugGeo, ironMat);
plug.rotation.z = Math.PI / 2;
plug.position.set(-1.0, 2.6, 0);
cannon.add(plug);

// Lifting ring on breech
const ringGeo = new THREE.TorusGeometry(0.3, 0.04, 8, 16);
const ring = new THREE.Mesh(ringGeo, ironMat);
ring.position.set(-1.0, 2.95, 0);
cannon.add(ring);

// ── Carriage (wooden base) ──
const carriageGroup = new THREE.Group();

// Main carriage beam
const beamGeo = new THREE.BoxGeometry(4.5, 0.35, 0.9);
const beam = new THREE.Mesh(beamGeo, woodMat);
beam.position.set(-0.5, 1.8, 0);
beam.castShadow = true;
carriageGroup.add(beam);

// Trail (angled support going back to ground)
const trailGeo = new THREE.BoxGeometry(0.3, 2.8, 0.5);
const trail = new THREE.Mesh(trailGeo, woodMat);
trail.position.set(-2.5, 0.9, 0);
trail.rotation.z = 0.35;
trail.castShadow = true;
carriageGroup.add(trail);

// Cross supports under barrel
for (let i = 0; i < 3; i++) {
  const crossGeo = new THREE.BoxGeometry(0.15, 0.8, 0.7);
  const cross = new THREE.Mesh(crossGeo, woodMat);
  cross.position.set(0.5 + i * 1.0, 1.4, 0);
  cross.castShadow = true;
  carriageGroup.add(cross);
}

// ── Wheels ──
function makeWheel(x) {
  const wheelGroup = new THREE.Group();

  // Tire (torus)
  const tireGeo = new THREE.TorusGeometry(0.9, 0.1, 8, 24);
  const tire = new THREE.Mesh(tireGeo, ironMat);
  tire.castShadow = true;
  wheelGroup.add(tire);

  // Inner hub disc
  const hubGeo = new THREE.CylinderGeometry(0.25, 0.25, 0.2, 24);
  const hub = new THREE.Mesh(hubGeo, woodMat);
  hub.rotation.x = Math.PI / 2;
  wheelGroup.add(hub);

  // Spokes
  for (let i = 0; i < 8; i++) {
    const spokeGeo = new THREE.CylinderGeometry(0.035, 0.035, 0.75, 6);
    const spoke = new THREE.Mesh(spokeGeo, woodMat);
    const angle = (i / 8) * Math.PI * 2;
    spoke.position.set(Math.cos(angle) * 0.45, Math.sin(angle) * 0.45, 0);
    spoke.rotation.z = angle;
    spoke.castShadow = true;
    wheelGroup.add(spoke);
  }

  // Outer rim disc
  const rimGeo = new THREE.CylinderGeometry(0.9, 0.9, 0.06, 24);
  const rim = new THREE.Mesh(rimGeo, wheelMat);
  rim.rotation.x = Math.PI / 2;
  rim.position.z = 0.08;
  wheelGroup.add(rim);

  wheelGroup.position.set(x, 0.9, 0);
  return wheelGroup;
}

carriageGroup.add(makeWheel(1.8));
carriageGroup.add(makeWheel(-1.8));

// Axle
const axleGeo = new THREE.CylinderGeometry(0.06, 0.06, 2.0, 8);
const axle = new THREE.Mesh(axleGeo, ironMat);
axle.rotation.z = Math.PI / 2;
axle.position.set(0, 0.9, 0);
axle.castShadow = true;
carriageGroup.add(axle);

cannon.add(carriageGroup);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(30, 64);
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt patch under cannon
const dirtGeo = new THREE.CircleGeometry(3, 32);
const dirtMat = new THREE.MeshStandardMaterial({ color: 0x6b5b3a, roughness: 1 });
const dirt = new THREE.Mesh(dirtGeo, dirtMat);
dirt.rotation.x = -Math.PI / 2;
dirt.position.y = 0.005;
dirt.receiveShadow = true;
scene.add(dirt);

scene.add(cannon);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

| Part | Geometry | Material |
|---|---|---|
| **Barrel** | Tapered `CylinderGeometry` | Dark iron (metallic) |
| **Muzzle ring** | `TorusGeometry` lip | Iron |
| **Breech** | Hemisphere `SphereGeometry` + plug + lifting ring | Iron |
| **Carriage beam** | `BoxGeometry` | Wood |
| **Trail** | Angled `BoxGeometry` support | Wood |
| **Cross supports** | 3 vertical `BoxGeometry` pieces | Wood |
| **Wheels** (×2) | `TorusGeometry` tire + 8 spokes + hub + rim disc | Wood + iron |
| **Axle** | `CylinderGeometry` rod | Iron |
| **Ground** | `CircleGeometry` grass + dirt patch | Standard |

**Features:**
- **Shadows** — PCF soft shadow maps from a directional sun light
- **Orbit controls** — drag to rotate, scroll to zoom
- **Fog** — subtle depth cueing
- **Responsive** — handles window resize
- **Single file** — just open `index.html` in a browser

