**What's included:**

- **`CapsuleGeometry(radius, length, capSegments, radialSegments)`** — a pill shape with radius `1` and cylinder length `2`
- **`MeshStandardMaterial`** — lit material with a red/pink color
- **Three lights** — ambient fill, directional key, and a blue point light for color contrast
- **OrbitControls** — drag to rotate, scroll to zoom
- **Gentle Y-axis rotation** animation
- **Responsive resize** handling
- **Dark background** (`#1a1a2e`) to make the capsule pop

Save as `index.html` and open in any modern browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Car</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
#info {
  position: absolute; top: 12px; left: 50%; transform: translateX(-50%);
  color: #fff; font-family: system-ui, sans-serif; font-size: 14px;
  background: rgba(0,0,0,.55); padding: 8px 18px; border-radius: 20px;
  pointer-events: none; letter-spacing: .3px;
}
</style>
</head>
<body>
<div id="info">🚗 Drag to orbit · Scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── Scene ── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87ceeb);
scene.fog = new THREE.FogExp2(0x87ceeb, 0.012);

/* ── Camera ── */
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 200);
camera.position.set(8, 5, 10);

/* ── Renderer ── */
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ── Controls ── */
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 1.2, 0);
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 4;
controls.maxDistance = 30;

/* ── Lights ── */
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(10, 15, 8);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.left = -12;
sun.shadow.camera.right = 12;
sun.shadow.camera.top = 12;
sun.shadow.camera.bottom = -12;
sun.shadow.camera.near = 0.5;
sun.shadow.camera.far = 40;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8ec5fc, 0.6);
fill.position.set(-8, 4, -6);
scene.add(fill);

/* ── Ground ── */
const groundGeo = new THREE.PlaneGeometry(100, 100);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x3a7d44, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Road
const roadGeo = new THREE.PlaneGeometry(6, 60);
const roadMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.8 });
const road = new THREE.Mesh(roadGeo, roadMat);
road.rotation.x = -Math.PI / 2;
road.position.y = 0.005;
road.receiveShadow = true;
scene.add(road);

// Road lines
for (let z = -25; z < 25; z += 4) {
  const lineGeo = new THREE.PlaneGeometry(0.15, 2);
  const lineMat = new THREE.MeshStandardMaterial({ color: 0xffffff });
  const line = new THREE.Mesh(lineGeo, lineMat);
  line.rotation.x = -Math.PI / 2;
  line.position.set(0, 0.01, z);
  scene.add(line);
}

/* ── Car Group ── */
const car = new THREE.Group();

// Materials
const bodyMat = new THREE.MeshStandardMaterial({ color: 0xd42a2a, metalness: 0.6, roughness: 0.25 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, metalness: 0.3, roughness: 0.6 });
const glassMat = new THREE.MeshStandardMaterial({ color: 0x88bbee, metalness: 0.1, roughness: 0.05, transparent: true, opacity: 0.45 });
const chromeMat = new THREE.MeshStandardMaterial({ color: 0xcccccc, metalness: 0.95, roughness: 0.08 });
const headlightMat = new THREE.MeshStandardMaterial({ color: 0xffffee, emissive: 0xffffaa, emissiveIntensity: 0.6, metalness: 0.1, roughness: 0.1 });
const taillightMat = new THREE.MeshStandardMaterial({ color: 0xff0000, emissive: 0xff2200, emissiveIntensity: 0.4, metalness: 0.1, roughness: 0.2 });
const tireMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.9 });
const rimMat = new THREE.MeshStandardMaterial({ color: 0xbbbbbb, metalness: 0.9, roughness: 0.15 });

// ── Main Body (lower) ──
const bodyGeo = new THREE.BoxGeometry(2.2, 0.7, 4.6);
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.set(0, 0.55, 0);
body.castShadow = true;
car.add(body);

// Front hood slope
const hoodGeo = new THREE.BoxGeometry(2.0, 0.15, 1.4);
const hood = new THREE.Mesh(hoodGeo, bodyMat);
hood.position.set(0, 0.92, 1.5);
hood.rotation.x = 0.12;
hood.castShadow = true;
car.add(hood);

// Trunk
const trunkGeo = new THREE.BoxGeometry(2.0, 0.15, 1.0);
const trunk = new THREE.Mesh(trunkGeo, bodyMat);
trunk.position.set(0, 0.92, -1.5);
trunk.rotation.x = -0.08;
trunk.castShadow = true;
car.add(trunk);

// ── Cabin (upper) ──
const cabinGeo = new THREE.BoxGeometry(1.9, 0.65, 2.2);
const cabin = new THREE.Mesh(cabinGeo, bodyMat);
cabin.position.set(0, 1.22, -0.2);
cabin.castShadow = true;
car.add(cabin);

// Windshield (front glass)
const windshieldGeo = new THREE.BoxGeometry(1.75, 0.55, 0.08);
const windshield = new THREE.Mesh(windshieldGeo, glassMat);
windshield.position.set(0, 1.2, 0.88);
windshield.rotation.x = -0.35;
car.add(windshield);

// Rear window
const rearWindowGeo = new THREE.BoxGeometry(1.75, 0.5, 0.08);
const rearWindow = new THREE.Mesh(rearWindowGeo, glassMat);
rearWindow.position.set(0, 1.22, -1.28);
rearWindow.rotation.x = 0.3;
car.add(rearWindow);

// Side windows
for (const side of [-1, 1]) {
  const sideWinGeo = new THREE.BoxGeometry(0.06, 0.45, 1.8);
  const sideWin = new THREE.Mesh(sideWinGeo, glassMat);
  sideWin.position.set(side * 0.95, 1.22, -0.15);
  car.add(sideWin);
}

// ── Bumpers ──
for (const z of [2.35, -2.35]) {
  const bumperGeo = new THREE.BoxGeometry(2.3, 0.25, 0.15);
  const bumper = new THREE.Mesh(bumperGeo, chromeMat);
  bumper.position.set(0, 0.35, z);
  bumper.castShadow = true;
  car.add(bumper);
}

// ── Headlights ──
for (const x of [-0.75, 0.75]) {
  const hlGeo = new THREE.SphereGeometry(0.12, 16, 16);
  const hl = new THREE.Mesh(hlGeo, headlightMat);
  hl.position.set(x, 0.6, 2.32);
  car.add(hl);
}

// ── Taillights ──
for (const x of [-0.85, 0.85]) {
  const tlGeo = new THREE.BoxGeometry(0.3, 0.12, 0.06);
  const tl = new THREE.Mesh(tlGeo, taillightMat);
  tl.position.set(x, 0.6, -2.32);
  car.add(tl);
}

// ── Side mirrors ──
for (const side of [-1, 1]) {
  const mirrorArmGeo = new THREE.BoxGeometry(0.06, 0.06, 0.3);
  const mirrorArm = new THREE.Mesh(mirrorArmGeo, darkMat);
  mirrorArm.position.set(side * 1.05, 1.05, 0.6);
  car.add(mirrorArm);

  const mirrorGeo = new THREE.BoxGeometry(0.15, 0.12, 0.1);
  const mirror = new THREE.Mesh(mirrorGeo, bodyMat);
  mirror.position.set(side * 1.2, 1.05, 0.7);
  car.add(mirror);
}

// ── Wheels ──
function createWheel() {
  const group = new THREE.Group();

  // Tire
  const tireGeo = new THREE.CylinderGeometry(0.38, 0.38, 0.28, 24);
  const tire = new THREE.Mesh(tireGeo, tireMat);
  tire.rotation.z = Math.PI / 2;
  tire.castShadow = true;
  group.add(tire);

  // Rim
  const rimGeo = new THREE.CylinderGeometry(0.24, 0.24, 0.3, 16);
  const rim = new THREE.Mesh(rimGeo, rimMat);
  rim.rotation.z = Math.PI / 2;
  group.add(rim);

  // Hubcap detail
  const hubGeo = new THREE.CylinderGeometry(0.08, 0.08, 0.31, 8);
  const hub = new THREE.Mesh(hubGeo, chromeMat);
  hub.rotation.z = Math.PI / 2;
  group.add(hub);

  return group;
}

const wheelPositions = [
  { x: -1.1, y: 0.38, z: 1.45 },
  { x:  1.1, y: 0.38, z: 1.45 },
  { x: -1.1, y: 0.38, z: -1.45 },
  { x:  1.1, y: 0.38, z: -1.45 },
];

const wheels = [];
wheelPositions.forEach(pos => {
  const wheel = createWheel();
  wheel.position.set(pos.x, pos.y, pos.z);
  car.add(wheel);
  wheels.push(wheel);
});

// ── Door lines ──
for (const side of [-1, 1]) {
  const doorLineGeo = new THREE.BoxGeometry(0.02, 0.5, 2.0);
  const doorLine = new THREE.Mesh(doorLineGeo, darkMat);
  doorLine.position.set(side * 1.1, 0.6, 0.1);
  car.add(doorLine);
}

// ── Roof rails ──
for (const side of [-1, 1]) {
  const railGeo = new THREE.BoxGeometry(0.05, 0.04, 2.0);
  const rail = new THREE.Mesh(railGeo, chromeMat);
  rail.position.set(side * 0.85, 1.55, -0.2);
  car.add(rail);
}

// ── Antenna ──
const antennaGeo = new THREE.CylinderGeometry(0.01, 0.015, 0.4, 6);
const antenna = new THREE.Mesh(antennaGeo, chromeMat);
antenna.position.set(0.5, 1.62, -1.0);
car.add(antenna);

scene.add(car);

/* ── Environment trees ── */
function createTree(x, z) {
  const tree = new THREE.Group();
  const trunkGeo = new THREE.CylinderGeometry(0.12, 0.18, 1.5, 8);
  const trunkMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e });
  const trunk = new THREE.Mesh(trunkGeo, trunkMat);
  trunk.position.y = 0.75;
  trunk.castShadow = true;
  tree.add(trunk);

  const leavesGeo = new THREE.SphereGeometry(0.9, 8, 8);
  const leavesMat = new THREE.MeshStandardMaterial({ color: 0x2d6b30, roughness: 0.8 });
  const leaves = new THREE.Mesh(leavesGeo, leavesMat);
  leaves.position.y = 2.0;
  leaves.castShadow = true;
  tree.add(leaves);

  tree.position.set(x, 0, z);
  scene.add(tree);
}

for (let z = -25; z < 25; z += 5) {
  createTree(-5.5, z + Math.random() * 2);
  createTree(5.5, z + Math.random() * 2);
}

/* ── Animation ── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle bob
  car.position.y = Math.sin(t * 1.5) * 0.015;

  // Subtle wheel spin (idle)
  wheels.forEach(w => {
    w.children[0].rotation.x = t * 0.3;
    w.children[1].rotation.x = t * 0.3;
    w.children[2].rotation.x = t * 0.3;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ── Resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- A **red sedan** built from Three.js primitives (boxes, cylinders, spheres) with a glossy metallic paint finish
- **Chrome bumpers**, **glass windows**, **emissive headlights/taillights**, side mirrors, roof rails, and an antenna
- **4 detailed wheels** with tires, rims

