rimLight.position.set(-4, 2, -5);
scene.add(rimLight);

// ── Chain Material ──
const chainMat = new THREE.MeshPhysicalMaterial({
  color: 0xccbbaa,
  metalness: 0.95,
  roughness: 0.18,
  clearcoat: 0.3,
  clearcoatRoughness: 0.1,
  envMapIntensity: 1.0,
});

// ── Env map (simple procedural) ──
const pmrem = new THREE.PMREMGenerator(renderer);
const envScene = new THREE.Scene();
envScene.background = new THREE.Color(0x303050);
const envLight1 = new THREE.DirectionalLight(0xffffff, 3);
envLight1.position.set(5, 5, 5);
envScene.add(envLight1);
const envLight2 = new THREE.DirectionalLight(0x4466ff, 2);
envLight2.position.set(-5, 3, -5);
envScene.add(envLight2);
chainMat.envMap = pmrem.fromScene(envScene, 0.04).texture;

// ── Chain Links ──
const LINK_COUNT = 40;
const linkGroup = new THREE.Group();
scene.add(linkGroup);

const linkRadius = 0.35;
const linkTubeRadius = 0.08;
const linkSpacing = linkRadius * 1.6;

// Shared geometries (two orientations)
const torusGeo = new THREE.TorusGeometry(linkRadius, linkTubeRadius, 16, 48);

const links = [];

for (let i = 0; i < LINK_COUNT; i++) {
  const t = i / (LINK_COUNT - 1);          // 0 → 1 along chain
  const x = (t - 0.5) * 16;                // spread horizontally

  // Catenary: y = a·cosh(x/a) − a
  const a = 5;
  const y = a * Math.cosh(x / a) - a - 2;  // shift down

  const mesh = new THREE.Mesh(torusGeo, chainMat);
  mesh.castShadow = true;
  mesh.receiveShadow = true;

  // Alternate orientation: even links along Z, odd along X
  if (i % 2 === 0) {
    mesh.rotation.y = Math.PI / 2;          // ring plane = XZ (links along chain)
  } else {
    mesh.rotation.y = 0;                    // ring plane = YZ
  }

  // Slight twist along the chain for visual interest
  mesh.rotation.x = Math.sin(t * Math.PI * 2) * 0.05;
  mesh.rotation.z = Math.cos(t * Math.PI * 2.5) * 0.05;

  mesh.position.set(x, y, 0);
  linkGroup.add(mesh);
  links.push(mesh);
}

// ── Anchor points (two posts) ──
const postGeo = new THREE.CylinderGeometry(0.15, 0.2, 3, 16);
const postMat = new THREE.MeshStandardMaterial({ color: 0x555555, metalness: 0.6, roughness: 0.4 });

const leftPost = new THREE.Mesh(postGeo, postMat);
leftPost.position.set(-8, 3, 0);
leftPost.castShadow = true;
scene.add(leftPost);

const rightPost = new THREE.Mesh(postGeo, postMat);
rightPost.position.set(8, 3, 0);
rightPost.castShadow = true;
scene.add(rightPost);

// ── Ground plane ──
const groundGeo = new THREE.PlaneGeometry(60, 60);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 0.85, metalness: 0.1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -6;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle sway
  const sway = Math.sin(elapsed * 0.8) * 0.015;
  links.forEach((link, i) => {
    const phase = i * 0.15;
    link.position.z = Math.sin(elapsed * 1.2 + phase) * 0.12 + sway * Math.sin(elapsed * 0.5 + i * 0.3);
    link.position.x += Math.cos(elapsed * 0.6 + i * 0.1) * 0.0003;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the scene

| Feature | Detail |
|---|---|
| **Chain links** | 40 `TorusGeometry` meshes alternating orientation (even ≈ horizontal, odd ≈ vertical) to simulate interlocking |
| **Shape** | Links are placed along a **catenary curve** (`y = a·cosh(x/a) − a`), the natural hanging shape of a chain |
| **Material** | `MeshPhysicalMaterial` with high metalness, low roughness, and a procedural environment map for realistic reflections |
| **Lighting** | Key (warm directional), fill (cool directional), rim (orange point) + ambient — all shadow-casting |
| **Anchors** | Two metallic posts at the ends |
| **Animation** | Gentle sine-wave sway giving the chain a subtle living motion |
| **Interaction** | `OrbitControls` — drag to rotate, scroll to zoom |
| **Post-processing** | ACES filmic tone mapping, exponential fog, soft shadow maps |

