<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene, Camera, Renderer ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);
scene.fog = new THREE.FogExp2(0x0a0a12, 0.025);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// ── Materials ──
const brassMat = new THREE.MeshStandardMaterial({
  color: 0xc4a35a, metalness: 0.9, roughness: 0.25
});
const darkBrassMat = new THREE.MeshStandardMaterial({
  color: 0x8a6f30, metalness: 0.85, roughness: 0.35
});
const crystalMat = new THREE.MeshPhysicalMaterial({
  color: 0xffffff, metalness: 0.0, roughness: 0.05,
  transmission: 0.92, thickness: 0.5, ior: 1.54,
  transparent: true, opacity: 0.85
});
const flameMat = new THREE.MeshBasicMaterial({ color: 0xffcc44 });
const glowMat = new THREE.MeshBasicMaterial({ color: 0xffdd88, transparent: true, opacity: 0.3 });

// ── Helper functions ──
function makeChain(height, links) {
  const group = new THREE.Group();
  const linkGeo = new THREE.TorusGeometry(0.06, 0.02, 8, 16);
  for (let i = 0; i < links; i++) {
    const link = new THREE.Mesh(linkGeo, brassMat);
    link.position.y = i * 0.12;
    link.rotation.x = (i % 2) * Math.PI / 2;
    group.add(link);
  }
  return group;
}

function makeCandle() {
  const group = new THREE.Group();
  // candle body
  const body = new THREE.Mesh(
    new THREE.CylinderGeometry(0.04, 0.04, 0.28, 12),
    new THREE.MeshStandardMaterial({ color: 0xfff5e6, roughness: 0.6 })
  );
  body.position.y = 0.14;
  group.add(body);
  // flame
  const flame = new THREE.Mesh(
    new THREE.SphereGeometry(0.045, 8, 8),
    flameMat
  );
  flame.position.y = 0.32;
  flame.scale.y = 1.6;
  group.add(flame);
  // glow halo
  const glow = new THREE.Mesh(
    new THREE.SphereGeometry(0.1, 16, 16),
    glowMat
  );
  glow.position.y = 0.32;
  group.add(glow);
  // point light
  const light = new THREE.PointLight(0xffaa33, 2, 6, 2);
  light.position.y = 0.32;
  group.add(light);
  return group;
}

function makeCrystal(dropLength) {
  const group = new THREE.Group();
  // stem
  const stem = new THREE.Mesh(
    new THREE.CylinderGeometry(0.008, 0.008, 0.08, 6),
    brassMat
  );
  stem.position.y = -0.04;
  group.add(stem);
  // crystal drop
  const drop = new THREE.Mesh(
    new THREE.OctahedronGeometry(0.06, 0),
    crystalMat
  );
  drop.scale.y = dropLength / 0.12;
  drop.position.y = -0.08 - dropLength * 0.4;
  group.add(drop);
  return group;
}

function makeArm(angle) {
  const group = new THREE.Group();
  // curved arm using a tube along a path
  const curve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(0, 0, 0),
    new THREE.Vector3(0.3, 0.15, 0),
    new THREE.Vector3(0.7, 0.25, 0),
    new THREE.Vector3(1.0, 0.2, 0),
  ]);
  const tubeGeo = new THREE.TubeGeometry(curve, 20, 0.025, 8, false);
  const arm = new THREE.Mesh(tubeGeo, brassMat);
  group.add(arm);
  // candle holder cup
  const cup = new THREE.Mesh(
    new THREE.CylinderGeometry(0.055, 0.04, 0.06, 12),
    darkBrassMat
  );
  cup.position.set(1.0, 0.23, 0);
  group.add(cup);
  // candle
  const candle = makeCandle();
  candle.position.set(1.0, 0.26, 0);
  group.add(candle);
  // crystal drops from arm
  for (let i = 0; i < 3; i++) {
    const t = 0.3 + i * 0.25;
    const pos = curve.getPointAt(t);
    const crystal = makeCrystal(0.08 + Math.random() * 0.08);
    crystal.position.copy(pos);
    group.add(crystal);
  }
  // rotate arm to angle
  group.rotation.y = angle;
  return group;
}

// ── Build the Chandelier ──
const chandelier = new THREE.Group();

// Chain
const chain = makeChain(3.5, 30);
chain.position.y = 1.8;
chandelier.add(chain);

// Top canopy
const canopy = new THREE.Mesh(
  new THREE.CylinderGeometry(0.25, 0.18, 0.08, 24),
  brassMat
);
canopy.position.y = 3.35;
chandelier.add(canopy);

// Central body - upper dome
const upperDome = new THREE.Mesh(
  new THREE.SphereGeometry(0.2, 24, 12, 0, Math.PI * 2, 0, Math.PI / 2),
  brassMat
);
upperDome.position.y = 0;
chandelier.add(upperDome);

// Central body - lower bowl
const lowerBowl = new THREE.Mesh(
  new THREE.SphereGeometry(0.22, 24, 12, 0, Math.PI * 2, Math.PI / 2, Math.PI / 2),
  brassMat
);
lowerBowl.position.y = -0.05;
chandelier.add(lowerBowl);

// Decorative ring
const ring = new THREE.Mesh(
  new THREE.TorusGeometry(0.22, 0.02, 8, 32),
  darkBrassMat
);
ring.rotation.x = Math.PI / 2;
ring.position.y = 0;
chandelier.add(ring);

// Central column
const column = new THREE.Mesh(
  new THREE.CylinderGeometry(0.06, 0.08, 0.3, 16),
  brassMat
);
column.position.y = -0.25;
chandelier.add(column);

// Bottom decorative piece
const bottomOrb = new THREE.Mesh(
  new THREE.SphereGeometry(0.1, 16, 16),
  brassMat
);
bottomOrb.position.y = -0.45;
chandelier.add(bottomOrb);

// Bottom crystal cluster
for (let i = 0; i < 8; i++) {
  const a = (i / 8) * Math.PI * 2;
  const crystal = makeCrystal(0.12 + Math.random() * 0.1);
  crystal.position.set(
    Math.cos(a) * 0.12,
    -0.55,
    Math.sin(a) * 0.12
  );
  chandelier.add(crystal);
}

// Center hanging crystal
const centerCrystal = makeCrystal(0.25);
centerCrystal.position.y = -0.55;
chandelier.add(centerCrystal);

// Arms with candles
const NUM_ARMS = 8;
for (let i = 0; i < NUM_ARMS; i++) {
  const angle = (i / NUM_ARMS) * Math.PI * 2;
  const arm = makeArm(angle);
  arm.position.y = -0.1;
  chandelier.add(arm);
}

// Lower tier - smaller arms
for (let i = 0; i < 4; i++) {
  const angle = (i / 4) * Math.PI * 2 + Math.PI / 4;
  const group = new THREE.Group();
  const curve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(0, 0, 0),
    new THREE.Vector3(0.15, -0.1, 0),
    new THREE.Vector3(0.4, -0.15, 0),
    new THREE.Vector3(0.55, -0.1, 0),
  ]);
  const tube = new THREE.Mesh(new THREE.TubeGeometry(curve, 16, 0.018, 8, false), brassMat);
  group.add(tube);
  const cup = new THREE.Mesh(
    new THREE.CylinderGeometry(0.045, 0.035, 0.05, 10),
    darkBrassMat
  );
  cup.position.set(0.55, -0.07, 0);
  group.add(cup);
  const candle = makeCandle();
  candle.scale.set(0.8, 0.8, 0.8);
  candle.position.set(0.55, -0.04, 0);
  group.add(candle);
  const crystal = makeCrystal(0.06 + Math.random() * 0.06);
  const pos = curve.getPointAt(0.5);
  crystal.position.copy(pos);
  group.add(crystal);
  group.rotation.y = angle;
  group.position.y = -0.4;
  chandelier.add(group);
}

scene.add(chandelier);

// ── Ambient light ──
scene.add(new THREE.AmbientLight(0x1a1a2e, 0.5));

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  chandelier.rotation.z = Math.sin(t * 0.3) * 0.015;
  chandelier.rotation.x = Math.cos(t * 0.25) * 0.01;

  // Flicker flames
  chandelier.traverse(child => {
    if (child.isPointLight) {
      child.intensity = 1.5 + Math.sin(t * 8 + child.id) * 0.5 + Math.sin(t * 13 + child.id * 2) * 0.3;
    }
    if (child.material === flameMat) {
      child.scale.y = 1.4 + Math.sin(t * 10 + child.id) * 0.3;
      child.scale.x = 1.0 + Math.sin(t * 7 + child.id * 3) * 0.1;
    }
    if (child.material === glowMat) {
      child.material.opacity = 0.2 + Math.sin(t * 6 + child.id) * 0.1;
    }
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
