lock.position.set(0, 0.85, 0.78);
lock.castShadow = true;
chest.add(lock);

// Keyhole
const keyholeGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.05, 12);
const keyhole = new THREE.Mesh(keyholeGeo, leatherMat);
keyhole.rotation.x = Math.PI / 2;
keyhole.position.set(0, 0.82, 0.83);
