const foil1 = new THREE.Mesh(foilGeo1, foilMat);
foil1.position.set(0, 0, D / 2 + 0.01);
foil1.castShadow = true;
barGroup.add(foil1);

const foil2 = foil1.clone();
foil2.position.z = -D / 2 - 0.01;
barGroup.add(foil2);

const foilGeo2 = new THREE.BoxGeometry(0.02, H + 0.02, D + 0.05);
const foil3 = new THREE.Mesh(foilGeo2, foilMat);
foil3.position.set(W / 2 + 0.01, 0, 0);
foil3.castShadow = true;
barGroup.add(foil3);

const foil4 = foil3.clone();
foil4.position.x = -W / 2 - 0.01;
barGroup.add(foil4);

barGroup.rotation.y = 0.3;
scene.add(barGroup);

// ── Ground Plane ──
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x222222,
  roughness: 0.85,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -H / 2 - 0.01;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating particles (cocoa dust) ──
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const sizes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 10;
  positions[i * 3 + 1] = Math.random() * 6 - 1;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 10;
  sizes[i] = Math.random() * 3 + 1;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.PointsMaterial({
  color: 0x8b6914,
  size: 0.04,
  transparent: true,
  opacity: 0.4,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float
  barGroup.position.y = Math.sin(t * 0.8) * 0.15;
  barGroup.rotation.y = 0.3 + Math.sin(t * 0.3) * 0.15;

  // Particles drift
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(t + i) * 0.001;
    pos.array[i * 3] += Math.cos(t * 0.5 + i * 0.3) * 0.0005;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
