}
const cupGeo = new THREE.LatheGeometry(cupProfile, 48);
const cup = new THREE.Mesh(cupGeo, ceramicMat);
cup.castShadow = true;
cup.receiveShadow = true;
cupGroup.add(cup);

// Cup inner (dark circle at top)
const innerGeo = new THREE.CircleGeometry(0.78, 48);
const innerMesh = new THREE.Mesh(innerGeo, darkCeramicMat);
innerMesh.rotation.x = -Math.PI / 2;
innerMesh.position.y = 1.98;
cupGroup.add(innerMesh);

// Coffee liquid
const coffeeGeo = new THREE.CircleGeometry(0.74, 48);
const coffeeMesh = new THREE.Mesh(coffeeGeo, coffeeMat);
coffeeMesh.rotation.x = -Math.PI / 2;
coffeeMesh.position.y = 1.72;
cupGroup.add(coffeeMesh);

// Coffee surface (slightly convex with foam)
const coffeeTopGeo = new THREE.CircleGeometry(0.72, 48);
const foamMat = new THREE.MeshStandardMaterial({
  color: 0x5c3317,
  roughness: 0.3,
  metalness: 0.0,
  transparent: true,
  opacity: 0.85,
});
const foamMesh = new THREE.Mesh(coffeeTopGeo, foamMat);
foamMesh.rotation.x = -Math.PI / 2;
foamMesh.position.y = 1.74;
cupGroup.add(foamMesh);

// ── Handle ──
const handleCurve = new THREE.CubicBezierCurve3(
  new THREE.Vector3(0.82, 1.5, 0),
  new THREE.Vector3(1.5, 1.6, 0),
  new THREE.Vector3(1.5, 0.8, 0),
  new THREE.Vector3(0.78, 0.85, 0),
);
const handleGeo = new THREE.TubeGeometry(handleCurve, 24, 0.08, 12, false);
const handle = new THREE.Mesh(handleGeo, ceramicMat);
handle.castShadow = true;
cupGroup.add(handle);

// ── Saucer ──
const saucerProfile = [];
for (let i = 0; i <= 16; i++) {
  const t = i / 16;
  const angle = t * Math.PI * 0.5;
  const r = 1.4 + Math.cos(angle) * 0.3;
  const y = -Math.sin(angle) * 0.12 - 0.05;
  saucerProfile.push(new THREE.Vector2(Math.max(r, 0.01), y));
}
const saucerGeo = new THREE.LatheGeometry(saucerProfile, 48);
const saucer = new THREE.Mesh(saucerGeo, ceramicMat);
saucer.position.y = -0.15;
saucer.castShadow = true;
saucer.receiveShadow = true;
cupGroup.add(saucer);

// Saucer top surface
const saucerTopGeo = new THREE.RingGeometry(0.6, 1.35, 48);
const saucerTop = new THREE.Mesh(saucerTopGeo, ceramicMat);
saucerTop.rotation.x = -Math.PI / 2;
saucerTop.position.y = -0.06;
saucerTop.receiveShadow = true;
cupGroup.add(saucerTop);

// ── Table ──
const tableGeo = new THREE.CylinderGeometry(8, 8, 0.15, 64);
const table = new THREE.Mesh(tableGeo, tableMat);
table.position.y = -0.22;
table.receiveShadow = true;
scene.add(table);

// ── Steam Particles ──
const steamCount = 60;
const steamGeo = new THREE.BufferGeometry();
const steamPositions = new Float32Array(steamCount * 3);
const steamVelocities = [];
const steamOpacities = new Float32Array(steamCount);
const steamSizes = new Float32Array(steamCount);

for (let i = 0; i < steamCount; i++) {
  steamPositions[i * 3] = (Math.random() - 0.5) * 0.5;
  steamPositions[i * 3 + 1] = 1.8 + Math.random() * 2.5;
  steamPositions[i * 3 + 2] = (Math.random() - 0.5) * 0.5;
  steamVelocities.push({
    x: (Math.random() - 0.5) * 0.003,
    y: 0.008 + Math.random() * 0.012,
    z: (Math.random() - 0.5) * 0.003,
    phase: Math.random() * Math.PI * 2,
  });
  steamOpacities[i] = Math.random();
  steamSizes[i] = 8 + Math.random() * 12;
}

steamGeo.setAttribute('position', new THREE.BufferAttribute(steamPositions, 3));
steamGeo.setAttribute('opacity', new THREE.BufferAttribute(steamOpacities, 1));
steamGeo.setAttribute('size', new THREE.BufferAttribute(steamSizes, 1));

const steamVert = `
  attribute float opacity;
  attribute float size;
  varying float vOpacity;
  void main() {
    vOpacity = opacity;
    vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
    gl_PointSize = size * (200.0 / -mvPosition.z);
    gl_Position = projectionMatrix * mvPosition;
  }
`;

const steamFrag = `
  varying float vOpacity;
  void main() {
    float d = length(gl_PointCoord - vec2(0.5));
    if (d > 0.5) discard;
    float alpha = smoothstep(0.5, 0.0, d) * vOpacity * 0.35;
    gl_FragColor = vec4(0.95, 0.93, 0.90, alpha);
  }
`;

const steamMat = new THREE.ShaderMaterial({
  vertexShader: steamVert,
  fragmentShader: steamFrag,
  transparent: true,
  depthWrite: false,
  blending: THREE.AdditiveBlending,
});

const steam = new THREE.Points(steamGeo, steamMat);
cupGroup.add(steam);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle rotation
  cupGroup.rotation.y = Math.sin(t * 0.15) * 0.15;

  // Update steam
  const pos = steamGeo.attributes.position.array;
  const op = steamGeo.attributes.opacity.array;

  for (let i = 0; i < steamCount; i++) {
    const v = steamVelocities[i];
    pos[i * 3] += v.x + Math.sin(t * 0.8 + v.phase) * 0.002;
    pos[i * 3 + 1] += v.y;
    pos[i * 3 + 2] += v.z + Math.cos(t * 0.6 + v.phase) * 0.002;

    // Reset particle when too high
    if (pos[i * 3 + 1] > 4.5) {
      pos[i * 3] = (Math.random() - 0.5) * 0.5;
      pos[i * 3 + 1] = 1.8;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 0.5;
    }

    // Fade based on height
    const height = (pos[i * 3 + 1] - 1.8) / 2.7;
    op[i] = Math.max(0, 1 - height);
  }

  steamGeo.attributes.position.needsUpdate = true;
  steamGeo.attributes.opacity.needsUpdate = true;

  // Coffee surface ripple
  foamMesh.position.y = 1.74 + Math.sin(t * 1.2) * 0.005;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a cozy coffee scene with:

- **Ceramic cup** with a curved profile and rounded rim (built with `LatheGeometry`)
- **Handle** using a bezier curve tube
- **Coffee liquid** with a subtle foam layer that gently ripples
- **Saucer** underneath with a curved dish shape
- **Rising steam** particles using custom shaders with additive blending — they drift upward, sway gently, and fade out
- **Wooden table** surface
- **Three-point lighting** (warm key, cool fill, orange rim) with soft shadows
- **ACES filmic tone mapping** for a cinematic look
- **Orbit controls** — drag to rotate, scroll to zoom
- Gentle auto-rotation so the cup slowly sways

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Coin Scene</title>
