<body>
  <div id="info">Click &amp; drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene Setup ──────────────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0a0a12);
    scene.fog = new THREE.FogExp2(0x0a0a12, 0.08);

    const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 3, 5);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.target.set(0, 0, 0);
    controls.minDistance = 2;
    controls.maxDistance = 12;

    // ── Lighting ─────────────────────────────────────────
    const ambientLight = new THREE.AmbientLight(0x334466, 0.5);
    scene.add(ambientLight);

    const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
    keyLight.position.set(3, 6, 4);
    keyLight.castShadow = true;
    keyLight.shadow.mapSize.set(1024, 1024);
    keyLight.shadow.camera.near = 1;
    keyLight.shadow.camera.far = 20;
    keyLight.shadow.camera.left = -4;
    keyLight.shadow.camera.right = 4;
    keyLight.shadow.camera.top = 4;
    keyLight.shadow.camera.bottom = -4;
    keyLight.shadow.radius = 4;
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0x8899cc, 1);
    fillLight.position.set(-4, 3, -2);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xffaa44, 2, 10);
    rimLight.position.set(-2, 1, -3);
    scene.add(rimLight);

    const topLight = new THREE.PointLight(0xffffff, 1.5, 8);
    topLight.position.set(0, 5, 0);
    scene.add(topLight);

    // ── Coin Materials ───────────────────────────────────
    const goldMaterial = new THREE.MeshPhysicalMaterial({
      color: 0xd4a017,
      metalness: 0.95,
      roughness: 0.15,
      clearcoat: 0.3,
      clearcoatRoughness: 0.2,
    });

    const edgeMaterial = new THREE.MeshPhysicalMaterial({
      color: 0xc4920e,
      metalness: 0.95,
      roughness: 0.25,
      clearcoat: 0.1,
    });

    const darkGoldMaterial = new THREE.MeshPhysicalMaterial({
      color: 0x8a6508,
      metalness: 0.9,
      roughness: 0.3,
    });

    // ── Coin Group ───────────────────────────────────────
    const coin = new THREE.Group();

    // Main coin body
    const bodyGeo = new THREE.CylinderGeometry(1, 1, 0.12, 64);
    const body = new THREE.Mesh(bodyGeo, goldMaterial);
    body.castShadow = true;
    body.receiveShadow = true;
    coin.add(body);

    // Outer rim
    const rimGeo = new THREE.TorusGeometry(1.0, 0.04, 16, 64);
    const rim = new THREE.Mesh(rimGeo, goldMaterial);
    rim.rotation.x = Math.PI / 2;
    rim.position.y = 0.06;
    coin.add(rim);

    const rimBottom = rim.clone();
    rimBottom.position.y = -0.06;
    coin.add(rimBottom);

    // Inner decorative ring
    const innerRingGeo = new THREE.TorusGeometry(0.85, 0.02, 12, 64);
    const innerRing = new THREE.Mesh(innerRingGeo, darkGoldMaterial);
    innerRing.rotation.x = Math.PI / 2;
    innerRing.position.y = 0.061;
    coin.add(innerRing);

    const innerRingBottom = innerRing.clone();
    innerRingBottom.position.y = -0.061;
    coin.add(innerRingBottom);

    // Edge ridges (small ridges around the circumference)
    for (let i = 0; i < 32; i++) {
      const angle = (i / 32) * Math.PI * 2;
      const ridgeGeo = new THREE.BoxGeometry(0.015, 0.12, 0.04);
      const ridge = new THREE.Mesh(ridgeGeo, edgeMaterial);
      ridge.position.set(
        Math.cos(angle) * 1.0,
        0,
        Math.sin(angle) * 1.0
      );
      ridge.rotation.y = -angle;
      coin.add(ridge);
    }

    // Star on top face
    function createStarShape(radius) {
      const shape = new THREE.Shape();
      const spikes = 6;
      const outerR = radius;
      const innerR = radius * 0.45;
      for (let i = 0; i < spikes * 2; i++) {
        const r = i % 2 === 0 ? outerR : innerR;
        const a = (i / (spikes * 2)) * Math.PI * 2 - Math.PI / 2;
        if (i === 0) shape.moveTo(Math.cos(a) * r, Math.sin(a) * r);
        else shape.lineTo(Math.cos(a) * r, Math.sin(a) * r);
      }
      shape.closePath();
      return shape;
    }

    const starShape = createStarShape(0.5);
    const starExtrudeSettings = { depth: 0.015, bevelEnabled: true, bevelThickness: 0.005, bevelSize: 0.005, bevelSegments: 2 };
    const starGeo = new THREE.ExtrudeGeometry(starShape, starExtrudeSettings);
    const star = new THREE.Mesh(starGeo, goldMaterial);
    star.position.y = 0.07;
    star.rotation.x = -Math.PI / 2;
    star.castShadow = true;
    coin.add(star);

    // Small stars around the edge on top face
    for (let i = 0; i < 12; i++) {
      const angle = (i / 12) * Math.PI * 2;
      const smallStar = createStarShape(0.07);
      const smallStarGeo = new THREE.ExtrudeGeometry(smallStar, { depth: 0.008, bevelEnabled: false });
      const smallStarMesh = new THREE.Mesh(smallStarGeo, goldMaterial);
      smallStarMesh.position.set(
        Math.cos(angle) * 0.75,
        0.07,
        Math.sin(angle) * 0.75
      );
      smallStarMesh.rotation.x = -Math.PI / 2;
      smallStarMesh.rotation.z = angle;
      coin.add(smallStarMesh);
    }

    // "LIBERTY" text approximation - raised rectangle strips
    const textStripGeo = new THREE.BoxGeometry(0.9, 0.008, 0.08);
    const textStrip = new THREE.Mesh(textStripGeo, darkGoldMaterial);
    textStrip.position.set(0, 0.07, -0.55);
    coin.add(textStrip);

    // Bottom face: date approximation
    const dateGeo = new THREE.BoxGeometry(0.5, 0.008, 0.1);
    const dateMesh = new THREE.Mesh(dateGeo, darkGoldMaterial);
    dateMesh.position.set(0, -0.07, 0.45);
    coin.add(dateMesh);

    // Bottom face center: wreath circle
    const wreathGeo = new THREE.TorusGeometry(0.5, 0.025, 8, 48);
    const wreath = new THREE.Mesh(wreathGeo, darkGoldMaterial);
    wreath.rotation.x = Math.PI / 2;
    wreath.position.y = -0.071;
    coin.add(wreath);

    scene.add(coin);

    // ── Ground Plane ─────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(8, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x111118,
      metalness: 0.8,
      roughness: 0.4,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -1.2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Particle Sparkles ────────────────────────────────
    const particleCount = 80;
    const particleGeo = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    const velocities = [];
    for (let i = 0; i < particleCount; i++) {
      positions[i * 3] = (Math.random() - 0.5) * 6;
      positions[i * 3 + 1] = Math.random() * 4 - 0.5;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 6;
      velocities.push({
        x: (Math.random() - 0.5) * 0.003,
        y: Math.random() * 0.005 + 0.002,
        z: (Math.random() - 0.5) * 0.003,
      });
    }
    particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const particleMat = new THREE.PointsMaterial({
      color: 0xffd700,
      size: 0.03,
      transparent: true,
      opacity: 0.6,
      sizeAttenuation: true,
    });
    const particles = new THREE.Points(particleGeo, particleMat);
    scene.add(particles);

    // ── Animation ────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Gentle coin spin and float
      coin.rotation.y = elapsed * 0.4;
      coin.position.y = Math.sin(elapsed * 0.8) * 0.15;

      // Update particles
      const pos = particles.geometry.attributes.position;
      for (let i = 0; i < particleCount; i++) {
        pos.array[i * 3] += velocities[i].x;
        pos.array[i * 3 + 1] += velocities[i].y;
        pos.array[i * 3 + 2] += velocities[i].z;
        if (pos.array[i * 3 + 1] > 4) {
          pos.array[i * 3] = (Math.random() - 0.5) * 6;
          pos.array[i * 3 + 1] = -0.5;
          pos.array[i * 3 + 2] = (Math.random() - 0.5) * 6;
        }
      }
      pos.needsUpdate = true;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
