// --- Procedural cork texture ---
function createCorkTexture(size) {
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext('2d');

  // Base color
  ctx.fillStyle = '#c4a06a';
  ctx.fillRect(0, 0, size, size);

  // Granular noise
  const imageData = ctx.getImageData(0, 0, size, size);
  const d = imageData.data;
  for (let i = 0; i < d.length; i += 4) {
    const noise = (Math.random() - 0.5) * 40;
    d[i]     = Math.min(255, Math.max(0, d[i] + noise + 10));
    d[i + 1] = Math.min(255, Math.max(0, d[i + 1] + noise));
    d[i + 2] = Math.min(255, Math.max(0, d[i + 2] + noise - 15));
  }
  ctx.putImageData(imageData, 0, 0);

  // Cell-like structures (cork is made of tiny cells)
  for (let i = 0; i < 800; i++) {
    const x = Math.random() * size;
    const y = Math.random() * size;
    const r = 1 + Math.random() * 4;
    ctx.beginPath();
    ctx.ellipse(x, y, r, r * (0.6 + Math.random() * 0.8), Math.random() * Math.PI, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${140 + Math.random()*40}, ${110 + Math.random()*30}, ${60 + Math.random()*30}, ${0.15 + Math.random()*0.2})`;
    ctx.fill();
  }

  // Subtle darker veins
  for (let i = 0; i < 30; i++) {
    ctx.beginPath();
    let x = Math.random() * size, y = Math.random() * size;
    ctx.moveTo(x, y);
    for (let j = 0; j < 5 + Math.random() * 10; j++) {
      x += (Math.random() - 0.5) * 20;
      y += (Math.random() - 0.5) * 20;
      ctx.lineTo(x, y);
    }
    ctx.strokeStyle = `rgba(100, 75, 40, ${0.05 + Math.random() * 0.1})`;
    ctx.lineWidth = 0.5 + Math.random() * 1.5;
    ctx.stroke();
  }

  const tex = new THREE.CanvasTexture(canvas);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  return tex;
}

// --- Bump map ---
function createBumpTexture(size) {
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#808080';
  ctx.fillRect(0, 0, size, size);

  const imageData = ctx.getImageData(0, 0, size, size);
  const d = imageData.data;
  for (let i = 0; i < d.length; i += 4) {
    const v = 128 + (Math.random() - 0.5) * 80;
    d[i] = d[i+1] = d[i+2] = v;
  }
  ctx.putImageData(imageData, 0, 0);

  // Bumpy cells
  for (let i = 0; i < 600; i++) {
    const x = Math.random() * size;
    const y = Math.random() * size;
    const r = 1 + Math.random() * 5;
    const bright = Math.random() > 0.5;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fillStyle = bright ? `rgba(200,200,200,0.3)` : `rgba(50,50,50,0.3)`;
    ctx.fill();
  }

  const tex = new THREE.CanvasTexture(canvas);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  return tex;
}

const corkTexture = createCorkTexture(512);
