// Widest part (middle-upper)
points.push(new THREE.Vector2(0.88, 0.5));
points.push(new THREE.Vector2(0.90, 0.65));
points.push(new THREE.Vector2(0.88, 0.8));
points.push(new THREE.Vector2(0.82, 1.0));
points.push(new THREE.Vector2(0.74, 1.2));
points.push(new THREE.Vector2(0.65, 1.4));
// Top taper
points.push(new THREE.Vector2(0.55, 1.55));
points.push(new THREE.Vector2(0.45, 1.65));
points.push(new THREE.Vector2(0.38, 1.72));
points.push(new THREE.Vector2(0.30, 1.78));
points.push(new THREE.Vector2(0.22, 1.82));
points.push(new THREE.Vector2(0.10, 1.85));
points.push(new THREE.Vector2(0.0, 1.86));

const geometry = new THREE.LatheGeometry(points, 64);
geometry.computeVertexNormals();

const material = new THREE.MeshStandardMaterial({
  map: corkTexture,
  bumpMap: bumpTexture,
  bumpScale: 0.015,
  roughness: 0.95,
  metalness: 0.0,
  color: 0xd4b08a,
});

const cork = new THREE.Mesh(geometry, material);
cork.castShadow = true;
cork.receiveShadow = true;
scene.add(cork);

// --- Ground plane ---
const groundGeo = new THREE.CircleGeometry(4, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.8 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// --- Lighting ---
const ambient = new THREE.AmbientLight(0xfff5e6, 0.4);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 1.2);
keyLight.position.set(3, 5, 4);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 1;
keyLight.shadow.camera.far = 15;
keyLight.shadow.camera.left = -3;
keyLight.shadow.camera.right = 3;
keyLight.shadow.camera.top = 3;
keyLight.shadow.camera.bottom = -3;
keyLight.shadow.radius = 4;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0xc8d8ff, 0.4);
fillLight.position.set(-3, 3, -2);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffd4a0, 0.5);
rimLight.position.set(0, 2, -4);
scene.add(rimLight);

// --- Animation ---
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  cork.rotation.y = t * 0.4;
  cork.position.y = Math.sin(t * 0.8) * 0.08;
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
