body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);
camera.lookAt(0, 0.5, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// Lighting
const ambient = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xfff4e0, 1.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.3);
fillLight.position.set(-3, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffaa44, 0.8, 15);
rimLight.position.set(-2, 4, -3);
scene.add(rimLight);

// --- CORN GROUP ---
const corn = new THREE.Group();

// --- COB ---
const cobGeo = new THREE.CylinderGeometry(0.38, 0.45, 3.2, 32, 1);
// Slightly taper the ends
const cobPos = cobGeo.attributes.position;
for (let i = 0; i < cobPos.count; i++) {
  const y = cobPos.getY(i);
  const t = y / 1.6; // -1 to 1
  const taper = 1.0 - 0.15 * (1 - (1 - t * t));
  cobPos.setX(i, cobPos.getX(i) * taper);
  cobPos.setZ(i, cobPos.getZ(i) * taper);
}
cobPos.needsUpdate = true;
cobGeo.computeVertexNormals();

const cobMat = new THREE.MeshStandardMaterial({
  color: 0xf5d442,
  roughness: 0.7,
  metalness: 0.05,
});
const cob = new THREE.Mesh(cobGeo, cobMat);
cob.castShadow = true;
cob.receiveShadow = true;
corn.add(cob);

// --- KERNELS ---
const kernelGeo = new THREE.SphereGeometry(0.065, 8, 6, 0, Math.PI * 2, 0, Math.PI * 0.55);
const kernelMat = new THREE.MeshStandardMaterial({
  color: 0xffe44d,
  roughness: 0.4,
  metalness: 0.05,
});

const kernelInstanced = new THREE.InstancedMesh(kernelGeo, kernelMat, 2000);
kernelInstanced.castShadow = true;
kernelInstanced.receiveShadow = true;

const dummy = new THREE.Object3D();
let idx = 0;
const rows = 16;
const cols = 14;
const cobLength = 2.8;

for (let r = 0; r < cols; r++) {
  const y = -cobLength / 2 + 0.15 + (r / (cols - 1)) * cobLength;
  const t = (y / 1.6 + 1) / 2; // 0 to 1
  const taper = 1.0 - 0.15 * (1 - (1 - ((y / 1.6) * (y / 1.6))));
  const radius = 0.42 * taper;

  for (let c = 0; c < rows; c++) {
    const angle = (c / rows) * Math.PI * 2 + (r % 2) * (Math.PI / rows); // staggered
    const x = Math.cos(angle) * (radius + 0.055);
    const z = Math.sin(angle) * (radius + 0.055);

    dummy.position.set(x, y, z);
    dummy.lookAt(0, y, 0);
    dummy.rotateX(Math.PI);

    // Slight random variation
    dummy.scale.set(
      0.85 + Math.random() * 0.3,
      0.7 + Math.random() * 0.4,
      0.85 + Math.random() * 0.3
    );

    dummy.updateMatrix();
    kernelInstanced.setMatrixAt(idx, dummy.matrix);

    // Color variation
    const hue = 0.12 + Math.random() * 0.04;
    const col = new THREE.Color().setHSL(hue, 0.85 + Math.random() * 0.1, 0.65 + Math.random() * 0.15);
    kernelInstanced.setColorAt(idx, col);
    idx++;
  }
}
kernelInstanced.count = idx;
kernelInstanced.instanceMatrix.needsUpdate = true;
if (kernelInstanced.instanceColor) kernelInstanced.instanceColor.needsUpdate = true;
corn.add(kernelInstanced);

// --- HUSK LEAVES ---
function createHuskLeaf(width, length, curl, color) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(width * 0.3, length * 0.3, width * 0.5, length * 0.7);
  shape.quadraticCurveTo(width * 0.2, length * 0.95, 0, length);
  shape.quadraticCurveTo(-width * 0.15, length * 0.8, -width * 0.1, length * 0.4);
  shape.quadraticCurveTo(-width * 0.05, length * 0.2, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 12);
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const y = pos.getY(i);
    const t = y / length;
    pos.setZ(i, pos.getZ(i) + curl * t * t);
    pos.setX(i, pos.getX(i) + curl * 0.3 * t * Math.sin(t * Math.PI));
  }
  pos.needsUpdate = true;
  geo.computeVertexNormals();

  const mat = new THREE.MeshStandardMaterial({
    color: color,
    roughness: 0.8,
    metalness: 0.0,
    side: THREE.DoubleSide,
  });
  return new THREE.Mesh(geo, mat);
}

const huskColors = [0x4a7c2e, 0x5a8c35, 0x3d6b25, 0x558830, 0x4d7a30, 0x60993a];
const huskConfigs = [
  { w: 0.8, l: 3.5, curl: -0.8, rotY: 0.3, pos: [0.5, -0.2, 0.3], color: 0 },
  { w: 0.7, l: 3.3, curl: -0.6, rotY: 1.8, pos: [-0.4, 0.1, 0.4], color: 1 },
  { w: 0.65, l: 3.0, curl: -0.9, rotY: 3.2, pos: [0.3, -0.1, -0.5], color: 2 },
  { w: 0.75, l: 3.6, curl: -0.5, rotY: 4.5, pos: [-0.3, 0, 0.5], color: 3 },
  { w: 0.6, l: 2.8, curl: -1.0, rotY: 5.5, pos: [0.4, 0.2, -0.3], color: 4 },
  { w: 0.55, l: 2.5, curl: -0.7, rotY: 0.8, pos: [-0.5, -0.3, -0.2], color: 5 },
];

huskConfigs.forEach(cfg => {
  const leaf = createHuskLeaf(cfg.w, cfg.l, cfg.curl, huskColors[cfg.color]);
  leaf.position.set(...cfg.pos);
  leaf.rotation.y = cfg.rotY;
  leaf.rotation.x = -0.3 + Math.random() * 0.2;
  leaf.rotation.z = (Math.random() - 0.5) * 0.3;
  leaf.castShadow = true;
  leaf.receiveShadow = true;
  corn.add(leaf);
});

// --- TOP HUSK WRAP ---
const topWrapGeo = new THREE.CylinderGeometry(0.5, 0.42, 0.6, 24, 1, true);
const topWrapMat = new THREE.MeshStandardMaterial({
  color: 0x5a8c35,
  roughness: 0.85,
  side: THREE.DoubleSide,
});
const topWrap = new THREE.Mesh(topWrapGeo, topWrapMat);
topWrap.position.y = 1.5;
topWrap.castShadow = true;
corn.add(topWrap);

// --- SILK ---
const silkMat = new THREE.MeshStandardMaterial({
  color: 0xe8c86a,
  roughness: 0.9,
  metalness: 0.0,
});

for (let i = 0; i < 40; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 0.15 + Math.random() * 0.2;
  const startX = Math.cos(angle) * radius;
  const startZ = Math.sin(angle) * radius;
  const startY = 1.75 + Math.random() * 0.1;

  const endX = startX + (Math.random() - 0.5) * 0.6;
  const endY = startY + 0.5 + Math.random() * 1.0;
  const endZ = startZ + (Math.random() - 0.5) * 0.6;

  const midX = (startX + endX) / 2 + (Math.random() - 0.5) * 0.3;
  const midY = (startY + endY) / 2 + Math.random() * 0.2;
  const midZ = (startZ + endZ) / 2 + (Math.random() - 0.5) * 0.3;

  const curve = new THREE.QuadraticBezierCurve3(
    new THREE.Vector3(startX, startY, startZ),
    new THREE.Vector3(midX, midY, midZ),
    new THREE.Vector3(endX, endY, endZ)
  );

  const tubeGeo = new THREE.TubeGeometry(curve, 8, 0.006, 4, false);
  const silk = new THREE.Mesh(tubeGeo, silkMat);
  silk.castShadow = false;
  corn.add(silk);
}

// --- BOTTOM TIP ---
const tipGeo = new THREE.SphereGeometry(0.35, 16, 8, 0, Math.PI * 2, Math.PI * 0.5, Math.PI * 0.5);
const tipMat = new THREE.MeshStandardMaterial({ color: 0xf5d442, roughness: 0.7 });
const tip = new THREE.Mesh(tipGeo, tipMat);
tip.position.y = -1.6;
tip.rotation.x = Math.PI;
corn.add(tip);

// Center and add corn to scene
corn.position.y = 0.5;
scene.add(corn);

// --- GROUND ---
const groundGeo = new THREE.CircleGeometry(5, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.5;
ground.receiveShadow = true;
scene.add(ground);

// --- ANIMATION ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  corn.rotation.y = t * 0.3;
  corn.position.y = 0.5 + Math.sin(t * 0.8) * 0.1;

  // Gentle leaf sway
  corn.children.forEach((child, i) => {
    if (child.geometry && child.geometry.type === 'ShapeGeometry') {
      child.rotation.x = -0.3 + Math.sin(t * 1.2 + i) * 0.05;
    }
  });

  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **procedural 3D corn on the cob** with:

- **Cob** — tapered cylinder with a rounded tip
- **~224 kernels** — instanced hemispheres in staggered rows with color/size variation
- **6 husk leaves** — curved, double-sided shape geometries in varying greens
- **Top husk wrap** — partially covering the top
- **40 silk strands** — thin tubes along quadratic Bézier curves
- **Lighting** — directional, fill, rim, and ambient lights with shadows
- **Animation** — slow rotation + gentle floating + leaf sway
- **Ground plane** — dark surface with shadow reception

```html
<!DOCTYPE html>
<html lang="en">
<head>
