<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3.5, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0.8, 0);
controls.minDistance = 3;
controls.maxDistance = 15;

// ── Lighting ──
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
dirLight.shadow.bias = -0.001;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 0.6);
rimLight.position.set(-4, 3, -3);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xff6633, 0.5, 10);
pointLight.position.set(-2, 2, 2);
scene.add(pointLight);

// ── Materials ──
const woodMat = new THREE.MeshStandardMaterial({
  color: 0x8B6914,
  roughness: 0.85,
  metalness: 0.05,
});

const woodMatDark = new THREE.MeshStandardMaterial({
  color: 0x6B4F12,
  roughness: 0.9,
  metalness: 0.05,
});

const metalMat = new THREE.MeshStandardMaterial({
  color: 0x888888,
  roughness: 0.3,
  metalness: 0.8,
});

// ── Crate Group ──
const crate = new THREE.Group();

// Main body
const bodyGeo = new THREE.BoxGeometry(2, 1.6, 1.4);
const body = new THREE.Mesh(bodyGeo, woodMat);
body.position.y = 0.8;
body.castShadow = true;
body.receiveShadow = true;
crate.add(body);

// Vertical plank lines (thin boxes on each face)
function addPlankLines(group, parent, w, h, d, mat) {
  const plankThick = 0.02;
  const plankDepth = d + plankThick;
  const plankWidth = 0.02;
  const plankHeight = h + plankThick;

  // Front & back face vertical planks
  for (let i = -1; i <= 1; i += 2) {
    const plank = new THREE.Mesh(
      new THREE.BoxGeometry(plankThick, h, plankDepth),
      mat
    );
    plank.position.set(i * 0.5, 0, 0);
    plank.castShadow = true;
    parent.add(plank);
  }

  // Left & right face vertical planks
  for (let i = -1; i <= 1; i += 2) {
    const plank = new THREE.Mesh(
      new THREE.BoxGeometry(w + plankThick, h, plankThick),
      mat
    );
    plank.position.set(0, 0, i * 0.45);
    plank.castShadow = true;
    parent.add(plank);
  }
}

addPlankLines(crate, body, 2, 1.6, 1.4, woodMatDark);

// Cross beams on top
const beamGeo = new THREE.BoxGeometry(2.1, 0.15, 0.15);
const beam1 = new THREE.Mesh(beamGeo, woodMatDark);
beam1.position.set(0, 1.68, 0);
beam1.castShadow = true;
crate.add(beam1);

const beamGeo2 = new THREE.BoxGeometry(0.15, 0.15, 1.55);
const beam2 = new THREE.Mesh(beamGeo2, woodMatDark);
beam2.position.set(0, 1.68, 0);
beam2.castShadow = true;
crate.add(beam2);

// Metal corner brackets
function addBracket(x, y, z, rotY) {
  const bracketGroup = new THREE.Group();

  const plate1 = new THREE.Mesh(new THREE.BoxGeometry(0.04, 0.35, 0.25), metalMat);
  plate1.position.set(0, 0.175, 0.1);
  plate1.castShadow = true;
  bracketGroup.add(plate1);

  const plate2 = new THREE.Mesh(new THREE.BoxGeometry(0.25, 0.35, 0.04), metalMat);
  plate2.position.set(0.1, 0.175, 0);
  plate2.castShadow = true;
  bracketGroup.add(plate2);

  bracketGroup.position.set(x, y, z);
  bracketGroup.rotation.y = rotY;
  return bracketGroup;
}

const corners = [
  [-1, 0, -0.7, 0],
  [1, 0, -0.7, Math.PI / 2],
  [-1, 0, 0.7, -Math.PI / 2],
  [1, 0, 0.7, Math.PI],
];

corners.forEach(([x, y, z, r]) => {
  crate.add(addBracket(x, y, z, r));
});

// Metal bands around the crate
function addBand(axis, offset) {
  const band = new THREE.Mesh(
    new THREE.BoxGeometry(
      axis === 'x' ? 2.08 : 0.04,
      axis === 'y' ? 0.04 : 1.68,
      axis === 'z' ? 1.48 : 0.04
    ),
    metalMat
  );
  band.position.set(
    axis === 'x' ? 0 : offset,
    axis === 'y' ? offset : 0.8,
    axis === 'z' ? 0 : offset
  );
  band.castShadow = true;
  return band;
}

crate.add(addBand('x', 0));
crate.add(addBand('z', 0));

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Add crate to scene ──
scene.add(crate);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float
  crate.position.y = Math.sin(t * 0.8) * 0.08;
  crate.rotation.y = Math.sin(t * 0.3) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

