```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Crown</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a0a2e);
scene.fog = new THREE.FogExp2(0x1a0a2e, 0.04);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 6);
camera.lookAt(0, 0.5, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// Lighting
const ambientLight = new THREE.AmbientLight(0xffd699, 0.4);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
mainLight.position.set(3, 5, 4);
scene.add(mainLight);

const backLight = new THREE.DirectionalLight(0xffaa44, 1.0);
backLight.position.set(-3, 2, -3);
scene.add(backLight);

const pointLight1 = new THREE.PointLight(0xff6600, 2, 10);
pointLight1.position.set(2, 3, 2);
scene.add(pointLight1);

const pointLight2 = new THREE.PointLight(0xff0066, 1.5, 10);
pointLight2.position.set(-2, 1, 3);
scene.add(pointLight2);

// Materials
const goldMaterial = new THREE.MeshStandardMaterial({
  color: 0xffd700,
  metalness: 0.9,
  roughness: 0.2,
});

const darkGoldMaterial = new THREE.MeshStandardMaterial({
  color: 0xcc9900,
  metalness: 0.85,
  roughness: 0.3,
});

const rubyMaterial = new THREE.MeshStandardMaterial({
  color: 0xff1144,
  metalness: 0.1,
  roughness: 0.05,
  emissive: 0x440011,
  emissiveIntensity: 0.3,
});

const sapphireMaterial = new THREE.MeshStandardMaterial({
  color: 0x2244ff,
  metalness: 0.1,
  roughness: 0.05,
  emissive: 0x001144,
  emissiveIntensity: 0.3,
});

const emeraldMaterial = new THREE.MeshStandardMaterial({
  color: 0x11cc44,
  metalness: 0.1,
  roughness: 0.05,
  emissive: 0x003311,
  emissiveIntensity: 0.3,
});

const crownGroup = new THREE.Group();

// Base band - main torus
const baseTorus = new THREE.Mesh(
  new THREE.TorusGeometry(1.2, 0.18, 16, 48),
  goldMaterial
);
baseTorus.rotation.x = Math.PI / 2;
baseTorus.position.y = 0;
crownGroup.add(baseTorus);

// Inner band detail
const innerBand = new THREE.Mesh(
  new THREE.TorusGeometry(1.2, 0.06, 12, 48),
  darkGoldMaterial
);
innerBand.rotation.x = Math.PI / 2;
innerBand.position.y = 0.12;
crownGroup.add(innerBand);

// Bottom band detail
const bottomBand = new THREE.Mesh(
  new THREE.TorusGeometry(1.2, 0.05, 12, 48),
  darkGoldMaterial
);
bottomBand.rotation.x = Math.PI / 2;
bottomBand.position.y = -0.12;
crownGroup.add(bottomBand);

// Crown spikes / points
const NUM_SPIKES = 7;
const gemMaterials = [rubyMaterial, sapphireMaterial, emeraldMaterial];

for (let i = 0; i < NUM_SPIKES; i++) {
  const angle = (i / NUM_SPIKES) * Math.PI * 2;
  const isTall = i % 2 === 0;
  const height = isTall ? 1.6 : 1.1;
  const radius = 0.12;

  // Spike (cone)
  const spike = new THREE.Mesh(
    new THREE.ConeGeometry(radius, height, 8),
    goldMaterial
  );
  spike.position.set(
    Math.cos(angle) * 1.2,
    height / 2 + 0.18,
    Math.sin(angle) * 1.2
  );
  crownGroup.add(spike);

  // Gem on each spike
  const gem = new THREE.Mesh(
    new THREE.SphereGeometry(0.1, 16, 16),
    gemMaterials[i % 3]
  );
  gem.position.set(
    Math.cos(angle) * 1.2,
    height + 0.15,
    Math.sin(angle) * 1.2
  );
  crownGroup.add(gem);

  // Small gold ball under the gem
  const ball = new THREE.Mesh(
    new THREE.SphereGeometry(0.08, 12, 12),
    goldMaterial
  );
  ball.position.set(
    Math.cos(angle) * 1.2,
    height + 0.03,
    Math.sin(angle) * 1.2
  );
  crownGroup.add(ball);
}

// Decorative gems along the base band
for (let i = 0; i < 14; i++) {
  const angle = (i / 14) * Math.PI * 2 + Math.PI / 14;
  const smallGem = new THREE.Mesh(
    new THREE.SphereGeometry(0.055, 12, 12),
    gemMaterials[i % 3]
  );
  smallGem.position.set(
    Math.cos(angle) * 1.2,
    0.18,
    Math.sin(angle) * 1.2
  );
  crownGroup.add(smallGem);
}

// Front center large gem
const centerGem = new THREE.Mesh(
  new THREE.SphereGeometry(0.15, 20, 20),
  rubyMaterial
);
centerGem.position.set(0, 0.18, 1.2);
crownGroup.add(centerGem);

// Small decorative arches between tall spikes
for (let i = 0; i < NUM_SPIKES; i++) {
  const angle = (i / NUM_SPIKES) * Math.PI * 2;
  const nextAngle = ((i + 1) / NUM_SPIKES) * Math.PI * 2;
  const midAngle = (angle + nextAngle) / 2;

  const archCurve = new THREE.QuadraticBezierCurve3(
    new THREE.Vector3(Math.cos(angle) * 1.2, 1.0, Math.sin(angle) * 1.2),
    new THREE.Vector3(Math.cos(midAngle) * 1.35, 1.5, Math.sin(midAngle) * 1.35),
    new THREE.Vector3(Math.cos(nextAngle) * 1.2, 1.0, Math.sin(nextAngle) * 1.2),
  );

  const archPoints = archCurve.getPoints(12);
  const archGeometry = new THREE.TubeGeometry(
    new THREE.CatmullRomCurve3(archPoints),
    12, 0.025, 8, false
  );
  const arch = new THREE.Mesh(archGeometry, goldMaterial);
  crownGroup.add(arch);
}

crownGroup.rotation.y = Math.PI;
scene.add(crownGroup);

// Floating particles
const particleCount = 200;
const particleGeometry = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 10;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMaterial = new THREE.PointsMaterial({
  color: 0xffd700,
  size: 0.03,
  transparent: true,
  opacity: 0.6,
});
const particles = new THREE.Points(particleGeometry, particleMaterial);
scene.add(particles);

// Mouse interaction
let mouseX = 0, mouseY = 0;
document.addEventListener('mousemove', (e) => {
  mouseX = (e.clientX / innerWidth - 0.5) * 2;
  mouseY = (e.clientY / innerHeight - 0.5) * 2;
});

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// Animate
function animate(time) {
  requestAnimationFrame(animate);
  const t = time * 0.001;

  crownGroup.rotation.y = Math.sin(t * 0.3) * 0.3 + mouseX * 0.5;
  crownGroup.position.y = Math.sin(t * 0.8) * 0.15;

  particles.rotation.y = t * 0.02;
  particles.rotation.x = Math.sin(t * 0.1) * 0.1;

  pointLight1.position.x = Math.sin(t) * 3;
  pointLight1.position.z = Math.cos(t) * 3;

  camera.position.x += (mouseX * 2 - camera.position.x) * 0.02;
  camera.position.y += (2 - mouseY * 1.5 - camera.position.y) * 0.02;
  camera.lookAt(0, 0.5, 0);

  renderer.render(scene, camera);
}
animate(0);
</script>
</body>
</html>
