const handleGeo = new THREE.TorusGeometry(0.55, 0.08, 16, 32, Math.PI * 1.4);
const handle = new THREE.Mesh(handleGeo, ceramic);
handle.position.set(1.15, 1.2, 0);
handle.rotation.z = Math.PI / 2;
handle.rotation.y = -Math.PI * 0.2;
