    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0, 0);
    controls.enableDamping = true;

    // ── Lighting ───────────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x404060, 0.8));

    const keyLight = new THREE.DirectionalLight(0xffffff, 2.5);
    keyLight.position.set(4, 6, 4);
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
    fillLight.position.set(-3, 2, -2);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xff6644, 1.5, 15);
    rimLight.position.set(0, -1, -5);
    scene.add(rimLight);

    // ── Materials ──────────────────────────────────────────────
    const metalMat = new THREE.MeshStandardMaterial({
      color: 0xcccccc, metalness: 0.95, roughness: 0.15
    });

    const darkMetalMat = new THREE.MeshStandardMaterial({
      color: 0x555555, metalness: 0.9, roughness: 0.25
    });

    const gripMat = new THREE.MeshStandardMaterial({
      color: 0x222222, metalness: 0.3, roughness: 0.8
    });

    const flightColors = [0xe63946, 0xe63946, 0xe63946];
    const flightMats = flightColors.map(c => new THREE.MeshStandardMaterial({
      color: c, metalness: 0.0, roughness: 0.6, side: THREE.DoubleSide, transparent: true, opacity: 0.9
    }));

    const bandMat = new THREE.MeshStandardMaterial({
      color: 0xddaa22, metalness: 0.85, roughness: 0.2
    });

    // ── Dart Group ─────────────────────────────────────────────
    const dart = new THREE.Group();

    // Tip (cone)
    const tipGeo = new THREE.ConeGeometry(0.08, 0.5, 16);
    tipGeo.translate(0, 0.25, 0);
    const tip = new THREE.Mesh(tipGeo, metalMat);
    dart.add(tip);

    // Barrel (cylinder)
    const barrelGeo = new THREE.CylinderGeometry(0.1, 0.08, 1.6, 16);
    barrelGeo.translate(0, -0.8, 0);
    const barrel = new THREE.Mesh(barrelGeo, metalMat);
    dart.add(barrel);

    // Grip rings on barrel
    for (let i = 0; i < 12; i++) {
      const ringGeo = new THREE.CylinderGeometry(0.105, 0.105, 0.025, 16);
      ringGeo.translate(0, -0.3 - i * 0.09, 0);
      const ring = new THREE.Mesh(ringGeo, gripMat);
      dart.add(ring);
    }

    // Gold band near tip
    const bandGeo = new THREE.TorusGeometry(0.102, 0.018, 8, 24);
    bandGeo.rotateX(Math.PI / 2);
    bandGeo.translate(0, -0.02, 0);
    const band = new THREE.Mesh(bandGeo, bandMat);
    dart.add(band);

    // Stem
    const stemGeo = new THREE.CylinderGeometry(0.025, 0.035, 0.6, 12);
    stemGeo.translate(0, -1.7, 0);
    const stem = new THREE.Mesh(stemGeo, darkMetalMat);
    dart.add(stem);

    // Flights (3 flat shapes)
    function createFlight(angle) {
      const shape = new THREE.Shape();
      shape.moveTo(0, 0);
      shape.bezierCurveTo(0.06, 0.25, 0.12, 0.5, 0.02, 0.75);
      shape.lineTo(0, 0.75);
      shape.lineTo(-0.02, 0.75);
      shape.bezierCurveTo(-0.12, 0.5, -0.06, 0.25, 0, 0);

      const geo = new THREE.ShapeGeometry(shape, 8);
      const mesh = new THREE.Mesh(geo, flightMats[0]);
      mesh.rotation.z = angle;
      mesh.position.y = -2.0;
      return mesh;
    }

    for (let i = 0; i < 3; i++) {
      dart.add(createFlight((i * Math.PI * 2) / 3));
    }

    // Small cap at bottom of stem
    const capGeo = new THREE.CylinderGeometry(0.04, 0.025, 0.06, 12);
    capGeo.translate(0, -2.03, 0);
    const cap = new THREE.Mesh(capGeo, darkMetalMat);
    dart.add(cap);

    // Tilt the dart to point diagonally
    dart.rotation.z = -Math.PI / 6;
    dart.rotation.x = Math.PI / 8;
    scene.add(dart);

    // ── Ground plane (subtle) ──────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(4, 48);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x1a1a2e, metalness: 0.5, roughness: 0.8
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -3;
    scene.add(ground);

    // ── Animation ──────────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle floating rotation
      dart.rotation.y = Math.sin(t * 0.4) * 0.3;
      dart.position.y = Math.sin(t * 0.8) * 0.15;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ─────────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
