  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 4);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

// --- Diamond geometry (lathe from profile) ---
const points = [
  // Table (top flat)
  new THREE.Vector2(0.0, 1.0),
  new THREE.Vector2(0.5, 1.0),
  // Crown
  new THREE.Vector2(0.55, 0.85),
  new THREE.Vector2(0.6, 0.75),
  // Girdle
  new THREE.Vector2(0.85, 0.65),
  new THREE.Vector2(1.0, 0.55),
  new THREE.Vector2(1.05, 0.45),
  new THREE.Vector2(1.0, 0.35),
  new THREE.Vector2(0.85, 0.25),
  // Pavilion
  new THREE.Vector2(0.6, 0.1),
  new THREE.Vector2(0.3, -0.2),
  new THREE.Vector2(0.1, -0.5),
  // Culet (bottom point)
  new THREE.Vector2(0.0, -0.65),
];

const geometry = new THREE.LatheGeometry(points, 32);
geometry.computeVertexNormals();

// --- Diamond material ---
const material = new THREE.MeshPhysicalMaterial({
  color: 0xffffff,
  metalness: 0.0,
  roughness: 0.0,
  transmission: 0.97,
  thickness: 1.5,
  ior: 2.42,
  specularIntensity: 1.0,
  specularColor: new THREE.Color(0xffffff),
  envMapIntensity: 3.0,
  clearcoat: 1.0,
  clearcoatRoughness: 0.0,
  transparent: true,
  opacity: 0.95,
  side: THREE.DoubleSide,
  attenuationColor: new THREE.Color(0xddeeff),
  attenuationDistance: 2,
});

const diamond = new THREE.Mesh(geometry, material);
scene.add(diamond);

// --- Environment (studio-style sphere) ---
const envCanvas = document.createElement('canvas');
envCanvas.width = 1024;
envCanvas.height = 512;
const ctx = envCanvas.getContext('2d');

// Gradient background
const grad = ctx.createLinearGradient(0, 0, 0, 512);
grad.addColorStop(0, '#1a1a2e');
grad.addColorStop(0.3, '#16213e');
grad.addColorStop(0.5, '#0f3460');
grad.addColorStop(0.7, '#16213e');
grad.addColorStop(1, '#1a1a2e');
ctx.fillStyle = grad;
ctx.fillRect(0, 0, 1024, 512);

// Bright spots for reflections
const spots = [
  { x: 200, y: 150, r: 60, c: 'rgba(255,255,255,0.9)' },
  { x: 700, y: 120, r: 80, c: 'rgba(200,220,255,0.8)' },
  { x: 500, y: 200, r: 40, c: 'rgba(255,255,255,1.0)' },
  { x: 100, y: 300, r: 50, c: 'rgba(180,200,255,0.6)' },
  { x: 850, y: 280, r: 55, c: 'rgba(255,240,220,0.7)' },
  { x: 400, y: 80, r: 30, c: 'rgba(255,255,255,0.95)' },
  { x: 600, y: 350, r: 45, c: 'rgba(200,220,255,0.5)' },
];
spots.forEach(s => {
  const g = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, s.r);
  g.addColorStop(0, s.c);
  g.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.fillStyle = g;
  ctx.fillRect(s.x - s.r, s.y - s.r, s.r * 2, s.r * 2);
});

const envTexture = new THREE.CanvasTexture(envCanvas);
const pmrem = new THREE.PMREMGenerator(renderer);
const envRT = pmrem.fromEquirectangular(envTexture);
scene.environment = envRT.texture;
envTexture.dispose();
pmrem.dispose();

// --- Lights ---
const ambient = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambient);

const keyLight = new THREE.PointLight(0xffffff, 80, 20);
keyLight.position.set(3, 4, 3);
scene.add(keyLight);

const fillLight = new THREE.PointLight(0x8888ff, 30, 20);
fillLight.position.set(-4, 2, -2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffeedd, 40, 20);
rimLight.position.set(0, -2, -4);
scene.add(rimLight);

const topLight = new THREE.PointLight(0xffffff, 50, 15);
topLight.position.set(0, 6, 0);
scene.add(topLight);

// --- Sparkle particles ---
const sparkleCount = 60;
const sparkleGeo = new THREE.BufferGeometry();
const sparklePos = new Float32Array(sparkleCount * 3);
const sparkleSizes = new Float32Array(sparkleCount);
for (let i = 0; i < sparkleCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.acos(2 * Math.random() - 1);
  const r = 1.5 + Math.random() * 1.5;
  sparklePos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
  sparklePos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
  sparklePos[i * 3 + 2] = r * Math.cos(phi);
  sparkleSizes[i] = Math.random() * 3 + 1;
}
sparkleGeo.setAttribute('position', new THREE.BufferAttribute(sparklePos, 3));
sparkleGeo.setAttribute('size', new THREE.BufferAttribute(sparkleSizes, 1));

const sparkleMat = new THREE.PointsMaterial({
  color: 0xffffff,
  size: 0.04,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
});
const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
scene.add(sparkles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  diamond.rotation.y = t * 0.3;
  sparkles.rotation.y = t * 0.1;
  sparkles.rotation.x = Math.sin(t * 0.15) * 0.2;

  // Twinkle sparkles
  sparkleMat.opacity = 0.3 + Math.sin(t * 2) * 0.3;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
