<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Diaper</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
position: absolute; top: 12px; width: 100%; text-align: center;
font-family: system-ui, sans-serif; color: #fff; font-size: 14px;
pointer-events: none; opacity: 0.6;
}
</style>
</head>
<body>
<div id="info">🍼 Three.js Diaper — drag to orbit</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 18);

// ── Camera ─────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2.5, 5);

// ── Renderer ───────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ───────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.minDistance = 3;
controls.maxDistance = 10;

// ── Lights ─────────────────────────────────────────────
const ambient = new THREE.AmbientLight(0x8090b0, 0.6);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xfff4e6, 2.5);
key.position.set(3, 5, 4);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
key.shadow.camera.near = 1;
key.shadow.camera.far = 15;
key.shadow.camera.left = -4;
key.shadow.camera.right = 4;
key.shadow.camera.top = 4;
key.shadow.camera.bottom = -4;
scene.add(key);

const fill = new THREE.DirectionalLight(0xc0d0ff, 0.8);
fill.position.set(-3, 2, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xffc0cb, 1.5, 10);
rim.position.set(-2, 3, -3);
scene.add(rim);

// ── Materials ──────────────────────────────────────────
const outerMat = new THREE.MeshStandardMaterial({
  color: 0xe8e8e8,
  roughness: 0.7,
  metalness: 0.0,
});

const innerMat = new THREE.MeshStandardMaterial({
  color: 0xfff8f0,
  roughness: 0.9,
  metalness: 0.0,
});

const elasticMat = new THREE.MeshStandardMaterial({
  color: 0x6688cc,
  roughness: 0.5,
  metalness: 0.1,
});

const waistMat = new THREE.MeshStandardMaterial({
  color: 0xd0d8f0,
  roughness: 0.6,
  metalness: 0.05,
});

const tapeMat = new THREE.MeshStandardMaterial({
  color: 0xc0c0c0,
  roughness: 0.8,
  metalness: 0.0,
});

const patternMat = new THREE.MeshStandardMaterial({
  color: 0xb0d0ff,
  roughness: 0.7,
  metalness: 0.0,
});

// ── Diaper Group ───────────────────────────────────────
const diaper = new THREE.Group();

// Helper: create a rounded box via shape extrusion
function createRoundedPanel(w, h, r, thickness) {
  const shape = new THREE.Shape();
  const hw = w / 2, hh = h / 2;
  shape.moveTo(-hw + r, -hh);
  shape.lineTo(hw - r, -hh);
  shape.quadraticCurveTo(hw, -hh, hw, -hh + r);
  shape.lineTo(hw, hh - r);
  shape.quadraticCurveTo(hw, hh, hw - r, hh);
  shape.lineTo(-hw + r, hh);
  shape.quadraticCurveTo(-hw, hh, -hw, hh - r);
  shape.lineTo(-hw, -hh + r);
  shape.quadraticCurveTo(-hw, -hh, -hw + r, -hh);

  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: thickness,
    bevelEnabled: true,
    bevelThickness: r * 0.5,
    bevelSize: r * 0.5,
    bevelSegments: 4,
  });
  geo.center();
  return geo;
}

// ── Main Body (outer shell) ────────────────────────────
const bodyGeo = createRoundedPanel(2.2, 2.8, 0.35, 0.25);
const body = new THREE.Mesh(bodyGeo, outerMat);
body.castShadow = true;
body.receiveShadow = true;
diaper.add(body);

// ── Inner lining (slightly smaller, warmer color) ──────
const innerGeo = createRoundedPanel(2.0, 2.6, 0.3, 0.15);
const inner = new THREE.Mesh(innerGeo, innerMat);
inner.position.z = 0.06;
diaper.add(inner);

// ── Absorbent core bulge (center) ──────────────────────
const coreGeo = new THREE.SphereGeometry(0.7, 32, 24);
coreGeo.scale(1, 1.6, 0.35);
const core = new THREE.Mesh(coreGeo, innerMat);
core.position.set(0, 0, 0.12);
diaper.add(core);

// ── Waistband (top elastic band) ───────────────────────
const waistGeo = new THREE.TorusGeometry(0.95, 0.1, 16, 48);
const waist = new THREE.Mesh(waistGeo, waistMat);
waist.position.set(0, 1.2, 0.1);
waist.rotation.x = Math.PI / 2;
waist.scale.set(1, 0.6, 1);
diaper.add(waist);

// ── Leg gathers (elastic cuffs) ────────────────────────
function createLegCuff(x, rotY) {
  const group = new THREE.Group();

  const cuffGeo = new THREE.TorusGeometry(0.35, 0.08, 12, 32);
  const cuff = new THREE.Mesh(cuffGeo, elasticMat);
  cuff.castShadow = true;
  group.add(cuff);

  // Secondary inner ring
  const innerCuffGeo = new THREE.TorusGeometry(0.25, 0.05, 10, 28);
  const innerCuff = new THREE.Mesh(innerCuffGeo, elasticMat);
  innerCuff.position.z = 0.05;
  group.add(innerCuff);

  group.position.set(x, -0.7, 0.15);
  group.rotation.y = rotY;
  group.rotation.x = Math.PI / 2;
  return group;
}

diaper.add(createLegCuff(-0.7, 0));
diaper.add(createLegCuff(0.7, 0));

// ── Tape fasteners (back side) ─────────────────────────
function createTape(x, y) {
  const tapeGeo = new THREE.BoxGeometry(0.35, 0.12, 0.04);
  const tape = new THREE.Mesh(tapeGeo, tapeMat);
  tape.position.set(x, y, -0.15);
  tape.castShadow = true;
  return tape;
}

diaper.add(createTape(-0.5, 1.0));
diaper.add(createTape(0.5, 1.0));

// ── Decorative pattern dots ────────────────────────────
const dotGeo = new THREE.SphereGeometry(0.03, 8, 8);
const dotPositions = [
  [-0.4, 0.3], [0.4, 0.3], [-0.4, -0.1], [0.4, -0.1],
  [-0.4, -0.5], [0.4, -0.5], [0, 0.6], [0, -0.3],
];
dotPositions.forEach(([x, y]) => {
  const dot = new THREE.Mesh(dotGeo, patternMat);
  dot.position.set(x, y, 0.22);
  diaper.add(dot);
});

// ── Position diaper ────────────────────────────────────
diaper.rotation.x = -0.15;
diaper.rotation.y = 0.3;
diaper.position.y = 0.3;
scene.add(diaper);

// ── Floor ──────────────────────────────────────────────
const floorGeo = new THREE.CircleGeometry(6, 64);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a4a,
  roughness: 0.9,
  metalness: 0.1,
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -1.2;
floor.receiveShadow = true;
scene.add(floor);

// ── Subtle ring light reflection on floor ──────────────
const ringGeo = new THREE.RingGeometry(1.5, 1.55, 64);
const ringMat = new THREE.MeshBasicMaterial({
  color: 0x6688cc,
  transparent: true,
  opacity: 0.15,
  side: THREE.DoubleSide,
});
const ring = new THREE.Mesh(ringGeo, ringMat);
ring.rotation.x = -Math.PI / 2;
ring.position.y = -1.19;
scene.add(ring);

// ── Animation ──────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating
  diaper.position.y = 0.3 + Math.sin(t * 0.8) * 0.12;

  // Subtle rotation
  diaper.rotation.y = 0.3 + Math.sin(t * 0.3) * 0.15;

  // Rim light orbit
  rim.position.x = Math.sin(t * 0.5) * 3;
  rim.position.z = Math.cos(t * 0.5) * 3;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the scene

| Element | Geometry | Purpose |
|---|---|---|
| **Main body** | Extruded rounded rectangle | The diaper's outer shell |
| **Inner lining** | Smaller extruded panel | Warm-toned inner surface |
| **Absorbent core** | Scaled sphere | Puffy center bulge |
| **Waistband** | Flattened torus | Top elastic band |
| **Leg cuffs** | Double torus pairs ×2 | Elastic leg gathers |
| **Tape fasteners** | Small boxes | Back adhesive tabs |
| **Pattern dots** | Small spheres | Decorative print |

**Features:**
- 🎥 **OrbitControls** — drag to rotate, scroll to zoom
- 💡 **3-point lighting** with soft shadows and a pink rim light
- 🌊 **Gentle float animation** with subtle sway
- 🎨 **ACES tone mapping** for a polished look
- 📱 **Responsive** — adapts to window resize

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Doughnut</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 5);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

// --- Doughnut (Torus) ---
const geometry = new THREE.TorusGeometry(1, 0.4, 32, 100);
const material = new THREE.MeshStandardMaterial({
  color: 0xe8a87c,
  roughness: 0.35,
  metalness: 0.1,
});
const doughnut = new THREE.Mesh(geometry, material);
doughnut.castShadow = true;
scene.add(doughnut);

// --- Sprinkles ---
const sprinkleColors = [0xff6b6b, 0x48dbfb, 0xfeca57, 0xff9ff3, 0x54a0ff];
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const tubeAngle = Math.random() * Math.PI * 2;
  const R = 1, r = 0.4;
  const x = (R + r * Math.cos(tubeAngle)) * Math.cos(angle);
  const y = r * Math.sin(tubeAngle);
  const z = (R + r * Math.cos(tubeAngle)) * Math.sin(angle);

  const sprinkleGeo = new THREE.CapsuleGeometry(0.02, 0.08, 4, 8);
  const sprinkleMat = new THREE.MeshStandardMaterial({
    color: sprinkleColors[Math.floor(Math.random() * sprinkleColors.length)],
    roughness: 0.5,
    metalness: 0.0,
  });
  const sprinkle = new THREE.Mesh(sprinkleGeo, sprinkleMat);
  sprinkle.position.set(x, y, z);
  sprinkle.lookAt(0, 0, 0);
  sprinkle.rotateX(Math.random() * Math.PI);
  sprinkle.rotateZ(Math.random() * Math.PI);
  doughnut.add(sprinkle);
}

// --- Lighting ---
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const keyLight = new THREE.DirectionalLight(0xfff0dd, 2.5);
keyLight.position.set(5, 8, 5);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff9966, 1.5, 15);
rimLight.position.set(-3, -2, 4);
scene.add(rimLight);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.minDistance = 3;
controls.maxDistance = 12;

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// --- Animate ---
function animate(time) {
  requestAnimationFrame(animate);
  doughnut.rotation.x = Math.sin(time * 0.0005) * 0.3;
  doughnut.rotation.y = time * 0.0008;
  controls.update();
  renderer.render(scene, camera);
}
animate(0);
</script>
</body>
</html>
```

## What you get

- **A 3D doughnut** (torus) rendered with warm frosting color (`#e8a87c`)
- **60 colorful sprinkles** randomly placed around the surface using capsule geometries
- **Three-point lighting** (key, fill, rim) for a cinematic look
- **Orbit controls** — click & drag to rotate, scroll to zoom
- **Gentle idle animation** — the doughnut slowly rotates and tilts
- **Responsive** — resizes with the browser window

Just save it as `index.html` and open in any modern browser. No build step needed!

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Dolphin</title>
<style>
* { margin: 0; padding: 0; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a1628);
scene.fog = new THREE.FogExp2(0x0a1628, 0.012);

const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 4, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0, 0);

// ── Lights ──
scene.add(new THREE.AmbientLight(0x334466, 0.8));
const sun = new THREE.DirectionalLight(0xffeedd, 2.5);
sun.position.set(5, 10, 5);
scene.add(sun);
const rim = new THREE.DirectionalLight(0x4488ff, 1.0);
rim.position.set(-3, 2, -5);
scene.add(rim);
const fill = new THREE.PointLight(0x2266aa, 1.5, 30);
fill.position.set(-4, -2, 6);
scene.add(fill);

// ── Dolphin Material ──
const dolphinMat = new THREE.MeshStandardMaterial({
  color: 0x6699bb,
  roughness: 0.35,
  metalness: 0.15,
});
const darkMat = new THREE.MeshStandardMaterial({
  color: 0x446688,
  roughness: 0.4,
  metalness: 0.1,
});

// ── Build Dolphin ──
const dolphin = new THREE.Group();

// Body (main)
const bodyGeo = new THREE.SphereGeometry(1, 32, 24);
bodyGeo.scale(1.8, 0.75, 0.65);
const body = new THREE.Mesh(bodyGeo, dolphinMat);
body.position.set(-0.2, 0, 0);
dolphin.add(body);

// Head
const headGeo = new THREE.SphereGeometry(0.55, 24, 18);
headGeo.scale(1.1, 0.9, 0.85);
const head = new THREE.Mesh(headGeo, dolphinMat);
head.position.set(1.5, 0.15, 0);
dolphin.add(head);

// Snout / beak
const snoutGeo = new THREE.ConeGeometry(0.18, 0.9, 16);
snoutGeo.rotateZ(-Math.PI / 2);
const snout = new THREE.Mesh(snoutGeo, dolphinMat);
snout.position.set(2.35, 0.1, 0);
dolphin.add(snout);

// Eye
const eyeGeo = new THREE.SphereGeometry(0.07, 12, 12);
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.2 });
const eyeL = new THREE.Mesh(eyeGeo, eyeMat);
eyeL.position.set(1.75, 0.35, 0.35);
dolphin.add(eyeL);
const eyeR = eyeL.clone();
eyeR.position.z = -0.35;
dolphin.add(eyeR);

// Tail stock (tapered)
const tailStockGeo = new THREE.CylinderGeometry(0.25, 0.45, 1.2, 16);
tailStockGeo.rotateZ(Math.PI / 2);
const tailStock = new THREE.Mesh(tailStockGeo, dolphinMat);
tailStock.position.set(-2.1, 0, 0);
dolphin.add(tailStock);

// Tail flukes (left & right)
function makeFluke(side) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.6, side * 0.5, 1.0, side * 1.1);
  shape.quadraticCurveTo(0.5, side * 0.6, 0, 0);
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: 0.06, bevelEnabled: true, bevelThickness: 0.03,
    bevelSize: 0.03, bevelSegments: 3
  });
  geo.rotateY(Math.PI / 2);
  const mesh = new THREE.Mesh(geo, darkMat);
  mesh.position.set(-2.8, 0.05, 0);
  return mesh;
}
dolphin.add(makeFluke(1));
dolphin.add(makeFluke(-1));

// Dorsal fin
const dorsalShape = new THREE.Shape();
dorsalShape.moveTo(0, 0);
dorsalShape.quadraticCurveTo(0.15, 0.6, -0.1, 1.0);
dorsalShape.quadraticCurveTo(-0.05, 0.5, -0.3, 0);
const dorsalGeo = new THREE.ExtrudeGeometry(dorsalShape, {
  depth: 0.05, bevelEnabled: true, bevelThickness: 0.025,
  bevelSize: 0.025, bevelSegments: 3
});
const dorsal = new THREE.Mesh(dorsalGeo, darkMat);
dorsal.position.set(-0.3, 0.55, -0.025);
dorsal.rotation.y = Math.PI / 2;
dorsal.rotation.z = Math.PI / 2;
dolphin.add(dorsal);

// Pectoral fins
function makePectoral(side) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.3, side * 0.15, 0.7, side * 0.55);
  shape.quadraticCurveTo(0.4, side * 0.3, 0.1, side * 0.05);
  shape.closePath();
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: 0.04, bevelEnabled: true, bevelThickness: 0.02,
    bevelSize: 0.02, bevelSegments: 2
  });
  const mesh = new THREE.Mesh(geo, darkMat);
  mesh.position.set(0.6, -0.15, side * 0.45);
  mesh.rotation.y = side * 0.3;
  mesh.rotation.x = -0.2;
  return mesh;
}
dolphin.add(makePectoral(1));
dolphin.add(makePectoral(-1));

scene.add(dolphin);

// ── Ocean Floor (grid of particles) ──
const floorGeo = new THREE.PlaneGeometry(100, 100, 1, 1);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x0c1a30, roughness: 1, metalness: 0
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -8;
scene.add(floor);

// ── Bubbles ──
const bubbleCount = 120;
const bubbleGeo = new THREE.BufferGeometry();
const bubblePos = new Float32Array(bubbleCount * 3);
const bubbleSizes = new Float32Array(bubbleCount);
for (let i = 0; i < bubbleCount; i++) {
  bubblePos[i * 3] = (Math.random() - 0.5) * 40;
  bubblePos[i * 3 + 1] = Math.random() * 30 - 5;
  bubblePos[i * 3 + 2] = (Math.random() - 0.5) * 40;
  bubbleSizes[i] = Math.random() * 3 + 1;
}
bubbleGeo.setAttribute('position', new THREE.BufferAttribute(bubblePos, 3));
bubbleGeo.setAttribute('size', new THREE.BufferAttribute(bubbleSizes, 1));

const bubbleMat = new THREE.PointsMaterial({
  color: 0x88bbdd,
  size: 0.15,
  transparent: true,
  opacity: 0.35,
  sizeAttenuation: true,
});
const bubbles = new THREE.Points(bubbleGeo, bubbleMat);
scene.add(bubbles);

// ── Light rays (fake caustics on floor) ──
const rayGeo = new THREE.PlaneGeometry(2, 20);
const rayMat = new THREE.MeshBasicMaterial({
  color: 0x4488cc,
  transparent: true,
  opacity: 0.06,
  side: THREE.DoubleSide,
  depthWrite: false,
});
for (let i = 0; i < 6; i++) {
  const ray = new THREE.Mesh(rayGeo, rayMat);
  ray.position.set((Math.random() - 0.5) * 20, 5, (Math.random() - 0.5) * 20);
  ray.rotation.set(0.3, Math.random() * Math.PI, 0.2 * (Math.random() - 0.5));
  scene.add(ray);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Swimming motion
  dolphin.position.y = Math.sin(t * 0.8) * 0.6;
  dolphin.rotation.z = Math.sin(t * 0.6) * 0.08;
  dolphin.rotation.x = Math.sin(t * 0.4) * 0.04;

  // Tail wag
  const tailAngle = Math.sin(t * 3) * 0.15;
  dolphin.children.forEach(child => {
    if (child.geometry && child.geometry.type === 'ExtrudeGeometry') {
      // flukes
      if (child.position.x < -2.5) {
        child.rotation.y = tailAngle;
      }
    }
  });

  // Slow orbit
  dolphin.position.x = Math.sin(t * 0.15) * 2;
  dolphin.position.z = Math.cos(t * 0.15) * 2;
  dolphin.rotation.y = -t * 0.15 + Math.PI;

  // Bubbles rise
  const pos = bubbles.geometry.attributes.position.array;
  for (let i = 0; i < bubbleCount; i++) {
    pos[i * 3 + 1] += 0.01 + Math.random() * 0.005;
    if (pos[i * 3 + 1] > 25) pos[i * 3 + 1] = -5;
    pos[i * 3] += Math.sin(t + i) * 0.002;
  }
  bubbles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this creates:**

- **Procedural dolphin** built from spheres, cones, cylinders, and extruded shapes — body, head, snout, eyes, tail stock, flukes, dorsal fin, and pectoral fins
- **PBR materials** with subtle blue-grey coloring and metallic sheen
- **Underwater atmosphere** — dark blue fog, light rays, rising bubble particles, and a dark ocean floor
- **Swimming animation** — gentle bobbing, tail wagging, and a slow circular patrol
- **OrbitControls** — drag to rotate, scroll to zoom
- **Responsive** — handles window resizing

Just save it as `index.html` and open in any modern browser. No build step or server required.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Donkey</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.Fog(0x87CEEB, 30, 80);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 5, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;

// ── Lighting ──
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.5);
sun.position.set(10, 15, 8);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 40;
sun.shadow.camera.left = -15;
sun.shadow.camera.right = 15;
sun.shadow.camera.top = 15;
sun.shadow.camera.bottom = -15;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8888ff, 0.3);
fill.position.set(-5, 3, -5);
scene.add(fill);

// ── Materials ──
const fur = new THREE.MeshStandardMaterial({ color: 0x8B8682, roughness: 0.9 });
const darkFur = new THREE.MeshStandardMaterial({ color: 0x5C5652, roughness: 0.9 });
const darkNose = new THREE.MeshStandardMaterial({ color: 0x3A3532, roughness: 0.8 });
const earInner = new THREE.MeshStandardMaterial({ color: 0xC4A882, roughness: 0.8 });
const hoof = new THREE.MeshStandardMaterial({ color: 0x2C2520, roughness: 0.6 });
const eyeWhite = new THREE.MeshStandardMaterial({ color: 0xF5F5F0, roughness: 0.3 });
const eyePupil = new THREE.MeshStandardMaterial({ color: 0x1A1208, roughness: 0.2 });
const eyeHighlight = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.1 });

// ── Donkey Group ──
const donkey = new THREE.Group();

// Body
const body = new THREE.Mesh(new THREE.BoxGeometry(2.4, 1.6, 1.2), fur);
body.position.set(0, 2.8, 0);
body.castShadow = true;
donkey.add(body);

// Chest (slightly wider front)
const chest = new THREE.Mesh(new THREE.BoxGeometry(0.6, 1.7, 1.3), fur);
chest.position.set(1.1, 2.8, 0);
chest.castShadow = true;
donkey.add(chest);

// Rump
const rump = new THREE.Mesh(new THREE.BoxGeometry(0.5, 1.8, 1.1), fur);
rump.position.set(-1.0, 2.9, 0);
rump.castShadow = true;
donkey.add(rump);

// Belly
const belly = new THREE.Mesh(new THREE.BoxGeometry(2.0, 0.8, 1.0), darkFur);
belly.position.set(0, 2.0, 0);
donkey.add(belly);

// ── Legs ──
function createLeg(x, z, scale = 1) {
  const leg = new THREE.Group();
  const upper = new THREE.Mesh(new THREE.CylinderGeometry(0.2, 0.18, 1.2, 8), fur);
  upper.position.y = 0.6;
  upper.castShadow = true;
  leg.add(upper);

  const lower = new THREE.Mesh(new THREE.CylinderGeometry(0.16, 0.14, 0.8, 8), darkFur);
  lower.position.y = 0;
  lower.castShadow = true;
  leg.add(lower);

  const h = new THREE.Mesh(new THREE.CylinderGeometry(0.17, 0.18, 0.25, 8), hoof);
  h.position.y = -0.45;
  leg.add(h);

  leg.position.set(x, 1.6, z);
  leg.scale.setScalar(scale);
  return leg;
}

donkey.add(createLeg(0.9, 0.35));
donkey.add(createLeg(0.9, -0.35));
donkey.add(createLeg(-0.9, 0.35, 1.02));
donkey.add(createLeg(-0.9, -0.35, 1.02));

// ── Neck ──
const neck = new THREE.Group();
const neckBody = new THREE.Mesh(new THREE.CylinderGeometry(0.4, 0.55, 1.6, 8), fur);
neckBody.castShadow = true;
neck.add(neckBody);
neck.position.set(1.3, 3.6, 0);
neck.rotation.z = Math.PI / 5;
donkey.add(neck);

// ── Head ──
const head = new THREE.Group();

// Main head
const headMain = new THREE.Mesh(new THREE.BoxGeometry(1.2, 0.7, 0.65), fur);
headMain.castShadow = true;
head.add(headMain);

// Snout
const snout = new THREE.Mesh(new THREE.BoxGeometry(0.6, 0.55, 0.55), darkFur);
snout.position.set(0.7, -0.1, 0);
head.add(snout);

// Nose
const nose = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.35, 0.45), darkNose);
nose.position.set(1.0, -0.1, 0);
head.add(nose);

// Nostrils
const nostrilGeo = new THREE.SphereGeometry(0.06, 8, 8);
const nostrilL = new THREE.Mesh(nostrilGeo, darkNose);
nostrilL.position.set(1.05, -0.05, 0.15);
head.add(nostrilL);
const nostrilR = new THREE.Mesh(nostrilGeo, darkNose);
nostrilR.position.set(1.05, -0.05, -0.15);
head.add(nostrilR);

// Mouth line
const mouthGeo = new THREE.BoxGeometry(0.02, 0.2, 0.3);
const mouth = new THREE.Mesh(mouthGeo, darkNose);
mouth.position.set(1.02, -0.15, 0);
head.add(mouth);

// Eyes
function createEye(z) {
  const eye = new THREE.Group();
  const white = new THREE.Mesh(new THREE.SphereGeometry(0.13, 12, 12), eyeWhite);
  eye.add(white);
  const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.08, 12, 12), eyePupil);
  pupil.position.set(0.06, 0, 0.1);
  eye.add(pupil);
  const highlight = new THREE.Mesh(new THREE.SphereGeometry(0.03, 8, 8), eyeHighlight);
  highlight.position.set(0.08, 0.04, 0.12);
  eye.add(highlight);
  // Eyelid line
  const lid = new THREE.Mesh(new THREE.BoxGeometry(0.25, 0.03, 0.02), darkNose);
  lid.position.set(0, 0.1, 0.12);
  eye.add(lid);
  eye.position.set(0.2, 0.22, z);
  return eye;
}
head.add(createEye(0.35));
head.add(createEye(-0.35));

// ── Long Ears (the donkey signature!) ──
function createEar(z, angle) {
  const ear = new THREE.Group();
  const outer = new THREE.Mesh(new THREE.BoxGeometry(0.12, 0.9, 0.08), fur);
  outer.castShadow = true;
  ear.add(outer);
  const inner = new THREE.Mesh(new THREE.BoxGeometry(0.06, 0.7, 0.04), earInner);
  inner.position.z = z > 0 ? 0.02 : -0.02;
  ear.add(inner);
  // Ear tip (slightly darker)
  const tip = new THREE.Mesh(new THREE.BoxGeometry(0.1, 0.15, 0.08), darkFur);
  tip.position.y = 0.5;
  ear.add(tip);
  ear.position.set(0.05, 0.55, z);
  ear.rotation.z = angle;
  return ear;
}
head.add(createEar(0.35, -0.15));
head.add(createEar(-0.35, 0.15));

// Mane
for (let i = 0; i < 8; i++) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(0.05, 0.35, 0.1), darkFur);
  m.position.set(1.0 - i * 0.15, 0.42 + i * 0.03, 0);
  m.rotation.z = 0.2;
  head.add(m);
}

head.position.set(1.8, 4.2, 0);
head.rotation.z = -0.1;
donkey.add(head);

// ── Tail ──
const tail = new THREE.Group();
const tailStick = new THREE.Mesh(new THREE.CylinderGeometry(0.03, 0.04, 0.6, 6), fur);
tailStick.position.y = 0.3;
tail.add(tailStick);
const tuft = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.04, 0.4, 8), darkFur);
tuft.position.y = 0.6;
tail.add(tuft);
const tuftTip = new THREE.Mesh(new THREE.SphereGeometry(0.1, 8, 8), darkFur);
tuftTip.position.y = 0.8;
tail.add(tuftTip);
tail.position.set(-1.2, 3.5, 0);
tail.rotation.z = Math.PI / 3;
donkey.add(tail);

// ── Saddle ──
const saddle = new THREE.Mesh(new THREE.BoxGeometry(1.0, 0.15, 1.0), new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.8 }));
saddle.position.set(0, 3.65, 0);
saddle.castShadow = true;
donkey.add(saddle);

const saddlePad = new THREE.Mesh(new THREE.BoxGeometry(1.1, 0.1, 1.1), new THREE.MeshStandardMaterial({ color: 0xCC3333, roughness: 0.7 }));
saddlePad.position.set(0, 3.57, 0);
donkey.add(saddlePad);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(60, 60),
  new THREE.MeshStandardMaterial({ color: 0x4A7C3F, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt path
const path = new THREE.Mesh(
  new THREE.PlaneGeometry(4, 60),
  new THREE.MeshStandardMaterial({ color: 0x9B8B6B, roughness: 1 })
);
path.rotation.x = -Math.PI / 2;
path.position.y = 0.01;
path.receiveShadow = true;
scene.add(path);

// Simple fence posts
for (let i = -4; i <= 4; i++) {
  for (let side of [-3, 3]) {
    const post = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.1, 1.2, 6),
      new THREE.MeshStandardMaterial({ color: 0x8B7355 }));
    post.position.set(i * 2.5, 0.6, side);
    post.castShadow = true;
    scene.add(post);
  }
}

scene.add(donkey);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle breathing
  body.scale.y = 1 + Math.sin(t * 1.5) * 0.01;
  body.position.y = 2.8 + Math.sin(t * 1.5) * 0.02;

  // Ear twitch
  head.children.forEach((child, i) => {
    if (i >= 8 && i <= 9) { // ear indices
      child.rotation.z = (i === 8 ? -0.15 : 0.15) + Math.sin(t * 3 + i) * 0.05;
    }
  });

  // Tail swish
  tail.rotation.x = Math.sin(t * 2) * 0.2;
  tail.rotation.z = Math.PI / 3 + Math.sin(t * 1.8) * 0.15;

  // Subtle head bob
  head.rotation.x = Math.sin(t * 0.8) * 0.02;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single-file scene features:

- **A donkey** built from primitive geometries — body, chest, rump, neck, head with long ears (the signature donkey trait), snout, eyes, mane, tail, and legs with hooves
- **A saddle** with a red pad for character
- **Animations** — gentle breathing, ear twitching, tail swishing, and subtle head bobbing
- **Environment** — green ground, dirt path, fence posts, sky-blue background with fog
- **Lighting** — directional sunlight with soft shadows, ambient fill, and a blue fill light
- **OrbitControls** — click and drag to rotate, scroll to zoom

