document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 1.2, 0);
controls.minDistance = 2;
controls.maxDistance = 15;
controls.maxPolarAngle = Math.PI / 2 + 0.1;

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.8);
dirLight.position.set(4, 6, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(2048, 2048);
dirLight.shadow.camera.near = 0.5;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -6;
dirLight.shadow.camera.right = 6;
dirLight.shadow.camera.top = 6;
dirLight.shadow.camera.bottom = -2;
dirLight.shadow.bias = -0.001;
scene.add(dirLight);

const fillLight = new THREE.PointLight(0x4488ff, 0.5, 10);
fillLight.position.set(-3, 3, -2);
scene.add(fillLight);

const warmLight = new THREE.PointLight(0xffaa44, 0.4, 6);
warmLight.position.set(0, 2.8, 0.6);
scene.add(warmLight);

// ── Materials ──
const wallMat = new THREE.MeshStandardMaterial({
  color: 0xd4c8b8, roughness: 0.85, metalness: 0.05
});

const floorMat = new THREE.MeshStandardMaterial({
  color: 0x8b7355, roughness: 0.7, metalness: 0.1
});

