);
floor.rotation.x = -Math.PI / 2;
floor.receiveShadow = true;
scene.add(floor);

// Floor pattern lines
const gridHelper = new THREE.GridHelper(20, 40, 0x6b5b45, 0x6b5b45);
gridHelper.position.y = 0.005;
gridHelper.material.opacity = 0.15;
gridHelper.material.transparent = true;
scene.add(gridHelper);

// ── Wall ──
const wallGroup = new THREE.Group();
scene.add(wallGroup);

// Wall dimensions
const wallW = 8, wallH = 3.5, wallD = 0.3;
const doorW = 1.4, doorH = 2.6;
const frameDepth = 0.35, frameOverhang = 0.08;

// Left wall section
const leftWallW = (wallW - doorW) / 2;
const leftWall = new THREE.Mesh(
  new THREE.BoxGeometry(leftWallW, wallH, wallD),
  wallMat
);
leftWall.position.set(-doorW / 2 - leftWallW / 2, wallH / 2, 0);
leftWall.castShadow = true;
leftWall.receiveShadow = true;
wallGroup.add(leftWall);

// Right wall section
const rightWall = new THREE.Mesh(
  new THREE.BoxGeometry(leftWallW, wallH, wallD),
