);
topWall.position.set(0, doorH + topWallH / 2, 0);
topWall.castShadow = true;
topWall.receiveShadow = true;
wallGroup.add(topWall);

// ── Door Frame ──
const frameGroup = new THREE.Group();
wallGroup.add(frameGroup);

// Left jamb
const leftJamb = new THREE.Mesh(
  new THREE.BoxGeometry(frameOverhang * 2, doorH, frameDepth),
  frameMat
);
leftJamb.position.set(-doorW / 2 - frameOverhang, doorH / 2, 0);
leftJamb.castShadow = true;
frameGroup.add(leftJamb);

// Right jamb
