  new THREE.BoxGeometry(frameOverhang * 2, doorH, frameDepth),
  frameMat
);
rightJamb.position.set(doorW / 2 + frameOverhang, doorH / 2, 0);
rightJamb.castShadow = true;
frameGroup.add(rightJamb);

