  new THREE.BoxGeometry(doorW + frameOverhang * 2, frameOverhang * 2, frameDepth),
  frameMat
);
header.position.set(0, doorH + frameOverhang, 0);
header.castShadow = true;
frameGroup.add(header);

// Sill
const sill = new THREE.Mesh(
  new THREE.BoxGeometry(doorW + frameOverhang * 4, 0.06, frameDepth + 0.15),
  frameMat
);
sill.position.set(0, 0.03, 0.05);
sill.castShadow = true;
sill.receiveShadow = true;
frameGroup.add(sill);

