// ── Materials ──
const woodMat = new THREE.MeshStandardMaterial({
  color: 0x8B6914, roughness: 0.6, metalness: 0.05
});
const woodDark = new THREE.MeshStandardMaterial({
  color: 0x5C4410, roughness: 0.7, metalness: 0.05
});
const drawerFrontMat = new THREE.MeshStandardMaterial({
  color: 0xA07820, roughness: 0.45, metalness: 0.08
});
const handleMat = new THREE.MeshStandardMaterial({
  color: 0xC0C0C0, roughness: 0.15, metalness: 0.9
});
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e, roughness: 0.85, metalness: 0.1
});
const innerMat = new THREE.MeshStandardMaterial({
  color: 0x3a2a10, roughness: 0.9, metalness: 0.0
});

// ── Helper ──
function box(w, h, d, mat, x, y, z, castShadow = true) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat);
  m.position.set(x, y, z);
  m.castShadow = castShadow;
  m.receiveShadow = true;
  return m;
}

// ── Floor ──
const floor = new THREE.Mesh(
  new THREE.PlaneGeometry(20, 20),
  floorMat
);
floor.rotation.x = -Math.PI / 2;
floor.receiveShadow = true;
scene.add(floor);

// ── Cabinet Group ──
const cabinet = new THREE.Group();
scene.add(cabinet);

// Back panel
cabinet.add(box(2.4, 1.6, 0.06, woodDark, 0, 0.8, -0.57));

// Left panel
cabinet.add(box(0.06, 1.6, 1.14, woodDark, -1.17, 0.8, 0));

// Right panel
cabinet.add(box(0.06, 1.6, 1.14, woodDark, 1.17, 0.8, 0));

// Bottom panel
cabinet.add(box(2.34, 0.06, 1.14, woodDark, 0, 0.03, 0));

// Top panel
cabinet.add(box(2.46, 0.06, 1.2, woodDark, 0, 1.63, 0));

// Middle shelf (between drawers)
cabinet.add(box(2.28, 0.04, 1.08, woodDark, 0, 0.82, 0));

// Top rail
cabinet.add(box(2.4, 0.1, 0.06, woodMat, 0, 1.57, 0.54));

// ── Drawer 1 (bottom) ──
const drawer1 = new THREE.Group();
drawer1.position.set(0, 0.44, 0);
cabinet.add(drawer1);

// Drawer box sides
const d1h = 0.38, d1w = 2.28, d1d = 1.08;
drawer1.add(box(d1w, d1h, 0.05, innerMat, 0, 0, -d1d / 2 + 0.025));
drawer1.add(box(0.05, d1h, d1d, innerMat, -d1w / 2 + 0.025, 0, 0));
drawer1.add(box(0.05, d1h, d1d, innerMat, d1w / 2 - 0.025, 0, 0));
drawer1.add(box(d1w, 0.04, d1d, innerMat, 0, -d1h / 2 + 0.02, 0));

// Drawer front face
