/* ── Rear vent lines on body ──────────────────────────────── */
for (let i = 0; i < 5; i++) {
  const ventGeo = new THREE.BoxGeometry(0.02, 0.25, 0.01);
  const vent = new THREE.Mesh(ventGeo, matBody);
  vent.position.set(-0.1 + i * 0.06, 1.15, 0.33);
  drill.add(vent);
}

/* ── Side label / logo plate ──────────────────────────────── */
const plateGeo = new THREE.BoxGeometry(0.35, 0.15, 0.005);
const plate = new THREE.Mesh(plateGeo, matAccent);
plate.position.set(0.1, 1.15, 0.33);
drill.add(plate);

/* ── Position the whole drill ─────────────────────────────── */
drill.rotation.y = -0.3;
drill.rotation.x = 0.05;
scene.add(drill);

/* ── Ground plane ─────────────────────────────────────────── */
const groundGeo = new THREE.CircleGeometry(6, 48);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* ── Grid helper (subtle) ─────────────────────────────────── */
const grid = new THREE.GridHelper(12, 24, 0x222244, 0x1a1a33);
grid.position.y = 0.005;
scene.add(grid);

/* ── Animation ────────────────────────────────────────────── */
let time = 0;

function animate() {
  requestAnimationFrame(animate);
  time += 0.016;

  /* Spin the drill bit */
  bitGroup.rotation.x += 0.3;

  /* Subtle idle hover */
  drill.position.y = Math.sin(time * 1.2) * 0.03;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ───────────────────────────────────────────────── */
window.addEventListener('resize', () => {
