  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0, 0);

// ── Materials ──
const handleMat = new THREE.MeshStandardMaterial({
  color: 0x888899, metalness: 0.9, roughness: 0.2
});
const plateMat = new THREE.MeshStandardMaterial({
  color: 0x222233, metalness: 0.7, roughness: 0.35
});
const ridgeMat = new THREE.MeshStandardMaterial({
  color: 0x333344, metalness: 0.6, roughness: 0.4
});
const endCapMat = new THREE.MeshStandardMaterial({
  color: 0x444455, metalness: 0.8, roughness: 0.25
});
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x111122, metalness: 0.1, roughness: 0.8
});

// ── Build Dumbbell ──
const dumbbell = new THREE.Group();

// Handle
const handleGeo = new THREE.CylinderGeometry(0.12, 0.12, 3.0, 24);
const handle = new THREE.Mesh(handleGeo, handleMat);
handle.rotation.z = Math.PI / 2;
handle.castShadow = true;
dumbbell.add(handle);

// Knurled grip rings on handle
for (let i = 0; i < 12; i++) {
  const t = (i / 11 - 0.5) * 1.6;
  const ringGeo = new THREE.TorusGeometry(0.13, 0.015, 8, 16);
  const ring = new THREE.Mesh(ringGeo, ridgeMat);
  ring.position.x = t;
  ring.rotation.y = Math.PI / 2;
  ring.castShadow = true;
  dumbbell.add(ring);
}

// Weight plates per side
const plateConfigs = [
  { radius: 0.7, thickness: 0.18, offset: 0.9, count: 2 },
  { radius: 0.55, thickness: 0.22, offset: 1.2, count: 1 },
  { radius: 0.4, thickness: 0.15, offset: 1.45, count: 1 },
];

function addPlates(side) {
  const sign = side === 'left' ? -1 : 1;
  plateConfigs.forEach(cfg => {
    for (let i = 0; i < cfg.count; i++) {
      const plateGeo = new THREE.CylinderGeometry(cfg.radius, cfg.radius, cfg.thickness, 32);
      const plate = new THREE.Mesh(plateGeo, plateMat);
      plate.rotation.z = Math.PI / 2;
      plate.position.x = sign * (cfg.offset + i * 0.02);
      plate.castShadow = true;
      plate.receiveShadow = true;
      dumbbell.add(plate);

      // Outer ridge on each plate
      const ridgeGeo = new THREE.TorusGeometry(cfg.radius - 0.02, 0.02, 8, 32);
      const ridge = new THREE.Mesh(ridgeGeo, ridgeMat);
      ridge.position.x = plate.position.x;
      ridge.rotation.y = Math.PI / 2;
      dumbbell.add(ridge);
    }
  });

  // End cap
  const capGeo = new THREE.CylinderGeometry(0.25, 0.18, 0.12, 24);
  const cap = new THREE.Mesh(capGeo, endCapMat);
  cap.rotation.z = Math.PI / 2;
  cap.position.x = sign * 1.7;
  cap.castShadow = true;
  dumbbell.add(cap);

  // Center hole ring on end cap
  const holeGeo = new THREE.TorusGeometry(0.14, 0.02, 8, 16);
  const hole = new THREE.Mesh(holeGeo, ridgeMat);
  hole.position.x = cap.position.x;
  hole.rotation.y = Math.PI / 2;
  dumbbell.add(hole);
}

addPlates('left');
addPlates('right');

// Center label ring
const labelGeo = new THREE.TorusGeometry(0.14, 0.025, 8, 16);
const label = new THREE.Mesh(labelGeo, endCapMat);
label.rotation.y = Math.PI / 2;
dumbbell.add(label);

dumbbell.rotation.x = -Math.PI / 6;
dumbbell.rotation.z = Math.PI / 12;
scene.add(dumbbell);

// ── Floor ──
const floorGeo = new THREE.CircleGeometry(8, 64);
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -1.5;
floor.receiveShadow = true;
scene.add(floor);

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 4);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 1;
keyLight.shadow.camera.far = 20;
keyLight.shadow.camera.left = -5;
keyLight.shadow.camera.right = 5;
keyLight.shadow.camera.top = 5;
keyLight.shadow.camera.bottom = -5;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6644, 1.5, 15);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

// ── Animation ──
function animate(time) {
  requestAnimationFrame(animate);
  dumbbell.rotation.y = Math.sin(time * 0.0005) * 0.3;
  dumbbell.position.y = Math.sin(time * 0.001) * 0.15;
  controls.update();
  renderer.render(scene, camera);
}
animate(0);

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
