    scene.add(fill);

    // ── Materials ──────────────────────────────────────
    const bodyMat   = new THREE.MeshStandardMaterial({ color: 0xF5E6A3, roughness: 0.6, metalness: 0.0 });
    const headMat   = new THREE.MeshStandardMaterial({ color: 0xF5E6A3, roughness: 0.5, metalness: 0.0 });
    const beakMat   = new THREE.MeshStandardMaterial({ color: 0xE8850C, roughness: 0.4, metalness: 0.0 });
    const wingMat   = new THREE.MeshStandardMaterial({ color: 0xD4C478, roughness: 0.6, metalness: 0.0 });
    const tailMat   = new THREE.MeshStandardMaterial({ color: 0xC8B86A, roughness: 0.6, metalness: 0.0 });
    const eyeMat    = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.2, metalness: 0.3 });
    const eyeWhite  = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.3 });
    const footMat   = new THREE.MeshStandardMaterial({ color: 0xE8850C, roughness: 0.5, metalness: 0.0 });
    const cheekMat  = new THREE.MeshStandardMaterial({ color: 0xE8A050, roughness: 0.5, transparent: true, opacity: 0.35 });

    // ── Duck Group ─────────────────────────────────────
    const duck = new THREE.Group();

    // Body — egg shape
    const bodyGeo = new THREE.SphereGeometry(1.6, 32, 32);
    const body = new THREE.Mesh(bodyGeo, bodyMat);
    body.scale.set(1, 0.85, 1.25);
    body.position.set(0, 2.0, 0);
    body.castShadow = true;
    duck.add(body);

    // Head
    const headGeo = new THREE.SphereGeometry(0.85, 32, 32);
    const head = new THREE.Mesh(headGeo, headMat);
    head.position.set(0, 3.4, 1.2);
    head.castShadow = true;
    duck.add(head);

    // Crown (slight bump on top of head)
    const crownGeo = new THREE.SphereGeometry(0.55, 24, 24);
    const crown = new THREE.Mesh(crownGeo, headMat);
    crown.position.set(0, 4.0, 1.0);
    crown.scale.set(1, 0.7, 0.9);
    crown.castShadow = true;
    duck.add(crown);

    // Beak
    const beakGeo = new THREE.ConeGeometry(0.35, 0.9, 24);
    const beak = new THREE.Mesh(beakGeo, beakMat);
    beak.rotation.x = Math.PI / 2;
    beak.position.set(0, 3.2, 2.2);
    beak.castShadow = true;
    duck.add(beak);

    // Beak bottom (slightly smaller, lower)
    const beakBotGeo = new THREE.ConeGeometry(0.25, 0.7, 24);
    const beakBot = new THREE.Mesh(beakBotGeo, beakMat);
    beakBot.rotation.x = Math.PI / 2;
    beakBot.position.set(0, 3.05, 2.25);
    duck.add(beakBot);

    // Eyes
    const eyeWhiteGeo = new THREE.SphereGeometry(0.18, 16, 16);
    const eyePupilGeo = new THREE.SphereGeometry(0.1, 16, 16);

    [-1, 1].forEach(side => {
      const ew = new THREE.Mesh(eyeWhiteGeo, eyeWhite);
      ew.position.set(side * 0.45, 3.55, 1.9);
      duck.add(ew);

      const ep = new THREE.Mesh(eyePupilGeo, eyeMat);
      ep.position.set(side * 0.45, 3.55, 2.05);
      duck.add(ep);
    });

    // Cheeks
    [-1, 1].forEach(side => {
      const cheekGeo = new THREE.SphereGeometry(0.25, 16, 16);
      const cheek = new THREE.Mesh(cheekGeo, cheekMat);
      cheek.position.set(side * 0.65, 3.2, 1.7);
      cheek.scale.set(1, 0.8, 0.6);
      duck.add(cheek);
    });

    // Wings
    [-1, 1].forEach(side => {
      const wingGeo = new THREE.SphereGeometry(1.0, 24, 24);
      const wing = new THREE.Mesh(wingGeo, wingMat);
      wing.scale.set(0.3, 0.7, 1.1);
      wing.position.set(side * 1.3, 2.3, 0.2);
      wing.rotation.z = side * -0.2;
      wing.castShadow = true;
      wing.userData.side = side;
      duck.add(wing);
    });

    // Tail feathers
    const tailGroup = new THREE.Group();
    for (let i = -1; i <= 1; i++) {
      const featherGeo = new THREE.ConeGeometry(0.15, 0.8, 12);
      const feather = new THREE.Mesh(featherGeo, tailMat);
      feather.position.set(i * 0.2, 0, 0);
      feather.rotation.x = -0.6;
      feather.castShadow = true;
      tailGroup.add(feather);
    }
    tailGroup.position.set(0, 2.6, -1.6);
    tailGroup.rotation.x = -0.3;
    duck.add(tailGroup);

    // Feet
    [-1, 1].forEach(side => {
      const footGroup = new THREE.Group();

      const footPadGeo = new THREE.SphereGeometry(0.35, 16, 16);
      const footPad = new THREE.Mesh(footPadGeo, footMat);
      footPad.scale.set(1.4, 0.3, 0.8);
      footGroup.add(footPad);

      // Toes
      for (let t = -1; t <= 1; t++) {
        const toeGeo = new THREE.ConeGeometry(0.08, 0.4, 8);
        const toe = new THREE.Mesh(toeGeo, footMat);
        toe.position.set(t * 0.22, 0, 0.35);
        toe.rotation.x = -0.3;
        footGroup.add(toe);
      }

      footGroup.position.set(side * 0.6, 0.7, 0.5);
      footGroup.castShadow = true;
      duck.add(footGroup);
    });

    // Neck connector (smooth blend between body and head)
    const neckGeo = new THREE.SphereGeometry(0.75, 24, 24);
    const neck = new THREE.Mesh(neckGeo, bodyMat);
    neck.position.set(0, 2.9, 1.0);
    neck.scale.set(0.85, 0.7, 0.9);
    duck.add(neck);

    scene.add(duck);

    // ── Water Plane ────────────────────────────────────
    const waterGeo = new THREE.PlaneGeometry(100, 100, 80, 80);
    const waterMat = new THREE.MeshStandardMaterial({
      color: 0x3a9e8f,
      roughness: 0.1,
      metalness: 0.3,
      transparent: true,
      opacity: 0.75,
    });
    const water = new THREE.Mesh(waterGeo, waterMat);
    water.rotation.x = -Math.PI / 2;
    water.position.y = -0.2;
    water.receiveShadow = true;
    scene.add(water);

    // ── Simple floating lily pads ──────────────────────
    function makeLilyPad(x, z, scale, rot) {
      const shape = new THREE.Shape();
      const r = 0.6;
      shape.absarc(0, 0, r, 0.3, Math.PI * 2 - 0.3, false);
      shape.lineTo(0, 0);
      const geo = new THREE.ShapeGeometry(shape);
      const mat = new THREE.MeshStandardMaterial({
        color: 0x4a8c5c, roughness: 0.7, side: THREE.DoubleSide
      });
      const mesh = new THREE.Mesh(geo, mat);
      mesh.rotation.x = -Math.PI / 2;
      mesh.position.set(x, 0.01, z);
      mesh.rotation.z = rot;
      mesh.scale.setScalar(scale);
      mesh.receiveShadow = true;
      scene.add(mesh);
    }

    makeLilyPad(-3, 2, 1.2, 0.5);
    makeLilyPad(3.5, -1, 0.9, -0.3);
    makeLilyPad(-2, -3, 1.0, 1.2);
    makeLilyPad(4, 3, 0.7, 0.8);
    makeLilyPad(-5, -1, 1.1, -0.6);

    // ── Animation ──────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle bob
      duck.position.y = Math.sin(t * 1.2) * 0.15;
      duck.rotation.z = Math.sin(t * 0.8) * 0.02;
      duck.rotation.x = Math.sin(t * 0.6) * 0.015;

      // Head tilt
      head.rotation.z = Math.sin(t * 1.5) * 0.04;
      head.rotation.x = Math.sin(t * 0.9) * 0.03;
      crown.rotation.copy(head.rotation);
      beak.rotation.z = Math.sin(t * 1.5) * 0.04;
      beakBot.rotation.z = Math.sin(t * 1.5) * 0.04;

      // Wing flap (subtle)
      duck.children.forEach(child => {
        if (child.userData.side) {
          child.rotation.z = child.userData.side * (-0.2 + Math.sin(t * 2.0 + child.userData.side) * 0.08);
        }
      });

      // Tail wag
      tailGroup.rotation.z = Math.sin(t * 1.8) * 0.06;

      // Water ripple
      const pos = waterGeo.attributes.position;
      for (let i = 0; i < pos.count; i++) {
        const x = pos.getX(i);
        const y = pos.getY(i);
        pos.setZ(i, Math.sin(x * 0.5 + t * 1.5) * 0.06 + Math.cos(y * 0.4 + t * 1.2) * 0.05);
      }
      pos.needsUpdate = true;
      waterGeo.computeVertexNormals();

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ─────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's in this demo

| Feature | Details |
|---|---|
| **Duck body** | Built from ~15 primitives — spheres, cones, and shapes merged into groups |
| **Anatomy** | Body, head, crown, beak (top + bottom), eyes (white + pupil), cheeks, wings, tail feathers, neck blend, and webbed feet with toes

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Egg</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #1a1a2e; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
        "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

    // ── Camera ──
    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 5);

    // ── Renderer ──
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.target.set(0, 0.8, 0);

    // ── Lighting ──
    const ambientLight = new THREE.HemisphereLight(0xffeedd, 0x332244, 0.6);
    scene.add(ambientLight);

    const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    keyLight.position.set(5, 8, 4);
    keyLight.castShadow = true;
    keyLight.shadow.mapSize.set(1024, 1024);
    keyLight.shadow.camera.near = 1;
    keyLight.shadow.camera.far = 20;
    keyLight.shadow.camera.left = -5;
    keyLight.shadow.camera.right = 5;
    keyLight.shadow.camera.top = 5;
    keyLight.shadow.camera.bottom = -5;
    keyLight.shadow.bias = -0.001;
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0x8888ff, 0.8);
    fillLight.position.set(-4, 3, -3);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xff6644, 1.5, 15);
    rimLight.position.set(-3, 4, -4);
    scene.add(rimLight);

    // ── Egg Geometry (Lathe) ──
    function createEggProfile() {
      const points = [];
      const segments = 64;

      // Egg profile using a parametric curve
      // Based on the egg-curve equation: x = cos(t), y = sin(t) * (1 + c*sin(t))
      // Adjusted for a natural egg shape
      for (let i = 0; i <= segments; i++) {
        const t = (i / segments) * Math.PI; // 0 to PI

        // Egg-shaped curve: wider at bottom, narrower at top
        const c = 0.35; // eggness factor
        const x = Math.cos(t);
        const y = Math.sin(t) * (1 + c * Math.sin(t));

        // Map to actual egg dimensions
        // Stretch vertically, scale radius
        const rx = Math.abs(x) * 1.0;
        const ry = y * 1.5 - 0.3; // shift so flat side is at bottom

        points.push(new THREE.Vector2(rx, ry));
      }

      return points;
    }

    const eggProfile = createEggProfile();
    const eggGeometry = new THREE.LatheGeometry(eggProfile, 64);
    eggGeometry.computeVertexNormals();

    // ── Egg Material ──
    const eggMaterial = new THREE.MeshPhysicalMaterial({
      color: 0xfff5e6,
      roughness: 0.25,
      metalness: 0.0,
      clearcoat: 0.3,
      clearcoatRoughness: 0.15,
      reflectivity: 0.5,
      sheen: 0.1,
      sheenColor: new THREE.Color(0xffeedd),
    });

    const egg = new THREE.Mesh(eggGeometry, eggMaterial);
    egg.castShadow = true;
    egg.receiveShadow = true;
    scene.add(egg);

    // ── Ground ──
    const groundGeo = new THREE.CircleGeometry(12, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x2a2a3e,
      roughness: 0.9,
      metalness: 0.1,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.3;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Subtle ring under egg ──
    const ringGeo = new THREE.RingGeometry(0.8, 1.2, 64);
    const ringMat = new THREE.MeshBasicMaterial({
      color: 0x444466,
      transparent: true,
      opacity: 0.3,
      side: THREE.DoubleSide,
    });
    const ring = new THREE.Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = -0.29;
    scene.add(ring);

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Gentle idle rotation
      egg.rotation.y = elapsed * 0.3;

      // Subtle floating bounce
      egg.position.y = Math.sin(elapsed * 0.8) * 0.05;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

**What this gives you:**

- **Egg shape** — Built with `LatheGeometry` from a parametric egg-curve profile (`x = cos t`, `y = sin t · (1 + c·sin t)`) revolved around the Y-axis, giving a natural wider-bottom / narrower-top silhouette
- **Material** — `MeshPhysicalMaterial` with clearcoat and sheen for a subtle ceramic/eggshell look
- **Lighting** — Three-point setup (warm key, cool fill, orange rim) plus hemisphere ambient
- **Shadows** — Soft PCF shadow cast onto a dark ground plane
- **Interaction** — `OrbitControls` with damping (drag to orbit, scroll to zoom)
- **Animation** — Gentle Y-axis rotation + subtle floating bounce
- **Responsive** — Handles window resize

Just save as `index.html` and open in any modern browser.

