}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { mergeGeometries } from 'three/addons/utils/BufferGeometryUtils.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(3, 4, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888cc, 0.8);
fillLight.position.set(-4, 2, 3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffc8a0, 1.5);
rimLight.position.set(0, -2, -4);
scene.add(rimLight);

const spotLight = new THREE.SpotLight(0xffd4b8, 3, 15, Math.PI / 6, 0.5);
spotLight.position.set(2, 3, 4);
scene.add(spotLight);

// ── Materials ──
const skinMat = new THREE.MeshStandardMaterial({
  color: 0xe8b89d,
  roughness: 0.55,
  metalness: 0.02,
  side: THREE.DoubleSide,
});

const darkSkinMat = new THREE.MeshStandardMaterial({
  color: 0xc49078,
  roughness: 0.6,
  metalness: 0.02,
  side: THREE.DoubleSide,
});

const innerMat = new THREE.MeshStandardMaterial({
  color: 0xd4a088,
  roughness: 0.5,
  metalness: 0.02,
  side: THREE.DoubleSide,
});

// ── Ear Construction ──
const earGroup = new THREE.Group();

// Main ear silhouette (extruded 2D shape)
const earShape = new THREE.Shape();
earShape.moveTo(0, 2.0);
earShape.bezierCurveTo(0.6, 2.1, 1.0, 1.8, 1.1, 1.3);
earShape.bezierCurveTo(1.2, 0.9, 1.0, 0.5, 0.8, 0.2);
earShape.bezierCurveTo(0.65, -0.1, 0.6, -0.5, 0.5, -0.9);
earShape.bezierCurveTo(0.45, -1.1, 0.5, -1.4, 0.4, -1.6);
earShape.bezierCurveTo(0.3, -1.8, 0.15, -1.9, 0.0, -1.9);
earShape.bezierCurveTo(-0.15, -1.9, -0.3, -1.8, -0.35, -1.6);
earShape.bezierCurveTo(-0.4, -1.4, -0.35, -1.1, -0.3, -0.8);
earShape.bezierCurveTo(-0.25, -0.5, -0.2, -0.2, -0.15, 0.1);
earShape.bezierCurveTo(-0.1, 0.4, -0.05, 0.8, 0.0, 1.2);
earShape.bezierCurveTo(-0.05, 1.5, -0.1, 1.7, 0.0, 2.0);

const extrudeSettings = { depth: 0.35, bevelEnabled: true, bevelThickness: 0.08, bevelSize: 0.08, bevelSegments: 8 };
const earGeo = new THREE.ExtrudeGeometry(earShape, extrudeSettings);
earGeo.center();
const earMesh = new THREE.Mesh(earGeo, skinMat);
earMesh.castShadow = true;
earMesh.receiveShadow = true;
earGroup.add(earMesh);

// Helix (outer rim) - torus-like curve
const helixPoints = [];
for (let i = 0; i <= 60; i++) {
  const t = i / 60;
  const angle = Math.PI * 0.15 + t * Math.PI * 1.3;
  const r = 0.7 + Math.sin(t * Math.PI) * 0.15;
  const x = r * Math.sin(angle) * 0.7;
  const y = 1.6 - t * 2.8;
  const z = 0.18 + Math.sin(t * Math.PI * 0.5) * 0.08;
  helixPoints.push(new THREE.Vector3(x, y, z));
}
const helixCurve = new THREE.CatmullRomCurve3(helixPoints);
const helixGeo = new THREE.TubeGeometry(helixCurve, 80, 0.06, 12, false);
const helixMesh = new THREE.Mesh(helixGeo, skinMat);
helixMesh.castShadow = true;
earGroup.add(helixMesh);

// Antihelix (inner ridge)
const antiPoints = [];
for (let i = 0; i <= 40; i++) {
  const t = i / 40;
  const angle = Math.PI * 0.3 + t * Math.PI * 0.8;
  const r = 0.45 + Math.sin(t * Math.PI) * 0.1;
  const x = r * Math.sin(angle) * 0.5;
  const y = 1.0 - t * 2.0;
  const z = 0.25 + Math.sin(t * Math.PI) * 0.05;
  antiPoints.push(new THREE.Vector3(x, y, z));
}
const antiCurve = new THREE.CatmullRomCurve3(antiPoints);
const antiGeo = new THREE.TubeGeometry(antiCurve, 60, 0.045, 10, false);
const antiMesh = new THREE.Mesh(antiGeo, darkSkinMat);
antiMesh.castShadow = true;
earGroup.add(antiMesh);

// Antitragus (small bump near earlobe)
const antiTragusGeo = new THREE.SphereGeometry(0.12, 16, 16);
const antiTragus = new THREE.Mesh(antiTragusGeo, darkSkinMat);
antiTragus.position.set(-0.15, -1.3, 0.25);
antiTragus.scale.set(1, 1.2, 0.8);
antiTragus.castShadow = true;
earGroup.add(antiTragus);

// Tragus (flap in front of ear canal)
const tragusGeo = new THREE.SphereGeometry(0.15, 16, 16);
const tragus = new THREE.Mesh(tragusGeo, darkSkinMat);
tragus.position.set(0.0, 0.1, 0.28);
tragus.scale.set(0.7, 1.1, 0.7);
tragus.castShadow = true;
earGroup.add(tragus);

// Earlobe (fleshy bottom)
const lobeGeo = new THREE.SphereGeometry(0.35, 24, 24);
const lobe = new THREE.Mesh(lobeGeo, skinMat);
lobe.position.set(0.0, -1.75, 0.05);
lobe.scale.set(0.8, 0.9, 0.6);
lobe.castShadow = true;
earGroup.add(lobe);

// Concha (bowl area)
const conchaGeo = new THREE.SphereGeometry(0.4, 20, 20);
const concha = new THREE.Mesh(conchaGeo, innerMat);
concha.position.set(0.05, -0.2, 0.15);
concha.scale.set(0.6, 0.7, 0.3);
earGroup.add(concha);

// Ear canal (dark opening)
const canalGeo = new THREE.CircleGeometry(0.12, 20);
const canalMat = new THREE.MeshStandardMaterial({ color: 0x2a1a10, roughness: 0.9 });
const canal = new THREE.Mesh(canalGeo, canalMat);
canal.position.set(0.0, -0.1, 0.38);
earGroup.add(canal);

// Inner ear folds - subtle detail lines
const foldPoints = [
  [new THREE.Vector3(-0.1, 0.5, 0.22), new THREE.Vector3(0.15, 0.0, 0.28), new THREE.Vector3(0.1, -0.5, 0.22)],
  [new THREE.Vector3(-0.05, 0.3, 0.24), new THREE.Vector3(0.2, -0.1, 0.3), new THREE.Vector3(0.05, -0.7, 0.24)],
];
foldPoints.forEach(pts => {
  const curve = new THREE.CatmullRomCurve3(pts);
  const geo = new THREE.TubeGeometry(curve, 30, 0.012, 6, false);
  const mesh = new THREE.Mesh(geo, darkSkinMat);
  earGroup.add(mesh);
});

// Scale and position the whole ear
earGroup.scale.set(1.1, 1.1, 1.1);
earGroup.rotation.y = 0.15;
scene.add(earGroup);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  earGroup.rotation.y = 0.15 + Math.sin(t * 0.3) * 0.08;
  earGroup.rotation.z = Math.sin(t * 0.2) * 0.02;
  earGroup.position.y = Math.sin(t * 0.5) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single `index.html` file creates a **procedurally generated 3D ear** using Three.js with:

- **Extruded silhouette** — a bezier-curve 2D ear profile extruded with bevel for the main body
- **Helix** (outer rim) — a CatmullRom tube tracing the ear's outer curve
- **Antihelix** — inner ridge detail
- **Tragus & Antitragus** — small cartilage bumps near the canal and lobe
- **Earlobe** — rounded bottom
- **Concha** — the bowl-shaped depression
- **Ear canal** — dark circular opening
- **Inner fold lines** — subtle crease details

