const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.y = 0;
body.castShadow = true;
body.receiveShadow = true;
envelope.add(body);

// ── Back panel (slightly larger to show depth) ──
const backGeo = new THREE.BoxGeometry(W + 0.02, H + 0.02, D * 0.5);
const back = new THREE.Mesh(backGeo, backMat);
back.position.z = -D * 0.75;
envelope.add(back);

// ── Triangular flap ──
function createFlapGeometry() {
  const geo = new THREE.BufferGeometry();
  // Triangle: base along top edge, tip pointing down
  const hw = W / 2;
  const tipY = H / 2 - 0.9;
  const vertices = new Float32Array([
    // Front face
    -hw,  H / 2,  D * 0.5,
     hw,  H / 2,  D * 0.5,
     0,   tipY,   D * 0.5,
    // Back face
    -hw,  H / 2, -D * 0.5,
     hw,  H / 2, -D * 0.5,
     0,   tipY,  -D * 0.5,
  ]);

  const indices = [
    // Front
    0, 1, 2,
    // Back
    3, 5, 4,
    // Left side
    0, 3, 2, 2, 3, 5,
    // Right side
    1, 2, 4, 4, 2, 5,
    // Top edge (thin strip)
    0, 4, 1, 1, 4, 3,
  ];

  geo.setAttribute('position', new THREE.BufferAttribute(vertices, 3));
  geo.setIndex(indices);
  geo.computeVertexNormals();
  return geo;
}

const flapGeo = createFlapGeometry();
const flap = new THREE.Mesh(flapGeo, flapMat);
flap.castShadow = true;
envelope.add(flap);

// ── Wax seal ──
const sealGeo = new THREE.CylinderGeometry(0.18, 0.18, 0.06, 24);
const seal = new THREE.Mesh(sealGeo, sealMat);
