<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js" } }
</script>
<script type="module">
import * as THREE from 'three';

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.z = 5;

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

// --- Sclera (white) ---
const sclera = new THREE.Mesh(
  new THREE.SphereGeometry(1, 64, 64),
  new THREE.MeshStandardMaterial({ color: 0xf5f0eb, roughness: 0.6, metalness: 0 })
);
scene.add(sclera);

// --- Iris ---
const irisGroup = new THREE.Group();

const iris = new THREE.Mesh(
  new THREE.CircleGeometry(0.42, 64),
  new THREE.MeshStandardMaterial({ color: 0x3b82b8, roughness: 0.3, metalness: 0.1 })
);
irisGroup.add(iris);

// Iris ring detail
const irisRing = new THREE.Mesh(
  new THREE.RingGeometry(0.32, 0.42, 64),
  new THREE.MeshStandardMaterial({ color: 0x2a6a99, roughness: 0.4, metalness: 0.2 })
);
irisGroup.add(irisRing);

// --- Pupil ---
const pupil = new THREE.Mesh(
  new THREE.CircleGeometry(0.16, 32),
  new THREE.MeshStandardMaterial({ color: 0x050505, roughness: 0.1, metalness: 0.3 })
);
pupil.position.z = 0.01;
irisGroup.add(pupil);

irisGroup.position.z = 0.98;
scene.add(irisGroup);

// --- Light reflection (specular highlight) ---
const highlight = new THREE.Mesh(
  new THREE.CircleGeometry(0.06, 16),
  new THREE.MeshBasicMaterial({ color: 0xffffff })
);
highlight.position.set(0.12, 0.12, 0.995);
scene.add(highlight);

// --- Lighting ---
scene.add(new THREE.AmbientLight(0xffffff, 0.6));
const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
dirLight.position.set(2, 3, 4);
scene.add(dirLight);

// --- Eye tracking ---
const mouse = new THREE.Vector2();
const target = new THREE.Vector2();

window.addEventListener('mousemove', (e) => {
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
});

// --- Animate ---
function animate() {
  requestAnimationFrame(animate);

  // Smoothly interpolate iris position toward mouse
  target.set(mouse.x * 0.35, mouse.y * 0.35);
  irisGroup.position.x += (target.x - irisGroup.position.x) * 0.08;
  irisGroup.position.y += (target.y - irisGroup.position.y) * 0.08;

  // Slight squash/stretch based on movement
  const dx = irisGroup.position.x;
  const dy = irisGroup.position.y;
  irisGroup.scale.set(1 - Math.abs(dx) * 0.1, 1 - Math.abs(dy) * 0.1, 1);

  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
