controls.dampingFactor = 0.05;

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(3, 4, 5);
scene.add(key);

const fill = new THREE.DirectionalLight(0x8888ff, 0.8);
fill.position.set(-4, -2, -3);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffffff, 1.5);
rim.position.set(0, -3, -5);
scene.add(rim);

// ── Feather Geometry Builder ──
function createFeatherGeometry() {
  const shaftLength = 2.8;
  const shaftRadius = 0.025;
  const maxHalfWidth = 0.6;
  const segmentsAlong = 60;
  const segmentsAcross = 30;

  const vaneVerts = [];
  const vaneIdx = [];
  const shaftVerts = [];
  const shaftIdx = [];

  // ── Shaft (thin cylinder along Y) ──
  const shaftSeg = 16;
  for (let i = 0; i <= segmentsAlong; i++) {
    const t = i / segmentsAlong;
    const y = (t - 0.5) * shaftLength;
    for (let j = 0; j <= shaftSeg; j++) {
      const a = (j / shaftSeg) * Math.PI * 2;
      shaftVerts.push(Math.cos(a) * shaftRadius, y, Math.sin(a) * shaftRadius);
    }
  }
  for (let i = 0; i < segmentsAlong; i++) {
    for (let j = 0; j < shaftSeg; j++) {
      const a = i * (shaftSeg + 1) + j;
      const b = a + 1;
      const c = a + shaftSeg + 1;
      const d = c + 1;
      shaftIdx.push(a, b, c, b, d, c);
    }
  }

  // ── Vanes (left + right) ──
  function buildVane(side) {
    const verts = [];
    const idx = [];
    const s = side; // +1 right, -1 left

    for (let i = 0; i <= segmentsAlong; i++) {
      const t = i / segmentsAlong;
      const y = (t - 0.5) * shaftLength;

      // Width profile: zero at tip and base, max in middle
      const tipFactor = 1 - Math.pow(t, 1.8);
      const baseFactor = Math.pow(1 - t, 0.6);
      const widthProfile = tipFactor * baseFactor;
      const halfW = maxHalfWidth * widthProfile;

      // Slight curve
      const curve = Math.sin(t * Math.PI) * 0.15;

      for (let j = 0; j <= segmentsAcross; j++) {
        const u = j / segmentsAcross;
        const localX = s * u * halfW;
        const localZ = curve + Math.sin(u * Math.PI) * 0.02 * s;

        // Barb jitter for realism
        const barbNoise = Math.sin(u * 80 + t * 30) * 0.008;
        const barbAngle = Math.atan2(localZ, localX);
        const barbDist = Math.sqrt(localX * localX + localZ * localZ);
        const nx = Math.cos(barbAngle + 0.1) * (barbDist + barbNoise);
        const nz = Math.sin(barbAngle + 0.1) * (barbDist + barbNoise);

        verts.push(nx, y, nz);
      }
    }

    for (let i = 0; i < segmentsAlong; i++) {
      for (let j = 0; j < segmentsAcross; j++) {
        const a = i * (segmentsAcross + 1) + j;
        const b = a + 1;
        const c = a + segmentsAcross + 1;
        const d = c + 1;
        idx.push(a, c, b, b, c, d);
      }
    }
    return { verts, idx };
  }

  const rightVane = buildVane(1);
  const leftVane = buildVane(-1);

  // Merge all
  const allVerts = [...shaftVerts, ...rightVane.verts, ...leftVane.verts];
  const vertCount = shaftVerts.length / 3;
  const rCount = rightVane.verts.length / 3;

  const allIdx = [
    ...shaftIdx,
    ...rightVane.idx.map(i => i + vertCount),
    ...leftVane.idx.map(i => i + vertCount + rCount)
  ];

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(allVerts, 3));
  geo.setIndex(allIdx);
  geo.computeVertexNormals();
  return geo;
}

// ── Feather Material ──
const featherMat = new THREE.MeshPhysicalMaterial({
  color: 0x2244aa,
  metalness: 0.0,
  roughness: 0.6,
  clearcoat: 0.3,
  clearcoatRoughness: 0.4,
  side: THREE.DoubleSide,
  transparent: true,
  opacity: 0.92,
  sheen: 1.0,
  sheenRoughness: 0.5,
  sheenColor: new THREE.Color(0x6688cc),
  iridescence: 0.6,
  iridescenceIOR: 1.3,
  iridescenceThicknessRange: [100, 800],
});

const feather = new THREE.Mesh(createFeatherGeometry(), featherMat);
scene.add(feather);

// ── Particle dust ──
const dustCount = 200;
const dustGeo = new THREE.BufferGeometry();
const dustPos = new Float32Array(dustCount * 3);
for (let i = 0; i < dustCount; i++) {
  dustPos[i * 3] = (Math.random() - 0.5) * 12;
  dustPos[i * 3 + 1] = (Math.random() - 0.5) * 12;
  dustPos[i * 3 + 2] = (Math.random() - 0.5) * 12;
}
dustGeo.setAttribute('position', new THREE.BufferAttribute(dustPos, 3));
const dustMat = new THREE.PointsMaterial({ color: 0x8888cc, size: 0.02, transparent: true, opacity: 0.5 });
const dust = new THREE.Points(dustGeo, dustMat);
scene.add(dust);

// ── Animate ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  feather.rotation.y = Math.sin(t * 0.3) * 0.4;
  feather.rotation.x = Math.sin(t * 0.2) * 0.1 + 0.1;
  feather.rotation.z = Math.sin(t * 0.25) * 0.15;
  feather.position.y = Math.sin(t * 0.5) * 0.15;

  dust.rotation.y = t * 0.02;
  dust.rotation.x = t * 0.01;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single `index.html` file creates a **procedural 3D feather** with:

- **Central shaft** — a thin cylinder running the length of the feather
- **Two vane blades** — left and right wings with a realistic tapered profile (zero width at tip/base, widest in the middle)
- **Barb micro-detail** — subtle vertex jitter simulating individual barbs
- **Gentle curvature** — the feather bows slightly for a natural look
- **Iridescent material** — `MeshPhysicalMaterial` with sheen, iridescence, and clearcoat for a pearlescent feather quality
- **Floating animation** — the feather gently drifts and tilts
- **Ambient dust particles** — floating specks for atmosphere
- **OrbitControls** — drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Fan</title>
