}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── Scene ── */
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 2.5, 4);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.6, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 2;
controls.maxDistance = 12;

/* ── Lights ── */
scene.add(new THREE.AmbientLight(0x8090b0, 0.8));
scene.add(new THREE.HemisphereLight(0xffeedd, 0x332244, 0.6));

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(4, 6, 3);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
sun.shadow.camera.near = 1; sun.shadow.camera.far = 20;
sun.shadow.camera.left = -5; sun.shadow.camera.right = 5;
sun.shadow.camera.top = 5; sun.shadow.camera.bottom = -5;
scene.add(sun);

const rim = new THREE.DirectionalLight(0x6688ff, 0.5);
rim.position.set(-3, 3, -4);
scene.add(rim);

/* ── Materials ── */
const furMat = new THREE.MeshStandardMaterial({ color: 0xc4956a, roughness: 0.85, metalness: 0 });
const bellyMat = new THREE.MeshStandardMaterial({ color: 0xe8d5c0, roughness: 0.9 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x2a1a0a, roughness: 0.7 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0x3a2020, roughness: 0.4, metalness: 0.1 });
const eyeWhite = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.3 });
const eyePupil = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.1 });
const maskMat = new THREE.MeshStandardMaterial({ color: 0x3a2518, roughness: 0.8 });

/* ── Ferret Group ── */
const ferret = new THREE.Group();
const bodyGroup = new THREE.Group();
const tailGroup = new THREE.Group();
const headGroup = new THREE.Group();

/* ── Body (elongated capsule) ── */
const bodyGeo = new THREE.CapsuleGeometry(0.32, 1.0, 12, 24);
const body = new THREE.Mesh(bodyGeo, furMat);
body.rotation.z = Math.PI / 2;
body.position.set(0, 0.52, 0);
body.castShadow = true;
bodyGroup.add(body);

/* Belly patch */
const bellyGeo = new THREE.CapsuleGeometry(0.22, 0.75, 8, 16);
const belly = new THREE.Mesh(bellyGeo, bellyMat);
belly.rotation.z = Math.PI / 2;
belly.position.set(0.05, 0.38, 0);
bodyGroup.add(belly);

/* ── Legs ── */
function makeLeg(x, z, angle) {
  const g = new THREE.Group();
  const legGeo = new THREE.CapsuleGeometry(0.065, 0.22, 6, 12);
  const leg = new THREE.Mesh(legGeo, furMat);
  leg.position.y = -0.11;
  leg.castShadow = true;
  g.add(leg);

  const footGeo = new THREE.SphereGeometry(0.07, 8, 8);
  const foot = new THREE.Mesh(footGeo, furMat);
  foot.position.y = -0.24;
  foot.scale.set(1, 0.6, 1.2);
  foot.castShadow = true;
  g.add(foot);

  g.position.set(x, 0.34, z);
  g.rotation.x = angle;
  return g;
}

const frontL = makeLeg(0.35, 0.2, 0.15);
const frontR = makeLeg(0.35, -0.2, 0.15);
const backL  = makeLeg(-0.35, 0.2, -0.15);
const backR  = makeLeg(-0.35, -0.2, -0.15);
bodyGroup.add(frontL, frontR, backL, backR);

/* ── Tail ── */
tailGroup.position.set(-0.55, 0.52, 0);
const tailCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 0, 0),
  new THREE.Vector3(-0.3, 0.05, 0),
  new THREE.Vector3(-0.6, 0.15, 0.05),
  new THREE.Vector3(-0.85, 0.35, 0),
]);
const tailGeo = new THREE.TubeGeometry(tailCurve, 16, 0.06, 8, false);
const tailMesh = new THREE.Mesh(tailGeo, furMat);
tailMesh.castShadow = true;
tailGroup.add(tailMesh);

/* Tail tip (darker) */
const tipGeo = new THREE.SphereGeometry(0.07, 8, 8);
const tip = new THREE.Mesh(tipGeo, darkMat);
tip.position.set(-0.85, 0.35, 0);
tailGroup.add(tip);

/* ── Head ── */
headGroup.position.set(0.62, 0.62, 0);

const headGeo = new THREE.SphereGeometry(0.24, 16, 16);
const head = new THREE.Mesh(headGeo, furMat);
head.scale.set(1.15, 1, 1);
head.castShadow = true;
headGroup.add(head);

/* Snout */
const snoutGeo = new THREE.ConeGeometry(0.1, 0.28, 12);
const snout = new THREE.Mesh(snoutGeo, furMat);
snout.rotation.z = -Math.PI / 2;
snout.position.set(0.28, -0.02, 0);
snout.castShadow = true;
headGroup.add(snout);

/* Nose */
const noseGeo = new THREE.SphereGeometry(0.045, 10, 10);
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.set(0.42, -0.02, 0);
nose.scale.set(1.2, 0.8, 1);
headGroup.add(nose);

/* Eye patches (dark mask) */
function makeEyePatch(side) {
  const g = new THREE.Group();
  const patchGeo = new THREE.SphereGeometry(0.1, 12, 12);
  const patch = new THREE.Mesh(patchGeo, maskMat);
  patch.scale.set(0.85, 0.7, 0.5);
  g.add(patch);

  /* Eye white */
  const ewGeo = new THREE.SphereGeometry(0.055, 10, 10);
  const ew = new THREE.Mesh(ewGeo, eyeWhite);
  ew.position.set(0.06, 0.04, side * 0.08);
  ew.scale.set(1.1, 1, 0.5);
  g.add(ew);

  /* Pupil */
  const pGeo = new THREE.SphereGeometry(0.032, 10, 10);
  const pupil = new THREE.Mesh(pGeo, eyePupil);
  pupil.position.set(0.09, 0.045, side * 0.09);
  g.add(pupil);

  g.position.set(0.14, 0.08, side * 0.14);
  return g;
}
headGroup.add(makeEyePatch(1), makeEyePatch(-1));

/* Ears */
function makeEar(side) {
  const g = new THREE.Group();
  const earGeo = new THREE.ConeGeometry(0.07, 0.14, 8);
  const ear = new THREE.Mesh(earGeo, furMat);
  ear.castShadow = true;
  g.add(ear);

  const innerGeo = new THREE.ConeGeometry(0.04, 0.09, 8);
  const inner = new THREE.Mesh(innerGeo, new THREE.MeshStandardMaterial({ color: 0xd4a0a0, roughness: 0.8 }));
  inner.position.z = side * 0.015;
  g.add(inner);

  g.position.set(0.05, 0.2, side * 0.16);
  g.rotation.z = side * -0.3;
  g.rotation.x = -0.2;
  return g;
}
headGroup.add(makeEar(1), makeEar(-1));

/* Whiskers (thin lines) */
function makeWhiskers(side) {
  const g = new THREE.Group();
  const mat = new THREE.LineBasicMaterial({ color: 0xddcccc });
  for (let i = -1; i <= 1; i++) {
    const pts = [
      new THREE.Vector3(0, i * 0.025, 0),
      new THREE.Vector3(0.25, i * 0.06 + Math.sin(i) * 0.01, side * 0.01),
    ];
    const geo = new THREE.BufferGeometry().setFromPoints(pts);
    g.add(new THREE.Line(geo, mat));
  }
  g.position.set(0.35, -0.04, side * 0.1);
  g.rotation.y = side * 0.3;
  return g;
}
headGroup.add(makeWhiskers(1), makeWhiskers(-1));

/* ── Assemble ── */
ferret.add(bodyGroup);
ferret.add(tailGroup);
ferret.add(headGroup);
scene.add(ferret);

/* ── Ground ── */
const groundGeo = new THREE.CircleGeometry(8, 48);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x2d4a3e, roughness: 0.95 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* Grass tufts */
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const r = 0.8 + Math.random() * 6;
  const x = Math.cos(angle) * r;
  const z = Math.sin(angle) * r;
  const h = 0.04 + Math.random() * 0.08;
  const gGeo = new THREE.ConeGeometry(0.02 + Math.random() * 0.02, h, 4);
  const gMat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28 + Math.random() * 0.06, 0.5 + Math.random() * 0.3, 0.25 + Math.random() * 0.15),
    roughness: 1,
  });
  const tuft = new THREE.Mesh(gGeo, gMat);
  tuft.position.set(x, h / 2, z);
  scene.add(tuft);
}

/* ── Animation ── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  /* Breathing */
  bodyGroup.scale.y = 1 + Math.sin(t * 2.2) * 0.015;
  bodyGroup.position.y = Math.sin(t * 2.2) * 0.008;

  /* Head bob */
  headGroup.rotation.y = Math.sin(t * 0.7) * 0.12;
  headGroup.rotation.x = Math.sin(t * 1.3) * 0.04;
  headGroup.position.y = 0.62 + Math.sin(t * 2.2) * 0.01;

  /* Tail wag */
  tailGroup.rotation.y = Math.sin(t * 1.8) * 0.25;
  tailGroup.rotation.x = Math.sin(t * 1.2) * 0.08;

  /* Subtle body sway */
  ferret.rotation.y = Math.sin(t * 0.4) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
