    const controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 3, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    // ── Lighting ──
    const ambientLight = new THREE.AmbientLight(0x404060, 0.6);
    scene.add(ambientLight);

    const sunLight = new THREE.DirectionalLight(0xffeedd, 1.2);
    sunLight.position.set(8, 12, 6);
    sunLight.castShadow = true;
    sunLight.shadow.mapSize.set(1024, 1024);
    sunLight.shadow.camera.near = 0.5;
    sunLight.shadow.camera.far = 50;
    sunLight.shadow.camera.left = -10;
    sunLight.shadow.camera.right = 10;
    sunLight.shadow.camera.top = 10;
    sunLight.shadow.camera.bottom = -10;
    scene.add(sunLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 0.4);
    rimLight.position.set(-5, 4, -5);
    scene.add(rimLight);

    // ── Ground ──
    const groundGeo = new THREE.PlaneGeometry(60, 60);
    const groundMat = new THREE.MeshStandardMaterial({ color: 0x16213e, roughness: 0.9 });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.01;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Flagpole ──
    const poleGeo = new THREE.CylinderGeometry(0.06, 0.08, 8, 12);
    const poleMat = new THREE.MeshStandardMaterial({ color: 0xaaaaaa, metalness: 0.8, roughness: 0.2 });
    const pole = new THREE.Mesh(poleGeo, poleMat);
    pole.position.set(0, 4, 0);
    pole.castShadow = true;
    scene.add(pole);

    // Pole ball
    const ballGeo = new THREE.SphereGeometry(0.15, 16, 16);
    const ballMat = new THREE.MeshStandardMaterial({ color: 0xffcc00, metalness: 0.9, roughness: 0.1 });
    const ball = new THREE.Mesh(ballGeo, ballMat);
    ball.position.set(0, 8.1, 0);
    ball.castShadow = true;
    scene.add(ball);

    // Pole base
    const baseGeo = new THREE.CylinderGeometry(0.3, 0.35, 0.3, 12);
    const baseMat = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.6, roughness: 0.3 });
    const base = new THREE.Mesh(baseGeo, baseMat);
    base.position.set(0, 0.15, 0);
    base.castShadow = true;
    scene.add(base);

    // ── Flag Texture (Canvas) ──
    function createFlagTexture() {
      const canvas = document.createElement('canvas');
      canvas.width = 512;
      canvas.height = 340;
      const ctx = canvas.getContext('2d');

      // Three horizontal stripes
      const stripeH = canvas.height / 3;
      ctx.fillStyle = '#002395';  // Blue
      ctx.fillRect(0, 0, canvas.width, stripeH);
      ctx.fillStyle = '#ffffff';  // White
      ctx.fillRect(0, stripeH, canvas.width, stripeH);
      ctx.fillStyle = '#ce1126';  // Red
      ctx.fillRect(0, stripeH * 2, canvas.width, stripeH);

      // Subtle texture overlay
      ctx.fillStyle = 'rgba(0,0,0,0.03)';
      for (let i = 0; i < canvas.width; i += 4) {
        for (let j = 0; j < canvas.height; j += 4) {
          if (Math.random() > 0.7) ctx.fillRect(i, j, 2, 2);
        }
      }

      const texture = new THREE.CanvasTexture(canvas);
      texture.minFilter = THREE.LinearFilter;
      texture.magFilter = THREE.LinearFilter;
      return texture;
    }

    // ── Flag Mesh ──
    const flagSegmentsX = 40;
    const flagSegmentsY = 26;
    const flagWidth = 5;
    const flagHeight = 3.33;

    const flagGeo = new THREE.PlaneGeometry(flagWidth, flagHeight, flagSegmentsX, flagSegmentsY);
    flagGeo.translate(flagWidth / 2, flagHeight / 2, 0);

    const flagTexture = createFlagTexture();
    const flagMat = new THREE.MeshStandardMaterial({
      map: flagTexture,
      side: THREE.DoubleSide,
      roughness: 0.8,
      metalness: 0.0,
      flatShading: false
    });

    const flag = new THREE.Mesh(flagGeo, flagMat);
    flag.position.set(0, 7.8, 0);
    flag.castShadow = true;
    flag.receiveShadow = true;
    scene.add(flag);

    // Store original vertex positions
    const originalPositions = flagGeo.attributes.position.array.slice();

    // ── Stars (decorative background) ──
    const starsGeo = new THREE.BufferGeometry();
    const starCount = 800;
    const starPositions = new Float32Array(starCount * 3);
    for (let i = 0; i < starCount; i++) {
      starPositions[i * 3]     = (Math.random() - 0.5) * 80;
      starPositions[i * 3 + 1] = Math.random() * 30 + 2;
      starPositions[i * 3 + 2] = (Math.random() - 0.5) * 80 - 10;
    }
    starsGeo.setAttribute('position', new THREE.BufferAttribute(starPositions, 3));
    const starsMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.08, transparent: true, opacity: 0.6 });
    const stars = new THREE.Points(starsGeo, starsMat);
    scene.add(stars);

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Wave the flag
      const positions = flagGeo.attributes.position.array;
      for (let i = 0; i < positions.length; i += 3) {
        const ox = originalPositions[i];
        const oy = originalPositions[i + 1];

        // Normalized distance from pole (0 = pole, 1 = tip)
        const nx = ox / flagWidth;

        // Multiple sine waves for natural look
        const wave1 = Math.sin(nx * Math.PI * 3 - t * 3.0) * 0.18;
        const wave2 = Math.sin(nx * Math.PI * 5 - t * 4.5) * 0.08;
        const wave3 = Math.sin(nx * Math.PI * 2 - t * 2.0) * 0.12;

        // Amplitude increases away from pole
        const amplitude = nx * nx;

        // Vertical undulation
        const vertWave = Math.sin(nx * Math.PI * 2 - t * 2.5) * 0.06 * amplitude;

        positions[i]     = ox;
        positions[i + 1] = oy + vertWave;
        positions[i + 2] = (wave1 + wave2 + wave3) * amplitude;
      }
      flagGeo.attributes.position.needsUpdate = true;
      flagGeo.computeVertexNormals();

      // Slow star twinkle
      const starPos = starsGeo.attributes.position.array;
      for (let i = 0; i < starCount; i++) {
        starPos[i * 3 + 1] += Math.sin(t * 0.5 + i) * 0.001;
      }
      starsGeo.attributes.position.needsUpdate = true;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What this creates

A **realistic waving flag** scene featuring:

- **🏳️ French tricolor flag** (blue/white/red) rendered via a canvas texture on a subdivided plane
- **🌊 Realistic wind animation** — multiple layered sine waves with amplitude that increases away from the pole, plus vertical undulation
- **🏛️ Flagpole** with a golden ball finial and weighted base
- **💡 Three-point lighting** — warm directional sun, cool rim light, and ambient fill
- **🌑 Dark sky** with twinkling star particles and subtle fog
- **🖱️ OrbitControls** — click and drag to rotate, scroll to zoom
- **📐 Shadows** — soft PCF shadow mapping from the sun light

Just save it as `index.html` and open in any modern browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Flame</title>
<style>body{margin:0;overflow:hidden;background:#000}</style>
</head>
<body>
<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js" } }
</script>
<script type="module">
import * as THREE from 'three';

const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x000000, 0.15);

const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 6);
camera.lookAt(0, 2.5, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
document.body.appendChild(renderer.domElement);

// --- Flame particle system ---
const COUNT = 2500;
const geo = new THREE.BufferGeometry();
const positions = new Float32Array(COUNT * 3);
const lifetimes = new Float32Array(COUNT);   // 0→1 life progress
const speeds = new Float32Array(COUNT);
const sizes = new Float32Array(COUNT);
const offsets = new Float32Array(COUNT * 3); // random horizontal offset

for (let i = 0; i < COUNT; i++) {
  positions[i * 3]     = (Math.random() - 0.5) * 0.3;
  positions[i * 3 + 1] = Math.random() * 4;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 0.3;
  lifetimes[i] = Math.random();
  speeds[i]    = 1.0 + Math.random() * 1.5;
  sizes[i]     = 3 + Math.random() * 8;
  offsets[i * 3]     = (Math.random() - 0.5);
  offsets[i * 3 + 1] = 0;
  offsets[i * 3 + 2] = (Math.random() - 0.5);
}

geo.setAttribute('position',  new THREE.BufferAttribute(positions, 3));
geo.setAttribute('aLifetime', new THREE.BufferAttribute(lifetimes, 1));
geo.setAttribute('aSpeed',    new THREE.BufferAttribute(speeds, 1));
geo.setAttribute('aSize',     new THREE.BufferAttribute(sizes, 1));
geo.setAttribute('aOffset',   new THREE.BufferAttribute(offsets, 3));

const mat = new THREE.ShaderMaterial({
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    attribute float aLifetime;
    attribute float aSpeed;
    attribute float aSize;
    attribute vec3 aOffset;

    uniform float uTime;

    varying float vLife;

    // Simplex-ish noise
    vec3 mod289(vec3 x){return x-floor(x*(1./289.))*289.;}
    vec4 mod289(vec4 x){return x-floor(x*(1./289.))*289.;}
    vec4 perm(vec4 x){return mod289(((x*34.)+1.)*x);}
    float noise(vec3 p){
      vec3 a=floor(p),d=p-a;a=mod289(a);
      vec4 b=a.xxyy+vec4(0,1,0,1),k1=perm(b.xyxy),k2=perm(k1.xyxy+b.zzww);
      vec4 c=clamp(vec4(2.)-(abs(k2*(1./41.)-d.zzzz)),0.,1.);
      vec4 o1=fract(k2*(1./41.))*d.xzxz*(1.-d.xzxz);
      return dot(c*c*c,o1)*3.2+0.5;
    }

    void main() {
      vLife = aLifetime;
      float life = fract(aLifetime + uTime * aSpeed * 0.3);
      float baseY = life * 4.5;

      float n1 = noise(vec3(aOffset.x * 4.0, life * 3.0 + uTime * 2.0, uTime * 1.3));
      float n2 = noise(vec3(aOffset.z * 4.0, life * 3.0 + uTime * 2.0, uTime * 0.7));
      float sway = (n1 - 0.5) * 0.8 * life + (n2 - 0.5) * 0.4 * life;

      vec3 pos = position;
      pos.y = baseY;
      pos.x += sway;
      pos.z += (n2 - 0.5) * 0.3 * life;

      // Taper width with height
      float width = max(0.0, 1.0 - life) * 0.6;
      pos.x += (aOffset.x - 0.5) * width;
      pos.z += (aOffset.z - 0.5) * width;

      vec4 mv = modelViewMatrix * vec4(pos, 1.0);
      gl_Position = projectionMatrix * mv;

      // Size fades near top and bottom
      float fadeIn  = smoothstep(0.0, 0.05, life);
      float fadeOut = 1.0 - smoothstep(0.6, 1.0, life);
      gl_PointSize = aSize * (1.0 + life * 2.0) * fadeIn * fadeOut * (200.0 / -mv.z);
    }
  `,
  fragmentShader: `
    varying float vLife;

    void main() {
      // Soft circular particle
      vec2 c = gl_PointCoord - 0.5;
      float d = length(c);
      if (d > 0.5) discard;
      float alpha = 1.0 - smoothstep(0.0, 0.5, d);

      // Color gradient: white-hot core → yellow → orange → red → transparent
      float t = vLife;
      vec3 col;
      if (t < 0.05)        col = mix(vec3(1.0,0.95,0.8), vec3(1.0,0.85,0.2), t / 0.05);
      else if (t < 0.3)    col = mix(vec3(1.0,0.85,0.2), vec3(1.0,0.35,0.0), (t-0.05)/0.25);
      else if (t < 0.6)    col = mix(vec3(1.0,0.35,0.0), vec3(0.8,0.05,0.0), (t-0.3)/0.3);
      else                 col = mix(vec3(0.8,0.05,0.0), vec3(0.2,0.0,0.0), (t-0.6)/0.4);

      alpha *= (1.0 - smoothstep(0.5, 1.0, t));
      alpha *= 0.7;

      gl_FragColor = vec4(col * 2.0, alpha);
    }
  `,
  transparent: true,
  depthWrite: false,
  blending: THREE.AdditiveBlending,
});

const flame = new THREE.Points(geo, mat);
scene.add(flame);

// --- Ember particles ---
const EMBER_COUNT = 200;
const emberGeo = new THREE.BufferGeometry();
const ePos = new Float32Array(EMBER_COUNT * 3);
const eLife = new Float32Array(EMBER_COUNT);
const eVel = new Float32Array(EMBER_COUNT * 3);

for (let i = 0; i < EMBER_COUNT; i++) {
  ePos[i*3] = (Math.random()-0.5)*0.2;
  ePos[i*3+1] = Math.random()*4;
  ePos[i*3+2] = (Math.random()-0.5)*0.2;
  eLife[i] = Math.random();
  eVel[i*3] = (Math.random()-0.5)*0.5;
  eVel[i*3+1] = 2 + Math.random()*3;
  eVel[i*3+2] = (Math.random()-0.5)*0.5;
}
emberGeo.setAttribute('position', new THREE.BufferAttribute(ePos, 3));
emberGeo.setAttribute('aLife', new THREE.BufferAttribute(eLife, 1));

const emberMat = new THREE.ShaderMaterial({
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    attribute float aLife;
    uniform float uTime;
    varying float vLife;
    void main() {
      vLife = fract(aLife + uTime * 0.4);
      vec3 p = position;
      p.y = vLife * 5.0;
      p.x += sin(uTime * 3.0 + aLife * 20.0) * 0.3;
      p.z += cos(uTime * 2.5 + aLife * 15.0) * 0.3;
      vec4 mv = modelViewMatrix * vec4(p,1.0);
      gl_Position = projectionMatrix * mv;
      gl_PointSize = (1.0 - vLife) * 4.0 * (100.0 / -mv.z);
    }
  `,
  fragmentShader: `
    varying float vLife;
    void main() {
      float d = length(gl_PointCoord - 0.5);
      if(d>0.5) discard;
      float a = (1.0 - d*2.0) * (1.0 - vLife) * 0.8;
      vec3 c = mix(vec3(1.0,0.6,0.1), vec3(1.0,0.2,0.0), vLife);
      gl_FragColor = vec4(c * 2.5, a);
    }
  `,
  transparent: true, depthWrite: false, blending: THREE.AdditiveBlending,
});
const embers = new THREE.Points(emberGeo, emberMat);
scene.add(embers);

// --- Glow sprite at base ---
const glowTex = (() => {
  const c = document.createElement('canvas');
  c.width = c.height = 128;
  const ctx = c.getContext('2d');
  const g = ctx.createRadialGradient(64,64,0,64,64,64);
  g.addColorStop(0, 'rgba(255,160,40,0.4)');
  g.addColorStop(0.5, 'rgba(255,80,0,0.1)');
  g.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.fillStyle = g;
  ctx.fillRect(0,0,128,128);
  return new THREE.CanvasTexture(c);
})();

const glow = new THREE.Sprite(new THREE.SpriteMaterial({
  map: glowTex, blending: THREE.AdditiveBlending, transparent: true, depthWrite: false,
}));
glow.position.set(0, 0.5, 0);
glow.scale.set(3, 3, 1);
scene.add(glow);

// --- Ground disc ---
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(2, 32),
  new THREE.MeshBasicMaterial({ color: 0x111111 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = 0.01;
scene.add(ground);

// --- Light from flame ---
const light = new THREE.PointLight(0xff6622, 3, 12);
light.position.set(0, 2, 0);
scene.add(light);
scene.add(new THREE.AmbientLight(0x221100, 0.5));

// --- Animate ---
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  mat.uniforms.uTime.value = t;
  emberMat.uniforms.uTime.value = t;

  // Flicker light
  light.intensity = 2.5 + Math.sin(t * 8) * 0.5 + Math.sin(t * 13.7) * 0.3 + Math.sin(t * 21.3) * 0.2;
  light.position.y = 2 + Math.sin(t * 6) * 0.3;

  // Glow flicker
  const s = 3 + Math.sin(t * 7) * 0.3 + Math.sin(t * 11) * 0.2;
  glow.scale.set(s, s, 1);
  glow.material.opacity = 0.8 + Math.sin(t * 9) * 0.15;

  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's in here:**

- **Particle flame** — 2,500 particles with a custom vertex shader using 3D noise for organic sway/turbulence, and a fragment shader that maps lifetime to a white→yellow→orange→red→transparent color gradient
- **Ember particles** — 200 smaller glowing sparks that float upward with sinusoidal drift
- **Glow sprite** — a soft radial gradient at the base for bloom-like illumination
- **Dynamic point light** — flickers using layered sine waves to simulate real flame light
- **Additive blending** on all flame elements for natural light accumulation
- **Responsive** — handles window resize

