function createPetalShape() {
  const s = new THREE.Shape();
  s.moveTo(0, 0);
  s.bezierCurveTo(0.15, 0.15, 0.25, 0.55, 0.0, 1.0);
  s.bezierCurveTo(-0.25, 0.55, -0.15, 0.15, 0, 0);
  return s;
}

function createPetal(material, scale = 1) {
  const shape = createPetalShape();
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: 0.02,
    bevelEnabled: true,
    bevelThickness: 0.015,
    bevelSize: 0.015,
    bevelSegments: 4,
  });
  geo.center();
  const mesh = new THREE.Mesh(geo, material);
  mesh.scale.setScalar(scale);
  return mesh;
}

// ── Flower Group ─────────────────────────────────────
const flower = new THREE.Group();

// ── Stem ─────────────────────────────────────────────
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, -1.5, 0),
  new THREE.Vector3(0.02, 0, 0),
  new THREE.Vector3(0, 1.5, 0),
]);
const stemGeo = new THREE.TubeGeometry(stemCurve, 20, 0.06, 8, false);
const stem = new THREE.Mesh(stemGeo, stemMat);
flower.add(stem);

// ── Leaves ───────────────────────────────────────────
function createLeaf() {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.bezierCurveTo(0.12, 0.2, 0.25, 0.5, 0.0, 1.0);
  shape.bezierCurveTo(-0.25, 0.5, -0.12, 0.2, 0, 0);
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: 0.01,
    bevelEnabled: true,
    bevelThickness: 0.008,
    bevelSize: 0.008,
    bevelSegments: 3,
  });
  geo.center();
  return new THREE.Mesh(geo, leafMat);
}

const leaf1 = createLeaf();
leaf1.position.set(0.12, 0.2, 0);
leaf1.rotation.set(0.3, -0.5, 1.2);
leaf1.scale.setScalar(1.2);
flower.add(leaf1);

const leaf2 = createLeaf();
leaf2.position.set(-0.1, 0.6, 0.05);
leaf2.rotation.set(-0.2, 0.8, -1.0);
leaf2.scale.setScalar(1.0);
flower.add(leaf2);

// ── Petals ───────────────────────────────────────────
const petalGroup = new THREE.Group();

// Outer ring
for (let i = 0; i < 8; i++) {
  const petal = createPetal(petalMat, 1.1);
  const angle = (i / 8) * Math.PI * 2;
  petal.position.set(Math.cos(angle) * 0.55, 1.5, Math.sin(angle) * 0.55);
  petal.rotation.y = -angle;
  petal.rotation.x = -0.5;
  petalGroup.add(petal);
}

// Inner ring
for (let i = 0; i < 6; i++) {
  const petal = createPetal(petalMatInner, 0.85);
  const angle = (i / 6) * Math.PI * 2 + Math.PI / 6;
  petal.position.set(Math.cos(angle) * 0.32, 1.55, Math.sin(angle) * 0.32);
  petal.rotation.y = -angle;
  petal.rotation.x = -0.35;
  petalGroup.add(petal);
}

flower.add(petalGroup);

// ── Center ───────────────────────────────────────────
const centerGeo = new THREE.SphereGeometry(0.22, 24, 24);
const center = new THREE.Mesh(centerGeo, centerMat);
center.position.y = 1.58;
flower.add(center);

// Center bumps (texture detail)
for (let i = 0; i < 20; i++) {
  const bump = new THREE.Mesh(
    new THREE.SphereGeometry(0.035, 8, 8),
    new THREE.MeshStandardMaterial({
      color: 0xddaa11,
      roughness: 0.9,
    })
  );
  const phi = Math.acos(2 * Math.random() - 1);
  const theta = Math.random() * Math.PI * 2;
  const r = 0.2;
  bump.position.set(
    r * Math.sin(phi) * Math.cos(theta),
    1.58 + r * Math.cos(phi),
    r * Math.sin(phi) * Math.sin(theta)
  );
  flower.add(bump);
}

scene.add(flower);

// ── Floating Particles ───────────────────────────────
const particleCount = 120;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const particleSpeeds = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 12;
  positions[i * 3 + 1] = Math.random() * 6 - 1;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 12;
  particleSpeeds[i] = 0.002 + Math.random() * 0.006;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0xffaacc,
  size: 0.04,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Ground Glow ──────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(4, 48);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a0a2e,
  roughness: 1,
  metalness: 0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.5;
scene.add(ground);

// ── Animation ────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  flower.rotation.z = Math.sin(t * 0.5) * 0.04;
  flower.rotation.x = Math.sin(t * 0.3) * 0.02;

  // Petal breathing
  petalGroup.children.forEach((petal, i) => {
    const breathe = Math.sin(t * 0.8 + i * 0.5) * 0.03;
    petal.scale.setScalar(petal.scale.x + breathe * 0.01);
  });

  // Bloom light pulse
  bloom.intensity = 1.5 + Math.sin(t * 1.2) * 0.5;

  // Particles drift
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += particleSpeeds[i];
    pos.array[i * 3] += Math.sin(t + i) * 0.001;
    if (pos.array[i * 3 + 1] > 6) pos.array[i * 3 + 1] = -1;
  }
  pos.needsUpdate = true;

  renderer.render(scene, camera);
}

animate();

// ── Resize ───────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single file gives you a complete 3D flower scene with:

- **Two layers of petals** (8 outer, 6 inner) using extruded bezier-curve petal shapes with beveled edges
- **Textured center** — a yellow sphere with smaller bump spheres for pollen detail
- **Curved stem** built from a CatmullRom spline tube
- **Two leaves** attached along the stem
- **Floating particles** that drift upward like pollen/sparkles
- **Three-point lighting** (sun, rim, and a pulsing bloom light)
- **Gentle animations** — the flower sways, petals "breathe," and particles float
- **Responsive** — handles window resizing

Just save it as `index.html` and open in any modern browser.

