    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // ── Scene ──────────────────────────────────────────────
        const scene = new THREE.Scene();

        // Gradient background
        const bgCanvas = document.createElement('canvas');
        bgCanvas.width = 2; bgCanvas.height = 512;
        const bgCtx = bgCanvas.getContext('2d');
        const grad = bgCtx.createLinearGradient(0, 0, 0, 512);
        grad.addColorStop(0, '#1a1a2e');
        grad.addColorStop(0.5, '#16213e');
        grad.addColorStop(1, '#0f3460');
        bgCtx.fillStyle = grad;
        bgCtx.fillRect(0, 0, 2, 512);
        scene.background = new THREE.CanvasTexture(bgCanvas);

        // ── Camera ─────────────────────────────────────────────
        const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
        camera.position.set(0, 0, 5);

        // ── Renderer ───────────────────────────────────────────
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(innerWidth, innerHeight);
        renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
        renderer.toneMapping = THREE.ACESFilmicToneMapping;
        renderer.toneMappingExposure = 1.2;
        document.body.appendChild(renderer.domElement);

        // ── Controls ───────────────────────────────────────────
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.08;
        controls.minDistance = 2.5;
        controls.maxDistance = 10;

        // ── Soccer Ball Texture (canvas) ───────────────────────
        function createSoccerTexture(radius = 1024) {
            const canvas = document.createElement('canvas');
            canvas.width = radius * 2;
            canvas.height = radius;
            const ctx = canvas.getContext('2d');

            // White base
            ctx.fillStyle = '#f5f5f0';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const w = canvas.width, h = canvas.height;
            const patchRadius = w * 0.08;

            function drawPentagon(cx, cy, r) {
                ctx.beginPath();
                for (let i = 0; i < 5; i++) {
                    const angle = (i * 2 * Math.PI / 5) - Math.PI / 2;
                    const x = cx + r * Math.cos(angle);
                    const y = cy + r * Math.sin(angle);
                    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.fillStyle = '#1a1a1a';
                ctx.fill();

                // Subtle edge highlight
                ctx.strokeStyle = 'rgba(255,255,255,0.15)';
                ctx.lineWidth = 2;
                ctx.stroke();
            }

            function drawHexagon(cx, cy, r) {
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                    const angle = (i * Math.PI / 3);
                    const x = cx + r * Math.cos(angle);
                    const y = cy + r * Math.sin(angle);
                    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.strokeStyle = 'rgba(0,0,0,0.08)';
                ctx.lineWidth = 1.5;
                ctx.stroke();
            }

            // Place pentagons in equirectangular layout (12 total)
            const pentPositions = [
                // Top cap area
                [w * 0.125, h * 0.15], [w * 0.375, h * 0.12], [w * 0.625, h * 0.12], [w * 0.875, h * 0.15],
                // Mid-upper
                [w * 0.25, h * 0.35], [w * 0.5, h * 0.32], [w * 0.75, h * 0.35],
                // Mid-lower
                [w * 0.125, h * 0.65], [w * 0.375, h * 0.68], [w * 0.625, h * 0.68], [w * 0.875, h * 0.65],
                // Bottom cap
                [w * 0.25, h * 0.88], [w * 0.5, h * 0.9], [w * 0.75, h * 0.88],
            ];

            pentPositions.forEach(([x, y]) => drawPentagon(x, y, patchRadius));

            // Hexagons in the gaps
            const hexPositions = [
                [w * 0.25, h * 0.22], [w * 0.5, h * 0.2], [w * 0.75, h * 0.22],
                [w * 0.125, h * 0.45], [w * 0.375, h * 0.48], [w * 0.625, h * 0.48], [w * 0.875, h * 0.45],
                [w * 0.25, h * 0.52], [w * 0.5, h * 0.55], [w * 0.75, h * 0.52],
                [w * 0.125, h * 0.78], [w * 0.375, h * 0.8], [w * 0.625, h * 0.8], [w * 0.875, h * 0.78],
                [w * 0.5, h * 0.12], [w * 0.25, h * 0.78], [w * 0.75, h * 0.78],
            ];

            hexPositions.forEach(([x, y]) => drawHexagon(x, y, patchRadius * 0.9));

            // Wrap-around edges
            drawPentagon(w * 0.0, h * 0.15);
            drawPentagon(w * 1.0, h * 0.15);
            drawPentagon(w * 0.0, h * 0.65);
            drawPentagon(w * 1.0, h * 0.65);

            const texture = new THREE.CanvasTexture(canvas);
            texture.wrapS = THREE.RepeatWrapping;
            texture.wrapT = THREE.ClampToEdgeWrapping;
            return texture;
        }

        function createBumpTexture(radius = 1024) {
            const canvas = document.createElement('canvas');
            canvas.width = radius * 2;
            canvas.height = radius;
            const ctx = canvas.getContext('2d');

            ctx.fillStyle = '#808080';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const w = canvas.width, h = canvas.height;
            const patchRadius = w * 0.08;

            // Lighten the seams (stitched look)
            ctx.strokeStyle = 'rgba(200,200,200,0.5)';
            ctx.lineWidth = 3;

            const allPositions = [
                [w * 0.125, h * 0.15], [w * 0.375, h * 0.12], [w * 0.625, h * 0.12], [w * 0.875, h * 0.15],
                [w * 0.25, h * 0.35], [w * 0.5, h * 0.32], [w * 0.75, h * 0.35],
                [w * 0.125, h * 0.65], [w * 0.375, h * 0.68], [w * 0.625, h * 0.68], [w * 0.875, h * 0.65],
                [w * 0.25, h * 0.88], [w * 0.5, h * 0.9], [w * 0.75, h * 0.88],
            ];

            allPositions.forEach(([x, y]) => {
                ctx.beginPath();
                for (let i = 0; i < 5; i++) {
                    const angle = (i * 2 * Math.PI / 5) - Math.PI / 2;
                    const px = x + patchRadius * Math.cos(angle);
                    const py = y + patchRadius * Math.sin(angle);
                    i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
                }
                ctx.closePath();
                ctx.stroke();
            });

            return new THREE.CanvasTexture(canvas);
        }

        // ── Football Mesh ──────────────────────────────────────
        const ballGeometry = new THREE.SphereGeometry(1.2, 64, 64);
        const ballMaterial = new THREE.MeshStandardMaterial({
            map: createSoccerTexture(),
            bumpMap: createBumpTexture(),
            bumpScale: 0.02,
            roughness: 0.65,
            metalness: 0.05,
        });

        const football = new THREE.Mesh(ballGeometry, ballMaterial);
        scene.add(football);

        // ── Lighting ───────────────────────────────────────────
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.4);
        scene.add(ambientLight);

        const keyLight = new THREE.DirectionalLight(0xffffff, 2.5);
        keyLight.position.set(5, 5, 5);
        scene.add(keyLight);

        const fillLight = new THREE.DirectionalLight(0x8888ff, 0.8);
        fillLight.position.set(-5, -2, 3);
        scene.add(fillLight);

        const rimLight = new THREE.DirectionalLight(0xffa644, 1.0);
        rimLight.position.set(0, 3, -5);
        scene.add(rimLight);

        // ── Shadow Ground (subtle) ─────────────────────────────
        const shadowGeo = new THREE.PlaneGeometry(10, 10);
        const shadowMat = new THREE.ShadowMaterial({ opacity: 0.15 });
        const shadowPlane = new THREE.Mesh(shadowGeo, shadowMat);
        shadowPlane.rotation.x = -Math.PI / 2;
        shadowPlane.position.y = -2.2;
        shadowPlane.receiveShadow = true;
        scene.add(shadowPlane);

        football.castShadow = true;

        // ── Animation ──────────────────────────────────────────
        const clock = new THREE.Clock();

        function animate() {
            requestAnimationFrame(animate);
            const elapsed = clock.getElapsedTime();

            // Gentle idle rotation
            football.rotation.y = elapsed * 0.3;
            football.rotation.x = Math.sin(elapsed * 0.2) * 0.15;

            // Gentle float
            football.position.y = Math.sin(elapsed * 0.8) * 0.1;

            controls.update();
            renderer.render(scene, camera);
        }

        animate();

        // ── Resize ─────────────────────────────────────────────
        window.addEventListener('resize', () => {
            camera.aspect = innerWidth / innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(innerWidth, innerHeight);
        });
    </script>
