document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;

// Lighting
const ambientLight = new THREE.AmbientLight(0xffffff, 0.4);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(5, 8, 6);
dirLight.castShadow = true;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 0.6);
rimLight.position.set(-4, 2, -3);
scene.add(rimLight);

// Frame
const frameGroup = new THREE.Group();

const W = 3.2, H = 4.2, D = 0.25, T = 0.2; // width, height, depth, thickness

const frameMat = new THREE.MeshStandardMaterial({
  color: 0x8B6914,
  metalness: 0.7,
  roughness: 0.3,
});

const matMat = new THREE.MeshStandardMaterial({
  color: 0xf5f0e1,
  metalness: 0.0,
  roughness: 0.9,
});

const canvasMat = new THREE.MeshStandardMaterial({
  color: 0x222222,
  metalness: 0.1,
  roughness: 0.8,
  emissive: 0x111111,
});

function makeBar(w, h, d) {
  const geo = new THREE.BoxGeometry(w, h, d);
  return new THREE.Mesh(geo, frameMat);
}

// Frame pieces
const topBar = makeBar(W, T, D);
topBar.position.y = H / 2 - T / 2;
frameGroup.add(topBar);

const botBar = makeBar(W, T, D);
botBar.position.y = -H / 2 + T / 2;
frameGroup.add(botBar);

const sideW = W / 2 - T;
const leftBar = makeBar(T, H - T * 2, D);
leftBar.position.x = -sideW - T / 2;
frameGroup.add(leftBar);

const rightBar = makeBar(T, H - T * 2, D);
rightBar.position.x = sideW + T / 2;
frameGroup.add(rightBar);

// Mat (inner border)
const matW = W - T * 2.8, matH = H - T * 2.8;
const matThick = 0.12, matD = 0.18;

const topMat = new THREE.Mesh(new THREE.BoxGeometry(matW, matThick, matD), matMat);
topMat.position.y = (H - T * 2.8) / 2 - matThick / 2;
frameGroup.add(topMat);

const botMat = topMat.clone();
botMat.position.y *= -1;
frameGroup.add(botMat);

const sideMatW = matW / 2 - matThick / 2;
const leftMat = new THREE.Mesh(new THREE.BoxGeometry(matThick, matH - matThick * 2, matD), matMat);
leftMat.position.x = -(matW / 2 - matThick / 2);
frameGroup.add(leftMat);

const rightMat = leftMat.clone();
rightMat.position.x *= -1;
frameGroup.add(rightMat);

// Canvas / inner surface
const innerW = matW - matThick * 2, innerH = matH - matThick * 2;
const canvasGeo = new THREE.PlaneGeometry(innerW, innerH);
const canvasMesh = new THREE.Mesh(canvasGeo, canvasMat);
canvasMesh.position.z = -matD / 2 + 0.01;
frameGroup.add(canvasMesh);

// Glass overlay
const glassMat = new THREE.MeshPhysicalMaterial({
  color: 0xffffff,
  transparent: true,
  opacity: 0.08,
  roughness: 0.0,
  metalness: 0.0,
  transmission: 0.9,
  thickness: 0.02,
});
const glass = new THREE.Mesh(new THREE.PlaneGeometry(innerW, innerH), glassMat);
glass.position.z = D / 2 - 0.01;
frameGroup.add(glass);

// Backing
const backMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.9 });
const back = new THREE.Mesh(new THREE.PlaneGeometry(W - 0.1, H - 0.1), backMat);
back.position.z = -D / 2 - 0.01;
back.rotation.y = Math.PI;
frameGroup.add(back);

scene.add(frameGroup);

// Subtle floating animation
function animate() {
  requestAnimationFrame(animate);
  const t = performance.now() * 0.001;
  frameGroup.rotation.y = Math.sin(t * 0.5) * 0.15;
  frameGroup.rotation.x = Math.sin(t * 0.3) * 0.05;
  frameGroup.position.y = Math.sin(t * 0.8) * 0.1;
  controls.update();
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
