<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;

// ── Lights ──
scene.add(new THREE.AmbientLight(0xffeedd, 0.6));
const dir = new THREE.DirectionalLight(0xffffff, 1.5);
dir.position.set(3, 6, 4);
dir.castShadow = true;
dir.shadow.mapSize.set(1024, 1024);
scene.add(dir);
const rim = new THREE.DirectionalLight(0x4488ff, 0.4);
rim.position.set(-3, 2, -3);
scene.add(rim);

// ── Materials ──
const orange  = new THREE.MeshStandardMaterial({ color: 0xe87a2a, roughness: 0.7, flatShading: true });
const white   = new THREE.MeshStandardMaterial({ color: 0xf5f0e8, roughness: 0.8, flatShading: true });
const dark    = new THREE.MeshStandardMaterial({ color: 0x2a1a0a, roughness: 0.9, flatShading: true });
const noseMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.3, flatShading: true });

// ── Fox group ──
const fox = new THREE.Group();

// Body
const body = new THREE.Mesh(new THREE.DodecahedronGeometry(0.65, 1), orange);
body.scale.set(1, 0.75, 1.4);
body.position.set(0, 1.15, 0);
body.castShadow = true;
fox.add(body);

// Chest (white)
const chest = new THREE.Mesh(new THREE.SphereGeometry(0.45, 6, 5), white);
chest.scale.set(1, 0.85, 0.6);
chest.position.set(0, 1.05, 0.55);
fox.add(chest);

// Head
const head = new THREE.Mesh(new THREE.DodecahedronGeometry(0.45, 1), orange);
head.scale.set(1, 0.9, 1.05);
head.position.set(0, 1.7, 0.65);
head.castShadow = true;
fox.add(head);

// Snout
const snout = new THREE.Mesh(new THREE.ConeGeometry(0.18, 0.45, 5), orange);
snout.rotation.x = Math.PI / 2;
snout.position.set(0, 1.58, 1.05);
fox.add(snout);

// Nose tip
const nose = new THREE.Mesh(new THREE.SphereGeometry(0.06, 6, 4), noseMat);
nose.position.set(0, 1.58, 1.28);
fox.add(nose);

// Eyes
[-1, 1].forEach(s => {
  const eye = new THREE.Mesh(new THREE.SphereGeometry(0.055, 6, 4), dark);
  eye.position.set(s * 0.18, 1.78, 0.95);
  fox.add(eye);
  // Eye shine
  const shine = new THREE.Mesh(new THREE.SphereGeometry(0.02, 4, 3), white);
  shine.position.set(s * 0.18, 1.80, 0.99);
  fox.add(shine);
});

// Ears
[-1, 1].forEach(s => {
  const ear = new THREE.Mesh(new THREE.ConeGeometry(0.14, 0.35, 4), orange);
  ear.position.set(s * 0.25, 2.15, 0.55);
  ear.rotation.z = s * -0.3;
  ear.rotation.x = -0.15;
  ear.castShadow = true;
  fox.add(ear);
  // Inner ear
  const inner = new THREE.Mesh(new THREE.ConeGeometry(0.07, 0.22, 4), white);
  inner.position.set(s * 0.25, 2.13, 0.57);
  inner.rotation.z = s * -0.3;
  inner.rotation.x = -0.15;
  fox.add(inner);
});

// Cheek fluff (white patches)
[-1, 1].forEach(s => {
  const cheek = new THREE.Mesh(new THREE.SphereGeometry(0.15, 5, 4), white);
  cheek.scale.set(1, 0.6, 0.8);
  cheek.position.set(s * 0.3, 1.55, 0.85);
  fox.add(cheek);
});

// Legs
const legPositions = [
  [-0.28, 0.45, 0.35], [0.28, 0.45, 0.35],
  [-0.28, 0.45, -0.35], [0.28, 0.45, -0.35]
];
legPositions.forEach(([x, y, z]) => {
  const leg = new THREE.Mesh(new THREE.CylinderGeometry(0.09, 0.1, 0.55, 6), orange);
  leg.position.set(x, y, z);
  leg.castShadow = true;
  fox.add(leg);
  // Paw
  const paw = new THREE.Mesh(new THREE.SphereGeometry(0.1, 5, 4), white);
  paw.scale.set(1, 0.5, 1.2);
  paw.position.set(x, 0.18, z);
  fox.add(paw);
});

// Tail
const tailGroup = new THREE.Group();
tailGroup.position.set(0, 1.0, -0.55);

const tailBase = new THREE.Mesh(new THREE.ConeGeometry(0.22, 0.9, 6), orange);
tailBase.rotation.x = -0.6;
tailBase.castShadow = true;
tailGroup.add(tailBase);

const tailTip = new THREE.Mesh(new THREE.SphereGeometry(0.18, 6, 4), white);
tailTip.scale.set(1, 0.8, 1.3);
tailTip.position.set(0, 0.55, -0.35);
tailGroup.add(tailTip);

fox.add(tailGroup);

scene.add(fox);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(6, 32),
  new THREE.MeshStandardMaterial({ color: 0x2a3a2a, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Snow particles ──
const snowGeo = new THREE.BufferGeometry();
const snowCount = 300;
const snowPos = new Float32Array(snowCount * 3);
for (let i = 0; i < snowCount * 3; i += 3) {
  snowPos[i]     = (Math.random() - 0.5) * 12;
  snowPos[i + 1] = Math.random() * 8;
  snowPos[i + 2] = (Math.random() - 0.5) * 12;
}
snowGeo.setAttribute('position', new THREE.BufferAttribute(snowPos, 3));
const snowMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.04, transparent: true, opacity: 0.7 });
const snow = new THREE.Points(snowGeo, snowMat);
scene.add(snow);

// ── Animate ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle sway
  fox.rotation.y = Math.sin(t * 0.5) * 0.15;
  tailGroup.rotation.y = Math.sin(t * 1.5) * 0.25;

  // Snowfall
  const positions = snow.geometry.attributes.position.array;
  for (let i = 1; i < positions.length; i += 3) {
    positions[i] -= 0.008;
    if (positions[i] < 0) positions[i] = 8;
  }
  snow.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **A stylized low-poly fox** built entirely from Three.js primitives (dodecahedrons, cones, spheres, cylinders) — no external models needed
- **Orange & white coloring** matching a red fox (orange body, white chest/cheeks/paws/tail-tip, dark eyes & nose)
- **Gentle animations** — the fox idly sways side-to-side and its tail wags
- **Falling snow particles** for atmosphere
- **OrbitControls** — click and drag to rotate, scroll to zoom
- **Shadows & fog** for depth
- **Responsive** — handles window resizing

