  roughness: 0.6,
  side: THREE.DoubleSide,
});
const leaf = new THREE.Mesh(leafGeo, leafMat);
leaf.position.set(0.08, 1.12, 0);
leaf.rotation.set(0.3, -0.5, 0.4);
scene.add(leaf);

// --- Lighting ---
