scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 1.5);
keyLight.position.set(3, 5, 4);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.4);
fillLight.position.set(-3, 2, -2);
scene.add(fillLight);

