  apple.position.y = -0.1 + Math.sin(s * 1.2) * 0.08;
  stem.position.y = 0.95 + Math.sin(s * 1.2) * 0.08;
  leaf.position.y = 1.12 + Math.sin(s * 1.2) * 0.08;
