```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Galaxy</title>
<style>
  * { margin: 0; padding: 0; }
  body { overflow: hidden; background: #000; }
  canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── scene ── */
const scene  = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 1000);
camera.position.set(0, 18, 32);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

/* ── galaxy parameters ── */
const P = {
  count:        80_000,
  arms:         6,
  radius:       20,
  spin:         1.2,
  randomness:   0.5,
  randPower:    3,
  insideColor:  '#ff6030',
  outsideColor: '#1b3984'
};

const colorIn  = new THREE.Color(P.insideColor);
const colorOut = new THREE.Color(P.outsideColor);

const geo = new THREE.BufferGeometry();
const pos = new Float32Array(P.count * 3);
const col = new Float32Array(P.count * 3);
const sz  = new Float32Array(P.count);

for (let i = 0; i < P.count; i++) {
  const i3 = i * 3;

  const r   = Math.random() * P.radius;
  const spin = r * P.spin;
  const arm  = (i % P.arms) / P.arms * Math.PI * 2;

  const rx = Math.pow(Math.random(), P.randPower) * (Math.random() < .5 ? 1 : -1) * P.randomness * r;
  const ry = Math.pow(Math.random(), P.randPower) * (Math.random() < .5 ? 1 : -1) * P.randomness * r * .3;
  const rz = Math.pow(Math.random(), P.randPower) * (Math.random() < .5 ? 1 : -1) * P.randomness * r;

  pos[i3]     = Math.cos(arm + spin) * r + rx;
  pos[i3 + 1] = ry;
  pos[i3 + 2] = Math.sin(arm + spin) * r + rz;

  const c = colorIn.clone().lerp(colorOut, r / P.radius);
  const v = Math.random() * .15;
  col[i3]     = c.r + v;
  col[i3 + 1] = c.g + v * .5;
  col[i3 + 2] = c.b + v;

  sz[i] = Math.random() * .15 + .02;
}

geo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
geo.setAttribute('color',    new THREE.BufferAttribute(col, 3));
geo.setAttribute('size',     new THREE.BufferAttribute(sz, 1));

/* ── shader material (soft glowing sprites) ── */
const mat = new THREE.ShaderMaterial({
  vertexShader: /* glsl */ `
    attribute float size;
    varying vec3 vColor;
    void main() {
      vColor = color;
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      gl_PointSize = size * (300.0 / -mv.z);
      gl_Position  = projectionMatrix * mv;
    }
  `,
  fragmentShader: /* glsl */ `
    varying vec3 vColor;
    void main() {
      float d = length(gl_PointCoord - .5);
      if (d > .5) discard;
      float g = pow(1.0 - smoothstep(0.0, .5, d), 1.5);
      gl_FragColor = vec4(vColor, g);
    }
  `,
  transparent: true,
  vertexColors: true,
  depthWrite: false,
  blending: THREE.AdditiveBlending
});

const galaxy = new THREE.Points(geo, mat);
scene.add(galaxy);

/* ── central glow ── */
const glow = new THREE.Mesh(
  new THREE.SphereGeometry(1.5, 32, 32),
  new THREE.MeshBasicMaterial({ color: 0xffaa44, transparent: true, opacity: .3, blending: THREE.AdditiveBlending })
);
scene.add(glow);

/* ── background stars ── */
const bgGeo = new THREE.BufferGeometry();
const bgPos = new Float32Array(3000 * 3);
for (let i = 0; i < bgPos.length; i++) bgPos[i] = (Math.random() - .5) * 600;
bgGeo.setAttribute('position', new THREE.BufferAttribute(bgPos, 3));
scene.add(new THREE.Points(bgGeo, new THREE.PointsMaterial({ size: .3, color: 0xffffff, sizeAttenuation: true })));

/* ── animate ── */
const clock = new THREE.Clock();

(function loop() {
  requestAnimationFrame(loop);
  const t = clock.getElapsedTime();

  galaxy.rotation.y = t * .05;
  glow.scale.setScalar(1 + Math.sin(t * 2) * .1);

  controls.update();
  renderer.render(scene, camera);
})();

/* ── resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

| Feature | Detail |
|---|---|
| **80 000 stars** | Arranged in 6 logarithmic spiral arms with Gaussian scatter |
| **Custom GLSL shaders** | Soft circular sprites with radial falloff + additive blending |
| **Color gradient** | Warm orange/red core → cool blue outer arms with per-star variation |
| **Central glow** | Pulsating sphere at the galactic center |
| **Background stars** | 3 000 distant stars for depth |
| **OrbitControls** | Click-drag to orbit, scroll to zoom, right-drag to pan |
| **Responsive** | Adapts to window resize, capped at 2× pixel ratio for performance |

