```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Gate</title>
<style>body{margin:0;overflow:hidden;background:#000}</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.5, 0);
controls.enableDamping = true;

// Lights
scene.add(new THREE.AmbientLight(0x334466, 0.8));
const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -6;
dirLight.shadow.camera.right = 6;
dirLight.shadow.camera.top = 6;
dirLight.shadow.camera.bottom = -2;
scene.add(dirLight);

const pointLight = new THREE.PointLight(0xff6633, 2, 15);
pointLight.position.set(0, 4, 2);
scene.add(pointLight);

// Materials
const ironMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a35, metalness: 0.9, roughness: 0.3
});
const postMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a22, metalness: 0.7, roughness: 0.5
});
const finialMat = new THREE.MeshStandardMaterial({
  color: 0x444455, metalness: 0.95, roughness: 0.15
});
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, metalness: 0.1, roughness: 0.9
});

// Ground
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  groundMat
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Helper
function box(w, h, d, mat) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat);
  m.castShadow = true;
  m.receiveShadow = true;
  return m;
}

// Gate group
const gate = new THREE.Group();
const POST_W = 0.2, POST_H = 3.5, POST_D = 0.2;
const BAR_COUNT = 8, BAR_W = 0.04, BAR_H = 2.8, BAR_D = 0.04;
const RAIL_H = 0.08, RAIL_D = 0.06;
const SPACING = 0.5;

// Posts
for (const side of [-1, 1]) {
  const post = box(POST_W, POST_H, POST_D, postMat);
  post.position.set(side * (SPACING * (BAR_COUNT - 1) / 2 + 0.3), POST_H / 2, 0);
  gate.add(post);

  // Post cap / finial
  const finial = new THREE.Mesh(
    new THREE.ConeGeometry(0.15, 0.35, 6), finialMat
  );
  finial.position.set(post.position.x, POST_H + 0.17, 0);
  finial.castShadow = true;
  gate.add(finial);

  // Decorative scroll on post
  const scroll = new THREE.Mesh(
    new THREE.TorusGeometry(0.12, 0.025, 8, 12, Math.PI), finialMat
  );
  scroll.position.set(post.position.x, POST_H - 0.6, 0.12);
  scroll.rotation.y = side > 0 ? -Math.PI / 2 : Math.PI / 2;
  scroll.castShadow = true;
  gate.add(scroll);
}

// Top rail
const topRail = box(SPACING * (BAR_COUNT - 1) + 0.8, RAIL_H, RAIL_D, ironMat);
topRail.position.y = POST_H - 0.1;
gate.add(topRail);

// Middle rail
const midRail = box(SPACING * (BAR_COUNT - 1) + 0.8, RAIL_H, RAIL_D, ironMat);
midRail.position.y = POST_H * 0.5;
gate.add(midRail);

// Bottom rail
const botRail = box(SPACING * (BAR_COUNT - 1) + 0.8, RAIL_H, RAIL_D, ironMat);
botRail.position.y = 0.2;
gate.add(botRail);

// Vertical bars
for (let i = 0; i < BAR_COUNT; i++) {
  const bar = box(BAR_W, BAR_H, BAR_D, ironMat);
  bar.position.set(-SPACING * (BAR_COUNT - 1) / 2 + i * SPACING, BAR_H / 2 + 0.2, 0);
  gate.add(bar);
}

// Decorative center diamond
const diamond = new THREE.Mesh(
  new THREE.OctahedronGeometry(0.18, 0), finialMat
);
diamond.position.set(0, POST_H * 0.5, 0.1);
diamond.castShadow = true;
gate.add(diamond);

// Side chains (decorative)
for (const side of [-1, 1]) {
  for (let i = 0; i < 4; i++) {
    const link = new THREE.Mesh(
      new THREE.TorusGeometry(0.06, 0.015, 6, 8), finialMat
    );
    link.position.set(
      side * (SPACING * (BAR_COUNT - 1) / 2 + 0.15),
      POST_H * 0.5 + (i - 1.5) * 0.18,
      0.1
    );
    link.rotation.y = (i % 2) * Math.PI / 2;
    link.castShadow = true;
    gate.add(link);
  }
}

scene.add(gate);

// Floating particles
const particleCount = 60;
const particles = new THREE.Group();
for (let i = 0; i < particleCount; i++) {
  const p = new THREE.Mesh(
    new THREE.SphereGeometry(0.02, 4, 4),
    new THREE.MeshBasicMaterial({ color: 0xffaa44, transparent: true, opacity: 0.6 })
  );
  p.position.set(
    (Math.random() - 0.5) * 12,
    Math.random() * 6,
    (Math.random() - 0.5) * 12
  );
  p.userData.speed = 0.002 + Math.random() * 0.004;
  p.userData.y0 = p.position.y;
  p.userData.phase = Math.random() * Math.PI * 2;
  particles.add(p);
}
scene.add(particles);

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gate slowly opens/closes
  const swing = Math.sin(t * 0.3) * 0.4;
  gate.rotation.y = swing;
  gate.position.z = -Math.sin(swing) * 2.5;

  // Particles drift
  particles.children.forEach(p => {
    p.position.y = p.userData.y0 + Math.sin(t * p.userData.speed * 100 + p.userData.phase) * 0.5;
    p.position.x += Math.sin(t * 0.5 + p.userData.phase) * 0.001;
    p.material.opacity = 0.3 + 0.3 * Math.sin(t * 2 + p.userData.phase);
  });

  // Flicker point light
  pointLight.intensity = 2 + Math.sin(t * 5) * 0.5 + Math.sin(t * 13) * 0.3;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

