<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;

// --- Gear Shape Generator ---
function createGearShape(teeth, outerRadius, innerRadius, holeRadius) {
  const shape = new THREE.Shape();
  const step = (Math.PI * 2) / teeth;
  const halfTooth = step / 2;
  const ramp = halfTooth * 0.35;

  for (let i = 0; i < teeth; i++) {
    const a = i * step;
    // Valley start (inner radius)
    const a1 = a - halfTooth;
    const a2 = a - ramp;
    const a3 = a + ramp;
    const a4 = a + halfTooth;

    if (i === 0) {
      shape.moveTo(
        Math.cos(a1) * innerRadius,
        Math.sin(a1) * innerRadius
      );
    }

    // Ramp up to outer radius
    shape.lineTo(Math.cos(a2) * outerRadius, Math.sin(a2) * outerRadius);
    // Top of tooth (flat)
    shape.lineTo(Math.cos(a3) * outerRadius, Math.sin(a3) * outerRadius);
    // Ramp down
    shape.lineTo(Math.cos(a4) * innerRadius, Math.sin(a4) * innerRadius);

    // Valley arc
    shape.absarc(0, 0, innerRadius, a4, a + step - halfTooth, false);
  }

  // Center hole
  const holePath = new THREE.Path();
  holePath.absarc(0, 0, holeRadius, 0, Math.PI * 2, true);
  shape.holes.push(holePath);

  return shape;
}

// --- Build Gear ---
const gearShape = createGearShape(16, 1.8, 1.4, 0.5);
const extrudeSettings = {
  depth: 0.5,
  bevelEnabled: true,
  bevelThickness: 0.05,
  bevelSize: 0.05,
  bevelSegments: 3
};

const gearGeo = new THREE.ExtrudeGeometry(gearShape, extrudeSettings);
gearGeo.center();

const gearMat = new THREE.MeshStandardMaterial({
  color: 0x4a90d9,
  metalness: 0.7,
  roughness: 0.25,
});

const gear = new THREE.Mesh(gearGeo, gearMat);
gear.rotation.x = Math.PI / 2;
gear.castShadow = true;
gear.receiveShadow = true;
scene.add(gear);

// --- Second smaller gear (meshed) ---
const smallShape = createGearShape(12, 1.2, 0.92, 0.35);
const smallGeo = new THREE.ExtrudeGeometry(smallShape, extrudeSettings);
smallGeo.center();

const smallMat = new THREE.MeshStandardMaterial({
  color: 0xd94a4a,
  metalness: 0.7,
  roughness: 0.25,
});

const smallGear = new THREE.Mesh(smallGeo, smallMat);
smallGear.rotation.x = Math.PI / 2;
smallGear.position.set(2.7, 0, 0);
smallGear.castShadow = true;
smallGear.receiveShadow = true;
scene.add(smallGear);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x404060, 1);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffffff, 2);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
scene.add(dirLight);

const pointLight = new THREE.PointLight(0x4a90d9, 3, 20);
pointLight.position.set(-3, 2, 3);
scene.add(pointLight);

const rimLight = new THREE.PointLight(0xd94a4a, 2, 20);
rimLight.position.set(3, -2, -3);
scene.add(rimLight);

// --- Grid helper ---
const grid = new THREE.GridHelper(12, 24, 0x333355, 0x222244);
grid.position.y = -1.5;
scene.add(grid);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  gear.rotation.z = t * 0.5;
  smallGear.rotation.z = -t * 0.66; // meshed rotation (opposite direction, faster)

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
