```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Gem</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

// ——— Renderer ———
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ——— Scene & Camera ———
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);

const camera = new THREE.PerspectiveCamera(35, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0.5, 5);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// ——— Environment (for reflections/refractions) ———
const pmrem = new THREE.PMREMGenerator(renderer);
const envMap = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
scene.environment = envMap;

// ——— Gem Geometry (brilliant-cut diamond shape) ———
function createGemGeometry() {
  const tableR   = 0.35;   // top flat face radius
  const crownR   = 1.0;    // girdle radius
  const crownH   = 0.35;   // crown height
  const pavH     = 0.85;   // pavilion height
  const segments = 8;      // facets per ring

  const vertices = [];
  const indices  = [];

  // Helper: ring of vertices
  function ring(radius, y, count, offset = 0) {
    const verts = [];
    for (let i = 0; i < count; i++) {
      const a = (i / count) * Math.PI * 2 + offset;
      verts.push(new THREE.Vector3(Math.cos(a) * radius, y, Math.sin(a) * radius));
    }
    return verts;
  }

  // Vertices
  const topCenter  = new THREE.Vector3(0, crownH, 0);
  const tableRing  = ring(tableR, crownH, segments);
  const crownRing  = ring(crownR, 0, segments, 0);
  const crownRing2 = ring(crownR, 0, segments, Math.PI / segments);
  const pavMid     = ring(crownR * 0.3, -pavH * 0.5, segments, Math.PI / segments);
  const bottomTip  = new THREE.Vector3(0, -pavH, 0);

  const allVerts = [topCenter, ...tableRing, ...crownRing, ...crownRing2, ...pavMid, bottomTip];
  const n = segments;

  // Face: topCenter → table ring
  for (let i = 0; i < n; i++) {
    const a = 0, b = 1 + i, c = 1 + (i + 1) % n;
    indices.push(a, b, c);
  }

  // Crown: table ring → crown ring (two tris per segment for offset)
  for (let i = 0; i < n; i++) {
    const t  = 1 + i;
    const t2 = 1 + (i + 1) % n;
    const c  = 1 + n + i;
    const c2 = 1 + n + (i + 1) % n;
    indices.push(t, c, t2);
    indices.push(t2, c, c2);
  }

  // Lower crown: crown ring → crown ring 2 (girdle facet bands)
  for (let i = 0; i < n; i++) {
    const a = 1 + n + i;
    const b = 1 + n + (i + 1) % n;
    const c = 1 + 2 * n + i;
    indices.push(a, c, b);
  }

  // Pavilion: crown ring 2 → pavilion mid
  for (let i = 0; i < n; i++) {
    const a = 1 + 2 * n + i;
    const b = 1 + 2 * n + (i + 1) % n;
    const c = 1 + 3 * n + i;
    const d = 1 + 3 * n + (i + 1) % n;
    indices.push(a, c, b);
    indices.push(b, c, d);
  }

  // Bottom: pavilion mid → bottom tip
  for (let i = 0; i < n; i++) {
    const a = 1 + 3 * n + i;
    const b = 1 + 3 * n + (i + 1) % n;
    indices.push(allVerts.length - 1, b, a);
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(allVerts.map(v => [v.x, v.y, v.z]).flat(), 3));
  geo.setIndex(indices);
  geo.computeVertexNormals();
  return geo;
}

// ——— Gem Material ———
const gemMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x88ccff,
  metalness: 0.0,
  roughness: 0.0,
  transmission: 0.97,
  thickness: 1.5,
  ior: 2.42,                  // diamond IOR
  clearcoat: 1.0,
  clearcoatRoughness: 0.0,
  envMapIntensity: 2.0,
  attenuationColor: new THREE.Color(0xaaddff),
  attenuationDistance: 2.0,
  specularIntensity: 1.0,
  specularColor: new THREE.Color(0xffffff),
  transparent: true,
  opacity: 0.95,
});

const gem = new THREE.Mesh(createGemGeometry(), gemMaterial);
scene.add(gem);

// ——— Inner glow (slightly smaller solid core) ———
const glowMat = new THREE.MeshPhysicalMaterial({
  color: 0x6699cc,
  emissive: 0x112244,
  emissiveIntensity: 0.3,
  metalness: 0,
  roughness: 0.1,
  transparent: true,
  opacity: 0.15,
});
const glowMesh = new THREE.Mesh(createGemGeometry(), glowMat);
glowMesh.scale.setScalar(0.98);
gem.add(glowMesh);

// ——— Lighting ———
const keyLight = new THREE.PointLight(0xffffff, 80, 20);
keyLight.position.set(2, 3, 2);
scene.add(keyLight);

const fillLight = new THREE.PointLight(0x8888ff, 40, 20);
fillLight.position.set(-3, 1, -1);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff8866, 50, 20);
rimLight.position.set(0, -2, -3);
scene.add(rimLight);

const topLight = new THREE.PointLight(0xffffff, 30, 20);
topLight.position.set(0, 5, 0);
scene.add(topLight);

// ——— Sparkle particles ———
const sparkleCount = 60;
const sparkleGeo = new THREE.BufferGeometry();
const sparklePos = new Float32Array(sparkleCount * 3);
for (let i = 0; i < sparkleCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi   = Math.acos(2 * Math.random() - 1);
  const r     = 1.5 + Math.random() * 2.0;
  sparklePos[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
  sparklePos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
  sparklePos[i * 3 + 2] = r * Math.cos(phi);
}
sparkleGeo.setAttribute('position', new THREE.Float32BufferAttribute(sparklePos, 3));

const sparkleMat = new THREE.PointsMaterial({
  color: 0xaaccff,
  size: 0.03,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
});
const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
scene.add(sparkles);

// ——— Animation ———
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  gem.rotation.y = t * 0.3;
  sparkles.rotation.y = -t * 0.1;
  sparkles.rotation.x = Math.sin(t * 0.2) * 0.1;

  // Twinkle sparkles
  sparkleMat.opacity = 0.3 + Math.sin(t * 2) * 0.2;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ——— Resize ———
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What you get

| Feature | Detail |
|---|---|
| **Gem shape** | Custom brilliant-cut diamond geometry with table, crown, girdle, pavilion, and culet — all faceted |
| **Material** | `MeshPhysicalMaterial` with **transmission**, **IOR 2.42** (real diamond), clearcoat, and attenuation color for realistic light refraction |
| **Environment** | `RoomEnvironment` via PMREM gives the gem realistic reflections and refractions |
| **Lighting** | 4 point lights (key, fill, rim, top) in different colors for fire/scintillation |
| **Sparkles** | Floating particle ring with gentle twinkle animation |
| **Interaction** | `OrbitControls` with damping — drag to rotate, scroll to zoom |
| **Animation** | Slow Y-axis rotation of the gem + gentle sparkle drift |

