const backLight = new THREE.PointLight(0x6644aa, 1.5, 15);
backLight.position.set(0, 1, -3);
scene.add(backLight);

// --- Ghost Group ---
const ghost = new THREE.Group();
scene.add(ghost);

// --- Ghost Body via LatheGeometry ---
const points = [];
const segments = 40;
for (let i = 0; i <= segments; i++) {
  const t = i / segments;
  let x, y;
  if (t < 0.35) {
    // Top dome
    const angle = Math.PI * (0.5 - t / 0.35) * 0.5;
    x = Math.sin(angle) * 1.1;
    y = Math.cos(angle) * 0.9 + 1.5;
  } else if (t < 0.7) {
    // Straight-ish body
    const lt = (t - 0.35) / 0.35;
    x = 1.1 - lt * 0.15;
    y = 1.5 - lt * 1.2;
  } else {
    // Bottom taper
    const lt = (t - 0.7) / 0.3;
    x = 0.95 * (1 - lt * 0.6);
    y = 0.3 - lt * 0.3;
  }
  points.push(new THREE.Vector2(x, y));
}

const bodyGeo = new THREE.LatheGeometry(points, 32);
const bodyMat = new THREE.MeshPhysicalMaterial({
  color: 0xeef4ff,
  transparent: true,
  opacity: 0.85,
  roughness: 0.1,
  metalness: 0.0,
  transmission: 0.3,
  thickness: 0.5,
  emissive: 0x4466aa,
  emissiveIntensity: 0.08,
  side: THREE.DoubleSide,
});
const body = new THREE.Mesh(bodyGeo, bodyMat);
ghost.add(body);

// --- Wavy Bottom ---
const waveSegments = 12;
const waveGroup = new THREE.Group();
ghost.add(waveGroup);

for (let i = 0; i < waveSegments; i++) {
  const angle = (i / waveSegments) * Math.PI * 2;
  const radius = 0.57;
  const x = Math.cos(angle) * radius;
  const z = Math.sin(angle) * radius;
  const y = 0.0 + Math.sin(angle * 3) * 0.12;

  const dropGeo = new THREE.SphereGeometry(0.12, 12, 12);
  const drop = new THREE.Mesh(dropGeo, bodyMat);
  drop.position.set(x, y, z);
  drop.scale.y = 1.4;
  waveGroup.add(drop);
}

// --- Eyes ---
const eyeMat = new THREE.MeshBasicMaterial({ color: 0x111122 });
const eyeGlowMat = new THREE.MeshBasicMaterial({ color: 0xaaccff });

function createEye(side) {
  const group = new THREE.Group();
  const eyeGeo = new THREE.SphereGeometry(0.13, 16, 16);
  const eye = new THREE.Mesh(eyeGeo, eyeMat);
  group.add(eye);

  const glowGeo = new THREE.SphereGeometry(0.06, 16, 16);
  const glow = new THREE.Mesh(glowGeo, eyeGlowMat);
  glow.position.z = 0.08;
  group.add(glow);

  group.position.set(side * 0.32, 0.95, 0.85);
  group.rotation.z = side * 0.15;
  return group;
}

ghost.add(createEye(-1));
ghost.add(createEye(1));

// --- Mouth ---
const mouthCurve = new THREE.EllipseCurve(0, 0, 0.12, 0.08, Math.PI * 0.1, Math.PI * 0.9, false);
const mouthPoints = mouthCurve.getPoints(20);
const mouthGeo = new THREE.BufferGeometry().setFromPoints(mouthPoints);
const mouthMat = new THREE.LineBasicMaterial({ color: 0x111122, linewidth: 2 });
const mouth = new THREE.Line(mouthGeo, mouthMat);
mouth.position.set(0, 0.65, 0.92);
ghost.add(mouth);

// --- Aura / Glow Sphere ---
const auraGeo = new THREE.SphereGeometry(1.8, 32, 32);
const auraMat = new THREE.MeshBasicMaterial({
  color: 0x6688cc,
  transparent: true,
  opacity: 0.06,
  side: THREE.BackSide,
});
const aura = new THREE.Mesh(auraGeo, auraMat);
ghost.add(aura);

// --- Floating Particles ---
const particleCount = 80;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const sizes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 10;
  positions[i * 3 + 1] = Math.random() * 8 - 2;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 10;
  sizes[i] = Math.random() * 3 + 1;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.PointsMaterial({
  color: 0x8899cc,
  size: 0.05,
  transparent: true,
  opacity: 0.5,
  sizeAttenuation: true,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Floor ---
const floorGeo = new THREE.PlaneGeometry(30, 30);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x111122,
  roughness: 0.8,
  metalness: 0.2,
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -1.5;
scene.add(floor);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Float
  ghost.position.y = Math.sin(t * 1.2) * 0.4 + 1.2;
  ghost.rotation.y = Math.sin(t * 0.5) * 0.15;
  ghost.rotation.z = Math.sin(t * 0.7) * 0.03;

  // Light follows ghost
  ghostLight.position.y = ghost.position.y + 0.5;
  ghostLight.intensity = 2 + Math.sin(t * 2) * 0.3;

  // Pulse aura
  aura.scale.setScalar(1 + Math.sin(t * 1.5) * 0.05);
  auraMat.opacity = 0.05 + Math.sin(t * 2) * 0.02;

  // Animate particles
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(t + i) * 0.001;
    if (pos.array[i * 3 + 1] > 6) pos.array[i * 3 + 1] = -2;
  }
  pos.needsUpdate = true;

  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
