const shoulderGeo = new THREE.CylinderGeometry(0.032, 0.032, 0.3, 12);
const leftShoulder = new THREE.Mesh(shoulderGeo, hangerMat);
leftShoulder.position.set(-1.15, 1.6, 0);
leftShoulder.rotation.z = Math.PI / 2 + 0.15;
leftShoulder.castShadow = true;
hanger.add(leftShoulder);

const rightShoulder = new THREE.Mesh(shoulderGeo.clone(), hangerMat);
rightShoulder.position.set(1.15, 1.6, 0);
rightShoulder.rotation.z = -Math.PI / 2 - 0.15;
rightShoulder.castShadow = true;
hanger.add(rightShoulder);

// Gentle sway animation offset
hanger.position.y = 0;
scene.add(hanger);

// --- Floor ---
const floorGeo = new THREE.CircleGeometry(8, 64);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x111122,
  metalness: 0.3,
  roughness: 0.8,
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -1.5;
floor.receiveShadow = true;
scene.add(floor);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  hanger.rotation.z = Math.sin(t * 0.8) * 0.03;
  hanger.rotation.x = Math.sin(t * 0.5) * 0.015;
  hanger.position.y = Math.sin(t * 1.2) * 0.02;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
