bellyGeo.scale(1, 0.7, 0.55);
const belly = new THREE.Mesh(bellyGeo, bellyMat);
belly.position.set(0, 0.75, 0.3);
hamster.add(belly);

// Head
const headGeo = new THREE.SphereGeometry(0.65, 32, 32);
headGeo.scale(1, 0.9, 0.85);
const head = new THREE.Mesh(headGeo, furMat);
head.position.set(0, 1.55, 0.55);
head.castShadow = true;
hamster.add(head);

// Cheeks (puffy!)
const cheekGeo = new THREE.SphereGeometry(0.35, 16, 16);
cheekGeo.scale(1, 0.7, 0.6);
const leftCheek = new THREE.Mesh(cheekGeo, furMat);
leftCheek.position.set(-0.5, 1.4, 0.65);
hamster.add(leftCheek);
const rightCheek = new THREE.Mesh(cheekGeo, furMat);
rightCheek.position.set(0.5, 1.4, 0.65);
hamster.add(rightCheek);

// Snout
const snoutGeo = new THREE.SphereGeometry(0.2, 16, 16);
snoutGeo.scale(1.2, 0.8, 0.8);
const snout = new THREE.Mesh(snoutGeo, bellyMat);
snout.position.set(0, 1.35, 0.95);
hamster.add(snout);

// Nose
const noseGeo = new THREE.SphereGeometry(0.06, 16, 16);
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.set(0, 1.38, 1.15);
hamster.add(nose);

// Eyes
const eyeGeo = new THREE.SphereGeometry(0.08, 16, 16);
const leftEye = new THREE.Mesh(eyeGeo, eyeMat);
leftEye.position.set(-0.28, 1.65, 0.95);
hamster.add(leftEye);
const rightEye = new THREE.Mesh(eyeGeo, eyeMat);
rightEye.position.set(0.28, 1.65, 0.95);
