hamster.add(leftShine);
const rightShine = new THREE.Mesh(shineGeo, shineMat);
rightShine.position.set(0.30, 1.68, 1.01);
hamster.add(rightShine);

// Ears
const earGeo = new THREE.SphereGeometry(0.18, 16, 16);
earGeo.scale(1, 0.6, 0.7);
const leftEar = new THREE.Mesh(earGeo, furMat);
leftEar.position.set(-0.4, 2.05, 0.35);
leftEar.rotation.z = 0.3;
hamster.add(leftEar);
const rightEar = new THREE.Mesh(earGeo, furMat);
rightEar.position.set(0.4, 2.05, 0.35);
rightEar.rotation.z = -0.3;
hamster.add(rightEar);

// Inner ears
const innerEarGeo = new THREE.SphereGeometry(0.1, 16, 16);
innerEarGeo.scale(1, 0.6, 0.6);
const leftInnerEar = new THREE.Mesh(innerEarGeo, earInnerMat);
leftInnerEar.position.set(-0.4, 2.05, 0.42);
