hamster.add(leftInnerEar);
const rightInnerEar = new THREE.Mesh(innerEarGeo, earInnerMat);
rightInnerEar.position.set(0.4, 2.05, 0.42);
rightInnerEar.rotation.z = -0.3;
hamster.add(rightInnerEar);

// Whiskers
function createWhisker(start, end, parent) {
  const points = [new THREE.Vector3(...start), new THREE.Vector3(...end)];
  const geo = new THREE.BufferGeometry().setFromPoints(points);
  return new THREE.Line(geo, whiskerMat);
}

const whiskers = [];
const whiskerData = [
  [[-0.25, 1.38, 1.1], [-0.7, 1.35, 1.2]],
  [[-0.25, 1.38, 1.1], [-0.75, 1.38, 1.15]],
  [[-0.25, 1.38, 1.1], [-0.7, 1.42, 1.1]],
