  [[0.25, 1.38, 1.1], [0.75, 1.38, 1.15]],
  [[0.25, 1.38, 1.1], [0.7, 1.42, 1.1]],
];
whiskerData.forEach(([s, e]) => {
  const w = createWhisker(s, e, hamster);
  hamster.add(w);
  whiskers.push(w);
});

// Front paws
const pawGeo = new THREE.SphereGeometry(0.15, 16, 16);
pawGeo.scale(0.8, 0.6, 1);
