  const seed = new THREE.Mesh(seedGeo, seedMat);
  const angle = Math.random() * Math.PI * 2;
  const radius = 0.5 + Math.random() * 1.2;
  seed.position.set(Math.cos(angle) * radius, 0.02, Math.sin(angle) * radius);
  seed.rotation.y = Math.random() * Math.PI;
  seed.castShadow = true;
  scene.add(seed);
}

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle breathing
  body.scale.y = 0.85 + Math.sin(t * 2) * 0.02;
  body.scale.x = 1 + Math.sin(t * 2) * 0.01;
  head.position.y = 1.55 + Math.sin(t * 2) * 0.02;

  // Slight head bob
  head.rotation.z = Math.sin(t * 1.5) * 0.03;
  head.rotation.x = Math.sin(t * 0.8) * 0.02;

  // Ear twitch
  leftEar.rotation.z = 0.3 + Math.sin(t * 3) * 0.08;
  rightEar.rotation.z = -0.3 + Math.sin(t * 3 + 1) * 0.08;

  // Whisker twitch
  whiskers.forEach((w, i) => {
    w.rotation.z = Math.sin(t * 4 + i * 0.5) * 0.05;
  });

  // Paw wiggle
  leftPaw.rotation.z = Math.sin(t * 3) * 0.1;
  rightPaw.rotation.z = -Math.sin(t * 3 + 0.5) * 0.1;

  // Tail wag
  tail.rotation.z = Math.sin(t * 5) * 0.2;

  // Eye blink
  const blinkCycle = t % 4;
  const blinkAmount = blinkCycle < 0.1 ? Math.sin(blinkCycle / 0.1 * Math.PI) : 0;
  leftEye.scale.y = 1 - blinkAmount * 0.8;
  rightEye.scale.y = 1 - blinkAmount * 0.8;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
