brimProfile.push(new THREE.Vector2(0.75, 0.0));
brimProfile.push(new THREE.Vector2(0.75, 0.06));
brimProfile.push(new THREE.Vector2(0.8, 0.12));
brimProfile.push(new THREE.Vector2(1.2, 0.18));
brimProfile.push(new THREE.Vector2(1.6, 0.14));
brimProfile.push(new THREE.Vector2(1.85, 0.06));
brimProfile.push(new THREE.Vector2(1.95, 0.02));
brimProfile.push(new THREE.Vector2(1.95, -0.02));
brimProfile.push(new THREE.Vector2(1.85, -0.06));
brimProfile.push(new THREE.Vector2(1.6, -0.10));
brimProfile.push(new THREE.Vector2(1.2, -0.10));
