</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0008);
scene.fog = new THREE.FogExp2(0x0a0008, 0.02);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0, 30);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.autoRotate = true;
controls.autoRotateSpeed = 1.5;

// ── Heart Shape (2D profile revolved into 3D) ──
function createHeartGeometry() {
  const shape = new THREE.Shape();
  const s = 0.9;

  // Heart outline using bezier curves
  shape.moveTo(0, 2.5 * s);
  shape.bezierCurveTo(0, 2.5 * s, -0.5 * s, 3.5 * s, -2 * s, 3.5 * s);
  shape.bezierCurveTo(-4.5 * s, 3.5 * s, -5.5 * s, 1.5 * s, -5.5 * s, 0);
  shape.bezierCurveTo(-5.5 * s, -2.5 * s, -3 * s, -5.5 * s, 0, -8 * s);
  shape.bezierCurveTo(3 * s, -5.5 * s, 5.5 * s, -2.5 * s, 5.5 * s, 0);
  shape.bezierCurveTo(5.5 * s, 1.5 * s, 4.5 * s, 3.5 * s, 2 * s, 3.5 * s);
  shape.bezierCurveTo(0.5 * s, 3.5 * s, 0, 2.5 * s, 0, 2.5 * s);

  const extrudeSettings = {
    depth: 2.5 * s,
    bevelEnabled: true,
    bevelThickness: 1.2 * s,
    bevelSize: 1.0 * s,
    bevelOffset: 0,
    bevelSegments: 16,
    curveSegments: 32,
  };

  return new THREE.ExtrudeGeometry(shape, extrudeSettings);
}

// ── Heart Mesh ──
const geometry = createHeartGeometry();
geometry.center();

const material = new THREE.MeshPhysicalMaterial({
  color: 0xcc1133,
  emissive: 0x330011,
  metalness: 0.1,
  roughness: 0.35,
  clearcoat: 0.8,
  clearcoatRoughness: 0.2,
  reflectivity: 0.6,
});

const heart = new THREE.Mesh(geometry, material);
scene.add(heart);

// ── Particle Sparkles ──
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const sizes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.acos(2 * Math.random() - 1);
  const r = 8 + Math.random() * 12;
  positions[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
  positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
  positions[i * 3 + 2] = r * Math.cos(phi);
  sizes[i] = Math.random() * 2 + 0.5;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.PointsMaterial({
  color: 0xff4466,
  size: 0.3,
  transparent: true,
  opacity: 0.6,
  blending: THREE.AdditiveBlending,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x220011, 0.8);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xff6688, 3);
keyLight.position.set(5, 5, 8);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0xff2244, 1.5);
fillLight.position.set(-5, -2, 5);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xff8899, 2);
rimLight.position.set(0, 5, -5);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xff0033, 2, 30);
pointLight.position.set(0, 0, 5);
scene.add(pointLight);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Pulse
  const pulse = 1 + Math.sin(t * 2) * 0.06;
  heart.scale.setScalar(pulse);

  // Emissive glow pulse
  material.emissiveIntensity = 0.3 + Math.sin(t * 2) * 0.2;

  // Particles gentle rotation
  particles.rotation.y = t * 0.05;
  particles.rotation.x = Math.sin(t * 0.03) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's in there:**

- **3D Heart** — built from a Bézier-curve `Shape` extruded with rounded bevel for a smooth, organic look
- **`MeshPhysicalMaterial`** — red with clearcoat for a glossy, slightly metallic sheen
- **Pulsing animation** — the heart gently beats (`scale` oscillation) and its emissive glow pulses in sync
- **4-point lighting** — key, fill, rim, and a central point light for rich red tones
- **Floating particles** — soft glowing dots orbiting around the heart with additive blending
- **OrbitControls** — drag to rotate, scroll to zoom, with auto-rotation and damping
- **Responsive** — handles window resizing cleanly

Just save it as `index.html` and open in any modern browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Headphone — Three.js</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #0a0a0f; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x0a0a0f, 0.04);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.target.set(0, 0.5, 0);

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x334466, 0.8);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(4, 6, 4);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
scene.add(key);

const fill = new THREE.DirectionalLight(0x4488ff, 1.0);
fill.position.set(-5, 3, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff6633, 1.5, 15);
rim.position.set(0, -2, -5);
scene.add(rim);

// ── Materials ──
const matBand   = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 0.3, metalness: 0.8 });
const matCup    = new THREE.MeshStandardMaterial({ color: 0x16213e, roughness: 0.25, metalness: 0.7 });
const matCush   = new THREE.MeshStandardMaterial({ color: 0x0f0f1a, roughness: 0.9, metalness: 0.0 });
const matAccent = new THREE.MeshStandardMaterial({ color: 0x0e2a4a, roughness: 0.2, metalness: 0.9 });
const matPad    = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 0.85, metalness: 0.1 });
const matInner  = new THREE.MeshStandardMaterial({ color: 0x0a0a14, roughness: 0.95, metalness: 0.0 });
const matGlow   = new THREE.MeshStandardMaterial({ color: 0x00ccff, emissive: 0x00aaff, emissiveIntensity: 0.6, roughness: 0.3, metalness: 0.5 });

// ── Headphone Group ──
const headphones = new THREE.Group();

// ── Headband (tube along an arc) ──
const bandCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-2.2, -0.2, 0),
  new THREE.Vector3(-2.1, 0.6, 0),
  new THREE.Vector3(-1.7, 1.4, 0),
  new THREE.Vector3(-1.0, 2.0, 0),
  new THREE.Vector3(0, 2.25, 0),
  new THREE.Vector3(1.0, 2.0, 0),
  new THREE.Vector3(1.7, 1.4, 0),
  new THREE.Vector3(2.1, 0.6, 0),
  new THREE.Vector3(2.2, -0.2, 0),
]);
const bandGeo = new THREE.TubeGeometry(bandCurve, 48, 0.12, 16, false);
const band = new THREE.Mesh(bandGeo, matBand);
band.castShadow = true;
headphones.add(band);

// ── Inner padding on headband ──
const padCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-1.8, 0.2, 0),
  new THREE.Vector3(-1.4, 1.1, 0),
  new THREE.Vector3(-0.7, 1.75, 0),
  new THREE.Vector3(0, 1.95, 0),
  new THREE.Vector3(0.7, 1.75, 0),
  new THREE.Vector3(1.4, 1.1, 0),
  new THREE.Vector3(1.8, 0.2, 0),
]);
const padGeo = new THREE.TubeGeometry(padCurve, 32, 0.18, 12, false);
const pad = new THREE.Mesh(padGeo, matPad);
pad.position.y = -0.06;
headphones.add(pad);

// ── Ear cup builder ──
function buildEarCup(side) {
  const g = new THREE.Group();
  const x = side * 2.2;

  // Vertical slider arm
  const armGeo = new THREE.CylinderGeometry(0.06, 0.06, 1.6, 12);
  const arm = new THREE.Mesh(armGeo, matBand);
  arm.position.set(x, 0.2, 0);
  arm.castShadow = true;
  g.add(arm);

  // Slider notches (decorative)
  for (let i = 0; i < 5; i++) {
    const notchGeo = new THREE.TorusGeometry(0.075, 0.015, 8, 16);
    const notch = new THREE.Mesh(notchGeo, matAccent);
    notch.position.set(x, -0.1 + i * 0.28, 0);
    notch.rotation.y = Math.PI / 2;
    g.add(notch);
  }

  // Yoke / fork that holds the cup
  const yokeGeo = new THREE.BoxGeometry(0.08, 0.5, 0.08);
  const yoke = new THREE.Mesh(yokeGeo, matBand);
  yoke.position.set(x, -0.6, 0);
  yoke.castShadow = true;
  g.add(yoke);

  // Yoke wings (left and right of cup axis)
  for (const w of [-1, 1]) {
    const wingGeo = new THREE.BoxGeometry(0.06, 0.15, 0.35);
    const wing = new THREE.Mesh(wingGeo, matBand);
    wing.position.set(x + w * 0.12, -0.65, 0);
    g.add(wing);
  }

  // Main ear cup shell (flattened cylinder)
  const cupGeo = new THREE.CylinderGeometry(0.85, 0.85, 0.45, 32);
  const cup = new THREE.Mesh(cupGeo, matCup);
  cup.position.set(x, -0.85, 0);
  cup.rotation.z = Math.PI / 2;
  cup.castShadow = true;
  g.add(cup);

  // Outer cup face (slightly domed disc)
  const outerGeo = new THREE.SphereGeometry(0.82, 32, 16, 0, Math.PI * 2, 0, Math.PI * 0.3);
  const outer = new THREE.Mesh(outerGeo, matCup);
  outer.position.set(x + side * 0.18, -0.85, 0);
  outer.rotation.z = side > 0 ? -Math.PI / 2 : Math.PI / 2;
  g.add(outer);

  // Accent ring on outer face
  const ringGeo = new THREE.TorusGeometry(0.55, 0.025, 12, 48);
  const ring = new THREE.Mesh(ringGeo, matAccent);
  ring.position.set(x + side * 0.21, -0.85, 0);
  ring.rotation.y = Math.PI / 2;
  g.add(ring);

  // LED indicator dot
  const ledGeo = new THREE.SphereGeometry(0.03, 12, 12);
  const led = new THREE.Mesh(ledGeo, matGlow);
  led.position.set(x + side * 0.22, -0.6, 0.35);
  g.add(led);

  // Inner ear cushion (torus-like shape)
  const cushionGeo = new THREE.TorusGeometry(0.65, 0.2, 16, 32);
  const cushion = new THREE.Mesh(cushionGeo, matCush);
  cushion.position.set(x - side * 0.22, -0.85, 0);
  cushion.rotation.y = Math.PI / 2;
  g.add(cushion);

  // Inner driver cover (perforated look via ring pattern)
  const driverGeo = new THREE.CylinderGeometry(0.55, 0.55, 0.02, 32);
  const driver = new THREE.Mesh(driverGeo, matInner);
  driver.position.set(x - side * 0.23, -0.85, 0);
  driver.rotation.z = Math.PI / 2;
  g.add(driver);

  // Small inner rings for detail
  for (let r = 0; r < 3; r++) {
    const dRingGeo = new THREE.TorusGeometry(0.15 + r * 0.13, 0.012, 8, 24);
    const dRing = new THREE.Mesh(dRingGeo, matAccent);
    dRing.position.set(x - side * 0.24, -0.85, 0);
    dRing.rotation.y = Math.PI / 2;
    g.add(dRing);
  }

  return g;
}

headphones.add(buildEarCup(1));   // right
headphones.add(buildEarCup(-1));  // left

// ── Position & scale ──
headphones.position.y = 0.3;
scene.add(headphones);

// ── Ground (subtle) ──
const groundGeo = new THREE.PlaneGeometry(30, 30);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x0a0a0f, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating particles ──
const pCount = 200;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(pCount * 3);
for (let i = 0; i < pCount; i++) {
  pPos[i * 3]     = (Math.random() - 0.5) * 20;
  pPos[i * 3 + 1] = (Math.random() - 0.5) * 12;
  pPos[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const pMat = new THREE.PointsMaterial({ color: 0x4488ff, size: 0.03, transparent: true, opacity: 0.5 });
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// ── Animate ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  headphones.rotation.y = Math.sin(t * 0.3) * 0.3;
  headphones.position.y = 0.3 + Math.sin(t * 0.5) * 0.15;

  particles.rotation.y = t * 0.02;
  particles.rotation.x = Math.sin(t * 0.1) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's inside:**

| Part | Geometry | Material |
|---|---|---|
| **Headband** | `TubeGeometry` along a `CatmullRomCurve3` arc | Dark metallic |
| **Inner headpad** | Softer, wider `TubeGeometry` beneath the band | Matte dark |
| **Slider arms** | `CylinderGeometry` with decorative `TorusGeometry` notches | Metallic |
| **Yoke/fork** | `BoxGeometry` pieces connecting arm → cup | Dark metallic |
| **Ear cup shell** | `CylinderGeometry` (rotated sideways) + domed `SphereGeometry` cap | Dark metallic |
| **Accent ring** | `TorusGeometry` on the outer face | Blue-tinted metal |
| **LED indicator** | Small glowing `SphereGeometry` | Emissive cyan |
| **Ear cushion** | `TorusGeometry` facing inward | Soft matte black |
| **Driver detail** | Concentric `TorusGeometry` rings on the inner face | Metallic accent |

**Features:** orbit controls, damped rotation, gentle floating animation, fog, particles, ACES tone mapping, and soft shadows — all in a single file with no build step.

