        cap.scale.y = 1.3;
        helmet.add(cap);

        // -- Brow ridge --
        const browGeo = new THREE.TorusGeometry(0.95, 0.08, 16, 64, Math.PI);
        const brow = new THREE.Mesh(browGeo, metalMat);
        brow.rotation.x = Math.PI / 2;
        brow.rotation.z = Math.PI;
        brow.position.set(0, 0.25, 0.55);
        helmet.add(brow);

        // -- Visor / front face plate --
        const visorGroup = new THREE.Group();

        const facePlateShape = new THREE.Shape();
        facePlateShape.moveTo(-0.6, -0.4);
        facePlateShape.lineTo(-0.55, 0.35);
        facePlateShape.quadraticCurveTo(0, 0.55, 0.55, 0.35);
        facePlateShape.lineTo(0.6, -0.4);
        facePlateShape.quadraticCurveTo(0, -0.55, -0.6, -0.4);

        const facePlateGeo = new THREE.ExtrudeGeometry(facePlateShape, {
            depth: 0.06,
            bevelEnabled: true,
            bevelThickness: 0.02,
            bevelSize: 0.02,
            bevelSegments: 3
        });
        const facePlate = new THREE.Mesh(facePlateGeo, metalMat);
        facePlate.position.set(0, 0.35, 0.88);
        visorGroup.add(facePlate);

        // -- Eye slit (cross shape) --
        const eyeSlitH = new THREE.Mesh(
            new THREE.BoxGeometry(0.7, 0.06, 0.12),
            innerMat
        );
        eyeSlitH.position.set(0, 0.5, 0.95);
        visorGroup.add(eyeSlitH);

        const eyeSlitV = new THREE.Mesh(
            new THREE.BoxGeometry(0.06, 0.45, 0.12),
            innerMat
        );
        eyeSlitV.position.set(0, 0.5, 0.95);
        visorGroup.add(eyeSlitV);

        // -- Nose guard (ridge) --
        const noseRidgeGeo = new THREE.BoxGeometry(0.08, 0.35, 0.1);
        const noseRidge = new THREE.Mesh(noseRidgeGeo, metalMat);
        noseRidge.position.set(0, 0.35, 0.96);
        visorGroup.add(noseRidge);

        // -- Breathing holes below cross --
        for (let i = -1; i <= 1; i += 2) {
            const holeGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.1, 16);
            const hole = new THREE.Mesh(holeGeo, innerMat);
            hole.rotation.x = Math.PI / 2;
            hole.position.set(i * 0.15, 0.18, 0.96);
            visorGroup.add(hole);
        }

        helmet.add(visorGroup);

        // -- Neck guard (curved collar) --
        const neckGuardGeo = new THREE.CylinderGeometry(0.85, 0.65, 0.6, 64, 1, true, Math.PI, Math.PI);
        const neckGuard = new THREE.Mesh(neckGuardGeo, metalMat);
        neckGuard.position.set(0, -0.25, -0.15);
        neckGuard.rotation.x = 0.15;
        helmet.add(neckGuard);

        // -- Back neck extension --
        const backNeckGeo = new THREE.SphereGeometry(0.75, 32, 16, 0, Math.PI * 2, Math.PI * 0.45, Math.PI * 0.35);
        const backNeck = new THREE.Mesh(backNeckGeo, metalMat);
        backNeck.position.set(0, -0.15, -0.15);
        backNeck.rotation.x = Math.PI;
        helmet.add(backNeck);

        // -- Side cheek guards --
        for (let side of [-1, 1]) {
            const cheekShape = new THREE.Shape();
            cheekShape.moveTo(0, -0.5);
            cheekShape.quadraticCurveTo(side * 0.15, -0.1, side * 0.05, 0.4);
            cheekShape.lineTo(side * 0.55, 0.35);
            cheekShape.quadraticCurveTo(side * 0.7, -0.1, side * 0.6, -0.5);
            cheekShape.lineTo(0, -0.5);

            const cheekGeo = new THREE.ExtrudeGeometry(cheekShape, {
                depth: 0.06,
                bevelEnabled: true,
                bevelThickness: 0.015,
                bevelSize: 0.015,
                bevelSegments: 2
            });
            const cheek = new THREE.Mesh(cheekGeo, metalMat);
            cheek.position.set(side * 0.55, -0.1, 0.3);
            cheek.rotation.y = side * 0.6;
            helmet.add(cheek);
        }

        // -- Leather lining (visible at bottom) --
        const liningGeo = new THREE.CylinderGeometry(0.82, 0.62, 0.15, 64);
        const lining = new THREE.Mesh(liningGeo, leatherMat);
        lining.position.y = -0.55;
        helmet.add(lining);

        // -- Top crest base --
        const crestBaseGeo = new THREE.CylinderGeometry(0.12, 0.15, 0.1, 32);
        const crestBase = new THREE.Mesh(crestBaseGeo, darkMetalMat);
        crestBase.position.y = 1.15;
        helmet.add(crestBase);

        // -- Decorative rivets around brow --
        const rivetGeo = new THREE.SphereGeometry(0.035, 16, 16);
        for (let i = 0; i < 8; i++) {
            const angle = (i / 8) * Math.PI;
            const rivet = new THREE.Mesh(rivetGeo, darkMetalMat);
            rivet.position.set(
                Math.cos(angle) * 0.92,
                0.28,
                0.55 + Math.sin(angle) * 0.38
            );
            helmet.add(rivet);
        }

        // -- Position helmet --
        helmet.position.y = 0.8;
        scene.add(helmet);

        // ── Ground / Pedestal ──────────────────────────────────
        const pedestalGeo = new THREE.CylinderGeometry(1.2, 1.4, 0.15, 64);
        const pedestalMat = new THREE.MeshStandardMaterial({
            color: 0x2a2a3a,
            metalness: 0.3,
            roughness: 0.6,
        });
        const pedestal = new THREE.Mesh(pedestalGeo, pedestalMat);
        pedestal.position.y = -0.6;
        scene.add(pedestal);

        const groundGeo = new THREE.PlaneGeometry(40, 40);
        const groundMat = new THREE.MeshStandardMaterial({
            color: 0x111122,
            metalness: 0.1,
            roughness: 0.9,
        });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = -0.68;
        scene.add(ground);

        // ── Animation ──────────────────────────────────────────
        const clock = new THREE.Clock();

        function animate() {
            requestAnimationFrame(animate);
            const t = clock.getElapsedTime();

            // Gentle float + rotation
            helmet.rotation.y = Math.sin(t * 0.3) * 0.4;
            helmet.position.y = 0.8 + Math.sin(t * 0.8) * 0.08;

            controls.update();
            renderer.render(scene, camera);
        }

        animate();

        // ── Resize ─────────────────────────────────────────────
        window.addEventListener('resize', () => {
            camera.aspect = innerWidth / innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(innerWidth, innerHeight);
        });
    </script>
