      child.scale.y = child.scale.y; // keep original
    }
  });
  hippo.position.y = Math.sin(t * 1.2) * 0.04;

  // Subtle head bob
  const headBob = Math.sin(t * 0.8) * 0.02;
  hippo.rotation.x = headBob;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
