<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
camera.position.set(0, 3, 8);
camera.lookAt(0, 0, 0);

// ── Starfield ──
const starCount = 4000;
const starGeo = new THREE.BufferGeometry();
const starPos = new Float32Array(starCount * 3);
for (let i = 0; i < starCount * 3; i++) starPos[i] = (Math.random() - 0.5) * 400;
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({
  color: 0xffffff, size: 0.4, sizeAttenuation: true
})));

// ── Black sphere (event horizon) ──
scene.add(new THREE.Mesh(
  new THREE.SphereGeometry(1.5, 64, 64),
  new THREE.MeshBasicMaterial({ color: 0x000000 })
));

// ── Photon sphere (subtle glow just outside event horizon) ──
const photonGeo = new THREE.SphereGeometry(1.65, 64, 64);
const photonMat = new THREE.ShaderMaterial({
  transparent: true,
  side: THREE.FrontSide,
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    varying vec3 vNormal;
    varying vec3 vViewPos;
    void main(){
      vNormal = normalize(normalMatrix * normal);
      vec4 mv = modelViewMatrix * vec4(position,1.0);
      vViewPos = -mv.xyz;
      gl_Position = projectionMatrix * mv;
    }
  `,
  fragmentShader: `
    varying vec3 vNormal;
    varying vec3 vViewPos;
    uniform float uTime;
    void main(){
      float rim = 1.0 - max(dot(normalize(vViewPos), vNormal), 0.0);
      rim = pow(rim, 3.0);
      vec3 col = mix(vec3(0.8,0.5,0.2), vec3(1.0,0.8,0.4), sin(uTime*0.5)*0.5+0.5);
      gl_FragColor = vec4(col, rim * 0.6);
    }
  `
});
scene.add(new THREE.Mesh(photonGeo, photonMat));

// ── Accretion disk ──
const diskGeo = new THREE.RingGeometry(1.8, 5.5, 256, 8);
// Rotate UVs for radial mapping
const diskUV = diskGeo.attributes.uv;
const diskPos2 = diskGeo.attributes.position;
for (let i = 0; i < diskPos2.count; i++) {
  const x = diskPos2.getX(i), y = diskPos2.getY(i);
  const r = Math.sqrt(x*x + y*y);
  diskUV.setXY(i, (r - 1.8) / (5.5 - 1.8), 0.5);
}

const diskMat = new THREE.ShaderMaterial({
  transparent: true,
  side: THREE.DoubleSide,
  depthWrite: false,
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    varying vec2 vUv;
    varying float vRadius;
    void main(){
      vUv = uv;
      vRadius = length(position.xy);
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
    }
  `,
  fragmentShader: `
    varying vec2 vUv;
    varying float vRadius;
    uniform float uTime;

    // Simplex-ish noise
    vec3 mod289(vec3 x){return x-floor(x*(1.0/289.0))*289.0;}
    vec2 mod289(vec2 x){return x-floor(x*(1.0/289.0))*289.0;}
    vec3 permute(vec3 x){return mod289(((x*34.0)+1.0)*x);}
    float snoise(vec2 v){
      const vec4 C=vec4(0.211324865405187,0.366025403784439,
                       -0.577350269189626,0.024390243902439);
      vec2 i=floor(v+dot(v,C.yy));
      vec2 x0=v-i+dot(i,C.xx);
      vec2 i1=(x0.x>x0.y)?vec2(1.0,0.0):vec2(0.0,1.0);
      vec4 x12=x0.xyxy+C.xxzz;
      x12.xy-=i1;
      i=mod289(i);
      vec3 p=permute(permute(i.y+vec3(0.0,i1.y,1.0))+i.x+vec3(0.0,i1.x,1.0));
      vec3 m=max(0.5-vec3(dot(x0,x0),dot(x12.xy,x12.xy),dot(x12.zw,x12.zw)),0.0);
      m=m*m;m=m*m;
      vec3 x=2.0*fract(p*C.www)-1.0;
      vec3 h=abs(x)-0.5;
      vec3 ox=floor(x+0.5);
      vec3 a0=x-ox;
      m*=1.79284291400159-0.85373472095314*(a0*a0+h*h);
      vec3 g;
      g.x=a0.x*x0.x+h.x*x0.y;
      g.yz=a0.yz*x12.xz+h.yz*x12.yw;
      return 130.0*dot(m,g);
    }

    void main(){
      float t = uTime * 0.3;
      float r = vRadius;
      float angle = atan(position.y, position.x);

      // Spiral noise
      float n1 = snoise(vec2(r*2.5 - t*3.0, angle*3.0 + t));
      float n2 = snoise(vec2(r*4.0 + t*2.0, angle*5.0 - t*1.5));
      float n3 = snoise(vec2(r*8.0 - t*4.0, angle*2.0 + t*0.7));
      float noise = n1*0.5 + n2*0.3 + n3*0.2;

      // Temperature gradient: hot inner, cool outer
      float temp = 1.0 - smoothstep(1.8, 5.5, r);

      // Color from blackbody-ish
      vec3 hotColor  = vec3(1.0, 0.95, 0.7);
      vec3 midColor  = vec3(1.0, 0.5, 0.1);
      vec3 coolColor = vec3(0.6, 0.15, 0.05);

      vec3 col = mix(coolColor, midColor, smoothstep(0.0, 0.5, temp));
      col = mix(col, hotColor, smoothstep(0.5, 1.0, temp));

      float brightness = 0.3 + 0.7 * temp;
      brightness *= (0.6 + 0.4 * noise);

      // Fade edges
      float innerFade = smoothstep(1.8, 2.2, r);
      float outerFade = 1.0 - smoothstep(4.5, 5.5, r);
      float alpha = innerFade * outerFade * brightness;

      // Doppler brightening (one side brighter)
      float doppler = 1.0 + 0.4 * sin(angle + t * 0.5);
      col *= doppler;
      alpha *= doppler;

      gl_FragColor = vec4(col * brightness * 1.5, alpha * 0.85);
    }
  `
});
const disk = new THREE.Mesh(diskGeo, diskMat);
disk.rotation.x = -Math.PI * 0.45;
scene.add(disk);

// ── Infalling particles ──
const particleCount = 2000;
const pGeo = new THREE.BufferGeometry();
const pPositions = new Float32Array(particleCount * 3);
const pVelocities = new Float32Array(particleCount * 3);
const pAngles = new Float32Array(particleCount);
const pRadii = new Float32Array(particleCount);
const pSpeeds = new Float32Array(particleCount);

function resetParticle(i) {
  pAngles[i] = Math.random() * Math.PI * 2;
  pRadii[i] = 5.5 + Math.random() * 2;
  pSpeeds[i] = 0.3 + Math.random() * 0.7;
  pPositions[i*3+1] = (Math.random() - 0.5) * 1.5;
}
for (let i = 0; i < particleCount; i++) resetParticle(i);

pGeo.setAttribute('position', new THREE.BufferAttribute(pPositions, 3));
const particles = new THREE.Points(pGeo, new THREE.PointsMaterial({
  color: 0xffaa44, size: 0.04, transparent: true, opacity: 0.7,
  blending: THREE.AdditiveBlending, depthWrite: false
}));
particles.rotation.x = -Math.PI * 0.45;
scene.add(particles);

// ── Gravitational lensing ring (outer glow) ──
const lensGeo = new THREE.RingGeometry(1.55, 2.8, 128, 1);
const lensMat = new THREE.ShaderMaterial({
  transparent: true, side: THREE.DoubleSide, depthWrite: false,
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    varying vec2 vUv;
    void main(){
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
    }
  `,
  fragmentShader: `
    varying vec2 vUv;
    uniform float uTime;
    void main(){
      float d = length(vUv - 0.5) * 2.0;
      float ring = smoothstep(0.0, 0.3, d) * (1.0 - smoothstep(0.3, 0.6, d));
      float flicker = 0.8 + 0.2 * sin(uTime * 2.0 + d * 20.0);
      vec3 col = vec3(0.9, 0.6, 0.3) * ring * flicker;
      gl_FragColor = vec4(col, ring * 0.3);
    }
  `
});
const lensDisk = new THREE.Mesh(lensGeo, lensMat);
lensDisk.rotation.x = -Math.PI * 0.45;
scene.add(lensDisk);

// ── Ambient light ──
scene.add(new THREE.AmbientLight(0x222222));

// ── Mouse orbit ──
let mouseX = 0, mouseY = 0;
document.addEventListener('mousemove', e => {
  mouseX = (e.clientX / window.innerWidth - 0.5) * 2;
  mouseY = (e.clientY / window.innerHeight - 0.5) * 2;
});

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

// ── Animate ──
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  photonMat.uniforms.uTime.value = t;
  diskMat.uniforms.uTime.value = t;
  lensMat.uniforms.uTime.value = t;

  // Camera orbit
  const cx = Math.sin(mouseX * 0.5) * 8;
  const cy = 3 + mouseY * -3;
  const cz = Math.cos(mouseX * 0.5) * 8;
  camera.position.lerp(new THREE.Vector3(cx, cy, cz), 0.02);
  camera.lookAt(0, 0, 0);

  // Update infalling particles
  const pos = pGeo.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pAngles[i] += pSpeeds[i] * 0.02 / (pRadii[i] * 0.3 + 0.1);
    pRadii[i] -= 0.008 * pSpeeds[i];

    if (pRadii[i] < 1.6) { resetParticle(i); pRadii[i] = 1.6; }

    pos.array[i*3] = Math.cos(pAngles[i]) * pRadii[i];
    pos.array[i*3+1] = (Math.random() - 0.5) * 0.15;
    pos.array[i*3+2] = Math.sin(pAngles[i]) * pRadii[i];
  }
  pos.needsUpdate = true;

  renderer.render(scene, camera);
}
animate();
</script>
</body>
</html>
```

## What you get

| Layer | Description |
|---|---|
| **Event horizon** | Pure black sphere at `r = 1.5` — light cannot escape |
| **Photon sphere** | Glowing rim shader just outside the horizon with subtle color flicker |
| **Accretion disk** | Procedural spiral noise shader with blackbody temperature gradient (white-hot inner → red outer) and Doppler brightening |
| **Infalling particles** | 2,000 points spiraling inward with Kepler-like speed (faster near the center), additive blended |
| **Lensing ring** | Faint outer glow suggesting gravitational lensing of background light |
| **Starfield** | 4,000 background stars for scale |

**Interact** — move your mouse to orbit the camera around the hole. Everything runs in a single file with no build step.

