}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 15, 40);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 5, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1.5, 0);

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(8, 12, 6);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 30;
dirLight.shadow.camera.left = -10;
dirLight.shadow.camera.right = 10;
dirLight.shadow.camera.top = 10;
dirLight.shadow.camera.bottom = -10;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x6688cc, 0.6);
fillLight.position.set(-5, 4, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6633, 1.5, 20);
rimLight.position.set(-4, 6, 4);
scene.add(rimLight);

// ── Procedural Bump Texture (ribbed hose) ──
function createBumpTexture() {
  const canvas = document.createElement('canvas');
  canvas.width = 512;
  canvas.height = 512;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#808080';
  ctx.fillRect(0, 0, 512, 512);
  const spacing = 16;
  for (let y = 0; y < 512; y += spacing) {
    ctx.fillStyle = `rgba(0,0,0,${0.15 + Math.random() * 0.1})`;
    ctx.fillRect(0, y, 512, 2);
    ctx.fillStyle = `rgba(255,255,255,${0.05 + Math.random() * 0.05})`;
    ctx.fillRect(0, y + 2, 512, 1);
  }
  // Add subtle noise
  const imgData = ctx.getImageData(0, 0, 512, 512);
  for (let i = 0; i < imgData.data.length; i += 4) {
    const n = (Math.random() - 0.5) * 15;
    imgData.data[i] += n;
    imgData.data[i + 1] += n;
    imgData.data[i + 2] += n;
  }
  ctx.putImageData(imgData, 0, 0);
  const tex = new THREE.CanvasTexture(canvas);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  tex.repeat.set(1, 8);
  return tex;
}

// ── Hose Material ──
const hoseMaterial = new THREE.MeshStandardMaterial({
  color: 0x2a2a2a,
  roughness: 0.75,
  metalness: 0.05,
  bumpMap: createBumpTexture(),
  bumpScale: 0.04,
});

// ── Hose Curve (coiled shape) ──
const points = [];
const coils = 3;
const coilHeight = 0.4;
const coilRadius = 2.2;
const segments = 200;

for (let i = 0; i <= segments; i++) {
  const t = i / segments;
  const angle = t * Math.PI * 2 * coils;
  // Slight taper: coils get slightly larger toward the end
  const r = coilRadius + t * 0.5;
  // Slight vertical rise
  const y = t * 1.8 + Math.sin(angle * 2) * 0.08;
  // Add some natural sag
  const sag = Math.sin(t * Math.PI) * 0.3;
  points.push(new THREE.Vector3(
    Math.cos(angle) * r,
    y - sag,
    Math.sin(angle) * r
  ));
}

// Add a loose tail end
const tailSegments = 40;
for (let i = 1; i <= tailSegments; i++) {
  const t = i / tailSegments;
  const lastCoil = points[points.length - 1];
  const angle = coils * Math.PI * 2 + t * Math.PI * 0.8;
  const r = coilRadius + coils * 0.5 + t * 1.5;
  const y = 1.8 - 0.3 + t * 0.4 + Math.sin(t * Math.PI) * 0.5;
  points.push(new THREE.Vector3(
    Math.cos(angle) * r,
    y,
    Math.sin(angle) * r
  ));
}

const curve = new THREE.CatmullRomCurve3(points);
const tubeGeo = new THREE.TubeGeometry(curve, 500, 0.18, 16, false);
const hose = new THREE.Mesh(tubeGeo, hoseMaterial);
hose.castShadow = true;
hose.receiveShadow = true;
scene.add(hose);

// ── Hose Fittings (metal connectors at ends) ──
function createFitting(pos, tangent) {
  const group = new THREE.Group();
  const metalMat = new THREE.MeshStandardMaterial({
    color: 0x888899,
    roughness: 0.3,
    metalness: 0.8,
  });

  // Main cylinder body
  const bodyGeo = new THREE.CylinderGeometry(0.22, 0.25, 0.5, 16);
  const body = new THREE.Mesh(bodyGeo, metalMat);
  group.add(body);

  // Threads (ring segments)
  for (let i = 0; i < 4; i++) {
    const ringGeo = new THREE.TorusGeometry(0.24, 0.015, 8, 16);
    const ring = new THREE.Mesh(ringGeo, metalMat);
    ring.position.y = -0.12 + i * 0.08;
    ring.rotation.x = Math.PI / 2;
    group.add(ring);
  }

  // Cap end
  const capGeo = new THREE.CylinderGeometry(0.2, 0.2, 0.05, 16);
  const cap = new THREE.Mesh(capGeo, metalMat);
  cap.position.y = 0.27;
  group.add(cap);

  group.position.copy(pos);
  group.lookAt(pos.clone().add(tangent));
  group.rotateX(Math.PI / 2);
  group.castShadow = true;
  return group;
}

const startTan = curve.getTangent(0);
const endTan = curve.getTangent(1);
scene.add(createFitting(curve.getPoint(0), startTan));
scene.add(createFitting(curve.getPoint(1), endTan));

// ── Ground ──
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x222233,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.5;
ground.receiveShadow = true;
scene.add(ground);

// Grid helper for context
const grid = new THREE.GridHelper(20, 20, 0x333355, 0x2a2a44);
grid.position.y = -0.49;
scene.add(grid);

// ── Water drops (ambient particles) ──
const dropCount = 60;
const dropGeo = new THREE.BufferGeometry();
const dropPositions = new Float32Array(dropCount * 3);
const dropVelocities = [];
for (let i = 0; i < dropCount; i++) {
  dropPositions[i * 3] = (Math.random() - 0.5) * 12;
  dropPositions[i * 3 + 1] = Math.random() * 8;
  dropPositions[i * 3 + 2] = (Math.random() - 0.5) * 12;
  dropVelocities.push(0.005 + Math.random() * 0.015);
}
dropGeo.setAttribute('position', new THREE.BufferAttribute(dropPositions, 3));
const dropMat = new THREE.PointsMaterial({
  color: 0x66aaff,
  size: 0.06,
  transparent: true,
  opacity: 0.5,
  sizeAttenuation: true,
});
const drops = new THREE.Points(dropGeo, dropMat);
scene.add(drops);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle hose sway
  hose.rotation.y = Math.sin(elapsed * 0.3) * 0.05;

  // Animate water drops
  const pos = drops.geometry.attributes.position.array;
  for (let i = 0; i < dropCount; i++) {
    pos[i * 3 + 1] -= dropVelocities[i];
    if (pos[i * 3 + 1] < -0.5) {
      pos[i * 3] = (Math.random() - 0.5) * 12;
      pos[i * 3 + 1] = 6 + Math.random() * 3;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 12;
    }
  }
  drops.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the scene

| Element | Details |
|---|---|
| **Hose body** | `TubeGeometry` along a CatmullRom spline forming **3 coils + a loose tail**, 500 segments for smoothness |
| **Ribbed texture** | Procedural canvas bump map with horizontal ridges + noise, wrapped along the tube |
| **Metal fittings** | Cylindrical connectors with threaded ring details at both ends, using a metallic PBR material |
| **Lighting** | 3-point setup (warm key, cool fill, orange rim) + ambient, with soft shadow mapping |
| **Ground** | Dark plane with subtle grid for spatial reference |
| **Water drops** | Floating particle system that falls and resets, adding atmosphere |
| **Animation** | Gentle sway on the hose + falling drops |
| **Controls** | `OrbitControls` with damping — drag to rotate, scroll to zoom |

