renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;

// ── Lighting ──
scene.add(new THREE.AmbientLight(0xffffff, 0.4));
const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(3, 5, 4);
scene.add(dirLight);
const rimLight = new THREE.DirectionalLight(0x8888ff, 0.6);
rimLight.position.set(-3, -2, -3);
scene.add(rimLight);

// ── Hourglass group ──
const hourglass = new THREE.Group();
scene.add(hourglass);

// ── Glass body via LatheGeometry ──
const glassPoints = [];
const R = 1.0;          // max radius
const H = 2.0;          // total height
const neckR = 0.06;     // neck radius
const steps = 40;

// Top bulb (upper half)
for (let i = 0; i <= steps; i++) {
  const t = i / steps;
  const y = H / 2 - t * (H / 2);
  const angle = t * Math.PI / 2;
  // smooth curve: wide at top, narrow at neck
  const r = neckR + (R - neckR) * Math.pow(Math.sin(angle), 0.7);
  glassPoints.push(new THREE.Vector2(r, y));
}
// Bottom bulb (lower half) — mirror
for (let i = steps; i >= 0; i--) {
  const t = i / steps;
  const y = -H / 2 + t * (H / 2);
  const angle = t * Math.PI / 2;
  const r = neckR + (R - neckR) * Math.pow(Math.sin(angle), 0.7);
  glassPoints.push(new THREE.Vector2(r, y));
}

const glassGeo = new THREE.LatheGeometry(glassPoints, 64);
const glassMat = new THREE.MeshPhysicalMaterial({
  color: 0xffffff,
  transparent: true,
  opacity: 0.18,
  roughness: 0.05,
  metalness: 0.0,
  transmission: 0.92,
  thickness: 0.5,
  ior: 1.5,
  side: THREE.DoubleSide,
  depthWrite: false,
});
hourglass.add(new THREE.Mesh(glassGeo, glassMat));

// ── Sand ──
const sandMat = new THREE.MeshStandardMaterial({
  color: 0xd4a056,
  roughness: 0.95,
  metalness: 0.0,
});

// Top sand pile (inverted cone)
const topSandGeo = new THREE.ConeGeometry(R * 0.75, 0.8, 32);
const topSand = new THREE.Mesh(topSandGeo, sandMat);
topSand.position.y = 0.35;
topSand.rotation.x = Math.PI;
hourglass.add(topSand);

// Bottom sand pile
const botSandGeo = new THREE.ConeGeometry(R * 0.72, 0.75, 32);
const botSand = new THREE.Mesh(botSandGeo, sandMat);
botSand.position.y = -0.38;
hourglass.add(botSand);

// Sand stream
const streamGeo = new THREE.CylinderGeometry(0.015, 0.015, 1.2, 8);
const streamMat = new THREE.MeshStandardMaterial({ color: 0xd4a056, roughness: 0.9 });
const stream = new THREE.Mesh(streamGeo, streamMat);
stream.position.y = 0;
hourglass.add(stream);

// Falling sand particles
const particleCount = 120;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const velocities = new Float32Array(particleCount);
const offsets = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 0.03;
  positions[i * 3 + 1] = Math.random() * 1.2 - 0.6;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 0.03;
  velocities[i] = 0.8 + Math.random() * 0.6;
  offsets[i] = Math.random() * Math.PI * 2;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0xd4a056,
  size: 0.025,
  transparent: true,
  opacity: 0.85,
  depthWrite: false,
});
const particles = new THREE.Points(particleGeo, particleMat);
hourglass.add(particles);

// ── Wooden frame ──
const woodMat = new THREE.MeshStandardMaterial({
  color: 0x5c3a1e,
  roughness: 0.7,
  metalness: 0.1,
});

// Top and bottom rings
const ringGeo = new THREE.TorusGeometry(R + 0.08, 0.08, 12, 64);
const topRing = new THREE.Mesh(ringGeo, woodMat);
topRing.position.y = H / 2;
topRing.rotation.x = Math.PI / 2;
hourglass.add(topRing);

const botRing = new THREE.Mesh(ringGeo, woodMat);
botRing.position.y = -H / 2;
botRing.rotation.x = Math.PI / 2;
hourglass.add(botRing);

// Corner pillars
const pillarGeo = new THREE.CylinderGeometry(0.04, 0.04, H + 0.2, 12);
const pillarPositions = [
  [R + 0.06, 0, 0],
  [-(R + 0.06), 0, 0],
  [0, 0, R + 0.06],
  [0, 0, -(R + 0.06)],
];
pillarPositions.forEach(([x, , z]) => {
  const pillar = new THREE.Mesh(pillarGeo, woodMat);
  pillar.position.set(x, 0, z);
  hourglass.add(pillar);
});

// Top and bottom caps
const capGeo = new THREE.CylinderGeometry(R + 0.12, R + 0.12, 0.06, 64);
const topCap = new THREE.Mesh(capGeo, woodMat);
topCap.position.y = H / 2 + 0.03;
hourglass.add(topCap);

const botCap = new THREE.Mesh(capGeo, woodMat);
botCap.position.y = -H / 2 - 0.03;
hourglass.add(botCap);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle rotation
  hourglass.rotation.y = Math.sin(t * 0.3) * 0.3;

  // Animate sand particles
  const pos = particles.geometry.attributes.position.array;
