  const soleMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });
  const sole = new THREE.Mesh(soleGeo, soleMat);
  sole.position.set(0, -0.97, 0.04);
  legGroup.add(sole);

  legs.push(legGroup);
  human.add(legGroup);
});

scene.add(human);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle breathing
  chest.scale.x = 1 + Math.sin(t * 1.5) * 0.02;
  chest.scale.z = 1 + Math.sin(t * 1.5) * 0.02;
  torso.scale.x = 1 + Math.sin(t * 1.5) * 0.01;
  torso.scale.z = 1 + Math.sin(t * 1.5) * 0.01;

