  arms[1].rotation.x = -Math.sin(t * 0.8) * 0.05;

  // Head subtle movement
  headGroup.rotation.y = Math.sin(t * 0.3) * 0.1;
  headGroup.rotation.x = Math.sin(t * 0.5) * 0.03;

  // Subtle weight shift
  legs[0].rotation.z = Math.sin(t * 0.6) * 0.01;
  legs[1].rotation.z = -Math.sin(t * 0.6) * 0.01;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
