<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

// ——— Renderer ———
const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ——— Scene & Camera ———
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x050510);

const camera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 1, 5);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// ——— Environment (for reflections) ———
const pmrem = new THREE.PMREMGenerator(renderer);
scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
pmrem.dispose();

// ——— Gem Geometry (brilliant-cut profile → lathe) ———
function createGemProfile() {
  const points = [];
  // Culet (bottom tip)
  points.push(new THREE.Vector2(0, -1.6));
  // Pavilion
  points.push(new THREE.Vector2(0.3, -1.1));
  points.push(new THREE.Vector2(0.85, -0.35));
  // Girdle
  points.push(new THREE.Vector2(1.0, -0.15));
  points.push(new THREE.Vector2(1.05, 0.0));
  points.push(new THREE.Vector2(1.0, 0.15));
  // Crown
  points.push(new THREE.Vector2(0.85, 0.35));
  points.push(new THREE.Vector2(0.5, 0.65));
  // Table
  points.push(new THREE.Vector2(0.35, 0.75));
  points.push(new THREE.Vector2(0.0, 0.78));
  return points;
}

const gemGeometry = new THREE.LatheGeometry(
  createGemProfile(), 24
);
gemGeometry.computeVertexNormals();

// ——— Gem Material ———
const gemMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x88ccff,
  metalness: 0.0,
  roughness: 0.0,
  transmission: 0.97,
  thickness: 2.0,
  ior: 2.42,
  clearcoat: 1.0,
  clearcoatRoughness: 0.0,
  specularIntensity: 1.0,
  specularColor: new THREE.Color(0xffffff),
  envMapIntensity: 2.0,
  transparent: true,
  opacity: 0.95,
  side: THREE.DoubleSide,
});

const gem = new THREE.Mesh(gemGeometry, gemMaterial);
gem.castShadow = true;
gem.receiveShadow = true;
scene.add(gem);

// ——— Inner glow (slightly smaller solid core) ———
const glowMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x4488ff,
  emissive: 0x112244,
  emissiveIntensity: 0.3,
  metalness: 0.0,
  roughness: 0.1,
  transparent: true,
  opacity: 0.15,
});
const glowMesh = new THREE.Mesh(gemGeometry.clone(), glowMaterial);
glowMesh.scale.setScalar(0.92);
gem.add(glowMesh);

// ——— Sparkle particles ———
const sparkleCount = 80;
const sparkleGeo = new THREE.BufferGeometry();
const sparklePositions = new Float32Array(sparkleCount * 3);
const sparkleSizes = new Float32Array(sparkleCount);

for (let i = 0; i < sparkleCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.acos(2 * Math.random() - 1);
  const r = 1.3 + Math.random() * 1.5;
  sparklePositions[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
  sparklePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
  sparklePositions[i * 3 + 2] = r * Math.cos(phi);
  sparkleSizes[i] = Math.random() * 3 + 1;
}
sparkleGeo.setAttribute('position', new THREE.BufferAttribute(sparklePositions, 3));
sparkleGeo.setAttribute('size', new THREE.BufferAttribute(sparkleSizes, 1));

const sparkleMat = new THREE.PointsMaterial({
  color: 0xaaddff,
  size: 0.04,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
  blending: THREE.AdditiveBlending,
  depthWrite: false,
});
const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
scene.add(sparkles);

// ——— Lights ———
const keyLight = new THREE.PointLight(0xffffff, 80, 20);
keyLight.position.set(2, 3, 3);
keyLight.castShadow = true;
scene.add(keyLight);

const fillLight = new THREE.PointLight(0x4488ff, 40, 20);
fillLight.position.set(-3, 1, 2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6644, 30, 20);
rimLight.position.set(0, -2, -3);
scene.add(rimLight);

const topLight = new THREE.PointLight(0xffffff, 50, 15);
topLight.position.set(0, 5, 0);
scene.add(topLight);

// ——— Pedestal ———
const pedestalGeo = new THREE.CylinderGeometry(0.6, 0.8, 0.15, 32);
const pedestalMat = new THREE.MeshPhysicalMaterial({
  color: 0x111111,
  metalness: 0.9,
  roughness: 0.2,
  clearcoat: 0.5,
});
const pedestal = new THREE.Mesh(pedestalGeo, pedestalMat);
pedestal.position.y = -2.0;
pedestal.receiveShadow = true;
scene.add(pedestal);

// ——— Animation ———
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float + rotation
  gem.rotation.y = t * 0.3;
  gem.position.y = Math.sin(t * 0.5) * 0.15;

  // Sparkle twinkle
  sparkleMat.opacity = 0.3 + Math.sin(t * 2) * 0.2;
  sparkles.rotation.y = -t * 0.1;

  // Orbit lights subtly
  keyLight.position.x = Math.cos(t * 0.7) * 3;
  keyLight.position.z = Math.sin(t * 0.7) * 3;
  fillLight.position.x = Math.cos(t * 0.5 + 2) * 3.5;
  fillLight.position.z = Math.sin(t * 0.5 + 2) * 2.5;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ——— Resize ———
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
