      new THREE.Vector3(0.70, 1.60, 0),
      new THREE.Vector3(1.40, 1.70, 0),
      new THREE.Vector3(1.55, 1.30, 0),
      new THREE.Vector3(1.45, 0.90, 0),
      new THREE.Vector3(0.95, 0.70, 0),
    ]);

    const handleGeo = new THREE.TubeGeometry(handlePath, 48, 0.1, 16, false);
    const handle = new THREE.Mesh(handleGeo, jugMat);
    handle.castShadow = true;
    scene.add(handle);

    // ── Spout ──
    const spoutProfile = [
      new THREE.Vector2(0.00, 0.00),
      new THREE.Vector2(0.08, 0.02),
      new THREE.Vector2(0.12, 0.15),
      new THREE.Vector2(0.18, 0.40),
      new THREE.Vector2(0.24, 0.60),
      new THREE.Vector2(0.28, 0.75),
      new THREE.Vector2(0.30, 0.85),
      new THREE.Vector2(0.28, 0.92),
      new THREE.Vector2(0.22, 0.95),
      new THREE.Vector2(0.16, 0.92),
      new THREE.Vector2(0.12, 0.85),
      new THREE.Vector2(0.06, 0.70),
      new THREE.Vector2(0.04, 0.50),
      new THREE.Vector2(0.03, 0.30),
      new THREE.Vector2(0.02, 0.10),
      new THREE.Vector2(0.00, 0.05),
    ];

    const spoutGeo = new THREE.LatheGeometry(spoutProfile, 32);
    spoutGeo.computeVertexNormals();
    const spout = new THREE.Mesh(spoutGeo, jugMat);
    spout.position.set(1.05, 1.85, 0);
    spout.rotation.z = -Math.PI / 3.2;
    spout.castShadow = true;
    scene.add(spout);

    // ── Lid / Top Knob ──
    const knobGeo = new THREE.SphereGeometry(0.12, 32, 32);
    const knob = new THREE.Mesh(knobGeo, darkMat);
    knob.position.set(0, 2.42, 0);
    knob.castShadow = true;
    scene.add(knob);

    // ── Decorative Bands ──
    const bandGeo = new THREE.TorusGeometry(1.08, 0.02, 8, 64);
    const bandMat = new THREE.MeshStandardMaterial({ color: 0x9e8668, roughness: 0.3 });
    [0.5, 0.9, 1.35].forEach(y => {
      const band = new THREE.Mesh(bandGeo, bandMat);
      band.position.y = y;
      band.rotation.x = Math.PI / 2;
      scene.add(band);
    });

    // ── Ground Plane ──
    const groundGeo = new THREE.CircleGeometry(6, 64);
    const groundMat = new THREE.MeshStandardMaterial({ color: 0x16213e, roughness: 0.85 });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.01;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Lighting ──
    const ambient = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambient);

    const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    keyLight.position.set(5, 8, 4);
    keyLight.castShadow = true;
    keyLight.shadow.mapSize.set(1024, 1024);
    keyLight.shadow.camera.near = 1;
    keyLight.shadow.camera.far = 20;
    keyLight.shadow.camera.left = -4;
    keyLight.shadow.camera.right = 4;
    keyLight.shadow.camera.top = 4;
    keyLight.shadow.camera.bottom = -4;
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0x8888cc, 0.6);
    fillLight.position.set(-4, 3, -2);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xffaa66, 1.5, 12);
    rimLight.position.set(-3, 4, -3);
    scene.add(rimLight);

    const bottomLight = new THREE.PointLight(0x4466aa, 0.4, 8);
    bottomLight.position.set(0, -1, 3);
    scene.add(bottomLight);

    // ── Animation ──
    const clock = new THREE.Clock();
    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle idle rotation
      body.rotation.y   = Math.sin(t * 0.3) * 0.15;
      handle.rotation.y = Math.sin(t * 0.3) * 0.15;
      spout.rotation.y  = Math.sin(t * 0.3) * 0.15;
      knob.rotation.y   = Math.sin(t * 0.3) * 0.15;
      scene.children.forEach(c => {
        if (c.isMesh && c !== body && c !== handle && c !== spout && c !== knob && c !== ground) {
          c.rotation.y = Math.sin(t * 0.3) * 0.15;
        }
      });

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

**What's included:**

| Part | Geometry | Details |
|---|---|---|
| **Body** | `LatheGeometry` | A full pot profile with belly, tapering neck, and flared rim — revolved around Y |
| **Handle** | `TubeGeometry` + `CatmullRomCurve3` | An arched handle attached from shoulder to neck |
| **Spout** | `LatheGeometry` | A small curved spout rotated to point forward |
| **Lid knob** | `SphereGeometry` | A small darker sphere on top |
| **Bands** | `TorusGeometry` × 3 | Thin decorative rings around the body |

**Rendering features:**
- **ACES Filmic tone mapping** for a cinematic look
- **PCF soft shadows** cast onto a dark ground plane
- **Four-light setup** (key, fill, rim, bottom) for rich ceramic-like shading
- **OrbitControls** — drag to rotate, scroll to zoom
- **Gentle idle wobble** animation
- Fully responsive to window resizing

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Knot</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
