</head>
<body>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>

<script type="module">
  import * as THREE from 'three';
  import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

  // ── Scene ──────────────────────────────────────────────
  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x0a0a1a);
  scene.fog = new THREE.FogExp2(0x0a0a1a, 0.035);

  // ── Camera ─────────────────────────────────────────────
  const camera = new THREE.PerspectiveCamera(
    50, window.innerWidth / window.innerHeight, 0.1, 100
  );
  camera.position.set(0, 2, 6);

  // ── Renderer ───────────────────────────────────────────
  const renderer = new THREE.WebGLRenderer({ antialias: true });
  renderer.setSize(window.innerWidth, window.innerHeight);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.2;
  document.body.appendChild(renderer.domElement);

  // ── Controls ───────────────────────────────────────────
  const controls = new OrbitControls(camera, renderer.domElement);
  controls.enableDamping = true;
  controls.dampingFactor = 0.05;
  controls.minDistance = 3;
  controls.maxDistance = 15;

  // ── Knot Geometry ──────────────────────────────────────
  const knotGeometry = new THREE.TorusKnotGeometry(1.2, 0.4, 256, 64, 2, 3);

  const knotMaterial = new THREE.MeshPhysicalMaterial({
    color: 0x4488ff,
    metalness: 0.3,
    roughness: 0.2,
    clearcoat: 1.0,
    clearcoatRoughness: 0.1,
    emissive: 0x112244,
    emissiveIntensity: 0.2,
  });

  const knot = new THREE.Mesh(knotGeometry, knotMaterial);
  scene.add(knot);

  // ── Secondary wireframe overlay ────────────────────────
  const wireGeo = new THREE.TorusKnotGeometry(1.2, 0.4, 256, 64, 2, 3);
  const wireMat = new THREE.MeshBasicMaterial({
    color: 0x88bbff,
    wireframe: true,
    transparent: true,
    opacity: 0.04,
  });
  const wireframe = new THREE.Mesh(wireGeo, wireMat);
  scene.add(wireframe);

  // ── Lighting ───────────────────────────────────────────
  const ambient = new THREE.AmbientLight(0x334466, 0.8);
  scene.add(ambient);

  const dirLight = new THREE.DirectionalLight(0xffffff, 2.5);
  dirLight.position.set(5, 5, 5);
  scene.add(dirLight);

  const pointLight1 = new THREE.PointLight(0xff6644, 40, 20);
  pointLight1.position.set(-4, 3, 2);
  scene.add(pointLight1);

  const pointLight2 = new THREE.PointLight(0x4488ff, 40, 20);
  pointLight2.position.set(4, -3, -2);
  scene.add(pointLight2);

  const rimLight = new THREE.PointLight(0x8844ff, 25, 15);
  rimLight.position.set(0, -5, 4);
  scene.add(rimLight);

  // ── Particle field ─────────────────────────────────────
  const particleCount = 600;
  const particleGeo = new THREE.BufferGeometry();
  const positions = new Float32Array(particleCount * 3);
  for (let i = 0; i < particleCount; i++) {
    positions[i * 3]     = (Math.random() - 0.5) * 30;
    positions[i * 3 + 1] = (Math.random() - 0.5) * 30;
    positions[i * 3 + 2] = (Math.random() - 0.5) * 30;
  }
  particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

  const particleMat = new THREE.PointsMaterial({
    color: 0x6688cc,
    size: 0.04,
    transparent: true,
    opacity: 0.6,
    sizeAttenuation: true,
  });
  const particles = new THREE.Points(particleGeo, particleMat);
  scene.add(particles);

  // ── Animation ──────────────────────────────────────────
  const clock = new THREE.Clock();

  function animate() {
    requestAnimationFrame(animate);

    const t = clock.getElapsedTime();

    // Rotate the knot
    knot.rotation.x = t * 0.25;
    knot.rotation.y = t * 0.35;
    wireframe.rotation.copy(knot.rotation);

    // Gentle float
    knot.position.y = Math.sin(t * 0.5) * 0.2;
    wireframe.position.y = knot.position.y;

    // Orbit the point lights
    pointLight1.position.x = Math.sin(t * 0.7) * 5;
    pointLight1.position.z = Math.cos(t * 0.7) * 5;
    pointLight2.position.x = Math.cos(t * 0.5) * 5;
    pointLight2.position.z = Math.sin(t * 0.5) * 5;

    // Slow particle drift
    particles.rotation.y = t * 0.02;
    particles.rotation.x = t * 0.01;

    controls.update();
    renderer.render(scene, camera);
  }

  animate();

  // ── Resize ─────────────────────────────────────────────
  window.addEventListener('resize', () => {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(window.innerWidth, window.innerHeight);
  });
</script>

</body>
</html>
