## What you get

| Feature | Detail |
|---|---|
| **Geometry** | `TorusKnotGeometry` with p=2, q=3 (a classic trefoil knot) |
| **Material** | `MeshPhysicalMaterial` with clearcoat for a glossy, metallic look |
| **Wireframe overlay** | Subtle transparent wireframe layered on top for visual depth |
| **Lighting** | Ambient + directional + 3 colored point lights (warm, cool, purple) |
| **Particles** | 600 floating dots for atmosphere |
| **Animation** | Continuous rotation, gentle vertical float, orbiting lights |
| **Interactivity** | `OrbitControls` — drag to rotate, scroll to zoom |
| **Responsive** | Adapts to window resize |

Just save it as `index.html` and open in any modern browser — no build step needed.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Kite</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
#info {
  position: absolute; bottom: 20px; left: 50%; transform: translateX(-50%);
  color: #fff; font-family: sans-serif; font-size: 14px;
  background: rgba(0,0,0,0.4); padding: 8px 16px; border-radius: 20px;
  pointer-events: none;
}
</style>
</head>
<body>
<div id="info">🪁 Drag to orbit · Scroll to zoom</div>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.012);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 2, 12);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 2, 0);

// ── Lights ──
const ambient = new THREE.AmbientLight(0xffffff, 0.6);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(10, 20, 8);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
scene.add(sun);

const rim = new THREE.DirectionalLight(0x8ec5fc, 0.5);
rim.position.set(-5, 3, -5);
scene.add(rim);

// ── Kite Group ──
const kiteGroup = new THREE.Group();
scene.add(kiteGroup);

// ── Diamond sail ──
const sailShape = new THREE.Shape();
sailShape.moveTo(0, 3.5);
sailShape.lineTo(2.2, 0);
sailShape.lineTo(0, -4);
sailShape.lineTo(-2.2, 0);
sailShape.closePath();

const sailGeo = new THREE.ShapeGeometry(sailShape, 32);

// Colored canvas texture
const canvas = document.createElement('canvas');
canvas.width = 512; canvas.height = 512;
const ctx = canvas.getContext('2d');
const grad = ctx.createLinearGradient(0, 0, 512, 512);
grad.addColorStop(0, '#ff6b6b');
grad.addColorStop(0.35, '#ffa502');
grad.addColorStop(0.65, '#ffd32a');
grad.addColorStop(1, '#ff6b6b');
ctx.fillStyle = grad;
ctx.fillRect(0, 0, 512, 512);
// subtle pattern
for (let i = 0; i < 8; i++) {
  ctx.strokeStyle = `rgba(255,255,255,${0.1 + Math.random() * 0.15})`;
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.moveTo(0, i * 64 + 32);
  ctx.lineTo(512, i * 64 + 32);
  ctx.stroke();
}
const sailTex = new THREE.CanvasTexture(canvas);

const sailMat = new THREE.MeshStandardMaterial({
  map: sailTex, side: THREE.DoubleSide,
  roughness: 0.7, metalness: 0.05,
  transparent: true, opacity: 0.92
});
const sail = new THREE.Mesh(sailGeo, sailMat);
sail.castShadow = true;
sail.receiveShadow = true;
kiteGroup.add(sail);

// ── Cross sticks ──
const stickMat = new THREE.MeshStandardMaterial({ color: 0x8B6914, roughness: 0.8 });

// Vertical stick
const vStick = new THREE.Mesh(
  new THREE.CylinderGeometry(0.04, 0.04, 7.5, 8), stickMat
);
vStick.position.y = -0.25;
kiteGroup.add(vStick);

// Horizontal stick
const hStick = new THREE.Mesh(
  new THREE.CylinderGeometry(0.035, 0.035, 4.4, 8), stickMat
);
hStick.rotation.z = Math.PI / 2;
hStick.position.y = 0.2;
kiteGroup.add(hStick);

// ── Bow (curved top spine) ──
const bowCurve = new THREE.QuadraticBezierCurve3(
  new THREE.Vector3(0, 0.5, 0),
  new THREE.Vector3(0, 5.5, 0),
  new THREE.Vector3(0, 3.5, 0.3)
);
const bowGeo = new THREE.TubeGeometry(bowCurve, 20, 0.03, 8, false);
const bow = new THREE.Mesh(bowGeo, stickMat);
kiteGroup.add(bow);

// ── Bridle strings ──
const bridleMat = new THREE.LineBasicMaterial({ color: 0xcccccc });
const bridlePts1 = [
  new THREE.Vector3(0, 1.2, 0),
  new THREE.Vector3(0, -0.5, -0.05),
  new THREE.Vector3(0, -0.5, -0.05)
];
const bridlePts2 = [
  new THREE.Vector3(0, -2.0, 0),
  new THREE.Vector3(0, -0.5, -0.05),
];
kiteGroup.add(new THREE.Line(
  new THREE.BufferGeometry().setFromPoints(bridlePts1), bridleMat));
kiteGroup.add(new THREE.Line(
  new THREE.BufferGeometry().setFromPoints(bridlePts2), bridleMat));

// ── Kite line (string going up) ──
const stringPoints = [];
for (let i = 0; i <= 60; i++) {
  const t = i / 60;
  const y = -0.5 + t * 18;
  const sway = Math.sin(t * 4) * 0.6 * t;
  stringPoints.push(new THREE.Vector3(sway, y, -0.05 - t * 2));
}
const stringGeo = new THREE.BufferGeometry().setFromPoints(stringPoints);
const stringLine = new THREE.Line(stringGeo, new THREE.LineBasicMaterial({
  color: 0xeeeeee, transparent: true, opacity: 0.7
}));
kiteGroup.add(stringLine);

// ── Tail ──
const tailSegments = 20;
const tailGroup = new THREE.Group();
kiteGroup.add(tailGroup);

const tailMaterials = [
  new THREE.MeshStandardMaterial({ color: 0xff6b6b, roughness: 0.6 }),
  new THREE.MeshStandardMaterial({ color: 0xffa502, roughness: 0.6 }),
  new THREE.MeshStandardMaterial({ color: 0xffd32a, roughness: 0.6 }),
  new THREE.MeshStandardMaterial({ color: 0x7bed9f, roughness: 0.6 }),
  new THREE.MeshStandardMaterial({ color: 0x70a1ff, roughness: 0.6 }),
];

const tailPoles = [];
for (let i = 0; i < tailSegments; i++) {
  const mat = tailMaterials[i % tailMaterials.length];
  const pole = new THREE.Mesh(
    new THREE.BoxGeometry(0.35 - i * 0.012, 0.55, 0.05), mat
  );
  pole.position.y = -i * 0.6;
  pole.castShadow = true;
  tailGroup.add(pole);
  tailPoles.push(pole);
}

// ── Clouds ──
function makeCloud(x, y, z, scale) {
  const g = new THREE.Group();
  const mat = new THREE.MeshStandardMaterial({
    color: 0xffffff, roughness: 1, transparent: true, opacity: 0.85
  });
  const blobs = [
    { s: [1.5, 0.8, 0.8], p: [0, 0, 0] },
    { s: [1.2, 0.7, 0.7], p: [1.2, 0.1, 0.2] },
    { s: [1.0, 0.6, 0.6], p: [-1.0, -0.05, -0.1] },
    { s: [0.8, 0.5, 0.5], p: [0.5, 0.3, -0.2] },
    { s: [0.9, 0.5, 0.5], p: [-0.6, 0.2, 0.1] },
  ];
  blobs.forEach(b => {
    const m = new THREE.Mesh(new THREE.SphereGeometry(1, 12, 10), mat);
    m.scale.set(...b.s);
    m.position.set(...b.p);
    g.add(m);
  });
  g.position.set(x, y, z);
  g.scale.setScalar(scale);
  return g;
}

const clouds = [
  makeCloud(-15, 12, -20, 2.5),
  makeCloud(18, 15, -25, 3),
  makeCloud(8, 8, -15, 1.8),
  makeCloud(-10, 18, -30, 2.2),
  makeCloud(22, 10, -18, 2),
  makeCloud(-20, 6, -12, 1.5),
];
clouds.forEach(c => scene.add(c));

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(200, 200),
  new THREE.MeshStandardMaterial({ color: 0x5a9e5a, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -12;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Kite bobbing
  kiteGroup.position.y = Math.sin(t * 0.8) * 0.8;
  kiteGroup.position.x = Math.sin(t * 0.5) * 0.3;
  kiteGroup.rotation.z = Math.sin(t * 0.7) * 0.06;
  kiteGroup.rotation.x = Math.sin(t * 0.55) * 0.04;
  kiteGroup.rotation.y = Math.sin(t * 0.3) * 0.08;

  // Tail wave
  tailPoles.forEach((pole, i) => {
    const phase = i * 0.4;
    pole.position.x = Math.sin(t * 2.5 + phase) * (0.15 * i * 0.5);
    pole.position.z = Math.cos(t * 1.8 + phase) * (0.1 * i * 0.3);
    pole.rotation.z = Math.sin(t * 2.2 + phase) * 0.15 * (i * 0.15);
  });

  // Cloud drift
  clouds.forEach((c, i) => {
    c.position.x += 0.008 * (i % 2 === 0 ? 1 : -0.7);
    if (c.position.x > 40) c.position.x = -40;
    if (c.position.x < -40) c.position.x = 40;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's in the scene:**

| Element | Details |
|---|---|
| **Diamond sail** | Custom `ShapeGeometry` with a warm red→orange→yellow gradient texture, semi-transparent |
| **Cross sticks** | Vertical + horizontal wooden rods + a curved bow spine |
| **Bridle lines** | Strings from top and bottom of the sail meeting at the tie point |
| **Kite line** | A swooping string extending upward with gentle sine-wave sag |
| **Tail** | 20 colorful box segments that wave independently in the wind |
| **Clouds** | 6 fluffy cloud clusters drifting slowly across the sky |
| **Ground** | Green plane for depth reference |
| **Lighting** | Ambient + directional sun (with shadows) + blue rim light |
| **Controls** | Orbit controls — drag to rotate, scroll to zoom |

The kite gently bobs, sways, and rolls as if caught in a breeze, while the tail streams undulate behind it.

