<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene, Camera, Renderer ──────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ─────────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;

// ── Lighting ─────────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
keyLight.position.set(4, 6, 4);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 1;
keyLight.shadow.camera.far = 20;
keyLight.shadow.camera.left = -5;
keyLight.shadow.camera.right = 5;
keyLight.shadow.camera.top = 5;
keyLight.shadow.camera.bottom = -5;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.8);
fillLight.position.set(-3, 2, -2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6633, 1.5, 15);
rimLight.position.set(-2, 1, -4);
scene.add(rimLight);

// ── Materials ────────────────────────────────────────────
const bladeMat = new THREE.MeshStandardMaterial({
  color: 0xccccdd,
  metalness: 0.95,
  roughness: 0.15,
});

const handleMat = new THREE.MeshStandardMaterial({
  color: 0x3b2018,
  metalness: 0.05,
  roughness: 0.7,
});

const guardMat = new THREE.MeshStandardMaterial({
  color: 0xbbaa88,
  metalness: 0.8,
  roughness: 0.25,
});

const edgeMat = new THREE.MeshStandardMaterial({
  color: 0xeeeeff,
  metalness: 0.95,
  roughness: 0.05,
});

// ── Blade ────────────────────────────────────────────────
function createBlade() {
  const group = new THREE.Group();

  // Blade profile (top-down XZ shape, we'll extrude in Y for thickness)
  const bladeShape = new THREE.Shape();
  bladeShape.moveTo(-0.12, -1.6);   // tip
  bladeShape.lineTo(-0.12, -0.8);   // tip end of edge
  bladeShape.lineTo(0.0, -0.75);    // slight curve near tip
  bladeShape.lineTo(0.0, 1.4);      // spine near guard
  bladeShape.lineTo(0.28, 1.4);     // spine end
  bladeShape.lineTo(0.28, -0.5);    // back
  bladeShape.lineTo(0.12, -0.5);    // heel
  bladeShape.lineTo(0.12, -1.6);    // back to tip

  const extrudeSettings = {
    steps: 1,
    depth: 0.04,
    bevelEnabled: true,
    bevelThickness: 0.008,
    bevelSize: 0.008,
    bevelSegments: 2,
  };

  const bladeGeo = new THREE.ExtrudeGeometry(bladeShape, extrudeSettings);
  bladeGeo.rotateX(Math.PI / 2);
  bladeGeo.translate(0, 0.02, 0);

  const blade = new THREE.Mesh(bladeGeo, bladeMat);
  blade.castShadow = true;
  blade.receiveShadow = true;
  group.add(blade);

  // Sharp edge line
  const edgeCurve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(-0.12, 0.0, -1.6),
    new THREE.Vector3(0.0, 0.0, -0.75),
    new THREE.Vector3(0.12, 0.0, -0.5),
  ]);
  const edgeGeo = new THREE.TubeGeometry(edgeCurve, 20, 0.004, 6, false);
  const edge = new THREE.Mesh(edgeGeo, edgeMat);
  group.add(edge);

  return group;
}

// ── Handle ───────────────────────────────────────────────
function createHandle() {
  const group = new THREE.Group();

  // Main handle body - slightly tapered cylinder
  const handleGeo = new THREE.CylinderGeometry(0.1, 0.13, 1.2, 16);
  const handle = new THREE.Mesh(handleGeo, handleMat);
  handle.position.set(0, 0, 2.2);
  handle.castShadow = true;
  handle.receiveShadow = true;
  group.add(handle);

  // Handle rings (decorative)
  for (let i = 0; i < 3; i++) {
    const ringGeo = new THREE.TorusGeometry(0.115 - i * 0.005, 0.01, 8, 24);
    const ring = new THREE.Mesh(ringGeo, guardMat);
    ring.position.set(0, 0, 1.7 + i * 0.4);
    ring.rotation.x = Math.PI / 2;
    ring.castShadow = true;
    group.add(ring);
  }

  // Pommel (end cap)
  const pommelGeo = new THREE.SphereGeometry(0.11, 16, 8, 0, Math.PI * 2, 0, Math.PI / 2);
  const pommel = new THREE.Mesh(pommelGeo, guardMat);
  pommel.position.set(0, 0, 2.8);
  pommel.rotation.x = Math.PI;
  pommel.castShadow = true;
  group.add(pommel);

  return group;
}

// ── Guard / Bolster ──────────────────────────────────────
function createGuard() {
  const group = new THREE.Group();

  // Main guard disc
  const guardGeo = new THREE.CylinderGeometry(0.22, 0.22, 0.08, 24);
  const guard = new THREE.Mesh(guardGeo, guardMat);
  guard.position.set(0, 0, 1.55);
  guard.castShadow = true;
  guard.receiveShadow = true;
  group.add(guard);

  // Guard flares
  const flareGeo = new THREE.TorusGeometry(0.2, 0.025, 8, 24);
  const flare = new THREE.Mesh(flareGeo, guardMat);
  flare.position.set(0, 0, 1.55);
  flare.rotation.x = Math.PI / 2;
  flare.castShadow = true;
  group.add(flare);

  // Cross-guard prongs
  for (const side of [-1, 1]) {
    const prongGeo = new THREE.CylinderGeometry(0.02, 0.015, 0.3, 8);
    const prong = new THREE.Mesh(prongGeo, guardMat);
    prong.position.set(side * 0.22, 0.12, 1.55);
    prong.rotation.z = side * 0.3;
    prong.castShadow = true;
    group.add(prong);
  }

  return group;
}

// ── Assemble Knife ───────────────────────────────────────
const knife = new THREE.Group();
knife.add(createBlade());
knife.add(createHandle());
knife.add(createGuard());

// Rotate so knife points right
knife.rotation.y = Math.PI / 2;
knife.rotation.z = 0.15;
knife.position.y = 0.3;
scene.add(knife);

// ── Ground Plane ─────────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(6, 48);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x222233,
  metalness: 0.3,
  roughness: 0.8,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ────────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  knife.rotation.y = Math.PI / 2 + Math.sin(t * 0.5) * 0.15;
  knife.position.y = 0.3 + Math.sin(t * 0.8) * 0.08;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ───────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the scene

| Part | Geometry | Material |
|---|---|---|
| **Blade** | `ExtrudeGeometry` with a hand-drawn blade profile shape + bevel | High metalness, low roughness steel |
| **Sharp edge** | `TubeGeometry` along a `CatmullRomCurve3` | Brighter, sharper metal highlight |
| **Handle** | `CylinderGeometry` (tapered) + 3 decorative `TorusGeometry` rings + `SphereGeometry` pommel | Dark brown, low metalness (wood-like) |
| **Guard/Bolster** | `CylinderGeometry` disc + `TorusGeometry` flare + prong cylinders | Brass/gold-toned metal |
| **Ground** | `CircleGeometry` | Dark matte surface, receives shadows |

**Lighting:** Three-point setup (warm key, cool fill, orange rim) + soft shadows. The knife gently floats and sways. Drag to orbit, scroll to zoom.

