// --- Kiwi skin (half ellipsoid) ---
const skinGeo = new THREE.SphereGeometry(1, 64, 32, 0, Math.PI * 2, 0, Math.PI / 2);
// Scale to ellipsoid
skinGeo.scale(1.3, 0.85, 1.3);

// Custom skin shader with fuzzy noise
const skinMat = new THREE.ShaderMaterial({
  uniforms: {
    uTime: { value: 0 },
    uColor: { value: new THREE.Color(0x6b4226) }
  },
  vertexShader: `
    varying vec3 vNormal;
    varying vec3 vPos;
    varying vec2 vUv;
    void main() {
      vNormal = normalize(normalMatrix * normal);
      vPos = position;
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform vec3 uColor;
    uniform float uTime;
    varying vec3 vNormal;
    varying vec3 vPos;
    varying vec2 vUv;

    float hash(vec2 p) {
      return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
    }

    float noise(vec2 p) {
      vec2 i = floor(p);
      vec2 f = fract(p);
      f = f * f * (3.0 - 2.0 * f);
      return mix(
        mix(hash(i), hash(i + vec2(1,0)), f.x),
        mix(hash(i + vec2(0,1)), hash(i + vec2(1,1)), f.x),
        f.y
      );
    }

    void main() {
      float n = noise(vUv * 80.0) * 0.15;
      float n2 = noise(vUv * 200.0) * 0.05;
      float fuzz = noise(vUv * 120.0 + uTime * 0.1);

      vec3 col = uColor + n + n2;
      col += fuzz * 0.05;

      // Hair-like streaks
      float hair = noise(vUv * vec2(300.0, 40.0));
      col += (hair - 0.5) * 0.08;

      // Rim darkening
      float rim = 1.0 - max(dot(vNormal, vec3(0,0,1)), 0.0);
      col *= 1.0 - rim * 0.3;

      gl_FragColor = vec4(col, 1.0);
    }
  `
});

const skin = new THREE.Mesh(skinGeo, skinMat);
skin.position.y = 0.05;
kiwiGroup.add(skin);

// --- Cut face (bottom) ---
const cutGeo = new THREE.CircleGeometry(1, 64);
cutGeo.scale(1.3, 1.3, 1);

const cutMat = new THREE.ShaderMaterial({
  uniforms: {
    uTime: { value: 0 }
  },
  vertexShader: `
    varying vec2 vUv;
    varying vec3 vPos;
    void main() {
      vUv = uv;
      vPos = position;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform float uTime;
    varying vec2 vUv;
    varying vec3 vPos;

    float hash(vec2 p) {
      return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
    }

    void main() {
      vec2 center = vUv - 0.5;
      float dist = length(center);

      // Core
      float core = smoothstep(0.12, 0.10, dist);
      vec3 coreCol = vec3(0.95, 0.92, 0.75);

      // Green flesh
      float flesh = smoothstep(0.48, 0.15, dist);
      vec3 greenCol = mix(vec3(0.25, 0.55, 0.15), vec3(0.4, 0.7, 0.2), dist);

      // Skin edge
      float skinEdge = smoothstep(0.50, 0.45, dist);
      vec3 skinCol = vec3(0.55, 0.35, 0.18);

      vec3 col = mix(skinCol, greenCol, flesh);
      col = mix(col, coreCol, core);

      // Variations in green
      float angle = atan(center.y, center.x);
      float stripe = sin(angle * 12.0 + dist * 20.0) * 0.5 + 0.5;
      stripe = pow(stripe, 3.0) * 0.06 * flesh;
      col += stripe;

      // Brightness variation
      float n = hash(floor(vUv * 200.0));
      col += (n - 0.5) * 0.02;

      // Subtle specular
      float spec = smoothstep(0.48, 0.40, dist) * 0.1;
      col += spec * vec3(0.3, 0.3, 0.1);

      // Discard outside circle
      if (dist > 0.5) discard;

      gl_FragColor = vec4(col, 1.0);
    }
  `
});

const cutFace = new THREE.Mesh(cutGeo, cutMat);
