const RAIL_HEIGHT    = 7;
const RAIL_WIDTH     = 0.12;
const RAIL_DEPTH     = 0.18;
const RUNG_WIDTH     = 1.2;
const RUNG_THICKNESS = 0.08;
const RUNG_DEPTH     = 0.12;
const LADDER_TILT    = 0.15; // radians lean back

// ── Materials ─────────────────────────────────────────────
const railMaterial = new THREE.MeshStandardMaterial({
  color: 0x8B6914,
  roughness: 0.45,
  metalness: 0.05,
});

const rungMaterial = new THREE.MeshStandardMaterial({
  color: 0xA07820,
  roughness: 0.55,
  metalness: 0.02,
});

// ── Build Ladder ──────────────────────────────────────────
const ladderGroup = new THREE.Group();

// Rails
const railGeo = new THREE.BoxGeometry(RAIL_DEPTH, RAIL_HEIGHT, RAIL_WIDTH);
const leftRail  = new THREE.Mesh(railGeo, railMaterial);
const rightRail = new THREE.Mesh(railGeo, railMaterial);

leftRail.position.set(-RUNG_WIDTH / 2, RAIL_HEIGHT / 2, 0);
rightRail.position.set( RUNG_WIDTH / 2, RAIL_HEIGHT / 2, 0);

leftRail.castShadow = true;
rightRail.castShadow = true;

ladderGroup.add(leftRail);
ladderGroup.add(rightRail);

// Rungs
const rungGeo = new THREE.BoxGeometry(RUNG_DEPTH, RUNG_THICKNESS, RUNG_WIDTH - RAIL_WIDTH * 0.2);
const rungSpacing = RAIL_HEIGHT / (NUM_RUNGS - 1);

for (let i = 0; i < NUM_RUNGS; i++) {
  const rung = new THREE.Mesh(rungGeo, rungMaterial);
  rung.position.set(0, i * rungSpacing, 0);
  rung.castShadow = true;
  rung.receiveShadow = true;
  ladderGroup.add(rung);
}

// Lean the ladder back slightly
ladderGroup.rotation.x = -LADDER_TILT;
scene.add(ladderGroup);

// ── Subtle floating particles ─────────────────────────────
const particleCount = 120;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3]     = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = Math.random() * 12;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0x8888cc,
  size: 0.04,
  transparent: true,
  opacity: 0.5,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation Loop ────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle particle drift
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(elapsed + i) * 0.0003;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ────────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>

</body>
</html>
```

