</head>
<body>
  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene, Camera, Renderer ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

    const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 1.5, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    // ── Lighting ──
    const ambient = new THREE.AmbientLight(0xffeedd, 0.6);
    scene.add(ambient);

    const keyLight = new THREE.DirectionalLight(0xfff4e0, 3.5);
    keyLight.position.set(4, 6, 4);
    keyLight.castShadow = true;
    keyLight.shadow.mapSize.set(1024, 1024);
    keyLight.shadow.camera.near = 1;
    keyLight.shadow.camera.far = 20;
    keyLight.shadow.camera.left = -4;
    keyLight.shadow.camera.right = 4;
    keyLight.shadow.camera.top = 4;
    keyLight.shadow.camera.bottom = -4;
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0xc8d8ff, 1.0);
    fillLight.position.set(-3, 2, -2);
    scene.add(fillLight);

    const rimLight = new THREE.DirectionalLight(0xffe066, 1.5);
    rimLight.position.set(-2, 3, -5);
    scene.add(rimLight);

    // ── Lemon Geometry ──
    // Build a lemon profile and revolve it
    const points = [];
    const segments = 64;
    for (let i = 0; i <= segments; i++) {
      const t = i / segments;
      const angle = t * Math.PI; // 0 to PI
      // Radius profile: wide in middle, tapers to points
      const r = Math.sin(angle) * Math.pow(Math.sin(angle), 0.25);
      // Position along axis: from -1.6 to +1.6
      const y = Math.cos(angle) * 1.6;
      points.push(new THREE.Vector2(Math.max(r * 0.85, 0.001), y));
    }

    const lemonGeo = new THREE.LatheGeometry(points, 48);
    lemonGeo.computeVertexNormals();

    // ── Lemon Material ──
    const lemonMat = new THREE.MeshStandardMaterial({
      color: 0xffd700,
      roughness: 0.45,
      metalness: 0.0,
      bumpScale: 0.005,
    });

    // Procedural bump texture for citrus dimples
    const bumpCanvas = document.createElement('canvas');
    bumpCanvas.width = 256;
    bumpCanvas.height = 256;
    const ctx = bumpCanvas.getContext('2d');
    ctx.fillStyle = '#808080';
    ctx.fillRect(0, 0, 256, 256);
    for (let i = 0; i < 2000; i++) {
      const x = Math.random() * 256;
      const y = Math.random() * 256;
      const r = Math.random() * 3 + 1;
      const v = Math.random() > 0.5 ? 100 + Math.random() * 55 : 70 + Math.random() * 40;
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.fillStyle = `rgb(${v},${v},${v})`;
      ctx.fill();
    }
    const bumpTexture = new THREE.CanvasTexture(bumpCanvas);
    lemonMat.bumpMap = bumpTexture;
    lemonMat.bumpScale = 0.015;

    const lemon = new THREE.Mesh(lemonGeo, lemonMat);
    lemon.rotation.z = Math.PI / 2;
    lemon.castShadow = true;
    lemon.receiveShadow = true;
    scene.add(lemon);

    // ── Stem (tiny cone) ──
    const stemGeo = new THREE.ConeGeometry(0.04, 0.25, 8);
    const stemMat = new THREE.MeshStandardMaterial({ color: 0x5a7247, roughness: 0.8 });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.position.set(1.6, 0, 0);
    stem.rotation.z = -Math.PI / 2;
    stem.castShadow = true;
    lemon.add(stem);

    // ── Small leaf ──
    const leafShape = new THREE.Shape();
    leafShape.moveTo(0, 0);
    leafShape.quadraticCurveTo(0.15, 0.2, 0.1, 0.5);
    leafShape.quadraticCurveTo(0, 0.55, -0.1, 0.5);
    leafShape.quadraticCurveTo(-0.15, 0.2, 0, 0);

    const leafGeo = new THREE.ShapeGeometry(leafShape, 12);
    const leafMat = new THREE.MeshStandardMaterial({
      color: 0x4a8c3f,
      roughness: 0.6,
      side: THREE.DoubleSide,
    });
    const leaf = new THREE.Mesh(leafGeo, leafMat);
    leaf.position.set(1.55, 0.05, 0);
    leaf.rotation.set(0.3, -0.5, 0.8);
    leaf.scale.set(1.2, 1.2, 1.2);
    leaf.castShadow = true;
    lemon.add(leaf);

    // ── Ground Plane ──
    const groundGeo = new THREE.CircleGeometry(8, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x1a1a2e,
      roughness: 0.9,
      metalness: 0.1,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Subtle particle ring (for ambiance) ──
    const particleCount = 300;
    const particleGeo = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      const angle = Math.random() * Math.PI * 2;
      const radius = 3 + Math.random() * 5;
      positions[i * 3] = Math.cos(angle) * radius;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 4;
      positions[i * 3 + 2] = Math.sin(angle) * radius;
    }
    particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const particleMat = new THREE.PointsMaterial({
      color: 0xffd700,
      size: 0.02,
      transparent: true,
      opacity: 0.4,
    });
    const particles = new THREE.Points(particleGeo, particleMat);
    scene.add(particles);

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Gentle float and rotate
      lemon.position.y = Math.sin(elapsed * 0.5) * 0.15;
      lemon.rotation.y = elapsed * 0.15;

      particles.rotation.y = elapsed * 0.02;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
