// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x406040, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
dirLight.position.set(3, 5, 4);
scene.add(dirLight);

const backLight = new THREE.DirectionalLight(0x88ccff, 0.6);
backLight.position.set(-3, 2, -3);
scene.add(backLight);

const pointLight = new THREE.PointLight(0xff9944, 0.5, 10);
pointLight.position.set(-2, 1, 3);
scene.add(pointLight);

// --- Leaf Geometry ---
function createLeafGeometry() {
  const widthSegments = 60;
  const heightSegments = 100;
  const geometry = new THREE.PlaneGeometry(1, 1, widthSegments, heightSegments);

  const pos = geometry.attributes.position;
  const uv = geometry.attributes.uv;
  const colors = new Float32Array(pos.count * 3);

  const greenBase = new THREE.Color(0x2d8a4e);
  const greenDark = new THREE.Color(0x1a5c32);
  const greenLight = new THREE.Color(0x4aad6a);
  const stemColor = new THREE.Color(0x3a7a3a);

  for (let i = 0; i < pos.count; i++) {
    const u = uv.getX(i);
    const v = uv.getY(i);

    // Map [0,1] x [0,1] to leaf shape
    const t = v; // 0 = base, 1 = tip
    const s = u - 0.5; // centered horizontal

    // Leaf width profile: wide in middle, narrow at tip and base
    const widthCurve = Math.sin(t * Math.PI) * Math.pow(t, 0.4);
    // Wavy edges
    const wave = Math.sin(t * 12 + s * 8) * 0.02 * t;
    const halfWidth = (0.35 * widthCurve + wave);

    let x = s * 2 * halfWidth;
    let y = t * 2.2 - 0.5;
    let z = 0;

    // Central ridge (midrib) - slight upward bulge
    const distFromCenter = Math.abs(s);
    const ridge = Math.exp(-distFromCenter * 20) * 0.06 * Math.sin(t * Math.PI);
    z += ridge;

    // Vein displacement - subtle surface variation
    const veinAngle = Math.atan2(x, y * 0.5);
    const veinFreq = 5;
    const veinDisp = Math.sin(veinAngle * veinFreq + t * 8) * 0.008 * (1 - Math.exp(-t * 3));
    z += veinDisp;

    // Slight curl at tip
    if (t > 0.7) {
      const curlAmount = (t - 0.7) / 0.3;
      z -= curlAmount * curlAmount * 0.15;
    }

    // Gentle overall curve
    z -= Math.sin(t * Math.PI) * 0.03;

    pos.setXYZ(i, x, y, z);

    // Vertex colors
    const mixFactor = t * 0.5 + Math.random() * 0.05;
    const color = greenBase.clone().lerp(greenLight, mixFactor);

    // Darker near edges
    const edgeFactor = Math.abs(s) / (0.5 + 0.001);
    if (edgeFactor > 0.8) {
      color.lerp(greenDark, (edgeFactor - 0.8) * 3);
    }

    // Stem area at base
    if (t < 0.15) {
      const stemFactor = 1 - t / 0.15;
      color.lerp(stemColor, stemFactor * 0.5);
    }

    colors[i * 3] = color.r;
    colors[i * 3 + 1] = color.g;
    colors[i * 3 + 2] = color.b;
  }

  geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));
  geometry.computeVertexNormals();
  return geometry;
}

// --- Leaf Material ---
const leafMaterial = new THREE.MeshPhysicalMaterial({
  vertexColors: true,
  roughness: 0.6,
  metalness: 0.0,
  clearcoat: 0.15,
  clearcoatRoughness: 0.4,
  side: THREE.DoubleSide,
  sheen: 0.3,
  sheenRoughness: 0.8,
  sheenColor: new THREE.Color(0x33aa55),
});

const leaf = new THREE.Mesh(createLeafGeometry(), leafMaterial);
scene.add(leaf);

// --- Stem ---
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, -0.5, 0),
  new THREE.Vector3(0.02, -0.8, 0.01),
  new THREE.Vector3(0.05, -1.1, -0.02),
  new THREE.Vector3(0.08, -1.4, 0.01),
]);

const stemGeo = new THREE.TubeGeometry(stemCurve, 20, 0.025, 8, false);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x3a6b2a,
  roughness: 0.8,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
scene.add(stem);

// --- Vein Lines ---
function createVeins() {
  const veinGroup = new THREE.Group();
  const veinMat = new THREE.LineBasicMaterial({ color: 0x1e6b35, transparent: true, opacity: 0.35 });

  // Secondary veins branching from midrib
  for (let i = 0; i < 12; i++) {
    const t = 0.15 + (i / 12) * 0.7;
    const baseY = t * 2.2 - 0.5;
    const widthAtT = Math.sin(t * Math.PI) * Math.pow(t, 0.4) * 0.35;

    for (let side = -1; side <= 1; side += 2) {
      const points = [];
      const segments = 6;
      for (let j = 0; j <= segments; j++) {
        const jt = j / segments;
        const x = side * jt * widthAtT * (0.9 - jt * 0.3);
        const y = baseY + jt * 0.15 * side * 0.3;
        const z = Math.exp(-Math.abs(x / widthAtT) * 5) * 0.04;
        points.push(new THREE.Vector3(x, y, z));
      }
      const curve = new THREE.CatmullRomCurve3(points);
      const veinGeo = new THREE.BufferGeometry().setFromPoints(curve.getPoints(20));
      const veinLine = new THREE.Line(veinGeo, veinMat);
      veinGroup.add(veinLine);
    }
  }

  return veinGroup;
}

const veins = createVeins();
leaf.add(veins);

// --- Particles (dust/pollen) ---
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3] = (Math.random() - 0.5) * 8;
  particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 8;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 8;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xaaddaa,
  size: 0.02,
  transparent: true,
  opacity: 0.4,
  sizeAttenuation: true,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle sway
  leaf.rotation.z = Math.sin(elapsed * 0.5) * 0.05;
  leaf.rotation.x = Math.sin(elapsed * 0.3) * 0.02;

  // Slow rotation for display
  leaf.rotation.y = elapsed * 0.15;

  // Animate particles
  const pp = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pp.setY(i, pp.getY(i) + 0.002);
    pp.setX(i, pp.getX(i) + Math.sin(elapsed + i) * 0.0003);
    if (pp.getY(i) > 4) pp.setY(i, -4);
  }
  pp.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **3D leaf** with:

- **Parametric leaf shape** — elliptical profile with a pointed tip, wavy edges, and a curled apex
- **Central ridge (midrib)** — subtle upward bulge down the center
- **Vein network** — translucent branching lines from the midrib to the edges
- **Vertex colors** — green gradient from dark edges to lighter center, darker stem base
- **Stem** — a curved tube extending from the leaf base
- **PBR material** — `MeshPhysicalMaterial` with clearcoat and sheen for a realistic waxy surface
- **Multi-light setup** — warm key light, cool back light, and accent point light
- **Floating particles** — subtle pollen/dust motes drifting upward
- **Gentle animation** — slow rotation + natural sway
- **Orbit controls** — drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Lightbulb</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
        "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0a0a12);
    scene.fog = new THREE.FogExp2(0x0a0a12, 0.08);

    // ── Camera ──
    const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 2, 8);

    // ── Renderer ──
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.target.set(0, 1.5, 0);

    // ── Lightbulb Group ──
    const bulb = new THREE.Group();

    // Glass envelope (rounded sphere)
    const glassGeo = new THREE.SphereGeometry(1.5, 64, 48, 0, Math.PI * 2, 0, Math.PI * 0.72);
    const glassMat = new THREE.MeshPhysicalMaterial({
      color: 0xffffff,
      transmission: 0.92,
      opacity: 1,
      transparent: true,
      metalness: 0,
      roughness: 0.05,
      ior: 1.5,
      thickness: 0.1,
      side: THREE.DoubleSide,
      depthWrite: false,
    });
    const glass = new THREE.Mesh(glassGeo, glassMat);
    glass.position.y = 2.6;
    bulb.add(glass);

    // Filament wire (catenary shape)
    const filamentPoints = [];
    for (let i = 0; i <= 40; i++) {
      const t = (i / 40) * Math.PI;
      const x = Math.cos(t) * 0.4;
      const y = 2.0 - Math.cos(t) * 0.35 + Math.sin(t) * 0.15;
      filamentPoints.push(new THREE.Vector3(x, y, 0));
    }
    const filamentCurve = new THREE.CatmullRomCurve3(filamentPoints);
    const filamentGeo = new THREE.TubeGeometry(filamentCurve, 64, 0.012, 8, false);
    const filamentMat = new THREE.MeshStandardMaterial({
      color: 0xffaa33,
      emissive: 0xffaa33,
      emissiveIntensity: 3,
      toneMapped: false,
    });
    const filament = new THREE.Mesh(filamentGeo, filamentMat);
    bulb.add(filament);

    // Inner support wires
    for (let i = 0; i < 2; i++) {
      const angle = (i - 0.5) * 0.6;
      const pts = [
        new THREE.Vector3(0, 1.3, 0),
        new THREE.Vector3(Math.sin(angle) * 0.3, 1.7, Math.cos(angle) * 0.1),
        new THREE.Vector3(Math.cos(angle) * 0.4, 2.0 + Math.sin(angle) * 0.15, 0),
      ];
      const curve = new THREE.CatmullRomCurve3(pts);
      const wireGeo = new THREE.TubeGeometry(curve, 20, 0.008, 6, false);
      const wire = new THREE.Mesh(wireGeo, filamentMat);
      bulb.add(wire);
    }

    // Screw base (threaded metal cylinder)
    const baseMat = new THREE.MeshStandardMaterial({
      color: 0x888888,
      metalness: 0.9,
      roughness: 0.3,
    });

    // Main screw body
    const screwBodyGeo = new THREE.CylinderGeometry(0.55, 0.55, 1.3, 32);
    const screwBody = new THREE.Mesh(screwBodyGeo, baseMat);
    screwBody.position.y = 0.65;
    bulb.add(screwBody);

    // Screw threads (torus rings stacked)
    for (let i = 0; i < 6; i++) {
      const threadGeo = new THREE.TorusGeometry(0.57, 0.04, 8, 32);
      const thread = new THREE.Mesh(threadGeo, baseMat);
      thread.position.y = 0.25 + i * 0.18;
      thread.rotation.x = Math.PI / 2;
      bulb.add(thread);
    }

    // Bottom contact tip
    const tipGeo = new THREE.CylinderGeometry(0.2, 0.3, 0.2, 16);
    const tipMat = new THREE.MeshStandardMaterial({ color: 0x666666, metalness: 0.8, roughness: 0.4 });
    const tip = new THREE.Mesh(tipGeo, tipMat);
    tip.position.y = -0.05;
    bulb.add(tip);

    // Insulating ring between threads and tip
    const insulatorGeo = new THREE.CylinderGeometry(0.4, 0.45, 0.12, 32);
    const insulatorMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.8 });
    const insulator = new THREE.Mesh(insulatorGeo, insulatorMat);
    insulator.position.y = 0.02;
    bulb.add(insulator);

    // Top glass-to-metal seal
    const sealGeo = new THREE.CylinderGeometry(0.35, 0.55, 0.15, 32);
    const sealMat = new THREE.MeshStandardMaterial({ color: 0x444444, metalness: 0.7, roughness: 0.5 });
    const seal = new THREE.Mesh(sealGeo, sealMat);
    seal.position.y = 1.35;
    bulb.add(seal);

    // Inner stem (glass rod holding filament)
    const stemGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.8, 12);
    const stemMat = new THREE.MeshPhysicalMaterial({
      color: 0xffffff, transmission: 0.8, transparent: true, opacity: 0.5, roughness: 0.1,
    });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.position.y = 1.7;
    bulb.add(stem);

    scene.add(bulb);

    // ── Lighting ──
    // Warm point light from inside the bulb
    const pointLight = new THREE.PointLight(0xffcc77, 40, 15, 1.5);
    pointLight.position.set(0, 2.2, 0);
    bulb.add(pointLight);

    // Subtle ambient
    scene.add(new THREE.AmbientLight(0x111122, 0.5));

    // Rim light for the glass
    const rimLight = new THREE.DirectionalLight(0x4466aa, 0.8);
    rimLight.position.set(3, 4, 5);
    scene.add(rimLight);

    // ── Ground reflection hint ──
    const groundGeo = new THREE.CircleGeometry(6, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x0a0a12, metalness: 0.5, roughness: 0.3,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.15;
    scene.add(ground);

    // ── Glow sprite ──
    const glowCanvas = document.createElement('canvas');
    glowCanvas.width = 256;
    glowCanvas.height = 256;
    const ctx = glowCanvas.getContext('2d');
    const gradient = ctx.createRadialGradient(128, 128, 0, 128, 128, 128);
    gradient.addColorStop(0, 'rgba(255,200,100,0.35)');
    gradient.addColorStop(0.4, 'rgba(255,160,60,0.12)');
    gradient.addColorStop(1, 'rgba(255,100,0,0)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, 256, 256);
    const glowTexture = new THREE.CanvasTexture(glowCanvas);
    const glowSprite = new THREE.Sprite(
      new THREE.SpriteMaterial({ map: glowTexture, blending: THREE.AdditiveBlending, transparent: true, depthWrite: false })
    );
    glowSprite.position.set(0, 2.2, 0);
    glowSprite.scale.set(5, 5, 1);
    bulb.add(glowSprite);

    // ── Animate ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle bob
      bulb.position.y = Math.sin(t * 0.8) * 0.15;

      // Flicker
      const flicker = 0.92 + Math.sin(t * 12) * 0.02 + Math.sin(t * 7.3) * 0.015;
      pointLight.intensity = 40 * flicker;
      filamentMat.emissiveIntensity = 3 * flicker;
      glowSprite.material.opacity = flicker;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
