});
const lantern = new THREE.Mesh(glassGeo, glassMat);
lantern.position.y = 21.25;
towerGroup.add(lantern);

// --- Roof / Dome ---
const roofGeo = new THREE.ConeGeometry(1.5, 2, 16);
const roofMat = new THREE.MeshStandardMaterial({ color: 0x222222, metalness: 0.6, roughness: 0.3 });
const roof = new THREE.Mesh(roofGeo, roofMat);
roof.position.y = 23.5;
roof.castShadow = true;
towerGroup.add(roof);

// Ball on top
