const ball = new THREE.Mesh(ballGeo, new THREE.MeshStandardMaterial({ color: 0x111111, metalness: 0.8 }));
ball.position.y = 24.7;
towerGroup.add(ball);

scene.add(towerGroup);

// --- Light Beam ---
const beamSpot = new THREE.SpotLight(0xffeedd, 50, 120, Math.PI / 6, 0.4, 1.5);
beamSpot.position.set(0, 21, 0);
beamSpot.castShadow = false;
towerGroup.add(beamSpot);

// Visible beam cone
const beamGeo = new THREE.ConeGeometry(0.5, 80, 32, 1, true);
const beamMat = new THREE.MeshBasicMaterial({
  color: 0xffeedd, transparent: true, opacity: 0.04,
