});
const beam = new THREE.Mesh(beamGeo, beamMat);
beam.rotation.x = Math.PI / 2;
beam.position.z = 40;
beam.position.y = 0;
towerGroup.add(beam);
beamSpot.target = beam;

// Inner bright beam
const beamInnerGeo = new THREE.ConeGeometry(0.15, 80, 16, 1, true);
const beamInnerMat = new THREE.MeshBasicMaterial({
  color: 0xffffee, transparent: true, opacity: 0.12,
  side: THREE.DoubleSide, depthWrite: false, blending: THREE.AdditiveBlending
});
const beamInner = new THREE.Mesh(beamInnerGeo, beamInnerMat);
beamInner.rotation.x = Math.PI / 2;
beamInner.position.z = 40;
towerGroup.add(beamInner);

// Point light inside lantern
const lanternLight = new THREE.PointLight(0xffaa33, 10, 20);
lanternLight.position.y = 21;
towerGroup.add(lanternLight);

// --- Stars ---
const starsGeo = new THREE.BufferGeometry();
const starPositions = [];
for (let i = 0; i < 1500; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.random() * Math.PI * 0.45;
  const r = 200 + Math.random() * 50;
  starPositions.push(
    r * Math.sin(phi) * Math.cos(theta),
    r * Math.cos(phi) + 20,
    r * Math.sin(phi) * Math.sin(theta)
  );
}
starsGeo.setAttribute('position', new THREE.Float32BufferAttribute(starPositions, 3));
const starsMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.5, sizeAttenuation: true });
scene.add(new THREE.Points(starsGeo, starsMat));

// --- Camera orbit ---
let angle = 0;
const camRadius = 35;
const camHeight = 14;

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Rotate beam
  beamSpot.angle = Math.PI / 6;
  beamSpot.position.set(0, 21, 0);
  const beamAngle = t * 0.5;
  beamSpot.target.position.set(Math.cos(beamAngle) * 60, 0, Math.sin(beamAngle) * 60);
  beamSpot.updateMatrixWorld();
  beam.lookAt(beamSpot.target.position);
  beamInner.lookAt(beamSpot.target.position);

  // Pulse lantern glow
  lanternLight.intensity = 8 + Math.sin(t * 3) * 2;
  glassMat.emissiveIntensity = 1.5 + Math.sin(t * 3) * 0.5;

  // Animate ocean
  const pos = oceanGeo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    pos.setZ(i, Math.sin(x * 0.15 + t * 0.8) * 0.5 + Math.cos(y * 0.12 + t * 0.6) * 0.4);
  }
  pos.needsUpdate = true;
  oceanGeo.computeVertexNormals();

  // Camera orbit
  angle += 0.002;
  camera.position.x = Math.cos(angle) * camRadius;
  camera.position.z = Math.sin(angle) * camRadius;
  camera.position.y = camHeight + Math.sin(angle * 0.5) * 3;
  camera.lookAt(0, 10, 0);

  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**Features included:**

- **Tapered lighthouse tower** with red-and-white striped texture (8 alternating bands)
- **Lantern room** with glowing glass, railing, and a dome roof with a ball on top
- **Rotating light beam** — a spotlight + two visible cone meshes (wide dim + narrow bright) with additive blending
- **Pulsing glow** from the lantern room (sine-wave animated intensity)
- **Animated ocean** — vertex displacement on a plane geometry simulating waves
- **Rocky island base** — a cylinder platform surrounded by scattered dodecahedron rocks
- **Night sky** with 1,500 stars as point particles
- **Fog** for atmospheric depth
- **Slow orbiting camera** that circles the lighthouse
