<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoundedBoxGeometry } from 'three/addons/geometries/RoundedBoxGeometry.js';

// ── Renderer ────────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Scene & Camera ──────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a0f);
scene.fog = new THREE.FogExp2(0x0a0a0f, 0.04);

const camera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 6);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);
controls.minDistance = 3;
controls.maxDistance = 15;

// ── Lighting ────────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x334466, 0.5);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xffeedd, 3);
mainLight.position.set(4, 6, 4);
mainLight.castShadow = true;
mainLight.shadow.mapSize.set(1024, 1024);
mainLight.shadow.camera.near = 1;
mainLight.shadow.camera.far = 20;
mainLight.shadow.camera.left = -4;
mainLight.shadow.camera.right = 4;
mainLight.shadow.camera.top = 4;
mainLight.shadow.camera.bottom = -4;
mainLight.shadow.radius = 4;
scene.add(mainLight);

const fillLight = new THREE.DirectionalLight(0x4488cc, 1);
fillLight.position.set(-3, 2, -2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6633, 2, 12);
rimLight.position.set(-2, -1, -3);
scene.add(rimLight);

const topLight = new THREE.PointLight(0xffffff, 1.5, 10);
topLight.position.set(0, 5, 0);
scene.add(topLight);

// ── Materials ───────────────────────────────────────────
const bodyMaterial = new THREE.MeshStandardMaterial({
  color: 0x8a8a9a,
  metalness: 0.92,
  roughness: 0.18,
});

const shackleMaterial = new THREE.MeshStandardMaterial({
  color: 0xb0b0c0,
  metalness: 0.95,
  roughness: 0.12,
});

const keyholeMaterial = new THREE.MeshStandardMaterial({
  color: 0x111115,
  metalness: 0.3,
  roughness: 0.8,
});

const darkMetalMaterial = new THREE.MeshStandardMaterial({
  color: 0x333340,
  metalness: 0.9,
  roughness: 0.3,
});

const pinMaterial = new THREE.MeshStandardMaterial({
  color: 0xccaa44,
  metalness: 0.85,
  roughness: 0.25,
});

// ── Lock Group ──────────────────────────────────────────
const lockGroup = new THREE.Group();
scene.add(lockGroup);

// ── Lock Body ───────────────────────────────────────────
const bodyWidth = 2.0;
const bodyHeight = 1.4;
const bodyDepth = 0.7;

const bodyGeo = new RoundedBoxGeometry(bodyWidth, bodyHeight, bodyDepth, 6, 0.12);
const body = new THREE.Mesh(bodyGeo, bodyMaterial);
body.castShadow = true;
body.receiveShadow = true;
lockGroup.add(body);

// ── Body Bevel / Edge Ring ──────────────────────────────
const edgeGeo = new RoundedBoxGeometry(bodyWidth + 0.06, bodyHeight + 0.06, bodyDepth + 0.06, 4, 0.15);
const edge = new THREE.Mesh(edgeGeo, darkMetalMaterial);
edge.scale.set(1, 1, 1);
lockGroup.add(edge);
// Subtract effect: place edge behind body
edge.position.z = -0.01;
edge.renderOrder = -1;
// Actually let's just skip this overlapping approach and use a simpler border

// ── Shackle ─────────────────────────────────────────────
const shackleWidth = bodyWidth * 0.65;
const shackleHeight = 1.6;
const shackleRadius = 0.13;

// Build shackle from parts: left leg, right leg, and top arc
const legHeight = shackleHeight * 0.45;
const halfShackleWidth = shackleWidth / 2;

// Left leg
const legGeo = new THREE.CylinderGeometry(shackleRadius, shackleRadius, legHeight, 24);
const leftLeg = new THREE.Mesh(legGeo, shackleMaterial);
leftLeg.position.set(-halfShackleWidth, legHeight / 2 - bodyHeight / 2 + 0.15, 0);
leftLeg.castShadow = true;
lockGroup.add(leftLeg);

// Right leg
const rightLeg = new THREE.Mesh(legGeo, shackleMaterial);
rightLeg.position.set(halfShackleWidth, legHeight / 2 - bodyHeight / 2 + 0.15, 0);
rightLeg.castShadow = true;
lockGroup.add(rightLeg);

// Top arc (half torus)
const arcGeo = new THREE.TorusGeometry(
  halfShackleWidth, shackleRadius, 24, 48, Math.PI
);
const arc = new THREE.Mesh(arcGeo, shackleMaterial);
arc.position.set(0, legHeight - bodyHeight / 2 + 0.15, 0);
arc.rotation.z = Math.PI; // flip so it arches upward
arc.castShadow = true;
lockGroup.add(arc);

// Shackle base plates (where legs meet body)
const plateGeo = new THREE.CylinderGeometry(shackleRadius + 0.08, shackleRadius + 0.08, 0.08, 24);
const leftPlate = new THREE.Mesh(plateGeo, darkMetalMaterial);
leftPlate.position.copy(leftLeg.position);
leftPlate.position.y = leftLeg.position.y - legHeight / 2 + 0.04;
lockGroup.add(leftPlate);

const rightPlate = new THREE.Mesh(plateGeo, darkMetalMaterial);
rightPlate.position.copy(rightLeg.position);
rightPlate.position.y = rightLeg.position.y - legHeight / 2 + 0.04;
lockGroup.add(rightPlate);

// ── Keyhole ─────────────────────────────────────────────
// Circular part
const keyHoleCircleGeo = new THREE.CircleGeometry(0.15, 32);
const keyHoleCircle = new THREE.Mesh(keyHoleCircleGeo, keyholeMaterial);
keyHoleCircle.position.set(0, 0.12, bodyDepth / 2 + 0.005);
lockGroup.add(keyHoleCircle);

// Slot part (rectangle)
const keyHoleSlotGeo = new THREE.PlaneGeometry(0.12, 0.45);
const keyHoleSlot = new THREE.Mesh(keyHoleSlotGeo, keyholeMaterial);
keyHoleSlot.position.set(0, -0.18, bodyDepth / 2 + 0.005);
lockGroup.add(keyHoleSlot);

// Keyhole ring / trim
const ringGeo = new THREE.RingGeometry(0.14, 0.2, 32);
const ringMat = new THREE.MeshStandardMaterial({
  color: 0x222228, metalness: 0.9, roughness: 0.3, side: THREE.DoubleSide
});
const ring = new THREE.Mesh(ringGeo, ringMat);
ring.position.set(0, 0.12, bodyDepth / 2 + 0.006);
lockGroup.add(ring);

// ── Bottom Plate ────────────────────────────────────────
const bottomPlateGeo = new RoundedBoxGeometry(bodyWidth * 0.5, 0.08, bodyDepth * 0.6, 3, 0.03);
const bottomPlate = new THREE.Mesh(bottomPlateGeo, darkMetalMaterial);
bottomPlate.position.set(0, -bodyHeight / 2 - 0.04, 0);
lockGroup.add(bottomPlate);

// ── Decorative pins/rivets ──────────────────────────────
const rivetGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.06, 16);
const rivetPositions = [
  [bodyWidth / 2 - 0.2, bodyHeight / 2 - 0.2],
  [-bodyWidth / 2 + 0.2, bodyHeight / 2 - 0.2],
  [bodyWidth / 2 - 0.2, -bodyHeight / 2 + 0.2],
  [-bodyWidth / 2 + 0.2, -bodyHeight / 2 + 0.2],
];

rivetPositions.forEach(([x, y]) => {
  const rivet = new THREE.Mesh(rivetGeo, pinMaterial);
  rivet.rotation.x = Math.PI / 2;
  rivet.position.set(x, y, bodyDepth / 2 + 0.03);
  lockGroup.add(rivet);
});

// ── Engraved Line Details ───────────────────────────────
const lineGeo = new THREE.PlaneGeometry(bodyWidth * 0.7, 0.02);
const lineMat = new THREE.MeshStandardMaterial({
  color: 0x555560, metalness: 0.8, roughness: 0.4, side: THREE.DoubleSide
});

[-0.35, 0.35].forEach(y => {
  const line = new THREE.Mesh(lineGeo, lineMat);
  line.position.set(0, y, bodyDepth / 2 + 0.004);
  lockGroup.add(line);
});

// ── Ground Plane ────────────────────────────────────────
const groundGeo = new THREE.PlaneGeometry(30, 30);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x0a0a0f, metalness: 0.5, roughness: 0.8
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating Particles ──────────────────────────────────
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const particleSpeeds = [];

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 12;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 8;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 8;
  particleSpeeds.push(0.002 + Math.random() * 0.005);
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0x6688cc,
  size: 0.03,
  transparent: true,
  opacity: 0.5,
  sizeAttenuation: true,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ───────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating motion
  lockGroup.position.y = Math.sin(t * 0.8) * 0.15;
  lockGroup.rotation.y = Math.sin(t * 0.3) * 0.15;
  lockGroup.rotation.x = Math.sin(t * 0.2) * 0.05;

  // Animate particles
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += particleSpeeds[i];
    if (pos.array[i * 3 + 1] > 4) {
      pos.array[i * 3 + 1] = -4;
    }
  }
  pos.needsUpdate = true;

  // Subtle rim light animation
  rimLight.intensity = 2 + Math.sin(t * 1.5) * 0.5;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
</body>
</html>
