document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.8, 0);
controls.enableDamping = true;
controls.maxPolarAngle = Math.PI / 2.05;

// --- Procedural Textures ---
function createBarkTexture() {
  const c = document.createElement('canvas');
  c.width = 512; c.height = 512;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#5a3a1a';
  ctx.fillRect(0, 0, 512, 512);
  for (let i = 0; i < 300; i++) {
    const y = Math.random() * 512;
    ctx.strokeStyle = `rgba(${40 + Math.random()*40},${25 + Math.random()*20},${10 + Math.random()*15},${0.3 + Math.random()*0.5})`;
    ctx.lineWidth = 1 + Math.random() * 4;
    ctx.beginPath();
    ctx.moveTo(0, y);
    for (let x = 0; x < 512; x += 20) {
      ctx.lineTo(x, y + (Math.random() - 0.5) * 12);
    }
    ctx.stroke();
  }
  for (let i = 0; i < 40; i++) {
    const x = Math.random() * 512;
    ctx.strokeStyle = `rgba(30,15,5,${0.2 + Math.random()*0.3})`;
    ctx.lineWidth = 2 + Math.random() * 6;
    ctx.beginPath();
    ctx.moveTo(x, 0);
    for (let y = 0; y < 512; y += 15) {
      ctx.lineTo(x + (Math.random() - 0.5) * 10, y);
    }
    ctx.stroke();
  }
  const tex = new THREE.CanvasTexture(c);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  tex.repeat.set(3, 1);
  return tex;
}

function createBarkNormal() {
  const c = document.createElement('canvas');
  c.width = 512; c.height = 512;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#8080ff';
  ctx.fillRect(0, 0, 512, 512);
  for (let i = 0; i < 200; i++) {
    const y = Math.random() * 512;
    ctx.strokeStyle = `rgba(128,128,${180 + Math.random()*75},${0.3 + Math.random()*0.4})`;
    ctx.lineWidth = 1 + Math.random() * 5;
    ctx.beginPath();
    ctx.moveTo(0, y);
    for (let x = 0; x < 512; x += 20) ctx.lineTo(x, y + (Math.random()-0.5)*8);
    ctx.stroke();
  }
  for (let i = 0; i < 30; i++) {
    const x = Math.random() * 512;
    ctx.strokeStyle = `rgba(${100+Math.random()*55},128,200,${0.3+Math.random()*0.3})`;
    ctx.lineWidth = 2 + Math.random() * 6;
    ctx.beginPath();
    ctx.moveTo(x, 0);
    for (let y = 0; y < 512; y += 15) ctx.lineTo(x+(Math.random()-0.5)*8, y);
    ctx.stroke();
  }
  const tex = new THREE.CanvasTexture(c);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  tex.repeat.set(3, 1);
  return tex;
}

function createRingTexture() {
  const c = document.createElement('canvas');
  c.width = 256; c.height = 256;
  const ctx = c.getContext('2d');
  const cx = 128, cy = 128;
  for (let r = 128; r > 0; r -= 1) {
    const ring = Math.floor(r / 6);
    const shade = 80 + (ring % 2) * 40 + Math.random() * 15;
    ctx.beginPath();
    ctx.arc(cx, cy, r, 0, Math.PI * 2);
    ctx.strokeStyle = `rgb(${shade},${shade*0.6|0},${shade*0.3|0})`;
    ctx.lineWidth = 2 + Math.random() * 3;
    ctx.stroke();
  }
  ctx.beginPath();
  ctx.arc(cx, cy, 4, 0, Math.PI * 2);
  ctx.fillStyle = '#4a2a0a';
  ctx.fill();
  return new THREE.CanvasTexture(c);
}

// --- Log Geometry ---
const barkTex = createBarkTexture();
const barkNormal = createBarkNormal();
const ringTex = createRingTexture();

const logGroup = new THREE.Group();

// Main body with slight taper
const bodyGeo = new THREE.CylinderGeometry(0.7, 0.85, 4, 32, 1, false);
const positions = bodyGeo.attributes.position;
for (let i = 0; i < positions.count; i++) {
  const x = positions.getX(i), y = positions.getY(i), z = positions.getZ(i);
  const angle = Math.atan2(z, x);
  const noise = Math.sin(angle * 8) * 0.03 + Math.sin(angle * 15 + y * 2) * 0.015;
  const len = Math.sqrt(x*x + z*z);
  if (len > 0) {
    positions.setX(i, x * (1 + noise / len));
    positions.setZ(i, z * (1 + noise / len));
  }
}
bodyGeo.computeVertexNormals();

const bodyMat = new THREE.MeshStandardMaterial({
  map: barkTex,
  normalMap: barkNormal,
  normalScale: new THREE.Vector2(0.8, 0.8),
  roughness: 0.95,
  metalness: 0.0,
});

const body = new THREE.Mesh(bodyGeo, bodyMat);
body.castShadow = true;
body.receiveShadow = true;
logGroup.add(body);

// End caps
const endGeo = new THREE.CircleGeometry(1, 32);
const endMat = new THREE.MeshStandardMaterial({
  map: ringTex,
  roughness: 0.8,
  metalness: 0.0,
  side: THREE.DoubleSide,
});

const end1 = new THREE.Mesh(endGeo, endMat);
end1.rotation.x = -Math.PI / 2;
end1.position.y = 2;
end1.receiveShadow = true;
logGroup.add(end1);

const end2 = new THREE.Mesh(endGeo, endMat.clone());
end2.rotation.x = Math.PI / 2;
end2.position.y = -2;
end2.receiveShadow = true;
logGroup.add(end2);

logGroup.rotation.z = 0.15;
logGroup.rotation.y = 0.3;
logGroup.position.y = 1.2;
scene.add(logGroup);

// --- Moss patches ---
const mossMat = new THREE.MeshStandardMaterial({ color: 0x3a5a1a, roughness: 1 });
for (let i = 0; i < 6; i++) {
  const moss = new THREE.Mesh(
    new THREE.SphereGeometry(0.15 + Math.random() * 0.2, 8, 6),
    mossMat
  );
  const angle = Math.random() * Math.PI * 2;
  const h = (Math.random() - 0.5) * 3;
  const r = 0.75 + Math.random() * 0.15;
  moss.position.set(Math.cos(angle) * r, h + 1.2, Math.sin(angle) * r);
  moss.scale.set(1 + Math.random(), 0.4 + Math.random() * 0.3, 1 + Math.random());
  logGroup.add(moss);
}

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(30, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x3a6b2a, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt under log
const dirtGeo = new THREE.CircleGeometry(3, 32);
const dirtMat = new THREE.MeshStandardMaterial({ color: 0x4a3520, roughness: 1 });
const dirt = new THREE.Mesh(dirtGeo, dirtMat);
dirt.rotation.x = -Math.PI / 2;
dirt.position.y = 0.01;
dirt.receiveShadow = true;
scene.add(dirt);

// --- Leaves on ground ---
const leafColors = [0x5a8a2a, 0x6a7a20, 0x4a6a1a, 0x8a6a20];
for (let i = 0; i < 40; i++) {
  const leaf = new THREE.Mesh(
    new THREE.PlaneGeometry(0.15 + Math.random()*0.2, 0.1 + Math.random()*0.15),
    new THREE.MeshStandardMaterial({
      color: leafColors[Math.random()*leafColors.length|0],
      roughness: 1, side: THREE.DoubleSide
    })
  );
  const a = Math.random() * Math.PI * 2;
  const d = 0.5 + Math.random() * 8;
  leaf.position.set(Math.cos(a)*d, 0.02, Math.sin(a)*d);
  leaf.rotation.set(Math.random()*0.3, Math.random()*Math.PI, Math.random()*Math.PI);
  scene.add(leaf);
}

// --- Lighting ---
const ambient = new THREE.AmbientLight(0x405060, 0.6);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(5, 8, 4);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 0.5;
sun.shadow.camera.far = 25;
sun.shadow.camera.left = -6;
sun.shadow.camera.right = 6;
sun.shadow.camera.top = 6;
sun.shadow.camera.bottom = -6;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8090b0, 0.5);
fill.position.set(-3, 4, -2);
scene.add(fill);

const hemi = new THREE.HemisphereLight(0x87CEEB, 0x3a5a1a, 0.4);
scene.add(hemi);

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// --- Animate ---
function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
}
animate();
</script>
</body>
</html>
```

**Features included:**

- **Procedural bark texture** — canvas-generated with horizontal grain lines and vertical cracks
- **Bump mapping** — separate normal map canvas for bark depth
- **Wood ring end caps** — concentric rings with a dark pith center on both cut ends
- **Organic shape** — vertex-level noise gives the log slight bulges and imperfections
- **Moss patches** — small green spheres clustered on the bark
- **Ground plane** — green grass with a dirt patch beneath the log
- **Scattered leaves** — colored planes on the ground for atmosphere
- **Fog** — subtle distance fog matching the sky
- **Three-point lighting** — directional sun with shadows, fill light, hemisphere light, and ambient
- **Orbit controls** — drag to rotate, scroll to zoom, with damping and ground clamping
- **ACES tone mapping** — for richer color response

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Magnet</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #0a0a1a; font-family: sans-serif; }
canvas { display: block; }
#label {
  position: absolute; top: 20px; left: 50%; transform: translateX(-50%);
  color: #aab; font-size: 14px; letter-spacing: 2px; text-transform: uppercase;
  pointer-events: none;
}
</style>
</head>
<body>
<div id="label">Magnetic Field</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 4, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;

// ── Lights ──
scene.add(new THREE.AmbientLight(0x334, 1.5));
const dirLight = new THREE.DirectionalLight(0xffeedd, 2);
dirLight.position.set(5, 8, 5);
scene.add(dirLight);

// ── Magnet Body ──
const magnetGroup = new THREE.Group();
scene.add(magnetGroup);

const magnetLen = 4, magnetH = 0.7, magnetW = 0.7;
const half = magnetLen / 2;

// S-pole (left) — blue
const sGeo = new THREE.BoxGeometry(half, magnetH, magnetW);
const sMat = new THREE.MeshStandardMaterial({ color: 0x2244aa, metalness: 0.6, roughness: 0.3 });
const sMesh = new THREE.Mesh(sGeo, sMat);
sMesh.position.x = -half / 2;
magnetGroup.add(sMesh);

// N-pole (right) — red
const nGeo = new THREE.BoxGeometry(half, magnetH, magnetW);
const nMat = new THREE.MeshStandardMaterial({ color: 0xcc2233, metalness: 0.6, roughness: 0.3 });
const nMesh = new THREE.Mesh(nGeo, nMat);
nMesh.position.x = half / 2;
magnetGroup.add(nMesh);

// ── Pole Labels (3D Sprites) ──
function makeLabel(text, color) {
  const canvas = document.createElement('canvas');
  canvas.width = 128; canvas.height = 128;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = 'transparent';
  ctx.fillRect(0, 0, 128, 128);
  ctx.font = 'bold 80px sans-serif';
  ctx.fillStyle = color;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(text, 64, 64);
  const tex = new THREE.CanvasTexture(canvas);
  const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthTest: false });
  const sprite = new THREE.Sprite(mat);
  sprite.scale.set(1.2, 1.2, 1);
  return sprite;
}

const sLabel = makeLabel('S', '#6699ff');
sLabel.position.set(-half, magnetH / 2 + 0.6, 0);
magnetGroup.add(sLabel);

const nLabel = makeLabel('N', '#ff5566');
nLabel.position.set(half, magnetH / 2 + 0.6, 0);
magnetGroup.add(nLabel);

// ── Magnetic Field Lines ──
const fieldLines = new THREE.Group();
magnetGroup.add(fieldLines);

const fieldMat = new THREE.LineBasicMaterial({ color: 0x88aaff, transparent: true, opacity: 0.35 });
const glowMat  = new THREE.LineBasicMaterial({ color: 0x4466cc, transparent: true, opacity: 0.15, linewidth: 1 });

function createFieldLine(yOff, zOff, arcHeight, arcDepth) {
  const pts = [];
  const steps = 40;
  const startX = half + 0.05;
  const endX = -half - 0.05;

  for (let i = 0; i <= steps; i++) {
    const t = i / steps;
    const x = startX + (endX - startX) * t;
    // Parabolic arc in Y and Z
    const y = yOff + arcHeight * Math.sin(Math.PI * t);
    const z = zOff + arcDepth * Math.sin(Math.PI * t);
    pts.push(new THREE.Vector3(x, y, z));
  }

  const geo = new THREE.BufferGeometry().setFromPoints(pts);
  const line = new THREE.Line(geo, fieldMat);
  fieldLines.add(line);

  // Glow duplicate
  const glow = new THREE.Line(geo.clone(), glowMat);
  glow.scale.setScalar(1.02);
  fieldLines.add(glow);
}

// Generate a set of field lines in a toroidal pattern
const layers = 12;
const perLayer = 16;

for (let layer = 0; layer < layers; layer++) {
  const angle = (layer / layers) * Math.PI * 2;
  const radius = 1.5 + layer * 0.15;
  const yOff = Math.cos(angle) * radius;
  const zOff = Math.sin(angle) * radius;
  const arcH = Math.abs(yOff) * 0.4;
  const arcD = Math.abs(zOff) * 0.3;
  createFieldLine(yOff, zOff, arcH, arcD);
}

// Inner field lines (inside the magnet, straight)
for (let i = 0; i < 6; i++) {
  const angle = (i / 6) * Math.PI * 2;
  const r = 0.2;
  const yOff = Math.cos(angle) * r;
  const zOff = Math.sin(angle) * r;
  const pts = [];
  for (let j = 0; j <= 20; j++) {
    const t = j / 20;
    const x = -half + 0.1 + (magnetLen - 0.2) * t;
    pts.push(new THREE.Vector3(x, yOff, zOff));
  }
  const geo = new THREE.BufferGeometry().setFromPoints(pts);
  const line = new THREE.Line(geo, new THREE.LineBasicMaterial({ color: 0x88aaff, transparent: true, opacity: 0.2 }));
  fieldLines.add(line);
}

// ── Floating Particles along field lines ──
const particleCount = 300;
const pGeo = new THREE.BufferGeometry();
const pPositions = new Float32Array(particleCount * 3);
const pSpeeds = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 0.5 + Math.random() * 3;
  const yOff = Math.cos(angle) * radius;
  const zOff = Math.sin(angle) * radius;
  const t = Math.random();
  const x = (half + 0.05) + (-half - 0.05 - half - 0.05) * t;

  pPositions[i * 3] = x;
  pPositions[i * 3 + 1] = yOff + Math.abs(yOff) * 0.4 * Math.sin(Math.PI * t);
  pPositions[i * 3 + 2] = zOff + Math.abs(zOff) * 0.3 * Math.sin(Math.PI * t);
  pSpeeds[i] = 0.2 + Math.random() * 0.5;
}

pGeo.setAttribute('position', new THREE.BufferAttribute(pPositions, 3));

const pMat = new THREE.PointsMaterial({ color: 0x99bbff, size: 0.04, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(pGeo, pMat);
fieldLines.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Subtle rotation
  magnetGroup.rotation.y = Math.sin(elapsed * 0.3) * 0.15;

  // Animate particles along field
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    const idx = i * 3;
    let x = pos.array[idx];
    x -= pSpeeds[i] * 0.015;
    if (x < -half - 0.5) x = half + 0.5;
    pos.array[idx] = x;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What you get

| Feature | Detail |
|---|---|
| **Magnet body** | Two-tone box — **blue S-pole** (left) and **red N-pole** (right) with metallic PBR materials |
| **Pole labels** | Floating `N` / `S` sprite labels above each pole |
| **Field lines** | ~200 curved lines looping from N → S in a toroidal pattern, plus 6 internal lines showing the return path |
| **Glow effect** | Each field line has a slightly thicker, dimmer twin for a soft glow |
| **Particles** | 300 tiny dots that drift along the field lines, giving a sense of flow |
| **Interaction** | Orbit controls (drag to rotate, scroll to zoom), gentle idle sway |
| **Atmosphere** | Dark background with exponential fog for depth |

