    const flagGeo = new THREE.BoxGeometry(0.01, 0.28, 0.18);
    const flag = new THREE.Mesh(flagGeo, flagMat);
    flag.position.set(0.82, 2.42, -0.09);
    flag.castShadow = true;
    mailbox.add(flag);

    // Post
    const postGeo = new THREE.CylinderGeometry(0.06, 0.08, 1.6, 12);
    const post = new THREE.Mesh(postGeo, postMat);
    post.position.set(0, 1.0, 0);
    post.castShadow = true;
    post.receiveShadow = true;
    mailbox.add(post);

    // Post base / foot
    const baseGeo = new THREE.CylinderGeometry(0.12, 0.14, 0.08, 12);
    const base = new THREE.Mesh(baseGeo, baseMat);
    base.position.set(0, 0.04, 0);
    base.receiveShadow = true;
    mailbox.add(base);

    // Decorative ball on top of post (where body sits)
    const capGeo = new THREE.SphereGeometry(0.07, 16, 16);
    const cap = new THREE.Mesh(capGeo, domeMat);
    cap.position.set(0, 1.83, 0);
    mailbox.add(cap);

    scene.add(mailbox);

    // ── Ground ─────────────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(30, 64);
    const ground = new THREE.Mesh(groundGeo, grassMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // Gravel patch around post
    const gravelGeo = new THREE.CircleGeometry(0.6, 32);
    const gravel = new THREE.Mesh(gravelGeo, gravelMat);
    gravel.rotation.x = -Math.PI / 2;
    gravel.position.y = 0.005;
    gravel.receiveShadow = true;
    scene.add(gravel);

    // ── Simple grass tufts ─────────────────────────────────
    const tuftGeo = new THREE.ConeGeometry(0.03, 0.15, 5);
    const tuftMat = new THREE.MeshStandardMaterial({ color: 0x3D6B35, roughness: 1 });
    for (let i = 0; i < 120; i++) {
      const tuft = new THREE.Mesh(tuftGeo, tuftMat);
      const angle = Math.random() * Math.PI * 2;
      const radius = 1.5 + Math.random() * 8;
      tuft.position.set(Math.cos(angle) * radius, 0.075, Math.sin(angle) * radius);
      tuft.rotation.y = Math.random() * Math.PI;
      tuft.scale.set(0.8 + Math.random() * 0.6, 0.7 + Math.random() * 0.8, 0.8 + Math.random() * 0.6);
      scene.add(tuft);
    }

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle flag wave
      flag.rotation.z = Math.sin(t * 4) * 0.15;
      flag.rotation.y = Math.sin(t * 3) * 0.08;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's in the scene

| Element | Geometry | Details |
|---|---|---|
| **Body** | `BoxGeometry` | Metallic grey box with a front door panel and handle |
| **Dome lid** | Hemisphere (`SphereGeometry`) | Scaled to fit the body width |
| **Flag** | `BoxGeometry` | Bright red, gently waves via sine-wave rotation |
| **Flag pole** | `CylinderGeometry` | Thin dark rod mounted on the right side |
| **Post** | `CylinderGeometry` | Wooden-toned tapered cylinder |
| **Base** | `CylinderGeometry` | Flat foot resting on the ground |
| **Ground** | `CircleGeometry` | Green grass plane with scattered cone grass tufts |
| **Lighting** | Directional + Hemisphere + Ambient | Soft shadows, warm sun, sky/ground bounce |

**Interactivity:** Drag to orbit, scroll to zoom. The flag animates with a subtle wind wave.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Mask Demo</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
    #info {
      position: absolute; top: 16px; width: 100%; text-align: center;
      color: #ccc; font-family: system-ui, sans-serif; font-size: 14px;
      pointer-events: none; text-shadow: 0 1px 4px rgba(0,0,0,.8);
    }
  </style>
</head>
<body>
  <div id="info">Drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene    = new THREE.Scene();
    scene.background = new THREE.Color(0x0a0a12);
    scene.fog = new THREE.FogExp2(0x0a0a12, 0.035);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 1.2, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0.8, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.06;
    controls.update();

    // ── Lighting ───────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x334466, 0.6));

    const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    keyLight.position.set(4, 6, 4);
    scene.add(keyLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 1.2);
    rimLight.position.set(-3, 2, -4);
    scene.add(rimLight);

    const bottomFill = new THREE.PointLight(0xff6633, 0.8, 12);
    bottomFill.position.set(0, -1, 3);
    scene.add(bottomFill);

    // ── Materials ──────────────────────────────────────────
    const maskMat = new THREE.MeshStandardMaterial({
      color: 0xcc2222,
      roughness: 0.35,
      metalness: 0.15,
    });

    const darkMat = new THREE.MeshStandardMaterial({
      color: 0x111111,
      roughness: 0.8,
      metalness: 0.0,
    });

    const goldMat = new THREE.MeshStandardMaterial({
      color: 0xffcc33,
      roughness: 0.2,
      metalness: 0.85,
      emissive: 0x332200,
      emissiveIntensity: 0.15,
    });

    // ── Build Mask ─────────────────────────────────────────
    const mask = new THREE.Group();

    // Face plate — elongated half-sphere
    const faceGeo = new THREE.SphereGeometry(1.4, 64, 48, 0, Math.PI * 2, 0, Math.PI * 0.55);
    const face = new THREE.Mesh(faceGeo, maskMat);
    face.rotation.x = Math.PI;          // open side faces forward
    face.position.y = 1.0;
    mask.add(face);

    // Forehead curve
    const foreheadGeo = new THREE.SphereGeometry(1.42, 64, 24, 0, Math.PI * 2, 0, Math.PI * 0.3);
    const forehead = new THREE.Mesh(foreheadGeo, maskMat);
    forehead.position.y = 1.75;
    forehead.scale.set(1, 0.45, 0.7);
    mask.add(forehead);

    // Nose bridge (raised ridge)
    const noseGeo = new THREE.CylinderGeometry(0.08, 0.14, 0.7, 16);
    const nose = new THREE.Mesh(noseGeo, maskMat);
    nose.position.set(0, 0.55, 0.95);
    nose.rotation.x = -0.3;
    mask.add(nose);

    // Nose tip
    const noseTipGeo = new THREE.SphereGeometry(0.16, 24, 24);
    const noseTip = new THREE.Mesh(noseTipGeo, maskMat);
    noseTip.position.set(0, 0.25, 1.05);
    mask.add(noseTip);

    // Eye holes
    function makeEyeHole(x) {
      const group = new THREE.Group();

      // Dark interior
      const holeGeo = new THREE.SphereGeometry(0.28, 32, 32);
      const hole = new THREE.Mesh(holeGeo, darkMat);
      hole.scale.set(1.1, 0.65, 0.5);
      group.add(hole);

      // Gold rim
      const rimGeo = new THREE.TorusGeometry(0.28, 0.025, 16, 48);
      const rim = new THREE.Mesh(rimGeo, goldMat);
      rim.scale.set(1.1, 0.65, 1);
      group.add(rim);

      group.position.set(x, 1.25, 0.82);
      return group;
    }

    mask.add(makeEyeHole(-0.42));
    mask.add(makeEyeHole(0.42));

    // Mouth opening with gold teeth-like accents
    const mouthGeo = new THREE.TorusGeometry(0.35, 0.04, 16, 48, Math.PI);
    const mouth = new THREE.Mesh(mouthGeo, goldMat);
    mouth.position.set(0, 0.15, 1.08);
    mouth.rotation.x = Math.PI;
    mask.add(mouth);

    // Vertical decorative lines on cheeks
    for (let side of [-1, 1]) {
      const lineGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.6, 8);
      const line = new THREE.Mesh(lineGeo, goldMat);
      line.position.set(side * 0.7, 0.6, 0.85);
      line.rotation.z = side * 0.15;
      line.rotation.x = -0.1;
      mask.add(line);
    }

    // Forehead diamond emblem
    const emblemGeo = new THREE.OctahedronGeometry(0.12, 0);
    const emblem = new THREE.Mesh(emblemGeo, goldMat);
    emblem.position.set(0, 1.85, 0.55);
    emblem.rotation.y = Math.PI / 4;
    mask.add(emblem);

    // Straps
    for (let side of [-1, 1]) {
      const strapCurve = new THREE.CatmullRomCurve3([
        new THREE.Vector3(side * 1.3, 1.4, 0.3),
        new THREE.Vector3(side * 1.6, 1.55, -0.5),
        new THREE.Vector3(side * 1.5, 1.5, -1.2),
        new THREE.Vector3(side * 1.0, 1.3, -1.6),
      ]);
      const strapGeo = new THREE.TubeGeometry(strapCurve, 32, 0.04, 12, false);
      const strap = new THREE.Mesh(strapGeo, darkMat);
      mask.add(strap);
    }

    // Chin guard
    const chinGeo = new THREE.CylinderGeometry(0.55, 0.35, 0.35, 32, 1, true, -Math.PI * 0.4, Math.PI * 0.8);
    const chin = new THREE.Mesh(chinGeo, maskMat);
    chin.position.set(0, -0.15, 0.55);
    chin.rotation.x = 0.4;
    mask.add(chin);

    scene.add(mask);

    // ── Floating particles ─────────────────────────────────
    const count = 600;
    const positions = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 20;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 20;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
    }
    const particleGeo = new THREE.BufferGeometry();
    particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const particleMat = new THREE.PointsMaterial({
      size: 0.03,
      color: 0xffcc66,
      transparent: true,
      opacity: 0.5,
      sizeAttenuation: true,
    });
    scene.add(new THREE.Points(particleGeo, particleMat));

    // ── Ground ring ────────────────────────────────────────
    const ringGeo = new THREE.RingGeometry(2.2, 2.35, 128);
    const ringMat = new THREE.MeshStandardMaterial({
      color: 0xffcc33,
      roughness: 0.3,
      metalness: 0.7,
      side: THREE.DoubleSide,
      emissive: 0x332200,
      emissiveIntensity: 0.3,
    });
    const ring = new THREE.Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = -0.5;
    scene.add(ring);

    // ── Animate ────────────────────────────────────────────
    const clock = new THREE.Clock();

    (function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle float
      mask.position.y = Math.sin(t * 0.8) * 0.12;
      mask.rotation.y = Math.sin(t * 0.3) * 0.15;

      // Ring pulse
      ring.scale.setScalar(1 + Math.sin(t * 1.5) * 0.04);
      ringMat.emissiveIntensity = 0.2 + Math.sin(t * 2) * 0.15;

      controls.update();
      renderer.render(scene, camera);
    })();

    // ── Resize ─────────────────────────────────────────────
    addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
