<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// Scene
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.02);

// Camera
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);

// Renderer
const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// Controls
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// Materials
const goldMat = new THREE.MeshStandardMaterial({
  color: 0xd4a017,
  metalness: 0.95,
  roughness: 0.15,
});

const darkGoldMat = new THREE.MeshStandardMaterial({
  color: 0xb8860b,
  metalness: 0.9,
  roughness: 0.3,
});

const ribbonMat = new THREE.MeshStandardMaterial({
  color: 0xcc0000,
  metalness: 0.0,
  roughness: 0.7,
  side: THREE.DoubleSide,
});

const ribbonMat2 = new THREE.MeshStandardMaterial({
  color: 0x1a1a6e,
  metalness: 0.0,
  roughness: 0.7,
  side: THREE.DoubleSide,
});

const starMat = new THREE.MeshStandardMaterial({
  color: 0xffd700,
  metalness: 0.95,
  roughness: 0.1,
  emissive: 0xffd700,
  emissiveIntensity: 0.15,
});

// Medal group
const medalGroup = new THREE.Group();

// Main disk
const diskGeo = new THREE.CylinderGeometry(1.2, 1.2, 0.12, 64);
const disk = new THREE.Mesh(diskGeo, goldMat);
disk.rotation.x = Math.PI / 2;
disk.castShadow = true;
medalGroup.add(disk);

// Outer rim
const rimGeo = new THREE.TorusGeometry(1.2, 0.06, 16, 64);
const rim = new THREE.Mesh(rimGeo, goldMat);
rim.position.z = 0.06;
rim.castShadow = true;
medalGroup.add(rim);

// Inner decorative ring
const innerRingGeo = new THREE.TorusGeometry(0.95, 0.025, 12, 64);
const innerRing = new THREE.Mesh(innerRingGeo, darkGoldMat);
innerRing.position.z = 0.065;
medalGroup.add(innerRing);

// Star emblem
function createStarShape() {
  const shape = new THREE.Shape();
  const outerR = 0.55, innerR = 0.25, points = 5;
  for (let i = 0; i < points * 2; i++) {
    const r = i % 2 === 0 ? outerR : innerR;
    const angle = (i * Math.PI) / points - Math.PI / 2;
    const x = Math.cos(angle) * r;
    const y = Math.sin(angle) * r;
    i === 0 ? shape.moveTo(x, y) : shape.lineTo(x, y);
  }
  shape.closePath();
  return shape;
}

const starShape = createStarShape();
const starExtrudeSettings = { depth: 0.04, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02, bevelSegments: 3 };
const starGeo = new THREE.ExtrudeGeometry(starShape, starExtrudeSettings);
const star = new THREE.Mesh(starGeo, starMat);
star.position.z = 0.07;
star.castShadow = true;
medalGroup.add(star);

// Small stars around
for (let i = 0; i < 8; i++) {
  const angle = (i / 8) * Math.PI * 2;
  const smallStar = new THREE.Mesh(
    new THREE.CircleGeometry(0.06, 5),
    starMat
  );
  smallStar.position.set(Math.cos(angle) * 1.05, Math.sin(angle) * 1.05, 0.07);
  smallStar.rotation.z = angle;
  medalGroup.add(smallStar);
}

// Ring at top
const ringGeo = new THREE.TorusGeometry(0.2, 0.04, 16, 32);
const ring = new THREE.Mesh(ringGeo, goldMat);
ring.position.set(0, 1.4, 0);
ring.castShadow = true;
medalGroup.add(ring);

// Connector between ring and medal
const connectorGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.25, 16);
const connector = new THREE.Mesh(connectorGeo, goldMat);
connector.position.set(0, 1.22, 0);
medalGroup.add(connector);

// Ribbon
const ribbonShape = new THREE.Shape();
ribbonShape.moveTo(-0.5, 0);
ribbonShape.lineTo(0.5, 0);
ribbonShape.lineTo(0.5, 2.2);
ribbonShape.lineTo(0.3, 2.2);
ribbonShape.lineTo(0.15, 2.6);
ribbonShape.lineTo(0, 2.2);
ribbonShape.lineTo(-0.15, 2.6);
ribbonShape.lineTo(-0.3, 2.2);
ribbonShape.lineTo(-0.5, 2.2);
ribbonShape.closePath();

const ribbonGeo = new THREE.ExtrudeGeometry(ribbonShape, { depth: 0.02, bevelEnabled: false });
const ribbon = new THREE.Mesh(ribbonGeo, ribbonMat);
ribbon.position.set(0, 1.5, -0.01);
ribbon.castShadow = true;
medalGroup.add(ribbon);

// Ribbon stripes
for (let i = 0; i < 3; i++) {
  const stripeGeo = new THREE.PlaneGeometry(0.12, 1.8);
  const stripe = new THREE.Mesh(stripeGeo, ribbonMat2);
  stripe.position.set(-0.22 + i * 0.22, 2.5, 0.005);
  medalGroup.add(stripe);
}

// Text ring around star (simulated with small dots)
for (let i = 0; i < 40; i++) {
  const angle = (i / 40) * Math.PI * 2;
  const dot = new THREE.Mesh(
    new THREE.SphereGeometry(0.015, 8, 8),
    darkGoldMat
  );
  dot.position.set(Math.cos(angle) * 0.78, Math.sin(angle) * 0.78, 0.07);
  medalGroup.add(dot);
}

// Bottom edge bevel ring
const bottomRimGeo = new THREE.TorusGeometry(1.2, 0.04, 16, 64);
const bottomRim = new THREE.Mesh(bottomRimGeo, goldMat);
bottomRim.position.z = -0.06;
medalGroup.add(bottomRim);

scene.add(medalGroup);

// Lighting
const ambientLight = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xfff0dd, 3);
mainLight.position.set(5, 8, 5);
mainLight.castShadow = true;
mainLight.shadow.mapSize.set(1024, 1024);
scene.add(mainLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 1);
fillLight.position.set(-3, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffd700, 2, 10);
rimLight.position.set(0, 0, -3);
scene.add(rimLight);

const topLight = new THREE.PointLight(0xffffff, 1.5, 8);
topLight.position.set(0, 4, 2);
scene.add(topLight);

// Background particles
const particleCount = 300;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({ color: 0xffd700, size: 0.03, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  medalGroup.rotation.y = Math.sin(t * 0.3) * 0.3;
  medalGroup.position.y = Math.sin(t * 0.5) * 0.15;

  particles.rotation.y = t * 0.02;
  particles.rotation.x = t * 0.01;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
