scene.fog = new THREE.FogExp2(0x111118, 0.035);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 6);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.update();

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
keyLight.position.set(4, 6, 4);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
scene.add(keyLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 1.5);
rimLight.position.set(-3, 4, -3);
scene.add(rimLight);

const bottomFill = new THREE.PointLight(0x223344, 1, 10);
bottomFill.position.set(0, -1, 2);
scene.add(bottomFill);

// ── Materials ──
const metalMat = new THREE.MeshStandardMaterial({
  color: 0x888890, metalness: 0.92, roughness: 0.25
});
const darkMat = new THREE.MeshStandardMaterial({
  color: 0x222225, metalness: 0.8, roughness: 0.35
});
const grilleMat = new THREE.MeshStandardMaterial({
  color: 0x555560, metalness: 0.7, roughness: 0.4
});
const baseMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1e, metalness: 0.6, roughness: 0.5
});

// ── Microphone Group ──
const mic = new THREE.Group();

// Head (spherical grille)
const headGeo = new THREE.SphereGeometry(0.32, 32, 32);
const head = new THREE.Mesh(headGeo, grilleMat);
head.position.y = 2.25;
head.castShadow = true;
mic.add(head);

// Grille wireframe overlay
const wireGeo = new THREE.SphereGeometry(0.33, 12, 8);
const wireMat = new THREE.MeshBasicMaterial({ color: 0x333340, wireframe: true });
const wire = new THREE.Mesh(wireGeo, wireMat);
wire.position.y = 2.25;
mic.add(wire);

// Collar (band between head and body)
const collarGeo = new THREE.CylinderGeometry(0.34, 0.34, 0.12, 32);
const collar = new THREE.Mesh(collarGeo, darkMat);
collar.position.y = 1.92;
collar.castShadow = true;
mic.add(collar);

// Body
const bodyGeo = new THREE.CylinderGeometry(0.14, 0.15, 1.0, 32);
const body = new THREE.Mesh(bodyGeo, metalMat);
body.position.y = 1.3;
body.castShadow = true;
mic.add(body);

// Body band accents
for (const y of [1.0, 1.1, 1.5, 1.6]) {
  const bandGeo = new THREE.CylinderGeometry(0.152, 0.152, 0.015, 32);
  const band = new THREE.Mesh(bandGeo, darkMat);
  band.position.y = y;
  mic.add(band);
}

// Bottom cap
const capGeo = new THREE.CylinderGeometry(0.14, 0.13, 0.08, 32);
const cap = new THREE.Mesh(capGeo, darkMat);
cap.position.y = 0.76;
mic.add(cap);

// XLR connector
const xlrGeo = new THREE.CylinderGeometry(0.08, 0.08, 0.12, 16);
const xlr = new THREE.Mesh(xlrGeo, darkMat);
xlr.position.y = 0.68;
mic.add(xlr);

const xlrPinGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.06, 8);
const pinMat = new THREE.MeshStandardMaterial({ color: 0xccaa44, metalness: 1, roughness: 0.2 });
for (let i = -1; i <= 1; i++) {
  const pin = new THREE.Mesh(xlrPinGeo, pinMat);
  pin.position.set(i * 0.035, 0.61, 0);
  mic.add(pin);
}

// ── Stand ──
// Boom arm joint
const jointGeo = new THREE.SphereGeometry(0.12, 16, 16);
const joint = new THREE.Mesh(jointGeo, darkMat);
joint.position.set(0, 0.55, 0);
mic.add(joint);

// Vertical stand pole
const poleGeo = new THREE.CylinderGeometry(0.04, 0.05, 0.5, 16);
const pole = new THREE.Mesh(poleGeo, metalMat);
pole.position.y = 0.25;
pole.castShadow = true;
mic.add(pole);

// Desk mount / base
const baseGeo = new THREE.CylinderGeometry(0.35, 0.4, 0.06, 32);
const base = new THREE.Mesh(baseGeo, baseMat);
base.position.y = -0.01;
base.receiveShadow = true;
mic.add(base);

// Base ring
const ringGeo = new THREE.TorusGeometry(0.37, 0.015, 8, 32);
const ring = new THREE.Mesh(ringGeo, darkMat);
ring.rotation.x = Math.PI / 2;
ring.position.y = 0.02;
mic.add(ring);

scene.add(mic);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x0a0a10, metalness: 0.3, roughness: 0.8
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.04;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating particles ──
const particleCount = 120;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  pPos[i * 3]     = (Math.random() - 0.5) * 10;
  pPos[i * 3 + 1] = Math.random() * 6;
  pPos[i * 3 + 2] = (Math.random() - 0.5) * 10;
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const pMat = new THREE.PointsMaterial({ color: 0x4466aa, size: 0.02, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// ── Animate ──
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle mic hover
  mic.position.y = Math.sin(t * 0.8) * 0.03;
  mic.rotation.y = Math.sin(t * 0.3) * 0.05;

  // Particles drift
  const pos = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pos[i * 3 + 1] += 0.002;
    if (pos[i * 3 + 1] > 6) pos[i * 3 + 1] = 0;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **Dynamic microphone** (SM58-style) built from primitive geometries — spherical mesh head with a wireframe overlay, cylindrical body with accent bands, XLR connector with gold pins
- **Desk stand** with a weighted base, vertical pole, and spherical boom joint
- **Cinematic lighting** — warm key light, cool blue rim light, dark ambient, and soft shadows
- **Gentle animation** — the mic subtly bobs and sways, while tiny blue particles drift upward in the background
- **OrbitControls** — click-drag to rotate, scroll to zoom
- **ACES filmic tone mapping** for a polished look against a dark foggy backdrop

