}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ─── Scene, Camera, Renderer ─── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0.5, 0);

/* ─── Lights ─── */
scene.add(new THREE.AmbientLight(0x8090b0, 0.8));

const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(4, 8, 6);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
key.shadow.camera.near = 1; key.shadow.camera.far = 20;
key.shadow.camera.left = -5; key.shadow.camera.right = 5;
key.shadow.camera.top = 5; key.shadow.camera.bottom = -5;
scene.add(key);

const fill = new THREE.DirectionalLight(0x6688cc, 0.6);
fill.position.set(-5, 3, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff8866, 1.2, 15);
rim.position.set(-3, 4, -4);
scene.add(rim);

/* ─── Materials ─── */
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0xcc2233,
  roughness: 0.85,
  metalness: 0.0,
});

const cuffMat = new THREE.MeshStandardMaterial({
  color: 0xaa1122,
  roughness: 0.9,
  metalness: 0.0,
});

const thumbMat = new THREE.MeshStandardMaterial({
  color: 0xbb2233,
  roughness: 0.85,
  metalness: 0.0,
});

const seamMat = new THREE.MeshStandardMaterial({
  color: 0x881122,
  roughness: 0.7,
  metalness: 0.05,
});

const floorMat = new THREE.MeshStandardMaterial({
  color: 0x111122,
  roughness: 0.95,
  metalness: 0.1,
});

/* ─── Mitten Group ─── */
const mitten = new THREE.Group();

/* ── Main Body (finger compartment) ── */
// Slightly squished sphere for the main mitten body
const bodyGeo = new THREE.SphereGeometry(1, 48, 36);
// Deform: squash bottom, elongate top, widen fingers area
const pos = bodyGeo.attributes.position;
for (let i = 0; i < pos.count; i++) {
  let x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);

  // Squash the bottom slightly (palm side)
  if (y < 0) y *= 0.7;
  // Elongate the top (finger area)
  if (y > 0.2) y *= 1.25;
  // Widen the top area
  if (y > 0.3) {
    x *= 1.15;
    z *= 1.15;
  }
  // Round the tip more
  if (y > 0.8) {
    const t = (y - 0.8) / 0.4;
    x *= (1 - t * 0.35);
    z *= (1 - t * 0.35);
  }

  pos.setXYZ(i, x, y, z);
}
bodyGeo.computeVertexNormals();
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.castShadow = true;
body.receiveShadow = true;
mitten.add(body);

/* ── Thumb ── */
const thumbGroup = new THREE.Group();

// Thumb base cylinder
const thumbBaseGeo = new THREE.CylinderGeometry(0.22, 0.28, 0.55, 16);
const thumbBase = new THREE.Mesh(thumbBaseGeo, thumbMat);
thumbBase.castShadow = true;
thumbGroup.add(thumbBase);

// Thumb tip (rounded)
const thumbTipGeo = new THREE.SphereGeometry(0.24, 24, 18);
const thumbTip = new THREE.Mesh(thumbTipGeo, thumbMat);
thumbTip.position.y = 0.35;
thumbTip.scale.y = 0.85;
thumbTip.castShadow = true;
thumbGroup.add(thumbTip);

// Position thumb on the side
thumbGroup.position.set(0.85, 0.1, 0);
thumbGroup.rotation.z = -Math.PI * 0.35;
thumbGroup.rotation.y = 0.15;
mitten.add(thumbGroup);

/* ── Cuff (wrist) ── */
// Main cuff cylinder
const cuffGeo = new THREE.CylinderGeometry(0.62, 0.68, 0.7, 32, 1, true);
const cuff = new THREE.Mesh(cuffGeo, cuffMat);
cuff.position.y = -1.05;
cuff.castShadow = true;
cuff.receiveShadow = true;
mitten.add(cuff);

// Cuff top rim
const cuffTopGeo = new THREE.TorusGeometry(0.64, 0.06, 12, 32);
const cuffTop = new THREE.Mesh(cuffTopGeo, cuffMat);
cuffTop.position.y = -0.7;
cuffTop.rotation.x = Math.PI / 2;
mitten.add(cuffTop);

// Cuff bottom rim (slightly larger, folded look)
const cuffBotGeo = new THREE.TorusGeometry(0.7, 0.08, 12, 32);
const cuffBot = new THREE.Mesh(cuffBotGeo, cuffMat);
cuffBot.position.y = -1.4;
cuffBot.rotation.x = Math.PI / 2;
mitten.add(cuffBot);

// Cuff inner dark ring
const cuffInnerGeo = new THREE.TorusGeometry(0.6, 0.04, 8, 32);
const cuffInner = new THREE.Mesh(cuffInnerGeo, new THREE.MeshStandardMaterial({
  color: 0x550011, roughness: 0.95
}));
cuffInner.position.y = -1.38;
cuffInner.rotation.x = Math.PI / 2;
mitten.add(cuffInner);

/* ── Cuff ribs (horizontal knit lines) ── */
for (let i = 0; i < 5; i++) {
  const ribGeo = new THREE.TorusGeometry(0.64 + i * 0.005, 0.015, 8, 32);
  const rib = new THREE.Mesh(ribGeo, seamMat);
  rib.position.y = -0.75 - i * 0.12;
  rib.rotation.x = Math.PI / 2;
  mitten.add(rib);
}

/* ── Seam line on top ── */
const seamCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 1.2, 0),
  new THREE.Vector3(0, 0.8, 0.05),
  new THREE.Vector3(0, 0.3, 0.08),
  new THREE.Vector3(0, -0.2, 0.06),
  new THREE.Vector3(0, -0.6, 0.04),
]);
const seamGeo = new THREE.TubeGeometry(seamCurve, 20, 0.018, 8, false);
const seam = new THREE.Mesh(seamGeo, seamMat);
mitten.add(seam);

/* ── Thumb seam ── */
const thumbSeamCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0.85, 0.45, 0),
  new THREE.Vector3(0.95, 0.3, 0),
  new THREE.Vector3(1.0, 0.0, 0),
  new THREE.Vector3(0.98, -0.25, 0),
]);
const thumbSeamGeo = new THREE.TubeGeometry(thumbSeamCurve, 12, 0.012, 8, false);
const thumbSeam = new THREE.Mesh(thumbSeamGeo, seamMat);
mitten.add(thumbSeam);

/* ── Decorative snowflake-like patch on top ── */
const patchGeo = new THREE.CircleGeometry(0.18, 6);
const patchMat = new THREE.MeshStandardMaterial({
  color: 0xffffff, roughness: 0.6, side: THREE.DoubleSide
});
const patch = new THREE.Mesh(patchGeo, patchMat);
patch.position.set(0, 1.18, 0.01);
patch.rotation.x = -Math.PI / 2;
mitten.add(patch);

// Small star shape on patch
const starShape = new THREE.Shape();
const outerR = 0.1, innerR = 0.045;
for (let i = 0; i < 10; i++) {
  const r = i % 2 === 0 ? outerR : innerR;
  const angle = (i * Math.PI) / 5 - Math.PI / 2;
  if (i === 0) starShape.moveTo(r * Math.cos(angle), r * Math.sin(angle));
  else starShape.lineTo(r * Math.cos(angle), r * Math.sin(angle));
}
starShape.closePath();
const starGeo = new THREE.ShapeGeometry(starShape);
const starMat = new THREE.MeshStandardMaterial({
  color: 0xcc2233, roughness: 0.7, side: THREE.DoubleSide
});
const star = new THREE.Mesh(starGeo, starMat);
star.position.set(0, 1.185, 0.01);
star.rotation.x = -Math.PI / 2;
mitten.add(star);

/* ── Position mitten ── */
mitten.position.y = 1.2;
mitten.rotation.y = -0.3;
scene.add(mitten);

/* ─── Floor ─── */
const floorGeo = new THREE.CircleGeometry(12, 64);
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.receiveShadow = true;
scene.add(floor);

/* ─── Animation ─── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float
  mitten.position.y = 1.2 + Math.sin(t * 0.8) * 0.12;
  mitten.rotation.y = -0.3 + Math.sin(t * 0.5) * 0.08;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ─── Resize ─── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
