  cube.castShadow = true;
  cube.receiveShadow = true;
  scene.add(cube);
  objects.push(cube);
}

// ─── MIRROR SETUP ───
const mirrorWidth = 5;
const mirrorHeight = 6;
const mirrorDepth = 0.15;
const mirrorPos = new THREE.Vector3(0, 4, -9.85);

// Mirror frame
const frameGeo = new THREE.BoxGeometry(mirrorWidth + 0.4, mirrorHeight + 0.4, mirrorDepth);
const frameMat = new THREE.MeshStandardMaterial({
  color: 0x8B7355, roughness: 0.3, metalness: 0.8
});
const frame = new THREE.Mesh(frameGeo, frameMat);
frame.position.copy(mirrorPos);
frame.castShadow = true;
scene.add(frame);

// Mirror surface (will be replaced by reflection texture)
const mirrorGeo = new THREE.PlaneGeometry(mirrorWidth, mirrorHeight);

// Render target for mirror reflection
const mirrorRenderTarget = new THREE.WebGLRenderTarget(
  mirrorWidth * 100, mirrorHeight * 100,
  { minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter }
);

const mirrorMaterial = new THREE.MeshBasicMaterial({
  map: mirrorRenderTarget.texture
});

const mirrorPlane = new THREE.Mesh(mirrorGeo, mirrorMaterial);
mirrorPlane.position.copy(mirrorPos);
mirrorPlane.position.z += 0.076; // slightly in front of frame
mirrorPlane.name = 'mirror';
scene.add(mirrorPlane);

// Mirror glass overlay for realism
const glassOverlay = new THREE.Mesh(
  new THREE.PlaneGeometry(mirrorWidth, mirrorHeight),
  new THREE.MeshPhysicalMaterial({
    color: 0xffffff, transparent: true, opacity: 0.08,
    roughness: 0, metalness: 0, reflectivity: 1
  })
);
glassOverlay.position.copy(mirrorPos);
glassOverlay.position.z += 0.08;
scene.add(glassOverlay);

// Clipping plane for mirror
const mirrorClipPlane = new THREE.Plane(
  new THREE.Vector3(0, 0, 1), // normal pointing toward the room
  mirrorPos.z + 0.076
);

// Clone camera for mirror rendering
const mirrorCamera = camera.clone();
mirrorCamera.layers.enableAll();

// Matrix for camera reflection
const mirrorNormalMatrix = new THREE.Matrix4();
const tempMatrix = new THREE.Matrix4();
const tempVector = new THREE.Vector3();
const tempQuaternion = new THREE.Quaternion();
const tempEuler = new THREE.Euler();

function updateMirrorReflection() {
  // Calculate mirror camera position (reflect main camera across mirror plane)
  tempVector.copy(camera.position);
  tempVector.applyMatrix4(mirrorNormalMatrix);

  // Manual reflection across the mirror plane
  const distToPlane = tempVector.dot(mirrorClipPlane.normal) + mirrorClipPlane.constant;
  tempVector.sub(mirrorClipPlane.normal.multiplyScalar(2 * distToPlane));

  mirrorCamera.position.copy(tempVector);

  // Reflect camera orientation
  mirrorCamera.position.z = 2 * mirrorPos.z - camera.position.z;

  // Look at the reflected target
  const target = new THREE.Vector3();
  tempQuaternion.setFromEuler(controls.target);
  tempVector.set(controls.target.x, controls.target.y, controls.target.z);
  const reflectedTarget = new THREE.Vector3(
    tempVector.x,
    tempVector.y,
    2 * mirrorPos.z - tempVector.z
  );
  mirrorCamera.lookAt(reflectedTarget);

  // Flip the mirror camera's view (mirror images are flipped)
  mirrorCamera.matrixWorldNeedsUpdate = true;
  mirrorCamera.updateMatrixWorld();
}

// ─── Animation Loop ───
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Animate floating spheres
  objects.forEach(obj => {
    if (obj.userData.baseY !== undefined) {
      obj.position.y = obj.userData.baseY +
        Math.sin(elapsed * obj.userData.floatSpeed + obj.userData.floatOffset) * obj.userData.floatAmplitude;
    }
    if (obj.userData.rotSpeed) {
      obj.rotation.x += obj.userData.rotSpeed.x * 0.016;
      obj.rotation.y += obj.userData.rotSpeed.y * 0.016;
    }
  });

  // Update mirror reflection
  updateMirrorReflection();

  // Render mirror reflection
  scene.remove(mirrorPlane);
  scene.remove(glassOverlay);
  scene.remove(frame);

  renderer.clippingPlanes = [mirrorClipPlane];
  renderer.setRenderTarget(mirrorRenderTarget);
  renderer.render(scene, mirrorCamera);

  // Restore clipping
  renderer.clippingPlanes = [];
  renderer.setRenderTarget(null);

  // Add mirror objects back
  scene.add(mirrorPlane);
  scene.add(glassOverlay);
  scene.add(frame);

  // Render main scene
  renderer.render(scene, camera);

  controls.update();
}

// ─── Resize Handler ───
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

animate();
</script>
</body>
</html>
