  requestAnimationFrame(animate);
  // Gentle sway
  mop.rotation.z = 0.15 + Math.sin(Date.now() * 0.001) * 0.02;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **traditional string mop** with:

- **Wooden handle** with decorative grip rings and a metal top cap
- **Metal disk connector** at the bottom
- **~80 mop strings** with varied lengths, thicknesses, and slight color variation — some lighter/dry, some darker/wet — all randomly tilted for a natural look
- **Water puddle** on the floor beneath the mop head
- **Gentle swaying animation** so the mop feels alive
- **OrbitControls** — click and drag to rotate, scroll to zoom
- **Soft shadows**, fog, and rim lighting for atmosphere

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Moon Visualization</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
    #info {
      position: absolute;
      bottom: 20px;
      left: 50%;
      transform: translateX(-50%);
      color: #aaa;
      font-family: 'Helvetica Neue', sans-serif;
      font-size: 13px;
      letter-spacing: 1px;
      pointer-events: none;
      text-transform: uppercase;
    }
  </style>
</head>
<body>
  <div id="info">click &amp; drag to orbit · scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene = new THREE.Scene();

    // ── Camera ─────────────────────────────────────────────
    const camera = new THREE.PerspectiveCamera(
      45,
      window.innerWidth / window.innerHeight,
      0.1,
      1000
    );
    camera.position.set(0, 0, 3.5);

    // ── Renderer ───────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.minDistance = 1.8;
    controls.maxDistance = 10;
    controls.rotateSpeed = 0.5;

    // ── Starfield ──────────────────────────────────────────
    const starCount = 6000;
    const starGeo = new THREE.BufferGeometry();
    const starPos = new Float32Array(starCount * 3);
    const starSizes = new Float32Array(starCount);
    for (let i = 0; i < starCount; i++) {
      const r = 80 + Math.random() * 120;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      starPos[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
      starPos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      starPos[i * 3 + 2] = r * Math.cos(phi);
      starSizes[i] = Math.random() * 1.5 + 0.5;
    }
    starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
    starGeo.setAttribute('size', new THREE.BufferAttribute(starSizes, 1));

    const starMat = new THREE.ShaderMaterial({
      uniforms: { time: { value: 0 } },
      vertexShader: `
        attribute float size;
        varying float vBrightness;
        uniform float time;
        void main() {
          vBrightness = size / 2.0;
          vec4 mvPos = modelViewMatrix * vec4(position, 1.0);
          gl_PointSize = size * (200.0 / -mvPos.z);
          gl_Position = projectionMatrix * mvPos;
        }
      `,
      fragmentShader: `
        varying float vBrightness;
        void main() {
          float d = length(gl_PointCoord - 0.5) * 2.0;
          float alpha = 1.0 - smoothstep(0.0, 1.0, d);
          gl_FragColor = vec4(vec3(0.95, 0.95, 1.0) * vBrightness, alpha * 0.9);
        }
      `,
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
    });
    scene.add(new THREE.Points(starGeo, starMat));

    // ── Procedural Moon Texture ────────────────────────────
    function createMoonTexture(size) {
      const canvas = document.createElement('canvas');
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');

      // Base gradient (dark gray)
      const grad = ctx.createRadialGradient(size * 0.4, size * 0.35, size * 0.05, size * 0.5, size * 0.5, size * 0.7);
      grad.addColorStop(0, '#8a8a8a');
      grad.addColorStop(0.5, '#6e6e6e');
      grad.addColorStop(1, '#555555');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, size, size);

      // Noise layer
      const imageData = ctx.getImageData(0, 0, size, size);
      const data = imageData.data;
      for (let i = 0; i < data.length; i += 4) {
        const noise = (Math.random() - 0.5) * 30;
        data[i] += noise;
        data[i + 1] += noise;
        data[i + 2] += noise;
      }
      ctx.putImageData(imageData, 0, 0);

      // Dark maria (seas)
      const maria = [
        { x: 0.35, y: 0.45, r: 0.15 },
        { x: 0.55, y: 0.35, r: 0.12 },
        { x: 0.45, y: 0.55, r: 0.1 },
        { x: 0.65, y: 0.55, r: 0.09 },
        { x: 0.3,  y: 0.6,  r: 0.08 },
        { x: 0.7,  y: 0.4,  r: 0.07 },
        { x: 0.5,  y: 0.7,  r: 0.11 },
      ];
      maria.forEach(m => {
        const mg = ctx.createRadialGradient(
          m.x * size, m.y * size, 0,
          m.x * size, m.y * size, m.r * size
        );
        mg.addColorStop(0, 'rgba(40,40,45,0.45)');
        mg.addColorStop(0.6, 'rgba(50,50,55,0.2)');
        mg.addColorStop(1, 'rgba(60,60,60,0)');
        ctx.fillStyle = mg;
        ctx.beginPath();
        ctx.arc(m.x * size, m.y * size, m.r * size, 0, Math.PI * 2);
        ctx.fill();
      });

      // Craters
      const craters = [];
      for (let i = 0; i < 200; i++) {
        craters.push({
          x: Math.random(),
          y: Math.random(),
          r: Math.random() * 0.03 + 0.005,
          depth: Math.random() * 40 + 10,
        });
      }
      craters.forEach(c => {
        // Shadow
        const sg = ctx.createRadialGradient(
          c.x * size + c.r * size * 0.3, c.y * size + c.r * size * 0.3, 0,
          c.x * size, c.y * size, c.r * size
        );
        sg.addColorStop(0, `rgba(20,20,20,${c.depth / 60})`);
        sg.addColorStop(0.7, `rgba(30,30,30,${c.depth / 80})`);
        sg.addColorStop(1, 'rgba(60,60,60,0)');
        ctx.fillStyle = sg;
        ctx.beginPath();
        ctx.arc(c.x * size, c.y * size, c.r * size, 0, Math.PI * 2);
        ctx.fill();

        // Rim highlight
        ctx.strokeStyle = `rgba(180,180,180,${c.depth / 120})`;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.arc(c.x * size, c.y * size, c.r * size, 0, Math.PI * 2);
        ctx.stroke();
      });

      return new THREE.CanvasTexture(canvas);
    }

    function createBumpTexture(size) {
      const canvas = document.createElement('canvas');
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      ctx.fillStyle = '#808080';
      ctx.fillRect(0, 0, size, size);

      const imageData = ctx.getImageData(0, 0, size, size);
      const data = imageData.data;
      for (let i = 0; i < data.length; i += 4) {
        const noise = 128 + (Math.random() - 0.5) * 50;
        data[i] = data[i + 1] = data[i + 2] = noise;
      }
      ctx.putImageData(imageData, 0, 0);

      // Crater depressions
      for (let i = 0; i < 150; i++) {
        const x = Math.random() * size;
        const y = Math.random() * size;
        const r = Math.random() * 15 + 3;
        const g = ctx.createRadialGradient(x, y, 0, x, y, r);
        g.addColorStop(0, `rgba(40,40,40,${Math.random() * 0.5 + 0.2})`);
        g.addColorStop(1, 'rgba(128,128,128,0)');
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(x, y, r, 0, Math.PI * 2);
        ctx.fill();
      }

      return new THREE.CanvasTexture(canvas);
    }

    // ── Moon ───────────────────────────────────────────────
    const moonTexture = createMoonTexture(2048);
    moonTexture.colorSpace = THREE.SRGBColorSpace;
    const moonBump = createBumpTexture(2048);

    const moonGeo = new THREE.SphereGeometry(1, 128, 128);
    const moonMat = new THREE.MeshStandardMaterial({
      map: moonTexture,
      bumpMap: moonBump,
      bumpScale: 0.04,
      roughness: 0.95,
      metalness: 0.0,
    });
    const moon = new THREE.Mesh(moonGeo, moonMat);
    scene.add(moon);

    // ── Atmospheric Glow ───────────────────────────────────
    const glowGeo = new THREE.SphereGeometry(1.015, 64, 64);
    const glowMat = new THREE.ShaderMaterial({
      side: THREE.FrontSide,
      transparent: true,
      depthWrite: false,
      uniforms: {},
      vertexShader: `
        varying vec3 vNormal;
        varying vec3 vWorldPos;
        void main() {
          vNormal = normalize(normalMatrix * normal);
          vWorldPos = (modelMatrix * vec4(position, 1.0)).xyz;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        varying vec3 vNormal;
        varying vec3 vWorldPos;
        void main() {
          vec3 viewDir = normalize(cameraPosition - vWorldPos);
          float rim = 1.0 - max(dot(viewDir, vNormal), 0.0);
          rim = pow(rim, 3.0);
          gl_FragColor = vec4(0.6, 0.7, 1.0, rim * 0.15);
        }
      `,
    });
    scene.add(new THREE.Mesh(glowGeo, glowMat));

    // ── Lighting ───────────────────────────────────────────
    const sunLight = new THREE.DirectionalLight(0xfff5e0, 3.5);
    sunLight.position.set(5, 3, 5);
    scene.add(sunLight);

    const ambientLight = new THREE.AmbientLight(0x222233, 0.4);
    scene.add(ambientLight);

    // Subtle blue fill from opposite side
    const fillLight = new THREE.DirectionalLight(0x334466, 0.15);
    fillLight.position.set(-5, -2, -5);
    scene.add(fillLight);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      moon.rotation.y = elapsed * 0.03;
      moon.rotation.x = Math.sin(elapsed * 0.01) * 0.05;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    });
  </script>
</body>
</html>
```

## What this creates

| Feature | Detail |
|---|---|
| **Moon sphere** | High-poly sphere (128×128 segments) with a procedurally generated 2048px texture including dark maria, 200 craters with shadows/rims, and surface noise |
| **Bump mapping** | Separate procedural bump texture gives craters real 3D depth under lighting |
| **Atmospheric glow** | Custom Fresnel rim-light shader adds a subtle blue halo around the edges |
| **Starfield** | 6,000 point-sprite stars with varying sizes and additive blending for a deep-space backdrop |
| **Lighting** | Warm directional sun light, cool ambient fill, and a subtle blue fill light on the dark side |
| **Interaction** | `OrbitControls` — drag to rotate, scroll to zoom, with smooth damping |
| **Animation** | Slow axial rotation with a slight wobble |

Just save it as `index.html` and open in any modern browser — no build step or server required.

