scene.add(ground);

// Banana tree trunk (simple)
const trunk = new THREE.Mesh(
  new THREE.CylinderGeometry(0.08, 0.12, 2, 12),
  new THREE.MeshStandardMaterial({ color: 0x6B4226, roughness: 0.9 })
);
trunk.position.set(2.5, 1, -1);
trunk.castShadow = true;
scene.add(trunk);

// Bananas
const bananaMat = new THREE.MeshStandardMaterial({ color: 0xFFD700, roughness: 0.4 });
for (let i = 0; i < 5; i++) {
  const banana = new THREE.Mesh(new THREE.CapsuleGeometry(0.04, 0.25, 8, 12), bananaMat);
  banana.position.set(2.5 + Math.cos(i * 0.5) * 0.15, 2.2 + Math.sin(i * 0.8) * 0.1, -1 + Math.sin(i * 0.5) * 0.15);
  banana.rotation.z = Math.PI * 0.3 + i * 0.2;
  banana.rotation.y = i * 0.6;
  scene.add(banana);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle bob
  monkey.position.y = 1.2 + Math.sin(t * 1.5) * 0.05;

  // Head sway
  head.rotation.y = Math.sin(t * 0.8) * 0.15;
  head.rotation.z = Math.sin(t * 0.5) * 0.05;

  // Eye tracking (look at camera)
  const camDir = new THREE.Vector3();
  camera.getWorldDirection(camDir);
  eyeGroup.children.forEach((child, i) => {
    if (i % 2 === 1) { // pupils
      const side = i === 1 ? -1 : 1;
      child.position.x = side * 0.2 + Math.sin(t * 0.8) * 0.02;
      child.position.y = 1.25 + Math.sin(t * 0.5) * 0.01;
    }
  });

  // Tail wag
  tail.rotation.y = Math.sin(t * 2) * 0.15;

  // Subtle arm swing
  monkey.children.forEach(child => {
    if (child.isGroup && child.children.length >= 2) {
      child.rotation.z = Math.sin(t * 1.2 + (child.position.x > 0 ? 0 : Math.PI)) * 0.05;
    }
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single `index.html` file creates a fully self-contained Three.js scene featuring:

- **A monkey** built entirely from primitive geometries — spheres for the head/body/ears, capsules for limbs, a tube for the tail, and a torus for the mouth
- **Facial details** — eyes with pupils that subtly animate, eyebrows, nose with nostrils, and a curved mouth
- **A banana tree** in the background with golden bananas
- **Animation** — idle bobbing, head swaying, tail wagging, subtle arm swinging, and eye movement
- **Lighting** — ambient, directional with soft shadows, and a blue rim light for depth
- **OrbitControls** — drag to rotate, scroll to zoom, right-click to pan

