  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(2, 1.5, 3);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    new OrbitControls(camera, renderer.domElement);

    // --- Nail Material ---
    const nailMat = new THREE.MeshStandardMaterial({
      color: 0xb0b0b0,
      metalness: 0.9,
      roughness: 0.25,
    });

    const nail = new THREE.Group();

    // --- Head ---
    const headGeo = new THREE.CylinderGeometry(0.45, 0.45, 0.1, 32);
    const head = new THREE.Mesh(headGeo, nailMat);
    head.position.y = 1.35;
    nail.add(head);

    // Under-bevel (slight taper connecting head to shaft)
    const bevelGeo = new THREE.CylinderGeometry(0.45, 0.08, 0.08, 32);
    const bevel = new THREE.Mesh(bevelGeo, nailMat);
    bevel.position.y = 1.21;
    nail.add(bevel);

    // --- Shaft ---
    const shaftGeo = new THREE.CylinderGeometry(0.08, 0.08, 1.8, 16);
    const shaft = new THREE.Mesh(shaftGeo, nailMat);
    shaft.position.y = -0.05;
    nail.add(shaft);

    // --- Point ---
    const pointGeo = new THREE.ConeGeometry(0.08, 0.35, 16);
    const point = new THREE.Mesh(pointGeo, nailMat);
    point.position.y = -1.15;
    nail.add(point);

    // Rotate nail to a natural angle
    nail.rotation.z = Math.PI * 0.15;
    scene.add(nail);

    // --- Lighting ---
    scene.add(new THREE.AmbientLight(0x404060, 0.5));

    const dir1 = new THREE.DirectionalLight(0xffffff, 3);
