controls.target.set(0, -1, 0);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x303050, 0.5);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
keyLight.position.set(5, 8, 5);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 1);
fillLight.position.set(-5, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffa844, 2);
rimLight.position.set(0, -2, -5);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffcc88, 5, 20);
pointLight.position.set(0, 0, 4);
scene.add(pointLight);

// ── Materials ──
const goldMaterial = new THREE.MeshStandardMaterial({
  color: 0xd4a843,
  metalness: 0.95,
  roughness: 0.15,
  envMapIntensity: 1.5,
});

const diamondMaterial = new THREE.MeshPhysicalMaterial({
  color: 0xffffff,
  metalness: 0.0,
  roughness: 0.0,
  transmission: 0.92,
  thickness: 0.5,
  ior: 2.42,
  clearcoat: 1.0,
  clearcoatRoughness: 0.0,
  envMapIntensity: 2.0,
  attenuationColor: new THREE.Color(0xaaddff),
  attenuationDistance: 2,
});

const rubyMaterial = new THREE.MeshPhysicalMaterial({
  color: 0xcc0033,
  metalness: 0.1,
  roughness: 0.05,
  clearcoat: 1.0,
  clearcoatRoughness: 0.0,
  envMapIntensity: 1.5,
  sheen: 0.5,
  sheenRoughness: 0.2,
  sheenColor: new THREE.Color(0xff4466),
});

// ── Env Map (simple procedural) ──
const pmremGenerator = new THREE.PMREMGenerator(renderer);
const envScene = new THREE.Scene();
envScene.background = new THREE.Color(0x111122);
const envLight1 = new THREE.PointLight(0xffeedd, 100, 50);
envLight1.position.set(5, 10, 5);
envScene.add(envLight1);
const envLight2 = new THREE.PointLight(0x4466ff, 50, 50);
envLight2.position.set(-5, 5, -5);
envScene.add(envLight2);
const envRT = pmremGenerator.fromScene(envScene);
scene.environment = envRT.texture;

// ── Chain ──
const chainGroup = new THREE.Group();
scene.add(chainGroup);

const linkCount = 60;
const linkRadius = 0.12;
const linkTubeRadius = 0.025;
const linkGeo = new THREE.TorusGeometry(linkRadius, linkTubeRadius, 16, 32);

// Catenary curve parameters
const catenaryA = 4;
const catenaryH = 2.5;
const catenaryW = 5;

function catenaryY(t) {
  // t from -1 to 1
  const x = t * catenaryW;
  return catenaryA * Math.cosh(x / catenaryA) - catenaryA;
}

for (let i = 0; i < linkCount; i++) {
  const t = -1 + (2 * i) / (linkCount - 1);
  const x = t * catenaryW;
  const y = -catenaryY(t) + catenaryH;

  const link = new THREE.Mesh(linkGeo, goldMaterial);
  link.position.set(x, y, 0);

  // Alternate link orientation
  if (i % 2 === 0) {
    link.rotation.y = Math.PI / 2;
  }

  // Slight tilt along the chain curve
  const nextT = -1 + (2 * (i + 1)) / (linkCount - 1);
  const nextX = nextT * catenaryW;
  const nextY = -catenaryY(nextT) + catenaryH;
  const angle = Math.atan2(nextY - y, nextX - x);
  link.rotation.z = angle;

  chainGroup.add(link);
}

// ── Pendant Group ──
const pendantGroup = new THREE.Group();
const pendantAttachT = 0; // center
const pendantX = 0;
const pendantY = -catenaryY(pendantAttachT) + catenaryH;
pendantGroup.position.set(pendantX, pendantY - linkRadius, 0);
scene.add(pendantGroup);

// Bail (loop that connects pendant to chain)
const bailGeo = new THREE.TorusGeometry(0.15, 0.02, 12, 24);
const bail = new THREE.Mesh(bailGeo, goldMaterial);
bail.position.y = 0.2;
pendantGroup.add(bail);

// Connector ring
const connectorGeo = new THREE.TorusGeometry(0.08, 0.015, 12, 24);
const connector = new THREE.Mesh(connectorGeo, goldMaterial);
connector.position.y = 0.05;
connector.rotation.x = Math.PI / 2;
pendantGroup.add(connector);

// Pendant setting (gold bezel)
const settingGeo = new THREE.CylinderGeometry(0.35, 0.3, 0.15, 32);
const setting = new THREE.Mesh(settingGeo, goldMaterial);
setting.position.y = -0.2;
pendantGroup.add(setting);

// Teardrop gem
const dropShape = new THREE.Shape();
dropShape.moveTo(0, 0.5);
dropShape.bezierCurveTo(0.35, 0.3, 0.4, -0.1, 0, -0.6);
dropShape.bezierCurveTo(-0.4, -0.1, -0.35, 0.3, 0, 0.5);

const extrudeSettings = { depth: 0.25, bevelEnabled: true, bevelThickness: 0.08, bevelSize: 0.08, bevelSegments: 8 };
const gemGeo = new THREE.ExtrudeGeometry(dropShape, extrudeSettings);
const gem = new THREE.Mesh(gemGeo, rubyMaterial);
gem.position.set(0, -0.35, -0.125);
gem.rotation.x = Math.PI;
pendantGroup.add(gem);

// Small accent diamonds around the setting
for (let i = 0; i < 8; i++) {
  const angle = (i / 8) * Math.PI * 2;
  const smallDiamondGeo = new THREE.OctahedronGeometry(0.06, 1);
  const smallDiamond = new THREE.Mesh(smallDiamondGeo, diamondMaterial);
  smallDiamond.position.set(
    Math.cos(angle) * 0.32,
    -0.12,
    Math.sin(angle) * 0.32
  );
  smallDiamond.rotation.y = angle;
  pendantGroup.add(smallDiamond);
}

// Bottom accent gem
const bottomGemGeo = new THREE.SphereGeometry(0.12, 16, 16);
const bottomGem = new THREE.Mesh(bottomGemGeo, diamondMaterial);
bottomGem.position.y = -0.95;
bottomGem.scale.y = 1.3;
pendantGroup.add(bottomGem);

// ── Sparkle Particles ──
const particleCount = 80;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
const particleSpeeds = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 1 + Math.random() * 4;
  particlePositions[i * 3] = Math.cos(angle) * radius;
  particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 6;
  particlePositions[i * 3 + 2] = Math.sin(angle) * radius;
  particleSpeeds[i] = 0.2 + Math.random() * 0.5;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0xffeedd,
  size: 0.05,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle sway
  pendantGroup.rotation.z = Math.sin(elapsed * 0.8) * 0.05;
  pendantGroup.rotation.x = Math.sin(elapsed * 0.6) * 0.03;

  // Chain subtle movement
  chainGroup.children.forEach((link, i) => {
    const wave = Math.sin(elapsed * 0.8 + i * 0.15) * 0.003;
    link.position.z = wave;
  });

  // Particles drift
  const positions = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    positions[i * 3 + 1] += particleSpeeds[i] * 0.005;
    if (positions[i * 3 + 1] > 4) {
      positions[i * 3 + 1] = -4;
    }
    positions[i * 3] += Math.sin(elapsed + i) * 0.001;
  }
  particles.geometry.attributes.position.needsUpdate = true;
  particleMat.opacity = 0.3 + Math.sin(elapsed * 2) * 0.2;

  // Point light subtle flicker
  pointLight.intensity = 5 + Math.sin(elapsed * 3) * 0.5;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single-file scene features:

- **Chain** — 60 interlocking torus links arranged along a catenary curve, alternating orientation to simulate real linked rings
- **Pendant** — A ruby teardrop gem (extruded bezier shape) set in a gold bezel, surrounded by 8 small diamond accents, with a dangling diamond drop below
- **Materials** — PBR gold (`MeshStandardMaterial`), ruby with sheen, and physically-based diamond with transmission/ior/glass refraction
- **Lighting** — Key, fill, rim, and point lights with a procedural environment map for realistic metallic reflections
- **Animation** — Gentle pendant sway, chain ripple, drifting sparkle particles, and subtle light flicker
- **Interactivity** — OrbitControls with damping for mouse/touch exploration

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Nest</title>
<style>*{margin:0;padding:0}body{background:#1a1a2e;overflow:hidden}</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 4, 8);
camera.lookAt(0, 0, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

// Lighting
const ambient = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xffe4b5, 1.8);
sun.position.set(5, 10, 5);
sun.castShadow = true;
scene.add(sun);

const rim = new THREE.DirectionalLight(0x8899cc, 0.5);
rim.position.set(-5, 3, -5);
scene.add(rim);

// Nest parameters
const NEST_RADIUS = 2.5;
const NEST_DEPTH = 0.8;
const STRAND_COUNT = 120;
const TWIG_THICKNESS = 0.04;

// Create a spiral curve for a strand
function createStrandCurve(index, total) {
  const points = [];
  const turns = 3 + Math.random() * 2;
  const steps = 60;
  const phase = (index / total) * Math.PI * 2;
  const radiusVariation = 0.3 + Math.random() * 0.4;
  const verticalWobble = 0.1 + Math.random() * 0.2;
  const baseRadius = NEST_RADIUS * (0.5 + Math.random() * 0.5);
  const direction = index % 2 === 0 ? 1 : -1;

  for (let i = 0; i <= steps; i++) {
    const t = i / steps;
    const angle = t * Math.PI * 2 * turns * direction + phase;
    const r = baseRadius + Math.sin(t * Math.PI * 2 * 3 + phase) * radiusVariation;
    // Bowl shape: higher at edges, lower in center
    const bowlFactor = Math.pow(t, 0.6);
    const y = -NEST_DEPTH * (1 - bowlFactor) + Math.sin(t * Math.PI * 5 + index) * verticalWobble;
    const x = Math.cos(angle) * r;
    const z = Math.sin(angle) * r;
    points.push(new THREE.Vector3(x, y, z));
  }
  return new THREE.CatmullRomCurve3(points);
}

// Nest material with warm brown tones
function twigMaterial(i) {
  const base = 0.25 + Math.random() * 0.2;
  const r = base + 0.08 + Math.random() * 0.06;
  const g = base + Math.random() * 0.04;
  const b = base * 0.3 + Math.random() * 0.04;
  return new THREE.MeshStandardMaterial({
    color: new THREE.Color(r, g, b),
    roughness: 0.85 + Math.random() * 0.15,
    metalness: 0.0,
  });
}

// Build nest strands
const nestGroup = new THREE.Group();
scene.add(nestGroup);

for (let i = 0; i < STRAND_COUNT; i++) {
  const curve = createStrandCurve(i, STRAND_COUNT);
  const thickness = TWIG_THICKNESS * (0.6 + Math.random() * 0.8);
  const geo = new THREE.TubeGeometry(curve, 40, thickness, 5, false);
  const mesh = new THREE.Mesh(geo, twigMaterial(i));
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  nestGroup.add(mesh);
}

// Add some crossing twigs (straight-ish pieces across the nest)
for (let i = 0; i < 30; i++) {
  const angle = Math.random() * Math.PI * 2;
  const r1 = NEST_RADIUS * (0.2 + Math.random() * 0.7);
  const r2 = NEST_RADIUS * (0.2 + Math.random() * 0.7);
  const a1 = angle + (Math.random() - 0.5) * 1.5;
  const a2 = angle + (Math.random() - 0.5) * 1.5;
  const y1 = -NEST_DEPTH * 0.3 + Math.random() * NEST_DEPTH * 0.5;
  const y2 = -NEST_DEPTH * 0.3 + Math.random() * NEST_DEPTH * 0.5;

  const points = [
    new THREE.Vector3(Math.cos(a1) * r1, y1, Math.sin(a1) * r1),
    new THREE.Vector3(
      Math.cos(angle) * (r1 + r2) * 0.5 + (Math.random() - 0.5) * 0.3,
      (y1 + y2) * 0.5 + (Math.random() - 0.5) * 0.2,
      Math.sin(angle) * (r1 + r2) * 0.5 + (Math.random() - 0.5) * 0.3
    ),
    new THREE.Vector3(Math.cos(a2) * r2, y2, Math.sin(a2) * r2),
  ];
  const curve = new THREE.CatmullRomCurve3(points);
  const thickness = TWIG_THICKNESS * (0.5 + Math.random() * 0.7);
  const geo = new THREE.TubeGeometry(curve, 12, thickness, 4, false);
  const mesh = new THREE.Mesh(geo, twigMaterial(i));
  mesh.castShadow = true;
  nestGroup.add(mesh);
}

// Add small loose twigs sticking out
for (let i = 0; i < 40; i++) {
  const angle = Math.random() * Math.PI * 2;
  const r = NEST_RADIUS * (0.6 + Math.random() * 0.5);
  const y = -NEST_DEPTH * 0.2 + Math.random() * NEST_DEPTH * 0.6;
  const stemAngle = angle + (Math.random() - 0.5) * 0.8;
  const length = 0.3 + Math.random() * 0.8;
  const upAngle = Math.random() * Math.PI * 0.6;

  const points = [
    new THREE.Vector3(Math.cos(angle) * r, y, Math.sin(angle) * r),
    new THREE.Vector3(
      Math.cos(stemAngle) * (r + length * Math.cos(upAngle)),
      y + length * Math.sin(upAngle) * 0.5,
      Math.sin(stemAngle) * (r + length * Math.cos(upAngle))
    ),
  ];
  const curve = new THREE.CatmullRomCurve3(points);
  const geo = new THREE.TubeGeometry(curve, 4, TWIG_THICKNESS * (0.3 + Math.random() * 0.5), 3, false);
  const mesh = new THREE.Mesh(geo, twigMaterial(i));
  mesh.castShadow = true;
  nestGroup.add(mesh);
}

// Eggs in the center
const eggGroup = new THREE.Group();
nestGroup.add(eggGroup);

function createEgg(x, z, scale, color) {
  const geo = new THREE.SphereGeometry(0.35 * scale, 24, 24);
  geo.scale(1, 1.3, 1);
  const mat = new THREE.MeshStandardMaterial({
    color: color,
    roughness: 0.3,
    metalness: 0.05,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(x, -NEST_DEPTH * 0.75, z);
  mesh.rotation.z = (Math.random() - 0.5) * 0.4;
  mesh.rotation.x = (Math.random() - 0.5) * 0.3;
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  return mesh;
}

const eggColors = [0xfff5e1, 0xf5e6cc, 0xfaf0d7];
eggGroup.add(createEgg(-0.25, 0.1, 1.0, eggColors[0]));
eggGroup.add(createEgg(0.2, -0.15, 0.95, eggColors[1]));
eggGroup.add(createEgg(0.05, 0.3, 0.9, eggColors[2]));

// Ground plane
const groundGeo = new THREE.CircleGeometry(15, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a3a2a,
  roughness: 1,
  metalness: 0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -NEST_DEPTH - 0.5;
ground.receiveShadow = true;
scene.add(ground);

// Branch the nest sits on
const branchGeo = new THREE.CylinderGeometry(0.15, 0.18, 12, 8);
const branchMat = new THREE.MeshStandardMaterial({
  color: 0x4a3520,
  roughness: 0.9,
  metalness: 0,
});
const branch = new THREE.Mesh(branchGeo, branchMat);
branch.rotation.z = Math.PI / 2;
branch.position.set(0, -NEST_DEPTH - 0.15, 0);
branch.castShadow = true;
scene.add(branch);

// Animation
let time = 0;
function animate() {
  requestAnimationFrame(animate);
  time += 0.005;

  // Gentle rotation
  nestGroup.rotation.y = time * 0.5;

  // Subtle camera orbit
  camera.position.x = Math.sin(time * 0.3) * 8;
  camera.position.z = Math.cos(time * 0.3) * 8;
  camera.position.y = 4 + Math.sin(time * 0.2) * 1;
  camera.lookAt(0, -0.3, 0);

  renderer.render(scene, camera);
}
animate();

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single `index.html` file creates a **3D nest visualization** with:

- **~120 spiral strands** using `TubeGeometry` along `CatmullRomCurve3` paths, forming a realistic woven bowl shape with varied brown tones
- **30 crossing twigs** and **40 loose protruding twigs** for organic detail
- **3 speckled eggs** nestled in the center depression
- A **branch** the nest rests on and a **ground plane**
- **Soft directional lighting** with shadows
- **Gentle auto-rotation** of the nest and a slow camera orbit for a cinematic feel
- **Fog** for atmospheric depth

Just save and open in a browser — no build tools needed.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Net</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #0a0a1a; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.012);

const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 8, 22);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x334466, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(10, 20, 10);
scene.add(dirLight);

const pointLight1 = new THREE.PointLight(0x4488ff, 3, 40);
pointLight1.position.set(-10, 5, -5);
scene.add(pointLight1);

const pointLight2 = new THREE.PointLight(0xff6644, 2, 40);
pointLight2.position.set(10, -3, 5);
scene.add(pointLight2);

// --- Net Generation ---
const COLS = 12;
const ROWS = 10;
const SPACING_X = 2.2;
const SPACING_Y = 2.0;
const SAG = 1.8;

const netGroup = new THREE.Group();
scene.add(netGroup);

// Compute node positions with catenary sag
function computeNodePos(i, j, time = 0) {
  const x = (i - COLS / 2) * SPACING_X;
  const yTop = (j - ROWS / 2) * SPACING_Y;

  // Catenary sag — more sag in the middle
  const edgeDist = Math.min(
    i, COLS - 1 - i, j, ROWS - 1 - j
  ) / Math.max(COLS, ROWS);
  const sagFactor = Math.pow(edgeDist, 0.7);
  const sagAmount = SAG * (1 - sagFactor);

  const y = yTop + sagAmount;

  // Gentle wave animation
  const waveX = Math.sin(y * 0.3 + time * 1.2) * 0.3;
  const waveZ = Math.cos(x * 0.25 + time * 0.9) * 0.3;
  const z = sagAmount * 0.5 + waveZ + Math.sin(time * 0.7 + i * 0.5 + j * 0.3) * 0.15;

  return new THREE.Vector3(x + waveX, y, z);
}

// Build rope geometry using TubeGeometry along curved paths
const ropeMaterial = new THREE.MeshStandardMaterial({
  color: 0xb8945a,
  roughness: 0.85,
  metalness: 0.1,
});

const knotMaterial = new THREE.MeshStandardMaterial({
  color: 0x8b6f3e,
  roughness: 0.7,
  metalness: 0.15,
});

const ropeRadius = 0.045;
const knotRadius = 0.09;

// Helper: create a curved rope between two points with midpoint sag
function createRope(start, end, midSag, mat) {
  const mid = new THREE.Vector3().lerpVectors(start, end, 0.5);
  mid.z += midSag || 0;
  const curve = new THREE.QuadraticBezierCurve3(start, mid, end);
  const tubeGeo = new THREE.TubeGeometry(curve, 12, ropeRadius, 6, false);
  return new THREE.Mesh(tubeGeo, mat);
}

// Store positions for animation
const nodePositions = [];

for (let j = 0; j < ROWS; j++) {
  nodePositions[j] = [];
  for (let i = 0; i < COLS; i++) {
    nodePositions[j][i] = computeNodePos(i, j, 0);
  }
}

// Create horizontal ropes
for (let j = 0; j < ROWS; j++) {
  for (let i = 0; i < COLS - 1; i++) {
    const p1 = nodePositions[j][i];
    const p2 = nodePositions[j][i + 1];
    const mid = new THREE.Vector3().lerpVectors(p1, p2, 0.5);
    mid.z += 0.15;
    const curve = new THREE.QuadraticBezierCurve3(p1, mid, p2);
    const tubeGeo = new THREE.TubeGeometry(curve, 8, ropeRadius, 6, false);
    netGroup.add(new THREE.Mesh(tubeGeo, ropeMaterial));
  }
}

// Create vertical ropes
for (let j = 0; j < ROWS - 1; j++) {
  for (let i = 0; i < COLS; i++) {
    const p1 = nodePositions[j][i];
    const p2 = nodePositions[j + 1][i];
    const mid = new THREE.Vector3().lerpVectors(p1, p2, 0.5);
    mid.z += 0.15;
    const curve = new THREE.QuadraticBezierCurve3(p1, mid, p2);
    const tubeGeo = new THREE.TubeGeometry(curve, 8, ropeRadius, 6, false);
    netGroup.add(new THREE.Mesh(tubeGeo, ropeMaterial));
  }
}

// Create diagonal ropes for extra net realism
for (let j = 0; j < ROWS - 1; j++) {
  for (let i = 0; i < COLS - 1; i++) {
    if ((i + j) % 2 === 0) {
      const p1 = nodePositions[j][i];
      const p2 = nodePositions[j + 1][i + 1];
      const mid = new THREE.Vector3().lerpVectors(p1, p2, 0.5);
      mid.z += 0.12;
      const curve = new THREE.QuadraticBezierCurve3(p1, mid, p2);
      const tubeGeo = new THREE.TubeGeometry(curve, 6, ropeRadius * 0.7, 4, false);
      netGroup.add(new THREE.Mesh(tubeGeo, ropeMaterial));
    }
  }
}

// Knots at intersections
const knotGeo = new THREE.SphereGeometry(knotRadius, 8, 6);
const knotInstanced = new THREE.InstancedMesh(knotGeo, knotMaterial, COLS * ROWS);
let idx = 0;
const dummy = new THREE.Object3D();
for (let j = 0; j < ROWS; j++) {
  for (let i = 0; i < COLS; i++) {
    const pos = nodePositions[j][i];
    dummy.position.copy(pos);
    dummy.updateMatrix();
    knotInstanced.setMatrixAt(idx++, dummy.matrix);
  }
}
netGroup.add(knotInstanced);

// --- Top anchor bar ---
const barGeo = new THREE.CylinderGeometry(0.12, 0.12, (COLS - 1) * SPACING_X + 2, 8);
barGeo.rotateZ(Math.PI / 2);
const barMat = new THREE.MeshStandardMaterial({ color: 0x6b5b3a, roughness: 0.6, metalness: 0.3 });
const bar = new THREE.Mesh(barGeo, barMat);
bar.position.set(0, (ROWS / 2) * SPACING_Y - SPACING_Y / 2, 0);
netGroup.add(bar);

// Anchor points on the bar
const anchorGeo = new THREE.SphereGeometry(0.2, 8, 8);
const anchorMat = new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.4, metalness: 0.6 });
for (let i = 0; i < COLS; i++) {
  const x = (i - COLS / 2) * SPACING_X;
  const y = (ROWS / 2) * SPACING_Y - SPACING_Y / 2;
  const anchor = new THREE.Mesh(anchorGeo, anchorMat);
  anchor.position.set(x, y, 0);
  netGroup.add(anchor);
}

// --- Floating particles ---
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const particlePos = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  particlePos[i * 3] = (Math.random() - 0.5) * 40;
  particlePos[i * 3 + 1] = (Math.random() - 0.5) * 30;
  particlePos[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePos, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0x88aacc,
  size: 0.08,
  transparent: true,
  opacity: 0.4,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Update knot positions with wave animation
  let kIdx = 0;
  for (let j = 0; j < ROWS; j++) {
    for (let i = 0; i < COLS; i++) {
      const pos = computeNodePos(i, j, t);
      dummy.position.copy(pos);
      dummy.updateMatrix();
      knotInstanced.setMatrixAt(kIdx++, dummy.matrix);
    }
  }
  knotInstanced.instanceMatrix.needsUpdate = true;

  // Slow rotation
  netGroup.rotation.y = Math.sin(t * 0.15) * 0.1;

  // Particles drift
  const pPositions = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pPositions[i * 3 + 1] += Math.sin(t + i) * 0.002;
    pPositions[i * 3] += Math.cos(t * 0.5 + i * 0.1) * 0.001;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **3D fishing net** scene featuring:

- **Catenary-sagging ropes** — the net droops naturally, more in the center and tight at the edges
- **Horizontal, vertical, and diagonal** rope lines using curved `TubeGeometry`
- **Knots** at every intersection using `InstancedMesh` for performance
- **Top anchor bar** with metal anchor points holding the net up
- **Gentle wave animation** — the whole net sways organically over time
- **Warm rope material** (`#b8945a`) against a dark atmospheric background
- **Floating particles** for ambient depth
- **Multi-source lighting** — directional, ambient, and two colored point lights
- **Orbit controls** — drag to rotate, scroll to zoom

