document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0.35, 0);
controls.minDistance = 2;
controls.maxDistance = 15;

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambientLight);

const hemiLight = new THREE.HemisphereLight(0x8888cc, 0x443322, 0.6);
scene.add(hemiLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(2048, 2048);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
dirLight.shadow.bias = -0.001;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8899ff, 0.8);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6644, 1.5, 15);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

// ── Environment Map (procedural) ──
const pmremGenerator = new THREE.PMREMGenerator(renderer);
const envScene = new THREE.Scene();

const envGeo = new THREE.SphereGeometry(10, 32, 32);
const envMat = new THREE.ShaderMaterial({
  side: THREE.BackSide,
  uniforms: {},
  vertexShader: `varying vec3 vWorldPos;
    void main(){ vWorldPos = position; gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0); }`,
  fragmentShader: `varying vec3 vWorldPos;
    void main(){
      float y = normalize(vWorldPos).y;
      vec3 top = vec3(0.15, 0.15, 0.3);
      vec3 mid = vec3(0.4, 0.35, 0.3);
      vec3 bot = vec3(0.05, 0.05, 0.08);
      vec3 col = mix(bot, mid, smoothstep(-0.3, 0.2, y));
      col = mix(col, top, smoothstep(0.2, 0.8, y));
      // Add some bright spots for reflections
      float spot1 = pow(max(dot(normalize(vWorldPos), normalize(vec3(5.0,8.0,4.0))), 0.0), 64.0);
      float spot2 = pow(max(dot(normalize(vWorldPos), normalize(vec3(-4.0,3.0,-3.0))), 0.0), 32.0);
      col += vec3(1.0, 0.95, 0.85) * spot1 * 2.0;
      col += vec3(0.5, 0.6, 1.0) * spot2 * 1.5;
      gl_FragColor = vec4(col, 1.0);
    }`
});
envScene.add(new THREE.Mesh(envGeo, envMat));

const envTexture = pmremGenerator.fromScene(envScene).texture;
scene.environment = envTexture;

// ── Hex Nut Geometry ──
function createHexNutGeometry(outerRadius, innerRadius, height, bevelAmount) {
  const shape = new THREE.Shape();

  // Outer hexagon
  for (let i = 0; i < 6; i++) {
    const angle = (Math.PI / 3) * i - Math.PI / 6;
    const x = outerRadius * Math.cos(angle);
    const y = outerRadius * Math.sin(angle);
    if (i === 0) shape.moveTo(x, y);
    else shape.lineTo(x, y);
  }
  shape.closePath();

  // Inner circle hole (approximated with many segments)
  const holePath = new THREE.Path();
  const segments = 48;
  for (let i = 0; i <= segments; i++) {
    const angle = (2 * Math.PI / segments) * i;
    const x = innerRadius * Math.cos(angle);
    const y = innerRadius * Math.sin(angle);
    if (i === 0) holePath.moveTo(x, y);
    else holePath.lineTo(x, y);
  }
  shape.holes.push(holePath);

  const extrudeSettings = {
    depth: height,
    bevelEnabled: true,
    bevelThickness: bevelAmount,
    bevelSize: bevelAmount,
    bevelOffset: 0,
    bevelSegments: 4
  };

  return new THREE.ExtrudeGeometry(shape, extrudeSettings);
}

const nutGeometry = createHexNutGeometry(1.0, 0.35, 0.45, 0.04);
nutGeometry.center();

// ── Nut Material ──
const nutMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x888890,
  metalness: 0.95,
  roughness: 0.25,
