  clearcoat: 0.3,
  clearcoatRoughness: 0.15,
});

const nut = new THREE.Mesh(nutGeometry, nutMaterial);
nut.rotation.x = Math.PI / 2;
nut.castShadow = true;
nut.receiveShadow = true;
scene.add(nut);

// ── Thread detail (decorative ring inside hole) ──
const threadGeo = new THREE.TorusGeometry(0.35, 0.02, 8, 48);
const threadMat = new THREE.MeshPhysicalMaterial({
