  metalness: 0.95,
  roughness: 0.3,
  envMapIntensity: 1.5,
});

// Add a few thread rings
for (let i = 0; i < 5; i++) {
  const thread = new THREE.Mesh(threadGeo, threadMat);
  thread.position.y = -0.18 + i * 0.09;
  scene.add(thread);
}

// ── Ground Plane ──
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshPhysicalMaterial({
  color: 0x222233,
  metalness: 0.1,
  roughness: 0.8,
  envMapIntensity: 0.3,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.5;
ground.receiveShadow = true;
scene.add(ground);

// ── Grid helper (subtle) ──
const grid = new THREE.GridHelper(20, 40, 0x333355, 0x222244);
grid.position.y = -0.49;
scene.add(grid);

