            color: #e0d6c8; font-size: 14px; background: rgba(0,0,0,0.5);
            padding: 8px 18px; border-radius: 20px; pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">🚣 Drag to orbit &nbsp;|&nbsp; Scroll to zoom</div>
    <script type="importmap">
    {
        "imports": {
            "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
            "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
        }
    }
    </script>
    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // ── Scene ──
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x1a1a2e);
        scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

        // ── Camera ──
        const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
        camera.position.set(4, 3, 6);

        // ── Renderer ──
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(innerWidth, innerHeight);
        renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        renderer.toneMapping = THREE.ACESFilmicToneMapping;
        renderer.toneMappingExposure = 1.2;
        document.body.appendChild(renderer.domElement);

        // ── Controls ──
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.08;
        controls.target.set(0, 0.5, 0);

        // ── Lights ──
        const ambient = new THREE.AmbientLight(0x404060, 0.8);
        scene.add(ambient);

        const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
        dirLight.position.set(5, 8, 4);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.set(1024, 1024);
        dirLight.shadow.camera.near = 1;
        dirLight.shadow.camera.far = 20;
        dirLight.shadow.camera.left = -5;
        dirLight.shadow.camera.right = 5;
        dirLight.shadow.camera.top = 5;
        dirLight.shadow.camera.bottom = -5;
        scene.add(dirLight);

        const rimLight = new THREE.DirectionalLight(0x4488ff, 0.6);
        rimLight.position.set(-3, 2, -4);
        scene.add(rimLight);

        // ── Wood Materials ──
        const shaftMat = new THREE.MeshStandardMaterial({
            color: 0x8B6914,
            roughness: 0.65,
            metalness: 0.05,
        });

        const bladeMat = new THREE.MeshStandardMaterial({
            color: 0x6B4F1D,
            roughness: 0.55,
            metalness: 0.08,
        });

        const gripMat = new THREE.MeshStandardMaterial({
            color: 0x3D2B1F,
            roughness: 0.8,
            metalness: 0.0,
        });

        const ferruleMat = new THREE.MeshStandardMaterial({
            color: 0xC0C0C0,
            roughness: 0.2,
            metalness: 0.9,
        });

        // ── Build Oar ──
        const oarGroup = new THREE.Group();

        // Shaft — tapered cylinder
        const shaftGeo = new THREE.CylinderGeometry(0.045, 0.06, 3.2, 16);
        const shaft = new THREE.Mesh(shaftGeo, shaftMat);
        shaft.position.y = 1.6;
        shaft.castShadow = true;
        shaft.receiveShadow = true;
        oarGroup.add(shaft);

        // Handle / grip — thicker at top
        const gripGeo = new THREE.CylinderGeometry(0.055, 0.05, 0.5, 16);
        const grip = new THREE.Mesh(gripGeo, gripMat);
        grip.position.y = 3.35;
        grip.castShadow = true;
        oarGroup.add(grip);

        // Top knob
        const knobGeo = new THREE.SphereGeometry(0.06, 16, 16);
        const knob = new THREE.Mesh(knobGeo, gripMat);
        knob.position.y = 3.63;
        knob.castShadow = true;
        oarGroup.add(knob);

        // Ferrule (metal ring at top)
        const ferruleGeo = new THREE.CylinderGeometry(0.062, 0.062, 0.06, 16);
        const ferrule = new THREE.Mesh(ferruleGeo, ferruleMat);
        ferrule.position.y = 3.55;
        ferrule.castShadow = true;
        oarGroup.add(ferrule);

        // ── Blade ──
        // Create blade shape using a custom profile
        const bladeShape = new THREE.Shape();
        const bLen = 1.2;      // blade length
        const bWid = 0.18;     // max half-width
        const bThick = 0.025;  // thickness

        // Blade outline (front face) — teardrop / elliptical shape
        bladeShape.moveTo(0, 0);
        // Right side — curves out then tapers to a point
        bladeShape.bezierCurveTo(0.12, -0.1, bWid * 1.3, -bLen * 0.5, bWid * 0.8, -bLen * 0.85);
        bladeShape.bezierCurveTo(bWid * 0.5, -bLen * 0.97, 0.02, -bLen, 0, -bLen * 1.0);
        // Left side — mirrors back
        bladeShape.bezierCurveTo(-0.02, -bLen, -bWid * 0.5, -bLen * 0.97, -bWid * 0.8, -bLen * 0.85);
        bladeShape.bezierCurveTo(-bWid * 1.3, -bLen * 0.5, -0.12, -0.1, 0, 0);

        const extrudeSettings = {
            depth: bThick,
            bevelEnabled: true,
            bevelThickness: 0.008,
            bevelSize: 0.008,
            bevelSegments: 4,
        };

        const bladeGeo = new THREE.ExtrudeGeometry(bladeShape, extrudeSettings);
        bladeGeo.center(); // center for easier placement

        const blade = new THREE.Mesh(bladeGeo, bladeMat);
        blade.position.y = -0.45;
        blade.rotation.x = Math.PI / 2;
        blade.castShadow = true;
        blade.receiveShadow = true;
        oarGroup.add(blade);

        // Pin / rowlock hole at blade base
        const pinGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.08, 12);
        const pinMat = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.7, roughness: 0.3 });
        const pin = new THREE.Mesh(pinGeo, pinMat);
        pin.rotation.x = Math.PI / 2;
        pin.position.set(0, -0.12, 0);
        oarGroup.add(pin);

        // Position entire oar
        oarGroup.rotation.z = 0.15;
        oarGroup.rotation.x = -0.1;
        oarGroup.position.set(0, 0.5, 0);
        scene.add(oarGroup);

        // ── Ground ──
        const groundGeo = new THREE.CircleGeometry(8, 64);
        const groundMat = new THREE.MeshStandardMaterial({
            color: 0x2a2a3e,
            roughness: 0.9,
            metalness: 0.1,
        });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // Subtle grid
        const gridHelper = new THREE.GridHelper(12, 24, 0x3a3a5e, 0x2a2a4e);
        gridHelper.position.y = 0.005;
        scene.add(gridHelper);

        // ── Water plane (subtle animated) ──
        const waterGeo = new THREE.PlaneGeometry(20, 20, 64, 64);
        const waterMat = new THREE.MeshStandardMaterial({
            color: 0x1a3a5c,
            roughness: 0.1,
            metalness: 0.3,
            transparent: true,
            opacity: 0.35,
        });
        const water = new THREE.Mesh(waterGeo, waterMat);
        water.rotation.x = -Math.PI / 2;
        water.position.y = -0.3;
        water.receiveShadow = true;
        scene.add(water);

        // ── Animation ──
        const clock = new THREE.Clock();

        function animate() {
            requestAnimationFrame(animate);
            const t = clock.getElapsedTime();

            // Gentle oar float
            oarGroup.position.y = 0.5 + Math.sin(t * 0.8) * 0.03;
            oarGroup.rotation.z = 0.15 + Math.sin(t * 0.5) * 0.02;

            // Water ripple
            const positions = waterGeo.attributes.position;
            for (let i = 0; i < positions.count; i++) {
                const x = positions.getX(i);
                const y = positions.getY(i);
                positions.setZ(i, Math.sin(x * 0.8 + t * 1.2) * 0.03 + Math.cos(y * 0.6 + t * 0.9) * 0.02);
            }
            positions.needsUpdate = true;
            waterGeo.computeVertexNormals();

            controls.update();
            renderer.render(scene, camera);
        }

        animate();

        // ── Resize ──
        window.addEventListener('resize', () => {
            camera.aspect = innerWidth / innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(innerWidth, innerHeight);
        });
    </script>
</body>
</html>
```

## What's Included

| Feature | Details |
|---|---|
| **Oar Shaft** | Tapered cylinder with wood-colored `MeshStandardMaterial` |
| **Blade** | Teardrop-shaped `ExtrudeGeometry` with beveled edges, bezier-curved profile |
| **Handle** | Darker grip, spherical knob, and metallic ferrule ring |
| **Pin** | Small metal pin at the blade base (rowlock attachment) |
| **Lighting** | Directional key light + blue rim light + ambient, with soft shadows |
| **Ground** | Dark circular floor with subtle grid overlay |
| **Water** | Animated ripple plane beneath the oar using vertex displacement |
| **Animation** | Gentle floating/bobbing motion on the oar + water wave simulation |
| **Controls** | `OrbitControls` with damping — drag to orbit, scroll to zoom |
| **Tone Mapping** | ACES Filmic for cinematic look |

