```html
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>Octopus</title>
<style>body{margin:0;overflow:hidden;background:#001828}</style>
</head>
<body>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x001828);
scene.fog = new THREE.FogExp2(0x001828, 0.035);

const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
document.body.appendChild(renderer.domElement);

scene.add(new THREE.AmbientLight(0x334466, 0.8));
const dir = new THREE.DirectionalLight(0xffeedd, 1.2);
dir.position.set(5, 10, 5);
scene.add(dir);
const back = new THREE.DirectionalLight(0x4466aa, 0.5);
back.position.set(-5, 2, -5);
scene.add(back);

const octo = new THREE.Group();
scene.add(octo);

const bodyMat = new THREE.MeshStandardMaterial({ color: 0xcc4466, roughness: 0.4, metalness: 0.1 });
const eyeMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.2 });
const pupilMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.3 });

// Head / mantle
const head = new THREE.Mesh(new THREE.SphereGeometry(1.5, 32, 32), bodyMat);
head.scale.set(1, 1.2, 0.9);
head.position.y = 1.2;
octo.add(head);

// Eyes
function makeEye(side) {
  const g = new THREE.Group();
  const white = new THREE.Mesh(new THREE.SphereGeometry(0.35, 16, 16), eyeMat);
  const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.18, 16, 16), pupilMat);
  pupil.position.z = 0.25;
  white.add(pupil);
  g.add(white);
  g.position.set(side * 0.8, 1.5, 1.0);
  g.rotation.y = side * 0.3;
  return g;
}
octo.add(makeEye(-1));
octo.add(makeEye(1));

// Tentacles
const tentacles = [];
const tentMat = bodyMat.clone();

for (let i = 0; i < 8; i++) {
  const angle = (i / 8) * Math.PI * 2;
  const r = 0.6;
  const basePts = [
    new THREE.Vector3(0, 0, 0),
    new THREE.Vector3(0, -1.5, 0),
    new THREE.Vector3(0, -3, 0),
    new THREE.Vector3(0, -4, 0.5)
  ];
  const curve = new THREE.CatmullRomCurve3(basePts);
  const mesh = new THREE.Mesh(new THREE.TubeGeometry(curve, 20, 0.25, 8, false), tentMat);
  mesh.position.set(Math.cos(angle) * r, 0.3, Math.sin(angle) * r);
  mesh.rotation.y = -angle;
  octo.add(mesh);
  tentacles.push({ mesh, curve, basePts, angle, i });
}

// Floating particles
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(300 * 3);
for (let i = 0; i < 900; i++) pPos[i] = (Math.random() - 0.5) * 30;
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const particles = new THREE.Points(pGeo, new THREE.PointsMaterial({
  color: 0x88aacc, size: 0.05, transparent: true, opacity: 0.6
}));
scene.add(particles);

// Animate
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  octo.position.y = Math.sin(t * 0.5) * 0.3;
  octo.rotation.y = Math.sin(t * 0.3) * 0.15;
  octo.rotation.x = Math.sin(t * 0.4) * 0.05;

  tentacles.forEach(ten => {
    const pts = ten.curve.points, b = ten.basePts, phase = ten.i * 0.8;
    pts[1].x = b[1].x + Math.sin(t * 1.2 + phase) * 0.3;
    pts[1].z = b[1].z + Math.cos(t * 0.9 + phase) * 0.2;
    pts[2].x = b[2].x + Math.sin(t * 1.0 + phase + 1) * 0.5;
    pts[2].z = b[2].z + Math.cos(t * 0.7 + phase + 1) * 0.3;
    pts[3].x = b[3].x + Math.sin(t * 0.8 + phase + 2) * 0.6;
    pts[3].z = b[3].z + Math.cos(t * 0.6 + phase + 2) * 0.4;
    ten.mesh.geometry.dispose();
    ten.mesh.geometry = new THREE.TubeGeometry(ten.curve, 20, 0.25, 8, false);
  });

  particles.rotation.y = t * 0.02;
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
