    }

    // Outer papery skin (golden-brown)
    const outerSkin = createLayer(1.35, 0xc4956a, 0.9, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    outerSkin.position.y = 0;
    onionGroup.add(outerSkin);

    // Second layer — slightly peeled back effect
    const layer2 = createLayer(1.25, 0xd4a87a, 0.85, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    layer2.position.y = 0.05;
    onionGroup.add(layer2);

    // Third layer
    const layer3 = createLayer(1.12, 0xe8cfa8, 0.8, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    layer3.position.y = 0.1;
    onionGroup.add(layer3);

    // Inner white layers
    const inner1 = createLayer(0.98, 0xf5f0e8, 0.7, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    inner1.position.y = 0.12;
    onionGroup.add(inner1);

    const inner2 = createLayer(0.84, 0xfaf5ee, 0.65, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    inner2.position.y = 0.14;
    onionGroup.add(inner2);

    const inner3 = createLayer(0.68, 0xfcf8f2, 0.6, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    inner3.position.y = 0.15;
    onionGroup.add(inner3);

    const core = createLayer(0.45, 0xfff8ee, 0.5, 0.0, { x: 1.0, y: 1.05, z: 1.0 });
    core.position.y = 0.16;
    onionGroup.add(core);

    // ── Papery skin texture overlay (irregular bumps) ──
    const bumpGeo = new THREE.SphereGeometry(1.36, 48, 36);
    const bumpMat = new THREE.MeshStandardMaterial({
      color: 0xb8864e,
      roughness: 1.0,
      metalness: 0.0,
      transparent: true,
      opacity: 0.35,
      side: THREE.FrontSide,
    });
    const bumpMesh = new THREE.Mesh(bumpGeo, bumpMat);
    bumpMesh.scale.set(1.0, 1.05, 1.0);
    onionGroup.add(bumpMesh);

    // ── Stem (top) ──
    const stemCurve = new THREE.CatmullRomCurve3([
      new THREE.Vector3(0, 1.2, 0),
      new THREE.Vector3(0.05, 1.55, 0.02),
      new THREE.Vector3(0.12, 1.85, -0.03),
      new THREE.Vector3(0.08, 2.1, -0.1),
    ]);
    const stemGeo = new THREE.TubeGeometry(stemCurve, 16, 0.06, 12, false);
    const stemMat = new THREE.MeshStandardMaterial({
      color: 0x8b6f47,
      roughness: 0.9,
      metalness: 0.0,
    });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.castShadow = true;
    onionGroup.add(stem);

    // Dried stem tip
    const tipGeo = new THREE.SphereGeometry(0.07, 12, 12);
    const tipMat = new THREE.MeshStandardMaterial({ color: 0x6b5535, roughness: 1.0 });
    const tip = new THREE.Mesh(tipGeo, tipMat);
    tip.position.set(0.08, 2.1, -0.1);
    onionGroup.add(tip);

    // ── Roots (bottom) ──
    const rootMat = new THREE.MeshStandardMaterial({
      color: 0x7a6545,
      roughness: 0.95,
      metalness: 0.0,
    });

    const rootData = [
      { start: [0, -1.3, 0], end: [0.15, -1.9, 0.05], radius: 0.025 },
      { start: [0, -1.3, 0], end: [-0.12, -1.85, 0.1], radius: 0.02 },
      { start: [0, -1.3, 0], end: [0.05, -1.95, -0.12], radius: 0.022 },
      { start: [0, -1.3, 0], end: [-0.08, -1.8, -0.15], radius: 0.018 },
      { start: [0, -1.3, 0], end: [0.1, -1.75, -0.08], radius: 0.02 },
      { start: [0, -1.3, 0], end: [-0.18, -1.88, -0.02], radius: 0.015 },
      { start: [0, -1.3, 0], end: [0.02, -2.0, 0.12], radius: 0.023 },
      { start: [0, -1.3, 0], end: [-0.05, -1.7, 0.15], radius: 0.016 },
    ];

    rootData.forEach(r => {
      const curve = new THREE.CatmullRomCurve3([
        new THREE.Vector3(...r.start),
        new THREE.Vector3(
          (r.start[0] + r.end[0]) / 2 + (Math.random() - 0.5) * 0.1,
          (r.start[1] + r.end[1]) / 2,
          (r.start[2] + r.end[2]) / 2 + (Math.random() - 0.5) * 0.1,
        ),
        new THREE.Vector3(...r.end),
      ]);
      const geo = new THREE.TubeGeometry(curve, 12, r.radius, 8, false);
      const mesh = new THREE.Mesh(geo, rootMat);
      mesh.castShadow = true;
      onionGroup.add(mesh);
    });

    // ── Small floating onion pieces (decorative) ──
    const pieces = [];
    for (let i = 0; i < 5; i++) {
      const r = 0.08 + Math.random() * 0.12;
      const geo = new THREE.SphereGeometry(r, 16, 16);
      const mat = new THREE.MeshStandardMaterial({
        color: new THREE.Color().setHSL(0.08 + Math.random() * 0.05, 0.4, 0.7 + Math.random() * 0.2),
        roughness: 0.7,
        metalness: 0.0,
      });
      const mesh = new THREE.Mesh(geo, mat);
      const angle = Math.random() * Math.PI * 2;
      const dist = 2.5 + Math.random() * 1.5;
      mesh.position.set(
        Math.cos(angle) * dist,
        (Math.random() - 0.5) * 2,
        Math.sin(angle) * dist,
      );
      mesh.scale.set(1, 0.8, 1);
      mesh.castShadow = true;
      onionGroup.add(mesh);
      pieces.push({
        mesh,
        baseY: mesh.position.y,
        speed: 0.3 + Math.random() * 0.5,
        offset: Math.random() * Math.PI * 2,
        radius: dist,
        angle,
        orbitSpeed: 0.05 + Math.random() * 0.1,
      });
    }

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle onion bob
      onionGroup.position.y = Math.sin(t * 0.5) * 0.08;

      // Floating pieces orbit
      pieces.forEach(p => {
        p.angle += p.orbitSpeed * 0.016;
        p.mesh.position.x = Math.cos(p.angle) * p.radius;
        p.mesh.position.z = Math.sin(p.angle) * p.radius;
        p.mesh.position.y = p.baseY + Math.sin(t * p.speed + p.offset) * 0.3;
        p.mesh.rotation.x += 0.005;
        p.mesh.rotation.z += 0.003;
      });

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's in the scene

| Element | How it's built |
|---|---|
| **Onion layers** | 7 concentric `SphereGeometry` meshes with decreasing radii and progressively lighter colors (golden-brown → creamy white), each slightly offset upward to suggest the layered structure |
| **Papery skin** | A semi-transparent outer shell with high roughness overlaid on top |
| **Stem** | A `TubeGeometry` along a `CatmullRomCurve3` path, topped with a small dried tip sphere |
| **Roots** | 8 thin tube geometries fanning out from the base along slight random curves |
| **Floating pieces** | 5 small spheres orbiting the onion with gentle bobbing — decorative atmosphere |
| **Lighting** | 3-point setup (key warm, fill cool, rim warm) + ambient, with soft shadow mapping |
| **Interaction** | `OrbitControls` with damping — drag to rotate, scroll to zoom |

Open the file in any modern browser and drag to orbit around the onion!

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>🍊 Three.js Orange</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { background: #1a1a2e; overflow: hidden; }
canvas { display: block; }
#info {
  position: fixed; bottom: 16px; width: 100%; text-align: center;
  color: #fff6; font: 14px/1 system-ui, sans-serif; pointer-events: none;
}
</style>
</head>
<body>
<div id="info">drag to orbit · scroll to zoom</div>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Scene & Camera ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.2, 5);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;

// ── Lighting ──
scene.add(new THREE.AmbientLight(0xffeedd, 0.4));

const key = new THREE.DirectionalLight(0xfff4e0, 2.5);
key.position.set(4, 6, 4);
scene.add(key);

const fill = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fill.position.set(-3, 2, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffaa44, 1.2);
rim.position.set(-2, -1, -4);
scene.add(rim);

// ── Orange Body (deformed sphere with pitted skin) ──
const geo = new THREE.SphereGeometry(1.2, 128, 96);
const pos = geo.attributes.position;
const vec = new THREE.Vector3();
const tmp = new THREE.Vector3();

for (let i = 0; i < pos.count; i++) {
  vec.fromBufferAttribute(pos, i);

  // Slight flattening (real oranges are oblate)
  vec.y *= 0.92;

  // Stem dimple (north pole)
  const stemDist = vec.distanceTo(new THREE.Vector3(0, 1.1, 0));
  if (stemDist < 0.25) {
    const factor = 1 - smoothstep(0.25, 0, stemDist);
    vec.lerp(new THREE.Vector3(0, 1.0, 0), factor * 0.18);
  }

  // Blossom end dimple (south pole)
  const bloomDist = vec.distanceTo(new THREE.Vector3(0, -1.1, 0));
  if (bloomDist < 0.3) {
    const factor = 1 - smoothstep(0.3, 0, bloomDist);
    vec.lerp(new THREE.Vector3(0, -1.05, 0), factor * 0.12);
  }

  // Pitted / pebbly skin via noise-like displacement
  const noise = pseudoNoise(vec);
  const displacement = 1 + noise * 0.025;
  vec.normalize().multiplyScalar(vec.length() * displacement);

  pos.setXYZ(i, vec.x, vec.y, vec.z);
}

geo.computeVertexNormals();

function smoothstep(edge0, edge1, x) {
  const t = Math.max(0, Math.min(1, (x - edge0) / (edge1 - edge0)));
  return t * t * (3 - 2 * t);
}

function pseudoNoise(v) {
  // Layered sine-based pseudo-noise for pitted look
  let n = 0;
  n += Math.sin(v.x * 22.0 + 1.0) * Math.sin(v.y * 19.0 + 2.0) * Math.sin(v.z * 23.0);
  n += Math.sin(v.x * 47.0 + 3.0) * Math.sin(v.y * 43.0 + 4.0) * Math.sin(v.z * 51.0) * 0.5;
  n += Math.sin(v.x * 97.0 + 5.0) * Math.sin(v.y * 89.0 + 6.0) * Math.sin(v.z * 101.0) * 0.25;
  return n / 1.75;
}

// ── Procedural Normal Map for extra bump detail ──
const normalCanvas = document.createElement('canvas');
normalCanvas.width = normalCanvas.height = 256;
const ctx = normalCanvas.getContext('2d');
const imgData = ctx.createImageData(256, 256);

for (let y = 0; y < 256; y++) {
  for (let x = 0; x < 256; x++) {
    const u = x / 256, v = y / 256;
    const px = (u - 0.5) * 8, py = (v - 0.5) * 8;
    let dx = 0, dy = 0;
    // Compute gradient of noise
    const eps = 0.01;
    const nCenter = pseudoNoise3(px, py, 0);
    const nx = (pseudoNoise3(px + eps, py, 0) - nCenter) / eps;
    const ny = (pseudoNoise3(px, py + eps, 0) - nCenter) / eps;
    dx = nx * 12; dy = ny * 12;
    const idx = (y * 256 + x) * 4;
    imgData.data[idx]     = Math.floor((dx * 0.5 + 0.5) * 255);
    imgData.data[idx + 1] = Math.floor((dy * 0.5 + 0.5) * 255);
    imgData.data[idx + 2] = 255;
    imgData.data[idx + 3] = 255;
  }
}
ctx.putImageData(imgData, 0, 0);
const normalMap = new THREE.CanvasTexture(normalCanvas);
normalMap.wrapS = normalMap.wrapT = THREE.RepeatWrapping;

function pseudoNoise3(x, y, z) {
  let n = 0;
  n += Math.sin(x * 22.0 + 1.0) * Math.sin(y * 19.0 + 2.0) * Math.sin(z * 23.0);
  n += Math.sin(x * 47.0 + 3.0) * Math.sin(y * 43.0 + 4.0) * Math.sin(z * 51.0) * 0.5;
  n += Math.sin(x * 97.0 + 5.0) * Math.sin(y * 89.0 + 6.0) * Math.sin(z * 101.0) * 0.25;
  return n / 1.75;
}

// ── Material ──
const material = new THREE.MeshStandardMaterial({
  color: 0xe87a1a,
  roughness: 0.65,
  metalness: 0.0,
  normalMap,
  normalScale: new THREE.Vector2(0.8, 0.8),
});

const orange = new THREE.Mesh(geo, material);
scene.add(orange);

// ── Stem ──
const stemGeo = new THREE.CylinderGeometry(0.025, 0.035, 0.22, 8);
const stemMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.9 });
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.set(0, 1.18, 0);
scene.add(stem);

// ── Leaf ──
const leafShape = new THREE.Shape();
leafShape.moveTo(0, 0);
leafShape.quadraticCurveTo(0.15, 0.2, 0.05, 0.5);
leafShape.quadraticCurveTo(-0.1, 0.6, 0, 0.7);
leafShape.quadraticCurveTo(0.1, 0.6, -0.05, 0.5);
leafShape.quadraticCurveTo(-0.15, 0.2, 0, 0);

const leafGeo = new THREE.ShapeGeometry(leafShape, 16);
const leafMat = new THREE.MeshStandardMaterial({
  color: 0x3a7a2a, roughness: 0.7, side: THREE.DoubleSide
});
const leaf = new THREE.Mesh(leafGeo, leafMat);
leaf.position.set(0.02, 1.22, 0);
leaf.rotation.set(0.3, 0.5, 0.2);
scene.add(leaf);

// ── Ground reflection disc ──
const groundGeo = new THREE.CircleGeometry(3, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e, roughness: 0.3, metalness: 0.8
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.5;
scene.add(ground);

// ── Animate ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle rotation
  orange.rotation.y = t * 0.15;
  stem.rotation.y = t * 0.15;
  leaf.rotation.y = 0.5 + t * 0.15;

  // Subtle bob
  orange.position.y = Math.sin(t * 0.8) * 0.03;
  stem.position.y = 1.18 + Math.sin(t * 0.8) * 0.03;
  leaf.position.y = 1.22 + Math.sin(t * 0.8) * 0.03;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
