leftArm.position.set(-1.2, 0.3, 0);
leftArm.rotation.z = 0.4;
panda.add(leftArm);
leftArm.add(mesh(new THREE.CylinderGeometry(0.25, 0.28, 1.1, 16), black, [0, -0.5, 0.2]));
leftArm.add(mesh(new THREE.SphereGeometry(0.28, 16, 16), black, [0, -1.0, 0.3]));

const rightArm = new THREE.Group();
rightArm.position.set(1.2, 0.3, 0);
rightArm.rotation.z = -0.4;
panda.add(rightArm);
rightArm.add(mesh(new THREE.CylinderGeometry(0.25, 0.28, 1.1, 16), black, [0, -0.5, 0.2]));
rightArm.add(mesh(new THREE.SphereGeometry(0.28, 16, 16), black, [0, -1.0, 0.3]));

scene.add(panda);

/* ── Bamboo stick ──────────────────────────────────── */
const bambooGroup = new THREE.Group();
bambooGroup.position.set(1.5, -0.8, 1.2);
bambooGroup.rotation.set(0.2, -0.5, 0.3);
panda.add(bambooGroup);

for (let i = 0; i < 4; i++) {
  bambooGroup.add(mesh(new THREE.CylinderGeometry(0.06, 0.06, 0.8, 8), i % 2 ? bambooDark : bamboo, [0, i * 0.75, 0]));
  // Bamboo nodes
  bambooGroup.add(mesh(new THREE.TorusGeometry(0.07, 0.015, 8, 12), bamboo, [0, i * 0.75 + 0.38, 0], [Math.PI / 2, 0, 0]));
}

// Bamboo leaves
for (let i = 0; i < 5; i++) {
  const leaf = mesh(new THREE.PlaneGeometry(0.5, 0.12), bamboo, [
    (Math.random() - 0.5) * 0.4,
    2.5 + Math.random() * 0.8,
    (Math.random() - 0.5) * 0.4
  ], [0.3, Math.random() * Math.PI, Math.random() * 0.5]);
  bambooGroup.add(leaf);
}

/* ── Ground ────────────────────────────────────────── */
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(20, 48),
  new THREE.MeshStandardMaterial({ color: 0x5a8f3c, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Grass tufts
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 2 + Math.random() * 16;
  const h = 0.1 + Math.random() * 0.25;
  const tuft = mesh(
    new THREE.ConeGeometry(0.06, h, 4),
    new THREE.MeshStandardMaterial({ color: new THREE.Color().setHSL(0.28 + Math.random() * 0.06, 0.6, 0.3 + Math.random() * 0.15) }),
    [Math.cos(angle) * radius, h / 2 - 0.01, Math.sin(angle) * radius]
  );
  scene.add(tuft);
}

// Small rocks
for (let i = 0; i < 12; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 3 + Math.random() * 10;
  const s = 0.1 + Math.random() * 0.2;
  scene.add(mesh(
    new THREE.DodecahedronGeometry(s, 0),
    new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.9 }),
    [Math.cos(angle) * radius, s * 0.4, Math.sin(angle) * radius],
    [Math.random(), Math.random(), Math.random()]
  ));
}

/* ── Controls ──────────────────────────────────────── */
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.1;
controls.minDistance = 5;
controls.maxDistance = 20;
controls.update();

/* ── Animation ─────────────────────────────────────── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle bob
  panda.position.y = Math.sin(t * 1.5) * 0.08;

  // Head tilt
  head.rotation.z = Math.sin(t * 0.8) * 0.06;
  head.rotation.y = Math.sin(t * 0.5) * 0.1;

  // Arm sway
  leftArm.rotation.z = 0.4 + Math.sin(t * 1.2) * 0.05;
  rightArm.rotation.z = -0.4 - Math.sin(t * 1.2) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ────────────────────────────────────────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's included

| Feature | Details |
|---|---|
| **Panda model** | Built entirely from `SphereGeometry`, `CylinderGeometry`, `TorusGeometry`, and `PlaneGeometry` primitives — no external assets needed |
| **Anatomy** | Body, head, ears (with inner ear), eye patches, eyes with pupils, nose, mouth, rosy cheeks, arms, legs, foot pads |
| **Bamboo prop** | Segmented bamboo stick held by the panda with small leaf planes |
| **Environment** | Green ground plane, randomized grass tufts, scattered rocks, fog, sky-blue background |
| **Lighting** | Warm directional sun with soft shadows, cool fill light, ambient light |
| **Animation** | Idle body bob, gentle head tilt/sway, arm sway |
| **Interaction** | `OrbitControls` — drag to orbit, scroll to zoom, damped |
| **Responsive** | Handles window resize |

Just save it as `index.html` and open in any modern browser — everything loads from the CDN.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Panther</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);
scene.fog = new THREE.FogExp2(0x0a0a12, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;
controls.maxPolarAngle = Math.PI / 2.05;

// --- Lighting ---
scene.add(new THREE.AmbientLight(0x1a1a2e, 0.8));

const moon = new THREE.DirectionalLight(0x8888cc, 1.5);
moon.position.set(5, 10, 5);
moon.castShadow = true;
moon.shadow.mapSize.set(2048, 2048);
moon.shadow.camera.near = 0.5;
moon.shadow.camera.far = 30;
moon.shadow.camera.left = -8;
moon.shadow.camera.right = 8;
moon.shadow.camera.top = 8;
moon.shadow.camera.bottom = -8;
scene.add(moon);

const rim = new THREE.DirectionalLight(0x334466, 0.6);
rim.position.set(-3, 4, -5);
scene.add(rim);

const eyeLight = new THREE.PointLight(0xff6600, 0.5, 3);
eyeLight.position.set(0, 2, 1.5);
scene.add(eyeLight);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(20, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x1a1a0e, roughness: 0.95 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// --- Panther Material ---
const pantherMat = new THREE.MeshStandardMaterial({
  color: 0x111111,
  roughness: 0.35,
  metalness: 0.15,
});
const highlightMat = new THREE.MeshStandardMaterial({
  color: 0x222222,
  roughness: 0.25,
  metalness: 0.3,
});

// --- Panther Group ---
const panther = new THREE.Group();
scene.add(panther);

// Helper: capsule-like body section
function makeBodySection(radiusX, radiusY, radiusZ, x, y, z) {
  const g = new THREE.SphereGeometry(1, 16, 12);
  const m = new THREE.Mesh(g, pantherMat);
  m.scale.set(radiusX, radiusY, radiusZ);
  m.position.set(x, y, z);
  m.castShadow = true;
  return m;
}

// Main body
panther.add(makeBodySection(0.9, 0.55, 0.5, 0, 1.15, 0));
panther.add(makeBodySection(0.6, 0.5, 0.48, 0.5, 1.2, 0));  // chest
panther.add(makeBodySection(0.55, 0.5, 0.45, -0.55, 1.18, 0)); // hind

// --- Head ---
const headGroup = new THREE.Group();
headGroup.position.set(1.15, 1.55, 0);
panther.add(headGroup);

const head = new THREE.Mesh(new THREE.SphereGeometry(0.32, 16, 12), pantherMat);
head.scale.set(1.15, 0.9, 0.85);
head.castShadow = true;
headGroup.add(head);

// Snout
const snout = new THREE.Mesh(new THREE.SphereGeometry(0.18, 12, 10), pantherMat);
snout.scale.set(1.3, 0.7, 0.8);
snout.position.set(0.28, -0.08, 0);
snout.castShadow = true;
headGroup.add(snout);

// Nose
const nose = new THREE.Mesh(new THREE.SphereGeometry(0.05, 8, 8), new THREE.MeshStandardMaterial({ color: 0x050505, roughness: 0.6 }));
nose.position.set(0.42, -0.04, 0);
headGroup.add(nose);

// Ears
function makeEar(z) {
  const ear = new THREE.Mesh(new THREE.ConeGeometry(0.08, 0.18, 8), pantherMat);
  ear.position.set(0.05, 0.28, z);
  ear.rotation.z = z > 0 ? -0.3 : 0.3;
  ear.rotation.x = -0.2;
  ear.castShadow = true;
  return ear;
}
headGroup.add(makeEar(0.18));
headGroup.add(makeEar(-0.18));

// Inner ears
function makeInnerEar(z) {
  const ie = new THREE.Mesh(new THREE.ConeGeometry(0.04, 0.1, 8), new THREE.MeshStandardMaterial({ color: 0x2a1a1a }));
  ie.position.set(0.06, 0.27, z);
  ie.rotation.z = z > 0 ? -0.3 : 0.3;
  ie.rotation.x = -0.2;
  return ie;
}
headGroup.add(makeInnerEar(0.18));
headGroup.add(makeInnerEar(-0.18));

// Eyes
function makeEye(z) {
  const eyeWhite = new THREE.Mesh(
    new THREE.SphereGeometry(0.045, 8, 8),
    new THREE.MeshStandardMaterial({ color: 0xeeeecc, emissive: 0x443300, emissiveIntensity: 0.3 })
  );
  eyeWhite.position.set(0.2, 0.08, z);
  eyeWhite.scale.set(1.2, 0.8, 0.6);

  const pupil = new THREE.Mesh(
    new THREE.SphereGeometry(0.022, 8, 8),
    new THREE.MeshStandardMaterial({ color: 0x000000 })
  );
  pupil.position.set(0.23, 0.08, z);
  pupil.scale.set(1.5, 1, 0.5);

  return [eyeWhite, pupil];
}
makeEye(0.12).forEach(e => headGroup.add(e));
makeEye(-0.12).forEach(e => headGroup.add(e));

// --- Legs ---
function makeLeg(x, z, isFront) {
  const group = new THREE.Group();
  group.position.set(x, 1.05, z);

  const upperLen = isFront ? 0.55 : 0.5;
  const lowerLen = isFront ? 0.45 : 0.5;

  // Upper leg
  const upper = new THREE.Mesh(
    new THREE.CylinderGeometry(0.1, 0.09, upperLen, 8),
    pantherMat
  );
  upper.position.y = -upperLen / 2;
  upper.castShadow = true;
  group.add(upper);

  // Knee joint
  const knee = new THREE.Mesh(new THREE.SphereGeometry(0.09, 8, 8), pantherMat);
  knee.position.y = -upperLen;
  group.add(knee);

  // Lower leg
  const lower = new THREE.Mesh(
    new THREE.CylinderGeometry(0.08, 0.07, lowerLen, 8),
    pantherMat
  );
  lower.position.y = -upperLen - lowerLen / 2;
  lower.castShadow = true;
  group.add(lower);

  // Paw
  const paw = new THREE.Mesh(
    new THREE.SphereGeometry(0.08, 8, 8),
    highlightMat
  );
  paw.scale.set(1, 0.5, 1.3);
  paw.position.y = -upperLen - lowerLen;
  paw.castShadow = true;
  group.add(paw);

  return group;
}

const legFL = makeLeg(0.55, 0.3, true);
const legFR = makeLeg(0.55, -0.3, true);
const legBL = makeLeg(-0.5, 0.28, false);
const legBR = makeLeg(-0.5, -0.28, false);
panther.add(legFL, legFR, legBL, legBR);

// --- Tail ---
const tailSegments = 12;
const tailGroup = new THREE.Group();
tailGroup.position.set(-0.9, 1.25, 0);
panther.add(tailGroup);

const tailParts = [];
for (let i = 0; i < tailSegments; i++) {
  const t = i / tailSegments;
  const radius = 0.08 * (1 - t * 0.7);
  const seg = new THREE.Mesh(
    new THREE.SphereGeometry(radius, 8, 8),
    pantherMat
  );
  seg.position.set(-i * 0.18, Math.sin(i * 0.4) * 0.08, 0);
  seg.castShadow = true;
  tailGroup.add(seg);
  tailParts.push(seg);
}

// --- Walk Animation ---
let time = 0;
const walkSpeed = 2.5;

function animate() {
  requestAnimationFrame(animate);
  time += 0.016;

  const walkCycle = time * walkSpeed;

  // Leg walk cycle
  const legAngle = Math.sin(walkCycle) * 0.45;
  legFL.rotation.x = legAngle;
  legBR.rotation.x = legAngle;
  legFR.rotation.x = -legAngle;
  legBL.rotation.x = -legAngle;

  // Slight body bob
  panther.position.y = Math.abs(Math.sin(walkCycle * 2)) * 0.06;

  // Body tilt with walk
  panther.rotation.z = Math.sin(walkCycle) * 0.02;

  // Head subtle movement
  headGroup.rotation.y = Math.sin(walkCycle * 0.5) * 0.1;
  headGroup.rotation.x = Math.sin(walkCycle * 0.7) * 0.05 - 0.15;
  headGroup.position.y = 1.55 + Math.sin(walkCycle) * 0.03;

  // Tail sway
  tailParts.forEach((seg, i) => {
    const phase = i * 0.5;
    seg.position.y = Math.sin(walkCycle * 1.5 + phase) * 0.12 * (1 - i / tailSegments);
    seg.position.z = Math.sin(walkCycle * 1.2 + phase) * 0.06 * (1 - i / tailSegments);
  });

  // Ear twitch
  const twitch = Math.sin(walkCycle * 3) > 0.95 ? 0.15 : 0;
  headGroup.children[3].rotation.x = -0.2 - twitch; // left ear
  headGroup.children[5].rotation.x = -0.2 - twitch * 0.5; // right ear

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single HTML file creates a **procedural black panther** built entirely from Three.js primitives — no external models needed. Here's what's included:

**Panther Anatomy:**
- **Body** — overlapping spheres forming a sleek torso with chest and hindquarters
- **Head** — shaped sphere with snout, nose, ears (with inner ear detail), and glowing amber eyes with pupils
- **4 Legs** — upper/lower segments with knee joints and paws
- **Tail** — 12 tapered segments that sway independently

**Animation:**
- Full **walk cycle** with alternating leg movement
- **Body bob** and subtle tilt
- **Head** gently sways and bobs
- **Tail** undulates with a wave propagation
- **Ear twitching** periodically

**Scene:**
- Moonlit atmosphere with fog
- Soft shadow mapping
- Rim lighting for silhouette definition
- OrbitControls for camera interaction
- Responsive resize handling

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Parachute</title>
<style>
* { margin: 0; padding: 0; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.015);

const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 4, 14);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0, 0);

// Lighting
scene.add(new THREE.AmbientLight(0x404060, 0.8));
const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 15, 10);
dirLight.castShadow = true;
scene.add(dirLight);
const rimLight = new THREE.DirectionalLight(0x4488ff, 1.0);
rimLight.position.set(-8, 5, -5);
scene.add(rimLight);

// --- Parachute Group ---
const para = new THREE.Group();
scene.add(para);

// Canopy — hemisphere with slight cone taper
const canopyGeo = new THREE.SphereGeometry(4, 48, 24, 0, Math.PI * 2, 0, Math.PI * 0.48);
const canopyMat = new THREE.MeshStandardMaterial({
  color: 0xcc2244,
  roughness: 0.45,
  metalness: 0.05,
  side: THREE.DoubleSide,
  flatShading: false,
});
const canopy = new THREE.Mesh(canopyGeo, canopyMat);
canopy.castShadow = true;
canopy.receiveShadow = true;
para.add(canopy);

// Alternate colored panels (stripes)
const stripeColors = [0xeeeeff, 0xcc2244];
for (let i = 0; i < 16; i++) {
  const angle = (i / 16) * Math.PI * 2;
  const stripeGeo = new THREE.PlaneGeometry(0.06, 3.5);
  const stripeMat = new THREE.MeshStandardMaterial({
    color: stripeColors[i % 2],
    roughness: 0.5,
    side: THREE.DoubleSide,
  });
  const stripe = new THREE.Mesh(stripeGeo, stripeMat);
  stripe.position.set(
    Math.sin(angle) * 2.6,
    0.5,
    Math.cos(angle) * 2.6
  );
  stripe.rotation.y = -angle;
  stripe.rotation.x = 0.15;
  para.add(stripe);
}

// Canopy rim ring
const rimGeo = new THREE.TorusGeometry(3.8, 0.06, 8, 64);
const rimMat = new THREE.MeshStandardMaterial({ color: 0xdddddd, roughness: 0.3 });
const rim = new THREE.Mesh(rimGeo, rimMat);
rim.position.y = -1.65;
rim.rotation.x = Math.PI / 2;
para.add(rim);

// Vent hole at top (dark circle)
const ventGeo = new THREE.CircleGeometry(0.35, 24);
const ventMat = new THREE.MeshStandardMaterial({ color: 0x111111, side: THREE.DoubleSide });
const vent = new THREE.Mesh(ventGeo, ventMat);
vent.position.y = 2.05;
vent.rotation.x = -Math.PI / 2;
para.add(vent);

// Shroud lines
const NUM_LINES = 8;
const lineMat = new THREE.LineBasicMaterial({ color: 0xeeeeee, linewidth: 1 });
const attachRadius = 3.6;
const loadPos = new THREE.Vector3(0, -7, 0);

const linePoints = [];
for (let i = 0; i < NUM_LINES; i++) {
  const angle = (i / NUM_LINES) * Math.PI * 2;
  const top = new THREE.Vector3(
    Math.sin(angle) * attachRadius,
    -1.7,
    Math.cos(angle) * attachRadius
  );
  const pts = [top.clone(), loadPos.clone()];
  const geo = new THREE.BufferGeometry().setFromPoints(pts);
  const line = new THREE.Line(geo, lineMat);
  para.add(line);
  linePoints.push({ top, line, angle });
}

// Load (cargo capsule)
const loadGroup = new THREE.Group();
loadGroup.position.copy(loadPos);
para.add(loadGroup);

const bodyGeo = new THREE.CapsuleGeometry(0.45, 1.2, 8, 16);
const bodyMat = new THREE.MeshStandardMaterial({ color: 0x888899, roughness: 0.3, metalness: 0.6 });
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.castShadow = true;
loadGroup.add(body);

// Small window
const winGeo = new THREE.CircleGeometry(0.15, 16);
const winMat = new THREE.MeshStandardMaterial({ color: 0x88ccff, roughness: 0.1, metalness: 0.8 });
const win = new THREE.Mesh(winGeo, winMat);
win.position.set(0, 0.1, 0.44);
loadGroup.add(win);

// --- Particles (dust / atmosphere) ---
const pCount = 600;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(pCount * 3);
for (let i = 0; i < pCount; i++) {
  pPos[i * 3]     = (Math.random() - 0.5) * 60;
  pPos[i * 3 + 1] = (Math.random() - 0.5) * 40;
  pPos[i * 3 + 2] = (Math.random() - 0.5) * 60;
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const pMat = new THREE.PointsMaterial({ color: 0xaabbdd, size: 0.08, transparent: true, opacity: 0.5 });
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  para.rotation.z = Math.sin(t * 0.6) * 0.06;
  para.rotation.x = Math.sin(t * 0.4) * 0.03;
  para.position.y = Math.sin(t * 0.8) * 0.4;

  // Animate shroud lines to follow sway
  for (const lp of linePoints) {
    const positions = lp.line.geometry.attributes.position.array;
    positions[3] = loadPos.x;
    positions[4] = loadPos.y + para.position.y;
    positions[5] = loadPos.z;
    lp.line.geometry.attributes.position.needsUpdate = true;
  }
  loadGroup.position.y = loadPos.y + para.position.y;

  // Slow rotation
  para.rotation.y = t * 0.15;

  // Particles drift
  const pp = particles.geometry.attributes.position.array;
  for (let i = 0; i < pCount; i++) {
    pp[i * 3 + 1] -= 0.005;
    if (pp[i * 3 + 1] < -20) pp[i * 3 + 1] = 20;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
