fill.position.set(-4, 3, -3);
scene.add(fill);

const rim = new THREE.PointLight(0xff9944, 0.6, 20);
rim.position.set(-3, 2, -5);
scene.add(rim);

// ── Pasta Material ─────────────────────────────────────
const pastaMat = new THREE.MeshStandardMaterial({
  color: 0xe8a838,
  roughness: 0.72,
  metalness: 0.0,
  flatShading: false,
});

// ── Fusilli Geometry ───────────────────────────────────
function createFusilli() {
  const group = new THREE.Group();

  // Fusilli cross-section (oval-ish)
  function crossSection(t, radius) {
    const angle = t * Math.PI * 2;
    // Slightly flattened ellipse
    const rx = radius * 1.0;
    const ry = radius * 0.55;
    return new THREE.Vector2(Math.cos(angle) * rx, Math.sin(angle) * ry);
  }

  // Build points for the helical spine
  function helixPoints(direction, startT, endT, turns, maxRadius) {
    const pts = [];
    const steps = 300;
    for (let i = 0; i <= steps; i++) {
      const frac = i / steps;
      const t = startT + frac * (endT - startT);
      const angle = t * Math.PI * 2 * turns * direction;
      const r = frac * maxRadius + 0.08;          // slight gap at center
      const y = (frac - 0.5) * 3.2;                // vertical spread
      pts.push(new THREE.Vector3(
        Math.cos(angle) * r,
        y,
        Math.sin(angle) * r
      ));
    }
    return pts;
  }

  // Two arms spiraling in opposite directions
  const arm1 = helixPoints(1,  0, Math.PI, 2.4, 2.8);
  const arm2 = helixPoints(-1, 0, Math.PI, 2.4, 2.8);

  // Tube radius tapers toward ends
  function taperedRadius(points, index) {
    const frac = index / points.length;
    // Bell curve taper
    return 0.18 * Math.exp(-4 * (frac - 0.5) * (frac - 0.5));
  }

  // Build tube from points with varying radius
  function buildTube(points) {
    const segments = [];
    const radialSegs = 12;

    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const dir = new THREE.Vector3().subVectors(p1, p0).normalize();

      // Build orthonormal frame
      let up = new THREE.Vector3(0, 1, 0);
      if (Math.abs(dir.dot(up)) > 0.9) up.set(1, 0, 0);
      const right = new THREE.Vector3().crossVectors(dir, up).normalize();
      up = new THREE.Vector3().crossVectors(right, dir).normalize();

      for (let j = 0; j <= radialSegs; j++) {
        const angle = (j / radialSegs) * Math.PI * 2;
        const cos = Math.cos(angle);
        const sin = Math.sin(angle);
        const r = taperedRadius(points, i);
        const px = p0.x + right.x * cos * r + up.x * sin * r;
        const py = p0.y + right.y * cos * r + up.y * sin * r;
        const pz = p0.z + right.z * cos * r + up.z * sin * r;
        segments.push(px, py, pz);
      }
    }

    const positions = new Float32Array(segments);
    const normals = new Float32Array(segments.length);
    const indices = [];

    // Generate faces
    for (let i = 0; i < points.length - 2; i++) {
      for (let j = 0; j < radialSegs; j++) {
        const a = i * (radialSegs + 1) + j;
        const b = a + 1;
        const c = (i + 1) * (radialSegs + 1) + j;
        const d = c + 1;
        indices.push(a, c, b);
        indices.push(b, c, d);
      }
    }

    // Compute flat-ish normals
    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geo.setIndex(indices);
    geo.computeVertexNormals();
    return geo;
  }

  const mesh1 = new THREE.Mesh(buildTube(arm1), pastaMat);
  const mesh2 = new THREE.Mesh(buildTube(arm2), pastaMat);
  mesh1.castShadow = true;
  mesh2.castShadow = true;
  group.add(mesh1, mesh2);

  // Central core
  const coreGeo = new THREE.CylinderGeometry(0.2, 0.2, 0.5, 12);
  const core = new THREE.Mesh(coreGeo, pastaMat);
  core.castShadow = true;
  group.add(core);

  return group;
}

const fusilli = createFusilli();
scene.add(fusilli);

// ── Ground (subtle) ────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({
