const clipBodyGeo = new THREE.BoxGeometry(0.06, 1.0, 0.04);
const clipBody = new THREE.Mesh(clipBodyGeo, clipMat);
clipBody.castShadow = true;
clipGroup.add(clipBody);

// Clip tip (hook)
const hookGeo = new THREE.CylinderGeometry(0.03, 0.03, 0.15, 16);
const hook = new THREE.Mesh(hookGeo, clipMat);
hook.position.set(0, 0.5, 0.04);
hook.rotation.x = Math.PI / 4;
clipGroup.add(hook);

// Clip base mount
const mountGeo = new THREE.CylinderGeometry(0.22, 0.22, 0.05, 32, 1, true, 0, Math.PI);
const mount = new THREE.Mesh(mountGeo, clipMat);
mount.rotation.x = Math.PI / 2;
mount.position.set(0, -0.48, 0);
clipGroup.add(mount);

clipGroup.position.set(0, 2.2, 0.22);
clipGroup.rotation.x = -0.15;
pen.add(clipGroup);

// Gold accent near cap
const accent2Geo = new THREE.TorusGeometry(0.205, 0.02, 8, 32);
const accent2 = new THREE.Mesh(accent2Geo, accentMat);
accent2.position.y = 1.58;
accent2.rotation.x = Math.PI / 2;
pen.add(accent2);

// Position pen upright
pen.rotation.z = 0.05;
pen.rotation.x = -0.02;
scene.add(pen);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(6, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x111122, metalness: 0.5, roughness: 0.6
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.6;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  pen.rotation.y = t * 0.3;
  pen.position.y = Math.sin(t * 0.8) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **A detailed 3D capped pen** built from primitives — barrel, cap with dome, metallic tip cone, rubber grip with ridges, gold accent rings, and a functional-looking clip with hook
- **Realistic materials** — metallic sheen on the tip/clip/rings, matte rubber grip, deep blue barrel, gold accents
- **Cinematic lighting** — warm key light, cool fill light, orange rim light, plus ACES filmic tone mapping
- **Soft shadows** cast onto a dark reflective ground disc
- **Gentle animation** — the pen slowly rotates and floats up/down
- **Orbit controls** — drag to rotate, scroll to zoom, right-drag to pan
- **Fully responsive** — adapts to window resizing

