scene.add(ambient);

const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(3, 5, 4);
scene.add(key);

const fill = new THREE.DirectionalLight(0x8888ff, 0.6);
fill.position.set(-4, 2, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xff6633, 0.8);
rim.position.set(0, -2, -4);
scene.add(rim);

// Pepper body via LatheGeometry
const points = [];
const profile = [
  [0.0, -1.2],
  [0.35, -1.15],
  [0.75, -0.9],
  [1.05, -0.55],
  [1.2, -0.2],
  [1.25, 0.1],
  [1.22, 0.3],
  [1.1, 0.5],
  [0.85, 0.65],
  [0.55, 0.75],
  [0.3, 0.82],
  [0.15, 0.88],
  [0.08, 0.92],
  [0.0, 0.95],
];
profile.forEach(p => points.push(new THREE.Vector2(p[0], p[1])));

const pepperGeo = new THREE.LatheGeometry(points, 32);
const pepperMat = new THREE.MeshPhysicalMaterial({
  color: 0xcc2200,
  roughness: 0.25,
  metalness: 0.0,
  clearcoat: 0.8,
  clearcoatRoughness: 0.15,
  reflectivity: 0.6,
});
const pepper = new THREE.Mesh(pepperGeo, pepperMat);
scene.add(pepper);

// Stem
const stemGeo = new THREE.CylinderGeometry(0.08, 0.12, 0.6, 12);
const stemMat = new THREE.MeshPhysicalMaterial({
  color: 0x2d6b1e,
  roughness: 0.7,
  clearcoat: 0.2,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.y = 1.25;
scene.add(stem);

// Curved stem tip
const tipCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 1.55, 0),
  new THREE.Vector3(0.05, 1.7, 0.05),
  new THREE.Vector3(0.15, 1.8, 0.08),
  new THREE.Vector3(0.25, 1.78, 0.05),
]);
const tipGeo = new THREE.TubeGeometry(tipCurve, 12, 0.06, 8, false);
const tip = new THREE.Mesh(tipGeo, stemMat);
scene.add(tip);

// Leaves
function makeLeaf(pos, rot, scale) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.4, 0.25, 0.8, 0);
  shape.quadraticCurveTo(0.4, -0.15, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 12);
  const mat = new THREE.MeshPhysicalMaterial({
    color: 0x3a8a2a,
    roughness: 0.6,
    side: THREE.DoubleSide,
    clearcoat: 0.3,
  });
  const leaf = new THREE.Mesh(geo, mat);
  leaf.position.copy(pos);
  leaf.rotation.set(rot.x, rot.y, rot.z);
  leaf.scale.setScalar(scale);
  scene.add(leaf);
}

makeLeaf(new THREE.Vector3(0.1, 1.5, 0.05), { x: -0.5, y: 0.3, z: 0.2 }, 0.9);
makeLeaf(new THREE.Vector3(-0.05, 1.55, -0.05), { x: -0.8, y: -0.6, z: -0.3 }, 0.7);

// Subtle shadow plane
const shadowGeo = new THREE.PlaneGeometry(6, 6);
const shadowMat = new THREE.ShadowMaterial({ opacity: 0.3 });
const shadowPlane = new THREE.Mesh(shadowGeo, shadowMat);
shadowPlane.rotation.x = -Math.PI / 2;
shadowPlane.position.y = -2.2;
