  text-shadow: 0 1px 3px rgba(0,0,0,0.5);
}
</style>
</head>
<body>
<div id="info">drag to orbit · scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

// ── Camera ─────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 6);

// ── Renderer ───────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ───────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.target.set(0, 0, 0);
controls.minDistance = 3;
controls.maxDistance = 18;

// ── Lights ─────────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x8090b0, 0.6);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xfff4e6, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
dirLight.shadow.bias = -0.001;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x6688cc, 0.8);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffaa66, 1.5, 15);
rimLight.position.set(-2, 1, -4);
scene.add(rimLight);

// ── Materials ──────────────────────────────────────────
const yellowPaintMat = new THREE.MeshStandardMaterial({
  color: 0xf5d442, roughness: 0.45, metalness: 0.05
});

const woodMat = new THREE.MeshStandardMaterial({
  color: 0xe8c87a, roughness: 0.7, metalness: 0.0
});

const graphiteMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a2a, roughness: 0.6, metalness: 0.1
});

const ferruleMat = new THREE.MeshStandardMaterial({
  color: 0xc0c0c0, roughness: 0.2, metalness: 0.9
});

const eraserMat = new THREE.MeshStandardMaterial({
  color: 0xe88b9a, roughness: 0.8, metalness: 0.0
});

const grooveMat = new THREE.MeshStandardMaterial({
  color: 0xd4b830, roughness: 0.5, metalness: 0.05
});

// ── Pencil Group ───────────────────────────────────────
const pencil = new THREE.Group();
scene.add(pencil);

// Dimensions
const BODY_RADIUS    = 0.12;
const BODY_LENGTH    = 3.2;
const TIP_WOOD_LEN   = 0.9;
const GRAPHITE_LEN   = 0.25;
const FERRULE_LEN    = 0.25;
const ERASER_LEN     = 0.35;
const ERASER_RADIUS  = 0.115;
const SEGMENTS       = 6; // hexagonal

// ── 1. Painted Body (hexagonal cylinder) ───────────────
const bodyGeo = new THREE.CylinderGeometry(
  BODY_RADIUS, BODY_RADIUS, BODY_LENGTH, SEGMENTS, 1, false
);
const body = new THREE.Mesh(bodyGeo, yellowPaintMat);
body.position.y = BODY_LENGTH / 2 - TIP_WOOD_LEN / 2;
body.castShadow = true;
body.receiveShadow = true;
pencil.add(body);

// ── 2. Body grooves (3 thin dark rings) ────────────────
for (let i = 0; i < 3; i++) {
  const grooveGeo = new THREE.CylinderGeometry(
    BODY_RADIUS + 0.003, BODY_RADIUS + 0.003, 0.025, SEGMENTS, 1, false
  );
  const groove = new THREE.Mesh(grooveGeo, grooveMat);
  groove.position.y = 0.3 + i * 0.25;
  pencil.add(groove);
}

// ── 3. Sharpened wood tip (hexagonal tapered cone) ─────
const tipWoodGeo = new THREE.CylinderGeometry(
  0.005, BODY_RADIUS, TIP_WOOD_LEN, SEGMENTS, 1, false
);
const tipWood = new THREE.Mesh(tipWoodGeo, woodMat);
tipWood.position.y = -TIP_WOOD_LEN / 2;
tipWood.castShadow = true;
pencil.add(tipWood);

// ── 4. Graphite core ───────────────────────────────────
const graphiteGeo = new THREE.CylinderGeometry(
  0.025, 0.025, GRAPHITE_LEN, 16, 1, false
);
const graphite = new THREE.Mesh(graphiteGeo, graphiteMat);
graphite.position.y = -TIP_WOOD_LEN - GRAPHITE_LEN / 2 + 0.05;
graphite.castShadow = true;
pencil.add(graphite);

// ── 5. Ferrule (metal band) ────────────────────────────
const ferruleGeo = new THREE.CylinderGeometry(
  BODY_RADIUS + 0.005, BODY_RADIUS + 0.005, FERRULE_LEN, SEGMENTS, 1, false
);
const ferrule = new THREE.Mesh(ferruleGeo, ferruleMat);
ferrule.position.y = BODY_LENGTH + FERRULE_LEN / 2 - 0.05;
ferrule.castShadow = true;
pencil.add(ferrule);

// Ferrule crimp lines
for (let i = 0; i < 2; i++) {
  const crimpGeo = new THREE.TorusGeometry(BODY_RADIUS + 0.008, 0.004, 8, SEGMENTS);
  const crimp = new THREE.Mesh(crimpGeo, ferruleMat);
  crimp.rotation.x = Math.PI / 2;
  crimp.position.y = BODY_LENGTH + FERRULE_LEN / 2 - 0.05 + (i === 0 ? -0.04 : 0.04);
  pencil.add(crimp);
}

// ── 6. Eraser ──────────────────────────────────────────
const eraserGeo = new THREE.CylinderGeometry(
  ERASER_RADIUS, ERASER_RADIUS, ERASER_LEN, SEGMENTS, 1, false
);
const eraser = new THREE.Mesh(eraserGeo, eraserMat);
eraser.position.y = BODY_LENGTH + FERRULE_LEN + ERASER_LEN / 2 - 0.05;
eraser.castShadow = true;
pencil.add(eraser);

// Eraser top dome
const eraserDomeGeo = new THREE.SphereGeometry(
  ERASER_RADIUS, SEGMENTS, 8, 0, Math.PI * 2, 0, Math.PI / 2
);
const eraserDome = new THREE.Mesh(eraserDomeGeo, eraserMat);
eraserDome.position.y = BODY_LENGTH + FERRULE_LEN + ERASER_LEN - 0.05;
eraserDome.castShadow = true;
pencil.add(eraserDome);

// ── Brand label (simple colored band) ──────────────────
const labelGeo = new THREE.CylinderGeometry(
  BODY_RADIUS + 0.002, BODY_RADIUS + 0.002, 0.4, SEGMENTS, 1, true
);
const labelMat = new THREE.MeshStandardMaterial({
  color: 0xcc2233, roughness: 0.5, metalness: 0.05,
  side: THREE.DoubleSide
});
const label = new THREE.Mesh(labelGeo, labelMat);
label.position.y = BODY_LENGTH * 0.65;
pencil.add(label);

// ── Tip edge ring (subtle) ─────────────────────────────
const tipRingGeo = new THREE.TorusGeometry(BODY_RADIUS, 0.004, 6, SEGMENTS);
const tipRing = new THREE.Mesh(tipRingGeo, new THREE.MeshStandardMaterial({
  color: 0xd4b830, roughness: 0.4, metalness: 0.1
}));
tipRing.rotation.x = Math.PI / 2;
tipRing.position.y = 0;
pencil.add(tipRing);

// ── Tilt the pencil ────────────────────────────────────
pencil.rotation.z = Math.PI / 6;
pencil.rotation.x = Math.PI / 12;

// ── Ground Plane ───────────────────────────────────────
const groundGeo = new THREE.PlaneGeometry(30, 30);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e, roughness: 0.9, metalness: 0.0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.5;
ground.receiveShadow = true;
scene.add(ground);

// ── Subtle grid on ground ──────────────────────────────
const gridHelper = new THREE.GridHelper(20, 40, 0x2a2a4e, 0x222244);
gridHelper.position.y = -2.49;
scene.add(gridHelper);

// ── Animation ──────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  pencil.rotation.y = t * 0.3;

  // Subtle bob
  pencil.position.y = Math.sin(t * 0.8) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
