    belly.scale.set(0.88, 1.15, 0.55);
    belly.position.set(0, 2.35, 0.35);
    belly.castShadow = true;
    penguin.add(belly);

    // Head
    const headGeo = new THREE.SphereGeometry(0.7, 32, 32);
    const head = new THREE.Mesh(headGeo, blackMat);
    head.position.set(0, 4.0, 0.1);
    head.castShadow = true;
    penguin.add(head);

    // Face (white patch)
    const faceGeo = new THREE.SphereGeometry(0.55, 32, 32);
    const face = new THREE.Mesh(faceGeo, whiteMat);
    face.scale.set(0.9, 0.85, 0.5);
    face.position.set(0, 3.95, 0.42);
    penguin.add(face);

    // Eyes
    const eyeGeo = new THREE.SphereGeometry(0.14, 16, 16);
    const leftEye  = new THREE.Mesh(eyeGeo, eyeMat);
    leftEye.position.set(-0.28, 4.12, 0.68);
    penguin.add(leftEye);
    const rightEye = new THREE.Mesh(eyeGeo, eyeMat);
    rightEye.position.set(0.28, 4.12, 0.68);
    penguin.add(rightEye);

    // Eye highlights
    const highlightGeo = new THREE.SphereGeometry(0.055, 8, 8);
    const lh = new THREE.Mesh(highlightGeo, pupilMat);
    lh.position.set(-0.24, 4.17, 0.78);
    penguin.add(lh);
    const rh = new THREE.Mesh(highlightGeo, pupilMat);
    rh.position.set(0.32, 4.17, 0.78);
    penguin.add(rh);

    // Cheeks
    const cheekGeo = new THREE.SphereGeometry(0.12, 16, 16);
    const leftCheek  = new THREE.Mesh(cheekGeo, cheekMat);
    leftCheek.position.set(-0.42, 3.92, 0.58);
    penguin.add(leftCheek);
    const rightCheek = new THREE.Mesh(cheekGeo, cheekMat);
    rightCheek.position.set(0.42, 3.92, 0.58);
    penguin.add(rightCheek);

    // Beak
    const beakGeo = new THREE.ConeGeometry(0.14, 0.45, 16);
    const beak = new THREE.Mesh(beakGeo, orangeMat);
    beak.rotation.x = Math.PI / 2;
    beak.position.set(0, 3.82, 0.82);
    beak.castShadow = true;
    penguin.add(beak);

    // Beak tip (slightly darker)
    const beakTipGeo = new THREE.ConeGeometry(0.08, 0.15, 16);
    const beakTipMat = new THREE.MeshStandardMaterial({ color: 0xcc6600, roughness: 0.5 });
    const beakTip = new THREE.Mesh(beakTipGeo, beakTipMat);
    beakTip.rotation.x = Math.PI / 2;
    beakTip.position.set(0, 3.82, 1.02);
    penguin.add(beakTip);

    // Flippers
    const flipperGeo = new THREE.SphereGeometry(0.35, 16, 16);
    const leftFlipper  = new THREE.Mesh(flipperGeo, blackMat);
    leftFlipper.scale.set(0.3, 1.6, 0.8);
    leftFlipper.position.set(-1.15, 2.8, 0);
    leftFlipper.rotation.z = 0.3;
    leftFlipper.castShadow = true;
    penguin.add(leftFlipper);

    const rightFlipper = new THREE.Mesh(flipperGeo, blackMat);
    rightFlipper.scale.set(0.3, 1.6, 0.8);
    rightFlipper.position.set(1.15, 2.8, 0);
    rightFlipper.rotation.z = -0.3;
    rightFlipper.castShadow = true;
    penguin.add(rightFlipper);

    // Feet
    const footGeo = new THREE.SphereGeometry(0.35, 16, 16);
    const leftFoot  = new THREE.Mesh(footGeo, orangeMat);
    leftFoot.scale.set(0.9, 0.3, 1.4);
    leftFoot.position.set(-0.4, 1.05, 0.25);
    leftFoot.castShadow = true;
    penguin.add(leftFoot);

    const rightFoot = new THREE.Mesh(footGeo, orangeMat);
    rightFoot.scale.set(0.9, 0.3, 1.4);
    rightFoot.position.set(0.4, 1.05, 0.25);
    rightFoot.castShadow = true;
    penguin.add(rightFoot);

    // ── Ground (snow) ───────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(20, 64);
    const groundMat = new THREE.MeshStandardMaterial({ color: 0xf0f4f8, roughness: 0.9 });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // Snow mounds
    for (let i = 0; i < 12; i++) {
      const r = 0.4 + Math.random() * 1.2;
      const moundGeo = new THREE.SphereGeometry(r, 16, 16);
      const mound = new THREE.Mesh(moundGeo, groundMat);
      const angle = Math.random() * Math.PI * 2;
      const dist  = 4 + Math.random() * 12;
      mound.position.set(Math.cos(angle) * dist, r * 0.3, Math.sin(angle) * dist);
      mound.scale.y = 0.4;
      mound.receiveShadow = true;
      scene.add(mound);
    }

    // ── Floating Snowflakes ─────────────────────────────────
    const snowCount = 300;
    const snowGeo = new THREE.BufferGeometry();
    const snowPos = new Float32Array(snowCount * 3);
    for (let i = 0; i < snowCount; i++) {
      snowPos[i * 3]     = (Math.random() - 0.5) * 30;
      snowPos[i * 3 + 1] = Math.random() * 15;
      snowPos[i * 3 + 2] = (Math.random() - 0.5) * 30;
    }
    snowGeo.setAttribute('position', new THREE.BufferAttribute(snowPos, 3));
    const snowMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.08, transparent: true, opacity: 0.8 });
    const snowflakes = new THREE.Points(snowGeo, snowMat);
    scene.add(snowflakes);

    // ── Animation ────────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle waddle
      penguin.rotation.y = Math.sin(t * 1.2) * 0.25;
      penguin.position.y = Math.sin(t * 2) * 0.08;

      // Flipper wiggle
      leftFlipper.rotation.z  = 0.3 + Math.sin(t * 3) * 0.15;
      rightFlipper.rotation.z = -0.3 - Math.sin(t * 3) * 0.15;

      // Subtle head bob
      head.rotation.z = Math.sin(t * 1.5) * 0.05;

      // Snowfall
      const positions = snowflakes.geometry.attributes.position.array;
      for (let i = 0; i < snowCount; i++) {
        positions[i * 3 + 1] -= 0.015;
        positions[i * 3]     += Math.sin(t + i) * 0.002;
        if (positions[i * 3 + 1] < 0) positions[i * 3 + 1] = 15;
      }
      snowflakes.geometry.attributes.position.needsUpdate = true;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ───────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's Inside

| Feature | Details |
|---|---|
| **Penguin body** | Built from `SphereGeometry` and `ConeGeometry` primitives — black body, white belly & face, orange beak & feet, pink cheeks |
| **Lighting** | Directional sun with soft shadows, fill light, and ambient light for a natural look |
| **Environment** | Snowy ground plane with random snow mounds and 300 falling snowflake particles |
| **Animation** | Gentle waddle (body sway + vertical bob), flipper wiggle, head bob, and continuous snowfall |
| **Interactivity** | `OrbitControls` — drag to rotate, scroll to zoom |
| **Rendering** | ACES filmic tone mapping, PCF soft shadows, antialiasing, DPR-aware pixel ratio |

Just save it as `index.html` and open in any modern browser — no build step needed.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Picture Scene</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; font-family: sans-serif; }
    canvas { display: block; }
