      letter-spacing: 0.5px;
    }
  </style>
</head>
<body>
  <div id="info">drag to orbit · scroll to zoom</div>

  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
        "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
      }
    }
  </script>

  <script type="module">
    import * as THREE from "three";
    import { OrbitControls } from "three/addons/controls/OrbitControls.js";

    // ── Scene, Camera, Renderer ──────────────────────────
    const scene    = new THREE.Scene();
    scene.background = new THREE.Color(0x111118);
    scene.fog = new THREE.FogExp2(0x111118, 0.06);

    const camera = new THREE.PerspectiveCamera(
      50, innerWidth / innerHeight, 0.1, 100
    );
    camera.position.set(0, 0, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    document.body.appendChild(renderer.domElement);

    // ── Controls ─────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.minDistance = 3;
    controls.maxDistance = 15;

    // ── Lights ───────────────────────────────────────────
    const ambient = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambient);

    const dir = new THREE.DirectionalLight(0xffffff, 1.5);
    dir.position.set(4, 6, 5);
    scene.add(dir);

    const rim = new THREE.PointLight(0x6688ff, 2, 15);
    rim.position.set(-4, 2, -3);
    scene.add(rim);

    // ── Picture (textured plane) ─────────────────────────
    const textureLoader = new THREE.TextureLoader();
    const imageUrl =
      "https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=1200";

    const texture = textureLoader.load(imageUrl, () => {
      texture.colorSpace = THREE.SRGBColorSpace;
      texture.needsUpdate = true;
    });

    const aspect = 3 / 2;
    const planeW = 3.6;
    const planeH = planeW / aspect;

    const planeGeo = new THREE.PlaneGeometry(planeW, planeH);
    const planeMat = new THREE.MeshStandardMaterial({
      map: texture,
      roughness: 0.4,
      metalness: 0.0,
      side: THREE.DoubleSide,
    });
    const picture = new THREE.Mesh(planeGeo, planeMat);
    scene.add(picture);

    // ── Frame ────────────────────────────────────────────
    const frameMat = new THREE.MeshStandardMaterial({
      color: 0x222222,
      roughness: 0.3,
      metalness: 0.8,
    });

    function makeBar(w, h, d) {
      return new THREE.Mesh(new THREE.BoxGeometry(w, h, d), frameMat);
    }

    const barT = makeBar(planeW + 0.24, 0.08, 0.08);
    const barB = makeBar(planeW + 0.24, 0.08, 0.08);
    const barL = makeBar(0.08, planeH + 0.16, 0.08);
    const barR = makeBar(0.08, planeH + 0.16, 0.08);

    const offset = planeW / 2 + 0.04;
    const offsetY = planeH / 2 + 0.04;

    barT.position.set(0,  offsetY, 0.01);
    barB.position.set(0, -offsetY, 0.01);
    barL.position.set(-offset, 0, 0.01);
    barR.position.set( offset, 0, 0.01);

    const frame = new THREE.Group();
    frame.add(barT, barB, barL, barR);
    picture.add(frame);

    // ── Floating particles ───────────────────────────────
    const count = 300;
    const positions = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 20;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 20;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
    }
    const partGeo = new THREE.BufferGeometry();
    partGeo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    const partMat = new THREE.PointsMaterial({
      color: 0x8888cc,
      size: 0.03,
      transparent: true,
      opacity: 0.6,
    });
    const particles = new THREE.Points(partGeo, partMat);
    scene.add(particles);

    // ── Animation Loop ───────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      picture.position.y = Math.sin(t * 0.6) * 0.15;
      picture.rotation.y = Math.sin(t * 0.3) * 0.08;
      picture.rotation.x = Math.cos(t * 0.25) * 0.04;

      particles.rotation.y = t * 0.02;
      particles.rotation.x = t * 0.01;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ───────────────────────────────────────────
    window.addEventListener("resize", () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
