});

// --- Pickaxe group ---
const pickaxe = new THREE.Group();

// Handle
const handleGeo = new THREE.CylinderGeometry(0.06, 0.05, 2.8, 12);
const handle = new THREE.Mesh(handleGeo, woodMat);
handle.position.y = 0.2;
handle.castShadow = true;
pickaxe.add(handle);

// Handle grip (wider at top)
const gripGeo = new THREE.CylinderGeometry(0.07, 0.06, 0.3, 12);
const grip = new THREE.Mesh(gripGeo, woodMat);
grip.position.y = 1.55;
grip.castShadow = true;
pickaxe.add(grip);

// Handle tip cap
const tipGeo = new THREE.SphereGeometry(0.055, 12, 8, 0, Math.PI * 2, 0, Math.PI / 2);
const tip = new THREE.Mesh(tipGeo, woodMat);
tip.position.y = 1.7;
tip.rotation.x = Math.PI;
pickaxe.add(tip);

// --- Head group (perpendicular to handle) ---
const head = new THREE.Group();
head.position.y = 0.95;

