const crossbarGeo = new THREE.BoxGeometry(1.6, 0.1, 0.18);
const crossbar = new THREE.Mesh(crossbarGeo, metalMat);
crossbar.castShadow = true;
head.add(crossbar);

// Collar (metal band around handle where head meets it)
const collarGeo = new THREE.CylinderGeometry(0.09, 0.09, 0.12, 16);
const collar = new THREE.Mesh(collarGeo, darkMetalMat);
collar.castShadow = true;
head.add(collar);

// --- Pick side (left) ---
const pickGroup = new THREE.Group();
pickGroup.position.x = -0.55;

// Pick arm (extends downward then curves)
const pickArmGeo = new THREE.BoxGeometry(0.08, 0.35, 0.14);
const pickArm = new THREE.Mesh(pickArmGeo, metalMat);
pickArm.position.y = -0.18;
pickArm.castShadow = true;
pickGroup.add(pickArm);

// Pick point (pointed tip)
const pickPointGeo = new THREE.ConeGeometry(0.045, 0.25, 6);
