pickPoint.rotation.z = Math.PI;
pickPoint.castShadow = true;
pickGroup.add(pickPoint);

// Pick curve connector
const pickCurveGeo = new THREE.SphereGeometry(0.055, 8, 8);
const pickCurve = new THREE.Mesh(pickCurveGeo, metalMat);
pickCurve.position.y = -0.3;
pickCurve.scale.set(1, 0.7, 1.2);
pickGroup.add(pickCurve);

head.add(pickGroup);

// --- Axe/blade side (right) ---
const bladeGroup = new THREE.Group();
