scene.add(new THREE.HemisphereLight(0xffeeb1, 0x080820, 0.4));

const sun = new THREE.DirectionalLight(0xffffff, 1.6);
sun.position.set(5, 8, 4);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
sun.shadow.camera.near = 1; sun.shadow.camera.far = 20;
sun.shadow.camera.left = -5; sun.shadow.camera.right = 5;
sun.shadow.camera.top = 5;  sun.shadow.camera.bottom = -5;
scene.add(sun);

/* ── Materials ─────────────────────────────────────── */
const pink      = new THREE.MeshStandardMaterial({ color: 0xf4a0b5, roughness: 0.55, metalness: 0.0 });
const darkPink  = new THREE.MeshStandardMaterial({ color: 0xe07a8e, roughness: 0.6 });
const snoutMat  = new THREE.MeshStandardMaterial({ color: 0xe88a9e, roughness: 0.45 });
const eyeWhite  = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.3 });
const eyePupil  = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.2, metalness: 0.3 });
const hoofMat   = new THREE.MeshStandardMaterial({ color: 0x3a2a1a, roughness: 0.8 });
const earInner  = new THREE.MeshStandardMaterial({ color: 0xf0b0c0, roughness: 0.5 });
const tailMat   = new THREE.MeshStandardMaterial({ color: 0xf4a0b5, roughness: 0.5 });

/* ── Helpers ───────────────────────────────────────── */
function mesh(geo, mat, pos, rot, scale, castShadow = true) {
  const m = new THREE.Mesh(geo, mat);
  if (pos) m.position.set(...pos);
  if (rot) m.rotation.set(...rot);
  if (scale) m.scale.set(...scale);
  m.castShadow = castShadow;
  m.receiveShadow = true;
  return m;
}

/* ── Pig group ─────────────────────────────────────── */
const pig = new THREE.Group();

// Body
pig.add(mesh(new THREE.SphereGeometry(1, 32, 24), pink, [0, 1.35, 0], null, [1.0, 0.82, 0.72]));

// Head
const head = new THREE.Group();
head.position.set(0, 1.65, 0.78);
pig.add(head);

head.add(mesh(new THREE.SphereGeometry(0.52, 28, 24), pink, [0, 0, 0], null, [1, 0.95, 0.88]));

// Snout
head.add(mesh(new THREE.SphereGeometry(0.28, 24, 20), snoutMat, [0, -0.08, 0.42], null, [1.15, 0.85, 0.7]));

// Nostrils
const nostrilGeo = new THREE.SphereGeometry(0.055, 12, 10);
head.add(mesh(nostrilGeo, darkPink, [-0.1, -0.06, 0.58], null, [1, 0.7, 0.5]));
head.add(mesh(nostrilGeo, darkPink, [0.1, -0.06, 0.58], null, [1, 0.7, 0.5]));

// Eyes
const eyeGeo = new THREE.SphereGeometry(0.09, 16, 12);
const pupilGeo = new THREE.SphereGeometry(0.055, 12, 10);
[-1, 1].forEach(s => {
  head.add(mesh(eyeGeo, eyeWhite, [s * 0.28, 0.15, 0.38]));
  head.add(mesh(pupilGeo, eyePupil, [s * 0.28, 0.15, 0.46]));
});

// Eyebrows
const browGeo = new THREE.BoxGeometry(0.16, 0.03, 0.06);
[-1, 1].forEach(s => {
  head.add(mesh(browGeo, darkPink, [s * 0.28, 0.28, 0.4], [0, 0, s * 0.2]));
});

// Ears
const earGeo = new THREE.SphereGeometry(0.22, 16, 14);
[-1, 1].forEach(s => {
  const earGroup = new THREE.Group();
  earGroup.position.set(s * 0.35, 0.42, 0.05);
  earGroup.rotation.set(0.1, 0, s * 0.6);
  earGroup.add(mesh(earGeo, pink, [0, 0, 0], null, [0.7, 1.1, 0.35]));
  earGroup.add(mesh(earGeo, earInner, [0, 0, 0.02], null, [0.55, 0.9, 0.25]));
  head.add(earGroup);
});

// Legs
const legGeo = new THREE.CylinderGeometry(0.12, 0.1, 0.6, 14);
const hoofGeo = new THREE.BoxGeometry(0.14, 0.08, 0.2);
const legPositions = [
  [-0.35, 0.55, 0.45],
  [0.35, 0.55, 0.45],
  [-0.35, 0.55, -0.45],
  [0.35, 0.55, -0.45],
];
legPositions.forEach(p => {
  pig.add(mesh(legGeo, pink, p));
  pig.add(mesh(hoofGeo, hoofMat, [p[0], 0.22, p[2]]));
});

// Tail (spiral of small spheres)
const tailGroup = new THREE.Group();
tailGroup.position.set(0, 1.5, -0.65);
pig.add(tailGroup);
const tailPoints = [];
for (let i = 0; i <= 40; i++) {
  const t = i / 40;
  const angle = t * Math.PI * 3;
  const r = 0.12 * (1 - t * 0.4);
  tailPoints.push(new THREE.Vector3(
    Math.cos(angle) * r,
    t * 0.55,
    Math.sin(angle) * r
  ));
}
tailPoints.forEach((p, i) => {
  const s = 0.045 * (1 - i / 40 * 0.5);
  tailGroup.add(mesh(new THREE.SphereGeometry(s, 8, 6), tailMat, p));
});

// Saddle patch (darker area on back)
pig.add(mesh(new THREE.SphereGeometry(1.02, 32, 24), darkPink, [0, 1.55, -0.05], null, [0.95, 0.35, 0.55], false));

// Belly highlight
pig.add(mesh(new THREE.SphereGeometry(1.0, 32, 24), new THREE.MeshStandardMaterial({
  color: 0xfcc8d4, roughness: 0.5, transparent: true, opacity: 0.3
}), [0, 1.2, 0.15], null, [0.85, 0.65, 0.55], false));

scene.add(pig);

/* ── Ground ────────────────────────────────────────── */
const groundGeo = new THREE.CircleGeometry(12, 48);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x5aad5a, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Mud patch
const mudGeo = new THREE.CircleGeometry(1.2, 24);
const mudMat = new THREE.MeshStandardMaterial({ color: 0x8b6f47, roughness: 1.0 });
const mud = new THREE.Mesh(mudGeo, mudMat);
mud.rotation.x = -Math.PI / 2;
mud.position.set(0, 0.005, 0);
mud.receiveShadow = true;
scene.add(mud);

// Small flowers
const flowerStemGeo = new THREE.CylinderGeometry(0.01, 0.01, 0.2, 6);
const flowerHeadGeo = new THREE.SphereGeometry(0.04, 8, 6);
for (let i = 0; i < 30; i++) {
  const angle = Math.random() * Math.PI * 2;
  const dist = 2 + Math.random() * 8;
  const fg = new THREE.Group();
  fg.add(mesh(flowerStemGeo, new THREE.MeshStandardMaterial({ color: 0x3a7a3a }), [0, 0.1, 0]));
  const colors = [0xff6b8a, 0xffd700, 0xffffff, 0xff9ecd, 0x87ceeb];
  fg.add(mesh(flowerHeadGeo, new THREE.MeshStandardMaterial({ color: colors[Math.floor(Math.random() * colors.length)] }), [0, 0.22, 0]));
  fg.position.set(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
  scene.add(fg);
}

// Clouds
const cloudGeo = new THREE.SphereGeometry(1, 16, 12);
const cloudMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 1, transparent: true, opacity: 0.85 });
for (let i = 0; i < 5; i++) {
  const cg = new THREE.Group();
  const count = 3 + Math.floor(Math.random() * 3);
  for (let j = 0; j < count; j++) {
    const s = 0.4 + Math.random() * 0.5;
    const m = mesh(cloudGeo, cloudMat, [j * 0.5 - count * 0.25, Math.random() * 0.2, Math.random() * 0.3], null, [s * 1.5, s, s * 0.8], false);
    cg.add(m);
  }
  cg.position.set(Math.random() * 20 - 10, 6 + Math.random() * 3, -8 - Math.random() * 6);
  scene.add(cg);
}

/* ── Animation ─────────────────────────────────────── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle breathing
  pig.children[0].scale.y = 0.82 + Math.sin(t * 1.5) * 0.015;
  pig.children[0].position.y = 1.35 + Math.sin(t * 1.5) * 0.01;

  // Head bob
  head.rotation.x = Math.sin(t * 0.8) * 0.04;
  head.rotation.z = Math.sin(t * 0.5) * 0.02;

  // Ear twitch
  head.children.forEach((c, i) => {
    if (c.isGroup && c.children.length === 2) {
      c.rotation.z += Math.sin(t * 3 + i) * 0.001;
    }
  });

  // Tail wag
  tailGroup.rotation.y = Math.sin(t * 2.5) * 0.4;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ────────────────────────────────────────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

