<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Pipe</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #111; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.015);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(8, 6, 10);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1.5, 0);

// --- Lighting ---
const ambient = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2);
dirLight.position.set(5, 10, 7);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 30;
dirLight.shadow.camera.left = -10;
dirLight.shadow.camera.right = 10;
dirLight.shadow.camera.top = 10;
dirLight.shadow.camera.bottom = -10;
scene.add(dirLight);

const pointLight = new THREE.PointLight(0x4488ff, 1, 20);
pointLight.position.set(-5, 4, -3);
scene.add(pointLight);

const rimLight = new THREE.PointLight(0xff6633, 0.8, 20);
rimLight.position.set(4, 2, -6);
scene.add(rimLight);

// --- Materials ---
const pipeMat = new THREE.MeshStandardMaterial({
  color: 0x888899,
  metalness: 0.9,
  roughness: 0.25,
});

const flangeMat = new THREE.MeshStandardMaterial({
  color: 0x666677,
  metalness: 0.85,
  roughness: 0.35,
});

const boltMat = new THREE.MeshStandardMaterial({
  color: 0xaaaaaa,
  metalness: 0.95,
  roughness: 0.15,
});

// --- Pipe Path (bent run) ---
const curve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-5, 0.5, 0),
  new THREE.Vector3(-2, 0.5, 0),
  new THREE.Vector3(0, 0.5, 0),
  new THREE.Vector3(0, 3.5, 0),
  new THREE.Vector3(0, 5.5, 0),
  new THREE.Vector3(2, 5.5, 0),
  new THREE.Vector3(4, 5.5, 0),
], false, 'catmullrom', 0.5);

// --- Main Pipe Segment ---
const pipeGeo = new THREE.TubeGeometry(curve, 64, 0.3, 16, false);
const pipe = new THREE.Mesh(pipeGeo, pipeMat);
pipe.castShadow = true;
pipe.receiveShadow = true;
scene.add(pipe);

// --- Helper: Flange at position along curve ---
function addFlange(t) {
  const pos = curve.getPointAt(t);
  const tangent = curve.getTangentAt(t).normalize();

  const group = new THREE.Group();
  group.position.copy(pos);

  // Flange disk
  const diskGeo = new THREE.CylinderGeometry(0.55, 0.55, 0.12, 24);
  const disk = new THREE.Mesh(diskGeo, flangeMat);
  disk.castShadow = true;

  // Orient disk perpendicular to pipe tangent
  const up = new THREE.Vector3(0, 1, 0);
  const quaternion = new THREE.Quaternion().setFromUnitVectors(up, tangent);
  disk.quaternion.copy(quaternion);

  group.add(disk);

  // Bolts around the flange
  for (let i = 0; i < 6; i++) {
    const angle = (i / 6) * Math.PI * 2;
    const boltGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.18, 8);
    const bolt = new THREE.Mesh(boltGeo, boltMat);
    bolt.position.set(Math.cos(angle) * 0.42, 0, Math.sin(angle) * 0.42);
    bolt.quaternion.copy(quaternion);
    bolt.castShadow = true;
    group.add(bolt);
  }

  scene.add(group);
}

addFlange(0.15);
addFlange(0.45);
addFlange(0.75);

// --- Vertical support pipe (branch) ---
const branchCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 3.5, 0),
  new THREE.Vector3(0, 3.5, 2),
  new THREE.Vector3(0, 3.5, 3.5),
], false, 'catmullrom', 0.5);

const branchGeo = new THREE.TubeGeometry(branchCurve, 32, 0.2, 12, false);
const branch = new THREE.Mesh(branchGeo, pipeMat);
branch.castShadow = true;
scene.add(branch);

// Tee joint
const teeGeo = new THREE.SphereGeometry(0.42, 16, 12);
const tee = new THREE.Mesh(teeGeo, flangeMat);
tee.position.set(0, 3.5, 0);
tee.castShadow = true;
scene.add(tee);

// --- End Caps ---
function addCap(position, tangent) {
  const capGeo = new THREE.CylinderGeometry(0.32, 0.32, 0.15, 16);
  const cap = new THREE.Mesh(capGeo, flangeMat);
  cap.position.copy(position);

  const up = new THREE.Vector3(0, 1, 0);
  cap.quaternion.setFromUnitVectors(up, tangent);
  cap.castShadow = true;
  scene.add(cap);
}

const startTan = curve.getTangentAt(0.001);
addCap(curve.getPointAt(0), startTan);
addCap(curve.getPointAt(1), curve.getTangentAt(0.999));

const endBranch = branchCurve.getPointAt(1);
const branchTan = branchCurve.getTangentAt(0.999);
addCap(endBranch, branchTan);

// --- Ground Plane ---
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x222233,
  metalness: 0.3,
  roughness: 0.8,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// --- Grid ---
const grid = new THREE.GridHelper(30, 30, 0x333355, 0x222244);
grid.position.y = 0.01;
scene.add(grid);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Subtle light animation
  pointLight.intensity = 1 + Math.sin(elapsed * 1.5) * 0.3;
  rimLight.intensity = 0.8 + Math.cos(elapsed * 1.2) * 0.3;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
