```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Pinecone</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { background: #1a1410; overflow: hidden; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1410);
scene.fog = new THREE.FogExp2(0x1a1410, 0.018);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 2, 18);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.06;

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xfff4e0, 1.8);
dirLight.position.set(5, 10, 7);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const backLight = new THREE.DirectionalLight(0xc8b8a0, 0.5);
backLight.position.set(-4, 3, -6);
scene.add(backLight);

const rimLight = new THREE.PointLight(0xffcc88, 0.6, 30);
rimLight.position.set(-3, 5, -4);
scene.add(rimLight);

// --- Scale geometry (curved diamond) ---
function createScaleGeometry() {
  const segW = 6, segH = 8;
  const positions = [], normals = [], uvs = [], indices = [];

  for (let j = 0; j <= segH; j++) {
    for (let i = 0; i <= segW; i++) {
      const u = i / segW;
      const v = j / segH;

      // Diamond profile: wide in middle, narrow at ends
      const x = (u - 0.5) * 1.6 * Math.sin(v * Math.PI);
      const y = (v - 0.5) * 2.4;

      // Slight 3D bulge (convex shape)
      const bulge = Math.sin(u * Math.PI) * Math.sin(v * Math.PI) * 0.18;
      const z = bulge;

      // Edge taper for organic look
      const edgeFactor = Math.sin(u * Math.PI) * Math.sin(v * Math.PI);
      const finalZ = z * edgeFactor;

      positions.push(x, y, finalZ);

      // Approximate normal
      const nx = x * 0.3;
      const ny = y * 0.1;
      const nz = 1.0;
      const len = Math.sqrt(nx * nx + ny * ny + nz * nz);
      normals.push(nx / len, ny / len, nz / len);

      uvs.push(u, v);
    }
  }

  for (let j = 0; j < segH; j++) {
    for (let i = 0; i < segW; i++) {
      const a = j * (segW + 1) + i;
      const b = a + 1;
      const c = a + segW + 1;
      const d = c + 1;
      indices.push(a, b, c);
      indices.push(b, d, c);
    }
  }

  const geo = new THREE.BufferGeometry();
  geo.setIndex(indices);
  geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  geo.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  return geo;
}

// --- Build pinecone from scales ---
const GOLDEN_ANGLE = 137.508 * Math.PI / 180;
const SCALE_COUNT = 280;
const CONE_HEIGHT = 8;
const BASE_RADIUS = 3.2;
const SCALE_SPACING = 0.42;

const scaleGeo = createScaleGeometry();

// Create a texture-like material with vertex color variation
const scaleMat = new THREE.MeshStandardMaterial({
  color: 0x8B6914,
  roughness: 0.75,
  metalness: 0.05,
  side: THREE.DoubleSide,
  flatShading: false,
});

const instancedScales = new THREE.InstancedMesh(scaleGeo, scaleMat, SCALE_COUNT);
instancedScales.castShadow = true;
instancedScales.receiveShadow = true;

const dummy = new THREE.Object3D();
const color = new THREE.Color();

for (let n = 0; n < SCALE_COUNT; n++) {
  const t = n / (SCALE_COUNT - 1); // 0 to 1 along cone

  // Phyllotaxis position
  const angle = n * GOLDEN_ANGLE;
  const r = BASE_RADIUS * Math.sqrt(t) * (1 - t * 0.3); // taper toward top

  // Cone surface position
  const x = r * Math.cos(angle);
  const z = r * Math.sin(angle);
  const y = (t - 0.5) * CONE_HEIGHT;

  dummy.position.set(x, y, z);

  // Orient scale outward from cone axis
  const outwardAngle = Math.atan2(z, x);
  dummy.rotation.y = -outwardAngle;

  // Tilt scales: more horizontal at base, more vertical at top
  const tilt = Math.PI * 0.15 + t * Math.PI * 0.35;
  dummy.rotation.x = tilt;

  // Slight random twist for natural look
  dummy.rotation.z = (Math.sin(n * 0.7) * 0.12);

  // Scale size: larger at base, smaller near tip
  const size = (0.35 + 0.3 * (1 - t)) * (0.9 + Math.sin(n * 0.3) * 0.1);
  dummy.scale.set(size, size, size);

  dummy.updateMatrix();
  instancedScales.setMatrixAt(n, dummy.matrix);

  // Color variation: darker at base, lighter at tips, with noise
  const baseR = 0.45 + (1 - t) * 0.15 + Math.sin(n * 1.7) * 0.05;
  const baseG = 0.30 + (1 - t) * 0.10 + Math.sin(n * 2.3) * 0.04;
  const baseB = 0.08 + (1 - t) * 0.06 + Math.sin(n * 0.9) * 0.03;
  color.setRGB(baseR, baseG, baseB);
  instancedScales.setColorAt(n, color);
}

instancedScales.instanceMatrix.needsUpdate = true;
instancedScales.instanceColor.needsUpdate = true;
scene.add(instancedScales);

// --- Central stem ---
const stemGeo = new THREE.CylinderGeometry(0.12, 0.25, CONE_HEIGHT * 0.95, 8);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x5a4020,
  roughness: 0.9,
  metalness: 0.0,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.y = -0.1;
stem.castShadow = true;
scene.add(stem);

// --- Small base disc ---
const baseGeo = new THREE.CylinderGeometry(0.35, 0.4, 0.15, 12);
const baseMesh = new THREE.Mesh(baseGeo, stemMat);
baseMesh.position.y = -CONE_HEIGHT * 0.47;
scene.add(baseMesh);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle rotation
  instancedScales.rotation.y = elapsed * 0.15;
  stem.rotation.y = elapsed * 0.15;
  baseMesh.rotation.y = elapsed * 0.15;

  // Subtle breathing scale
  const breathe = 1 + Math.sin(elapsed * 0.5) * 0.005;
  instancedScales.scale.setScalar(breathe);

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a realistic pinecone visualization with:

- **Phyllotaxis spiral arrangement** — 280 scales placed using the golden angle (137.5°), mimicking nature's Fibonacci packing pattern
- **Curved diamond scales** — each scale is a parametric mesh with a convex bulge, wider in the middle and tapering at the edges
- **Cone shape** — scales distributed from a wide base to a tapered tip along a conical surface
- **Natural color variation** — darker browns at the base, lighter tones near the tip, with sinusoidal noise for organic variation
- **Central stem** — a wooden cylinder running through the core
- **Three-point lighting** — warm key light, fill light, and rim light with ACES filmic tone mapping
- **Gentle auto-rotation** with a subtle breathing animation
- **OrbitControls** — drag to rotate, scroll to zoom

