<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

// --- Scene Setup ---
const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 1000);
camera.position.z = 4;

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
document.body.appendChild(renderer.domElement);

// --- Starfield ---
const starGeo = new THREE.BufferGeometry();
const starCount = 6000;
const starPos = new Float32Array(starCount * 3);
for (let i = 0; i < starCount * 3; i++) starPos[i] = (Math.random() - 0.5) * 200;
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({ color: 0xffffff, size: 0.15 })));

// --- Planet ---
const planetGeo = new THREE.SphereGeometry(1, 64, 64);
const planetMat = new THREE.ShaderMaterial({
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    varying vec3 vNormal;
    varying vec3 vPosition;
    void main() {
      vNormal = normalize(normalMatrix * normal);
      vPosition = position;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform float uTime;
    varying vec3 vNormal;
    varying vec3 vPosition;

    // Simple hash-based noise
    float hash(vec2 p) {
      p = fract(p * vec2(123.34, 456.21));
      p += dot(p, p + 45.32);
      return fract(p.x * p.y);
    }

    float noise(vec2 p) {
      vec2 i = floor(p), f = fract(p);
      f = f * f * (3.0 - 2.0 * f);
      float a = hash(i), b = hash(i + vec2(1,0)), c = hash(i + vec2(0,1)), d = hash(i + vec2(1,1));
      return mix(mix(a,b,f.x), mix(c,d,f.x), f.y);
    }

    float fbm(vec2 p) {
      float v = 0.0, a = 0.5;
      mat2 rot = mat2(0.8, 0.6, -0.6, 0.8);
      for (int i = 0; i < 6; i++) { v += a * noise(p); p = rot * p * 2.0; a *= 0.5; }
      return v;
    }

    void main() {
      vec2 uv = vPosition.xy * 2.0 + uTime * 0.02;
      float n = fbm(uv * 3.0);
      float lat = abs(vPosition.y);

      // Ocean / land / ice coloring
      vec3 ocean = mix(vec3(0.01, 0.05, 0.2), vec3(0.0, 0.3, 0.6), n * 1.5);
      vec3 land  = mix(vec3(0.1, 0.35, 0.1), vec3(0.4, 0.3, 0.15), n);
      vec3 ice   = vec3(0.9, 0.95, 1.0);

      vec3 color = n > 0.45 ? land : ocean;
      color = mix(color, ice, smoothstep(0.7, 0.95, lat));

      // Fresnel rim
      float rim = 1.0 - max(dot(vNormal, vec3(0,0,1)), 0.0);
      color += vec3(0.3, 0.6, 1.0) * pow(rim, 3.0) * 0.5;

      gl_FragColor = vec4(color, 1.0);
    }
  `
});
const planet = new THREE.Mesh(planetGeo, planetMat);
scene.add(planet);

// --- Atmosphere Glow ---
const atmosGeo = new THREE.SphereGeometry(1.15, 64, 64);
const atmosMat = new THREE.ShaderMaterial({
  transparent: true,
  side: THREE.BackSide,
  vertexShader: `
    varying vec3 vNormal;
    void main() {
      vNormal = normalize(normalMatrix * normal);
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    varying vec3 vNormal;
    void main() {
      float intensity = pow(0.65 - dot(vNormal, vec3(0,0,1)), 2.0);
      gl_FragColor = vec4(0.3, 0.6, 1.0, 1.0) * intensity * 1.2;
    }
  `
});
scene.add(new THREE.Mesh(atmosGeo, atmosMat));

// --- Lighting ---
scene.add(new THREE.AmbientLight(0x333355, 1.5));
const sun = new THREE.DirectionalLight(0xffeedd, 3);
sun.position.set(5, 3, 4);
scene.add(sun);

// --- Animate ---
function animate(t) {
  requestAnimationFrame(animate);
  planet.rotation.y = t * 0.05;
  planetMat.uniforms.uTime.value = t * 0.001;
  renderer.render(scene, camera);
}
animate(0);

// --- Resize ---
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

