  roughness: 0.5,
  metalness: 0.1,
});

const pepperoniPositions = [
  { x: 0.3, z: 0.2, r: 0.3 },
  { x: -0.5, z: -0.3, r: 0.7 },
  { x: 0.6, z: -0.5, r: 1.2 },
  { x: -0.3, z: 0.7, r: 0.1 },
  { x: 0.0, z: -0.8, r: 2.5 },
  { x: -0.7, z: 0.4, r: 1.8 },
  { x: 0.8, z: 0.5, r: 0.9 },
  { x: -0.1, z: -0.1, r: 0.5 },
  { x: 0.4, z: -0.6, r: 1.5 },
  { x: -0.6, z: -0.7, r: 2.8 },
  { x: 0.1, z: 0.6, r: 1.1 },
];

pepperoniPositions.forEach(({ x, z, r }) => {
  const pep = new THREE.Mesh(pepperoniGeo, pepperoniMat);
  pep.position.set(x, 0.28, z);
  pep.rotation.y = r;
  pep.castShadow = true;
  pizza.add(pep);

  // Fat spots on pepperoni
  for (let j = 0; j < 2; j++) {
    const spotGeo = new THREE.SphereGeometry(0.03, 8, 8);
    const spotMat = new THREE.MeshStandardMaterial({
      color: 0xf5d980,
      roughness: 0.6,
    });
    const spot = new THREE.Mesh(spotGeo, spotMat);
    const sa = Math.random() * Math.PI * 2;
    const sr = Math.random() * 0.1;
    spot.position.set(
      x + Math.cos(sa) * sr,
      0.31,
      z + Math.sin(sa) * sr
    );
    spot.scale.y = 0.3;
    pizza.add(spot);
  }
});

// Basil leaves
const leafGeo = new THREE.SphereGeometry(0.12, 8, 8);
const leafMat = new THREE.MeshStandardMaterial({
  color: 0x2d8b2d,
  roughness: 0.6,
  metalness: 0.0,
});

const leafPositions = [
  { x: 0.5, z: 0.8, rx: 0.2, ry: 0.5 },
  { x: -0.8, z: -0.2, rx: 0.3, ry: 1.0 },
  { x: 0.0, z: 0.0, rx: 0.1, ry: 0.0 },
];

leafPositions.forEach(({ x, z, rx, ry }) => {
  const leaf = new THREE.Mesh(leafGeo, leafMat);
  leaf.position.set(x, 0.32, z);
  leaf.scale.set(1, 0.3, 1.8);
  leaf.rotation.y = ry;
  leaf.castShadow = true;
  pizza.add(leaf);
});

// Tilt pizza slightly for a nicer view
pizza.rotation.x = -0.15;
scene.add(pizza);

// Plate
const plateGeo = new THREE.CylinderGeometry(2.6, 2.4, 0.1, 64);
const plateMat = new THREE.MeshStandardMaterial({
  color: 0xeeeeee,
  roughness: 0.3,
  metalness: 0.1,
});
const plate = new THREE.Mesh(plateGeo, plateMat);
plate.position.y = -0.05;
plate.receiveShadow = true;
plate.castShadow = true;
scene.add(plate);

// Floor
const floorGeo = new THREE.PlaneGeometry(30, 30);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e,
  roughness: 0.9,
  metalness: 0.0,
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -0.1;
floor.receiveShadow = true;
scene.add(floor);

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  pizza.rotation.y = t * 0.3;
  controls.update();
  renderer.render(scene, camera);
}

animate();

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
