```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Plum</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
position: absolute; bottom: 20px; left: 50%; transform: translateX(-50%);
color: #ccc; font-family: 'Helvetica Neue', sans-serif; font-size: 14px;
background: rgba(0,0,0,0.5); padding: 8px 18px; border-radius: 20px;
pointer-events: none; letter-spacing: 0.5px;
}
</style>
</head>
<body>
<div id="info">drag to rotate · scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.08);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 6);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);
controls.minDistance = 3;
controls.maxDistance = 12;

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.8);
fillLight.position.set(-5, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xff6699, 1.0);
rimLight.position.set(-3, -2, -5);
scene.add(rimLight);

const bottomLight = new THREE.PointLight(0x4444aa, 0.5, 10);
bottomLight.position.set(0, -4, 2);
scene.add(bottomLight);

// --- Environment (simple procedural for reflections) ---
const pmremGenerator = new THREE.PMREMGenerator(renderer);
const envScene = new THREE.Scene();
envScene.background = new THREE.Color(0x2a2a4a);

const envLight1 = new THREE.DirectionalLight(0xffffff, 3);
envLight1.position.set(5, 5, 5);
envScene.add(envLight1);
const envLight2 = new THREE.DirectionalLight(0xff88aa, 2);
envLight2.position.set(-5, 3, -5);
envScene.add(envLight2);
const envLight3 = new THREE.DirectionalLight(0x8888ff, 1.5);
envLight3.position.set(0, -5, 5);
envScene.add(envLight3);

const envMap = pmremGenerator.fromScene(envScene).texture;
scene.environment = envMap;

// --- Plum Body ---
const bodyGeometry = new THREE.SphereGeometry(1.2, 128, 128);

// Deform vertices to create plum shape
const pos = bodyGeometry.attributes.position;
const vertex = new THREE.Vector3();

for (let i = 0; i < pos.count; i++) {
  vertex.fromBufferAttribute(pos, i);

  const x = vertex.x;
  const y = vertex.y;
  const z = vertex.z;

  // Slight elongation (plums are a bit taller than wide)
  vertex.y *= 1.08;

  // Create the characteristic seam/crease
  // The seam runs along a curve around the plum
  const seamAngle = Math.atan2(z, x);
  const seamWidth = 0.35;
  const seamDepth = 0.06;

  // Seam is more pronounced on one side
  const seamFactor = Math.exp(-Math.pow((seamAngle - Math.PI * 0.3) / seamWidth, 2));
  const seamFactor2 = Math.exp(-Math.pow((seamAngle + Math.PI * 0.3) / seamWidth, 2));
  const seam = Math.max(seamFactor, seamFactor2);

  // Apply seam indentation - more at the equator, less at poles
  const latFactor = Math.cos(Math.asin(Math.max(-1, Math.min(1, y / 1.2))));
  const indentation = seam * seamDepth * latFactor;

  // Push vertices inward along the seam
  const len = vertex.length();
  vertex.normalize().multiplyScalar(len - indentation);

  // Subtle bumpiness for organic feel
  const noise = Math.sin(x * 8.0) * Math.cos(y * 6.0) * Math.sin(z * 7.0) * 0.008;
  vertex.normalize().multiplyScalar(len + noise);

  // Flatten the bottom slightly (where it sat on the branch)
  if (y < -0.8) {
    const bottomFactor = Math.abs(y + 0.8) / 0.4;
    vertex.x *= (1.0 - bottomFactor * 0.08);
    vertex.z *= (1.0 - bottomFactor * 0.08);
  }

  // Widen the top slightly (where stem attaches)
  if (y > 0.9) {
    const topFactor = (y - 0.9) / 0.3;
    vertex.x *= (1.0 + topFactor * 0.04);
    vertex.z *= (1.0 + topFactor * 0.04);
  }

  pos.setXYZ(i, vertex.x, vertex.y, vertex.z);
}

bodyGeometry.computeVertexNormals();

// --- Plum Material with custom coloring ---
const plumMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x5a1a6e,
  roughness: 0.25,
  metalness: 0.0,
  clearcoat: 0.8,
  clearcoatRoughness: 0.15,
  reflectivity: 0.6,
  sheen: 0.3,
  sheenRoughness: 0.5,
  sheenColor: new THREE.Color(0x8833aa),
  envMapIntensity: 1.0,
});

const plumBody = new THREE.Mesh(bodyGeometry, plumMaterial);
plumBody.castShadow = true;
scene.add(plumBody);

// --- Color variation using a second mesh with a vertex color approach ---
// We'll use a shader material overlay for the color gradient
const colorOverlayMaterial = new THREE.ShaderMaterial({
  uniforms: {
    envMap: { value: envMap },
  },
  vertexShader: `
    varying vec3 vNormal;
    varying vec3 vWorldPosition;
    varying vec3 vViewDir;
    varying vec3 vWorldNormal;
    varying vec2 vUv;

    void main() {
      vUv = uv;
      vNormal = normalize(normalMatrix * normal);
      vec4 worldPos = modelMatrix * vec4(position, 1.0);
      vWorldPosition = worldPos.xyz;
      vWorldNormal = normalize(mat3(modelMatrix) * normal);
      vViewDir = normalize(cameraPosition - worldPos.xyz);
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    varying vec3 vNormal;
    varying vec3 vWorldPosition;
    varying vec3 vViewDir;
    varying vec3 vWorldNormal;
    varying vec2 vUv;

    void main() {
      // Base purple color
      vec3 baseColor = vec3(0.35, 0.08, 0.42);

      // Red blush on one side
      float blush = smoothstep(-0.5, 0.8, vWorldNormal.x * 0.7 + vWorldNormal.z * 0.5);
      blush *= smoothstep(0.6, 0.0, abs(vWorldNormal.y)); // more on sides
      vec3 blushColor = vec3(0.7, 0.12, 0.25);
      baseColor = mix(baseColor, blushColor, blush * 0.7);

      // Darker at the bottom
      float bottomDark = smoothstep(-0.3, -1.0, vWorldNormal.y);
      baseColor = mix(baseColor, baseColor * 0.5, bottomDark * 0.4);

      // Lighter at the top
      float topLight = smoothstep(0.3, 1.0, vWorldNormal.y);
      baseColor = mix(baseColor, baseColor * 1.3 + vec3(0.05), topLight * 0.3);

      // Subtle specular-like sheen
      float fresnel = pow(1.0 - max(dot(vViewDir, vNormal), 0.0), 3.0);
      baseColor += vec3(0.15, 0.05, 0.12) * fresnel;

      // Slight waxy bloom
      float waxy = pow(max(dot(vViewDir, vNormal), 0.0), 16.0);
      baseColor += vec3(0.3, 0.1, 0.25) * waxy * 0.25;

      gl_FragColor = vec4(baseColor, 1.0);
    }
  `,
  transparent: false,
});

// Replace the body material with our shader
plumBody.material = colorOverlayMaterial;

// --- Stem ---
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 1.25, 0),
  new THREE.Vector3(0.05, 1.55, 0.02),
  new THREE.Vector3(0.12, 1.85, -0.03),
  new THREE.Vector3(0.15, 2.1, 0.0),
]);

const stemGeometry = new THREE.TubeGeometry(stemCurve, 20, 0.035, 12, false);
const stemMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x3d2b1f,
  roughness: 0.8,
  metalness: 0.0,
});
const stem = new THREE.Mesh(stemGeometry, stemMaterial);
scene.add(stem);

// --- Small leaf ---
const leafShape = new THREE.Shape();
leafShape.moveTo(0, 0);
leafShape.quadraticCurveTo(0.15, 0.3, 0.05, 0.6);
leafShape.quadraticCurveTo(-0.1, 0.3, 0, 0);

const leafGeometry = new THREE.ShapeGeometry(leafShape, 16);
const leafMaterial = new THREE.MeshPhysicalMaterial({
  color: 0x2d5a1e,
  roughness: 0.6,
  metalness: 0.0,
  side: THREE.DoubleSide,
  clearcoat: 0.3,
});

const leaf = new THREE.Mesh(leafGeometry, leafMaterial);
leaf.position.set(0.15, 2.1, 0.0);
leaf.rotation.set(0.3, -0.5, 0.8);
leaf.scale.set(1.2, 1.2, 1.2);
scene.add(leaf);

// Second smaller leaf
const leaf2 = new THREE.Mesh(leafGeometry, leafMaterial);
leaf2.position.set(0.1, 2.05, 0.05);
leaf2.rotation.set(-0.2, 0.8, -0.6);
leaf2.scale.set(0.8, 0.8, 0.8);
scene.add(leaf2);

// --- Ground plane (subtle reflection) ---
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshPhysicalMaterial({
  color: 0x1a1a2e,
  roughness: 0.3,
  metalness: 0.5,
  envMapIntensity: 0.3,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.2;
scene.add(ground);

// --- Subtle shadow plane ---
const shadowGeo = new THREE.PlaneGeometry(4, 4);
const shadowMat = new THREE.ShadowMaterial({ opacity: 0.3 });
const shadowPlane = new THREE.Mesh(shadowGeo, shadowMat);
shadowPlane.rotation.x = -Math.PI / 2;
shadowPlane.position.y = -2.19;
shadowPlane.receiveShadow = true;
scene.add(shadowPlane);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);

  const t = clock.getElapsedTime();

  // Gentle floating rotation
  plumBody.rotation.y = Math.sin(t * 0.3) * 0.15;
  stem.rotation.y = Math.sin(t * 0.3) * 0.15;
  leaf.rotation.z = 0.8 + Math.sin(t * 0.5) * 0.05;
  leaf2.rotation.z = -0.6 + Math.cos(t * 0.4) * 0.05;

  // Gentle up/down bob
  const bob = Math.sin(t * 0.8) * 0.05;
  plumBody.position.y = bob;
  stem.position.y = bob;
  leaf.position.y = 2.1 + bob;
  leaf2.position.y = 2.05 + bob;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
</body>
</html>
```

This creates a **realistic 3D plum** with:

- **Organic shape** — slightly elongated sphere with a characteristic seam/crease running around the side, subtle bumpiness, and flattened bottom
- **Rich coloration** — deep purple base with a red blush on one side, darker bottom, lighter top, and a waxy sheen — all done via a custom GLSL fragment shader
- **Glossy skin** — Fresnel-based highlights and specular-like reflections that respond to the camera angle
- **Stem & leaves** — a curved brown stem with two small green leaves that gently sway
- **Cinematic lighting** — key, fill, rim, and bottom lights with ACES filmic tone mapping
- **Gentle animation** — slow rotation and floating bob
- **Orbit controls** — drag to rotate, scroll to zoom

