  </style>
</head>
<body>
  <div id="info">🏆 Podium 🏆</div>
  <div id="hint">Click &amp; drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene = new THREE.Scene();
    scene.fog = new THREE.FogExp2(0x0a0a1a, 0.018);

    // ── Camera ─────────────────────────────────────────────
    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
    camera.position.set(0, 5, 12);

    // ── Renderer ───────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.06;
    controls.target.set(0, 2, 0);
    controls.maxPolarAngle = Math.PI / 2.05;
    controls.minDistance = 5;
    controls.maxDistance = 25;

    // ── Lights ─────────────────────────────────────────────
    const ambientLight = new THREE.AmbientLight(0x334466, 0.8);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    dirLight.position.set(5, 12, 8);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(2048, 2048);
    dirLight.shadow.camera.near = 1;
    dirLight.shadow.camera.far = 30;
    dirLight.shadow.camera.left = -10;
    dirLight.shadow.camera.right = 10;
    dirLight.shadow.camera.top = 10;
    dirLight.shadow.camera.bottom = -10;
    dirLight.shadow.bias = -0.001;
    scene.add(dirLight);

    const spotGold = new THREE.SpotLight(0xffd700, 40, 15, Math.PI / 6, 0.5);
    spotGold.position.set(0, 9, 2);
    spotGold.target.position.set(0, 3.75, 0);
    scene.add(spotGold);
    scene.add(spotGold.target);

    const rimLight = new THREE.PointLight(0x4488ff, 3, 20);
    rimLight.position.set(-6, 4, -4);
    scene.add(rimLight);

    // ── Materials ──────────────────────────────────────────
    const matGold   = new THREE.MeshStandardMaterial({ color: 0xffd700, metalness: 0.85, roughness: 0.18 });
    const matSilver = new THREE.MeshStandardMaterial({ color: 0xc0c0c0, metalness: 0.9,  roughness: 0.15 });
    const matBronze = new THREE.MeshStandardMaterial({ color: 0xcd7f32, metalness: 0.8,  roughness: 0.22 });
    const matGround = new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 0.9, metalness: 0.1 });
    const matEdge   = new THREE.MeshStandardMaterial({ color: 0xffffff, emissive: 0xffffff, emissiveIntensity: 0.15 });

    // ── Texture helper ─────────────────────────────────────
    function makeNumberTexture(num, color) {
      const canvas = document.createElement('canvas');
      canvas.width = 256; canvas.height = 256;
      const ctx = canvas.getContext('2d');
      ctx.fillStyle = color;
      ctx.fillRect(0, 0, 256, 256);
      ctx.fillStyle = '#111';
      ctx.font = 'bold 160px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(num, 128, 120);
      ctx.font = '28px sans-serif';
      ctx.fillStyle = '#222';
      ctx.fillText(num === '1' ? 'ST' : num === '2' ? 'ND' : 'RD', 128, 180);
      const tex = new THREE.CanvasTexture(canvas);
      tex.colorSpace = THREE.SRGBColorSpace;
      return tex;
    }

    function makeSideTexture(num) {
      const canvas = document.createElement('canvas');
      canvas.width = 512; canvas.height = 512;
      const ctx = canvas.getContext('2d');
      // subtle stripe pattern
      ctx.fillStyle = 'rgba(0,0,0,0.06)';
      for (let i = 0; i < 512; i += 32) ctx.fillRect(i, 0, 16, 512);
      const tex = new THREE.CanvasTexture(canvas);
      return tex;
    }

    // ── Podium builder ─────────────────────────────────────
    const podiumGroup = new THREE.Group();
    scene.add(podiumGroup);

    const podiums = [
      { rank: '2', height: 2.2, x: -2.8, mat: matSilver,  width: 2, depth: 2 },
      { rank: '1', height: 3.8, x: 0,     mat: matGold,   width: 2.2, depth: 2.2 },
      { rank: '3', height: 1.5, x: 2.8,   mat: matBronze, width: 2, depth: 2 },
    ];

    podiums.forEach(p => {
      const group = new THREE.Group();

      // Main block
      const geo = new THREE.BoxGeometry(p.width, p.height, p.depth);
      const faceMat = new THREE.MeshStandardMaterial({
        ...p.mat,
        map: makeNumberTexture(p.rank, p.rank === '1' ? '#ffd700' : p.rank === '2' ? '#c0c0c0' : '#cd7f32')
      });
      const sideMat = new THREE.MeshStandardMaterial({ ...p.mat, map: makeSideTexture(p.rank) });
      const materials = [sideMat, sideMat, sideMat, sideMat, faceMat, p.mat];
      const mesh = new THREE.Mesh(geo, materials);
      mesh.position.y = p.height / 2;
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      group.add(mesh);

      // Top edge glow strip
      const stripGeo = new THREE.BoxGeometry(p.width + 0.08, 0.06, p.depth + 0.08);
      const strip = new THREE.Mesh(stripGeo, matEdge.clone());
      strip.position.y = p.height + 0.03;
      strip.material.emissive = p.rank === '1' ? new THREE.Color(0xffd700) :
                                p.rank === '2' ? new THREE.Color(0xc0c0c0) :
                                                new THREE.Color(0xcd7f32);
      strip.material.emissiveIntensity = 0.4;
      group.add(strip);

      // Steps (subtle)
      const steps = 3;
      for (let s = 0; s < steps; s++) {
        const stepH = 0.12;
        const stepW = p.width + 0.3 + s * 0.15;
        const stepD = p.depth + 0.3 + s * 0.15;
        const stepGeo = new THREE.BoxGeometry(stepW, stepH, stepD);
        const step = new THREE.Mesh(stepGeo, p.mat);
        step.position.y = s * stepH;
        step.castShadow = true;
        step.receiveShadow = true;
        group.add(step);
      }

      group.position.set(p.x, 0, 0);
      podiumGroup.add(group);
    });

    // ── Ground ─────────────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(18, 64);
    const ground = new THREE.Mesh(groundGeo, matGround);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.01;
    ground.receiveShadow = true;
    scene.add(ground);

    // Grid ring on ground
    const ringGeo = new THREE.RingGeometry(5, 5.05, 64);
    const ringMat = new THREE.MeshStandardMaterial({ color: 0x334466, emissive: 0x334466, emissiveIntensity: 0.3, side: THREE.DoubleSide });
    const ring = new THREE.Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = 0.01;
    scene.add(ring);

    // ── Particles ──────────────────────────────────────────
    const particleCount = 300;
    const particleGeo = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    const colors = new Float32Array(particleCount * 3);
    const sizes = new Float32Array(particleCount);

    for (let i = 0; i < particleCount; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 20;
      positions[i * 3 + 1] = Math.random() * 10 + 0.5;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 20;

      const c = new THREE.Color().setHSL(0.1 + Math.random() * 0.15, 0.8, 0.6 + Math.random() * 0.3);
      colors[i * 3] = c.r; colors[i * 3 + 1] = c.g; colors[i * 3 + 2] = c.b;
      sizes[i] = Math.random() * 3 + 1;
    }

    particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    particleGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

    const particleMat = new THREE.PointsMaterial({
      size: 0.06,
      vertexColors: true,
      transparent: true,
      opacity: 0.7,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
    });

    const particles = new THREE.Points(particleGeo, particleMat);
    scene.add(particles);

    // ── Trophy (simple cone + sphere on 1st place) ─────────
    const trophyGroup = new THREE.Group();
    trophyGroup.position.set(0, 3.85, 0);

    // Base
    const tBase = new THREE.Mesh(new THREE.CylinderGeometry(0.3, 0.35, 0.15, 16), matGold);
    tBase.position.y = 0.075;
    tBase.castShadow = true;
    trophyGroup.add(tBase);

    // Stem
    const tStem = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.08, 0.5, 8), matGold);
    tStem.position.y = 0.4;
    tStem.castShadow = true;
    trophyGroup.add(tStem);

    // Cup
    const tCup = new THREE.Mesh(new THREE.CylinderGeometry(0.15, 0.35, 0.5, 16), matGold);
    tCup.position.y = 0.85;
    tCup.castShadow = true;
    trophyGroup.add(tCup);

    // Cup rim
    const tRim = new THREE.Mesh(new THREE.TorusGeometry(0.35, 0.02, 8, 32), matGold);
    tRim.rotation.x = Math.PI / 2;
    tRim.position.y = 1.1;
    trophyGroup.add(tRim);

    // Handles
    [-1, 1].forEach(side => {
      const handleGeo = new THREE.TorusGeometry(0.15, 0.025, 8, 16, Math.PI);
      const handle = new THREE.Mesh(handleGeo, matGold);
      handle.position.set(side * 0.4, 0.9, 0);
      handle.rotation.z = side > 0 ? -Math.PI / 2 : Math.PI / 2;
      handle.castShadow = true;
      trophyGroup.add(handle);
    });

    podiumGroup.add(trophyGroup);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle trophy bob
      trophyGroup.position.y = 3.85 + Math.sin(t * 1.5) * 0.03;
      trophyGroup.rotation.y = Math.sin(t * 0.5) * 0.1;

      // Particle drift
      const pos = particles.geometry.attributes.position.array;
      for (let i = 0; i < particleCount; i++) {
        pos[i * 3 + 1] += Math.sin(t + i) * 0.001;
        if (pos[i * 3 + 1] > 11) pos[i * 3 + 1] = 0.5;
      }
      particles.geometry.attributes.position.needsUpdate = true;

      // Pulse spot light
      spotGold.intensity = 40 + Math.sin(t * 2) * 8;

      // Ring pulse
      ring.material.emissiveIntensity = 0.2 + Math.sin(t * 1.2) * 0.15;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
