<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Noise helpers ---
function hash(x, y, z) {
  let h = (x * 374761393 + y * 668265263 + z * 1274126177) | 0;
  h = Math.imul(h ^ (h >>> 13), 1103515245);
  return ((h ^ (h >>> 16)) & 0x7fffffff) / 0x7fffffff;
}

function noise3D(x, y, z) {
  const ix = Math.floor(x), iy = Math.floor(y), iz = Math.floor(z);
  const fx = x - ix, fy = y - iy, fz = z - iz;
  const ux = fx * fx * (3 - 2 * fx);
  const uy = fy * fy * (3 - 2 * fy);
  const uz = fz * fz * (3 - 2 * fz);

  const a = hash(ix, iy, iz);
  const b = hash(ix + 1, iy, iz);
  const c = hash(ix, iy + 1, iz);
  const d = hash(ix + 1, iy + 1, iz);
  const e = hash(ix, iy, iz + 1);
  const f = hash(ix + 1, iy, iz + 1);
  const g = hash(ix, iy + 1, iz + 1);
  const h = hash(ix + 1, iy + 1, iz + 1);

  return (
    a + (b - a) * ux + (c - a) * uy + (e - a) * uz +
    (a - b - c + d) * ux * uy + (a - b - e + f) * ux * uz +
    (a - c - e + g) * uy * uz +
    (-a + b + c - d + e - f - g + h) * ux * uy * uz
  );
}

function fbm(x, y, z, octaves = 5) {
  let val = 0, amp = 0.5, freq = 1;
  for (let i = 0; i < octaves; i++) {
    val += amp * noise3D(x * freq, y * freq, z * freq);
    amp *= 0.5;
    freq *= 2.1;
  }
  return val;
}

// --- Scene setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.08);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

// --- Potato geometry ---
const baseGeo = new THREE.SphereGeometry(1, 128, 96);
const pos = baseGeo.attributes.position;
const colors = new Float32Array(pos.count * 3);

for (let i = 0; i < pos.count; i++) {
  let x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);

  // Organic displacement
  const n = fbm(x * 1.8, y * 1.8, z * 1.8, 6);
  const n2 = fbm(x * 3.5 + 10, y * 3.5 + 10, z * 3.5 + 10, 4) * 0.3;
  const displacement = 1.0 + n * 0.45 + n2;

  // Elongate slightly
  const scale = new THREE.Vector3(1.25, 0.95, 1.1);
  x *= scale.x; y *= scale.y; z *= scale.z;
  x *= displacement; y *= displacement; z *= displacement;

  pos.setXYZ(i, x, y, z);

  // Vertex colors — earthy potato tones
  const r = 0.55 + n * 0.2 + n2 * 0.1;
  const g = 0.38 + n * 0.12 + n2 * 0.08;
  const b = 0.2 + n * 0.08;
  colors[i * 3] = r;
  colors[i * 3 + 1] = g;
  colors[i * 3 + 2] = b;
}

baseGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
baseGeo.computeVertexNormals();

const potatoMat = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.85,
  metalness: 0.0,
  flatShading: false,
});

const potato = new THREE.Mesh(baseGeo, potatoMat);
potato.rotation.x = -0.2;
scene.add(potato);

// --- Eyes (small dents) ---
const eyePositions = [
  [0.6, 0.3, 0.7], [-0.5, -0.2, 0.85], [0.2, -0.6, 0.8],
  [-0.7, 0.1, -0.6], [0.8, -0.1, -0.3], [-0.3, 0.5, -0.8],
  [0.1, 0.7, 0.4], [-0.6, -0.5, 0.2],
];

eyePositions.forEach(([ex, ey, ez]) => {
  const eyeGeo = new THREE.SphereGeometry(0.06 + Math.random() * 0.04, 12, 12);
  const eyeMat = new THREE.MeshStandardMaterial({
    color: 0x3d2b1f,
    roughness: 1.0,
    metalness: 0.0,
  });
  const eye = new THREE.Mesh(eyeGeo, eyeMat);
  const len = Math.sqrt(ex * ex + ey * ey + ez * ez);
  eye.position.set(ex / len * 1.02, ey / len * 1.02, ez / len * 1.02);
  potato.add(eye);
});

// --- Lighting ---
const ambient = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xfff4e0, 2.5);
key.position.set(4, 6, 3);
scene.add(key);

const fill = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fill.position.set(-3, 2, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffd4a0, 1.2);
rim.position.set(-2, -1, -4);
scene.add(rim);

// Ground shadow hint
const groundGeo = new THREE.PlaneGeometry(20, 20);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e, roughness: 1, metalness: 0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.8;
ground.receiveShadow = true;
scene.add(ground);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  potato.rotation.y = t * 0.3;
  potato.position.y = Math.sin(t * 0.8) * 0.15;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
