const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.maxDistance = 20;
controls.minDistance = 3;

// ── Lights ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
scene.add(dirLight);

const pointLight1 = new THREE.PointLight(0x6366f1, 30, 20);
pointLight1.position.set(-4, 3, 2);
scene.add(pointLight1);

const pointLight2 = new THREE.PointLight(0xec4899, 20, 15);
pointLight2.position.set(4, -2, 3);
scene.add(pointLight2);

// ── Post Card ──
const cardGroup = new THREE.Group();
scene.add(cardGroup);

// Card body
const cardGeo = new RoundedBoxGeometry(4.5, 6, 0.15, 4, 0.15);
const cardMat = new THREE.MeshPhysicalMaterial({
  color: 0x1a1a2e,
  metalness: 0.1,
  roughness: 0.3,
  clearcoat: 0.8,
  clearcoatRoughness: 0.2,
  transparent: true,
  opacity: 0.92,
});
const card = new THREE.Mesh(cardGeo, cardMat);
card.castShadow = true;
card.receiveShadow = true;
cardGroup.add(card);

// Card border glow
const borderGeo = new THREE.EdgesGeometry(cardGeo);
const borderMat = new THREE.LineBasicMaterial({ color: 0x6366f1, transparent: true, opacity: 0.6 });
const border = new THREE.LineSegments(borderGeo, borderMat);
cardGroup.add(border);

// ── Avatar Circle ──
const avatarGeo = new THREE.CircleGeometry(0.55, 32);
const avatarCanvas = document.createElement('canvas');
avatarCanvas.width = 128; avatarCanvas.height = 128;
const actx = avatarCanvas.getContext('2d');
const grad = actx.createLinearGradient(0, 0, 128, 128);
grad.addColorStop(0, '#6366f1');
grad.addColorStop(1, '#ec4899');
actx.fillStyle = grad;
actx.beginPath(); actx.arc(64, 64, 60, 0, Math.PI * 2); actx.fill();
actx.fillStyle = '#fff'; actx.font = 'bold 52px Segoe UI';
actx.textAlign = 'center'; actx.textBaseline = 'middle';
actx.fillText('JD', 64, 64);

const avatarTex = new THREE.CanvasTexture(avatarCanvas);
const avatarMat = new THREE.MeshBasicMaterial({ map: avatarTex, transparent: true });
const avatar = new THREE.Mesh(avatarGeo, avatarMat);
avatar.position.set(-1.5, 2.2, 0.1);
cardGroup.add(avatar);

// ── Username Bar ──
const nameBarGeo = new RoundedBoxGeometry(1.8, 0.35, 0.05, 2, 0.08);
const nameBarMat = new THREE.MeshBasicMaterial({ color: 0x6366f1, transparent: true, opacity: 0.3 });
const nameBar = new THREE.Mesh(nameBarGeo, nameBarMat);
nameBar.position.set(-1.5, 1.55, 0.1);
cardGroup.add(nameBar);

// ── Text Lines ──
const lineData = [
  { y: 1.0, w: 3.8, color: 0xffffff, opacity: 0.85 },
  { y: 0.65, w: 3.5, color: 0xffffff, opacity: 0.7 },
  { y: 0.3, w: 4.0, color: 0xffffff, opacity: 0.6 },
  { y: -0.05, w: 3.2, color: 0xffffff, opacity: 0.5 },
  { y: -0.4, w: 2.8, color: 0xffffff, opacity: 0.4 },
];
lineData.forEach(l => {
  const geo = new RoundedBoxGeometry(l.w, 0.12, 0.05, 2, 0.04);
  const mat = new THREE.MeshBasicMaterial({ color: l.color, transparent: true, opacity: l.opacity });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(0.2, l.y, 0.1);
  cardGroup.add(mesh);
});

// ── Image Placeholder ──
const imgGeo = new RoundedBoxGeometry(3.8, 2.2, 0.08, 4, 0.1);
const imgCanvas = document.createElement('canvas');
imgCanvas.width = 512; imgCanvas.height = 256;
const ictx = imgCanvas.getContext('2d');
const imgGrad = ictx.createLinearGradient(0, 0, 512, 256);
imgGrad.addColorStop(0, '#1e1b4b');
imgGrad.addColorStop(0.5, '#312e81');
imgGrad.addColorStop(1, '#4c1d95');
ictx.fillStyle = imgGrad;
ictx.fillRect(0, 0, 512, 256);
// Decorative circles
for (let i = 0; i < 5; i++) {
  ictx.beginPath();
  ictx.arc(100 + i * 90, 128 + Math.sin(i) * 40, 30 + i * 10, 0, Math.PI * 2);
  ictx.fillStyle = `rgba(99,102,241,${0.15 + i * 0.05})`;
  ictx.fill();
}
const imgTex = new THREE.CanvasTexture(imgCanvas);
const imgMat = new THREE.MeshBasicMaterial({ map: imgTex });
const imgMesh = new THREE.Mesh(imgGeo, imgMat);
imgMesh.position.set(0.2, -1.3, 0.1);
cardGroup.add(imgMesh);

// ── Interaction Buttons ──
const btnData = [
  { x: -1.2, label: '♥', color: 0xec4899 },
  { x: -0.3, label: '💬', color: 0x6366f1 },
  { x: 0.6, label: '↗', color: 0x14b8a6 },
];
btnData.forEach(b => {
  const g = new RoundedBoxGeometry(0.8, 0.4, 0.05, 2, 0.08);
  const m = new THREE.MeshBasicMaterial({ color: b.color, transparent: true, opacity: 0.2 });
  const mesh = new THREE.Mesh(g, m);
  mesh.position.set(b.x, -2.6, 0.1);
  cardGroup.add(mesh);
});

// ── Floating Particles ──
const particleCount = 300;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const colors = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 30;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20 - 5;
  const c = new THREE.Color().setHSL(0.7 + Math.random() * 0.2, 0.8, 0.6);
  colors[i * 3] = c.r;
  colors[i * 3 + 1] = c.g;
  colors[i * 3 + 2] = c.b;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));

const particleMat = new THREE.PointsMaterial({
  size: 0.06,
  vertexColors: true,
  transparent: true,
  opacity: 0.7,
  blending: THREE.AdditiveBlending,
  depthWrite: false,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Floating Rings ──
for (let i = 0; i < 3; i++) {
  const ringGeo = new THREE.TorusGeometry(3 + i * 0.8, 0.02, 8, 64);
  const ringMat = new THREE.MeshBasicMaterial({
    color: new THREE.Color().setHSL(0.7 + i * 0.1, 0.7, 0.5),
    transparent: true,
    opacity: 0.15,
  });
  const ring = new THREE.Mesh(ringGeo, ringMat);
  ring.position.z = -3 - i * 1.5;
  ring.userData.rotSpeed = 0.2 + i * 0.1;
  ring.userData.tilt = (Math.random() - 0.5) * 0.5;
  scene.add(ring);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Card gentle float
  cardGroup.position.y = Math.sin(t * 0.8) * 0.15;
  cardGroup.rotation.y = Math.sin(t * 0.3) * 0.05;
  cardGroup.rotation.x = Math.sin(t * 0.5) * 0.02;

  // Particles drift
  const pos = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pos[i * 3 + 1] += Math.sin(t + i) * 0.001;
  }
  particles.geometry.attributes.position.needsUpdate = true;
  particles.rotation.y = t * 0.02;

  // Rings rotate
  scene.children.forEach(child => {
    if (child.userData.rotSpeed) {
      child.rotation.x = child.userData.tilt + Math.sin(t * child.userData.rotSpeed) * 0.3;
      child.rotation.z = Math.cos(t * child.userData.rotSpeed * 0.7) * 0.2;
    }
  });

  // Lights pulse
  pointLight1.intensity = 30 + Math.sin(t * 2) * 5;
  pointLight2.intensity = 20 + Math.cos(t * 1.5) * 5;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates an immersive 3D visualization of a social media post card featuring:

- **3D Post Card** — A glassmorphic rounded card with avatar, username bar, text lines, an image placeholder, and action buttons (like, comment, share)
- **Floating Particles** — 300 color-shifting particles with additive blending drifting in the background
- **Orbital Rings** — Three translucent torus rings slowly rotating behind the card
- **Dynamic Lighting** — Pulsing purple and pink point lights with a directional light casting shadows
- **Gentle Animation** — The card floats and sways; everything breathes and moves
- **Orbit Controls** — Drag to rotate, scroll to zoom

