    pyramid.rotation.y = Math.PI / 4;          // align square base to axes
    pyramid.castShadow = true;
    pyramid.receiveShadow = true;
    scene.add(pyramid);

    // ── Wireframe overlay ──────────────────────────
    const wireGeo = new THREE.EdgesGeometry(pyramidGeo);
    const wireMat = new THREE.LineBasicMaterial({ color: 0xffd97a, linewidth: 1 });
    const wireframe = new THREE.LineSegments(wireGeo, wireMat);
    wireframe.rotation.copy(pyramid.rotation);
    pyramid.add(wireframe);

    // ── Base platform ──────────────────────────────
    const platGeo = new THREE.BoxGeometry(6, 0.15, 6);
