      pyramid.rotation.y = Math.PI / 4 + Math.sin(t * 0.5) * 0.3;
      pyramid.position.y = Math.sin(t * 0.8) * 0.15;

      controls.update();
      renderer.render(scene, camera);
    })();
  </script>
