// ─── Chain (series of small links) ───
const chainGroup = new THREE.Group();
const linkMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.3, metalness: 0.9 });
const linkCount = 8;
const linkLen = 0.28;

for (let i = 0; i < linkCount; i++) {
  const link = new THREE.Mesh(
    new THREE.TorusGeometry(0.06, 0.02, 8, 12),
    linkMat
  );
  link.position.y = 4.35 - i * linkLen;
  link.rotation.x = (i % 2) * Math.PI / 2;
  link.castShadow = true;
  chainGroup.add(link);
}
chainGroup.position.y = 0;
scene.add(chainGroup);

// ─── Punching Bag Body ───
const bagPivot = new THREE.Group();
bagPivot.position.set(0, 4.35 - linkCount * linkLen, 0);
scene.add(bagPivot);

// Main body - cylinder
const bodyGeo = new THREE.CylinderGeometry(0.55, 0.5, 2.0, 24, 1, true);
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0x8b1a1a,
  roughness: 0.65,
  metalness: 0.05,
  side: THREE.DoubleSide
});
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.y = -1.0;
body.castShadow = true;
bagPivot.add(body);

// Top cap
const topCap = new THREE.Mesh(
  new THREE.SphereGeometry(0.55, 24, 12, 0, Math.PI * 2, 0, Math.PI / 2),
  bodyMat
);
topCap.position.y = 0;
topCap.castShadow = true;
bagPivot.add(topCap);

// Bottom cap
const bottomCap = new THREE.Mesh(
  new THREE.SphereGeometry(0.5, 24, 12, 0, Math.PI * 2, 0, Math.PI / 2),
  bodyMat
);
bottomCap.rotation.x = Math.PI;
bottomCap.position.y = -2.0;
bottomCap.castShadow = true;
bagPivot.add(bottomCap);

// Stitching lines
const stitchMat = new THREE.MeshStandardMaterial({ color: 0xcccccc, roughness: 0.8 });
for (let i = 0; i < 2; i++) {
  const ring = new THREE.Mesh(
    new THREE.TorusGeometry(0.54 + i * 0.02, 0.008, 6, 32),
    stitchMat
  );
  ring.position.y = 0.1 - i * 0.15;
  ring.rotation.x = Math.PI / 2;
  bagPivot.add(ring);
}

// Bottom ring (metal)
const bottomRing = new THREE.Mesh(
  new THREE.TorusGeometry(0.49, 0.025, 8, 24),
  new THREE.MeshStandardMaterial({ color: 0x999999, roughness: 0.3, metalness: 0.9 })
);
bottomRing.position.y = -2.0;
bottomRing.rotation.x = Math.PI / 2;
bagPivot.add(bottomRing);

// ─── Shadow blob on floor ───
const shadowBlob = new THREE.Mesh(
  new THREE.CircleGeometry(0.8, 24),
  new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.35 })
);
shadowBlob.rotation.x = -Math.PI / 2;
shadowBlob.position.y = 0.01;
scene.add(shadowBlob);

// ─── Pendulum Physics ───
let angle = 0;
let angularVel = 0;
const damping = 0.985;
const gravity = 12;
const chainLength = linkCount * linkLen;

// ─── Raycaster for interaction ───
const raycaster = new THREE.Raycaster();
const mouse = new THREE.Vector2();

function punch(force) {
  angularVel += force;
}

renderer.domElement.addEventListener('pointerdown', (e) => {
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);

  // Check if we hit the bag
  const bagMeshes = [body, topCap, bottomCap];
  const hits = raycaster.intersectObjects(bagMeshes);

  if (hits.length > 0) {
    const hitPoint = hits[0].point;
    // Punch direction: away from the hit point, roughly toward camera
    const dir = new THREE.Vector3().subVectors(camera.position, hitPoint).normalize();
    // Add some horizontal force based on hit position
    const hitLocal = bagPivot.worldToLocal(hitPoint.clone());
    const punchForce = 4 + Math.random() * 3;

    // Angle the punch based on where we hit
    const offset = hitLocal.x * 2;
    angularVel += (punchForce + offset) * (Math.random() > 0.5 ? 1 : -0.7);
    angularVel += dir.z * 2;

    // Visual feedback - brief flash
    bodyMat.emissive.set(0x441111);
    setTimeout(() => bodyMat.emissive.set(0x000000), 100);
  } else {
    // Click anywhere else gives a small random nudge
    angularVel += (Math.random() - 0.5) * 2;
  }
});

// ─── Resize ───
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// ─── Animate ───
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const dt = Math.min(clock.getDelta(), 0.05);

  // Pendulum: angularAccel = -(g/L) * sin(angle)
  const angularAccel = -(gravity / chainLength) * Math.sin(angle);
  angularVel += angularAccel * dt;
  angularVel *= damping;
  angle += angularVel * dt;

  bagPivot.rotation.z = angle;
  chainGroup.rotation.z = angle;

  // Shadow follows bag bottom
  const bagBottom = new THREE.Vector3(0, -2.0, 0);
  bagBottom.applyMatrix4(bagPivot.matrixWorld);
  shadowBlob.position.x = bagBottom.x;
  shadowBlob.position.z = bagBottom.z;
  const distFromCenter = Math.sqrt(bagBottom.x ** 2 + bagBottom.z ** 2);
  shadowBlob.scale.set(1 + distFromCenter * 0.3, 1 + distFromCenter * 0.3, 1);
  shadowBlob.material.opacity = 0.35 - distFromCenter * 0.05;

  // Subtle camera sway
  camera.position.x = Math.sin(Date.now() * 0.0003) * 0.3;
  camera.lookAt(0, 1.5, 0);

  renderer.render(scene, camera);
}

animate();
</script>
</body>
</html>
```

## What's included

| Feature | Details |
|---|---|
| **Bag geometry** | Cylinder body + hemispherical caps + metal bottom ring + stitching lines |
| **Chain** | 8 alternating torus links with metallic material |
| **Pendulum physics** | Real `θ'' = -(g/L)sin(θ)` integration with damping — the bag naturally swings and settles |
| **Click to punch** | Raycaster detects hits on the bag; punch force depends on hit position, with a brief red emissive flash |
| **Lighting** | Key light (warm), rim light (blue), bottom fill (orange), ambient — ACES filmic tone mapping |
| **Shadows** | PCF soft shadow map from the directional light + a dynamic shadow blob on the floor that tracks the bag |
| **Atmosphere** | Dark navy background, exponential fog, subtle camera sway |

Open the file in any modern browser — no build step needed. Click the bag to punch it, then watch it swing!

