</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);
scene.fog = new THREE.FogExp2(0x0a0a12, 0.035);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1.5, 0);
controls.maxPolarAngle = Math.PI / 2 + 0.2;

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x221100, 0.5);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x4466aa, 0.3);
fillLight.position.set(-3, 2, -3);
scene.add(fillLight);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(15, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a10,
  roughness: 0.95,
  metalness: 0.0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// --- Pumpkin Body ---
const pumpkinGroup = new THREE.Group();
scene.add(pumpkinGroup);

function createPumpkinGeometry() {
  const geo = new THREE.SphereGeometry(1.8, 128, 96);
  const pos = geo.attributes.position;

  for (let i = 0; i < pos.count; i++) {
    let x = pos.getX(i);
    let y = pos.getY(i);
    let z = pos.getZ(i);

    // Flatten top and bottom
    const yFactor = 0.75;
    y *= yFactor;

    // Create vertical ridges
    const angle = Math.atan2(z, x);
    const ridgeSegments = 8;
    const ridgeDepth = 0.12;
    const ridge = Math.cos(angle * ridgeSegments);
    const ridgeDisplacement = ridge * ridgeDepth;

    // Only apply ridges to the main body (not extreme poles)
    const absY = Math.abs(y);
    const ridgeFade = Math.max(0, 1 - absY / 1.4);
    const displacedRadius = Math.sqrt(x * x + z * z) + ridgeDisplacement * ridgeFade;

    const len = Math.sqrt(x * x + z * z);
    if (len > 0.001) {
      x = (x / len) * displacedRadius;
      z = (z / len) * displacedRadius;
    }

    // Slight bulge in the middle
    const bulge = 1 + 0.08 * Math.cos(y / 1.35 * Math.PI);
    x *= bulge;
    z *= bulge;

    pos.setXYZ(i, x, y, z);
  }

  geo.computeVertexNormals();
  return geo;
}

const pumpkinMat = new THREE.MeshStandardMaterial({
  color: 0xd4651a,
  roughness: 0.7,
  metalness: 0.0,
  flatShading: false
});

// Add slight color variation via vertex colors
const pumpkinGeo = createPumpkinGeometry();
const colors = new Float32Array(pumpkinGeo.attributes.position.count * 3);
const pPos = pumpkinGeo.attributes.position;
for (let i = 0; i < pPos.count; i++) {
  const y = pPos.getY(i);
  const variation = (Math.random() - 0.5) * 0.04;
  const r = 0.83 + variation + (y > 0.5 ? 0.05 : 0);
  const g = 0.39 + variation;
  const b = 0.10 + variation;
  colors[i * 3] = r;
  colors[i * 3 + 1] = g;
  colors[i * 3 + 2] = b;
}
pumpkinGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
pumpkinMat.vertexColors = true;

const pumpkin = new THREE.Mesh(pumpkinGeo, pumpkinMat);
pumpkin.castShadow = true;
pumpkin.receiveShadow = true;
pumpkinGroup.add(pumpkin);

// --- Stem ---
function createStemGeometry() {
  const points = [];
  const segments = 20;
  for (let i = 0; i <= segments; i++) {
    const t = i / segments;
    const y = t * 1.0;
    const radius = 0.18 * (1 - t * 0.6) + 0.02 * Math.sin(t * Math.PI * 3);
    points.push(new THREE.Vector2(radius, y));
  }
  return new THREE.LatheGeometry(points, 12);
}

const stemGeo = createStemGeometry();
// Shift stem up so base sits on pumpkin
const stemPos = stemGeo.attributes.position;
for (let i = 0; i < stemPos.count; i++) {
  stemPos.setY(i, stemPos.getY(i) + 1.25);
}
stemGeo.computeVertexNormals();

const stemMat = new THREE.MeshStandardMaterial({
  color: 0x2d5a1e,
  roughness: 0.85,
  metalness: 0.0
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
pumpkinGroup.add(stem);

// --- Stem leaf ---
const leafShape = new THREE.Shape();
leafShape.moveTo(0, 0);
leafShape.quadraticCurveTo(0.3, 0.2, 0.5, 0.05);
leafShape.quadraticCurveTo(0.3, -0.05, 0, 0);

const leafGeo = new THREE.ShapeGeometry(leafShape);
const leafMat = new THREE.MeshStandardMaterial({
  color: 0x3a7a28,
  roughness: 0.8,
  side: THREE.DoubleSide
});
const leaf = new THREE.Mesh(leafGeo, leafMat);
leaf.position.set(0.15, 1.75, 0);
leaf.rotation.set(-0.3, 0.5, 0.8);
leaf.castShadow = true;
pumpkinGroup.add(leaf);

// --- Carved Face ---
const faceGroup = new THREE.Group();
pumpkinGroup.add(faceGroup);

// Glowing material for face cutouts
const glowMat = new THREE.MeshBasicMaterial({
  color: 0xff8800,
  transparent: true,
  opacity: 0.95
});

const glowMatBright = new THREE.MeshBasicMaterial({
  color: 0xffcc44,
  transparent: true,
  opacity: 0.9
});

function createEye(x, y, z, rotationZ) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.lineTo(-0.25, -0.35);
  shape.lineTo(0.25, -0.35);
  shape.closePath();

  const geo = new THREE.ShapeGeometry(shape);
  const mesh = new THREE.Mesh(geo, glowMat);
  mesh.position.set(x, y, z);
  mesh.rotation.z = rotationZ;
  return mesh;
}

// Eyes
faceGroup.add(createEye(-0.55, 0.5, 1.65, 0));
faceGroup.add(createEye(0.55, 0.5, 1.65, 0));

// Nose
const noseShape = new THREE.Shape();
noseShape.moveTo(0, 0);
noseShape.lineTo(-0.12, -0.22);
noseShape.lineTo(0.12, -0.22);
noseShape.closePath();
const noseGeo = new THREE.ShapeGeometry(noseShape);
const nose = new THREE.Mesh(noseGeo, glowMat);
nose.position.set(0, 0.15, 1.72);
faceGroup.add(nose);

// Mouth - jagged grin
function createMouth() {
  const shape = new THREE.Shape();
  const teeth = 6;
  const width = 0.9;
  const startX = -width;

  // Bottom edge with teeth
  shape.moveTo(startX, 0);
  shape.lineTo(startX, -0.15);

  for (let i = 0; i < teeth; i++) {
    const x1 = startX + (width / teeth) * (i * 2);
    const x2 = startX + (width / teeth) * (i * 2 + 1);
    const x3 = startX + (width / teeth) * (i * 2 + 1.5);
    const x4 = startX + (width / teeth) * (i * 2 + 2);

    shape.lineTo(x1, -0.15);
    shape.lineTo(x2, 0.0);
    shape.lineTo(x3, -0.15);
    shape.lineTo(x4, -0.15);
  }

  // Bottom curve
  shape.quadraticCurveTo(0, -0.4, startX, -0.15);
  shape.closePath();

  const geo = new THREE.ShapeGeometry(shape);
  const mesh = new THREE.Mesh(geo, glowMatBright);
  mesh.position.set(0, -0.1, 1.65);
  return mesh;
}

faceGroup.add(createMouth());

// Inner glow light
const innerLight = new THREE.PointLight(0xff6600, 3, 8);
innerLight.position.set(0, 0.3, 0.5);
pumpkinGroup.add(innerLight);

const innerLight2 = new THREE.PointLight(0xff4400, 1.5, 5);
innerLight2.position.set(0, -0.2, 0.3);
pumpkinGroup.add(innerLight2);

// --- Particles (floating embers) ---
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
const particleSpeeds = [];

for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3] = (Math.random() - 0.5) * 6;
  particlePositions[i * 3 + 1] = Math.random() * 6;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 6;
  particleSpeeds.push(0.002 + Math.random() * 0.008);
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));

const particleMat = new THREE.PointsMaterial({
  color: 0xff8833,
  size: 0.04,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle pumpkin bob
  pumpkinGroup.position.y = Math.sin(t * 0.8) * 0.05;

  // Flickering inner light
  const flicker = Math.sin(t * 8) * 0.15 + Math.sin(t * 13) * 0.1 + Math.sin(t * 21) * 0.05;
  innerLight.intensity = 3 + flicker * 2;
  innerLight2.intensity = 1.5 + flicker;

  // Glow material flicker
  glowMat.opacity = 0.85 + flicker * 0.1;
  glowMatBright.opacity = 0.8 + flicker * 0.1;

  // Animate particles
  const pPos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    let y = pPos.getY(i);
    y += particleSpeeds[i];
    if (y > 6) y = -0.5;
    pPos.setY(i, y);
    pPos.setX(i, pPos.getX(i) + Math.sin(t + i) * 0.001);
  }
  pPos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
