<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Quilt</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

// --- Scene setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0.5, 5);
camera.lookAt(0, 0, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

// --- Lighting ---
const ambient = new THREE.AmbientLight(0xfff5e6, 0.6);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffffff, 1.2);
dirLight.position.set(3, 5, 4);
dirLight.castShadow = true;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x8888ff, 0.4);
rimLight.position.set(-3, 2, -2);
scene.add(rimLight);

// --- Quilt texture (procedural patchwork) ---
const canvas = document.createElement('canvas');
const SIZE = 512;
const GRID = 8;
const CELL = SIZE / GRID;
canvas.width = canvas.height = SIZE;
const ctx = canvas.getContext('2d');

const palette = [
  '#c0392b', '#e74c3c', '#f39c12', '#f1c40f',
  '#27ae60', '#2980b9', '#8e44ad', '#d35400',
  '#1abc9c', '#e91e63', '#ff5722', '#4caf50',
  '#3f51b5', '#00bcd4', '#ff9800', '#795548',
  '#607d8b', '#9c27b0', '#009688', '#ffc107',
];

// Draw patchwork squares with slight variations
for (let row = 0; row < GRID; row++) {
  for (let col = 0; col < GRID; col++) {
    const x = col * CELL;
    const y = row * CELL;
    const colorIdx = (row * GRID + col) % palette.length;
    const baseColor = palette[colorIdx];

    // Patch fill
    ctx.fillStyle = baseColor;
    ctx.fillRect(x + 1, y + 1, CELL - 2, CELL - 2);

    // Subtle inner pattern - alternating half squares
    if ((row + col) % 2 === 0) {
      ctx.fillStyle = 'rgba(0,0,0,0.08)';
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + CELL, y);
      ctx.lineTo(x + CELL, y + CELL);
      ctx.closePath();
      ctx.fill();
    }

    // Small diamond center
    ctx.save();
    ctx.translate(x + CELL / 2, y + CELL / 2);
    ctx.rotate(Math.PI / 4);
    ctx.fillStyle = 'rgba(255,255,255,0.12)';
    const d = CELL * 0.18;
    ctx.fillRect(-d, -d, d * 2, d * 2);
    ctx.restore();

    // Stitching lines (cross-stitch effect)
    ctx.strokeStyle = 'rgba(255,255,255,0.25)';
    ctx.lineWidth = 0.5;
    ctx.setLineDash([2, 2]);
    ctx.beginPath();
    ctx.moveTo(x + CELL * 0.3, y + CELL * 0.3);
    ctx.lineTo(x + CELL * 0.7, y + CELL * 0.7);
    ctx.moveTo(x + CELL * 0.7, y + CELL * 0.3);
    ctx.lineTo(x + CELL * 0.3, y + CELL * 0.7);
    ctx.stroke();
    ctx.setLineDash([]);
  }
}

// Binding border
ctx.strokeStyle = '#2c1810';
ctx.lineWidth = 6;
ctx.strokeRect(3, 3, SIZE - 6, SIZE - 6);
ctx.strokeStyle = '#4a2c1a';
ctx.lineWidth = 2;
ctx.strokeRect(8, 8, SIZE - 16, SIZE - 16);

// Stitching grid overlay
ctx.strokeStyle = 'rgba(255,255,255,0.15)';
ctx.lineWidth = 1;
for (let i = 0; i <= GRID; i++) {
  ctx.beginPath();
  ctx.moveTo(i * CELL, 0);
  ctx.lineTo(i * CELL, SIZE);
  ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(0, i * CELL);
  ctx.lineTo(SIZE, i * CELL);
  ctx.stroke();
}

const texture = new THREE.CanvasTexture(canvas);
texture.colorSpace = THREE.SRGBColorSpace;

// --- Quilt geometry with cloth drape ---
const W = 4, H = 4;
const SEGMENTS = 64;
const geo = new THREE.PlaneGeometry(W, H, SEGMENTS, SEGMENTS);

// Apply gentle drape / wave to vertices
const pos = geo.attributes.position;
for (let i = 0; i < pos.count; i++) {
  const x = pos.getX(i);
  const y = pos.getY(i);
  // Subtle sinusoidal drape - heavier at bottom corners
  const drapeX = Math.sin(x * 1.8) * 0.06;
  const drapeY = Math.sin(y * 1.5 + 0.5) * 0.05;
  const sag = (1 - y / (H / 2)) * 0.12; // more sag at bottom
  pos.setZ(i, drapeX + drapeY - sag * (Math.abs(x) / (W / 2)));
}
geo.computeVertexNormals();

const mat = new THREE.MeshStandardMaterial({
  map: texture,
  roughness: 0.85,
  metalness: 0.0,
  side: THREE.DoubleSide,
  bumpMap: texture,
  bumpScale: 0.005,
});

const quilt = new THREE.Mesh(geo, mat);
quilt.castShadow = true;
quilt.receiveShadow = true;
scene.add(quilt);

// --- Hanging rod ---
const rodGeo = new THREE.CylinderGeometry(0.03, 0.03, W + 0.6, 12);
const rodMat = new THREE.MeshStandardMaterial({ color: 0x8B7355, roughness: 0.4, metalness: 0.3 });
const rod = new THREE.Mesh(rodGeo, rodMat);
rod.rotation.z = Math.PI / 2;
rod.position.y = H / 2 + 0.05;
rod.castShadow = true;
scene.add(rod);

// Rod end caps
const capGeo = new THREE.SphereGeometry(0.05, 12, 12);
const capMat = new THREE.MeshStandardMaterial({ color: 0xDAA520, roughness: 0.3, metalness: 0.6 });
for (const x of [-(W / 2 + 0.25), W / 2 + 0.25]) {
  const cap = new THREE.Mesh(capGeo, capMat);
  cap.position.set(x, H / 2 + 0.05, 0);
  scene.add(cap);
}

// --- Subtle animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle swaying
  quilt.rotation.z = Math.sin(t * 0.5) * 0.015;
  quilt.rotation.x = Math.sin(t * 0.3 + 1) * 0.01;

  // Subtle vertex animation for cloth feel
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const baseZ = Math.sin(x * 1.8) * 0.06 + Math.sin(y * 1.5 + 0.5) * 0.05;
    const sag = (1 - y / (H / 2)) * 0.12 * (Math.abs(x) / (W / 2));
    const wave = Math.sin(t * 1.2 + x * 2) * 0.015 + Math.sin(t * 0.8 + y * 1.8) * 0.01;
    pos.setZ(i, baseZ - sag + wave);
  }
  pos.needsUpdate = true;
  geo.computeVertexNormals();

  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this creates:**

- **Procedural patchwork texture** — 8×8 grid of colored squares with half-square diagonal shading, diamond accents, cross-stitch marks, and a stitched binding border
- **Cloth drape physics** — vertices are displaced with sine waves and a bottom-heavy sag to simulate hanging fabric
- **Gentle animation** — the quilt sways slightly and ripples like cloth in a breeze
- **Hanging rod** — a wooden dowel with brass end caps at the top
- **Warm lighting** — ambient + directional + rim light with soft shadows

