This single HTML file creates a **fully interactive 3D rabbit scene** featuring:

- **Rabbit model** built from primitives — body, head, cheeks, long ears (with pink inner), eyes with shine, nose, mouth, whiskers, front/hind legs, paws, and a fluffy cotton tail
- **Environment** — green ground with grass tufts, colorful flowers, sky-blue background with fog
- **Lighting** — warm directional sunlight with soft shadows, fill light, and ambient light
- **Animation** — gentle breathing, head bobbing, and tail wagging
- **OrbitControls** — click and drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Racket</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 50);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1.5, 0);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 10, 7);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 1.2);
rimLight.position.set(-5, 3, -5);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xff6644, 1, 20);
pointLight.position.set(3, 5, 3);
scene.add(pointLight);

// ── Racket Group ──
const racket = new THREE.Group();

// Materials
const frameMat = new THREE.MeshStandardMaterial({
  color: 0xcc2233,
  metalness: 0.6,
  roughness: 0.3,
});

const gripMat = new THREE.MeshStandardMaterial({
  color: 0x222222,
  metalness: 0.1,
  roughness: 0.9,
});

const stringMat = new THREE.MeshStandardMaterial({
  color: 0xeeeeee,
  metalness: 0.0,
  roughness: 0.8,
  transparent: true,
  opacity: 0.7,
});

// ── Handle ──
const handleGeo = new THREE.CylinderGeometry(0.06, 0.08, 2.2, 16);
const handle = new THREE.Mesh(handleGeo, frameMat);
handle.position.y = -1.1;
handle.castShadow = true;
racket.add(handle);

// Grip (textured look via segments)
const gripGeo = new THREE.CylinderGeometry(0.075, 0.07, 1.4, 16);
const grip = new THREE.Mesh(gripGeo, gripMat);
grip.position.y = -1.7;
grip.castShadow = true;
racket.add(grip);

// Grip tape wraps
for (let i = 0; i < 8; i++) {
  const wrapGeo = new THREE.TorusGeometry(0.078, 0.008, 8, 24);
  const wrap = new THREE.Mesh(wrapGeo, new THREE.MeshStandardMaterial({
    color: 0x333333, roughness: 0.9, metalness: 0.1
  }));
  wrap.position.y = -1.3 - i * 0.12;
  wrap.rotation.x = Math.PI / 2;
  racket.add(wrap);
}

// Handle cap (bottom)
const capGeo = new THREE.SphereGeometry(0.082, 16, 8, 0, Math.PI * 2, 0, Math.PI / 2);
const cap = new THREE.Mesh(capGeo, gripMat);
cap.position.y = -2.4;
cap.rotation.x = Math.PI;
racket.add(cap);

// ── Throat (curved connectors) ──
const throatCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-0.08, -0.2, 0),
  new THREE.Vector3(-0.25, 0.1, 0),
  new THREE.Vector3(-0.45, 0.5, 0),
]);

const throatGeoL = new THREE.TubeGeometry(throatCurve, 20, 0.035, 12, false);
const throatL = new THREE.Mesh(throatGeoL, frameMat);
throatL.castShadow = true;
racket.add(throatL);

const throatCurveR = throatCurve.clone();
throatCurveR.points = throatCurve.points.map(p => new THREE.Vector3(-p.x, p.y, p.z));
const throatGeoR = new THREE.TubeGeometry(throatCurveR, 20, 0.035, 12, false);
const throatR = new THREE.Mesh(throatGeoR, frameMat);
throatR.castShadow = true;
racket.add(throatR);

// ── Racket Head (oval frame) ──
const headPoints = [];
const headRx = 0.85;
const headRy = 1.1;
const segments = 64;
for (let i = 0; i <= segments; i++) {
  const theta = (i / segments) * Math.PI * 2;
  headPoints.push(new THREE.Vector3(
    Math.cos(theta) * headRx,
    Math.sin(theta) * headRy + 0.8,
    0
  ));
}

const headCurve = new THREE.CatmullRomCurve3(headPoints, true);
const headGeo = new THREE.TubeGeometry(headCurve, 128, 0.035, 12, true);
const head = new THREE.Mesh(headGeo, frameMat);
head.castShadow = true;
racket.add(head);

// ── Strings ──
const stringGroup = new THREE.Group();
stringGroup.position.y = 0.8;

// Vertical strings
const vCount = 18;
for (let i = 0; i < vCount; i++) {
  const xOff = (i - (vCount - 1) / 2) * (headRx * 1.7 / vCount);
  const yExtent = Math.sqrt(Math.max(0, 1 - (xOff / headRx) ** 2)) * headRy;

  const points = [];
  const steps = 20;
  for (let j = 0; j <= steps; j++) {
    const t = j / steps;
    const y = -yExtent + t * yExtent * 2;
    const xNorm = xOff / headRx;
    const yNorm = y / headRy;
    const dist = Math.sqrt(xNorm * xNorm + yNorm * yNorm);
    const z = dist > 0.95 ? -0.02 : (dist - 0.5) * 0.01;
    points.push(new THREE.Vector3(xOff, y, z));
  }

  const curve = new THREE.CatmullRomCurve3(points);
  const geo = new THREE.TubeGeometry(curve, steps, 0.004, 6, false);
  const mesh = new THREE.Mesh(geo, stringMat);
  stringGroup.add(mesh);
}

// Horizontal strings
const hCount = 22;
for (let i = 0; i < hCount; i++) {
  const yOff = (i - (hCount - 1) / 2) * (headRy * 1.7 / hCount);
  const xExtent = Math.sqrt(Math.max(0, 1 - (yOff / headRy) ** 2)) * headRx;

  const points = [];
  const steps = 20;
  for (let j = 0; j <= steps; j++) {
    const t = j / steps;
    const x = -xExtent + t * xExtent * 2;
    const xNorm = x / headRx;
    const yNorm = yOff / headRy;
    const dist = Math.sqrt(xNorm * xNorm + yNorm * yNorm);
    const z = dist > 0.95 ? -0.02 : (dist - 0.5) * 0.01;
    points.push(new THREE.Vector3(x, yOff, z));
  }

  const curve = new THREE.CatmullRomCurve3(points);
  const geo = new THREE.TubeGeometry(curve, steps, 0.004, 6, false);
  const mesh = new THREE.Mesh(geo, stringMat);
  stringGroup.add(mesh);
}

racket.add(stringGroup);

// ── Logo on head ──
const logoGeo = new THREE.CircleGeometry(0.12, 32);
const logoMat = new THREE.MeshStandardMaterial({
  color: 0xffcc00, metalness: 0.8, roughness: 0.2, side: THREE.DoubleSide
});
const logo = new THREE.Mesh(logoGeo, logoMat);
logo.position.set(0, 0.8, 0.04);
racket.add(logo);

// ── Position & Tilt Racket ──
racket.rotation.z = -0.15;
racket.rotation.x = 0.1;
scene.add(racket);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x111122, metalness: 0.3, roughness: 0.8
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -3;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  racket.rotation.y = Math.sin(t * 0.5) * 0.3;
  racket.position.y = Math.sin(t * 0.8) * 0.15;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
