  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Ramp Visualization</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
    #info {
      position: absolute; top: 12px; left: 50%; transform: translateX(-50%);
      color: #fff; font-family: system-ui, sans-serif; font-size: 14px;
      background: rgba(0,0,0,0.55); padding: 8px 18px; border-radius: 8px;
      pointer-events: none; user-select: none;
    }
  </style>
</head>
<body>
  <div id="info">Drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.Fog(0x1a1a2e, 40, 80);

    // ── Camera ─────────────────────────────────────────────
    const camera = new THREE.PerspectiveCamera(
      50, window.innerWidth / window.innerHeight, 0.1, 200
    );
    camera.position.set(8, 6, 10);

    // ── Renderer ───────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.target.set(3, 1.5, 0);

    // ── Lighting ───────────────────────────────────────────
    const ambient = new THREE.AmbientLight(0x8888bb, 0.6);
    scene.add(ambient);

    const dirLight = new THREE.DirectionalLight(0xffeedd, 1.8);
    dirLight.position.set(10, 15, 10);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(2048, 2048);
    dirLight.shadow.camera.near = 0.5;
    dirLight.shadow.camera.far = 50;
    dirLight.shadow.camera.left = -15;
    dirLight.shadow.camera.right = 15;
    dirLight.shadow.camera.top = 15;
    dirLight.shadow.camera.bottom = -15;
    scene.add(dirLight);

    const fillLight = new THREE.DirectionalLight(0x4488ff, 0.3);
    fillLight.position.set(-8, 4, -6);
    scene.add(fillLight);

    // ── Ramp Geometry (wedge / triangular prism) ──────────
    const rampLength = 8;
    const rampHeight = 4;
    const rampWidth  = 4;

    const vertices = new Float32Array([
      // Bottom face (on ground)
      0, 0, -rampWidth / 2,
      rampLength, 0, -rampWidth / 2,
      rampLength, 0,  rampWidth / 2,
      0, 0,  rampWidth / 2,

      // Back vertical face
      0, 0, -rampWidth / 2,
      0, rampHeight, -rampWidth / 2,
      rampLength, rampHeight, -rampWidth / 2,
      rampLength, 0, -rampWidth / 2,

      // Front vertical face
      0, 0,  rampWidth / 2,
      rampLength, 0,  rampWidth / 2,
      rampLength, rampHeight,  rampWidth / 2,
      0, rampHeight,  rampWidth / 2,

      // Sloped top face
      0, 0, -rampWidth / 2,
      rampLength, rampHeight, -rampWidth / 2,
      rampLength, rampHeight,  rampWidth / 2,
      0, 0,  rampWidth / 2,

      // Left face (small triangle at start — collapsed, skip)
      // Right tall face
      rampLength, 0, -rampWidth / 2,
      rampLength, 0,  rampWidth / 2,
      rampLength, rampHeight,  rampWidth / 2,
      rampLength, rampHeight, -rampWidth / 2,
    ]);

    // Triangles (indices into the vertex array above)
    const indices = [
      // Bottom
      0, 1, 2,  0, 2, 3,
      // Back vertical
      4, 5, 6,  4, 6, 7,
      // Front vertical
      8, 9, 10,  8, 10, 11,
      // Sloped top
      12, 13, 14,  12, 14, 15,
      // Right tall face
      16, 17, 18,  16, 18, 19,
    ];

    const rampGeo = new THREE.BufferGeometry();
    rampGeo.setAttribute('position', new THREE.BufferAttribute(vertices, 3));
    rampGeo.setIndex(indices);
    rampGeo.computeVertexNormals();

    const rampMat = new THREE.MeshStandardMaterial({
      color: 0xcc7744,
      roughness: 0.65,
      metalness: 0.1,
      side: THREE.DoubleSide,
    });

    const ramp = new THREE.Mesh(rampGeo, rampMat);
    ramp.castShadow = true;
    ramp.receiveShadow = true;
    scene.add(ramp);

    // ── Edge lines for clarity ─────────────────────────────
    const edgesGeo = new THREE.EdgesGeometry(rampGeo, 15);
    const edgesMat = new THREE.LineBasicMaterial({ color: 0xffaa66, linewidth: 1 });
    const edges = new THREE.LineSegments(edgesGeo, edgesMat);
    ramp.add(edges);

    // ── Ground Plane ───────────────────────────────────────
    const groundGeo = new THREE.PlaneGeometry(60, 60);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x2a2a3e,
      roughness: 0.9,
      metalness: 0.0,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.01;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Grid Helper ────────────────────────────────────────
    const grid = new THREE.GridHelper(40, 40, 0x444466, 0x333355);
    grid.position.y = 0.005;
    scene.add(grid);

    // ── Small platform block at the top ────────────────────
    const platGeo = new THREE.BoxGeometry(1, 0.15, rampWidth + 0.6);
    const platMat = new THREE.MeshStandardMaterial({ color: 0x88aa66, roughness: 0.7 });
    const platform = new THREE.Mesh(platGeo, platMat);
    platform.position.set(rampLength, rampHeight + 0.075, 0);
    platform.castShadow = true;
    platform.receiveShadow = true;
    scene.add(platform);

    // ── Dimensions label (simple sprite) ───────────────────
    function makeLabel(text) {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      canvas.width = 256;
      canvas.height = 64;
      ctx.fillStyle = 'rgba(0,0,0,0)';
      ctx.fillRect(0, 0, 256, 64);
      ctx.font = 'bold 28px system-ui, sans-serif';
      ctx.fillStyle = '#ffffff';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(text, 128, 32);

      const tex = new THREE.CanvasTexture(canvas);
      const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthTest: false });
      const sprite = new THREE.Sprite(mat);
      sprite.scale.set(3, 0.75, 1);
      return sprite;
    }

    const heightLabel = makeLabel('H = 4');
    heightLabel.position.set(rampLength + 0.6, rampHeight / 2, 0);
    scene.add(heightLabel);

    const lengthLabel = makeLabel('L = 8');
    lengthLabel.position.set(rampLength / 2, -0.4, rampWidth / 2 + 1);
    scene.add(lengthLabel);

    // ── Angle indicator arc ────────────────────────────────
    const angle = Math.atan2(rampHeight, rampLength);
    const arcCurve = new THREE.EllipseCurve(0, 0, 1.5, 1.5, 0, angle, false, 0);
    const arcPoints = arcCurve.getPoints(32);
    const arcGeo = new THREE.BufferGeometry().setFromPoints(
      arcPoints.map(p => new THREE.Vector3(p.x, p.y, -rampWidth / 2 - 0.5))
    );
    const arcMat = new THREE.LineBasicMaterial({ color: 0x66ccff });
    scene.add(new THREE.Line(arcGeo, arcMat));

    // ── Animation Loop ─────────────────────────────────────
    function animate() {
      requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    });
  </script>
</body>
</html>
