* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
  position: absolute; bottom: 16px; left: 50%; transform: translateX(-50%);
  color: #ccc; font-family: system-ui, sans-serif; font-size: 13px;
  background: rgba(0,0,0,.45); padding: 6px 16px; border-radius: 20px;
  pointer-events: none;
}
</style>
</head>
<body>
<div id="info">drag to orbit · scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── renderer ── */
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ── scene & camera ── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.2, 5);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.3, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.minDistance = 2;
controls.maxDistance = 12;
controls.update();

/* ── lighting ── */
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(4, 6, 4);
scene.add(key);

const fill = new THREE.DirectionalLight(0x8888ff, 0.6);
fill.position.set(-4, 2, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xff8866, 0.9);
rim.position.set(0, -2, -5);
scene.add(rim);

const spot = new THREE.SpotLight(0xffffff, 3, 15, Math.PI / 6, 0.5);
spot.position.set(0, 5, 2);
scene.add(spot);

/* ── drupelet cluster ── */
const drupeletGeo = new THREE.SphereGeometry(1, 14, 10);
// squash slightly
drupeletGeo.scale(1, 0.88, 1);

const drupeletMat = new THREE.MeshPhysicalMaterial({
  color: 0xcc1133,
  roughness: 0.35,
  metalness: 0.0,
  clearcoat: 0.6,
  clearcoatRoughness: 0.2,
  sheen: 0.3,
  sheenRoughness: 0.5,
  sheenColor: new THREE.Color(0xff4466),
});

const instances = [];

// raspberry shape: inverted cone with rounded top, tapered bottom
function raspberryPosition(y) {
  // y goes from -1 (bottom) to +1.4 (top of fruit body)
  const t = (y + 1) / 2.4;          // normalised 0..1
  let r;
  if (t < 0.15) {
    // tapered bottom
    r = 0.15 + 0.55 * (t / 0.15);
  } else if (t < 0.7) {
    // main body – slightly bulging
    const u = (t - 0.15) / 0.55;
    r = 0.7 + 0.12 * Math.sin(u * Math.PI);
  } else {
    // top taper
    const u = (t - 0.7) / 0.3;
    r = 0.7 * (1 - u * 0.55);
  }
  return r;
}

const rng = (seed) => {
  let s = seed;
  return () => { s = (s * 16807) % 2147483647; return (s - 1) / 2147483646; };
};
const rand = rng(42);

const drupeletRadius = 0.085;
const spacing = drupeletRadius * 2.15;
let idx = 0;

// hexagonal packing rows
for (let y = -0.95; y <= 1.35; y += spacing * 0.72) {
  const r = raspberryPosition(y);
  if (r < 0.05) continue;

  const circumference = 2 * Math.PI * r;
  const count = Math.max(3, Math.round(circumference / spacing));
  const angleStep = (2 * Math.PI) / count;
  const phase = (Math.floor((y + 1) / (spacing * 0.72)) % 2) * angleStep * 0.5;

  for (let i = 0; i < count; i++) {
    const angle = i * angleStep + phase;
    const jitterR = (rand() - 0.5) * spacing * 0.3;
    const jitterY = (rand() - 0.5) * spacing * 0.25;
    const px = (r + jitterR) * Math.cos(angle);
    const pz = (r + jitterR) * Math.sin(angle);
    const py = y + jitterY;

    const dist = Math.sqrt(px * px + pz * pz);
    if (dist > r + spacing * 0.6) continue;

    instances.push({ px, py, pz });

    // slight inward normal push for tighter look
    const s = 0.85 + rand() * 0.3;
    const mat = drupeletMat.clone();

    // colour variation
    const bright = rand();
    const baseR = 0.65 + bright * 0.25;
    const baseG = bright * 0.08;
    const baseB = bright * 0.12;
    mat.color.setRGB(baseR, baseG, baseB);
    mat.roughness = 0.25 + rand() * 0.25;

    const m = new THREE.Mesh(drupeletGeo, mat);
    m.position.set(px, py, pz);
    m.scale.setScalar(drupeletRadius * s);
    // orient outward
    if (dist > 0.01) {
      m.lookAt(px + px, py, pz + pz);
      m.rotateX(Math.PI / 2);
    }
    scene.add(m);
  }
}

// fill inner gaps with smaller drupelets
for (let y = -0.85; y <= 1.2; y += spacing * 1.1) {
  const r = raspberryPosition(y) * 0.55;
  if (r < 0.05) continue;
  const count = Math.max(2, Math.round(2 * Math.PI * r / (spacing * 1.3)));
  const angleStep = (2 * Math.PI) / count;

  for (let i = 0; i < count; i++) {
    const angle = i * angleStep + rand() * 0.4;
    const px = r * Math.cos(angle) * (0.5 + rand() * 0.5);
    const pz = r * Math.sin(angle) * (0.5 + rand() * 0.5);
    const py = y + (rand() - 0.5) * spacing * 0.5;
    const s = 0.55 + rand() * 0.35;
    const mat = drupeletMat.clone();
    mat.color.setRGB(0.55 + rand() * 0.2, rand() * 0.06, rand() * 0.08);
    mat.roughness = 0.3 + rand() * 0.2;
    const m = new THREE.Mesh(drupeletGeo, mat);
    m.position.set(px, py, pz);
    m.scale.setScalar(drupeletRadius * s);
    scene.add(m);
  }
}

/* ── calyx (green sepals) ── */
function makeLeaf() {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.08, 0.15, 0.02, 0.35);
  shape.quadraticCurveTo(0, 0.42, 0, 0.45);
  shape.quadraticCurveTo(0, 0.42, -0.02, 0.35);
  shape.quadraticCurveTo(-0.08, 0.15, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 8);
  // bend it
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const z = pos.getZ(i);
    pos.setZ(i, z + Math.abs(x) * 1.8);
    pos.setX(i, x + z * 0.3 * (y / 0.45));
  }
  geo.computeVertexNormals();
  return geo;
}

const leafGeo = makeLeaf();
const leafMat = new THREE.MeshPhysicalMaterial({
  color: 0x338822,
  roughness: 0.55,
  metalness: 0.0,
  clearcoat: 0.3,
  side: THREE.DoubleSide,
});

const sepalCount = 5;
for (let i = 0; i < sepalCount; i++) {
  const m = new THREE.Mesh(leafGeo, leafMat.clone());
  m.material.color.setRGB(0.18 + rand() * 0.12, 0.45 + rand() * 0.15, 0.1 + rand() * 0.06);
  const a = (i / sepalCount) * Math.PI * 2;
  m.position.set(0, 1.25, 0);
  m.rotation.y = a;
  m.rotation.z = 0.35 + rand() * 0.2;
  m.scale.setScalar(0.9 + rand() * 0.3);
  scene.add(m);
}

// small stem
const stemGeo = new THREE.CylinderGeometry(0.015, 0.02, 0.35, 6);
const stemMat = new THREE.MeshPhysicalMaterial({ color: 0x448833, roughness: 0.6 });
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.set(0, 1.5, 0);
scene.add(stem);

/* ── ground shadow disc ── */
const shadowGeo = new THREE.CircleGeometry(1.2, 48);
const shadowMat = new THREE.MeshBasicMaterial({
  color: 0x000000, transparent: true, opacity: 0.25, depthWrite: false,
});
const shadow = new THREE.Mesh(shadowGeo, shadowMat);
shadow.rotation.x = -Math.PI / 2;
shadow.position.y = -1.15;
scene.add(shadow);

/* ── animation ── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // gentle bob
  scene.children.forEach(c => {
    if (c.userData.bob) return;
  });

  // slow rotation
  const group = scene;
  // We'll just rotate the camera subtly if not interacting
  controls.autoRotate = true;
  controls.autoRotateSpeed = 0.8;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── resize ── */
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
