<body>
<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js", "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/" } }
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 4, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0, 0);

// --- Procedural groove texture ---
function makeGrooveTexture() {
  const c = document.createElement('canvas');
  c.width = c.height = 1024;
  const ctx = c.getContext('2d');
  const cx = 512, cy = 512;
  // Dark base
  ctx.fillStyle = '#1a1a1a';
  ctx.fillRect(0, 0, 1024, 1024);
  // Grooves
  for (let r = 60; r < 490; r += 2.5) {
    const brightness = 25 + Math.random() * 15;
    ctx.beginPath();
    ctx.arc(cx, cy, r, 0, Math.PI * 2);
    ctx.strokeStyle = `rgb(${brightness},${brightness},${brightness})`;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
  const tex = new THREE.CanvasTexture(c);
  tex.colorSpace = THREE.SRGBColorSpace;
  return tex;
}

// --- Procedural label texture ---
function makeLabelTexture() {
  const c = document.createElement('canvas');
  c.width = c.height = 512;
  const ctx = c.getContext('2d');
  const cx = 256, cy = 256;
  // Gradient background
  const grad = ctx.createRadialGradient(cx, cy, 20, cx, cy, 240);
  grad.addColorStop(0, '#e8303a');
  grad.addColorStop(0.5, '#c41e2a');
  grad.addColorStop(1, '#8b0000');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, 512, 512);
  // Text
  ctx.fillStyle = '#f0e6d0';
  ctx.textAlign = 'center';
  ctx.font = 'bold 32px Georgia, serif';
  ctx.fillText('MIDNIGHT', cx, 220);
  ctx.font = 'bold 28px Georgia, serif';
  ctx.fillText('JAZZ', cx, 260);
  ctx.font = '18px Georgia, serif';
  ctx.fillText('L.P. 33⅓ RPM', cx, 300);
  ctx.font = '14px Georgia, serif';
  ctx.fillStyle = '#d0c0a0';
  ctx.fillText('STEREO • MONAURAL', cx, 340);
  // Small circle decoration
  ctx.beginPath();
  ctx.arc(cx, cy, 18, 0, Math.PI * 2);
  ctx.strokeStyle = '#f0e6d0';
  ctx.lineWidth = 2;
  ctx.stroke();
  const tex = new THREE.CanvasTexture(c);
  tex.colorSpace = THREE.SRGBColorSpace;
  return tex;
}

// --- Record group ---
const record = new THREE.Group();
const grooveTex = makeGrooveTexture();
const labelTex = makeLabelTexture();

// Main disc
const discGeo = new THREE.CylinderGeometry(2, 2, 0.06, 128);
const discMat = new THREE.MeshStandardMaterial({
  map: grooveTex,
  roughness: 0.35,
  metalness: 0.1,
});
const disc = new THREE.Mesh(discGeo, discMat);
disc.rotation.x = Math.PI / 2;
record.add(disc);

// Label
const labelGeo = new THREE.CylinderGeometry(0.7, 0.7, 0.065, 64);
const labelMat = new THREE.MeshStandardMaterial({
  map: labelTex,
  roughness: 0.6,
  metalness: 0.0,
});
const label = new THREE.Mesh(labelGeo, labelMat);
label.rotation.x = Math.PI / 2;
record.add(label);

// Spindle hole
const holeGeo = new THREE.CylinderGeometry(0.06, 0.06, 0.07, 16);
const holeMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });
const hole = new THREE.Mesh(holeGeo, holeMat);
hole.rotation.x = Math.PI / 2;
record.add(hole);

// Edge bevel ring
const edgeGeo = new THREE.TorusGeometry(2, 0.015, 8, 128);
const edgeMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.3, metalness: 0.5 });
const edge = new THREE.Mesh(edgeGeo, edgeMat);
record.add(edge);

record.rotation.x = 0.3;
scene.add(record);

// --- Turntable platter ---
const platterGeo = new THREE.CylinderGeometry(2.3, 2.3, 0.12, 128);
const platterMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.4, metalness: 0.8 });
const platter = new THREE.Mesh(platterGeo, platterMat);
platter.position.y = -0.09;
scene.add(platter);

// Tonearm base
const armBaseGeo = new THREE.CylinderGeometry(0.25, 0.3, 0.15, 24);
const armMat = new THREE.MeshStandardMaterial({ color: 0x444444, roughness: 0.3, metalness: 0.9 });
const armBase = new THREE.Mesh(armBaseGeo, armMat);
armBase.position.set(2.2, -0.02, -1.2);
scene.add(armBase);

// Tonearm
const armGeo = new THREE.CylinderGeometry(0.03, 0.025, 2.5, 12);
const arm = new THREE.Mesh(armGeo, armMat);
arm.position.set(2.2, 0.8, -1.2);
arm.rotation.z = Math.PI / 3;
scene.add(arm);

// --- Lighting ---
const ambient = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xfff0dd, 2.5);
key.position.set(3, 5, 4);
scene.add(key);

const fill = new THREE.DirectionalLight(0xc0d0ff, 0.8);
fill.position.set(-4, 3, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff6040, 1.5, 12);
rim.position.set(-3, 2, -3);
scene.add(rim);

// Subtle specular highlight to simulate record reflection
const spec = new THREE.PointLight(0xffffff, 2, 8);
spec.position.set(1, 3, 2);
scene.add(spec);

// --- Animation ---
function animate(t) {
  requestAnimationFrame(animate);
  record.rotation.z = t * 0.001; // ~33 RPM spin
  controls.update();
  renderer.render(scene, camera);
}
animate(0);

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**Features:**

- **Procedural vinyl grooves** — a canvas-drawn concentric ring texture mapped onto the disc surface
- **Procedural label** — red gradient "Midnight Jazz" label with typography
- **Spindle hole** and **metal edge bevel** for realism
- **Turntable platter** and **tonearm** (static) for context
- **Multi-light setup** — warm key, cool fill, rim accent, and specular highlight to catch reflections off the grooves
- **OrbitControls** — click-drag to rotate, scroll to zoom
- **Continuous spin** at ~33⅓ RPM
- **Responsive** — handles window resizing

