// Build ribbon geometry along a twisted helical path
const segments = 200;
const width = 1.2;
const positions = [];
const normals = [];
const uvs = [];
const indices = [];

const curve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-4, 2, -3),
  new THREE.Vector3(-2, -1, -1),
  new THREE.Vector3(0, 1.5, 2),
  new THREE.Vector3(2, -0.5, -2),
  new THREE.Vector3(4, 1, 1),
], false, 'catmullrom', 0.5);

const up = new THREE.Vector3(0, 1, 0);
const tangent = new THREE.Vector3();
const binormal = new THREE.Vector3();

for (let i = 0; i <= segments; i++) {
  const t = i / segments;
  const pos = curve.getPointAt(t);
  curve.getTangentAt(t, tangent);

  binormal.crossVectors(tangent, up).normalize();
  if (binormal.lengthSq() < 0.001) binormal.set(1, 0, 0);

  const twist = t * Math.PI * 4;
  const cos = Math.cos(twist);
  const sin = Math.sin(twist);

  const w = width * (0.6 + 0.4 * Math.sin(t * Math.PI));

  const right = new THREE.Vector3().copy(binormal).multiplyScalar(w * cos)
    .add(new THREE.Vector3().crossVectors(binormal, tangent).multiplyScalar(w * sin));

  // left vertex
  positions.push(pos.x - right.x, pos.y - right.y, pos.z - right.z);
  normals.push(0, 1, 0);
  uvs.push(t, 0);

  // right vertex
  positions.push(pos.x + right.x, pos.y + right.y, pos.z + right.z);
  normals.push(0, 1, 0);
  uvs.push(t, 1);

  if (i < segments) {
    const a = i * 2, b = i * 2 + 1, c = i * 2 + 2, d = i * 2 + 3;
    indices.push(a, b, c, b, d, c);
  }
}

const geo = new THREE.BufferGeometry();
geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
geo.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
geo.setIndex(indices);
geo.computeVertexNormals();

const mat = new THREE.MeshStandardMaterial({
  color: 0xcc3355,
  metalness: 0.3,
  roughness: 0.25,
  side: THREE.DoubleSide,
  emissive: 0x330011,
});

const ribbon = new THREE.Mesh(geo, mat);
scene.add(ribbon);

