  const twist = t * Math.PI * 3 + 1;
  const cos = Math.cos(twist), sin = Math.sin(twist);
  const w = width * 0.8 * (0.6 + 0.4 * Math.sin(t * Math.PI));
  const right = new THREE.Vector3().copy(binormal).multiplyScalar(w * cos)
