  pos2.push(p.x - right.x, p.y - right.y, p.z - right.z, p.x + right.x, p.y + right.y, p.z + right.z);
  nrm2.push(0, 1, 0, 0, 1, 0);
  uv2.push(t, 0, t, 1);
  if (i < segments) { const a = i*2, b = a+1, c = a+2, d = a+3; idx2.push(a,b,c, b,d,c); }
}

const geo2 = new THREE.BufferGeometry();
geo2.setAttribute('position', new THREE.Float32BufferAttribute(pos2, 3));
geo2.setAttribute('normal', new THREE.Float32BufferAttribute(nrm2, 3));
geo2.setAttribute('uv', new THREE.Float32BufferAttribute(uv2, 2));
geo2.setIndex(idx2);
