<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.008);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(55, window.innerWidth / window.innerHeight, 0.1, 500);
camera.position.set(0, 18, 35);
camera.lookAt(0, 0, -10);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, -5);
controls.enableDamping = true;
controls.maxPolarAngle = Math.PI / 2.1;
controls.minDistance = 5;
controls.maxDistance = 80;
controls.update();

// ── Lights ──
const ambientLight = new THREE.AmbientLight(0x406080, 0.8);
scene.add(ambientLight);

const sun = new THREE.DirectionalLight(0xffeedd, 2.5);
sun.position.set(20, 40, 20);
sun.castShadow = false;
scene.add(sun);

const hemiLight = new THREE.HemisphereLight(0x87CEEB, 0x3a5a1e, 0.6);
scene.add(hemiLight);

// ── Noise helper ──
function noise2D(x, z) {
  const n = Math.sin(x * 12.9898 + z * 78.233) * 43758.5453;
  return n - Math.floor(n);
}

function fbm(x, z, octaves = 4) {
  let val = 0, amp = 1, freq = 1, max = 0;
  for (let i = 0; i < octaves; i++) {
    val += (noise2D(x * freq, z * freq) - 0.5) * amp;
    max += amp;
    amp *= 0.5;
    freq *= 2.1;
  }
  return val / max;
}

// ── River Width Function ──
function riverWidth(z) {
  return 6 + Math.sin(z * 0.05) * 2.5 + Math.sin(z * 0.13) * 1.2;
}

// ── Water ──
const waterGeo = new THREE.PlaneGeometry(80, 200, 120, 300);
waterGeo.rotateX(-Math.PI / 2);

const waterMat = new THREE.MeshStandardMaterial({
  color: 0x1a6b8a,
  roughness: 0.15,
  metalness: 0.1,
  transparent: true,
  opacity: 0.82,
  side: THREE.DoubleSide,
});

const water = new THREE.Mesh(waterGeo, waterMat);
water.position.y = -0.3;
scene.add(water);

// ── Terrain ──
function createTerrain(side) {
  const segments = 200;
  const length = 200;
  const geo = new THREE.BufferGeometry();
  const vertices = [];
  const colors = [];
  const indices = [];

  const width = 40;
  const res = 30;

  for (let iz = 0; iz <= segments; iz++) {
    const z = (iz / segments - 0.5) * length;
    const rw = riverWidth(z);

    for (let ix = 0; ix <= res; ix++) {
      const t = ix / res;
      const x = side * (rw + t * width);
      const nx = x / width;
      const nz = z / length;

      const h = fbm(nx * 3, nz * 3, 5) * 8
              + fbm(nx * 8, nz * 8, 3) * 2
              + (t < 0.1 ? (0.1 - t) * 15 : 0); // steep bank edge

      vertices.push(x, h, z);

      // Color variation
      const green = 0.15 + fbm(nx * 5, nz * 5, 3) * 0.15;
      const r = 0.2 + fbm(nx * 7, nz * 7, 2) * 0.1;
      const b = 0.05 + fbm(nx * 4, nz * 6, 2) * 0.05;
      colors.push(r, green, b);
    }
  }

  for (let iz = 0; iz < segments; iz++) {
    for (let ix = 0; ix < res; ix++) {
      const a = iz * (res + 1) + ix;
      const b = a + 1;
      const c = a + res + 1;
      const d = c + 1;
      indices.push(a, c, b, b, c, d);
    }
  }

  geo.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
  geo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  geo.setIndex(indices);
  geo.computeVertexNormals();

  const mat = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness: 0.95,
    metalness: 0.0,
    flatShading: false,
  });

  return new THREE.Mesh(geo, mat);
}

const leftBank = createTerrain(-1);
const rightBank = createTerrain(1);
scene.add(leftBank, rightBank);

// ── Rocks ──
function addRocks() {
  const rockGeo = new THREE.IcosahedronGeometry(1, 1);
  const rockMat = new THREE.MeshStandardMaterial({
    color: 0x666666, roughness: 0.9, metalness: 0.05, flatShading: true,
  });

  for (let i = 0; i < 60; i++) {
    const z = (Math.random() - 0.5) * 180;
    const rw = riverWidth(z);
    const side = Math.random() > 0.5 ? 1 : -1;
    const offset = rw + Math.random() * 3;
    const x = side * offset;

    const rock = new THREE.Mesh(rockGeo, rockMat);
    const s = 0.3 + Math.random() * 1.2;
    rock.scale.set(s, s * (0.5 + Math.random() * 0.5), s);
    rock.position.set(x, s * 0.3, z);
    rock.rotation.set(Math.random(), Math.random(), Math.random());
    scene.add(rock);
  }
}
addRocks();

// ── Floating Debris (leaves) ──
const debris = [];
const debrisGeo = new THREE.PlaneGeometry(0.3, 0.2);
const debrisMat = new THREE.MeshStandardMaterial({
  color: 0x4a7a3a, roughness: 0.8, side: THREE.DoubleSide,
});

for (let i = 0; i < 40; i++) {
  const mesh = new THREE.Mesh(debrisGeo, debrisMat);
  mesh.rotation.x = -Math.PI / 2;
  mesh.userData = {
    z: (Math.random() - 0.5) * 180,
    speed: 0.01 + Math.random() * 0.03,
    wobble: Math.random() * Math.PI * 2,
    wobbleSpeed: 1 + Math.random() * 2,
  };
  scene.add(mesh);
  debris.push(mesh);
}

// ── Sky dome ──
const skyGeo = new THREE.SphereGeometry(200, 32, 16);
const skyMat = new THREE.MeshBasicMaterial({
  side: THREE.BackSide,
  color: 0x87CEEB,
});
const sky = new THREE.Mesh(skyGeo, skyMat);
scene.add(sky);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  const dt = clock.getDelta();

  // Animate water vertices
  const pos = waterGeo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const z = pos.getZ(i);

    // Multi-frequency waves flowing downstream
    const wave1 = Math.sin(z * 0.3 + t * 2.0) * 0.25;
    const wave2 = Math.sin(x * 0.5 + t * 1.5) * 0.12;
    const wave3 = Math.sin((z + x) * 0.15 + t * 3.0) * 0.18;
    const wave4 = Math.sin(z * 0.8 + t * 4.0 + x * 0.3) * 0.06;

    pos.setY(i, (wave1 + wave2 + wave3 + wave4) - 0.3);
  }
  pos.needsUpdate = true;
  waterGeo.computeVertexNormals();

  // Animate debris
  for (const d of debris) {
    d.userData.z += d.userData.speed;
    if (d.userData.z > 90) d.userData.z -= 180;

    const rw = riverWidth(d.userData.z);
    const wobble = Math.sin(d.userData.wobble + t * d.userData.wobbleSpeed) * 1.5;
    const xSpan = rw * 0.6;

    d.position.set(wobble, 0.05, d.userData.z);
    d.rotation.z = Math.sin(t * d.userData.wobbleSpeed * 0.5) * 0.5;
  }

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
</body>
</html>
