</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 0.9;
document.body.appendChild(renderer.domElement);

// ── Scene & Fog ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x9DC4E0, 0.008);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(65, window.innerWidth / window.innerHeight, 0.5, 500);
camera.position.set(0, 3, 30);
camera.lookAt(0, 1.5, 0);

// ── Lights ──
const ambient = new THREE.AmbientLight(0x6688AA, 0.8);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xFFEECC, 1.8);
sun.position.set(30, 60, 40);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.left = -60;
sun.shadow.camera.right = 60;
sun.shadow.camera.top = 60;
sun.shadow.camera.bottom = -60;
sun.shadow.camera.far = 180;
scene.add(sun);

// ── Materials ──
const roadMat  = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.9 });
const grassMat = new THREE.MeshStandardMaterial({ color: 0x4A8C3F, roughness: 1 });
const lineMat  = new THREE.MeshStandardMaterial({ color: 0xEEEEEE, roughness: 0.6 });
const yellowMat= new THREE.MeshStandardMaterial({ color: 0xFFCC00, roughness: 0.6 });
const trunkMat = new THREE.MeshStandardMaterial({ color: 0x5C4033, roughness: 1 });
const leafMats = [
  new THREE.MeshStandardMaterial({ color: 0x2D6B1E, roughness: 0.9 }),
  new THREE.MeshStandardMaterial({ color: 0x3A8C2F, roughness: 0.9 }),
  new THREE.MeshStandardMaterial({ color: 0x227722, roughness: 0.9 }),
];

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(600, 2000),
  grassMat
);
ground.rotation.x = -Math.PI / 2;
ground.position.set(0, -0.05, -800);
ground.receiveShadow = true;
scene.add(ground);

// ── Road ──
const road = new THREE.Mesh(
  new THREE.PlaneGeometry(12, 2000),
  roadMat
);
road.rotation.x = -Math.PI / 2;
road.position.set(0, 0, -800);
road.receiveShadow = true;
scene.add(road);

// ── Edge Lines (solid white) ──
function addLine(x, width) {
  const m = new THREE.Mesh(
    new THREE.PlaneGeometry(width, 2000),
    lineMat
  );
  m.rotation.x = -Math.PI / 2;
  m.position.set(x, 0.01, -800);
  scene.add(m);
}
addLine(-5.5, 0.2);
addLine(5.5, 0.2);

// ── Dashed Center Line (yellow) ──
const dashLen = 3, gapLen = 3, totalLen = 2000;
for (let z = -800; z < 200; z += dashLen + gapLen) {
  const dash = new THREE.Mesh(
    new THREE.PlaneGeometry(0.2, dashLen),
    yellowMat
  );
  dash.rotation.x = -Math.PI / 2;
  dash.position.set(0, 0.02, z);
  scene.add(dash);
}

// ── Lane Dividers (dashed white, two lanes each direction) ──
for (let z = -800; z < 200; z += dashLen + gapLen) {
  for (const x of [-2.75, 2.75]) {
    const dash = new THREE.Mesh(
      new THREE.PlaneGeometry(0.15, dashLen * 0.6),
      lineMat
    );
    dash.rotation.x = -Math.PI / 2;
    dash.position.set(x, 0.02, z);
    scene.add(dash);
  }
}

// ── Trees ──
function createTree(x, z) {
  const group = new THREE.Group();
  const trunk = new THREE.Mesh(
    new THREE.CylinderGeometry(0.15, 0.25, 2.5, 8),
    trunkMat
  );
  trunk.position.y = 1.25;
  trunk.castShadow = true;
  group.add(trunk);

  const layers = 2 + Math.floor(Math.random() * 2);
  for (let i = 0; i < layers; i++) {
    const r = 1.2 - i * 0.3 + Math.random() * 0.2;
    const h = 1.5 - i * 0.2;
    const cone = new THREE.Mesh(
      new THREE.ConeGeometry(r, h, 8),
      leafMats[Math.floor(Math.random() * leafMats.length)]
    );
    cone.position.y = 2.5 + i * 0.9;
    cone.castShadow = true;
    group.add(cone);
  }

  group.position.set(x, 0, z);
  const s = 0.8 + Math.random() * 0.6;
  group.scale.set(s, s, s);
  scene.add(group);
}

// Place trees along both sides
for (let z = -10; z < 180; z += 8 + Math.random() * 12) {
  createTree(-10 - Math.random() * 12, z);
  createTree(10 + Math.random() * 12, z);
}

// ── Simple Clouds ──
function createCloud(x, y, z) {
  const group = new THREE.Group();
  const mat = new THREE.MeshStandardMaterial({ color: 0xFFFFFF, roughness: 1, flatShading: true });
  for (let i = 0; i < 5 + Math.floor(Math.random() * 4); i++) {
    const r = 1.5 + Math.random() * 2;
    const puff = new THREE.Mesh(new THREE.SphereGeometry(r, 7, 5), mat);
    puff.position.set((Math.random() - 0.5) * 6, (Math.random() - 0.5) * 1.5, (Math.random() - 0.5) * 3);
    puff.scale.y = 0.5;
    group.add(puff);
  }
  group.position.set(x, y, z);
  scene.add(group);
  return group;
}

const clouds = [];
for (let i = 0; i < 12; i++) {
  clouds.push(createCloud(
    (Math.random() - 0.5) * 120,
    30 + Math.random() * 20,
    Math.random() * 200 - 50
  ));
}

// ── Sun Disc ──
const sunDisc = new THREE.Mesh(
  new THREE.CircleGeometry(8, 32),
  new THREE.MeshBasicMaterial({ color: 0xFFF4C4, transparent: true, opacity: 0.8 })
);
sunDisc.position.copy(sun.position);
scene.add(sunDisc);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Drive forward
  camera.position.z = 30 - t * 12;
  camera.lookAt(0, 1.5, camera.position.z - 25);

  // Update sun shadow camera to follow
  sun.position.z = camera.position.z + 40;
  sun.target.position.z = camera.position.z;
  sunDisc.position.z = camera.position.z + 40;

  // Drift clouds
  clouds.forEach((c, i) => {
    c.position.x += 0.01 * (i % 2 === 0 ? 1 : -0.7);
    c.position.z = camera.position.z - 30;
  });

  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
</body>
</html>
```

**What you get when you open this file:**

- **A 4-lane road** with solid white edge lines, a dashed yellow center line, and dashed white lane dividers
- **Green grass** flanking both sides and **procedural pine trees** scattered along the roadside
- **Clouds** drifting in the sky with a **sun disc**
- **Exponential fog** that fades distant objects into the sky color
- **ACES filmic tone mapping** and soft shadow maps for a cinematic feel
- **The camera drives forward** continuously at a steady pace, with the sun and clouds tracking alongside to create the illusion of an endless road

