<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x000011, 0.015);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 1000);
camera.position.set(5, 4, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1, 0);

// ── Lighting ──
scene.add(new THREE.AmbientLight(0x334466, 0.8));

const sun = new THREE.DirectionalLight(0xffeedd, 3);
sun.position.set(5, 10, 7);
scene.add(sun);

const rim = new THREE.DirectionalLight(0x4488ff, 1.5);
rim.position.set(-5, 3, -5);
scene.add(rim);

// ── Rocket ──
const rocket = new THREE.Group();

// Body
const bodyGeo = new THREE.CylinderGeometry(0.5, 0.55, 3.5, 32);
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0xdddddd, metalness: 0.6, roughness: 0.3
});
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.y = 1.2;
rocket.add(body);

// Nose cone
const noseGeo = new THREE.ConeGeometry(0.5, 1.2, 32);
const noseMat = new THREE.MeshStandardMaterial({
  color: 0xff3333, metalness: 0.4, roughness: 0.3
});
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.y = 3.35;
rocket.add(nose);

// Nose tip (small sphere)
const tipGeo = new THREE.SphereGeometry(0.06, 16, 16);
const tipMat = new THREE.MeshStandardMaterial({ color: 0xffffff, metalness: 1, roughness: 0.1 });
const tip = new THREE.Mesh(tipGeo, tipMat);
tip.position.y = 4.0;
rocket.add(tip);

// Window
const winGeo = new THREE.CircleGeometry(0.18, 24);
const winMat = new THREE.MeshStandardMaterial({
  color: 0x88ccff, metalness: 0.9, roughness: 0.05, emissive: 0x224466, emissiveIntensity: 0.3
});
const win = new THREE.Mesh(winGeo, winMat);
win.position.set(0, 2.0, 0.51);
rocket.add(win);

// Band accents
for (const y of [0.6, 1.8]) {
  const bandGeo = new THREE.TorusGeometry(0.54, 0.03, 8, 48);
  const bandMat = new THREE.MeshStandardMaterial({ color: 0xff3333, metalness: 0.5, roughness: 0.4 });
  const band = new THREE.Mesh(bandGeo, bandMat);
  band.position.y = y;
  band.rotation.x = Math.PI / 2;
  rocket.add(band);
}

// Fins
const finShape = new THREE.Shape();
finShape.moveTo(0, 0);
finShape.lineTo(0.9, -0.7);
finShape.lineTo(0.7, -1.1);
finShape.lineTo(0, -0.9);
finShape.closePath();

const finExtrudeSettings = { depth: 0.06, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02 };
const finGeo = new THREE.ExtrudeGeometry(finShape, finExtrudeSettings);
const finMat = new THREE.MeshStandardMaterial({ color: 0xff3333, metalness: 0.5, roughness: 0.4 });

for (let i = 0; i < 4; i++) {
  const fin = new THREE.Mesh(finGeo, finMat);
  fin.position.y = 0.1;
  fin.rotation.y = (Math.PI / 2) * i;
  fin.position.x = Math.sin((Math.PI / 2) * i) * 0.5;
  fin.position.z = Math.cos((Math.PI / 2) * i) * 0.5;
  rocket.add(fin);
}

// Engine nozzle
const nozzleGeo = new THREE.CylinderGeometry(0.35, 0.45, 0.4, 32);
const nozzleMat = new THREE.MeshStandardMaterial({ color: 0x444444, metalness: 0.8, roughness: 0.6 });
const nozzle = new THREE.Mesh(nozzleGeo, nozzleMat);
nozzle.position.y = -0.65;
rocket.add(nozzle);

// Flame (animated)
const flameGeo = new THREE.ConeGeometry(0.35, 1.5, 16, 1, true);
const flameMat = new THREE.MeshBasicMaterial({
  color: 0xff6600, transparent: true, opacity: 0.8, side: THREE.DoubleSide
});
const flame = new THREE.Mesh(flameGeo, flameMat);
flame.position.y = -1.5;
flame.rotation.x = Math.PI;
rocket.add(flame);

// Inner flame
const innerFlameGeo = new THREE.ConeGeometry(0.15, 0.9, 12, 1, true);
const innerFlameMat = new THREE.MeshBasicMaterial({
  color: 0xffff44, transparent: true, opacity: 0.9, side: THREE.DoubleSide
});
const innerFlame = new THREE.Mesh(innerFlameGeo, innerFlameMat);
innerFlame.position.y = -1.3;
innerFlame.rotation.x = Math.PI;
rocket.add(innerFlame);

// Flame light
const flameLight = new THREE.PointLight(0xff6600, 4, 8);
flameLight.position.y = -1.8;
rocket.add(flameLight);

scene.add(rocket);

// ── Stars ──
const starsGeo = new THREE.BufferGeometry();
const starPositions = [];
for (let i = 0; i < 2000; i++) {
  starPositions.push((Math.random() - 0.5) * 200, (Math.random() - 0.5) * 200, (Math.random() - 0.5) * 200);
}
starsGeo.setAttribute('position', new THREE.Float32BufferAttribute(starPositions, 3));
const starsMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.15, sizeAttenuation: true });
scene.add(new THREE.Points(starsGeo, starsMat));

// ── Animate ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle bob
  rocket.position.y = Math.sin(t * 0.8) * 0.15;
  rocket.rotation.z = Math.sin(t * 0.5) * 0.02;

  // Flicker flame
  const flicker = 0.85 + Math.sin(t * 20) * 0.1 + Math.sin(t * 31) * 0.05;
  flame.scale.set(flicker * 0.9, flicker, flicker * 0.9);
  flameMat.opacity = 0.6 + Math.sin(t * 25) * 0.2;
  innerFlame.scale.set(flicker, flicker, flicker);
  flameLight.intensity = 3 + Math.sin(t * 18) * 1.5;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
