}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 50);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 4, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0, 0);

// ── Lights ──
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-5, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6633, 1.5, 20);
rimLight.position.set(-3, 2, -5);
scene.add(rimLight);

// ── Materials ──
function createWoodMaterial(baseColor) {
  return new THREE.MeshStandardMaterial({
    color: baseColor,
    roughness: 0.55,
    metalness: 0.05,
  });
}

const bodyMat = createWoodMaterial(0xc4956a);
const handleMat = createWoodMaterial(0xa87b51);
const ferruleMat = new THREE.MeshStandardMaterial({
  color: 0x999999,
  roughness: 0.2,
  metalness: 0.9,
});

// ── Rolling Pin Group ──
const pin = new THREE.Group();

// Main cylinder body
const bodyGeo = new THREE.CylinderGeometry(0.55, 0.55, 4.0, 64, 1, false);
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.rotation.z = Math.PI / 2;
body.castShadow = true;
body.receiveShadow = true;
pin.add(body);

// Handles
const handleGeo = new THREE.CylinderGeometry(0.18, 0.18, 1.6, 32);

const leftHandle = new THREE.Mesh(handleGeo, handleMat);
leftHandle.rotation.z = Math.PI / 2;
leftHandle.position.x = -2.8;
leftHandle.castShadow = true;
pin.add(leftHandle);

const rightHandle = new THREE.Mesh(handleGeo, handleMat);
rightHandle.rotation.z = Math.PI / 2;
rightHandle.position.x = 2.8;
rightHandle.castShadow = true;
pin.add(rightHandle);

// Ferrules (metal end caps on handles)
const ferruleGeo = new THREE.CylinderGeometry(0.20, 0.20, 0.12, 32);

const leftFerrule = new THREE.Mesh(ferruleGeo, ferruleMat);
leftFerrule.rotation.z = Math.PI / 2;
leftFerrule.position.x = -3.62;
pin.add(leftFerrule);

const rightFerrule = new THREE.Mesh(ferruleGeo, ferruleMat);
rightFerrule.rotation.z = Math.PI / 2;
rightFerrule.position.x = 3.62;
pin.add(rightFerrule);

// Decorative grooves on the body
for (let i = 0; i < 3; i++) {
  const ringGeo = new THREE.TorusGeometry(0.56, 0.015, 8, 64);
  const ring = new THREE.Mesh(ringGeo, ferruleMat);
  ring.position.x = -1.2 + i * 1.2;
  pin.add(ring);
}

scene.add(pin);

// ── Ground Plane ──
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// Subtle grid
const grid = new THREE.GridHelper(30, 30, 0x3a3a5e, 0x2a2a4e);
grid.position.y = -1.99;
scene.add(grid);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle roll along the floor
  pin.position.y = Math.abs(Math.sin(t * 0.8)) * 0.6;
  pin.rotation.x = t * 0.8;

  // Slight wobble
  pin.rotation.z = Math.sin(t * 1.2) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
