ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// --- House Walls ---
const house = new THREE.Group();

// Main walls
const wallGeo = new THREE.BoxGeometry(6, 4, 4);
const walls = new THREE.Mesh(wallGeo, wallMat);
walls.position.y = 2;
walls.castShadow = true;
walls.receiveShadow = true;
house.add(walls);

// --- Pitched Roof ---
// Left slope
const slopeGeo = new THREE.BoxGeometry(4.2, 0.25, 4.4);
const leftRoof = new THREE.Mesh(slopeGeo, roofMat);
leftRoof.position.set(-1.5, 4.8, 0);
leftRoof.rotation.z = Math.atan2(2.2, 3);
leftRoof.castShadow = true;
house.add(leftRoof);

// Right slope
const rightRoof = new THREE.Mesh(slopeGeo, roofMat);
rightRoof.position.set(1.5, 4.8, 0);
rightRoof.rotation.z = -Math.atan2(2.2, 3);
rightRoof.castShadow = true;
house.add(rightRoof);

// Ridge beam
const ridgeGeo = new THREE.BoxGeometry(0.25, 0.25, 4.5);
const ridge = new THREE.Mesh(ridgeGeo, trimMat);
ridge.position.set(0, 5.95, 0);
ridge.castShadow = true;
house.add(ridge);

// Fascia / trim along eaves
const fasciaGeo = new THREE.BoxGeometry(4.4, 0.2, 0.15);
for (const side of [-1, 1]) {
  const fascia = new THREE.Mesh(fasciaGeo, trimMat);
  fascia.position.set(0, 3.7, side * 2.15);
  house.add(fascia);
}
for (const side of [-1, 1]) {
  const fascia = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.2, 4.4), trimMat);
  fascia.position.set(side * 2.15, 3.7, 0);
  house.add(fascia);
}

// Gable end triangles
const gableShape = new THREE.Shape();
gableShape.moveTo(-2.9, 0);
gableShape.lineTo(0, 2.1);
gableShape.lineTo(2.9, 0);
gableShape.lineTo(-2.9, 0);
const gableGeo = new THREE.ShapeGeometry(gableShape);
for (const side of [-1, 1]) {
  const gable = new THREE.Mesh(gableGeo, wallMat);
  gable.position.set(0, 4, side * 2.01);
  if (side === 1) gable.rotation.y = Math.PI;
  gable.castShadow = true;
  house.add(gable);
}

scene.add(house);

// --- Window ---
const windowMat = new THREE.MeshStandardMaterial({ color: 0x334466, roughness: 0.2, metalness: 0.3 });
const frameMat = new THREE.MeshStandardMaterial({ color: 0xFFFFFF, roughness: 0.5 });

function makeWindow(x, y, z, ry = 0) {
  const group = new THREE.Group();
  const glass = new THREE.Mesh(new THREE.PlaneGeometry(1, 1.2), windowMat);
  group.add(glass);

  const frameGeo = new THREE.BoxGeometry(1.15, 0.06, 0.08);
  for (const fy of [-0.6, 0, 0.6]) {
    const bar = new THREE.Mesh(frameGeo, frameMat);
    bar.position.y = fy;
    group.add(bar);
  }
  const frameGeoV = new THREE.BoxGeometry(0.06, 1.2, 0.08);
  for (const fx of [-0.5, 0.5]) {
    const bar = new THREE.Mesh(frameGeoV, frameMat);
    bar.position.x = fx;
    group.add(bar);
  }

  group.position.set(x, y, z);
  group.rotation.y = ry;
  return group;
}

house.add(makeWindow(0, 2.5, 2.04));
house.add(makeWindow(0, 2.5, -2.04, Math.PI));

// --- Door ---
const doorGroup = new THREE.Group();
const door = new THREE.Mesh(new THREE.PlaneGeometry(1, 2), new THREE.MeshStandardMaterial({ color: 0x5C3317, roughness: 0.8 }));
doorGroup.add(door);
const doorFrame = new THREE.Mesh(new THREE.BoxGeometry(1.2, 2.2, 0.08), frameMat);
doorFrame.position.z = -0.02;
doorGroup.add(doorFrame);
doorGroup.position.set(0, 1, 2.04);
house.add(doorGroup);

// --- Animation ---
function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
