const hemiLight = new THREE.HemisphereLight(0x87CEEB, 0x3a7d3a, 0.4);
scene.add(hemiLight);

// --- Ground ---
const groundGeo = new THREE.PlaneGeometry(800, 800);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x3a7d3a, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// --- Rollercoaster Path ---
const pathPoints = [
  new THREE.Vector3(0, 2, 0),
  new THREE.Vector3(20, 2, -10),
  new THREE.Vector3(40, 8, -5),
  new THREE.Vector3(55, 20, 10),
  new THREE.Vector3(60, 45, 30),
  new THREE.Vector3(50, 55, 50),
  new THREE.Vector3(30, 50, 60),
  new THREE.Vector3(10, 40, 55),
  new THREE.Vector3(-10, 35, 50),
  new THREE.Vector3(-25, 30, 40),
  new THREE.Vector3(-35, 25, 25),
  new THREE.Vector3(-30, 15, 10),
  new THREE.Vector3(-20, 8, -5),
  new THREE.Vector3(-10, 5, -15),
  new THREE.Vector3(0, 6, -20),
  new THREE.Vector3(15, 12, -25),
  new THREE.Vector3(30, 25, -30),
  new THREE.Vector3(45, 40, -25),
  new THREE.Vector3(50, 55, -10),
  new THREE.Vector3(45, 50, 5),
  new THREE.Vector3(35, 35, 15),
  new THREE.Vector3(25, 20, 20),
  new THREE.Vector3(20, 10, 15),
  new THREE.Vector3(15, 5, 5),
  new THREE.Vector3(10, 3, -5),
  new THREE.Vector3(5, 2, -10),
  new THREE.Vector3(0, 2, 0),
];

const curve = new THREE.CatmullRomCurve3(pathPoints, true, 'catmullrom', 0.5);

// --- Track (Tube) ---
const trackGeo = new THREE.TubeGeometry(curve, 500, 1.2, 8, true);
const trackMat = new THREE.MeshStandardMaterial({ color: 0xcc2222, roughness: 0.4, metalness: 0.3 });
const track = new THREE.Mesh(trackGeo, trackMat);
track.castShadow = true;
track.receiveShadow = true;
scene.add(track);

// Second rail (parallel tube)
const offsetCurve = new THREE.CatmullRomCurve3(
  pathPoints.map(p => {
    const t = curve.getTangentAt(pathPoints.indexOf(p) / pathPoints.length);
    const normal = new THREE.Vector3(-t.z, 0, t.x).normalize();
    return p.clone().add(normal.multiplyScalar(2.5));
  }),
  true, 'catmullrom', 0.5
);
const track2Geo = new THREE.TubeGeometry(offsetCurve, 500, 1.2, 8, true);
const track2 = new THREE.Mesh(track2Geo, trackMat);
track2.castShadow = true;
scene.add(track2);

// --- Support Pillars ---
const pillarMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.7, metalness: 0.2 });
const pillarInterval = 15;

for (let t = 0; t < 1; t += pillarInterval / curve.getLength()) {
  const pos = curve.getPointAt(t);
  const height = pos.y - 1;
  if (height > 1) {
    const pillarGeo = new THREE.CylinderGeometry(0.6, 0.8, height, 8);
