    pillar.receiveShadow = true;
    scene.add(pillar);

    // Cross braces
    if (Math.random() > 0.5) {
      const braceGeo = new THREE.CylinderGeometry(0.2, 0.2, height * 0.7, 6);
      const brace = new THREE.Mesh(braceGeo, pillarMat);
      brace.position.set(pos.x, height / 2, pos.z);
      brace.rotation.z = Math.PI / 4;
      scene.add(brace);
