}

// --- Trees ---
const treeMat = new THREE.MeshStandardMaterial({ color: 0x2d5a1e, roughness: 0.9 });
const trunkMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.9 });

