  for (let j = 0; j < numPuffs; j++) {
    const puffGeo = new THREE.SphereGeometry(4 + Math.random() * 4, 8, 6);
    const puff = new THREE.Mesh(puffGeo, cloudMat);
    puff.position.set(j * 5, Math.random() * 2, Math.random() * 3);
