  cloudGroup.position.set(
    (Math.random() - 0.5) * 500,
    80 + Math.random() * 40,
    (Math.random() - 0.5) * 500
  );
  scene.add(cloudGroup);
}

// --- Animation ---
const clock = new THREE.Clock();
const totalLength = curve.getLength();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();
  const speed = 0.04;
  let t = (elapsed * speed) % 1;

  for (let i = 0; i < numCars; i++) {
    const carT = (t - i * carSpacing + 1) % 1;
    const pos = curve.getPointAt(carT);
    const tangent = curve.getTangentAt(carT);
    const lookTarget = pos.clone().add(tangent);

    cars[i].position.copy(pos);
    cars[i].lookAt(lookTarget);

    // Slight bank into turns
    const nextT = (carT + 0.01) % 1;
    const nextPos = curve.getPointAt(nextT);
    const nextTan = curve.getTangentAt(nextT);
    const curvature = tangent.clone().sub(nextTan).length();
    cars[i].rotation.z = -curvature * 8;
  }

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
