This creates a full 3D rollercoaster scene with:

- **Dual-rail track** — two parallel tube geometries along a closed CatmullRom spline path with hills, loops, and curves
- **Animated train** — 5 colorful cars with seats, safety bars, and wheels that follow the track with realistic banking into turns
- **Support pillars** — auto-generated columns beneath the track with cross braces
- **Station platform** — with a blue roof and support columns at the start
- **Environment** — green ground plane, 80 procedural trees, fluffy clouds, atmospheric fog
- **Lighting** — directional sun with soft shadows, hemisphere light, and ambient fill
- **OrbitControls** — drag to rotate, scroll to zoom, right-drag to pan

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Rope</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x111118);
scene.fog = new THREE.FogExp2(0x111118, 0.04);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 4, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Lighting ──
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 10, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 1.0);
rimLight.position.set(-5, 3, -5);
scene.add(rimLight);

// ── Rope Physics (Verlet Integration) ──
const SEGMENTS = 80;
const ROPE_LENGTH = 8;
const GRAVITY = 0.0015;
const DAMPING = 0.995;
const CONSTRAINT_ITERATIONS = 10;

class Rope {
  constructor() {
    this.points = [];
    this.prevPoints = [];
    this.anchors = new Set();
    this.constraints = [];

    // Initialize points hanging straight down
    for (let i = 0; i <= SEGMENTS; i++) {
      const t = i / SEGMENTS;
      const x = 0;
      const y = -t * ROPE_LENGTH;
      const z = 0;
      this.points.push(new THREE.Vector3(x, y, z));
      this.prevPoints.push(new THREE.Vector3(x, y, z));
    }

    // Anchor the top point
    this.anchors.add(0);

    // Create distance constraints between adjacent points
    for (let i = 0; i < SEGMENTS; i++) {
      this.constraints.push({
        a: i,
        b: i + 1,
        restLength: this.points[i + 1].distanceTo(this.points[i])
      });
    }

    // Build visual mesh
    this.geometry = new THREE.TubeGeometry(
      new THREE.CatmullRomCurve3(this.points),
      SEGMENTS * 2,
      0.045,
      8,
      false
    );

    this.material = new THREE.MeshStandardMaterial({
      color: 0xcc8844,
      roughness: 0.7,
      metalness: 0.1,
    });

    this.mesh = new THREE.Mesh(this.geometry, this.material);
    this.mesh.castShadow = true;
    this.mesh.receiveShadow = true;
    scene.add(this.mesh);

    // Anchor point visual
    const anchorGeo = new THREE.SphereGeometry(0.12, 16, 16);
    const anchorMat = new THREE.MeshStandardMaterial({
      color: 0x888899,
      roughness: 0.3,
      metalness: 0.8
    });
    this.anchorMesh = new THREE.Mesh(anchorGeo, anchorMat);
    this.anchorMesh.position.copy(this.points[0]);
    this.anchorMesh.castShadow = true;
    scene.add(this.anchorMesh);

    // Hook at bottom
    const hookGeo = new THREE.TorusGeometry(0.12, 0.03, 8, 16);
    this.hookMesh = new THREE.Mesh(hookGeo, anchorMat);
    this.hookMesh.castShadow = true;
    scene.add(this.hookMesh);
  }

  update() {
    // Verlet integration step
    for (let i = 0; i <= SEGMENTS; i++) {
      if (this.anchors.has(i)) continue;

      const p = this.points[i];
      const prev = this.prevPoints[i];

      const vx = (p.x - prev.x) * DAMPING;
      const vy = (p.y - prev.y) * DAMPING;
      const vz = (p.z - prev.z) * DAMPING;

      prev.copy(p);

      p.x += vx;
      p.y += vy + GRAVITY;
      p.z += vz;
    }

    // Satisfy distance constraints
    for (let iter = 0; iter < CONSTRAINT_ITERATIONS; iter++) {
      for (const c of this.constraints) {
        const pa = this.points[c.a];
        const pb = this.points[c.b];

        const dx = pb.x - pa.x;
        const dy = pb.y - pa.y;
        const dz = pb.z - pa.z;
        const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

        if (dist === 0) continue;

        const diff = (c.restLength - dist) / dist * 0.5;
        const ox = dx * diff;
        const oy = dy * diff;
        const oz = dz * diff;

        if (!this.anchors.has(c.a)) {
          pa.x -= ox;
          pa.y -= oy;
          pa.z -= oz;
        }
        if (!this.anchors.has(c.b)) {
          pb.x += ox;
          pb.y += oy;
          pb.z += oz;
        }
      }
    }

    // Update tube geometry
    const curve = new THREE.CatmullRomCurve3(this.points, false, 'catmullrom', 0.5);
    const newGeo = new THREE.TubeGeometry(curve, SEGMENTS * 2, 0.045, 8, false);
    this.mesh.geometry.dispose();
    this.mesh.geometry = newGeo;

    // Update hook position at bottom
    const lastPoint = this.points[SEGMENTS];
    this.hookMesh.position.copy(lastPoint);
    this.hookMesh.lookAt(lastPoint.x, lastPoint.y - 1, lastPoint.z);
  }

  // Apply a force to a specific segment
  applyForce(index, force) {
    if (index < 0 || index > SEGMENTS) return;
    const p = this.points[index];
    p.add(force);
  }

  // Get closest segment to a world-space point
  closestPoint(worldPos) {
    let minDist = Infinity;
    let closest = 0;
    for (let i = 0; i <= SEGMENTS; i++) {
      const d = worldPos.distanceTo(this.points[i]);
      if (d < minDist) { minDist = d; closest = i; }
    }
    return closest;
  }
}

const rope = new Rope();

// ── Floor ──
const floorGeo = new THREE.PlaneGeometry(40, 40);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x222233,
  roughness: 0.9,
  metalness: 0.1
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -ROPE_LENGTH - 0.5;
floor.receiveShadow = true;
scene.add(floor);

// Grid helper for depth perception
const grid = new THREE.GridHelper(30, 30, 0x333344, 0x222233);
grid.position.y = -ROPE_LENGTH - 0.49;
scene.add(grid);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, -2, 0);
controls.minDistance = 3;
controls.maxDistance = 25;

// ── Mouse interaction ──
const raycaster = new THREE.Raycaster();
const mouse = new THREE.Vector2();
let isDragging = false;
let dragIndex = 0;
let dragPlane = new THREE.Plane();
let dragOffset = new THREE.Vector3();

renderer.domElement.addEventListener('pointerdown', (e) => {
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;

  raycaster.setFromCamera(mouse, camera);
  rope.mesh.geometry.dispose(); // temporarily use points for picking
  const hit = raycaster.intersectObject(rope.mesh);

  if (hit.length > 0) {
    isDragging = true;
    controls.enabled = false;
    dragIndex = rope.closestPoint(hit[0].point);

    // Create drag plane facing camera at hit point
    const camDir = camera.getWorldDirection(new THREE.Vector3());
    dragPlane.setFromNormalAndCoplanarPoint(camDir, hit[0].point);
    dragOffset.copy(hit[0].point).sub(rope.points[dragIndex]);
  }
});

window.addEventListener('pointermove', (e) => {
  if (!isDragging) return;

  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;

  raycaster.setFromCamera(mouse, camera);
  const target = new THREE.Vector3();
  raycaster.ray.intersectPlane(dragPlane, target);

  if (target) {
    // Move the rope point toward the drag target
    const force = target.clone().sub(rope.points[dragIndex]).multiplyScalar(0.3);
    rope.applyForce(dragIndex, force);

    // Also pull nearby points for a softer feel
    const spread = 3;
    for (let j = 1; j <= spread; j++) {
      const factor = 0.3 / (j * j);
      if (dragIndex - j >= 0) rope.applyForce(dragIndex - j, force.clone().multiplyScalar(factor));
      if (dragIndex + j <= SEGMENTS) rope.applyForce(dragIndex + j, force.clone().multiplyScalar(factor));
    }
  }
});

window.addEventListener('pointerup', () => {
  isDragging = false;
  controls.enabled = true;
});

// ── Wind ──
let time = 0;
function applyWind() {
  time += 0.012;
  for (let i = 5; i <= SEGMENTS; i++) {
    const t = i / SEGMENTS;
    const windX = Math.sin(time * 1.5 + t * 3.0) * 0.0008 * t * t;
    const windZ = Math.cos(time * 1.2 + t * 2.5) * 0.0005 * t * t;
    rope.points[i].x += windX;
    rope.points[i].z += windZ;
  }
}

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// ── Animate ──
function animate() {
  requestAnimationFrame(animate);
  applyWind();
  rope.update();
  controls.update();
  renderer.render(scene, camera);
}
animate();
</script>
</body>
</html>
```

## What this gives you

| Feature | Detail |
