<script>
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a0a0a);
scene.fog = new THREE.FogExp2(0x1a0a0a, 0.02);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);
camera.lookAt(0, 1.5, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// Lighting
const ambientLight = new THREE.AmbientLight(0x331111, 0.5);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xffeedd, 1.5);
mainLight.position.set(5, 8, 5);
scene.add(mainLight);

const fillLight = new THREE.DirectionalLight(0xff8866, 0.6);
fillLight.position.set(-3, 2, -2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff4466, 1.5, 15);
rimLight.position.set(-2, 4, -3);
scene.add(rimLight);

const bottomLight = new THREE.PointLight(0xff6644, 0.8, 10);
bottomLight.position.set(0, -2, 2);
scene.add(bottomLight);

// Petal geometry builder
function createPetalGeometry(width, height, curl, segments = 32) {
  const geo = new THREE.BufferGeometry();
  const vertices = [];
  const normals = [];
  const uvs = [];
  const indices = [];

  for (let i = 0; i <= segments; i++) {
    const v = i / segments;
    const y = (v - 0.5) * height;

    for (let j = 0; j <= segments; j++) {
      const u = j / segments;
      const x = (u - 0.5) * width;

      // Width tapering - wider in the middle, narrow at base and tip
      const widthFactor = Math.sin(u * Math.PI);
      // Height tapering
      const heightFactor = Math.cos(v * Math.PI * 0.5);

      const px = x * widthFactor;
      const py = y;
      const pz = curl * Math.sin(u * Math.PI) * Math.cos(v * Math.PI * 0.5)
               + 0.1 * x * x * (1 - v * 2) * Math.sin(u * Math.PI);

      // Add subtle waviness to edges
      const edgeWarp = Math.sin(u * Math.PI * 3) * 0.03 * widthFactor;

      vertices.push(px + edgeWarp, py, pz);

      // Approximate normal
      const nx = -curl * 0.5 * Math.cos(v * Math.PI * 0.5);
      const nz = 1.0;
      const len = Math.sqrt(nx * nx + nz * nz);
      normals.push(nx / len, 0, nz / len);

      uvs.push(u, v);
    }
  }

  for (let i = 0; i < segments; i++) {
    for (let j = 0; j < segments; j++) {
      const a = i * (segments + 1) + j;
      const b = a + 1;
      const c = (i + 1) * (segments + 1) + j;
      const d = c + 1;
      indices.push(a, b, c);
      indices.push(b, d, c);
    }
  }

  geo.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
  geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  geo.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  geo.setIndex(indices);
  geo.computeVertexNormals();
  return geo;
}

// Build the rose
const roseGroup = new THREE.Group();
scene.add(roseGroup);

const petalColors = [
  0x8B0000, 0x9B1B30, 0xA52A2A, 0xB22222, 0x800020,
  0x722F37, 0x6B0F1A, 0x5C1A1B, 0x8B1A1A, 0x991111
];

// Create petals in overlapping layers
function createPetal(index, totalInRing, ringIndex) {
  const petalGeo = createPetalGeometry(
    0.6 + ringIndex * 0.15,
    1.2 + ringIndex * 0.2,
    0.15 + ringIndex * 0.05
  );

  const colorIdx = (index + ringIndex * 3) % petalColors.length;
  const mat = new THREE.MeshStandardMaterial({
    color: petalColors[colorIdx],
    roughness: 0.6,
    metalness: 0.05,
    side: THREE.DoubleSide,
    transparent: true,
    opacity: 0.92,
  });

  const petal = new THREE.Mesh(petalGeo, mat);
  const angle = (index / totalInRing) * Math.PI * 2 + ringIndex * 0.3;
  const tilt = 0.3 + ringIndex * 0.15;

  petal.rotation.x = tilt;
  petal.rotation.z = Math.sin(angle) * 0.2;
  petal.rotation.y = angle;
  petal.position.y = 2.2 + ringIndex * 0.15;

  const scale = 0.6 + ringIndex * 0.12;
  petal.scale.set(scale, scale, scale);

  return petal;
}

// Inner petals (tight spiral)
for (let ring = 0; ring < 4; ring++) {
  const petalsInRing = 5 + ring * 2;
  for (let i = 0; i < petalsInRing; i++) {
    const petal = createPetal(i, petalsInRing, ring);
    roseGroup.add(petal);
  }
}

// Stem
const stemGeo = new THREE.CylinderGeometry(0.04, 0.06, 3.5, 12);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x2d5a1e,
  roughness: 0.8,
  metalness: 0.0,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.y = 0.5;
roseGroup.add(stem);

// Leaves
function createLeaf(side) {
  const leafGeo = new THREE.BufferGeometry();
  const verts = [];
  const norms = [];
  const uvsArr = [];
  const idxs = [];
  const segs = 20;

  for (let i = 0; i <= segs; i++) {
    const v = i / segs;
    const y = v * 0.8;
    const width = Math.sin(v * Math.PI) * 0.35;

    for (let j = 0; j <= 8; j++) {
      const u = j / 8;
      const x = (u - 0.5) * 2 * width;
      const z = 0.02 * Math.sin(u * Math.PI) * Math.sin(v * Math.PI);

      verts.push(x, y, z);
      norms.push(0, 0, 1);
      uvsArr.push(u, v);
    }
  }

  for (let i = 0; i < segs; i++) {
    for (let j = 0; j < 8; j++) {
      const a = i * 9 + j;
      const b = a + 1;
      const c = (i + 1) * 9 + j;
      const d = c + 1;
      idxs.push(a, b, c, b, d, c);
    }
  }

  leafGeo.setAttribute('position', new THREE.Float32BufferAttribute(verts, 3));
  leafGeo.setAttribute('normal', new THREE.Float32BufferAttribute(norms, 3));
  leafGeo.setAttribute('uv', new THREE.Float32BufferAttribute(uvsArr, 2));
  leafGeo.setIndex(idxs);
  leafGeo.computeVertexNormals();

  const leafMat = new THREE.MeshStandardMaterial({
    color: 0x2d6b1e,
    roughness: 0.7,
    metalness: 0.0,
    side: THREE.DoubleSide,
  });

  const leaf = new THREE.Mesh(leafGeo, leafMat);
  leaf.position.set(side * 0.15, 0.8, 0);
  leaf.rotation.set(
    -0.3,
    side * 0.8,
    side * 0.5
  );
  return leaf;
}

roseGroup.add(createLeaf(1));
roseGroup.add(createLeaf(-1));

// Second pair of leaves lower down
const leaf2 = createLeaf(1);
leaf2.position.set(0.12, 0.2, 0);
leaf2.rotation.set(-0.2, 1.2, 0.6);
leaf2.scale.setScalar(0.8);
roseGroup.add(leaf2);

const leaf3 = createLeaf(-1);
leaf3.position.set(-0.12, 0.2, 0);
leaf3.rotation.set(-0.2, -1.2, -0.6);
leaf3.scale.setScalar(0.8);
roseGroup.add(leaf3);

// Thorns
function createThorn(x, y, z, rotZ) {
  const thornGeo = new THREE.ConeGeometry(0.015, 0.12, 6);
  const thornMat = new THREE.MeshStandardMaterial({ color: 0x3a6b2a, roughness: 0.8 });
  const thorn = new THREE.Mesh(thornGeo, thornMat);
  thorn.position.set(x, y, z);
  thorn.rotation.z = rotZ;
  return thorn;
}

roseGroup.add(createThorn(0.06, 1.2, 0, -0.5));
roseGroup.add(createThorn(-0.06, 0.9, 0.02, 0.5));
roseGroup.add(createThorn(0.05, 0.5, -0.02, -0.4));

// Position the rose
roseGroup.position.y = -0.5;

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle rotation
  roseGroup.rotation.y = Math.sin(t * 0.3) * 0.3;
  roseGroup.rotation.x = Math.sin(t * 0.2) * 0.05;

  // Subtle petal breathing
  roseGroup.children.forEach((child, i) => {
    if (child.geometry && child.geometry.type === 'BufferGeometry' &&
        !child.geometry.parameters && child.material.color.getHex() > 0x400000) {
      child.rotation.x += Math.sin(t * 0.5 + i * 0.5) * 0.0003;
    }
  });

  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
