  const geo = new THREE.PlaneGeometry(0.85, 0.42);
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(xPos, RULER_THICK / 2 + 0.005, -RULER_WIDTH / 2 + 0.55);
  mesh.rotation.x = -Math.PI / 2;
  parent.add(mesh);
}

/* ───────── build ruler ───────── */
function buildRuler(mode) {
  // remove old
  while (rulerGroup.children.length) {
    const c = rulerGroup.children[0];
    if (c.geometry) c.geometry.dispose();
    if (c.material) {
      if (c.material.map) c.material.map.dispose();
      c.material.dispose();
    }
    rulerGroup.remove(c);
  }

  const bodyMat = new THREE.MeshStandardMaterial({
    color: 0xd4a843, roughness: 0.35, metalness: 0.55
  });

  // main body
  const bodyGeo = new THREE.BoxGeometry(RULER_LENGTH, RULER_THICK, RULER_WIDTH);
  const body = new THREE.Mesh(bodyGeo, bodyMat);
  body.castShadow = true;
  body.receiveShadow = true;
  rulerGroup.add(body);

  // bevel edges (thin strips)
  const edgeMat = new THREE.MeshStandardMaterial({ color: 0xc49833, roughness: 0.3, metalness: 0.6 });
  const edgeH = 0.06;

  // top edge along length
  const topEdgeGeo = new THREE.BoxGeometry(RULER_LENGTH, edgeH, RULER_WIDTH + 0.02);
  const topEdge = new THREE.Mesh(topEdgeGeo, edgeMat);
  topEdge.position.y = RULER_THICK / 2 + edgeH / 2;
  topEdge.castShadow = true;
  rulerGroup.add(topEdge);

  // bottom edge
  const botEdge = topEdge.clone();
  botEdge.position.y = -(RULER_THICK / 2 + edgeH / 2);
  rulerGroup.add(botEdge);

  // side edges
  const sideGeo = new THREE.BoxGeometry(RULER_LENGTH + 0.02, edgeH, 0.06);
  [-1, 1].forEach(s => {
    const se = new THREE.Mesh(sideGeo, edgeMat);
    se.position.set(0, RULER_THICK / 2 + edgeH / 2, s * (RULER_WIDTH / 2 + 0.03));
    rulerGroup.add(se);
  });

  const half = RULER_LENGTH / 2;
  const tickBaseH = 0.12;

  if (mode === 'cm') {
    /* ─── centimeter side ─── */
    for (let i = 0; i <= 300; i++) {
      const cm = i / 10;
      const xPos = cm - half;
      let depth, h;
      if (i % 10 === 0) {
        // major tick (cm)
        depth = 0.35; h = tickBaseH + 0.2;
        addNumberLabel(cm, xPos, rulerGroup, 72, 256, 128);
      } else if (i % 5 === 0) {
        depth = 0.25; h = tickBaseH + 0.12;
      } else {
        depth = 0.15; h = tickBaseH;
      }
      addTick(xPos, depth, 0.035, h, rulerGroup);
    }

    // "cm" label
    const cmTex = makeCanvasTexture('cm', 48, 128, 128, 'transparent', '#ffcc44');
    const cmMat = new THREE.MeshBasicMaterial({ map: cmTex, transparent: true, depthWrite: false });
    const cmPlane = new THREE.Mesh(new THREE.PlaneGeometry(0.6, 0.3), cmMat);
    cmPlane.position.set(half - 0.8, RULER_THICK / 2 + 0.005, -RULER_WIDTH / 2 + 0.25);
    cmPlane.rotation.x = -Math.PI / 2;
    rulerGroup.add(cmPlane);

  } else {
    /* ─── inches side ─── */
    const totalInches = RULER_LENGTH * 0.393701; // cm to inches
    const tickSpacing = 1 / 16; // 16th-inch precision

    for (let i = 0; i <= totalInches * 16; i++) {
      const inches = i * tickSpacing;
      if (inches > RULER_LENGTH * 0.5 + 0.1) break;
      const xPos = inches - half;
      let depth, h;
      if (i % 16 === 0) {
        depth = 0.35; h = tickBaseH + 0.2;
        const wholeInch = Math.round(inches * 1000) / 1000;
        addNumberLabel(String(wholeInch), xPos, rulerGroup, 72, 256, 128);
      } else if (i % 8 === 0) {
        depth = 0.25; h = tickBaseH + 0.12;
      } else if (i % 4 === 0) {
        depth = 0.20; h = tickBaseH + 0.06;
      } else {
        depth = 0.12; h = tickBaseH * 0.7;
      }
      addTick(xPos, depth, 0.035, h, rulerGroup);
    }

    const inTex = makeCanvasTexture('in', 48, 128, 128, 'transparent', '#ffcc44');
    const inMat = new THREE.MeshBasicMaterial({ map: inTex, transparent: true, depthWrite: false });
    const inPlane = new THREE.Mesh(new THREE.PlaneGeometry(0.6, 0.3), inMat);
    inPlane.position.set(half - 0.8, RULER_THICK / 2 + 0.005, -RULER_WIDTH / 2 + 0.25);
    inPlane.rotation.x = -Math.PI / 2;
    rulerGroup.add(inPlane);
  }

  // decorative holes at ends
  [-1, 1].forEach(s => {
    const holeGeo = new THREE.TorusGeometry(0.18, 0.04, 12, 24);
    const holeMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.2, metalness: 0.9 });
    const hole = new THREE.Mesh(holeGeo, holeMat);
    hole.position.set(s * (half - 0.5), RULER_THICK / 2 + 0.005, 0);
    hole.rotation.x = -Math.PI / 2;
    rulerGroup.add(hole);
  });
}

const rulerGroup = new THREE.Group();
rulerGroup.position.y = 1.2;
rulerGroup.rotation.x = -0.15;
scene.add(rulerGroup);
buildRuler(currentMode);

/* ───────── toggle button ───────── */
document.getElementById('toggle').addEventListener('click', () => {
  currentMode = currentMode === 'cm' ? 'inches' : 'cm';
  buildRuler(currentMode);
  document.getElementById('toggle').textContent =
    currentMode === 'cm' ? 'Switch to Inches' : 'Switch to cm';
});

/* ───────── resize ───────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

/* ───────── animation ───────── */
function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
}
animate();
</script>
</body>
</html>
```

**What you get:**

- **A 30 cm metallic gold ruler** rendered in Three.js with realistic proportions
- **Centimeter mode** — major ticks every 1 cm (numbered), medium ticks at 0.5 cm, fine ticks at 0.1 cm
- **Inches mode** — toggle via the button; ticks at 1/16″ resolution with numbered whole-inch marks
- **Number labels** rendered as canvas textures projected onto the ruler surface
- **Decorative end holes** (torus geometry) for a hole-punch look
- **Beveled edges** via thin strip meshes along all four edges
- **Three-point lighting** (key, fill, rim) with soft PCF shadows on a dark ground plane
- **OrbitControls** — drag to rotate, scroll to zoom, right-drag to pan
- **ACES filmic tone mapping** and subtle fog for atmosphere

