<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js" } }
</script>
<script type="module">
import * as THREE from 'three';

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0.5, 6);

// — Lighting —
scene.add(new THREE.AmbientLight(0x404060, 0.8));
const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(3, 5, 4);
scene.add(key);
const fill = new THREE.DirectionalLight(0x6688cc, 1.0);
fill.position.set(-4, 2, -2);
scene.add(fill);
const rim = new THREE.PointLight(0xff8866, 1.5, 12);
rim.position.set(-2, 3, -3);
scene.add(rim);

// — Scarf geometry —
const W = 4, H = 0.8, SW = 80, SH = 16;
const geo = new THREE.PlaneGeometry(W, H, SW, SH);
geo.rotateX(-Math.PI / 2);

// — Scarf material (two-tone for fold visibility) —
const mat = new THREE.MeshStandardMaterial({
  color: 0x8b2252,
  roughness: 0.85,
  metalness: 0.0,
  side: THREE.DoubleSide,
});

const scarf = new THREE.Mesh(geo, mat);
scene.add(scarf);

// — Fringe —
const fringeCount = 30;
const fringeGeo = new THREE.BufferGeometry();
const fVerts = [];
for (let i = 0; i < fringeCount; i++) {
  const t = i / (fringeCount - 1);
  const x = -W / 2 + t * W;
  const baseY = H / 2 + 0.02;
  // each fringe strand: 3 segments = 4 verts
  for (let s = 0; s < 3; s++) {
    fVerts.push(x - 0.015, baseY + s * 0.06, 0);
    fVerts.push(x + 0.015, baseY + s * 0.06, 0);
  }
}
const fIdx = [];
for (let i = 0; i < fringeCount; i++) {
  const a = i * 6, b = i * 6 + 1, c = i * 6 + 2, d = i * 6 + 3;
  fIdx.push(a, b, b, c, b, d, a, d, a, c, c, d);
}
fringeGeo.setAttribute('position', new THREE.Float32BufferAttribute(fVerts, 3));
fringeGeo.setIndex(fIdx);
fringeGeo.computeVertexNormals();
const fringe = new THREE.Mesh(fringeGeo, mat);
scene.add(fringe);

// — Animate —
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);   // actually Z in world, but local Y in plane
    const z = pos.getZ(i);

    // Primary drape wave
    const drape = Math.sin(x * 1.8 + t * 0.7) * 0.35
                + Math.sin(x * 3.2 + t * 1.1) * 0.12
                + Math.cos(x * 0.9 + t * 0.4) * 0.2;

    // Secondary flutter (along width)
    const flutter = Math.sin(y * 6 + t * 2.0) * 0.04 * Math.cos(x * 1.5);

    // Twist
    const twist = y * Math.sin(x * 0.8 + t * 0.5) * 0.3;

    pos.setZ(i, z + drape + flutter);
    pos.setX(i, x + twist * 0.1);
    pos.setY(i, y + drape * 0.3);
  }
  pos.needsUpdate = true;
  geo.computeVertexNormals();

  // Subtle camera sway
  camera.position.x = Math.sin(t * 0.15) * 0.5;
  camera.position.y = 0.5 + Math.sin(t * 0.2) * 0.2;
  camera.lookAt(0, 0, 0);

  renderer.render(scene, camera);
}
animate();

addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
