const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0, 0);

/* ── lights ── */
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 6);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 1;
keyLight.shadow.camera.far = 30;
keyLight.shadow.camera.left = -5;
keyLight.shadow.camera.right = 5;
keyLight.shadow.camera.top = 5;
keyLight.shadow.camera.bottom = -5;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffffff, 1.0);
rimLight.position.set(0, -2, -6);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffaa44, 0.8, 20);
pointLight.position.set(-3, 4, 2);
scene.add(pointLight);

/* ── materials ── */
const steelMaterial = new THREE.MeshStandardMaterial({
  color: 0xccccdd,
  metalness: 0.95,
  roughness: 0.12,
  envMapIntensity: 1.0,
});

const darkSteelMaterial = new THREE.MeshStandardMaterial({
  color: 0x888899,
  metalness: 0.9,
  roughness: 0.25,
});

const handleMaterial = new THREE.MeshStandardMaterial({
  color: 0x2244aa,
  metalness: 0.3,
  roughness: 0.45,
});

const handleMaterial2 = new THREE.MeshStandardMaterial({
  color: 0xcc3333,
  metalness: 0.3,
  roughness: 0.45,
});

const pivotMaterial = new THREE.MeshStandardMaterial({
  color: 0xaaaaaa,
  metalness: 0.95,
  roughness: 0.08,
});

/* ── env map (simple procedural) ── */
const pmremGenerator = new THREE.PMREMGenerator(renderer);
const envScene = new THREE.Scene();
envScene.background = new THREE.Color(0x303050);
const envLight1 = new THREE.DirectionalLight(0xffffff, 3);
envLight1.position.set(5, 5, 5);
envScene.add(envLight1);
const envLight2 = new THREE.DirectionalLight(0x8888ff, 2);
envLight2.position.set(-5, 3, -5);
envScene.add(envLight2);
const envRT = pmremGenerator.fromScene(envScene);
scene.environment = envRT.texture;

/* ── build one half of scissors ── */
function createScissorHalf(handleMat, mirrorX = false) {
  const half = new THREE.Group();

  // Blade length and proportions
  const bladeLength = 3.0;
  const bladeWidth = 0.22;
  const bladeThickness = 0.06;
  const handleRadius = 0.55;
  const handleTubeRadius = 0.14;

  /* Blade — custom shape that tapers to a point with a slight curve */
  const bladeShape = new THREE.Shape();
  bladeShape.moveTo(0, 0);
  bladeShape.lineTo(bladeLength * 0.85, -bladeWidth);
  bladeShape.lineTo(bladeLength, 0);
  bladeShape.lineTo(bladeLength * 0.85, bladeWidth);
  bladeShape.lineTo(0, 0);

  const bladeExtrudeSettings = { depth: bladeThickness, bevelEnabled: true, bevelThickness: 0.015, bevelSize: 0.015, bevelSegments: 3 };
  const bladeGeo = new THREE.ExtrudeGeometry(bladeShape, bladeExtrudeSettings);
  bladeGeo.center();

  const blade = new THREE.Mesh(bladeGeo, steelMaterial);
  blade.rotation.x = Math.PI / 2;
  // Center the blade so the pivot is at origin
  blade.position.set(0, 0, 0);
  half.add(blade);

  /* Handle ring — torus */
  const handleGeo = new THREE.TorusGeometry(handleRadius, handleTubeRadius, 24, 48);
  const handle = new THREE.Mesh(handleGeo, handleMat);
  handle.position.set(-1.4, 0, 0);
  handle.rotation.y = Math.PI / 2;
  half.add(handle);

  /* Finger guard — small cylinder between blade and handle */
  const guardGeo = new THREE.CylinderGeometry(0.12, 0.12, 0.5, 16);
  const guard = new THREE.Mesh(guardGeo, darkSteelMaterial);
  guard.rotation.z = Math.PI / 2;
  guard.position.set(-0.6, 0, 0);
  half.add(guard);

  /* Inner handle crossbar */
  const crossbarGeo = new THREE.CylinderGeometry(0.04, 0.04, handleRadius * 1.6, 12);
  const crossbar = new THREE.Mesh(crossbarGeo, handleMat);
  crossbar.rotation.z = Math.PI / 2;
  crossbar.position.set(-1.4, 0, 0);
  half.add(crossbar);

  /* Pivot collar (the part that goes around the pivot bolt) */
  const collarGeo = new THREE.CylinderGeometry(0.2, 0.2, 0.15, 24);
  const collar = new THREE.Mesh(collarGeo, darkSteelMaterial);
  collar.rotation.z = Math.PI / 2;
  collar.position.set(0, 0, 0);
  half.add(collar);

  if (mirrorX) {
    half.scale.x = -1;
  }

  return half;
}

/* ── assemble scissors ── */
const scissorsGroup = new THREE.Group();

const half1 = createScissorHalf(handleMaterial, false);
const half2 = createScissorHalf(handleMaterial2, true);

// Open angle for the scissors
const openAngle = 0.35;
half1.rotation.z = openAngle;
half2.rotation.z = -openAngle;

scissorsGroup.add(half1);
scissorsGroup.add(half2);

/* Pivot bolt */
const pivotBoltGeo = new THREE.CylinderGeometry(0.08, 0.08, 0.45, 24);
const pivotBolt = new THREE.Mesh(pivotBoltGeo, pivotMaterial);
pivotBolt.rotation.z = Math.PI / 2;
scissorsGroup.add(pivotBolt);

/* Pivot nut (small hexagonal nut on the other side) */
const nutGeo = new THREE.CylinderGeometry(0.14, 0.14, 0.1, 6);
const nut = new THREE.Mesh(nutGeo, pivotMaterial);
nut.rotation.z = Math.PI / 2;
nut.position.set(0, 0, -0.28);
scissorsGroup.add(nut);

/* Pivot washer */
const washerGeo = new THREE.TorusGeometry(0.12, 0.03, 8, 24);
const washer = new THREE.Mesh(washerGeo, pivotMaterial);
washer.position.set(0, 0, 0.24);
scissorsGroup.add(washer);

// Tilt the whole scissors group slightly for a nice viewing angle
scissorsGroup.rotation.x = 0.15;
scissorsGroup.rotation.y = -0.3;
scene.add(scissorsGroup);

/* ── ground plane (subtle) ── */
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e,
  metalness: 0.5,
  roughness: 0.8,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -3.5;
ground.receiveShadow = true;
scene.add(ground);

/* ── subtle floating particles ── */
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 12;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0x6688cc,
  size: 0.04,
  transparent: true,
  opacity: 0.5,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

/* ── animation ── */
let time = 0;

function animate() {
  requestAnimationFrame(animate);
  time += 0.008;

  // Gentle floating animation
  scissorsGroup.position.y = Math.sin(time * 1.2) * 0.15;

  // Very slow rotation
  scissorsGroup.rotation.y = -0.3 + Math.sin(time * 0.4) * 0.15;

  // Subtle scissors opening/closing animation
  const bladeAngle = openAngle + Math.sin(time * 0.8) * 0.08;
  half1.rotation.z = bladeAngle;
  half2.rotation.z = -bladeAngle;

  // Particles drift
  particles.rotation.y = time * 0.02;
  particles.position.y = Math.sin(time * 0.3) * 0.2;

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ── resize ── */
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});
</script>
</body>
</html>
