<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.08);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 2.5, 3);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.3, 0);
controls.enableDamping = true;
controls.update();

// --- Lighting ---
scene.add(new THREE.AmbientLight(0x404060, 0.8));

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 4);
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffa060, 1.5, 15);
rimLight.position.set(-2, 1, -3);
scene.add(rimLight);

// --- Seashell Geometry (Logarithmic Spiral Conch) ---
function createShellGeometry(turns = 3, segments = 120, rings = 60) {
  const positions = [];
  const normals = [];
  const uvs = [];
  const indices = [];

  const a = 0.15;          // initial radius
  const b = 0.25;          // growth rate
  const hRate = 0.08;      // vertical rise per radian
  const tubeA = 0.08;      // initial tube radius
  const tubeB = 0.004;     // tube growth rate

  const maxU = turns * Math.PI * 2;

  for (let i = 0; i <= segments; i++) {
    const u = (i / segments) * maxU;

    // Spiral center path
    const R = a * Math.exp(b * u);
    const cx = R * Math.cos(u);
    const cz = R * Math.sin(u);
    const cy = hRate * u - 0.3;

    // Tube radius grows along spiral
    const tubeR = tubeA + tubeB * Math.exp(b * u * 0.5);

    // Local basis vectors for the spiral curve
    const eps = 0.001;
    const u2 = u + eps;
    const R2 = a * Math.exp(b * u2);
    const dx = R2 * Math.cos(u2) - cx;
    const dy = hRate * eps;
    const dz = R2 * Math.sin(u2) - cz;
    const len = Math.sqrt(dx * dx + dy * dy + dz * dz);
    const tx = dx / len, ty = dy / len, tz = dz / len;

    // Build orthonormal frame (binormal, normal)
    let bx = 0, by = 1, bz = 0;
    if (Math.abs(ty) > 0.9) { bx = 1; by = 0; bz = 0; }
    const binLen = Math.sqrt(
      (ty * bz - tz * by) ** 2 +
      (tz * bx - tx * bz) ** 2 +
      (tx * by - ty * bx) ** 2
    );
    const nx = (ty * bz - tz * by) / binLen;
    const ny = (tz * bx - tx * bz) / binLen;
    const nz = (tx * by - ty * bx) / binLen;
    const ox = (ty * nz - tz * ny) / binLen;
    const oy = (tz * nx - tx * nz) / binLen;
    const oz = (tx * ny - ty * nx) / binLen;

    // Shell opening: cross-section is elliptical, wider on the outside
    const openingFactor = 0.3 + 0.7 * (u / maxU);

    for (let j = 0; j <= rings; j++) {
      const v = (j / rings) * Math.PI * 2;
      const cosV = Math.cos(v);
      const sinV = Math.sin(v);

      // Elliptical cross-section that opens outward
      const rOut = tubeR * (1 + 0.6 * Math.max(0, sinV)) * (0.5 + 0.5 * openingFactor);
      const rIn = tubeR * (0.5 + 0.5 * openingFactor);

      // Blend between inner and outer radius based on angle
      const r = rIn + (rOut - rIn) * Math.max(0, sinV);

      // Offset from center
      const oxOff = r * (nx * cosV + ox * sinV);
      const oyOff = r * (ny * cosV + oy * sinV);
      const ozOff = r * (nz * cosV + oz * sinV);

      positions.push(cx + oxOff, cy + oyOff, cz + ozOff);

      // Approximate normal
      const nx2 = oxOff / (r + 0.001);
      const ny2 = oyOff / (r + 0.001);
      const nz2 = ozOff / (r + 0.001);
      const nLen = Math.sqrt(nx2 * nx2 + ny2 * ny2 + nz2 * nz2);
      normals.push(nx2 / nLen, ny2 / nLen, nz2 / nLen);

      uvs.push(i / segments, j / rings);
    }
  }

  for (let i = 0; i < segments; i++) {
    for (let j = 0; j < rings; j++) {
      const a = i * (rings + 1) + j;
      const b2 = a + rings + 1;
      indices.push(a, b2, a + 1);
      indices.push(b2, b2 + 1, a + 1);
    }
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  geo.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  geo.setIndex(indices);
  geo.computeVertexNormals();
  return geo;
}

// --- Shell Material ---
const shellMaterial = new THREE.MeshStandardMaterial({
  color: 0xf5e6d3,
  roughness: 0.45,
  metalness: 0.05,
  side: THREE.DoubleSide,
});

// Add subtle color variation via vertex colors
const shellGeo = createShellGeometry(3.2, 140, 50);
const count = shellGeo.attributes.position.count;
const colors = new Float32Array(count * 3);
const pos = shellGeo.attributes.position.array;

for (let i = 0; i < count; i++) {
  const y = pos[i * 3 + 1];
  const dist = Math.sqrt(pos[i * 3] ** 2 + pos[i * 3 + 2] ** 2);

  // Warm cream base with pink/peach tones, darker near edges
  const t = Math.min(1, dist / 2.5);
  colors[i * 3]     = 0.96 - t * 0.12 + Math.random() * 0.02;
  colors[i * 3 + 1] = 0.84 - t * 0.15 + Math.random() * 0.02;
  colors[i * 3 + 2] = 0.72 - t * 0.12 + Math.random() * 0.02;
}
shellGeo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));

shellMaterial.vertexColors = true;
shellMaterial.roughness = 0.4;

const shell = new THREE.Mesh(shellGeo, shellMaterial);
shell.position.y = 0.1;
scene.add(shell);

// --- Subtle ground plane ---
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e,
  roughness: 1,
  metalness: 0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.6;
scene.add(ground);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  shell.rotation.y = t * 0.15;
  shell.position.y = 0.1 + Math.sin(t * 0.5) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
