const matWood = new THREE.MeshStandardMaterial({ color: 0xc49a6c, roughness: 0.7 });
const matFulcrum = new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.4, metalness: 0.6 });
const matGround = new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 0.9 });
const matRed = new THREE.MeshStandardMaterial({ color: 0xe74c3c, roughness: 0.5 });
const matBlue = new THREE.MeshStandardMaterial({ color: 0x3498db, roughness: 0.5 });
const matSkin = new THREE.MeshStandardMaterial({ color: 0xffcc99, roughness: 0.6 });
const matPants = new THREE.MeshStandardMaterial({ color: 0x2c3e50, roughness: 0.7 });
