);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Fulcrum Base (triangular prism) ──
const fulcrumGroup = new THREE.Group();

// Triangular base
const triGeo = new THREE.CylinderGeometry(0.6, 0.6, 1.4, 3);
const fulcrum = new THREE.Mesh(triGeo, matFulcrum);
fulcrum.position.y = 0.7;
fulcrum.castShadow = true;
fulcrum.receiveShadow = true;
fulcrumGroup.add(fulcrum);

// Top pivot cylinder
const pivotGeo = new THREE.CylinderGeometry(0.12, 0.12, 0.15, 16);
const pivot = new THREE.Mesh(pivotGeo, matFulcrum);
pivot.position.y = 1.45;
pivot.castShadow = true;
