const leftSeat = createSeat(-3.2, matRed);
const rightSeat = createSeat(3.2, matBlue);
plankGroup.add(leftSeat, rightSeat);

// ── Simple Figures ──
function createFigure(x, headColor, shirtColor) {
  const figure = new THREE.Group();
  figure.position.set(x, 0, 0);

  // Body
  const body = new THREE.Mesh(
