  const group = new THREE.Group();
  const cloudMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 1, flatShading: true });
  const counts = 3 + Math.floor(Math.random() * 3);
  for (let i = 0; i < counts; i++) {
    const s = 0.5 + Math.random() * 0.8;
    const puff = new THREE.Mesh(new THREE.SphereGeometry(s, 8, 6), cloudMat);
    puff.position.set(i * 0.7 - counts * 0.35, Math.random() * 0.3, Math.random() * 0.4);
    group.add(puff);
