const topY = h / 2, botY = -h / 2, sideX = w / 2;

shieldShape.moveTo(0, topY);
shieldShape.bezierCurveTo(sideX * 0.85, topY, sideX, topY * 0.5, sideX, topY * 0.05);
shieldShape.bezierCurveTo(sideX, botY * 0.4, 0, botY * 1.05, 0, botY);
shieldShape.bezierCurveTo(0, botY * 1.05, -sideX, botY * 0.4, -sideX, topY * 0.05);
shieldShape.bezierCurveTo(-sideX, topY * 0.5, -sideX * 0.85, topY, 0, topY);

// --- Extrusion Settings ---
const extrudeSettings = { depth: 0.15, bevelEnabled: true, bevelThickness: 0.06, bevelSize: 0.06, bevelSegments: 4 };
const shieldGeom = new THREE.ExtrudeGeometry(shieldShape, extrudeSettings);
shieldGeom.center();

