  color: 0xcc3333,
  metalness: 0.6,
  roughness: 0.3,
  side: THREE.DoubleSide,
});

const shield = new THREE.Mesh(shieldGeom, shieldMat);
scene.add(shield);

// --- Shield Border / Rim ---
const borderShape = new THREE.Shape();
borderShape.moveTo(0, topY);
borderShape.bezierCurveTo(sideX * 0.85, topY, sideX, topY * 0.5, sideX, topY * 0.05);
borderShape.bezierCurveTo(sideX, botY * 0.4, 0, botY * 1.05, 0, botY);
borderShape.bezierCurveTo(0, botY * 1.05, -sideX, botY * 0.4, -sideX, topY * 0.05);
borderShape.bezierCurveTo(-sideX, topY * 0.5, -sideX * 0.85, topY, 0, topY);

const holeShape = new THREE.Shape();
const m = 0.18;
holeShape.moveTo(0, topY - m);
holeShape.bezierCurveTo((sideX - m) * 0.85, topY - m, sideX - m, (topY - m) * 0.5, sideX - m, (topY - m) * 0.05);
holeShape.bezierCurveTo(sideX - m, (botY + m) * 0.4, 0, (botY + m) * 1.05, 0, botY + m);
holeShape.bezierCurveTo(0, (botY + m) * 1.05, -(sideX - m), (botY + m) * 0.4, -(sideX - m), (topY - m) * 0.05);
holeShape.bezierCurveTo(-(sideX - m), (topY - m) * 0.5, -(sideX - m) * 0.85, topY - m, 0, topY - m);

borderShape.holes.push(holeShape);

const borderGeom = new THREE.ExtrudeGeometry(borderShape, { depth: 0.22, bevelEnabled: true, bevelThickness: 0.03, bevelSize: 0.03, bevelSegments: 2 });
borderGeom.center();

