const fillLight = new THREE.DirectionalLight(0xc8ddf5, 0.4);
fillLight.position.set(-5, 3, -4);
scene.add(fillLight);

// ── Materials ──
const woolMat = new THREE.MeshStandardMaterial({
  color: 0xF5F0E8,
  roughness: 0.95,
  metalness: 0.0,
});

const skinMat = new THREE.MeshStandardMaterial({
  color: 0x2C2C2C,
  roughness: 0.7,
  metalness: 0.05,
});

const legMat = new THREE.MeshStandardMaterial({
  color: 0x3D2B1F,
  roughness: 0.8,
  metalness: 0.0,
});

const eyeWhiteMat = new THREE.MeshStandardMaterial({
  color: 0xFFFFFF,
  roughness: 0.3,
});

const eyePupilMat = new THREE.MeshStandardMaterial({
  color: 0x111111,
  roughness: 0.2,
});

const noseMat = new THREE.MeshStandardMaterial({
  color: 0x4A3728,
  roughness: 0.6,
});

const innerEarMat = new THREE.MeshStandardMaterial({
  color: 0x8B6F5E,
  roughness: 0.7,
});

// ── Sheep Group ──
const sheep = new THREE.Group();

// ── Body (woolly) ──
const bodyGeo = new THREE.SphereGeometry(1.4, 32, 32);
const body = new THREE.Mesh(bodyGeo, woolMat);
body.scale.set(1, 0.85, 1.2);
body.position.set(0, 2.0, 0);
body.castShadow = true;
body.receiveShadow = true;
sheep.add(body);

// Extra wool tufts on body
const tuftPositions = [
  { x: 0.6, y: 2.8, z: 0.3, s: 0.45 },
  { x: -0.5, y: 2.9, z: 0.5, s: 0.4 },
  { x: 0.3, y: 2.7, z: -0.6, s: 0.35 },
  { x: -0.7, y: 2.5, z: 0.2, s: 0.38 },
  { x: 0.8, y: 2.4, z: -0.4, s: 0.42 },
  { x: 0, y: 3.0, z: 0, s: 0.5 },
  { x: -0.3, y: 2.6, z: -0.8, s: 0.33 },
  { x: 0.5, y: 2.5, z: 0.7, s: 0.36 },
  { x: -0.9, y: 2.7, z: -0.3, s: 0.34 },
  { x: 0.2, y: 2.3, z: 0.9, s: 0.4 },
];

tuftPositions.forEach(t => {
  const tuft = new THREE.Mesh(
    new THREE.SphereGeometry(t.s, 12, 12),
    woolMat
  );
  tuft.position.set(t.x, t.y, t.z);
  tuft.castShadow = true;
  sheep.add(tuft);
});

// ── Neck ──
const neckGeo = new THREE.CylinderGeometry(0.55, 0.75, 0.8, 16);
const neck = new THREE.Mesh(neckGeo, woolMat);
neck.position.set(0, 1.65, 1.15);
neck.rotation.x = Math.PI * 0.3;
neck.castShadow = true;
sheep.add(neck);

// ── Head ──
const headGroup = new THREE.Group();
headGroup.position.set(0, 1.55, 1.85);

const headGeo = new THREE.SphereGeometry(0.55, 24, 24);
const head = new THREE.Mesh(headGeo, skinMat);
head.scale.set(0.9, 1, 1.05);
head.castShadow = true;
headGroup.add(head);

// Snout
const snoutGeo = new THREE.SphereGeometry(0.32, 16, 16);
const snout = new THREE.Mesh(snoutGeo, skinMat);
snout.scale.set(0.85, 0.65, 0.7);
snout.position.set(0, -0.12, 0.42);
snout.castShadow = true;
headGroup.add(snout);

// Nose
const noseGeo = new THREE.SphereGeometry(0.12, 12, 12);
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.set(0, -0.05, 0.62);
headGroup.add(nose);

// Nostrils
[-0.07, 0.07].forEach(x => {
  const nostril = new THREE.Mesh(
    new THREE.SphereGeometry(0.035, 8, 8),
    new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.9 })
  );
  nostril.position.set(x, -0.1, 0.68);
  headGroup.add(nostril);
});

// Eyes
[-0.22, 0.22].forEach(x => {
  const eyeWhite = new THREE.Mesh(
    new THREE.SphereGeometry(0.1, 12, 12),
    eyeWhiteMat
  );
  eyeWhite.position.set(x, 0.12, 0.42);
  headGroup.add(eyeWhite);

  const pupil = new THREE.Mesh(
    new THREE.SphereGeometry(0.06, 10, 10),
    eyePupilMat
  );
  pupil.position.set(x, 0.12, 0.49);
  headGroup.add(pupil);

  // Eye highlight
  const highlight = new THREE.Mesh(
    new THREE.SphereGeometry(0.02, 6, 6),
    new THREE.MeshBasicMaterial({ color: 0xffffff })
  );
  highlight.position.set(x + 0.02, 0.14, 0.52);
  headGroup.add(highlight);
});

// Ears
[-1, 1].forEach(side => {
  const earGroup = new THREE.Group();

  const earOuter = new THREE.Mesh(
    new THREE.BoxGeometry(0.12, 0.35, 0.25),
    skinMat
  );
  earOuter.position.set(side * 0.35, 0.25, 0);
  earOuter.rotation.z = side * 0.6;
  earOuter.rotation.y = side * 0.3;
  earOuter.castShadow = true;
  earGroup.add(earOuter);

  const earInner = new THREE.Mesh(
    new THREE.BoxGeometry(0.06, 0.22, 0.18),
    innerEarMat
  );
  earInner.position.set(side * 0.32, 0.22, 0.02);
  earInner.rotation.z = side * 0.6;
  earInner.rotation.y = side * 0.3;
  earGroup.add(earInner);

  headGroup.add(earGroup);
});

sheep.add(headGroup);

// ── Legs ──
const legPositions = [
  { x: -0.55, z: 0.6 },
  { x: 0.55, z: 0.6 },
  { x: -0.55, z: -0.6 },
  { x: 0.55, z: -0.6 },
];

legPositions.forEach(pos => {
  // Upper leg
  const legGeo = new THREE.CylinderGeometry(0.13, 0.11, 1.0, 10);
  const leg = new THREE.Mesh(legGeo, legMat);
  leg.position.set(pos.x, 0.7, pos.z);
  leg.castShadow = true;
  leg.receiveShadow = true;
  sheep.add(leg);

  // Hoof
  const hoofGeo = new THREE.CylinderGeometry(0.14, 0.15, 0.15, 10);
  const hoof = new THREE.Mesh(hoofGeo, new THREE.MeshStandardMaterial({
    color: 0x1a1a1a,
    roughness: 0.5,
  }));
  hoof.position.set(pos.x, 0.15, pos.z);
  hoof.castShadow = true;
  sheep.add(hoof);
});

// ── Tail ──
const tailGeo = new THREE.SphereGeometry(0.25, 12, 12);
const tail = new THREE.Mesh(tailGeo, woolMat);
tail.position.set(0, 2.1, -1.3);
tail.scale.set(0.8, 0.9, 1);
tail.castShadow = true;
sheep.add(tail);

scene.add(sheep);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(25, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x5B8C3E,
  roughness: 0.95,
  metalness: 0.0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Grass tufts ──
const grassMat = new THREE.MeshStandardMaterial({
  color: 0x4a7a2e,
  roughness: 0.9,
});

for (let i = 0; i < 80; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 2 + Math.random() * 20;
  const x = Math.cos(angle) * radius;
  const z = Math.sin(angle) * radius;

  const bladeCount = 3 + Math.floor(Math.random() * 3);
  const cluster = new THREE.Group();

  for (let j = 0; j < bladeCount; j++) {
    const bladeGeo = new THREE.ConeGeometry(0.04, 0.2 + Math.random() * 0.2, 4);
    const blade = new THREE.Mesh(bladeGeo, grassMat);
    blade.position.set(
      (Math.random() - 0.5) * 0.2,
      0.1,
      (Math.random() - 0.5) * 0.2
    );
    blade.rotation.z = (Math.random() - 0.5) * 0.3;
    cluster.add(blade);
  }

  cluster.position.set(x, 0, z);
  scene.add(cluster);
}

// ── Flowers ──
const flowerColors = [0xFF6B8A, 0xFFD700, 0xFF4500, 0xDA70D6, 0xFFFFFF];
for (let i = 0; i < 20; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 3 + Math.random() * 15;
  const x = Math.cos(angle) * radius;
  const z = Math.sin(angle) * radius;

  const stemGeo = new THREE.CylinderGeometry(0.02, 0.02, 0.3, 6);
  const stem = new THREE.Mesh(stemGeo, grassMat);
  stem.position.set(x, 0.15, z);
  scene.add(stem);

  const petalColor = flowerColors[Math.floor(Math.random() * flowerColors.length)];
  const flowerGeo = new THREE.SphereGeometry(0.08, 8, 8);
  const flower = new THREE.Mesh(flowerGeo, new THREE.MeshStandardMaterial({
    color: petalColor,
    roughness: 0.6,
  }));
  flower.position.set(x, 0.32, z);
  scene.add(flower);
}

// ── Idle Animation ──
let time = 0;

function animate() {
  requestAnimationFrame(animate);
  time += 0.015;

  // Gentle breathing
  const breathe = Math.sin(time * 2) * 0.02;
  body.scale.y = 0.85 + breathe;
  body.scale.x = 1 + breathe * 0.5;

  // Head bob
  headGroup.rotation.z = Math.sin(time * 1.5) * 0.04;
  headGroup.rotation.x = Math.sin(time * 1.2) * 0.02;

  // Tail wag
  tail.rotation.y = Math.sin(time * 3) * 0.3;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
