```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Three.js Shovel</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { overflow: hidden; background: #1a1a2e; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 16px;
            left: 50%;
            transform: translateX(-50%);
            color: #ccc;
            font-family: 'Segoe UI', sans-serif;
            font-size: 14px;
            background: rgba(0,0,0,0.5);
            padding: 8px 18px;
            border-radius: 20px;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click &amp; drag to orbit the shovel</div>
    <script type="importmap">
    {
        "imports": {
            "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
            "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
        }
    }
    </script>
    <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene, Camera, Renderer ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.Fog(0x1a1a2e, 10, 25);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0.5, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;

    // ── Lights ──
    const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    dirLight.position.set(5, 8, 4);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    dirLight.shadow.camera.near = 0.5;
    dirLight.shadow.camera.far = 20;
    dirLight.shadow.camera.left = -5;
    dirLight.shadow.camera.right = 5;
    dirLight.shadow.camera.top = 5;
    dirLight.shadow.camera.bottom = -5;
    scene.add(dirLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 0.8);
    rimLight.position.set(-3, 2, -4);
    scene.add(rimLight);

    const pointLight = new THREE.PointLight(0xffaa44, 1, 10);
    pointLight.position.set(2, 4, 2);
    scene.add(pointLight);

    // ── Materials ──
    const woodMaterial = new THREE.MeshStandardMaterial({
        color: 0x8B5E3C,
        roughness: 0.75,
        metalness: 0.05,
    });

    const darkWoodMaterial = new THREE.MeshStandardMaterial({
        color: 0x6B3A1F,
        roughness: 0.7,
        metalness: 0.05,
    });

    const metalMaterial = new THREE.MeshStandardMaterial({
        color: 0x888899,
        roughness: 0.3,
        metalness: 0.9,
    });

    const darkMetalMaterial = new THREE.MeshStandardMaterial({
        color: 0x555566,
        roughness: 0.4,
        metalness: 0.85,
    });

    // ── Shovel Group ──
    const shovel = new THREE.Group();

    // ── Handle (long pole) ──
    const handleGeo = new THREE.CylinderGeometry(0.045, 0.055, 2.6, 12);
    const handle = new THREE.Mesh(handleGeo, woodMaterial);
    handle.position.set(0, 1.45, 0);
    handle.castShadow = true;
    shovel.add(handle);

    // ── D-Grip (top of handle) ──
    // Main D-grip loop - half torus
    const gripTorusGeo = new THREE.TorusGeometry(0.12, 0.025, 8, 24, Math.PI);
    const gripTorus = new THREE.Mesh(gripTorusGeo, darkWoodMaterial);
    gripTorus.position.set(0, 2.75, 0);
    gripTorus.rotation.y = Math.PI / 2;
    gripTorus.castShadow = true;
    shovel.add(gripTorus);

    // D-grip back bar
    const gripBarGeo = new THREE.CylinderGeometry(0.022, 0.022, 0.24, 8);
    const gripBar = new THREE.Mesh(gripBarGeo, darkWoodMaterial);
    gripBar.rotation.z = Math.PI / 2;
    gripBar.position.set(0, 2.75, 0);
    gripBar.castShadow = true;
    shovel.add(gripBar);

    // ── Metal Shank (transition from handle to blade) ──
    const shankGeo = new THREE.BoxGeometry(0.12, 0.35, 0.04);
    const shank = new THREE.Mesh(shankGeo, metalMaterial);
    shank.position.set(0, -0.17, 0);
    shank.castShadow = true;
    shovel.add(shank);

    // Shank-to-blade connector (wider piece)
    const connectorGeo = new THREE.BoxGeometry(0.16, 0.08, 0.05);
    const connector = new THREE.Mesh(connectorGeo, metalMaterial);
    connector.position.set(0, -0.36, 0);
    connector.castShadow = true;
    shovel.add(connector);

    // ── Shovel Blade (curved scoop) ──
    function createBladeGeometry() {
        const segmentsW = 24;
        const segmentsH = 16;
        const width = 0.55;
        const height = 0.45;
        const depth = 0.12;
        const curveAmount = 0.18;

        const vertices = [];
        const normals = [];
        const indices = [];

        // Generate grid vertices with scoop curve
        for (let j = 0; j <= segmentsH; j++) {
            const v = j / segmentsH;
            const y = (v - 0.5) * height;

            // Taper width toward bottom
            const taper = 1.0 - Math.pow(Math.max(0, v * 2 - 1), 2) * 0.35;
            const w = width * taper;

            for (let i = 0; i <= segmentsW; i++) {
                const u = i / segmentsW;
                const x = (u - 0.5) * w;

                // Curvature: deeper in center, shallower at edges
                const centerDist = Math.abs(u - 0.5) * 2;
                const curve = curveAmount * (1 - centerDist * 0.6) * Math.pow(v, 1.5);

                // Slight bend upward at the bottom edge
                const edgeLift = Math.max(0, (0.5 - v) * 2) * 0.06 * (1 - centerDist * 0.5);

                const z = -curve + edgeLift;

                vertices.push(x, y, z);

                // Approximate normal
                const nx = (u - 0.5) * 0.5;
                const ny = 0.3 + v * 0.7;
                const nz = -0.6 + curveAmount * 2;
                const len = Math.sqrt(nx * nx + ny * ny + nz * nz);
                normals.push(nx / len, ny / len, nz / len);
            }
        }

        // Indices
        for (let j = 0; j < segmentsH; j++) {
            for (let i = 0; i < segmentsW; i++) {
                const a = j * (segmentsW + 1) + i;
                const b = a + 1;
                const c = (j + 1) * (segmentsW + 1) + i;
                const d = c + 1;
                indices.push(a, b, c);
                indices.push(b, d, c);
            }
        }

        const geo = new THREE.BufferGeometry();
        geo.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
        geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
        geo.setIndex(indices);
        geo.computeVertexNormals();
        return geo;
    }

    const bladeGeo = createBladeGeometry();
    const blade = new THREE.Mesh(bladeGeo, metalMaterial);
    blade.position.set(0, -0.6, 0);
    blade.rotation.x = 0.15;
    blade.castShadow = true;
    blade.receiveShadow = true;
    shovel.add(blade);

    // Blade lip (rim around the edge)
    function createBladeLip() {
        const points = [];
        const w = 0.55;
        const h = 0.45;
        const steps = 30;

        // Trace the outer edge of the blade
        for (let i = 0; i <= steps; i++) {
            const t = i / steps;
            // Top edge
            const x = -w * 0.8 + t * w * 1.6;
            points.push(new THREE.Vector3(x, h * 0.48, 0.02));
        }
        // Right side
        for (let i = 0; i <= 8; i++) {
            const t = i / 8;
            points.push(new THREE.Vector3(w * 0.8, h * 0.48 - t * h * 0.9, 0.02));
        }
        // Bottom (curved)
        for (let i = 0; i <= 16; i++) {
            const t = i / 16;
            const angle = Math.PI * t;
            const x = w * 0.8 * Math.cos(angle) * 0.3;
            const y = -h * 0.42 - Math.sin(angle) * 0.06;
            points.push(new THREE.Vector3(x, y, -0.08));
        }
        // Left side
        for (let i = 0; i <= 8; i++) {
            const t = i / 8;
            points.push(new THREE.Vector3(-w * 0.8, -h * 0.42 + t * h * 0.9, 0.02));
        }

        return points;
    }

    const lipPoints = createBladeLip();
    const lipCurve = new THREE.CatmullRomCurve3(lipPoints, true);
    const lipGeo = new THREE.TubeGeometry(lipCurve, 80, 0.012, 6, true);
    const lip = new THREE.Mesh(lipGeo, darkMetalMaterial);
    lip.position.set(0, -0.6, 0);
    lip.rotation.x = 0.15;
    shovel.add(lip);

    // ── Rivets on blade ──
    const rivetGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.06, 8);
    const rivetPositions = [
        [0.15, -0.38], [-0.15, -0.38],
        [0.12, -0.45], [-0.12, -0.45],
    ];
    rivetPositions.forEach(([x, y]) => {
        const rivet = new THREE.Mesh(rivetGeo, darkMetalMaterial);
        rivet.position.set(x, y, 0.02);
        rivet.rotation.x = Math.PI / 2;
        shovel.add(rivet);
    });

    // ── Position entire shovel ──
    shovel.rotation.z = -0.05;
    scene.add(shovel);

    // ── Ground Plane ──
    const groundGeo = new THREE.CircleGeometry(8, 48);
    const groundMat = new THREE.MeshStandardMaterial({
        color: 0x2a2a3e,
        roughness: 0.9,
        metalness: 0.1,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -1.1;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Subtle grid on ground ──
    const gridHelper = new THREE.GridHelper(12, 24, 0x333355, 0x222244);
    gridHelper.position.y = -1.09;
    scene.add(gridHelper);

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
        requestAnimationFrame(animate);
        const t = clock.getElapsedTime();

        // Gentle floating rotation
        shovel.rotation.y = Math.sin(t * 0.5) * 0.3;
        shovel.position.y = Math.sin(t * 0.8) * 0.05;

        controls.update();
        renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
        camera.aspect = innerWidth / innerHeight;
        camera.updateProjectionMatrix();
        renderer.setSize(innerWidth, innerHeight);
    });
    </script>
</body>
</html>
