// --- Lighting ---
const ambient = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(8, 15, 10);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 50;
sun.shadow.camera.left = -15;
sun.shadow.camera.right = 15;
sun.shadow.camera.top = 15;
sun.shadow.camera.bottom = -15;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8899ff, 0.3);
fill.position.set(-5, 3, -5);
scene.add(fill);

// --- Materials ---
const woodMat = new THREE.MeshStandardMaterial({
  color: 0x8B6914,
  roughness: 0.85,
  metalness: 0.0,
});

const darkWoodMat = new THREE.MeshStandardMaterial({
  color: 0x5C4010,
  roughness: 0.9,
  metalness: 0.0,
});

// --- Sign Texture ---
function createSignTexture() {
  const canvas = document.createElement('canvas');
  canvas.width = 1024;
  canvas.height = 512;
  const ctx = canvas.getContext('2d');

  // Wood background
  const grad = ctx.createLinearGradient(0, 0, 1024, 512);
  grad.addColorStop(0, '#C49A3C');
  grad.addColorStop(0.5, '#D4AA4C');
  grad.addColorStop(1, '#B8882C');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, 1024, 512);

  // Wood grain lines
  ctx.strokeStyle = 'rgba(120, 80, 20, 0.15)';
  ctx.lineWidth = 2;
  for (let i = 0; i < 40; i++) {
    const y = Math.random() * 512;
    ctx.beginPath();
    ctx.moveTo(0, y);
    for (let x = 0; x < 1024; x += 20) {
      ctx.lineTo(x, y + Math.sin(x * 0.02) * 4 + (Math.random() - 0.5) * 2);
    }
    ctx.stroke();
  }

  // Border
  ctx.strokeStyle = '#6B4E0A';
  ctx.lineWidth = 12;
  ctx.strokeRect(20, 20, 984, 472);
  ctx.strokeStyle = '#8B6914';
  ctx.lineWidth = 4;
  ctx.strokeRect(32, 32, 960, 448);

  // Text
  ctx.fillStyle = '#2C1810';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';

  ctx.font = 'bold 80px Georgia, serif';
  ctx.fillText('WELCOME', 512, 170);

  ctx.font = 'bold 120px Georgia, serif';
  ctx.fillText('TO THE SIGN', 512, 320);

  const texture = new THREE.CanvasTexture(canvas);
  texture.colorSpace = THREE.SRGBColorSpace;
  return texture;
}

// --- Build Sign ---
const signGroup = new THREE.Group();
scene.add(signGroup);

// Board
const boardGeo = new THREE.BoxGeometry(6, 3, 0.25);
const boardMat = new THREE.MeshStandardMaterial({
  map: createSignTexture(),
  roughness: 0.7,
  metalness: 0.0,
});
const board = new THREE.Mesh(boardGeo, boardMat);
board.castShadow = true;
board.receiveShadow = true;
board.position.y = 4.2;
signGroup.add(board);

// Posts
const postGeo = new THREE.CylinderGeometry(0.15, 0.18, 5, 12);
const postPositions = [[-2.4, 2.2, 0], [2.4, 2.2, 0]];
postPositions.forEach(pos => {
  const post = new THREE.Mesh(postGeo, woodMat);
  post.position.set(...pos);
  post.castShadow = true;
  post.receiveShadow = true;
  signGroup.add(post);
});

// Top trim
const trimGeo = new THREE.BoxGeometry(6.4, 0.15, 0.35);
const trimTop = new THREE.Mesh(trimGeo, darkWoodMat);
trimTop.position.y = 5.75;
trimTop.castShadow = true;
signGroup.add(trimTop);

const trimBot = new THREE.Mesh(trimGeo, darkWoodMat);
trimBot.position.y = 2.65;
trimBot.castShadow = true;
signGroup.add(trimBot);

// Nails / bolts
const nailGeo = new THREE.CylinderGeometry(0.05, 0.05, 0.35, 8);
const nailMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.3, metalness: 0.8 });
const nailPositions = [
  [-2.7, 5.5, 0.18], [2.7, 5.5, 0.18],
  [-2.7, 2.85, 0.18], [2.7, 2.85, 0.18],
  [0, 5.5, 0.18], [0, 2.85, 0.18],
];
nailPositions.forEach(pos => {
  const nail = new THREE.Mesh(nailGeo, nailMat);
  nail.position.set(...pos);
  nail.castShadow = true;
  signGroup.add(nail);
});

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(40, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x4a7c3f,
  roughness: 1.0,
  metalness: 0.0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt patch under sign
const dirtGeo = new THREE.CircleGeometry(4, 32);
const dirtMat = new THREE.MeshStandardMaterial({ color: 0x6B5B3A, roughness: 1.0 });
const dirt = new THREE.Mesh(dirtGeo, dirtMat);
dirt.rotation.x = -Math.PI / 2;
dirt.position.y = 0.01;
dirt.receiveShadow = true;
scene.add(dirt);

// --- Simple bushes ---
function createBush(x, z, scale = 1) {
  const bushGroup = new THREE.Group();
  const bushMat = new THREE.MeshStandardMaterial({
    color: new THREE.Color(0x2d6b1e).lerp(new THREE.Color(0x4a8c3a), Math.random() * 0.5),
    roughness: 0.9,
  });
  const count = 3 + Math.floor(Math.random() * 3);
  for (let i = 0; i < count; i++) {
    const r = (0.3 + Math.random() * 0.5) * scale;
    const geo = new THREE.SphereGeometry(r, 8, 6);
    const mesh = new THREE.Mesh(geo, bushMat);
    mesh.position.set(
      (Math.random() - 0.5) * 1.2 * scale,
      r * 0.7,
      (Math.random() - 0.5) * 1.2 * scale
    );
    mesh.castShadow = true;
    mesh.receiveShadow = true;
    bushGroup.add(mesh);
  }
  bushGroup.position.set(x, 0, z);
  return bushGroup;
}

const bushLocations = [
  [-5, -3, 1.2], [5.5, -2, 1.0], [-6, 1, 0.9],
  [7, 2, 1.3], [-3, -6, 0.8], [4, -7, 1.1],
  [-8, -1, 1.0], [9, -4, 0.7],
];
bushLocations.forEach(([x, z, s]) => scene.add(createBush(x, z, s)));

// --- Flowers ---
function createFlower(x, z) {
  const group = new THREE.Group();
  const stemMat = new THREE.MeshStandardMaterial({ color: 0x3a7d2c, roughness: 0.9 });
  const stemGeo = new THREE.CylinderGeometry(0.02, 0.02, 0.4 + Math.random() * 0.3, 4);
  const stem = new THREE.Mesh(stemGeo, stemMat);
  stem.position.y = 0.2;
  group.add(stem);

  const colors = [0xff6b8a, 0xffd700, 0xff4444, 0xffaa00, 0xee88ff, 0xffffff];
  const color = colors[Math.floor(Math.random() * colors.length)];
  const petalMat = new THREE.MeshStandardMaterial({ color, roughness: 0.6 });
  const petalGeo = new THREE.SphereGeometry(0.08, 6, 4);
  const petal = new THREE.Mesh(petalGeo, petalMat);
  petal.position.y = 0.45 + Math.random() * 0.2;
  petal.castShadow = true;
  group.add(petal);

  group.position.set(x, 0, z);
  return group;
}

for (let i = 0; i < 30; i++) {
  const angle = Math.random() * Math.PI * 2;
  const dist = 3 + Math.random() * 12;
  scene.add(createFlower(Math.cos(angle) * dist, Math.sin(angle) * dist));
}

// --- Clouds ---
function createCloud(x, y, z) {
  const group = new THREE.Group();
  const mat = new THREE.MeshStandardMaterial({
    color: 0xffffff, roughness: 1, metalness: 0, transparent: true, opacity: 0.85
  });
  for (let i = 0; i < 5; i++) {
    const r = 0.5 + Math.random() * 1.0;
    const geo = new THREE.SphereGeometry(r, 8, 6);
    const m = new THREE.Mesh(geo, mat);
    m.position.set((Math.random() - 0.5) * 3, (Math.random() - 0.5) * 0.5, (Math.random() - 0.5) * 1.5);
    m.scale.y = 0.6;
    group.add(m);
  }
  group.position.set(x, y, z);
  return group;
}

const clouds = [];
for (let i = 0; i < 6; i++) {
  const cloud = createCloud(
    (Math.random() - 0.5) * 60,
    12 + Math.random() * 8,
    -10 - Math.random() * 30
  );
  clouds.push(cloud);
  scene.add(cloud);
}

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sign sway
  signGroup.rotation.z = Math.sin(t * 0.5) * 0.008;
  signGroup.rotation.y = Math.sin(t * 0.3) * 0.01;

  // Cloud drift
  clouds.forEach((c, i) => {
    c.position.x += 0.003 * (i % 2 === 0 ? 1 : -0.7);
    if (c.position.x > 40) c.position.x = -40;
    if (c.position.x < -40) c.position.x = 40;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single `index.html` file creates a complete 3D scene featuring:

- **A wooden signboard** with "WELCOME TO THE SIGN" rendered on a canvas texture, complete with wood grain, border, and decorative nails
- **Two support posts** with top and bottom trim pieces
- **A grassy ground** with a dirt patch under the sign
- **Bushes and flowers** scattered around the scene
- **Drifting clouds** in the sky
- **Realistic lighting** — directional sun with soft shadows, ambient fill, and a blue fill light
- **Subtle animation** — the sign gently sways and clouds drift across the sky
- **OrbitControls** — click and drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Skateboard</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #1a1a2e; font-family: sans-serif; }
    canvas { display: block; }
    #info {
      position: absolute; top: 16px; width: 100%; text-align: center;
      color: #e0e0e0; font-size: 14px; pointer-events: none;
      text-shadow: 0 1px 4px rgba(0,0,0,.6);
    }
  </style>
</head>
<body>
  <div id="info">🛹 Drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.018);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3.5, 5);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.06;
    controls.target.set(0, 0.3, 0);

    // ── Lights ─────────────────────────────────────────────
    const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    dirLight.position.set(5, 8, 4);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    dirLight.shadow.camera.near = 1;
    dirLight.shadow.camera.far = 20;
    dirLight.shadow.camera.left = -5;
    dirLight.shadow.camera.right = 5;
    dirLight.shadow.camera.top = 5;
    dirLight.shadow.camera.bottom = -5;
    scene.add(dirLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 1.0);
    rimLight.position.set(-4, 3, -3);
    scene.add(rimLight);

    const pointLight = new THREE.PointLight(0xff6644, 1.5, 12);
    pointLight.position.set(-2, 2, 2);
    scene.add(pointLight);

    // ── Ground ─────────────────────────────────────────────
    const groundGeo = new THREE.PlaneGeometry(30, 30);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x22223a,
      roughness: 0.85,
      metalness: 0.1,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.65;
    ground.receiveShadow = true;
    scene.add(ground);

    // Grid helper
    const grid = new THREE.GridHelper(20, 40, 0x333355, 0x2a2a44);
    grid.position.y = -0.64;
    scene.add(grid);

    // ── Skateboard Group ───────────────────────────────────
    const skateboard = new THREE.Group();

    // ── Deck ───────────────────────────────────────────────
    const deckLength = 3.2;
    const deckWidth = 0.82;
    const deckHeight = 0.06;

    // Main deck body
    const deckGeo = new THREE.BoxGeometry(deckLength, deckHeight, deckWidth, 1, 1, 1);
    // Curve the deck slightly (kick)
    const deckPos = deckGeo.attributes.position;
    for (let i = 0; i < deckPos.count; i++) {
      const x = deckPos.getX(i);
      const z = deckPos.getZ(i);
      // Slight concave shape
      const concave = -Math.abs(z) * 0.04;
      // Kick tail / nose curve
      const distFromCenter = Math.abs(x) / (deckLength / 2);
      const kick = distFromCenter * distFromCenter * 0.08 * Math.sign(x);
      deckPos.setY(i, deckPos.getY(i) + concave + kick);
    }
    deckGeo.computeVertexNormals();

    const deckMat = new THREE.MeshStandardMaterial({
      color: 0x8B4513,
      roughness: 0.45,
      metalness: 0.05,
    });
    const deck = new THREE.Mesh(deckGeo, deckMat);
    deck.castShadow = true;
    deck.receiveShadow = true;
    skateboard.add(deck);

    // Grip tape (top surface)
    const gripGeo = new THREE.PlaneGeometry(deckLength - 0.1, deckWidth - 0.06);
    const gripMat = new THREE.MeshStandardMaterial({
      color: 0x1a1a1a,
      roughness: 0.95,
      metalness: 0.0,
      side: THREE.DoubleSide,
    });
    const grip = new THREE.Mesh(gripGeo, gripMat);
    grip.rotation.x = -Math.PI / 2;
    grip.position.y = deckHeight / 2 + 0.002;
    skateboard.add(grip);

    // Deck graphic strip
    const graphicGeo = new THREE.PlaneGeometry(1.6, 0.35);
    const graphicMat = new THREE.MeshStandardMaterial({
      color: 0xff4444,
      roughness: 0.5,
      metalness: 0.1,
      side: THREE.DoubleSide,
      emissive: 0xff2222,
      emissiveIntensity: 0.15,
    });
    const graphic = new THREE.Mesh(graphicGeo, graphicMat);
    graphic.rotation.x = -Math.PI / 2;
    graphic.position.y = deckHeight / 2 + 0.003;
    skateboard.add(graphic);

    // ── Trucks ─────────────────────────────────────────────
    const truckMat = new THREE.MeshStandardMaterial({
      color: 0xcccccc,
      roughness: 0.2,
      metalness: 0.9,
    });

    const truckPositions = [-0.85, 0.85]; // front and back

    truckPositions.forEach((xPos) => {
      const truck = new THREE.Group();

      // Baseplate
      const baseplateGeo = new THREE.BoxGeometry(0.55, 0.03, deckWidth - 0.1);
      const baseplate = new THREE.Mesh(baseplateGeo, truckMat);
      baseplate.castShadow = true;
      truck.add(baseplate);

      // Hanger (the perpendicular piece)
      const hangerGeo = new THREE.BoxGeometry(0.55, 0.035, 0.12);
      const hanger = new THREE.Mesh(hangerGeo, truckMat);
      hanger.castShadow = true;
      truck.add(hanger);

      // Kingpin / axle
      const axleGeo = new THREE.CylinderGeometry(0.025, 0.025, deckWidth - 0.05, 12);
      const axleMat = new THREE.MeshStandardMaterial({
        color: 0x888888,
        roughness: 0.3,
        metalness: 0.85,
      });
      const axle = new THREE.Mesh(axleGeo, axleMat);
      axle.rotation.x = Math.PI / 2;
      axle.position.y = -0.02;
      truck.add(axle);

      // Bushings (small cylinders on either side of kingpin)
      [-1, 1].forEach(side => {
        const bushingGeo = new THREE.CylinderGeometry(0.035, 0.035, 0.04, 12);
        const bushingMat = new THREE.MeshStandardMaterial({
          color: 0x222222,
          roughness: 0.8,
        });
        const bushing = new THREE.Mesh(bushingGeo, bushingMat);
        bushing.position.set(0, -0.01, side * 0.1);
        truck.add(bushing);
      });

      truck.position.set(xPos, -deckHeight / 2 - 0.025, 0);
      skateboard.add(truck);
    });

    // ── Wheels ─────────────────────────────────────────────
    const wheelRadius = 0.13;
    const wheelWidth = 0.08;
    const wheelMat = new THREE.MeshStandardMaterial({
      color: 0xffeecc,
      roughness: 0.35,
      metalness: 0.05,
    });

    const wheelPositions = [
      { x: -0.85, z: -0.32 },
      { x: -0.85, z: 0.32 },
      { x:  0.85, z: -0.32 },
      { x:  0.85, z: 0.32 },
    ];

    const wheels = [];

    wheelPositions.forEach(({ x, z }) => {
      const wheelGroup = new THREE.Group();

      // Main wheel body
      const wheelGeo = new THREE.CylinderGeometry(wheelRadius, wheelRadius, wheelWidth, 24);
      const wheel = new THREE.Mesh(wheelGeo, wheelMat);
      wheel.rotation.z = Math.PI / 2;
      wheel.castShadow = true;
      wheelGroup.add(wheel);

      // Wheel core / bearing
      const coreGeo = new THREE.CylinderGeometry(0.03, 0.03, wheelWidth + 0.01, 12);
      const coreMat = new THREE.MeshStandardMaterial({
        color: 0x333333,
        roughness: 0.4,
        metalness: 0.6,
      });
      const core = new THREE.Mesh(coreGeo, coreMat);
      core.rotation.z = Math.PI / 2;
      wheelGroup.add(core);

      // Spoke detail
      for (let i = 0; i < 4; i++) {
        const spokeGeo = new THREE.BoxGeometry(wheelWidth + 0.01, 0.008, 0.008);
        const spoke = new THREE.Mesh(spokeGeo, coreMat);
        const angle = (i / 4) * Math.PI * 2;
        spoke.position.y = Math.cos(angle) * (wheelRadius * 0.6);
        spoke.position.z = Math.sin(angle) * (wheelRadius * 0.6);
        spoke.rotation.x = angle;
        wheelGroup.add(spoke);
      }

      wheelGroup.position.set(x, -deckHeight / 2 - 0.06 - wheelRadius, z);
      skateboard.add(wheelGroup);
      wheels.push(wheelGroup);
    });

    // ── Mounting Hardware ──────────────────────────────────
    const boltMat = new THREE.MeshStandardMaterial({
      color: 0xaaaaaa,
      roughness: 0.3,
      metalness: 0.8,
    });

    const boltPositions = [
      [-0.85, -0.22], [-0.85, 0.22],
      [0.85, -0.22], [0.85, 0.22],
      [-0.55, -0.22], [-0.55, 0.22],
      [0.55, -0.22], [0.55, 0.22],
    ];

    boltPositions.forEach(([bx, bz]) => {
      const boltGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.06, 8);
      const bolt = new THREE.Mesh(boltGeo, boltMat);
      bolt.position.set(bx, -deckHeight / 2 - 0.005, bz);
      skateboard.add(bolt);
    });

    // Center the skateboard
    skateboard.position.y = 0.3;
    scene.add(skateboard);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Gentle floating animation
      skateboard.position.y = 0.3 + Math.sin(elapsed * 0.8) * 0.08;
      skateboard.rotation.y = Math.sin(elapsed * 0.3) * 0.15;

      // Wheel rotation
      const wheelSpeed = elapsed * 1.5;
      wheels.forEach((w, i) => {
        w.children[0].rotation.x = wheelSpeed + i;
      });

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
