const rim = new THREE.PointLight(0xffaa66, 1.5, 10);
rim.position.set(0, 3, -3);
scene.add(rim);

// ── Materials ──
const boneMat = new THREE.MeshStandardMaterial({
  color: 0xe8dcc8, roughness: 0.45, metalness: 0.05
});
const jointMat = new THREE.MeshStandardMaterial({
  color: 0xd4c4a8, roughness: 0.35, metalness: 0.08
});

// ── Helpers ──
const skeleton = new THREE.Group();
scene.add(skeleton);

function bone(from, to, radius = 0.035) {
  const dir = new THREE.Vector3().subVectors(to, from);
  const len = dir.length();
  const geo = new THREE.CylinderGeometry(radius, radius * 0.85, len, 8);
  const mesh = new THREE.Mesh(geo, boneMat);
  mesh.position.copy(from).add(to).multiplyScalar(0.5);
  const axis = new THREE.Vector3(0, 1, 0);
  const d = dir.clone().normalize();
  mesh.quaternion.setFromUnitVectors(axis, d);
  mesh.castShadow = true;
  skeleton.add(mesh);
  return mesh;
}

function joint(pos, r = 0.045) {
  const geo = new THREE.SphereGeometry(r, 12, 10);
  const mesh = new THREE.Mesh(geo, jointMat);
  mesh.position.copy(pos);
  mesh.castShadow = true;
  skeleton.add(mesh);
  return mesh;
}

function ribPair(y, width, drop) {
  for (const side of [-1, 1]) {
    const start = new THREE.Vector3(side * 0.12, y, 0);
    const mid = new THREE.Vector3(side * width, y - drop * 0.3, drop * 0.6);
    const end = new THREE.Vector3(side * 0.12, y - drop * 0.6, drop * 0.4);
    const curve = new THREE.QuadraticBezierCurve3(start, mid, end);
    const tubeGeo = new THREE.TubeGeometry(curve, 12, 0.018, 8, false);
    const mesh = new THREE.Mesh(tubeGeo, boneMat);
    mesh.castShadow = true;
    skeleton.add(mesh);
  }
}

// ── SKULL ──
const skullPos = new THREE.Vector3(0, 1.72, 0);
const skull = new THREE.Mesh(
  new THREE.SphereGeometry(0.12, 16, 14), boneMat
);
skull.position.copy(skullPos);
skull.scale.set(1, 1.15, 0.95);
skull.castShadow = true;
skeleton.add(skull);

// jaw
const jaw = new THREE.Mesh(
  new THREE.SphereGeometry(0.07, 12, 10), boneMat
);
jaw.position.set(0, 1.64, 0.03);
jaw.scale.set(1, 0.6, 0.8);
skeleton.add(jaw);

// eye sockets (dark rings)
for (const s of [-1, 1]) {
  const ring = new THREE.Mesh(
    new THREE.TorusGeometry(0.035, 0.008, 8, 16), jointMat
  );
  ring.position.set(s * 0.05, 1.73, 0.1);
  skeleton.add(ring);
}

// ── SPINE ──
const spinePoints = [];
for (let i = 0; i <= 12; i++) {
  const t = i / 12;
  const y = 1.62 - t * 0.72;
  const x = Math.sin(t * 0.3) * 0.01;
  const z = Math.sin(t * Math.PI) * 0.015;
  spinePoints.push(new THREE.Vector3(x, y, z));
  if (i > 0) joint(spinePoints[i], 0.03);
}
for (let i = 0; i < spinePoints.length - 1; i++) {
  bone(spinePoints[i], spinePoints[i + 1], 0.028);
}

// ── RIBS ──
for (let i = 0; i < 6; i++) {
  const y = 1.55 - i * 0.07;
  const w = 0.18 + i * 0.02;
  const d = 0.06 + i * 0.015;
  ribPair(y, w, d);
}

// sternum
bone(new THREE.Vector3(0, 1.55, 0.08), new THREE.Vector3(0, 1.30, 0.06), 0.022);

// ── CLAVICLES ──
for (const s of [-1, 1]) {
  bone(
    new THREE.Vector3(0, 1.58, 0.02),
    new THREE.Vector3(s * 0.28, 1.56, 0.01),
    0.02
  );
}

// ── SHOULDERS (scapula hint) ──
for (const s of [-1, 1]) {
  joint(new THREE.Vector3(s * 0.28, 1.56, 0.01), 0.04);
}

// ── ARMS ──
for (const s of [-1, 1]) {
  const shoulder = new THREE.Vector3(s * 0.28, 1.56, 0.01);
  const elbow = new THREE.Vector3(s * 0.38, 1.25, 0.02);
  const wrist = new THREE.Vector3(s * 0.42, 0.98, 0.02);
  const hand = new THREE.Vector3(s * 0.44, 0.86, 0.02);

  bone(shoulder, elbow, 0.032);
  joint(elbow, 0.04);
  bone(elbow, wrist, 0.028);
  joint(wrist, 0.032);

  // metacarpals (hand bones)
  for (let f = 0; f < 5; f++) {
    const fingerStart = new THREE.Vector3(
      s * (0.44 + (f - 2) * 0.018), 0.86, 0.02
    );
    const fingerEnd = new THREE.Vector3(
      s * (0.44 + (f - 2) * 0.018), 0.86 - (f === 2 ? 0.08 : 0.06), 0.02
    );
    bone(fingerStart, fingerEnd, 0.01);
  }
}

// ── PELVIS ──
const pelvisGeo = new THREE.TorusGeometry(0.14, 0.025, 8, 24, Math.PI);
const pelvis = new THREE.Mesh(pelvisGeo, boneMat);
pelvis.position.set(0, 0.90, 0);
pelvis.rotation.y = Math.PI;
pelvis.rotation.z = Math.PI * 0.15;
pelvis.castShadow = true;
skeleton.add(pelvis);

// sacrum
bone(new THREE.Vector3(0, 0.90, 0), new THREE.Vector3(0, 0.82, -0.02), 0.03);

// ── LEGS ──
for (const s of [-1, 1]) {
  const hip = new THREE.Vector3(s * 0.10, 0.86, 0);
  const knee = new THREE.Vector3(s * 0.10, 0.50, 0.01);
  const ankle = new THREE.Vector3(s * 0.10, 0.14, 0.01);
  const foot = new THREE.Vector3(s * 0.10, 0.06, 0.06);

  joint(hip, 0.05);
  bone(hip, knee, 0.04);
  joint(knee, 0.045);
  bone(knee, ankle, 0.032);
  joint(ankle, 0.035);
  bone(ankle, foot, 0.025);

  // foot bones
  bone(foot, new THREE.Vector3(s * 0.10, 0.04, 0.14), 0.018);
  for (let t = 0; t < 5; t++) {
    const toeStart = new THREE.Vector3(
      s * 0.10 + (t - 2) * 0.012, 0.04, 0.14
    );
    const toeEnd = new THREE.Vector3(
      s * 0.10 + (t - 2) * 0.012, 0.03, 0.17 + (t === 0 ? 0.01 : 0)
    );
    bone(toeStart, toeEnd, 0.007);
  }
}

// ── GROUND ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(20, 20),
  new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = 0.01;
ground.receiveShadow = true;
scene.add(ground);

// subtle grid
const grid = new THREE.GridHelper(10, 40, 0x222244, 0x1a1a33);
grid.position.y = 0.015;
scene.add(grid);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // gentle idle sway
  skeleton.rotation.y = Math.sin(t * 0.5) * 0.08;
  skeleton.position.y = Math.sin(t * 1.2) * 0.008;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

- **Skull** — scaled sphere with jaw and eye-socket rings
- **Spine** — 12 vertebrae joints connected by short bones with a gentle natural curve
- **Ribcage** — 6 curved rib pairs using quadratic Bézier tube geometry + a sternum bone
- **Clavicles & shoulders** — collarbones and shoulder joints
- **Arms** — humerus, elbow joint, radius/ulna, wrist, and 5 finger bones per hand
- **Pelvis** — torus-shaped hip bone with sacrum
- **Legs** — hip joint, femur, knee, tibia, ankle, foot, and 5 toes per leg
- **Lighting** — key, fill, and rim lights with shadows
- **Animation** — subtle idle sway/breathing motion
- **OrbitControls** — drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Skull</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { mergeGeometries } from 'three/addons/utils/BufferGeometryUtils.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);
scene.fog = new THREE.FogExp2(0x0a0a12, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0.5, 0);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x222233, 0.5);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x4466aa, 0.8);
fillLight.position.set(-4, 3, -2);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xff6633, 1.2);
rimLight.position.set(0, 2, -6);
scene.add(rimLight);

const eyeGlow = new THREE.PointLight(0x2244aa, 2, 4);
eyeGlow.position.set(0, 1.2, 2.5);
scene.add(eyeGlow);

// --- Materials ---
const boneMat = new THREE.MeshStandardMaterial({
  color: 0xd4c5a0,
  roughness: 0.65,
  metalness: 0.05,
});

const darkMat = new THREE.MeshStandardMaterial({
  color: 0x111111,
  roughness: 0.9,
  metalness: 0.0,
});

const toothMat = new THREE.MeshStandardMaterial({
  color: 0xe8dcc0,
  roughness: 0.5,
  metalness: 0.02,
});

const eyeballMat = new THREE.MeshStandardMaterial({
  color: 0x2244cc,
  emissive: 0x2244cc,
  emissiveIntensity: 2,
  roughness: 0.2,
  metalness: 0.3,
});

// --- Build Skull ---
const skullGroup = new THREE.Group();
const geometries = [];
const darkGeometries = [];
const toothGeometries = [];
const eyeballGeometries = [];

// Cranium (top dome)
geometries.push(new THREE.SphereGeometry(2, 32, 24).translate(0, 2.8, 0));

// Forehead / upper face
geometries.push(new THREE.SphereGeometry(1.95, 32, 24, 0, Math.PI * 2, 0, Math.PI * 0.45).translate(0, 2.6, 0.3));

// Cheekbone area (left)
geometries.push(new THREE.SphereGeometry(0.9, 16, 16).translate(-1.3, 1.3, 1.2));
// Cheekbone area (right)
geometries.push(new THREE.SphereGeometry(0.9, 16, 16).translate(1.3, 1.3, 1.2));

// Brow ridge (left)
geometries.push(new THREE.BoxGeometry(0.9, 0.25, 0.5).translate(-0.9, 2.0, 1.7));
// Brow ridge (right)
geometries.push(new THREE.BoxGeometry(0.9, 0.25, 0.5).translate(0.9, 2.0, 1.7));

// Upper jaw / maxilla
geometries.push(new THREE.SphereGeometry(1.5, 24, 18, 0, Math.PI * 2, Math.PI * 0.3, Math.PI * 0.4).translate(0, 0.5, 0.5));

// Jaw (mandible)
geometries.push(new THREE.BoxGeometry(2.6, 1.0, 1.2).translate(0, -0.5, 0.3));

// Jaw corners / rami (left)
geometries.push(new THREE.CylinderGeometry(0.35, 0.4, 1.8, 12).translate(-1.2, 0.4, -0.3));
// Jaw corners / rami (right)
geometries.push(new THREE.CylinderGeometry(0.35, 0.4, 1.8, 12).translate(1.2, 0.4, -0.3));

// Chin
geometries.push(new THREE.SphereGeometry(0.6, 16, 16).translate(0, -1.0, 0.8));

// Nose bridge
geometries.push(new THREE.BoxGeometry(0.3, 0.8, 0.3).translate(0, 1.5, 1.8));

// --- Dark cavities ---
// Eye socket (left)
darkGeometries.push(new THREE.SphereGeometry(0.65, 16, 16).translate(-0.85, 1.6, 1.55));
// Eye socket (right)
darkGeometries.push(new THREE.SphereGeometry(0.65, 16, 16).translate(0.85, 1.6, 1.55));

// Nasal cavity
darkGeometries.push(new THREE.SphereGeometry(0.35, 12, 12).translate(0, 1.0, 1.95));
darkGeometries.push(new THREE.SphereGeometry(0.25, 12, 12).translate(0, 0.7, 2.0));

// --- Teeth (upper) ---
for (let i = -4; i <= 4; i++) {
  const tooth = new THREE.BoxGeometry(0.22, 0.35, 0.3);
  tooth.translate(i * 0.27, 0.35, 1.05);
  tooth.rotateX(0.1);
  toothGeometries.push(tooth);
}

// --- Teeth (lower) ---
for (let i = -4; i <= 4; i++) {
  const tooth = new THREE.BoxGeometry(0.22, 0.3, 0.28);
  tooth.translate(i * 0.27, -0.35, 0.95);
  tooth.rotateX(-0.1);
  toothGeometries.push(tooth);
}

// --- Eyeballs ---
eyeballGeometries.push(new THREE.SphereGeometry(0.3, 16, 16).translate(-0.85, 1.6, 1.7));
eyeballGeometries.push(new THREE.SphereGeometry(0.3, 16, 16).translate(0.85, 1.6, 1.7));

// --- Merge & add ---
const boneMesh = new THREE.Mesh(mergeGeometries(geometries), boneMat);
boneMesh.castShadow = true;
boneMesh.receiveShadow = true;
skullGroup.add(boneMesh);

const darkMesh = new THREE.Mesh(mergeGeometries(darkGeometries), darkMat);
skullGroup.add(darkMesh);

const toothMesh = new THREE.Mesh(mergeGeometries(toothGeometries), toothMat);
toothMesh.castShadow = true;
skullGroup.add(toothMesh);

const eyeballMesh = new THREE.Mesh(mergeGeometries(eyeballGeometries), eyeballMat);
skullGroup.add(eyeballMesh);

skullGroup.position.y = -0.5;
scene.add(skullGroup);

// --- Ground plane ---
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x0a0a12, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.5;
ground.receiveShadow = true;
scene.add(ground);

// --- Floating particles ---
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 15;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({ color: 0x6688cc, size: 0.04, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  skullGroup.rotation.y = Math.sin(t * 0.3) * 0.3;
  skullGroup.position.y = -0.5 + Math.sin(t * 0.5) * 0.15;

  eyeGlow.intensity = 2 + Math.sin(t * 2) * 0.8;
  eyeballMat.emissiveIntensity = 1.5 + Math.sin(t * 2) * 1;

  particles.rotation.y = t * 0.02;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **procedurally generated 3D skull** with:

- **Cranium, jaw, cheekbones, brow ridges, chin, and nose bridge** built from merged spheres, boxes, and cylinders
- **Glowing blue eyeballs** with a pulsing point light inside the eye sockets
- **Upper and lower teeth** rows
- **Dark cavities** for eye sockets and nasal passage
- **Dramatic three-point lighting** (warm key, cool fill, orange rim)
- **Floating atmospheric particles**
- **Gentle floating/rotation animation**
- **OrbitControls** — drag to rotate, scroll to zoom
- **ACES filmic tone mapping** and fog for a moody atmosphere

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Sled</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.Fog(0x87CEEB, 30, 60);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 4, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1, 0);
controls.enableDamping = true;

// --- Lights ---
const ambient = new THREE.AmbientLight(0xffffff, 0.6);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(8, 12, 6);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 40;
sun.shadow.camera.left = -10;
sun.shadow.camera.right = 10;
sun.shadow.camera.top = 10;
sun.shadow.camera.bottom = -10;
scene.add(sun);

const fill = new THREE.DirectionalLight(0xc0d8ff, 0.4);
fill.position.set(-5, 3, -4);
scene.add(fill);

// --- Ground (Snow) ---
const groundGeo = new THREE.CircleGeometry(40, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0xf0f4f8, roughness: 0.9, metalness: 0.0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// --- Sled Builder ---
const sled = new THREE.Group();

const woodMat = new THREE.MeshStandardMaterial({ color: 0x8B5E3C, roughness: 0.7 });
const darkWoodMat = new THREE.MeshStandardMaterial({ color: 0x5C3A1E, roughness: 0.8 });
const metalMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.3, metalness: 0.8 });
const redMat = new THREE.MeshStandardMaterial({ color: 0xCC2222, roughness: 0.5 });
const ropeMat = new THREE.MeshStandardMaterial({ color: 0xD4A06A, roughness: 0.9 });

// --- Runners (two long curved skis) ---
function createRunner() {
  const runnerGroup = new THREE.Group();

  // Main runner body — we'll use a shaped geometry
  const shape = new THREE.Shape();
  const len = 3.6;
  const width = 0.15;
  const tipRadius = 0.35;

  // Draw a runner profile: wide middle, tapered tip
  shape.moveTo(-len / 2, 0);
  shape.lineTo(-len / 2 + tipRadius, -width);
  shape.quadraticCurveTo(-len / 2 + tipRadius * 1.5, -width * 2, -len / 2 + tipRadius * 3, 0);
  shape.lineTo(len / 2 - tipRadius * 2, 0);
  shape.quadraticCurveTo(len / 2, width * 2, len / 2, 0);
  shape.lineTo(len / 2 - tipRadius * 1.5, -width);
  shape.lineTo(-len / 2 + tipRadius, -width);

  const extrudeSettings = { depth: 0.08, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02, bevelSegments: 3 };
  const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);
  const mesh = new THREE.Mesh(geo, metalMat);
  mesh.rotation.x = -Math.PI / 2;
  mesh.position.set(0, 0.08, 0);
  mesh.castShadow = true;
  runnerGroup.add(mesh);

  return runnerGroup;
}

const leftRunner = createRunner();
leftRunner.position.set(0, 0, -0.45);
leftRunner.rotation.y = 0.02;
sled.add(leftRunner);

const rightRunner = createRunner();
rightRunner.position.set(0, 0, 0.45);
rightRunner.rotation.y = -0.02;
sled.add(rightRunner);

// --- Deck (platform) ---
const deckGeo = new THREE.BoxGeometry(3.2, 0.08, 1.0);
const deck = new THREE.Mesh(deckGeo, woodMat);
deck.position.set(0, 0.22, 0);
deck.castShadow = true;
deck.receiveShadow = true;
sled.add(deck);

// Deck cross-slats (visual detail)
for (let i = -2; i <= 2; i++) {
  const slatGeo = new THREE.BoxGeometry(0.04, 0.1, 1.02);
  const slat = new THREE.Mesh(slatGeo, darkWoodMat);
  slat.position.set(i * 0.55, 0.22, 0);
  slat.castShadow = true;
  sled.add(slat);
}

// --- Backrest ---
const backrestGeo = new THREE.BoxGeometry(2.8, 0.6, 0.06);
const backrest = new THREE.Mesh(backrestGeo, redMat);
backrest.position.set(0.15, 0.72, -0.52);
backrest.castShadow = true;
sled.add(backrest);

// Backrest top rail
const topRailGeo = new THREE.BoxGeometry(2.9, 0.06, 0.08);
const topRail = new THREE.Mesh(topRailGeo, darkWoodMat);
topRail.position.set(0.15, 1.05, -0.52);
topRail.castShadow = true;
sled.add(topRail);

// --- Uprights (connect deck to backrest) ---
for (let z of [-0.4, 0.4]) {
  const uprightGeo = new THREE.BoxGeometry(0.06, 0.55, 0.06);
  const upright = new THREE.Mesh(uprightGeo, darkWoodMat);
  upright.position.set(1.1, 0.55, z);
  upright.castShadow = true;
  sled.add(upright);
}

// --- Front handle bar ---
const handleGeo = new THREE.CylinderGeometry(0.03, 0.03, 0.9, 8);
const handle = new THREE.Mesh(handleGeo, darkWoodMat);
handle.rotation.x = Math.PI / 2;
handle.position.set(-1.55, 0.5, 0);
handle.castShadow = true;
sled.add(handle);

// Handle supports
for (let z of [-0.4, 0.4]) {
  const supportGeo = new THREE.BoxGeometry(0.04, 0.38, 0.04);
  const support = new THREE.Mesh(supportGeo, darkWoodMat);
  support.position.set(-1.55, 0.38, z);
  support.castShadow = true;
  sled.add(support);
}

// --- Tow ropes ---
for (let z of [-0.25, 0.25]) {
  const ropeGeo = new THREE.CylinderGeometry(0.02, 0.02, 1.2, 6);
  const rope = new THREE.Mesh(ropeGeo, ropeMat);
  rope.rotation.z = Math.PI / 2;
  rope.rotation.y = 0.15;
  rope.position.set(-2.2, 0.3, z);
  rope.castShadow = true;
  sled.add(rope);
}

// --- Decorative front curve (bow) ---
const bowGeo = new THREE.TorusGeometry(0.3, 0.03, 8, 16, Math.PI);
const bow = new THREE.Mesh(bowGeo, redMat);
bow.position.set(-1.6, 0.22, 0);
bow.rotation.y = Math.PI / 2;
bow.castShadow = true;
sled.add(bow);

// --- Position the whole sled ---
sled.position.y = 0.15;
sled.rotation.y = -0.2;
scene.add(sled);

// --- Snow mounds for atmosphere ---
for (let i = 0; i < 8; i++) {
  const moundGeo = new THREE.SphereGeometry(0.3 + Math.random() * 0.5, 12, 8);
  const moundMat = new THREE.MeshStandardMaterial({ color: 0xe8eef4, roughness: 0.95 });
  const mound = new THREE.Mesh(moundGeo, moundMat);
  const angle = Math.random() * Math.PI * 2;
  const dist = 5 + Math.random() * 15;
  mound.position.set(Math.cos(angle) * dist, 0.1, Math.sin(angle) * dist);
  mound.scale.y = 0.4 + Math.random() * 0.3;
  mound.receiveShadow = true;
  scene.add(mound);
}

// --- Snow particles ---
const snowCount = 600;
const snowGeo = new THREE.BufferGeometry();
const snowPositions = new Float32Array(snowCount * 3);
const snowVelocities = new Float32Array(snowCount);

for (let i = 0; i < snowCount; i++) {
  snowPositions[i * 3] = (Math.random() - 0.5) * 30;
  snowPositions[i * 3 + 1] = Math.random() * 15;
  snowPositions[i * 3 + 2] = (Math.random() - 0.5) * 30;
  snowVelocities[i] = 0.01 + Math.random() * 0.03;
}

snowGeo.setAttribute('position', new THREE.BufferAttribute(snowPositions, 3));

const snowMat = new THREE.PointsMaterial({
  color: 0xffffff,
  size: 0.06,
  transparent: true,
  opacity: 0.8,
  sizeAttenuation: true
});

const snowParticles = new THREE.Points(snowGeo, snowMat);
scene.add(snowParticles);

// --- Animation ---
function animate() {
  requestAnimationFrame(animate);

  // Gentle sled bob
  sled.position.y = 0.15 + Math.sin(Date.now() * 0.001) * 0.02;

  // Falling snow
  const positions = snowParticles.geometry.attributes.position.array;
  for (let i = 0; i < snowCount; i++) {
    positions[i * 3 + 1] -= snowVelocities[i];
    positions[i * 3] += Math.sin(Date.now() * 0.0005 + i) * 0.002;
    if (positions[i * 3 + 1] < 0) {
      positions[i * 3 + 1] = 15;
      positions[i * 3] = (Math.random() - 0.5) * 30;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 30;
    }
  }
  snowParticles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
