    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // ── Lights ───────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x404060, 1.5));

    const dirLight = new THREE.DirectionalLight(0xffeedd, 2);
    dirLight.position.set(10, 20, 10);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    dirLight.shadow.camera.near = 1;
    dirLight.shadow.camera.far = 60;
    dirLight.shadow.camera.left = -20;
    dirLight.shadow.camera.right = 20;
    dirLight.shadow.camera.top = 20;
    dirLight.shadow.camera.bottom = -20;
    scene.add(dirLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 0.8);
    rimLight.position.set(-8, 5, -10);
    scene.add(rimLight);

    // ── Ground ───────────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(40, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x2d5a27,
      roughness: 0.95,
      metalness: 0.0
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.5;
    ground.receiveShadow = true;
    scene.add(ground);

    // Grid helper for depth perception
    const grid = new THREE.GridHelper(80, 40, 0x3a7a34, 0x2a5a24);
    grid.position.y = -0.49;
    scene.add(grid);

    // ── Snake Construction ───────────────────────────────
    const SEGMENT_COUNT = 40;
    const segments = [];
    const segmentMeshes = [];

    const headGroup = new THREE.Group();

    // Head shape – slightly elongated sphere
    const headGeo = new THREE.SphereGeometry(0.55, 32, 32);
    const headMat = new THREE.MeshStandardMaterial({
      color: 0x22aa44,
      roughness: 0.4,
      metalness: 0.1
    });
    const headMesh = new THREE.Mesh(headGeo, headMat);
    headMesh.scale.set(1, 0.8, 1.3);
    headMesh.castShadow = true;
    headGroup.add(headMesh);

    // Eyes
    const eyeGeo = new THREE.SphereGeometry(0.1, 16, 16);
    const eyeWhiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.2 });
    const eyePupilMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.3 });

    [-1, 1].forEach(side => {
      const white = new THREE.Mesh(eyeGeo, eyeWhiteMat);
      white.position.set(side * 0.3, 0.2, 0.55);
      headGroup.add(white);

      const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.06, 16, 16), eyePupilMat);
      pupil.position.set(side * 0.3, 0.2, 0.63);
      headGroup.add(pupil);
    });

    // Tongue
    const tongueMat = new THREE.MeshStandardMaterial({ color: 0xdd3333 });
    const tongueGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.4, 8);
    const tongueL = new THREE.Mesh(tongueGeo, tongueMat);
    tongueL.rotation.x = Math.PI / 2;
    tongueL.position.set(-0.08, 0, 0.95);
    tongueL.rotation.z = 0.2;
    headGroup.add(tongueL);

    const tongueR = new THREE.Mesh(tongueGeo, tongueMat);
    tongueR.rotation.x = Math.PI / 2;
    tongueR.position.set(0.08, 0, 0.95);
    tongueR.rotation.z = -0.2;
    headGroup.add(tongueR);

    headGroup.castShadow = true;
    scene.add(headGroup);

    // Body segments
    for (let i = 0; i < SEGMENT_COUNT; i++) {
      const t = i / SEGMENT_COUNT;
      const radius = 0.5 * (1 - t * 0.75);

      const geo = new THREE.SphereGeometry(radius, 16, 16);
      const hue = 0.32 + t * 0.05; // subtle color shift toward tail
      const mat = new THREE.MeshStandardMaterial({
        color: new THREE.Color().setHSL(hue, 0.7, 0.4),
        roughness: 0.5,
        metalness: 0.05
      });

      const mesh = new THREE.Mesh(geo, mat);
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      scene.add(mesh);
      segmentMeshes.push(mesh);
      segments.push({ mesh, radius });
    }

    // ── Animation State ──────────────────────────────────
    const clock = new THREE.Clock();
    const PATH_RADIUS = 6;
    const SNAKE_SPEED = 0.6;
    const WIGGLE_AMP_X = 1.5;
    const WIGGLE_AMP_Y = 0.5;
    const WIGGLE_FREQ = 2.5;
    const SEGMENT_SPACING = 0.35;

    // Store past positions for the body to follow
    const positionHistory = [];
    const MAX_HISTORY = SEGMENT_COUNT * 3;

    function getHeadPosition(time) {
      const angle = time * SNAKE_SPEED;
      const x = Math.cos(angle) * PATH_RADIUS + Math.sin(time * WIGGLE_FREQ) * WIGGLE_AMP_X;
      const z = Math.sin(angle) * PATH_RADIUS + Math.cos(time * WIGGLE_FREQ * 1.3) * WIGGLE_AMP_X;
      const y = Math.sin(time * WIGGLE_FREQ * 0.8) * WIGGLE_AMP_Y + 0.8;
      return new THREE.Vector3(x, y, z);
    }

    // ── Tongue flicker ───────────────────────────────────
    let tongueVisible = true;
    let tongueTimer = 0;

    // ── Render Loop ──────────────────────────────────────
    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Compute head position
      const headPos = getHeadPosition(elapsed);
      headGroup.position.copy(headPos);

      // Head faces movement direction
      const lookAhead = getHeadPosition(elapsed + 0.05);
      headGroup.lookAt(lookAhead);

      // Tongue flicker
      tongueTimer += 0.016;
      if (tongueTimer > 1.5) {
        tongueVisible = !tongueVisible;
        tongueTimer = 0;
      }
      tongueL.visible = tongueVisible;
      tongueR.visible = tongueVisible;

      // Record head position
      positionHistory.unshift(headPos.clone());
      if (positionHistory.length > MAX_HISTORY) positionHistory.pop();

      // Position body segments along the trail
      for (let i = 0; i < SEGMENT_COUNT; i++) {
        const idx = Math.min(i * 2.5, positionHistory.length - 1);
        const pos = positionHistory[Math.floor(idx)] || new THREE.Vector3(0, 0, 0);

        // Add a slight wave to body segments
        const waveOffset = Math.sin(elapsed * WIGGLE_FREQ * 2 - i * 0.4) * 0.15;

        segmentMeshes[i].position.set(
          pos.x + waveOffset,
          pos.y - 0.1 * (i / SEGMENT_COUNT),
          pos.z
        );

        // Scale fade for tail
        const scale = 1 - (i / SEGMENT_COUNT) * 0.3;
        segmentMeshes[i].scale.setScalar(scale);
      }

      // Camera follow
      const camTarget = headPos.clone();
      camTarget.y += 10;
      camTarget.z += 14;
      camera.position.lerp(camTarget, 0.02);
      camera.lookAt(headPos);

      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
