<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x050510);
scene.fog = new THREE.FogExp2(0x050510, 0.08);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.enablePan = false;
controls.minDistance = 3;
controls.maxDistance = 15;

// ── Lighting ─────────────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x4466aa, 0.6);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffffff, 2.5);
dirLight.position.set(3, 5, 4);
scene.add(dirLight);

const dirLight2 = new THREE.DirectionalLight(0x8888ff, 1.2);
dirLight2.position.set(-4, -2, 3);
scene.add(dirLight2);

const pointLight = new THREE.PointLight(0xaaccff, 1.5, 20);
pointLight.position.set(0, 0, 5);
scene.add(pointLight);

// ── Materials ────────────────────────────────────────────────
const iceMaterial = new THREE.MeshPhysicalMaterial({
  color: 0xddeeff,
  metalness: 0.1,
  roughness: 0.15,
  transmission: 0.6,
  thickness: 0.5,
  ior: 1.31,
  clearcoat: 1.0,
  clearcoatRoughness: 0.05,
  transparent: true,
  opacity: 0.9,
});

const shimmerMaterial = new THREE.MeshPhysicalMaterial({
  color: 0xffffff,
  metalness: 0.3,
  roughness: 0.05,
  transmission: 0.8,
  thickness: 0.3,
  ior: 1.31,
  clearcoat: 1.0,
  emissive: 0x223355,
  emissiveIntensity: 0.15,
});

// ── Snowflake Builder ────────────────────────────────────────
const snowflakeGroup = new THREE.Group();
scene.add(snowflakeGroup);

// Create a branch segment (cylinder)
function createSegment(length, radiusTop, radiusBottom, mat) {
  const geo = new THREE.CylinderGeometry(radiusTop, radiusBottom, length, 8, 1);
  geo.translate(0, length / 2, 0);
  return new THREE.Mesh(geo, mat);
}

// Create a hexagonal center
function createCenter(radius, mat) {
  const shape = new THREE.Shape();
  for (let i = 0; i < 6; i++) {
    const angle = (Math.PI / 3) * i - Math.PI / 6;
    const x = radius * Math.cos(angle);
    const y = radius * Math.sin(angle);
    i === 0 ? shape.moveTo(x, y) : shape.lineTo(x, y);
  }
  shape.closePath();

  const extrudeSettings = { depth: 0.06, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02, bevelSegments: 2 };
  const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);
  geo.center();
  return new THREE.Mesh(geo, mat);
}

// Build one arm with recursive branching
function buildArm(depth = 3, length = 1.0, thickness = 0.04) {
  const group = new THREE.Group();

  // Main segment
  const main = createSegment(length, thickness, thickness * 0.6, iceMaterial);
  group.add(main);

  if (depth > 0) {
    const numBranches = Math.min(depth + 2, 5);
    for (let i = 1; i <= numBranches; i++) {
      const t = i / (numBranches + 1);
      const branchLen = length * (0.55 - depth * 0.05) * (1 - t * 0.3);
      const branchThick = thickness * 0.6 * (1 - t * 0.2);

      // Branch on each side
      for (const side of [-1, 1]) {
        const branch = buildArm(depth - 1, branchLen, branchThick);
        branch.position.y = length * t;
        branch.rotation.z = side * Math.PI / 3;
        group.add(branch);
      }
    }

    // Tiny tip cluster
    if (depth <= 2) {
      const tip = createSegment(length * 0.15, thickness * 0.5, thickness * 0.2, shimmerMaterial);
      tip.position.y = length;
      group.add(tip);
    }
  }

  return group;
}

// Assemble the full snowflake
const snowflake = new THREE.Group();

// Center hexagon
snowflake.add(createCenter(0.12, shimmerMaterial));
snowflake.add(createCenter(0.08, iceMaterial));

// Six main arms
for (let i = 0; i < 6; i++) {
  const arm = buildArm(3, 1.0, 0.04);
  arm.rotation.z = (Math.PI / 3) * i;
  snowflake.add(arm);
}

// Decorative ring
const ringGeo = new THREE.TorusGeometry(0.18, 0.012, 8, 48);
const ring = new THREE.Mesh(ringGeo, shimmerMaterial);
snowflake.add(ring);

snowflakeGroup.add(snowflake);

// ── Background Particles ─────────────────────────────────────
const particleCount = 800;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const sizes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3]     = (Math.random() - 0.5) * 30;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 30;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20 - 5;
  sizes[i] = Math.random() * 2 + 0.5;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.PointsMaterial({
  color: 0xaaccff,
  size: 0.04,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
  blending: THREE.AdditiveBlending,
  depthWrite: false,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ────────────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle snowflake rotation
  snowflakeGroup.rotation.z = t * 0.1;
  snowflakeGroup.rotation.x = Math.sin(t * 0.15) * 0.15;
  snowflakeGroup.rotation.y = Math.sin(t * 0.1) * 0.1;

  // Subtle breathing scale
  const breathe = 1 + Math.sin(t * 0.8) * 0.02;
  snowflakeGroup.scale.setScalar(breathe);

  // Animate particles drifting
  const pos = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pos[i * 3 + 1] -= 0.003;
    if (pos[i * 3 + 1] < -15) pos[i * 3 + 1] = 15;
    pos[i * 3] += Math.sin(t + i) * 0.001;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  // Shimmer light
  pointLight.intensity = 1.5 + Math.sin(t * 2) * 0.5;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ───────────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
