</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 2.5, 4);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

// --- Soap Geometry (rounded box via extruded shape) ---
function createSoapShape(w, h, r) {
  const shape = new THREE.Shape();
  const x = -w / 2, y = -h / 2;
  shape.moveTo(x + r, y);
  shape.lineTo(x + w - r, y);
  shape.quadraticCurveTo(x + w, y, x + w, y + r);
  shape.lineTo(x + w, y + h - r);
  shape.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  shape.lineTo(x + r, y + h);
  shape.quadraticCurveTo(x, y + h, x, y + h - r);
  shape.lineTo(x, y + r);
  shape.quadraticCurveTo(x, y, x + r, y);
  return shape;
}

const soapShape = createSoapShape(2.0, 1.2, 0.2);
const extrudeSettings = { depth: 0.5, bevelEnabled: true, bevelThickness: 0.06, bevelSize: 0.06, bevelSegments: 8 };
const soapGeometry = new THREE.ExtrudeGeometry(soapShape, extrudeSettings);
soapGeometry.center();

// --- Soap Material ---
const soapMaterial = new THREE.MeshPhysicalMaterial({
  color: 0xf5f0e8,
  roughness: 0.15,
  metalness: 0.0,
  clearcoat: 0.4,
  clearcoatRoughness: 0.1,
  transmission: 0.15,
  thickness: 0.5,
  ior: 1.4,
  sheen: 0.3,
  sheenRoughness: 0.4,
  sheenColor: new THREE.Color(0xffeedd),
});

const soap = new THREE.Mesh(soapGeometry, soapMaterial);
scene.add(soap);

// --- Brand indent (debossed text plate) ---
const plateGeo = new THREE.PlaneGeometry(0.8, 0.25);
const plateMat = new THREE.MeshStandardMaterial({ color: 0xe8e0d0, roughness: 0.5 });
const plate = new THREE.Mesh(plateGeo, plateMat);
plate.position.set(0, 0.32, 0.04);
plate.rotation.x = -Math.PI / 2;
scene.add(plate);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xfff4e6, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fillLight.position.set(-4, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffeedd, 1.5, 15);
rimLight.position.set(-2, 3, -4);
scene.add(rimLight);

// --- Surface ---
const surfaceGeo = new THREE.CircleGeometry(8, 64);
const surfaceMat = new THREE.MeshStandardMaterial({ color: 0x16213e, roughness: 0.85, metalness: 0.1 });
const surface = new THREE.Mesh(surfaceGeo, surfaceMat);
surface.rotation.x = -Math.PI / 2;
surface.position.y = -0.5;
scene.add(surface);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  soap.rotation.y = Math.sin(t * 0.3) * 0.3;
  soap.position.y = Math.sin(t * 0.8) * 0.08;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this gives you:**

- **Rounded soap bar** — built from an extruded rounded-rectangle shape with bevels, giving it realistic pillowy edges
- **Soap-like material** — `MeshPhysicalMaterial` with clearcoat, slight transmission (translucency), sheen, and warm cream coloring mimics real soap
- **Debossed brand plate** — a subtle flat rectangle on top suggesting an indented logo area
- **Three-point lighting** — warm key light, cool fill light, and a rim point light for that glossy soap highlight
- **Dark surface** — a dark circular platform the soap rests on
- **Gentle animation** — the soap slowly rocks and bobs
- **Orbit controls** — drag to rotate, scroll to zoom

