  bCushion.receiveShadow = true;
  sofa.add(bCushion);
}

// Armrests
for (let side of [-1, 1]) {
  // Armrest top
  const armGeo = createRoundedBox(0.18, 0.12, 0.78, 0.05, 3);
  const arm = new THREE.Mesh(armGeo, fabricMat);
  arm.position.set(side * 1.18, 0.66, 0.02);
