<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 0.5, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.autoRotate = true;
controls.autoRotateSpeed = 1.5;

// --- Build spade shape ---
const spade = new THREE.Shape();
const s = 1.3; // scale factor

spade.moveTo(-0.12 * s, -1.5 * s);          // bottom-left of stem
spade.lineTo(-0.12 * s, -0.7 * s);          // up to bulb junction
spade.bezierCurveTo(
  -0.12 * s, -0.5 * s,                       // control point 1
  -0.9 * s,  0.1 * s,                        // control point 2 (left lobe)
  -0.5 * s,  0.7 * s                         // control point 3 (approaching top)
);
spade.bezierCurveTo(
  -0.25 * s,  0.95 * s,                      // control point 1
  -0.08 * s,  1.15 * s,                      // control point 2
   0,        1.25 * s                        // top tip
);
spade.bezierCurveTo(
   0.08 * s,  1.15 * s,                      // control point 1
   0.25 * s,  0.95 * s,                      // control point 2
   0.5 * s,  0.7 * s                         // control point 3
);
spade.bezierCurveTo(
   0.9 * s,  0.1 * s,                        // control point 1 (right lobe)
   0.12 * s, -0.5 * s,                       // control point 2
   0.12 * s, -0.7 * s                        // control point 3 (back to stem)
);
spade.lineTo(0.12 * s, -1.5 * s);           // bottom-right of stem
spade.lineTo(-0.12 * s, -1.5 * s);          // close stem

// --- Extrude settings ---
const extrudeSettings = {
  depth: 0.25,
  bevelEnabled: true,
  bevelThickness: 0.06,
  bevelSize: 0.04,
  bevelOffset: 0,
  bevelSegments: 8
};

const geometry = new THREE.ExtrudeGeometry(spade, extrudeSettings);
geometry.center();

// --- Material ---
const material = new THREE.MeshPhysicalMaterial({
  color: 0x0a0a0a,
  metalness: 0.85,
  roughness: 0.15,
  clearcoat: 1.0,
  clearcoatRoughness: 0.05,
  envMapIntensity: 1.5,
});

const mesh = new THREE.Mesh(geometry, material);
mesh.castShadow = true;
mesh.receiveShadow = true;
scene.add(mesh);

// --- Edge wireframe overlay ---
const edgesGeo = new THREE.EdgesGeometry(geometry, 15);
const edgesMat = new THREE.LineBasicMaterial({ color: 0x334466, transparent: true, opacity: 0.3 });
const edges = new THREE.LineSegments(edgesGeo, edgesMat);
mesh.add(edges);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x404060, 0.5);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
keyLight.position.set(3, 5, 4);
keyLight.castShadow = true;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 1.2);
fillLight.position.set(-4, -1, 2);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6644, 2, 15);
rimLight.position.set(0, -3, -3);
scene.add(rimLight);

const topLight = new THREE.PointLight(0x4488ff, 1.5, 10);
topLight.position.set(0, 4, 0);
scene.add(topLight);

// --- Env map (simple procedural) ---
const pmremGenerator = new THREE.PMREMGenerator(renderer);
const envScene = new THREE.Scene();
envScene.background = new THREE.Color(0x222244);
const envLight1 = new THREE.PointLight(0xffffff, 100, 50);
envLight1.position.set(5, 5, 5);
envScene.add(envLight1);
const envLight2 = new THREE.PointLight(0x4466ff, 80, 50);
envLight2.position.set(-5, 3, -5);
envScene.add(envLight2);
const envRT = pmremGenerator.fromScene(envScene);
scene.environment = envRT.texture;

// --- Particle field ---
const particleCount = 300;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3]     = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0x667799, size: 0.03, transparent: true, opacity: 0.6,
  blending: THREE.AdditiveBlending, depthWrite: false
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// --- Animate ---
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  mesh.rotation.y = Math.sin(t * 0.3) * 0.15;
  mesh.rotation.x = Math.sin(t * 0.2) * 0.05;
  mesh.position.y = Math.sin(t * 0.5) * 0.1;

  particles.rotation.y = t * 0.02;
  particles.rotation.x = t * 0.01;

  controls.update();
  renderer.render(scene, camera);
}
animate();
</script>
</body>
