<body>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene, Camera, Renderer ──────────────────────────────
const scene    = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 50);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ─────────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0, 0);

// ── Lighting ─────────────────────────────────────────────
const ambient = new THREE.AmbientLight(0xffffff, 0.4);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xffffff, 2.5);
key.position.set(5, 8, 6);
scene.add(key);

const fill = new THREE.DirectionalLight(0x8888ff, 0.8);
fill.position.set(-4, 2, -3);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffddaa, 1.0);
rim.position.set(0, -3, -5);
scene.add(rim);

// ── Spoon Material ───────────────────────────────────────
const spoonMat = new THREE.MeshStandardMaterial({
  color: 0xc0c0c0,
  metalness: 0.95,
  roughness: 0.15,
  envMapIntensity: 1.0,
});

// ── Build the Spoon ──────────────────────────────────────
const spoon = new THREE.Group();

// -- Bowl (lathe profile for a realistic concave shape) --
const bowlProfile = [];
const steps = 20;
for (let i = 0; i <= steps; i++) {
  const t = i / steps;
  const angle = t * Math.PI;          // 0 → π (half-circle sweep)
  const r = 1.0 * Math.sin(angle);    // radius at each step
  const y = -0.35 + 0.35 * Math.cos(angle) * 0.6;  // shallow y-profile
  bowlProfile.push(new THREE.Vector2(Math.max(r, 0.001), y));
}
// Close the profile back along the axis
for (let i = steps; i >= 0; i--) {
  const t = i / steps;
  const angle = t * Math.PI;
  const r = 1.0 * Math.sin(angle) * 0.05;  // narrow back
  const y = -0.35 + 0.35 * Math.cos(angle) * 0.6;
  bowlProfile.push(new THREE.Vector2(Math.max(r, 0.001), y));
}

const bowlGeo = new THREE.LatheGeometry(bowlProfile, 48);
const bowl = new THREE.Mesh(bowlGeo, spoonMat);
bowl.position.y = 2.8;
spoon.add(bowl);

// -- Handle --
const handleGeo = new THREE.CylinderGeometry(0.12, 0.10, 4.5, 24);
const handle = new THREE.Mesh(handleGeo, spoonMat);
handle.position.y = 0;
spoon.add(handle);

// -- Handle tip (rounded cap) --
const tipGeo = new THREE.SphereGeometry(0.12, 24, 12, 0, Math.PI * 2, 0, Math.PI / 2);
const tip = new THREE.Mesh(tipGeo, spoonMat);
tip.position.y = -2.25;
tip.rotation.x = Math.PI;
spoon.add(tip);

// -- Neck (tapered transition from handle to bowl) --
