const neck = new THREE.Mesh(neckGeo, spoonMat);
neck.position.y = 2.0;
spoon.add(neck);

// -- Slight tilt for presentation --
spoon.rotation.z = Math.PI * 0.15;
scene.add(spoon);

// ── Ground plane (subtle reflection hint) ────────────────
const groundGeo = new THREE.PlaneGeometry(100, 100);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e,
  metalness: 0.5,
  roughness: 0.8,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -3.5;
scene.add(ground);

// ── Animation Loop ───────────────────────────────────────
function animate(time) {
  requestAnimationFrame(animate);
  spoon.rotation.y = time * 0.0008;
  controls.update();
  renderer.render(scene, camera);
}
animate(0);

// ── Resize ───────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the scene

| Part | Geometry | Role |
|---|---|---|
| **Bowl** | `LatheGeometry` from a hand-crafted profile curve | Creates the concave spoon head |
| **Handle** | `CylinderGeometry` (tapered) | Long thin shaft |
| **Neck** | `CylinderGeometry` (wider cylinder) | Smooth transition from handle to bowl |
| **Tip** | Half `SphereGeometry` | Rounded end cap |

**Features:**
- **Metallic material** — high metalness / low roughness for a stainless-steel look
- **Three-point lighting** — key, fill, and rim lights for dramatic shading
- **OrbitControls** — click-drag to rotate, scroll to zoom
- **Gentle auto-rotation** so the spoon slowly spins
- **Fog + ground plane** for depth and grounding

