  <script>
    // ── Scene, Camera, Renderer ──
    const scene = new THREE.Scene();
    scene.fog = new THREE.FogExp2(0x000011, 0.02);

    const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 1000);
    camera.position.z = 6;

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    document.body.appendChild(renderer.domElement);

    // ── Star Shape ──
    function createStarShape(points, outerRadius, innerRadius) {
      const shape = new THREE.Shape();
      const step = Math.PI / points;
      for (let i = 0; i < 2 * points; i++) {
        const r = i % 2 === 0 ? outerRadius : innerRadius;
        const angle = i * step - Math.PI / 2;
        const x = Math.cos(angle) * r;
        const y = Math.sin(angle) * r;
        i === 0 ? shape.moveTo(x, y) : shape.lineTo(x, y);
      }
      shape.closePath();
      return shape;
    }

    const starShape = createStarShape(5, 2, 0.85);

    const extrudeSettings = {
      depth: 0.4,
      bevelEnabled: true,
      bevelThickness: 0.15,
      bevelSize: 0.15,
      bevelSegments: 5
    };

    const starGeometry = new THREE.ExtrudeGeometry(starShape, extrudeSettings);
    starGeometry.center();

    const starMaterial = new THREE.MeshStandardMaterial({
      color: 0xffcc33,
      emissive: 0xffaa00,
      emissiveIntensity: 0.3,
      metalness: 0.6,
      roughness: 0.2,
    });

    const star = new THREE.Mesh(starGeometry, starMaterial);
    scene.add(star);

    // ── Glow (sprite) ──
    const glowCanvas = document.createElement('canvas');
    glowCanvas.width = glowCanvas.height = 256;
    const ctx = glowCanvas.getContext('2d');
    const gradient = ctx.createRadialGradient(128, 128, 0, 128, 128, 128);
    gradient.addColorStop(0, 'rgba(255,200,50,0.6)');
    gradient.addColorStop(0.4, 'rgba(255,160,20,0.2)');
    gradient.addColorStop(1, 'rgba(255,100,0,0)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, 256, 256);

    const glowTexture = new THREE.CanvasTexture(glowCanvas);
    const glowMaterial = new THREE.SpriteMaterial({
      map: glowTexture,
      transparent: true,
      blending: THREE.AdditiveBlending,
    });
    const glow = new THREE.Sprite(glowMaterial);
    glow.scale.set(8, 8, 1);
    star.add(glow);

    // ── Lights ──
    const ambientLight = new THREE.AmbientLight(0x333355, 0.5);
    scene.add(ambientLight);

    const pointLight = new THREE.PointLight(0xffdd88, 2, 20);
    pointLight.position.set(3, 3, 5);
    scene.add(pointLight);

    const rimLight = new THREE.PointLight(0x4488ff, 1.5, 20);
    rimLight.position.set(-4, -2, 3);
    scene.add(rimLight);

    // ── Background Particles ──
    const particleCount = 600;
    const particleGeometry = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount * 3; i++) {
      positions[i] = (Math.random() - 0.5) * 60;
    }
    particleGeometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));

    const particleMaterial = new THREE.PointsMaterial({
      color: 0xffffff,
      size: 0.08,
      transparent: true,
      opacity: 0.7,
    });
    const particles = new THREE.Points(particleGeometry, particleMaterial);
    scene.add(particles);

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      star.rotation.z = t * 0.3;
      star.rotation.y = Math.sin(t * 0.5) * 0.3;
      star.position.y = Math.sin(t * 0.8) * 0.3;

      glow.material.opacity = 0.6 + Math.sin(t * 2) * 0.15;
      glow.scale.setScalar(3.5 + Math.sin(t * 1.5) * 0.5);

      particles.rotation.y = t * 0.02;
      particles.rotation.x = t * 0.01;

      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What this creates

- **3D Extruded Star** — A 5-pointed star with beveled edges and golden material that rotates gently
- **Glow Effect** — An additive-blended sprite behind the star that pulses softly
- **Dynamic Lighting** — A warm key light and a cool blue rim light for dimension
- **Starfield** — 600 tiny background particles that slowly drift/rotate
- **Floating Animation** — The star gently bobs up and down while spinning
- **Responsive** — Handles window resizing automatically

