  opacity: 0.7,
  transparent: true,
  roughness: 0.2,
  side: THREE.DoubleSide,
  depthWrite: false,
});
const cap = new THREE.Mesh(capGeo, capMat);
cap.rotation.x = -Math.PI / 2;
cap.position.y = 0.01;
