backPanel.position.set(0, 1.55, -0.4);
stove.add(backPanel);

scene.add(stove);

// ── Floor ──
const floorGeo = new THREE.PlaneGeometry(20, 20);
const floor = new THREE.Mesh(floorGeo, matFloor);
floor.rotation.x = -Math.PI / 2;
floor.receiveShadow = true;
scene.add(floor);

// ── Counter / backsplash wall ──
const wallGeo = new THREE.PlaneGeometry(10, 5);
const wallMat = new THREE.MeshStandardMaterial({ color: 0x1e1e30, roughness: 0.8 });
const wall = new THREE.Mesh(wallGeo, wallMat);
wall.position.set(0, 2.5, -1.2);
wall.receiveShadow = true;
scene.add(wall);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Animate burner glow
  glowBurners.forEach((g, i) => {
    const flicker = 0.6 + 0.4 * Math.sin(t * 3 + i * 1.7) * Math.sin(t * 7 + i * 2.3);
    g.material.emissiveIntensity = 1.5 + flicker * 1.5;
  });

  // Animate oven glow
  ovenGlowMat.emissiveIntensity = 0.6 + 0.3 * Math.sin(t * 0.5);

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single file gives you a fully interactive 3D stove with:

- **Realistic geometry** — main body, stainless steel top, 4 coil burners with rings, oven door with glass window, control panel with 4 knobs, handle, legs, and backsplash
- **Animated burner glow** — each burner flickers with a warm orange emissive glow
- **Oven light** — a soft orange glow behind the glass door that pulses gently
- **Lighting** — key, fill, and rim lights with soft shadow mapping for depth
- **Materials** — PBR-style metals (stainless steel, dark body, chrome handle)
- **Orbit controls** — drag to rotate, scroll to zoom, with damping
- **Environment** — dark floor and back wall for contrast

