```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Strawberry</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #1a1a2e; }
    canvas { display: block; }
    #info {
      position: absolute; bottom: 20px; left: 50%; transform: translateX(-50%);
      color: #fff; font-family: 'Segoe UI', sans-serif; font-size: 14px;
      background: rgba(0,0,0,0.4); padding: 8px 18px; border-radius: 20px;
      pointer-events: none;
    }
  </style>
</head>
<body>
  <div id="info">🍓 Strawberry — drag to orbit</div>
  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
    }
  }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene Setup ──────────────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 2, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0.5, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.update();

    // ── Lighting ─────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0xffeedd, 0.6));

    const keyLight = new THREE.DirectionalLight(0xfff5e6, 2.5);
    keyLight.position.set(4, 6, 4);
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0xc8d8ff, 0.8);
    fillLight.position.set(-3, 2, -2);
    scene.add(fillLight);

    const rimLight = new THREE.DirectionalLight(0xff9999, 1.0);
    rimLight.position.set(0, -2, -4);
    scene.add(rimLight);

    // ── Strawberry Body (LatheGeometry) ──────────────────
    function createStrawberryProfile() {
      const pts = [];
      const steps = 40;
      for (let i = 0; i <= steps; i++) {
        const t = i / steps;
        // Custom profile: pointed top, bulging middle, rounded base
        const y = t * 2.8;
        let r;
        if (t < 0.05) {
          // Very tip — point
          r = t * 3.0;
        } else if (t < 0.25) {
          // Upper taper
          r = 0.15 + (t - 0.05) * 2.0;
        } else if (t < 0.55) {
          // Bulging middle
          const s = (t - 0.25) / 0.3;
          r = 0.55 + 0.55 * Math.sin(s * Math.PI);
        } else if (t < 0.8) {
          // Lower taper
          const s = (t - 0.55) / 0.25;
          r = 1.1 * (1 - s * 0.55);
        } else {
          // Rounded base
          const s = (t - 0.8) / 0.2;
          r = 0.495 * Math.cos(s * Math.PI * 0.5);
        }
        pts.push(new THREE.Vector2(Math.max(r, 0.001), y));
      }
      return pts;
    }

    const bodyGeo = new THREE.LatheGeometry(
      createStrawberryProfile(), 64
    );
    bodyGeo.computeVertexNormals();

    const bodyMat = new THREE.MeshStandardMaterial({
      color: 0xcc2244,
      roughness: 0.35,
      metalness: 0.05,
    });

    // Add subtle color variation via vertex colors
    const bodyCount = bodyGeo.attributes.position.count;
    const colors = new Float32Array(bodyCount * 3);
    const posAttr = bodyGeo.attributes.position;
    for (let i = 0; i < bodyCount; i++) {
      const y = posAttr.getY(i);
      const norm = Math.max(0, Math.min(1, y / 2.8));
      // Darker at bottom, brighter at top
      const r = 0.7 + norm * 0.2 + (Math.random() - 0.5) * 0.03;
      const g = 0.08 + norm * 0.05 + (Math.random() - 0.5) * 0.02;
      const b = 0.15 + norm * 0.05 + (Math.random() - 0.5) * 0.02;
      colors[i * 3] = r;
      colors[i * 3 + 1] = g;
      colors[i * 3 + 2] = b;
    }
    bodyGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    bodyMat.vertexColors = true;

    const strawberry = new THREE.Group();
    const bodyMesh = new THREE.Mesh(bodyGeo, bodyMat);
    strawberry.add(bodyMesh);

    // ── Seeds (achenes) ──────────────────────────────────
    const seedGeo = new THREE.SphereGeometry(0.035, 6, 6);
    // Flatten them slightly
    seedGeo.scale(1, 0.6, 1);
    const seedMat = new THREE.MeshStandardMaterial({
      color: 0xddcc88,
      roughness: 0.6,
      metalness: 0.1,
    });

    // Generate seed positions on the lathe surface
    const seedPositions = [];
    const profile = createStrawberryProfile();
    const seedRows = 12;
    const seedsPerRow = [0, 5, 7, 9, 10, 11, 11, 10, 9, 7, 5, 3];

    for (let row = 0; row < seedRows; row++) {
      const t = (row + 0.5) / seedRows;
      const y = t * 2.6 + 0.1;

      // Find radius at this height via interpolation
      let r = 0;
      for (let i = 0; i < profile.length - 1; i++) {
        if (profile[i].y <= y && profile[i + 1].y >= y) {
          const lt = (y - profile[i].y) / (profile[i + 1].y - profile[i].y + 0.001);
          r = profile[i].x + (profile[i + 1].x - profile[i].x) * lt;
          break;
        }
      }
      if (r < 0.05) continue;

      const count = seedsPerRow[row] || 7;
      for (let s = 0; s < count; s++) {
        const angle = (s / count) * Math.PI * 2 + (row % 2) * (Math.PI / count);
        const jitterR = r * (0.92 + Math.random() * 0.16);
        const jitterY = y + (Math.random() - 0.5) * 0.12;
        const x = Math.cos(angle) * jitterR;
        const z = Math.sin(angle) * jitterR;

        seedPositions.push(new THREE.Vector3(x, jitterY, z));

        // Create a small dimple + seed
        const seed = new THREE.Mesh(seedGeo, seedMat);
        seed.position.set(x, jitterY, z);

        // Orient seed outward
        seed.lookAt(0, jitterY, 0);
        seed.rotateX(Math.PI / 2);

        strawberry.add(seed);
      }
    }

    // ── Green Calyx (leafy top) ──────────────────────────
    const leafMat = new THREE.MeshStandardMaterial({
      color: 0x338833,
      roughness: 0.5,
      metalness: 0.05,
      side: THREE.DoubleSide,
    });

    const darkLeafMat = new THREE.MeshStandardMaterial({
      color: 0x226622,
      roughness: 0.5,
      metalness: 0.05,
      side: THREE.DoubleSide,
    });

    function createLeaf(angle, length, width, mat) {
      const shape = new THREE.Shape();
      shape.moveTo(0, 0);
      shape.quadraticCurveTo(width * 0.5, length * 0.3, 0, length);
      shape.quadraticCurveTo(-width * 0.5, length * 0.3, 0, 0);

      const geo = new THREE.ShapeGeometry(shape, 8);
      const leaf = new THREE.Mesh(geo, mat);
      leaf.rotation.z = angle;
      leaf.rotation.x = -0.4 - Math.random() * 0.5;
      leaf.position.y = 2.75;
      return leaf;
    }

    // Main leaves
    const leafCount = 7;
    for (let i = 0; i < leafCount; i++) {
      const angle = (i / leafCount) * Math.PI * 2;
      const len = 0.5 + Math.random() * 0.4;
      const w = 0.15 + Math.random() * 0.1;
      const leaf = createLeaf(angle, len, w, i % 2 === 0 ? leafMat : darkLeafMat);
      strawberry.add(leaf);
    }

    // Small stem
    const stemGeo = new THREE.CylinderGeometry(0.04, 0.05, 0.35, 8);
    const stemMat = new THREE.MeshStandardMaterial({
      color: 0x44aa44,
      roughness: 0.6,
    });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.position.y = 2.95;
    strawberry.add(stem);

    // ── Position strawberry ──────────────────────────────
    strawberry.position.y = -0.5;
    scene.add(strawberry);

    // ── Ground (subtle shadow plane) ─────────────────────
    const groundGeo = new THREE.CircleGeometry(3, 48);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x1a1a2e,
      roughness: 1,
      metalness: 0,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -1.2;
    scene.add(ground);

    // ── Particle sparkles ────────────────────────────────
    const sparkleCount = 60;
    const sparkleGeo = new THREE.BufferGeometry();
    const sparklePos = new Float32Array(sparkleCount * 3);
    for (let i = 0; i < sparkleCount; i++) {
      sparklePos[i * 3] = (Math.random() - 0.5) * 8;
      sparklePos[i * 3 + 1] = Math.random() * 5;
      sparklePos[i * 3 + 2] = (Math.random() - 0.5) * 8;
    }
    sparkleGeo.setAttribute('position', new THREE.BufferAttribute(sparklePos, 3));
    const sparkleMat = new THREE.PointsMaterial({
      color: 0xffeedd,
      size: 0.03,
      transparent: true,
      opacity: 0.6,
      sizeAttenuation: true,
    });
    const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
    scene.add(sparkles);

    // ── Animation ────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle rotation
      strawberry.rotation.y = t * 0.3;

      // Subtle bob
      strawberry.position.y = -0.5 + Math.sin(t * 0.8) * 0.08;

      // Twinkle sparkles
      sparkleMat.opacity = 0.4 + Math.sin(t * 2) * 0.2;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's in the strawberry

| Component | Technique |
|---|---|
| **Red body** | `LatheGeometry` with a hand-crafted profile curve (64 segments) that traces the characteristic tapered-to-bulging shape |
| **Vertex colors** | Each vertex gets a slight red/green/blue variation — darker at the base, brighter at the crown |
| **Seeds (achenes)** | ~80 flattened `SphereGeometry` meshes placed in concentric rings along the lathe surface, each oriented outward |
| **Green calyx** | 7 `ShapeGeometry` leaves with quadratic Bézier curves, alternating light/dark green, tilted downward |
| **Stem** | Small cylinder on top |
| **Lighting** | 3-point setup (key, fill, rim) + warm ambient, ACES filmic tone mapping |
| **Animation** | Gentle Y-axis rotation + sinusoidal bob, twinkling sparkle particles |
| **Interaction** | `OrbitControls` — drag to rotate, scroll to zoom |

