<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a1a);
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(8, 6, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 4, 0);
controls.enableDamping = true;
controls.maxPolarAngle = Math.PI / 2.05;
controls.update();

// ── Materials ──
const poleMat = new THREE.MeshStandardMaterial({ color: 0x2a2a2a, roughness: 0.6, metalness: 0.8 });
const baseMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.7, metalness: 0.6 });
const lampHousingMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.4, metalness: 0.7 });
const glassMat = new THREE.MeshStandardMaterial({
  color: 0xffffcc, emissive: 0xffee88, emissiveIntensity: 2.0,
  roughness: 0.1, transparent: true, opacity: 0.85
});
const groundMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.95 });
const sidewalkMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.9 });

// ── Ground ──
const ground = new THREE.Mesh(new THREE.PlaneGeometry(80, 80), groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

const sidewalk = new THREE.Mesh(new THREE.PlaneGeometry(6, 80), sidewalkMat);
sidewalk.rotation.x = -Math.PI / 2;
sidewalk.position.set(2.5, 0.01, 0);
sidewalk.receiveShadow = true;
scene.add(sidewalk);

// ── Streetlamp Group ──
const lampGroup = new THREE.Group();
scene.add(lampGroup);

// Base plate
const basePlate = new THREE.Mesh(new THREE.CylinderGeometry(0.6, 0.7, 0.15, 24), baseMat);
basePlate.position.y = 0.075;
basePlate.castShadow = true;
basePlate.receiveShadow = true;
lampGroup.add(basePlate);

// Flared base ring
const baseRing = new THREE.Mesh(new THREE.TorusGeometry(0.65, 0.06, 8, 32), baseMat);
baseRing.rotation.x = Math.PI / 2;
baseRing.position.y = 0.15;
lampGroup.add(baseRing);

// Main pole
const pole = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.18, 7, 16), poleMat);
pole.position.y = 3.65;
pole.castShadow = true;
lampGroup.add(pole);

// Decorative bands on pole
for (let i = 0; i < 3; i++) {
  const band = new THREE.Mesh(new THREE.TorusGeometry(0.16 - i * 0.01, 0.025, 8, 24), baseMat);
  band.rotation.x = Math.PI / 2;
  band.position.y = 1.5 + i * 2.2;
  lampGroup.add(band);
}

// Curved arm using a tube
const armCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 7.1, 0),
  new THREE.Vector3(0.3, 7.6, 0),
  new THREE.Vector3(1.0, 7.9, 0),
  new THREE.Vector3(1.8, 7.7, 0),
  new THREE.Vector3(2.4, 7.3, 0),
]);
const armGeo = new THREE.TubeGeometry(armCurve, 20, 0.07, 12, false);
const arm = new THREE.Mesh(armGeo, poleMat);
arm.castShadow = true;
lampGroup.add(arm);

// ── Lamp Head ──
const headGroup = new THREE.Group();
headGroup.position.set(2.4, 7.3, 0);
lampGroup.add(headGroup);

// Upper housing (visor/hood)
const hoodGeo = new THREE.CylinderGeometry(0.35, 0.55, 0.3, 24);
const hood = new THREE.Mesh(hoodGeo, lampHousingMat);
hood.position.y = 0.15;
hood.castShadow = true;
headGroup.add(hood);

// Hood top dome
const domeGeo = new THREE.SphereGeometry(0.35, 24, 12, 0, Math.PI * 2, 0, Math.PI / 2);
const dome = new THREE.Mesh(domeGeo, lampHousingMat);
dome.position.y = 0.3;
headGroup.add(dome);

// Glass globe (lower part)
const glassGeo = new THREE.SphereGeometry(0.45, 24, 16, 0, Math.PI * 2, Math.PI * 0.5, Math.PI * 0.5);
const glass = new THREE.Mesh(glassGeo, glassMat);
glass.position.y = -0.1;
headGroup.add(glass);

// Inner bulb sphere
const bulbGeo = new THREE.SphereGeometry(0.15, 16, 16);
const bulbMat = new THREE.MeshStandardMaterial({
  color: 0xffffff, emissive: 0xffeeaa, emissiveIntensity: 5.0
});
const bulb = new THREE.Mesh(bulbGeo, bulbMat);
bulb.position.y = -0.1;
headGroup.add(bulb);

// Bottom ring
const bottomRing = new THREE.Mesh(new THREE.TorusGeometry(0.45, 0.03, 8, 24), lampHousingMat);
bottomRing.rotation.x = Math.PI / 2;
bottomRing.position.y = -0.1;
headGroup.add(bottomRing);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x1a1a3a, 0.4);
scene.add(ambientLight);

// Main streetlamp light
const lampLight = new THREE.PointLight(0xffdd88, 40, 25, 1.5);
lampLight.position.set(2.4, 7.0, 0);
lampLight.castShadow = true;
lampLight.shadow.mapSize.set(1024, 1024);
lampLight.shadow.bias = -0.001;
scene.add(lampLight);

// Subtle warm fill
const fillLight = new THREE.PointLight(0xffaa44, 5, 15, 2);
fillLight.position.set(2.4, 6.5, 0);
scene.add(fillLight);

// ── Light cone (visible glow volume) ──
const coneGeo = new THREE.ConeGeometry(2.5, 5, 32, 1, true);
const coneMat = new THREE.MeshBasicMaterial({
  color: 0xffdd88, transparent: true, opacity: 0.04,
  side: THREE.DoubleSide, depthWrite: false
});
const lightCone = new THREE.Mesh(coneGeo, coneMat);
lightCone.position.set(2.4, 4.5, 0);
scene.add(lightCone);

// ── Floating dust particles ──
const particleCount = 300;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = Math.random() * 4 + 0.5;
  positions[i * 3]     = 2.4 + Math.cos(angle) * radius;
  positions[i * 3 + 1] = Math.random() * 7 + 1;
  positions[i * 3 + 2] = Math.sin(angle) * radius;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xffddaa, size: 0.04, transparent: true, opacity: 0.5,
  depthWrite: false, blending: THREE.AdditiveBlending
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle light flicker
  lampLight.intensity = 40 + Math.sin(t * 2.3) * 1.5 + Math.sin(t * 5.7) * 0.8;
  fillLight.intensity = 5 + Math.sin(t * 3.1) * 0.5;

  // Slow particle drift
  const pos = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pos[i * 3 + 1] += Math.sin(t + i) * 0.0003;
    pos[i * 3] += Math.cos(t * 0.5 + i * 0.1) * 0.0002;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
