const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 1000);
camera.position.z = 4;

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
document.body.appendChild(renderer.domElement);

// --- Starfield ---
const starGeo = new THREE.BufferGeometry();
const starPos = new Float32Array(3000 * 3);
for (let i = 0; i < 3000 * 3; i++) starPos[i] = (Math.random() - 0.5) * 400;
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({ color: 0xffffff, size: 0.3 })));

// --- Sun Sphere (procedural shader) ---
const sunGeo = new THREE.SphereGeometry(1, 64, 64);
const sunMat = new THREE.ShaderMaterial({
  uniforms: { time: { value: 0 } },
  vertexShader: `
    varying vec3 vNormal;
    varying vec2 vUv;
    void main(){
      vNormal = normalize(normalMatrix * normal);
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform float time;
    varying vec3 vNormal;
    varying vec2 vUv;

    // Simplex-like noise (compact)
    vec3 mod289(vec3 x){return x-floor(x*(1./289.))*289.;}
    vec4 mod289(vec4 x){return x-floor(x*(1./289.))*289.;}
    vec4 perm(vec4 x){return mod289(((x*34.)+1.)*x);}
    float noise(vec3 p){
      vec3 a=floor(p),d=p-a;a=mod289(a);
      vec4 b=a.xxyy+vec4(0,1,0,1),k1=perm(b.xyxy),k2=perm(k1.xyxy+b.zzww);
      vec4 c=clamp(vec4(2.)-(k2*.00587+d.zzzz),0.,1.);
      vec4 o1=fract(k2*(1./41.))*d.x, o2=fract(k2*(1./41.))*(d.x-1.),
           o3=fract(perm(k2+1.)*(1./41.))*d.y, o4=fract(perm(k2+1.)*(1./41.))*(d.y-1.);
      vec4 r=c*c*c*(c*(c*6.-15.)+10.);
      return dot(r, vec4(1.)) * 0.5 + 0.5;
    }

    void main(){
      float n = noise(vUv * 8.0 + time * 0.3);
      float n2 = noise(vUv * 16.0 - time * 0.15);
      float brightness = 0.7 + 0.3 * n + 0.15 * n2;

      // Fresnel-like rim glow
      float rim = 1.0 - max(dot(vNormal, vec3(0,0,1)), 0.0);
      rim = pow(rim, 2.0);

      vec3 hotColor  = vec3(1.0, 0.95, 0.6);
      vec3 warmColor = vec3(1.0, 0.55, 0.1);
      vec3 darkColor = vec3(0.9, 0.2, 0.0);

      vec3 col = mix(warmColor, hotColor, brightness);
      col = mix(col, darkColor, 0.3 * (1.0 - brightness));
      col += vec3(1.0, 0.8, 0.3) * rim * 0.6;

      gl_FragColor = vec4(col, 1.0);
    }
  `
});
const sun = new THREE.Mesh(sunGeo, sunMat);
scene.add(sun);

// --- Glow Sprites (multiple layers) ---
const glowTex = (() => {
  const c = document.createElement('canvas');
  c.width = c.height = 256;
  const ctx = c.getContext('2d');
  const g = ctx.createRadialGradient(128, 128, 0, 128, 128, 128);
  g.addColorStop(0,   'rgba(255,220,100,1)');
  g.addColorStop(0.2, 'rgba(255,180,50,0.6)');
  g.addColorStop(0.5, 'rgba(255,120,20,0.15)');
  g.addColorStop(1,   'rgba(255,80,0,0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, 256, 256);
  return new THREE.CanvasTexture(c);
})();

[2.8, 4.0, 6.0].forEach((s, i) => {
