    new THREE.SpriteMaterial({ map: glowTex, blending: THREE.AdditiveBlending,
                               transparent: true, opacity: 0.5 - i * 0.1 })
  );
  sprite.scale.setScalar(s);
  sun.add(sprite);
});

// --- Light ---
const sunLight = new THREE.PointLight(0xffeedd, 3, 100);
scene.add(sunLight);
scene.add(new THREE.AmbientLight(0x332211, 0.3));

// --- Animate ---
const clock = new THREE.Clock();
(function loop(){
  requestAnimationFrame(loop);
  const t = clock.getElapsedTime();
  sun.rotation.y = t * 0.05;
  sunMat.uniforms.time.value = t;
  renderer.render(scene, camera);
})();

// --- Resize ---
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
