  { radius: 4.0, color: 0x111111 },
  { radius: 3.0, color: 0x1155cc },
  { radius: 2.0, color: 0xcc2222 },
  { radius: 1.0, color: 0xddaa00 },
];

const thickness = 0.15;

rings.forEach(ring => {
  const geo = new THREE.CylinderGeometry(ring.radius, ring.radius, thickness, 128);
  const mat = new THREE.MeshStandardMaterial({
    color: ring.color,
    roughness: 0.4,
    metalness: 0.1,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.y = thickness / 2;
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  targetGroup.add(mesh);
});

// ── Stand / Mount ──
const standGeo = new THREE.CylinderGeometry(0.15, 0.2, 6, 16);
const standMat = new THREE.MeshStandardMaterial({ color: 0x555555, metalness: 0.8, roughness: 0.3 });
const stand = new THREE.Mesh(standGeo, standMat);
stand.position.y = -3.5;
stand.castShadow = true;
targetGroup.add(stand);

const baseGeo = new THREE.CylinderGeometry(1.5, 1.8, 0.3, 32);
const base = new THREE.Mesh(baseGeo, standMat);
base.position.y = -6.5;
base.castShadow = true;
targetGroup.add(base);

// ── Ground plane ──
const groundGeo = new THREE.PlaneGeometry(60, 60);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -6.65;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating animation ──
function animate() {
  requestAnimationFrame(animate);
  const t = performance.now() * 0.001;
  targetGroup.position.y = Math.sin(t * 0.8) * 0.3;
  targetGroup.rotation.y = Math.sin(t * 0.3) * 0.15;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **ISSF-style target** with 5 concentric rings — white → black → blue → red → yellow bullseye
- **Metal stand and base** holding the target upright
- **Soft floating animation** — the target gently bobs and sways
- **OrbitControls** — drag to rotate, scroll to zoom
- **Shadows, fog, and rim lighting** for depth
- **Fully responsive** to window resizing

Just save it as `index.html` and open in any modern browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Tape Roll</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
position: absolute;
bottom: 20px;
left: 50%;
transform: translateX(-50%);
color: #fff;
font-family: 'Segoe UI', sans-serif;
font-size: 14px;
opacity: 0.6;
pointer-events: none;
}
</style>
</head>
<body>
<div id="info">Click & drag to orbit · Scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.035);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(5, 4, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 1.2, 0);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xffeedd, 2.5);
mainLight.position.set(5, 8, 4);
mainLight.castShadow = true;
mainLight.shadow.mapSize.set(2048, 2048);
mainLight.shadow.camera.near = 0.5;
mainLight.shadow.camera.far = 25;
mainLight.shadow.camera.left = -6;
mainLight.shadow.camera.right = 6;
mainLight.shadow.camera.top = 6;
mainLight.shadow.camera.bottom = -6;
mainLight.shadow.bias = -0.001;
scene.add(mainLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6633, 1.5, 15);
rimLight.position.set(-3, 5, -4);
scene.add(rimLight);

// ── Materials ──
const cardboardMat = new THREE.MeshStandardMaterial({
  color: 0xd4a86a,
  roughness: 0.9,
  metalness: 0.0,
});

const tapeMat = new THREE.MeshPhysicalMaterial({
  color: 0xfff4c8,
  roughness: 0.2,
  metalness: 0.0,
  transmission: 0.55,
  thickness: 0.5,
  ior: 1.45,
  transparent: true,
  opacity: 0.85,
  side: THREE.DoubleSide,
  clearcoat: 0.3,
  clearcoatRoughness: 0.1,
});

const tapeEdgeMat = new THREE.MeshStandardMaterial({
  color: 0xe8d9a0,
  roughness: 0.5,
  metalness: 0.0,
  side: THREE.DoubleSide,
});

const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a4a,
  roughness: 0.8,
  metalness: 0.2,
});

// ── Tape Roll Group ──
const tapeRoll = new THREE.Group();
scene.add(tapeRoll);

// Cardboard tube (inner cylinder)
const tubeRadius = 0.35;
const tubeHeight = 1.2;
const tubeThickness = 0.04;

const tubeGeo = new THREE.CylinderGeometry(
  tubeRadius, tubeRadius, tubeHeight, 32, 1, true
);
const tube = new THREE.Mesh(tubeGeo, cardboardMat);
tube.castShadow = true;
tapeRoll.add(tube);

// Tube end caps (rings)
const ringGeo = new THREE.RingGeometry(tubeRadius - tubeThickness, tubeRadius, 32);
for (const y of [-tubeHeight / 2, tubeHeight / 2]) {
  const ring = new THREE.Mesh(ringGeo, cardboardMat);
  ring.rotation.x = Math.PI / 2;
  ring.position.y = y;
  ring.castShadow = true;
  tapeRoll.add(ring);
}

// Tube inner surface
const innerGeo = new THREE.CylinderGeometry(
  tubeRadius - tubeThickness, tubeRadius - tubeThickness, tubeHeight, 32, 1, true
);
const innerMat = new THREE.MeshStandardMaterial({
  color: 0xb89050,
  roughness: 0.95,
  side: THREE.BackSide,
});
const innerTube = new THREE.Mesh(innerGeo, innerMat);
tapeRoll.add(innerTube);

// Tape roll body (outer cylinder)
const tapeRadius = 1.0;
const tapeRollGeo = new THREE.CylinderGeometry(
  tapeRadius, tapeRadius, tubeHeight, 64, 1, true
);
const tapeRollMesh = new THREE.Mesh(tapeRollGeo, tapeMat);
tapeRollMesh.castShadow = true;
tapeRollMesh.receiveShadow = true;
tapeRoll.add(tapeRollMesh);

// Tape roll end caps (discs showing the spiral)
function createTapeEndCap() {
  const group = new THREE.Group();

  // Main disc
  const discGeo = new THREE.CircleGeometry(tapeRadius, 64);
  const disc = new THREE.Mesh(discGeo, tapeEdgeMat);
  group.add(disc);

  // Spiral lines to show tape layers
  const spiralPoints = [];
  const spiralTurns = 18;
  const spiralSteps = 300;
  for (let i = 0; i <= spiralSteps; i++) {
    const t = i / spiralSteps;
    const angle = t * Math.PI * 2 * spiralTurns;
    const r = (tapeRadius - tubeRadius) * t + tubeRadius;
    spiralPoints.push(new THREE.Vector3(
      Math.cos(angle) * r,
      Math.sin(angle) * r,
      0
    ));
  }
  const spiralCurve = new THREE.CatmullRomCurve3(spiralPoints);
  const spiralGeo = new THREE.TubeGeometry(spiralCurve, 400, 0.006, 8, false);
  const spiralMat = new THREE.MeshStandardMaterial({
    color: 0xc8b878,
    roughness: 0.6,
  });
  const spiral = new THREE.Mesh(spiralGeo, spiralMat);
  group.add(spiral);

  // Inner cardboard circle
  const innerCircleGeo = new THREE.CircleGeometry(tubeRadius, 32);
  const innerCircle = new THREE.Mesh(innerCircleGeo, cardboardMat);
  group.add(innerCircle);

  return group;
}

const topCap = createTapeEndCap();
topCap.position.y = tubeHeight / 2;
topCap.rotation.x = -Math.PI / 2;
tapeRoll.add(topCap);

const bottomCap = createTapeEndCap();
bottomCap.position.y = -tubeHeight / 2;
bottomCap.rotation.x = Math.PI / 2;
tapeRoll.add(bottomCap);

// ── Loose Tape End ──
function createTapeEnd() {
  const shape = new THREE.Shape();
  const w = 0.7;
  const h = 2.2;
  const r = 0.08;

  shape.moveTo(-w + r, -h);
  shape.lineTo(w - r, -h);
  shape.quadraticCurveTo(w, -h, w, -h + r);
  shape.lineTo(w, h - r);
  shape.quadraticCurveTo(w, h, w - r, h);
  shape.lineTo(-w + r, h);
  shape.quadraticCurveTo(-w, h, -w, h - r);
  shape.lineTo(-w, -h + r);
  shape.quadraticCurveTo(-w, -h, -w + r, -h);

  const geo = new THREE.ShapeGeometry(shape, 24);
  const mesh = new THREE.Mesh(geo, tapeMat);
  mesh.castShadow = true;
  return mesh;
}

const tapeEnd = createTapeEnd();
// Position it coming off the top of the roll
tapeEnd.position.set(0.5, tubeHeight / 2 + 1.0, 0.3);
tapeEnd.rotation.z = 0.3;
tapeEnd.rotation.y = -0.2;
tapeRoll.add(tapeEnd);

// Folded tip of the tape end
const tipGeo = new THREE.BoxGeometry(0.7, 0.15, 0.06);
const tip = new THREE.Mesh(tipGeo, tapeMat);
tip.position.set(0.5, tubeHeight / 2 + 2.2 + 0.075, 0.3);
tip.rotation.z = 0.3;
tip.rotation.y = -0.2;
tapeRoll.add(tip);

// ── Position the whole roll ──
tapeRoll.position.set(0, 0, 0);
tapeRoll.rotation.z = 0.15;

// ── Ground Plane ──
const groundGeo = new THREE.CircleGeometry(12, 64);
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating Particles ──
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = Math.random() * 10 - 2;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xffeedd,
  size: 0.03,
  transparent: true,
  opacity: 0.4,
  sizeAttenuation: true,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  tapeRoll.rotation.y = Math.sin(t * 0.3) * 0.4;
  tapeRoll.position.y = Math.sin(t * 0.5) * 0.15 + 0.5;

  // Tape end subtle wave
  tapeEnd.rotation.z = 0.3 + Math.sin(t * 1.2) * 0.05;
  tip.rotation.z = 0.3 + Math.sin(t * 1.2) * 0.05;

  // Particles drift
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(t + i) * 0.001;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a **3D adhesive tape roll** scene with:

- **Cardboard inner tube** — hollow cylinder with end rings and inner surface
- **Semi-transparent tape body** — using `MeshPhysicalMaterial` with transmission/glass-like properties for that real tape look
- **Spiral detail** on the top/bottom faces showing wound tape layers
- **Loose tape end** hanging off the roll with a folded tip
- **Cinematic lighting** — warm key light, cool fill, orange rim light
- **Shadow casting** and a reflective ground plane
- **Floating particles** for atmosphere
- **Gentle animation** — the roll bobs and sways, the tape end waves slightly
- **OrbitControls** — drag to rotate, scroll to zoom

