<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.Fog(0x87CEEB, 40, 120);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(8, 6, 10);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 4;
controls.maxDistance = 30;
controls.update();

// --- Lights ---
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(10, 15, 8);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.left = -15;
sun.shadow.camera.right = 15;
sun.shadow.camera.top = 15;
sun.shadow.camera.bottom = -15;
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 50;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8ec5fc, 0.4);
fill.position.set(-8, 5, -6);
scene.add(fill);

// --- Materials ---
const hullMat = new THREE.MeshStandardMaterial({ color: 0x4a5a3a, roughness: 0.7, metalness: 0.2 });
const trackMat = new THREE.MeshStandardMaterial({ color: 0x2a2a2a, roughness: 0.9, metalness: 0.1 });
const turretMat = new THREE.MeshStandardMaterial({ color: 0x3d4f32, roughness: 0.6, metalness: 0.3 });
const barrelMat = new THREE.MeshStandardMaterial({ color: 0x2e3a28, roughness: 0.4, metalness: 0.5 });
const wheelMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.8, metalness: 0.2 });
const detailMat = new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.5, metalness: 0.4 });

// --- Tank Group ---
const tank = new THREE.Group();

// Hull body
const hull = new THREE.Mesh(new THREE.BoxGeometry(3.2, 0.9, 5.5), hullMat);
hull.position.y = 0.7;
hull.castShadow = true;
hull.receiveShadow = true;
tank.add(hull);

// Hull front slope
const frontSlope = new THREE.Mesh(new THREE.BoxGeometry(3.2, 0.5, 1.2), hullMat);
frontSlope.position.set(0, 1.15, 2.2);
frontSlope.rotation.x = -0.3;
frontSlope.castShadow = true;
tank.add(frontSlope);

// Hull rear
const rear = new THREE.Mesh(new THREE.BoxGeometry(3.0, 0.7, 0.4), hullMat);
rear.position.set(0, 0.75, -2.7);
rear.castShadow = true;
tank.add(rear);

// --- Turret ---
const turretGroup = new THREE.Group();
turretGroup.position.set(0, 1.5, 0.3);

const turretBase = new THREE.Mesh(
  new THREE.CylinderGeometry(0.5, 0.7, 0.5, 8),
  turretMat
);
turretBase.position.y = 0.25;
turretBase.castShadow = true;
turretGroup.add(turretBase);

const turretTop = new THREE.Mesh(new THREE.BoxGeometry(1.8, 0.5, 2.4), turretMat);
turretTop.position.set(0, 0.7, -0.1);
turretTop.castShadow = true;
turretGroup.add(turretTop);

// Commander's hatch
const hatch = new THREE.Mesh(
  new THREE.CylinderGeometry(0.2, 0.2, 0.15, 12),
  turretMat
);
hatch.position.set(0.4, 1.05, 0.3);
turretGroup.add(hatch);

// Muzzle brake
const muzzle = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.18, 0.3, 8), barrelMat);
muzzle.rotation.x = Math.PI / 2;
muzzle.position.set(0, 0.5, 3.55);
turretGroup.add(muzzle);

// Barrel
const barrel = new THREE.Mesh(
  new THREE.CylinderGeometry(0.08, 0.1, 3.2, 12),
  barrelMat
);
barrel.rotation.x = Math.PI / 2;
barrel.position.set(0, 0.5, 1.8);
barrel.castShadow = true;
turretGroup.add(barrel);

// Barrel thermal sleeve lines
for (let i = 0; i < 12; i++) {
  const ring = new THREE.Mesh(
    new THREE.TorusGeometry(0.105, 0.012, 6, 12),
    detailMat
  );
  ring.position.set(0, 0.5, 0.4 + i * 0.22);
  turretGroup.add(ring);
}

tank.add(turretGroup);

// --- Tracks ---
function createTrack(side) {
  const trackGroup = new THREE.Group();
  const x = side * 1.75;

  // Track belt outer
  const trackOuter = new THREE.Mesh(
    new THREE.BoxGeometry(0.45, 0.5, 5.8),
    trackMat
  );
  trackOuter.position.set(x, 0.45, 0);
  trackOuter.castShadow = true;
  trackOuter.receiveShadow = true;
  trackGroup.add(trackOuter);

  // Track ends (rounded)
  const endGeo = new THREE.CylinderGeometry(0.25, 0.25, 0.45, 12);
  const frontEnd = new THREE.Mesh(endGeo, trackMat);
  frontEnd.rotation.z = Math.PI / 2;
  frontEnd.position.set(x, 0.45, 2.9);
  trackGroup.add(frontEnd);

  const rearEnd = new THREE.Mesh(endGeo, trackMat);
  rearEnd.rotation.z = Math.PI / 2;
  rearEnd.position.set(x, 0.45, -2.9);
  trackGroup.add(rearEnd);

  // Road wheels
  for (let i = 0; i < 5; i++) {
    const wheel = new THREE.Mesh(
      new THREE.CylinderGeometry(0.22, 0.22, 0.35, 12),
      wheelMat
    );
    wheel.rotation.z = Math.PI / 2;
    wheel.position.set(x, 0.35, 1.8 - i * 0.9);
    wheel.castShadow = true;
    trackGroup.add(wheel);
  }

  // Idler (front wheel)
  const idler = new THREE.Mesh(
    new THREE.CylinderGeometry(0.28, 0.28, 0.35, 12),
    wheelMat
  );
  idler.rotation.z = Math.PI / 2;
  idler.position.set(x, 0.45, 2.5);
  trackGroup.add(idler);

  // Drive sprocket (rear)
  const sprocket = new THREE.Mesh(
    new THREE.CylinderGeometry(0.3, 0.3, 0.35, 12),
    wheelMat
  );
  sprocket.rotation.z = Math.PI / 2;
  sprocket.position.set(x, 0.45, -2.5);
  trackGroup.add(sprocket);

  // Track detail teeth
  for (let i = 0; i < 18; i++) {
    const tooth = new THREE.Mesh(
      new THREE.BoxGeometry(0.08, 0.12, 0.08),
      trackMat
    );
    const angle = (i / 18) * Math.PI;
    const tx = x + (side > 0 ? 0.25 : -0.25);
    const tz = 1.8 - i * 0.2;
    tooth.position.set(tx, 0.7, tz);
    trackGroup.add(tooth);
  }

  return trackGroup;
}

tank.add(createTrack(1));
tank.add(createTrack(-1));

// --- Details ---
// Engine deck grilles
for (let i = 0; i < 4; i++) {
  const grille = new THREE.Mesh(
    new THREE.BoxGeometry(0.8, 0.05, 0.15),
    detailMat
  );
  grille.position.set(-0.5 + i * 0.5, 1.18, -2.3);
  tank.add(grille);
}

// Side skirts
for (const side of [-1, 1]) {
  const skirt = new THREE.Mesh(
    new THREE.BoxGeometry(0.15, 0.6, 4.0),
    hullMat
  );
  skirt.position.set(side * 1.6, 0.5, 0.2);
  skirt.castShadow = true;
  tank.add(skirt);
}

// Antenna
const antenna = new THREE.Mesh(
  new THREE.CylinderGeometry(0.015, 0.02, 1.2, 6),
  detailMat
);
antenna.position.set(-0.5, 2.2, 0.5);
tank.add(antenna);

const antennaTip = new THREE.Mesh(
  new THREE.SphereGeometry(0.04, 8, 8),
  new THREE.MeshStandardMaterial({ color: 0xff3333, emissive: 0xff0000, emissiveIntensity: 0.3 })
);
antennaTip.position.set(-0.5, 2.8, 0.5);
tank.add(antennaTip);

scene.add(tank);

// --- Ground ---
const groundGeo = new THREE.PlaneGeometry(100, 100);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x5a7a3a, roughness: 0.95 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// --- Simple terrain bumps ---
for (let i = 0; i < 30; i++) {
  const bump = new THREE.Mesh(
    new THREE.SphereGeometry(0.3 + Math.random() * 0.8, 8, 6),
    new THREE.MeshStandardMaterial({ color: 0x4a6a2a, roughness: 1 })
  );
  bump.position.set(
    (Math.random() - 0.5) * 40,
    -0.2,
    (Math.random() - 0.5) * 40
  );
  bump.scale.y = 0.3;
  bump.receiveShadow = true;
  scene.add(bump);
}

// --- Rocks ---
for (let i = 0; i < 15; i++) {
  const rock = new THREE.Mesh(
    new THREE.DodecahedronGeometry(0.2 + Math.random() * 0.4, 1),
    new THREE.MeshStandardMaterial({ color: 0x777777, roughness: 0.9 })
  );
  const angle = Math.random() * Math.PI * 2;
  const dist = 6 + Math.random() * 20;
  rock.position.set(Math.cos(angle) * dist, 0.15, Math.sin(angle) * dist);
  rock.rotation.set(Math.random(), Math.random(), Math.random());
  rock.castShadow = true;
  rock.receiveShadow = true;
  scene.add(rock);
}

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Subtle turret rotation
  turretGroup.rotation.y = Math.sin(t * 0.3) * 0.4;

  // Very subtle tank idle vibration
  tank.position.y = Math.sin(t * 2) * 0.005;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
