}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 5);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0.3, 0);

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 1;
keyLight.shadow.camera.far = 20;
keyLight.shadow.camera.left = -3;
keyLight.shadow.camera.right = 3;
keyLight.shadow.camera.top = 3;
keyLight.shadow.camera.bottom = -3;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fillLight.position.set(-4, 3, -2);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffa060, 1.0);
rimLight.position.set(-3, 2, -5);
scene.add(rimLight);

const bottomLight = new THREE.DirectionalLight(0xffeecc, 0.3);
bottomLight.position.set(0, -3, 2);
scene.add(bottomLight);

// ── Tomato Material ──
const tomatoMaterial = new THREE.MeshPhysicalMaterial({
  color: new THREE.Color(0xcc2211),
  roughness: 0.35,
  metalness: 0.0,
  clearcoat: 0.6,
  clearcoatRoughness: 0.15,
  reflectivity: 0.4,
  sheen: 0.3,
  sheenColor: new THREE.Color(0xff4433),
  sheenRoughness: 0.5,
});

// ── Tomato Body ──
const bodyGeo = new THREE.IcosahedronGeometry(1.4, 5);
const pos = bodyGeo.attributes.position;

for (let i = 0; i < pos.count; i++) {
  let x = pos.getX(i);
  let y = pos.getY(i);
  let z = pos.getZ(i);

  // Flatten slightly (tomato shape)
  y *= 0.85;

  // Create lobes (tomatoes have ~6 lobes)
  const theta = Math.atan2(z, x);
  const lobeFactor = 0.06 * Math.cos(6 * theta);
  const yInfluence = Math.max(0, 1 - Math.abs(y) / 1.2);
  const r = Math.sqrt(x * x + z * z);
  if (r > 0.01) {
    const scale = 1 + lobeFactor * yInfluence;
    x *= scale;
    z *= scale;
  }

  // Top indentation (where stem attaches)
  if (y > 0.7) {
    const indent = (y - 0.7) / 0.8;
    const topScale = 1 - indent * 0.25;
    x *= topScale;
    z *= topScale;
  }

  // Bottom subtle rounding
  if (y < -0.8) {
    const bottomFactor = (y + 0.8) / -1.0;
    const bottomScale = 1 - bottomFactor * 0.1;
    x *= bottomScale;
    z *= bottomScale;
  }

  // Add subtle noise for organic feel
  const noise = 0.015 * Math.sin(x * 8.0) * Math.sin(y * 7.0) * Math.sin(z * 9.0);
  const len = Math.sqrt(x * x + y * y + z * z);
  if (len > 0.01) {
    const n = 1 + noise / len;
    x *= n;
    y *= n;
    z *= n;
  }

  pos.setXYZ(i, x, y, z);
}

bodyGeo.computeVertexNormals();
const tomatoBody = new THREE.Mesh(bodyGeo, tomatoMaterial);
tomatoBody.castShadow = true;
tomatoBody.receiveShadow = true;
tomatoBody.position.y = 0.5;
scene.add(tomatoBody);

// ── Stem ──
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x3a7a2a,
  roughness: 0.7,
  metalness: 0.0,
});

const stemGeo = new THREE.CylinderGeometry(0.04, 0.06, 0.4, 8);
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.set(0, 1.95, 0);
stem.castShadow = true;
scene.add(stem);

// ── Calyx (green leafy crown) ──
const calyxMat = new THREE.MeshStandardMaterial({
  color: 0x2d6b1e,
  roughness: 0.6,
  metalness: 0.0,
  side: THREE.DoubleSide,
});

const numSepals = 8;
for (let i = 0; i < numSepals; i++) {
  const angle = (i / numSepals) * Math.PI * 2;
  const nextAngle = ((i + 1) / numSepals) * Math.PI * 2;

  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.15, 0.3, 0.02, 0.55);
  shape.quadraticCurveTo(-0.05, 0.3, 0, 0);

  const sepalGeo = new THREE.ShapeGeometry(shape, 4);
  const sepal = new THREE.Mesh(sepalGeo, calyxMat);

  const midAngle = (angle + nextAngle) / 2;
  sepal.position.set(
    Math.cos(midAngle) * 0.15,
    1.75,
    Math.sin(midAngle) * 0.15
  );
  sepal.rotation.y = -midAngle + Math.PI / 2;
  sepal.rotation.x = -0.6;
  sepal.castShadow = true;
  scene.add(sepal);
}

// Small ring at base of calyx
const ringGeo = new THREE.TorusGeometry(0.12, 0.025, 8, 16);
const ring = new THREE.Mesh(ringGeo, calyxMat);
ring.position.set(0, 1.72, 0);
ring.rotation.x = Math.PI / 2;
scene.add(ring);

// ── Ground Plane ──
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Shadow catcher (soft shadow disc) ──
const shadowGeo = new THREE.CircleGeometry(1.2, 32);
const shadowMat = new THREE.MeshBasicMaterial({
  color: 0x000000,
  transparent: true,
  opacity: 0.25,
  depthWrite: false,
});
const shadowDisc = new THREE.Mesh(shadowGeo, shadowMat);
shadowDisc.rotation.x = -Math.PI / 2;
shadowDisc.position.y = 0.01;
scene.add(shadowDisc);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  tomatoBody.rotation.y = t * 0.3;
  stem.rotation.y = t * 0.3;

  // Subtle bob
  const bob = Math.sin(t * 0.8) * 0.03;
  tomatoBody.position.y = 0.5 + bob;
  stem.position.y = 1.95 + bob;

  // Update calyx positions with bob
  scene.traverse(child => {
    if (child.geometry?.type === 'ShapeGeometry') {
      child.position.y = 1.75 + bob;
    }
    if (child.geometry?.type === 'TorusGeometry') {
      child.position.y = 1.72 + bob;
    }
  });

  // Shadow disc follows
  shadowDisc.position.x = Math.sin(t * 0.3) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
