</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 18);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 2, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.update();

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffffff, 2.5);
keyLight.position.set(4, 6, 3);
keyLight.castShadow = false;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-3, 2, -2);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xff8844, 0.8);
rimLight.position.set(0, -2, -4);
scene.add(rimLight);

// ── Materials ──
const handleMat = new THREE.MeshStandardMaterial({
  color: 0x1565c0, roughness: 0.35, metalness: 0.05
});
const gripMat = new THREE.MeshStandardMaterial({
  color: 0x0d47a1, roughness: 0.7, metalness: 0.0
});
const headMat = new THREE.MeshStandardMaterial({
  color: 0xe3f2fd, roughness: 0.3, metalness: 0.05
});
const bristleColors = [0xffffff, 0x42a5f5, 0xff7043, 0xffffff, 0x42a5f5];

// ── Toothbrush Group ──
const toothbrush = new THREE.Group();

// ── Handle (lathe profile) ──
const handlePoints = [];
const hSegments = 20;
for (let i = 0; i <= hSegments; i++) {
  const t = i / hSegments;
  const y = t * 2.8 - 0.1;
  let r;
  if (t < 0.05) r = 0.18 + t * 2;
  else if (t < 0.15) r = 0.28;
  else if (t < 0.35) r = 0.28 + Math.sin((t - 0.15) / 0.2 * Math.PI) * 0.06;
  else if (t < 0.55) r = 0.28;
  else if (t < 0.7) r = 0.28 - (t - 0.55) * 1.2;
  else if (t < 0.85) r = 0.1 - (t - 0.7) * 0.4;
  else r = 0.04 + (1 - t) * 0.16;
  handlePoints.push(new THREE.Vector2(r, y));
}
const handleGeo = new THREE.LatheGeometry(handlePoints, 24);
const handle = new THREE.Mesh(handleGeo, handleMat);
handle.position.y = -1.0;
toothbrush.add(handle);

// ── Grip bumps ──
for (let i = 0; i < 5; i++) {
  const bumpGeo = new THREE.TorusGeometry(0.27, 0.025, 8, 24);
  const bump = new THREE.Mesh(bumpGeo, gripMat);
  bump.position.y = -0.55 + i * 0.1;
  bump.rotation.x = Math.PI / 2;
  toothbrush.add(bump);
}

// ── Neck ──
const neckPoints = [
  new THREE.Vector2(0.04, 0),
  new THREE.Vector2(0.05, 0.05),
  new THREE.Vector2(0.12, 0.15),
  new THREE.Vector2(0.16, 0.25),
  new THREE.Vector2(0.22, 0.35),
  new THREE.Vector2(0.28, 0.45),
  new THREE.Vector2(0.30, 0.5),
];
const neckGeo = new THREE.LatheGeometry(neckPoints, 24);
const neck = new THREE.Mesh(neckGeo, handleMat);
neck.position.y = 1.7;
toothbrush.add(neck);

// ── Head ──
const headShape = new THREE.Shape();
const hw = 0.32, hh = 0.55, hr = 0.1;
headShape.moveTo(-hw + hr, -hh);
headShape.lineTo(hw - hr, -hh);
headShape.quadraticCurveTo(hw, -hh, hw, -hh + hr);
headShape.lineTo(hw, hh - hr);
headShape.quadraticCurveTo(hw, hh, hw - hr, hh);
headShape.lineTo(-hw + hr, hh);
headShape.quadraticCurveTo(-hw, hh, -hw, hh - hr);
headShape.lineTo(-hw, -hh + hr);
headShape.quadraticCurveTo(-hw, -hh, -hw + hr, -hh);

const headExtrudeSettings = { depth: 0.06, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02, bevelSegments: 4 };
const headGeo = new THREE.ExtrudeGeometry(headShape, headExtrudeSettings);
const head = new THREE.Mesh(headGeo, headMat);
head.rotation.x = -Math.PI / 2;
head.position.set(0, 2.35, -0.04);
toothbrush.add(head);

// ── Head top surface (flat cap) ──
const topGeo = new THREE.ShapeGeometry(headShape);
const topMesh = new THREE.Mesh(topGeo, headMat);
topMesh.rotation.x = -Math.PI / 2;
topMesh.position.set(0, 2.35, 0.06);
toothbrush.add(topMesh);

// ── Bristles ──
const bristleGeo = new THREE.CylinderGeometry(0.006, 0.008, 0.22, 6);
const bristleMats = bristleColors.map(c =>
  new THREE.MeshStandardMaterial({ color: c, roughness: 0.9, metalness: 0.0 })
);

const bristleRows = 6;
const bristleCols = 4;
const spacingX = 0.12;
const spacingZ = 0.14;
const startX = -(bristleCols - 1) * spacingX / 2;
const startZ = -(bristleRows - 1) * spacingZ / 2;

for (let row = 0; row < bristleRows; row++) {
  for (let col = 0; col < bristleCols; col++) {
    const mat = bristleMats[(row + col) % bristleColors.length];
    const bristle = new THREE.Mesh(bristleGeo, mat);

    // Slightly varied height for realism
    const heightVar = 0.16 + Math.random() * 0.1;
    bristle.scale.y = heightVar / 0.22;

    // Offset from head center
    const x = startX + col * spacingX;
    const z = startZ + row * spacingZ;

    // Curve bristles slightly outward
    const angle = Math.atan2(z, x);
    const bend = 0.05;

    bristle.position.set(
      x + Math.cos(angle) * bend * 0.3,
      2.35 + 0.08 + heightVar / 2,
      z + Math.sin(angle) * bend * 0.3
    );
    bristle.rotation.z = Math.cos(angle) * bend;
    bristle.rotation.x = Math.sin(angle) * bend;

    toothbrush.add(bristle);
  }
}

// ── Rubber grip band ──
const bandGeo = new THREE.TorusGeometry(0.29, 0.035, 8, 32);
const bandMat = new THREE.MeshStandardMaterial({ color: 0x0a1929, roughness: 0.85 });
const band = new THREE.Mesh(bandGeo, bandMat);
band.position.y = -0.3;
band.rotation.x = Math.PI / 2;
toothbrush.add(band);

const band2 = band.clone();
band2.position.y = -0.8;
toothbrush.add(band2);

// ── Position toothbrush ──
toothbrush.rotation.z = -0.15;
toothbrush.rotation.x = 0.1;
scene.add(toothbrush);

// ── Floor reflection hint ──
const floorGeo = new THREE.PlaneGeometry(20, 20);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e, roughness: 0.8, metalness: 0.2
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -3;
scene.add(floor);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  toothbrush.rotation.y = Math.sin(t * 0.5) * 0.3;
  toothbrush.position.y = Math.sin(t * 0.8) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

- **Handle** — built with `LatheGeometry` for a smooth, tapered ergonomic profile
- **Grip bumps** — torus rings for tactile texture detail
- **Rubber grip bands** — dark accent bands on the handle
- **Neck** — curved lathe profile transitioning to the head
- **Head** — rounded rectangle using `ExtrudeGeometry` with bevel
- **Bristles** — 24 small cylinders in a 6×4 grid with varied heights, slight outward curve, and alternating blue/white/orange colors
- **Lighting** — key, fill, and rim lights for a studio-like look
- **Animation** — gentle floating and swaying motion
- **OrbitControls** — drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Torch</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ─────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x050508);
scene.fog = new THREE.FogExp2(0x050508, 0.04);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2.5, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

// ── Ground ──────────────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(20, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, roughness: 0.9, metalness: 0.1
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Torch Handle ────────────────────────────────────────
const handleGroup = new THREE.Group();
scene.add(handleGroup);

// Main stick
const stickGeo = new THREE.CylinderGeometry(0.04, 0.055, 2.2, 8);
const stickMat = new THREE.MeshStandardMaterial({
  color: 0x5c3a1e, roughness: 0.85, metalness: 0.0
});
const stick = new THREE.Mesh(stickGeo, stickMat);
stick.position.y = 1.1;
handleGroup.add(stick);

// Charred top section
const charGeo = new THREE.CylinderGeometry(0.05, 0.04, 0.35, 8);
const charMat = new THREE.MeshStandardMaterial({
  color: 0x1a0e05, roughness: 0.95, metalness: 0.0
});
const char = new THREE.Mesh(charGeo, charMat);
char.position.y = 2.27;
handleGroup.add(char);

// Tapered tip
const tipGeo = new THREE.ConeGeometry(0.04, 0.15, 8);
const tip = new THREE.Mesh(tipGeo, charMat);
tip.position.y = 2.5;
handleGroup.add(tip);

// ── Flame Light ─────────────────────────────────────────
const flameLight = new THREE.PointLight(0xff6a1a, 8, 12, 2);
flameLight.position.set(0, 2.65, 0);
flameLight.castShadow = false;
handleGroup.add(flameLight);

const flameLight2 = new THREE.PointLight(0xffaa33, 3, 6, 2);
flameLight2.position.set(0, 2.55, 0);
handleGroup.add(flameLight2);

// Subtle ambient
const ambient = new THREE.AmbientLight(0x111122, 0.3);
scene.add(ambient);

// ── Flame Particles ─────────────────────────────────────
const FLAME_COUNT = 120;
const flameParticles = [];
const flameMeshes = [];

const flameTexture = createFlameTexture();

for (let i = 0; i < FLAME_COUNT; i++) {
  const size = 0.12 + Math.random() * 0.25;
  const geo = new THREE.PlaneGeometry(size, size);
  const mat = new THREE.MeshBasicMaterial({
    map: flameTexture,
    transparent: true,
    depthWrite: false,
    blending: THREE.AdditiveBlending,
    side: THREE.DoubleSide,
  });

  const mesh = new THREE.Mesh(geo, mat);
  const p = {
    mesh,
    baseY: 2.35 + Math.random() * 0.1,
    life: Math.random(),
    maxLife: 0.4 + Math.random() * 0.8,
    speed: 0.6 + Math.random() * 1.2,
    radius: Math.random() * 0.12,
    angle: Math.random() * Math.PI * 2,
    angleSpeed: (Math.random() - 0.5) * 2,
    size,
    layer: Math.random(), // 0 = inner (hot), 1 = outer (cool)
  };

  flameParticles.push(p);
  flameMeshes.push(mesh);
  handleGroup.add(mesh);
}

// ── Ember Particles ─────────────────────────────────────
const EMBER_COUNT = 40;
const embers = [];

for (let i = 0; i < EMBER_COUNT; i++) {
  const size = 0.015 + Math.random() * 0.03;
  const geo = new THREE.PlaneGeometry(size, size);
  const mat = new THREE.MeshBasicMaterial({
    color: 0xff4400,
    transparent: true,
    depthWrite: false,
    blending: THREE.AdditiveBlending,
    side: THREE.DoubleSide,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.visible = false;

  const e = {
    mesh,
    life: 0,
    maxLife: 1 + Math.random() * 2,
    vx: (Math.random() - 0.5) * 0.5,
    vy: 0.5 + Math.random() * 1.5,
    vz: (Math.random() - 0.5) * 0.5,
    delay: Math.random() * 3,
    active: false,
  };

  embers.push(e);
  handleGroup.add(mesh);
}

// ── Smoke Particles ─────────────────────────────────────
const SMOKE_COUNT = 20;
const smokes = [];

for (let i = 0; i < SMOKE_COUNT; i++) {
  const size = 0.3 + Math.random() * 0.4;
  const geo = new THREE.PlaneGeometry(size, size);
  const mat = new THREE.MeshBasicMaterial({
    color: 0x888888,
    transparent: true,
    opacity: 0.15,
    depthWrite: false,
    blending: THREE.NormalBlending,
    side: THREE.DoubleSide,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.visible = false;

  const s = {
    mesh,
    life: 0,
    maxLife: 2 + Math.random() * 2,
    vx: (Math.random() - 0.5) * 0.15,
    vy: 0.3 + Math.random() * 0.5,
    vz: (Math.random() - 0.5) * 0.15,
    delay: Math.random() * 4,
    active: false,
  };

  smokes.push(s);
  handleGroup.add(mesh);
}

// ── Helper: Flame Texture ───────────────────────────────
function createFlameTexture() {
  const canvas = document.createElement('canvas');
  canvas.width = 64;
  canvas.height = 64;
  const ctx = canvas.getContext('2d');
  const grad = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
  grad.addColorStop(0, 'rgba(255,255,255,1)');
  grad.addColorStop(0.2, 'rgba(255,255,200,0.8)');
  grad.addColorStop(0.5, 'rgba(255,150,50,0.4)');
  grad.addColorStop(1, 'rgba(255,50,0,0)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, 64, 64);
  const tex = new THREE.CanvasTexture(canvas);
  tex.needsUpdate = true;
  return tex;
}

// ── Animation ───────────────────────────────────────────
const clock = new THREE.Clock();
let emberTimer = 0;
let smokeTimer = 0;

function animate() {
  requestAnimationFrame(animate);
  const dt = clock.getDelta();
  const t = clock.getElapsedTime();

  // Torch sway
  handleGroup.rotation.z = Math.sin(t * 0.8) * 0.03 + Math.sin(t * 1.7) * 0.015;
  handleGroup.rotation.x = Math.sin(t * 0.6) * 0.02;

  // Flicker light
  const flicker = 0.7 + Math.sin(t * 12) * 0.1 + Math.sin(t * 17.3) * 0.08 + Math.sin(t * 7.7) * 0.12;
  flameLight.intensity = 8 * flicker;
  flameLight2.intensity = 3 * flicker;
  flameLight.color.setHSL(0.07 + Math.sin(t * 3) * 0.02, 1, 0.5);

  // Update flame particles
  for (const p of flameParticles) {
    p.life += dt / p.maxLife;
    if (p.life > 1) {
      p.life = 0;
      p.angle = Math.random() * Math.PI * 2;
    }

    const lifeRatio = p.life;
    const height = p.baseY + lifeRatio * 0.9;
    const wobble = Math.sin(t * p.speed * 5 + p.angle) * p.radius * (1 - lifeRatio * 0.5);

    p.mesh.position.set(
      wobble * Math.cos(p.angle),
      height,
      wobble * Math.sin(p.angle)
    );

    const scale = (1 - lifeRatio * lifeRatio) * 1.2;
    p.mesh.scale.setScalar(scale);
    p.mesh.lookAt(camera.position);

    // Color: inner = white-yellow, outer = orange-red
    const hue = 0.08 - p.layer * 0.05;
    const sat = 0.8 + p.layer * 0.2;
    const light = 0.8 - lifeRatio * 0.4;
    const alpha = (1 - lifeRatio) * (1 - lifeRatio) * (0.6 + p.layer * 0.3);

    p.mesh.material.color.setHSL(hue, sat, light);
    p.mesh.material.opacity = alpha;
  }

  // Update embers
  emberTimer += dt;
  for (const e of embers) {
    if (!e.active) {
      e.delay -= dt;
      if (e.delay <= 0) {
        e.active = true;
        e.life = 0;
        e.mesh.visible = true;
        e.mesh.position.set(
          (Math.random() - 0.5) * 0.08,
          2.5 + Math.random() * 0.2,
          (Math.random() - 0.5) * 0.08
        );
        e.vx = (Math.random() - 0.5) * 0.8;
        e.vy = 1 + Math.random() * 2;
        e.vz = (Math.random() - 0.5) * 0.8;
      }
      continue;
    }

    e.life += dt;
    if (e.life > e.maxLife) {
      e.active = false;
      e.mesh.visible = false;
      e.delay = 0.5 + Math.random() * 2;
      continue;
    }

    e.mesh.position.x += e.vx * dt;
    e.mesh.position.y += e.vy * dt;
    e.mesh.position.z += e.vz * dt;
    e.vy *= 0.99;
    e.vx *= 0.98;
    e.vz *= 0.98;

    const lifeRatio = e.life / e.maxLife;
    e.mesh.material.opacity = 1 - lifeRatio;
    e.mesh.lookAt(camera.position);
    e.mesh.scale.setScalar(1 - lifeRatio * 0.5);
  }

  // Update smoke
  smokeTimer += dt;
  for (const s of smokes) {
    if (!s.active) {
      s.delay -= dt;
      if (s.delay <= 0) {
        s.active = true;
        s.life = 0;
        s.mesh.visible = true;
        s.mesh.position.set(
          (Math.random() - 0.5) * 0.1,
          3.2 + Math.random() * 0.2,
          (Math.random() - 0.5) * 0.1
        );
      }
      continue;
    }

    s.life += dt;
    if (s.life > s.maxLife) {
      s.active = false;
      s.mesh.visible = false;
      s.delay = 1 + Math.random() * 3;
      continue;
    }

    s.mesh.position.x += s.vx * dt + Math.sin(t * 0.5 + s.life) * 0.02;
    s.mesh.position.y += s.vy * dt;
    s.mesh.position.z += s.vz * dt;

    const lifeRatio = s.life / s.maxLife;
    const scale = 1 + lifeRatio * 2;
    s.mesh.scale.setScalar(scale);
    s.mesh.material.opacity = (1 - lifeRatio) * 0.12;
    s.mesh.lookAt(camera.position);
  }

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in this scene

| Component | Details |
|---|---|
| **Torch handle** | Cylinder with tapered charred tip, warm wood tones |
| **Flame** | 120 additive-blended particles with per-particle life, color (white→yellow→orange→red), and sinusoidal wobble |
| **Flickering light** | Two `PointLight`s with layered sine-wave flicker for natural-looking illumination |
| **Embers** | 40 small glowing particles that launch upward and fade out |
| **Smoke** | 20 semi-transparent particles rising above the flame, expanding over time |
| **Ambient sway** | The whole torch gently rocks using sine functions |
| **Camera** | `OrbitControls` so you can rotate around the torch |

