<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';

    // Scene & Camera
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, innerWidth / innerHeight, 0.1, 100);
    camera.position.z = 4;

    // Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    document.body.appendChild(renderer.domElement);

    // Triangle geometry (3 vertices in XY plane)
    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute('position', new THREE.Float32BufferAttribute([
      0,  1.5, 0,   // top
     -1.2, -1, 0,   // bottom-left
      1.2, -1, 0    // bottom-right
    ], 3));

    // Material with vertex colors
    const colors = new Float32Array([
      1, 0.2, 0.3,   // top – coral red
      0.2, 0.6, 1,   // bottom-left – blue
      0.3, 1, 0.4    // bottom-right – green
    ]);
    geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));

    const material = new THREE.MeshBasicMaterial({
      vertexColors: true,
      side: THREE.DoubleSide
    });

    const triangle = new THREE.Mesh(geometry, material);
    scene.add(triangle);

    // Animate
    function animate(time) {
      requestAnimationFrame(animate);
      triangle.rotation.z = time * 0.001;
      renderer.render(scene, camera);
    }
    animate(0);

    // Handle resize
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

**What this does:**

- **Scene setup** — creates a Three.js scene, perspective camera, and WebGL renderer.
- **Triangle geometry** — defines 3 vertices using `BufferGeometry` forming an upright triangle.
- **Vertex colors** — each corner gets a distinct color (coral, blue, green) that interpolates across the face.
- **Animation** — the triangle slowly rotates on the Z-axis so you can see the gradient shading shift.
- **Responsive** — handles window resizing automatically.

