<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ──────────────── SCENE SETUP ──────────────── */
const scene    = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.012);

const camera   = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 200);
camera.position.set(6, 5, 10);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 4.5, 0);
controls.update();

/* ──────────────── LIGHTING ──────────────── */
const ambient = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.8);
dirLight.position.set(8, 15, 10);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 40;
dirLight.shadow.camera.left = -10;
dirLight.shadow.camera.right = 10;
dirLight.shadow.camera.top = 15;
dirLight.shadow.camera.bottom = -2;
scene.add(dirLight);

/* ──────────────── MATERIALS ──────────────── */
const poleMat   = new THREE.MeshStandardMaterial({ color: 0x555555, metalness: 0.8, roughness: 0.3 });
const bodyMat   = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, metalness: 0.4, roughness: 0.6 });
const hoodMat   = new THREE.MeshStandardMaterial({ color: 0x111111, metalness: 0.5, roughness: 0.5 });

function makeLightMat(color) {
  return new THREE.MeshStandardMaterial({
    color,
    emissive: color,
    emissiveIntensity: 0,
    metalness: 0.1,
    roughness: 0.2,
    transparent: true,
    opacity: 0.85,
  });
}

const redMat    = makeLightMat(0xff0000);
const yellowMat = makeLightMat(0xffdd00);
const greenMat  = makeLightMat(0x00cc44);

/* ──────────────── BUILD TRAFFIC LIGHT ──────────────── */
const trafficLight = new THREE.Group();

// Pole
const pole = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.14, 9, 16), poleMat);
pole.position.y = 4.5;
pole.castShadow = true;
trafficLight.add(pole);

// Base plate
const base = new THREE.Mesh(new THREE.CylinderGeometry(0.5, 0.55, 0.15, 24), poleMat);
base.position.y = 0.075;
base.castShadow = true;
trafficLight.add(base);

// Main housing body
const housingGeo = new THREE.BoxGeometry(1.4, 4.2, 1.2);
const housing    = new THREE.Mesh(housingGeo, bodyMat);
housing.position.y = 7.8;
housing.castShadow = true;
housing.receiveShadow = true;
trafficLight.add(housing);

// Housing bevel edges (thin strips)
const edgeMat = new THREE.MeshStandardMaterial({ color: 0x333333, metalness: 0.7, roughness: 0.3 });
for (const x of [-0.7, 0.7]) {
  const edge = new THREE.Mesh(new THREE.BoxGeometry(0.04, 4.25, 1.25), edgeMat);
  edge.position.set(x, 7.8, 0);
  trafficLight.add(edge);
}

/* ── Helper: build one signal lens ── */
function makeSignal(y, mat) {
  const group = new THREE.Group();
  group.position.y = y;

  // Dark recess ring
  const ring = new THREE.Mesh(
    new THREE.TorusGeometry(0.42, 0.06, 12, 32),
    new THREE.MeshStandardMaterial({ color: 0x111111, metalness: 0.6, roughness: 0.4 })
  );
  ring.position.z = 0.02;
  group.add(ring);

  // Lens (circle)
  const lens = new THREE.Mesh(new THREE.CircleGeometry(0.38, 32), mat);
  lens.position.z = 0.61;
  group.add(lens);

  // Glass dome (hemisphere)
  const dome = new THREE.Mesh(
    new THREE.SphereGeometry(0.39, 32, 16, 0, Math.PI * 2, 0, Math.PI / 2),
    new THREE.MeshStandardMaterial({
      color: 0xffffff,
      transparent: true,
      opacity: 0.15,
      roughness: 0.05,
      metalness: 0.0,
    })
  );
  dome.position.z = 0.61;
  group.add(dome);

  // Hood / visor
  const hood = new THREE.Mesh(
    new THREE.BoxGeometry(1.1, 0.06, 0.55),
    hoodMat
  );
  hood.position.set(0, 0.45, 0.35);
  hood.rotation.x = -0.35;
  hood.castShadow = true;
  group.add(hood);

  return group;
}

// Three signals
const redSignal    = makeSignal(9.2, redMat);
const yellowSignal = makeSignal(7.8, yellowMat);
const greenSignal  = makeSignal(6.4, greenMat);

trafficLight.add(redSignal, yellowSignal, greenSignal);

// Top cap
const cap = new THREE.Mesh(
  new THREE.ConeGeometry(0.75, 0.5, 4),
  bodyMat
);
cap.position.y = 10.15;
cap.rotation.y = Math.PI / 4;
cap.castShadow = true;
trafficLight.add(cap);

scene.add(trafficLight);

/* ──────────────── GROUND ──────────────── */
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(60, 60),
  new THREE.MeshStandardMaterial({ color: 0x222233, roughness: 0.9, metalness: 0.1 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Road marking lines
const lineMat = new THREE.MeshStandardMaterial({ color: 0x666666, roughness: 0.8 });
for (let i = -2; i <= 2; i++) {
  const line = new THREE.Mesh(new THREE.BoxGeometry(0.08, 0.01, 12), lineMat);
  line.position.set(i * 2.5, 0.005, 0);
  scene.add(line);
}

/* ──────────────── POINT LIGHTS (glow) ──────────────── */
function makePointLight(color, y) {
  const pl = new THREE.PointLight(color, 0, 8, 2);
  pl.position.set(0, y, 1.2);
  return pl;
}

const redPL    = makePointLight(0xff2200, 9.2);
const yellowPL = makePointLight(0xffdd00, 7.8);
const greenPL  = makePointLight(0x00ff44, 6.4);
scene.add(redPL, yellowPL, greenPL);

/* ──────────────── ANIMATION STATE MACHINE ──────────────── */
const PHASES = [
  { red: 1, yellow: 0, green: 0, duration: 3000 },
  { red: 0, yellow: 1, green: 0, duration: 1000 },
  { red: 0, yellow: 0, green: 1, duration: 3000 },
  { red: 0, yellow: 0, green: 0, duration: 800  },
];

let phaseIndex = 0;
let phaseTime  = 0;
const clock    = new THREE.Clock();

function lerpLights(phase, t) {
  const ease = t < 0.15 ? t / 0.15 : 1; // quick fade-in
  redMat.emissiveIntensity    = phase.red    * ease;
  yellowMat.emissiveIntensity = phase.yellow * ease;
  greenMat.emissiveIntensity  = phase.green  * ease;

  redPL.intensity    = phase.red    * ease * 12;
  yellowPL.intensity = phase.yellow * ease * 10;
  greenPL.intensity  = phase.green  * ease * 12;
}

/* ──────────────── RENDER LOOP ──────────────── */
function animate() {
  requestAnimationFrame(animate);

  const delta = clock.getDelta() * 1000; // ms
  phaseTime += delta;

  const phase = PHASES[phaseIndex];
  const t = Math.min(phaseTime / phase.duration, 1);

  lerpLights(phase, t);

  if (phaseTime >= phase.duration) {
    phaseTime = 0;
    phaseIndex = (phaseIndex + 1) % PHASES.length;
  }

  // Gentle pole sway
  trafficLight.rotation.z = Math.sin(Date.now() * 0.001) * 0.003;

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ──────────────── RESIZE ──────────────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the scene

| Part | Detail |
|---|---|
| **Pole & base** | Tapered cylinder with a wider circular foot plate |
| **Housing** | Black box with metallic edge strips and a pyramid top cap |
| **Three lenses** | Red / Yellow / Green circles with translucent glass domes, recessed rings, and angled hoods |
| **Point lights** | One colored `PointLight` per lamp that casts real glow into the scene |
| **State machine** | Cycles **Red → Yellow → Green → Off** with timed phases (3 s / 1 s / 3 s / 0.8 s) |
| **Ground** | Dark plane with subtle road-marking lines |
| **Controls** | `OrbitControls` — drag to rotate, scroll to zoom |
| **Extras** | ACES filmic tone mapping, soft shadow maps, fog, gentle pole sway |

