headGroup.add(head);

/* Snout */
const snoutGeo = new THREE.SphereGeometry(0.35, 24, 16);
const snout = new THREE.Mesh(snoutGeo, skinMat);
snout.scale.set(0.8, 0.65, 1.1);
snout.position.set(0, -0.1, 0.5);
headGroup.add(snout);

/* Eyes */
function makeEye(side) {
  const eyeGroup = new THREE.Group();
  eyeGroup.position.set(side * 0.42, 0.15, 0.15);

  const whiteGeo = new THREE.SphereGeometry(0.14, 16, 16);
  const white = new THREE.Mesh(whiteGeo, eyeWhite);
  eyeGroup.add(white);

  const pupilGeo = new THREE.SphereGeometry(0.085, 16, 16);
  const pupil = new THREE.Mesh(pupilGeo, eyePupil);
  pupil.position.z = 0.09;
  eyeGroup.add(pupil);

  const shineGeo = new THREE.SphereGeometry(0.03, 8, 8);
  const shine = new THREE.Mesh(shineGeo, eyeShine);
  shine.position.set(0.03, 0.03, 0.14);
  eyeGroup.add(shine);

  headGroup.add(eyeGroup);
}
makeEye(1);
makeEye(-1);

turtle.add(headGroup);

/* ── Legs ──────────────────────────────────────── */
const legData = [
  { x: -1.3, z:  1.3, ry:  0.4 },   // front-left
  { x:  1.3, z:  1.3, ry: -0.4 },   // front-right
  { x: -1.3, z: -1.3, ry:  0.6 },   // back-left
  { x:  1.3, z: -1.3, ry: -0.6 },   // back-right
];

const legMeshes = [];

legData.forEach((d, i) => {
  const legGroup = new THREE.Group();
  legGroup.position.set(d.x, 0.55, d.z);
  legGroup.rotation.y = d.ry;

  /* Upper leg */
  const upperGeo = new THREE.SphereGeometry(0.32, 16, 16);
  const upper = new THREE.Mesh(upperGeo, skinMat);
  upper.scale.set(1, 1, 1.3);
  upper.position.z = 0.15;
  upper.castShadow = true;
  legGroup.add(upper);

  /* Lower leg / foot */
  const footGeo = new THREE.SphereGeometry(0.35, 16, 16);
  const foot = new THREE.Mesh(footGeo, skinDark);
  foot.scale.set(1.1, 0.6, 1.4);
  foot.position.set(0, -0.25, 0.5);
  foot.castShadow = true;
  legGroup.add(foot);

  /* Claws */
  for (let c = -1; c <= 1; c += 2) {
    const clawGeo = new THREE.ConeGeometry(0.05, 0.2, 8);
    const claw = new THREE.Mesh(clawGeo, shellRim);
    claw.position.set(c * 0.15, -0.35, 0.85);
    claw.rotation.x = -0.5;
    legGroup.add(claw);
  }

  turtle.add(legGroup);
  legMeshes.push(legGroup);
});

/* ── Tail ──────────────────────────────────────── */
const tailGeo = new THREE.ConeGeometry(0.15, 0.6, 12);
const tail = new THREE.Mesh(tailGeo, skinDark);
tail.position.set(0, 0.55, -2.2);
tail.rotation.x = Math.PI / 2 - 0.3;
tail.castShadow = true;
turtle.add(tail);

scene.add(turtle);

/* ── Ground ────────────────────────────────────── */
const groundGeo = new THREE.CircleGeometry(30, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* Water pond */
const pondGeo = new THREE.CircleGeometry(4, 48);
const pondMat = new THREE.MeshStandardMaterial({
  color: 0x3388aa, roughness: 0.1, metalness: 0.3,
  transparent: true, opacity: 0.7
});
const pond = new THREE.Mesh(pondGeo, pondMat);
pond.rotation.x = -Math.PI / 2;
pond.position.set(5, 0.01, 3);
scene.add(pond);

/* Rocks */
function makeRock(x, z, s) {
  const geo = new THREE.DodecahedronGeometry(s, 1);
  const mat = new THREE.MeshStandardMaterial({ color: 0x888877, roughness: 0.9 });
  const rock = new THREE.Mesh(geo, mat);
  rock.position.set(x, s * 0.4, z);
  rock.rotation.set(Math.random(), Math.random(), Math.random());
  rock.scale.y = 0.5 + Math.random() * 0.3;
  rock.castShadow = true;
  rock.receiveShadow = true;
  scene.add(rock);
}
makeRock(-4, 3, 0.6);
makeRock(-3.2, 4, 0.4);
makeRock(6, 1, 0.5);
makeRock(7, 2.5, 0.35);

/* Simple grass tufts */
function makeGrass(x, z) {
  const group = new THREE.Group();
  for (let i = 0; i < 5; i++) {
    const bladeGeo = new THREE.ConeGeometry(0.04, 0.3 + Math.random() * 0.2, 4);
    const blade = new THREE.Mesh(bladeGeo, new THREE.MeshStandardMaterial({ color: 0x3a7a2c }));
    blade.position.set((Math.random() - 0.5) * 0.3, 0.15, (Math.random() - 0.5) * 0.3);
    blade.rotation.z = (Math.random() - 0.5) * 0.3;
    group.add(blade);
  }
  group.position.set(x, 0, z);
  scene.add(group);
}
for (let i = 0; i < 40; i++) {
  const angle = Math.random() * Math.PI * 2;
  const dist = 3 + Math.random() * 20;
  makeGrass(Math.cos(angle) * dist, Math.sin(angle) * dist);
}

/* ── Animation ─────────────────────────────────── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  /* Gentle leg walk cycle */
  legMeshes.forEach((leg, i) => {
    const phase = i < 2 ? 0 : Math.PI;
    const sideOffset = i % 2 === 0 ? 0 : Math.PI;
    const walk = Math.sin(t * 1.5 + phase + sideOffset) * 0.12;
    leg.rotation.x = walk;
    leg.position.y = 0.55 + Math.abs(Math.sin(t * 1.5 + phase + sideOffset)) * 0.08;
  });

  /* Head bob */
  headGroup.position.y = 0.65 + Math.sin(t * 2) * 0.05;
  headGroup.rotation.x = Math.sin(t * 0.8) * 0.08;
  headGroup.rotation.y = Math.sin(t * 0.5) * 0.15;

  /* Tail wag */
  tail.rotation.z = Math.sin(t * 1.2) * 0.15;

  /* Subtle body sway */
  turtle.rotation.y = Math.sin(t * 0.3) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ────────────────────────────────────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
