// ── Canopy (8 alternating panels) ────────────────────────
const NUM_PANELS = 8;
const RADIUS = 3.5;
const HEIGHT = 1.8;
const colors = [0xe63946, 0xf4a261];

for (let i = 0; i < NUM_PANELS; i++) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.3, HEIGHT * 0.6, RADIUS * 0.05, HEIGHT * 0.95);
  shape.lineTo(RADIUS, 0);
  shape.lineTo(0, 0);

  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: (Math.PI * 2) / NUM_PANELS * RADIUS * 0.48,
    bevelEnabled: false,
