```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Vacuum</title>
<style>
* { margin: 0; padding: 0; }
body { background: #000; overflow: hidden; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

// ── Scene ──
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x000000, 0.012);

const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 12, 30);
camera.lookAt(0, 0, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

// ── The Void (central black sphere with rim glow) ──
const voidGeo = new THREE.SphereGeometry(1.5, 32, 32);
const voidMat = new THREE.ShaderMaterial({
  transparent: true,
  side: THREE.FrontSide,
  uniforms: { time: { value: 0 } },
  vertexShader: `
    varying vec3 vNormal;
    varying vec3 vViewPos;
    void main() {
      vNormal = normalize(normalMatrix * normal);
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      vViewPos = mv.xyz;
      gl_Position = projectionMatrix * mv;
    }
  `,
  fragmentShader: `
    varying vec3 vNormal;
    varying vec3 vViewPos;
    uniform float time;
    void main() {
      float fresnel = pow(1.0 - abs(dot(normalize(-vViewPos), vNormal)), 3.0);
      vec3 rim = mix(vec3(0.05, 0.0, 0.2), vec3(0.1, 0.0, 0.5), sin(time * 0.5) * 0.5 + 0.5);
      gl_FragColor = vec4(rim, fresnel * 0.8);
    }
  `
});
const voidMesh = new THREE.Mesh(voidGeo, voidMat);
scene.add(voidMesh);

// ── Particles ──
const COUNT = 12000;
const MAX_R = 50;

const positions = new Float32Array(COUNT * 3);
const colors    = new Float32Array(COUNT * 3);
const sizes     = new Float32Array(COUNT);
const life      = new Float32Array(COUNT);

function reset(i) {
  const r = 15 + Math.random() * MAX_R;
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.acos(2 * Math.random() - 1);
  positions[i*3]   = r * Math.sin(phi) * Math.cos(theta);
  positions[i*3+1] = r * Math.sin(phi) * Math.sin(theta);
  positions[i*3+2] = r * Math.cos(phi);
  const hue = 0.6 + Math.random() * 0.15; // blue-violet range
  const c = new THREE.Color().setHSL(hue, 0.8, 0.5 + Math.random() * 0.3);
  colors[i*3] = c.r; colors[i*3+1] = c.g; colors[i*3+2] = c.b;
  sizes[i] = 0.5 + Math.random() * 2.0;
  life[i] = Math.random();
}
for (let i = 0; i < COUNT; i++) reset(i);

const particleGeo = new THREE.BufferGeometry();
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('color',    new THREE.BufferAttribute(colors, 3));
particleGeo.setAttribute('size',     new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.ShaderMaterial({
  transparent: true,
  depthWrite: false,
  blending: THREE.AdditiveBlending,
  vertexColors: true,
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    attribute float size;
    varying vec3 vColor;
    void main() {
      vColor = color;
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      gl_PointSize = size * (200.0 / -mv.z);
      gl_Position = projectionMatrix * mv;
    }
  `,
  fragmentShader: `
    varying vec3 vColor;
    void main() {
      float d = length(gl_PointCoord - 0.5);
      if (d > 0.5) discard;
      float alpha = smoothstep(0.5, 0.0, d);
      gl_FragColor = vec4(vColor, alpha * 0.7);
    }
  `
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const dt = Math.min(clock.getDelta(), 0.05);
  const t = clock.elapsedTime;

  voidMat.uniforms.time.value = t;
  particleMat.uniforms.uTime.value = t;

  // Gentle camera orbit
  camera.position.x = Math.sin(t * 0.1) * 30;
  camera.position.z = Math.cos(t * 0.1) * 30;
  camera.position.y = 8 + Math.sin(t * 0.15) * 5;
  camera.lookAt(0, 0, 0);

  // Pull particles toward the void
  for (let i = 0; i < COUNT; i++) {
    const ix = i * 3, iy = i * 3 + 1, iz = i * 3 + 2;
    let px = positions[ix], py = positions[iy], pz = positions[iz];

    const dist = Math.sqrt(px*px + py*py + pz*pz);
    if (dist < 0.01) { reset(i); continue; }

    // Radial pull (inverse-square-ish, softened)
    const pull = 8.0 / (dist * dist + 1.0);

    // Tangential (vortex) force
    const tx = -pz / dist;
    const tz =  px / dist;
    const vortexStrength = 4.0 / (dist + 2.0);

    positions[ix]   += (-px/dist * pull + tx * vortexStrength) * dt;
    positions[iy]   += (-py/dist * pull * 0.5) * dt;           // slight vertical damping
    positions[iz]   += (-pz/dist * pull + tz * vortexStrength) * dt;

    life[i] -= dt * 0.3;
    if (life[i] <= 0) reset(i);
  }

  particleGeo.attributes.position.needsUpdate = true;
  particleGeo.attributes.size.needsUpdate = true;
  particleGeo.attributes.color.needsUpdate = true;

  // Pulse the void
  const s = 1.0 + Math.sin(t * 2) * 0.05;
  voidMesh.scale.set(s, s, s);

  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
