dirLight.shadow.camera.bottom = -4;
dirLight.shadow.bias = -0.002;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x8888ff, 0.6);
rimLight.position.set(-3, 2, -3);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffaa44, 1.5, 10);
pointLight.position.set(-1, 3, 2);
scene.add(pointLight);

// Ground
const groundGeo = new THREE.CircleGeometry(6, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e,
  roughness: 0.85,
  metalness: 0.1
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Carrot group
const carrot = new THREE.Group();

// Carrot body using LatheGeometry for organic shape
const bodyPoints = [];
const segments = 20;
for (let i = 0; i <= segments; i++) {
  const t = i / segments;
  const y = t * 2.4;
  // Organic carrot profile: wider in the middle, tapered at both ends
  let r;
  if (t < 0.05) {
    r = t / 0.05 * 0.12;
  } else if (t < 0.5) {
    const st = (t - 0.05) / 0.45;
    r = 0.12 + st * 0.42 + Math.sin(st * Math.PI) * 0.12;
  } else {
    const st = (t - 0.5) / 0.5;
    r = 0.66 * (1 - st) * (1 - st * 0.5);
  }
  bodyPoints.push(new THREE.Vector2(Math.max(r, 0.001), y));
}

const bodyGeo = new THREE.LatheGeometry(bodyPoints, 24);
bodyGeo.computeVertexNormals();

const bodyMat = new THREE.MeshStandardMaterial({
  color: 0xe8651a,
  roughness: 0.55,
  metalness: 0.02,
  flatShading: false
});

const bodyMesh = new THREE.Mesh(bodyGeo, bodyMat);
bodyMesh.castShadow = true;
bodyMesh.receiveShadow = true;
carrot.add(bodyMesh);

// Add subtle horizontal rings (carrot texture)
for (let i = 0; i < 8; i++) {
  const t = 0.1 + i * 0.1;
  const y = t * 2.4;
  const ringR = bodyPoints[Math.floor(t * segments)].x;
  const ringGeo = new THREE.TorusGeometry(ringR + 0.002, 0.008, 6, 24);
  const ringMat = new THREE.MeshStandardMaterial({
    color: 0xc45515,
    roughness: 0.7,
    metalness: 0.0
  });
  const ring = new THREE.Mesh(ringGeo, ringMat);
  ring.position.y = y;
  ring.rotation.x = Math.PI / 2;
  carrot.add(ring);
}

// Carrot top (green leaves)
const leafGroup = new THREE.Group();
leafGroup.position.y = 2.4;

function createLeaf(angle, tilt, length, scale) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.06, length * 0.4, 0.02, length * 0.8);
  shape.quadraticCurveTo(0, length, -0.02, length * 0.8);
  shape.quadraticCurveTo(-0.06, length * 0.4, 0, 0);

  const leafGeo = new THREE.ShapeGeometry(shape, 8);
  const leafMat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28 + Math.random() * 0.06, 0.7, 0.32),
    roughness: 0.7,
    metalness: 0.0,
    side: THREE.DoubleSide
  });

  const leaf = new THREE.Mesh(leafGeo, leafMat);
  leaf.castShadow = true;

  const pivot = new THREE.Group();
  pivot.rotation.y = angle;
  pivot.rotation.z = tilt;
  pivot.add(leaf);
  leaf.position.y = 0.05;

  const pivot2 = new THREE.Group();
  pivot2.rotation.x = tilt * 0.5;
  pivot2.add(pivot);

  return pivot2;
}

const leafAngles = [
  { a: 0, tilt: -0.4, l: 1.2, s: 1.0 },
  { a: Math.PI * 0.4, tilt: -0.5, l: 1.0, s: 0.9 },
  { a: Math.PI * 0.8, tilt: -0.3, l: 1.1, s: 0.95 },
  { a: Math.PI * 1.2, tilt: -0.6, l: 0.9, s: 0.85 },
  { a: Math.PI * 1.6, tilt: -0.35, l: 1.05, s: 0.9 },
  { a: Math.PI * 0.2, tilt: -0.45, l: 0.8, s: 0.8 },
  { a: Math.PI * 1.0, tilt: -0.55, l: 0.85, s: 0.82 },
  { a: Math.PI * 1.4, tilt: -0.38, l: 0.95, s: 0.88 },
];

leafAngles.forEach(({ a, tilt, l, s }) => {
  const leaf = createLeaf(a, tilt, l, s);
  leaf.scale.setScalar(s);
  leafGroup.add(leaf);
});

carrot.add(leafGroup);

// Small root tip
