carrot.rotation.z = 0.1;
carrot.position.y = 0.05;
scene.add(carrot);

// Subtle floating particles
const particleCount = 30;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3] = (Math.random() - 0.5) * 8;
  particlePositions[i * 3 + 1] = Math.random() * 6;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 8;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xffcc88,
  size: 0.03,
  transparent: true,
  opacity: 0.4
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle bobbing
  carrot.position.y = 0.05 + Math.sin(elapsed * 0.8) * 0.08;
  carrot.rotation.y = Math.sin(elapsed * 0.3) * 0.15;

  // Leaf sway
  leafGroup.children.forEach((leaf, i) => {
    leaf.rotation.x = Math.sin(elapsed * 1.2 + i * 0.7) * 0.08;
    leaf.rotation.z = Math.cos(elapsed * 0.9 + i * 1.1) * 0.05;
  });

  // Particle drift
  const positions = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    positions[i * 3 + 1] += 0.003;
    if (positions[i * 3 + 1] > 6) positions[i * 3 + 1] = 0;
    positions[i * 3] += Math.sin(elapsed + i) * 0.001;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
