    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 4, 3);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;

// --- Waffle Geometry ---
const SIZE = 2.2;
const SEGMENTS = 120;
const GRID = 6;          // 6×6 waffle cells
const geo = new THREE.PlaneGeometry(SIZE, SIZE, SEGMENTS, SEGMENTS);
geo.rotateX(-Math.PI / 2);

const pos = geo.attributes.position;
const cellW = SIZE / GRID;
const ridge = 0.06;      // ridge width factor
const depth = 0.18;      // pocket depth
const baseH = 0.08;      // overall thickness

for (let i = 0; i < pos.count; i++) {
  const x = pos.getX(i);
  const z = pos.getZ(i);

  // Distance to nearest grid line (normalized 0..1 within cell)
  const nx = ((x % cellW) + cellW) % cellW;
  const nz = ((z % cellW) + cellW) % cellW;
  const dx = Math.min(nx, cellW - nx) / (cellW * 0.5);
  const dz = Math.min(nz, cellW - nz) / (cellW * 0.5);
  const d = Math.max(dx, dz);                       // ∞-norm → square pockets

  // Smooth ridge shape
  const ridgeFactor = Math.pow(Math.max(0, 1 - d / ridge), 2);
  const pocketFactor = d < ridge ? 0 : Math.pow((d - ridge) / (1 - ridge), 1.5);

  let y = baseH + ridgeFactor * 0.12 - pocketFactor * depth;

  // Rounded edges
  const hx = SIZE * 0.5, hz = SIZE * 0.5, bend = 0.4;
  const ex = Math.max(0, (Math.abs(x) - (hx - bend)) / bend);
  const ez = Math.max(0, (Math.abs(z) - (hz - bend)) / bend);
  const edge = Math.min(1, Math.max(ex, ez));
  y += Math.sin(edge * Math.PI * 0.5) * 0.06;

  // Subtle warp
  y += Math.sin(x * 3.7 + z * 2.3) * 0.008;

  pos.setY(i, y);
}

geo.computeVertexNormals();

// --- Waffle Material ---
const waffleMat = new THREE.MeshStandardMaterial({
  color: 0xc4883a,
  roughness: 0.75,
  metalness: 0.05,
  side: THREE.DoubleSide,
});

const waffle = new THREE.Mesh(geo, waffleMat);
waffle.castShadow = true;
waffle.receiveShadow = true;
scene.add(waffle);

// --- Syrup pool ---
const syrupGeo = new THREE.CircleGeometry(0.5, 32);
syrupGeo.rotateX(-Math.PI / 2);
const syrupMat = new THREE.MeshStandardMaterial({
  color: 0x5c2a00,
  roughness: 0.15,
  metalness: 0.1,
  transparent: true,
  opacity: 0.85,
});
const syrup = new THREE.Mesh(syrupGeo, syrupMat);
syrup.position.set(0.3, 0.18, 0.2);
scene.add(syrup);

// --- Lighting ---
scene.add(new THREE.AmbientLight(0xffeedd, 0.6));

const dir = new THREE.DirectionalLight(0xfff4e0, 2.5);
dir.position.set(3, 6, 4);
dir.castShadow = true;
dir.shadow.mapSize.set(1024, 1024);
dir.shadow.camera.near = 1;
dir.shadow.camera.far = 15;
dir.shadow.camera.left = dir.shadow.camera.bottom = -3;
dir.shadow.camera.right = dir.shadow.camera.top = 3;
scene.add(dir);

const rim = new THREE.DirectionalLight(0xff9944, 0.8);
rim.position.set(-4, 2, -3);
scene.add(rim);

// --- Plate ---
const plateGeo = new THREE.CylinderGeometry(2.0, 1.8, 0.08, 64);
const plateMat = new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.3 });
const plate = new THREE.Mesh(plateGeo, plateMat);
plate.position.y = -0.08;
plate.receiveShadow = true;
scene.add(plate);

// --- Animation ---
function animate() {
  requestAnimationFrame(animate);
  waffle.rotation.y += 0.003;
  syrup.position.y = 0.18 + Math.sin(Date.now() * 0.002) * 0.005;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
