  rail.castShadow = true;
  bodyGroup.add(rail);
});

// ── Canvas Cover (top) ──
const canvasCover = new THREE.Mesh(new THREE.BoxGeometry(3.4, 0.06, 1.9), canvasMat);
canvasCover.position.set(-0.2, 1.65, 0);
canvasCover.castShadow = true;
bodyGroup.add(canvasCover);

// Canvas bows (curved supports)
const curveMat = darkWoodMat;
for (let x = -1.2; x <= 1.2; x += 0.8) {
  const bowGeo = new THREE.TorusGeometry(0.5, 0.03, 8, 16, Math.PI);
  const bow = new THREE.Mesh(bowGeo, curveMat);
  bow.position.set(x, 1.65, 0);
  bow.rotation.y = Math.PI / 2;
  bow.castShadow = true;
  bodyGroup.add(bow);
}

// ── Tongue (front pole) ──
const tongue = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.06, 3.0, 12), darkWoodMat);
tongue.rotation.z = Math.PI / 2;
tongue.position.set(-3.7, 1.8, 0);
tongue.castShadow = true;
wagon.add(tongue);

// Tongue support (triangle brace)
const braceGeo = new THREE.BoxGeometry(0.06, 0.06, 0.06);
for (let i = 0; i < 3; i++) {
  const brace = new THREE.Mesh(braceGeo, darkWoodMat);
  const t = i / 2;
  brace.position.set(-2.4 - t * 0.8, 1.0 + t * 0.8, 0);
  brace.rotation.z = Math.PI / 4;
  brace.scale.set(1, 1, 1 + t * 2);
  wagon.add(brace);
}

// Hitch ring
const hitchRing = new THREE.Mesh(
  new THREE.TorusGeometry(0.15, 0.03, 8, 16),
  metalMat
);
hitchRing.position.set(-5.2, 1.8, 0);
hitchRing.rotation.y = Math.PI / 2;
wagon.add(hitchRing);

// ── Wheels ──
function createWheel() {
  const group = new THREE.Group();

  // Tire (outer ring)
  const tire = new THREE.Mesh(
    new THREE.TorusGeometry(0.75, 0.08, 8, 24),
    tireMat
  );
  tire.castShadow = true;
  group.add(tire);

  // Rim
  const rim = new THREE.Mesh(
    new THREE.TorusGeometry(0.65, 0.04, 6, 20),
    darkWoodMat
  );
  rim.castShadow = true;
  group.add(rim);

  // Hub
  const hub = new THREE.Mesh(
    new THREE.CylinderGeometry(0.12, 0.12, 0.2, 12),
    metalMat
  );
  hub.rotation.x = Math.PI / 2;
  hub.castShadow = true;
  group.add(hub);

  // Spokes
  const spokeGeo = new THREE.BoxGeometry(1.2, 0.04, 0.04);
  for (let i = 0; i < 8; i++) {
    const spoke = new THREE.Mesh(spokeGeo, darkWoodMat);
    spoke.rotation.z = (i / 8) * Math.PI;
    spoke.castShadow = true;
    group.add(spoke);
  }

  return group;
}

const wheelPositions = [
  { x: -1.0, z: -1.1 },
  { x: -1.0, z: 1.1 },
  { x: 1.0, z: -1.1 },
  { x: 1.0, z: 1.1 },
];

const wheels = [];
wheelPositions.forEach(({ x, z }) => {
  const wheel = createWheel();
  wheel.position.set(x, 0.75, z);
  wheel.castShadow = true;
  wagon.add(wheel);
  wheels.push(wheel);
});

// ── Axles ──
[-1.1, 1.1].forEach(z => {
  const axle = new THREE.Mesh(
    new THREE.CylinderGeometry(0.05, 0.05, 2.2, 8),
    metalMat
  );
  axle.rotation.z = Math.PI / 2;
  axle.position.set(0, 0.75, z);
  axle.castShadow = true;
  wagon.add(axle);
});

// ── Ground ──
const groundGeo = new THREE.PlaneGeometry(100, 100);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x4a7c3f, roughness: 1.0 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt path
const pathGeo = new THREE.PlaneGeometry(4, 60);
const pathMat = new THREE.MeshStandardMaterial({ color: 0x8B7355, roughness: 1.0 });
const path = new THREE.Mesh(pathGeo, pathMat);
path.rotation.x = -Math.PI / 2;
path.position.y = 0.005;
path.receiveShadow = true;
scene.add(path);

// ── Simple trees for atmosphere ──
function createTree(x, z) {
  const tree = new THREE.Group();
  const trunk = new THREE.Mesh(
    new THREE.CylinderGeometry(0.15, 0.25, 2.5, 8),
    new THREE.MeshStandardMaterial({ color: 0x5C4033, roughness: 0.9 })
  );
  trunk.position.y = 1.25;
  trunk.castShadow = true;
  tree.add(trunk);

  const leaves = new THREE.Mesh(
    new THREE.SphereGeometry(1.2, 8, 6),
    new THREE.MeshStandardMaterial({ color: 0x2d6b1e, roughness: 0.9 })
  );
  leaves.position.y = 3.2;
  leaves.castShadow = true;
  tree.add(leaves);

  tree.position.set(x, 0, z);
  return tree;
}

const treePositions = [
  [-6, -4], [-8, 2], [-5, 7], [7, -3], [9, 5],
  [-7, -8], [6, 8], [-9, 4], [8, -6], [-4, -10],
  [10, 0], [-10, -2], [5, -9], [-6, 10], [7, -10],
];
treePositions.forEach(([x, z]) => scene.add(createTree(x, z)));

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const elapsed = clock.getElapsedTime();

  // Gentle wheel wobble / wagon settle
  wagon.position.y = Math.sin(elapsed * 1.5) * 0.02;
  wagon.rotation.z = Math.sin(elapsed * 1.2) * 0.003;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
