// Pith ring (thin torus-like band at the cut edge)
const pithGeo = new THREE.TorusGeometry(1.58, 0.08, 16, 64);
const pith = new THREE.Mesh(pithGeo, pithMat);
pith.scale.set(1, 0.75, 1);
pith.rotation.x = Math.PI / 2;
pith.position.y = 0;
