dirLight.position.set(5, 10, 7);
scene.add(dirLight);
const pointLight = new THREE.PointLight(0x0088ff, 1.5, 40);
pointLight.position.set(0, 5, 0);
scene.add(pointLight);

// Wave mesh
const size = 20, segments = 120;
const geometry = new THREE.PlaneGeometry(size, size, segments, segments);
geometry.rotateX(-Math.PI / 2);

const material = new THREE.MeshPhongMaterial({
  color: 0x0066cc,
  emissive: 0x001133,
  specular: 0x44aaff,
  shininess: 80,
  wireframe: false,
  side: THREE.DoubleSide,
});

const waveMesh = new THREE.Mesh(geometry, material);
scene.add(waveMesh);

// Wireframe overlay
const wireMat = new THREE.MeshBasicMaterial({ color: 0x00ccff, wireframe: true, transparent: true, opacity: 0.08 });
const wireMesh = new THREE.Mesh(geometry, wireMat);
scene.add(wireMesh);

// Animate
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  const pos = geometry.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const z = pos.getZ(i);
    const y =
      Math.sin(x * 0.5 + t * 1.2) * 0.8 +
      Math.sin(z * 0.4 + t * 0.9) * 0.6 +
      Math.sin((x + z) * 0.3 + t * 1.5) * 0.4 +
      Math.cos(x * 0.2 - t * 0.7) * 0.3;
    pos.setY(i, y);
  }
  pos.needsUpdate = true;
  geometry.computeVertexNormals();

  // Gentle camera orbit
  camera.position.x = Math.sin(t * 0.15) * 12;
  camera.position.z = Math.cos(t * 0.15) * 12;
  camera.lookAt(0, 0, 0);

  pointLight.position.y = 5 + Math.sin(t) * 2;

  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
