```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Whip</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);
scene.fog = new THREE.FogExp2(0x0a0a12, 0.035);

const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1, 0);
controls.enableDamping = true;

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x334466, 0.8);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
scene.add(keyLight);

const rimLight = new THREE.PointLight(0x4488ff, 3, 20);
rimLight.position.set(-4, 3, -3);
scene.add(rimLight);

const tipLight = new THREE.PointLight(0xff6633, 0, 6);
scene.add(tipLight);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(40, 40),
  new THREE.MeshStandardMaterial({ color: 0x111118, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.5;
ground.receiveShadow = true;
scene.add(ground);

// ── Whip Physics ──
const SEGMENTS = 60;
const SEGMENT_LENGTH = 0.12;
const GRAVITY = -9.8;
const DAMPING = 0.985;
const CONSTRAINT_ITERATIONS = 12;

class Point {
  constructor(x, y, z, pinned = false) {
    this.pos = new THREE.Vector3(x, y, z);
    this.oldPos = new THREE.Vector3(x, y, z);
    this.acc = new THREE.Vector3(0, 0, 0);
    this.pinned = pinned;
  }
}

const points = [];
for (let i = 0; i < SEGMENTS; i++) {
  points.push(new Point(0, 4 - i * SEGMENT_LENGTH, 0, i === 0));
}

const constraints = [];
for (let i = 0; i < SEGMENTS - 1; i++) {
  constraints.push({ a: i, b: i + 1, length: SEGMENT_LENGTH });
}

function simulate(dt) {
  dt = Math.min(dt, 0.02);

  // Verlet integration
  for (const p of points) {
    if (p.pinned) continue;
    p.acc.set(0, GRAVITY, 0);
    const velX = (p.pos.x - p.oldPos.x) * DAMPING;
    const velY = (p.pos.y - p.oldPos.y) * DAMPING;
    const velZ = (p.pos.z - p.oldPos.z) * DAMPING;
    p.oldPos.copy(p.pos);
    p.pos.x += velX + p.acc.x * dt * dt;
    p.pos.y += velY + p.acc.y * dt * dt;
    p.pos.z += velZ + p.acc.z * dt * dt;
  }

  // Pin the handle
  const t = performance.now() * 0.001;
  const radius = 2.5;
  const speed = 1.8;
  points[0].pos.set(
    Math.sin(t * speed) * radius,
    4 + Math.sin(t * speed * 0.5) * 0.5,
    Math.cos(t * speed) * radius
  );
  points[0].oldPos.copy(points[0].pos);

  // Constraint solving
  for (let iter = 0; iter < CONSTRAINT_ITERATIONS; iter++) {
    for (const c of constraints) {
      const a = points[c.a], b = points[c.b];
      const dx = b.pos.x - a.pos.x;
      const dy = b.pos.y - a.pos.y;
      const dz = b.pos.z - a.pos.z;
      const dist = Math.sqrt(dx * dx + dy * dy + dz * dz) || 0.0001;
      const diff = (c.length - dist) / dist * 0.5;
      const ox = dx * diff, oy = dy * diff, oz = dz * diff;
      if (!a.pinned) { a.pos.x -= ox; a.pos.y -= oy; a.pos.z -= oz; }
      if (!b.pinned) { b.pos.x += ox; b.pos.y += oy; b.pos.z += oz; }
    }
  }
}

// ── Whip Mesh (tapered chain) ──
const whipGroup = new THREE.Group();
scene.add(whipGroup);

const handleGeo = new THREE.CylinderGeometry(0.06, 0.05, 0.6, 12);
const handleMat = new THREE.MeshStandardMaterial({
  color: 0x3a2210, roughness: 0.4, metalness: 0.1
});
const handle = new THREE.Mesh(handleGeo, handleMat);
handle.castShadow = true;
whipGroup.add(handle);

const segMeshes = [];
for (let i = 0; i < SEGMENTS - 1; i++) {
  const t = i / (SEGMENTS - 1);
  // Taper: thick at base, very thin at tip
  const r = THREE.MathUtils.lerp(0.045, 0.003, Math.pow(t, 0.7));
  const geo = new THREE.CylinderGeometry(r * 0.85, r, SEGMENT_LENGTH * 1.05, 8);
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.07, 0.6 - t * 0.3, 0.15 + t * 0.1),
    roughness: 0.6,
    metalness: 0.05,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.castShadow = true;
  whipGroup.add(mesh);
  segMeshes.push(mesh);
}

// Tip spark particle
const sparkGeo = new THREE.SphereGeometry(0.02, 6, 6);
const sparkMat = new THREE.MeshBasicMaterial({ color: 0xffaa44 });
const spark = new THREE.Mesh(sparkGeo, sparkMat);
scene.add(spark);

function updateWhipMesh() {
  // Handle
  handle.position.copy(points[0].pos);
  const dir1 = new THREE.Vector3().subVectors(points[1].pos, points[0].pos).normalize();
  handle.quaternion.setFromUnitVectors(new THREE.Vector3(0, -1, 0), dir1);

  // Segments
  for (let i = 0; i < SEGMENTS - 1; i++) {
    const mid = new THREE.Vector3().addVectors(points[i].pos, points[i + 1].pos).multiplyScalar(0.5);
    const dir = new THREE.Vector3().subVectors(points[i + 1].pos, points[i].pos).normalize();
    segMeshes[i].position.copy(mid);
    segMeshes[i].quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), dir);
  }

  // Tip
  const tipPos = points[SEGMENTS - 1].pos;
  spark.position.copy(tipPos);

  // Tip light follows tip
  tipLight.position.copy(tipPos);

  // Calculate tip speed for spark intensity
  const tipVel = new THREE.Vector3().subVectors(
    points[SEGMENTS - 1].pos, points[SEGMENTS - 1].oldPos
  ).length() * 60;
  const intensity = Math.min(tipVel * 0.5, 5);
  tipLight.intensity = intensity;
  sparkMat.opacity = Math.min(tipVel * 0.3, 1);
  spark.scale.setScalar(0.5 + tipVel * 0.1);
}

// ── Dust Particles ──
const DUST_COUNT = 300;
const dustGeo = new THREE.BufferGeometry();
const dustPositions = new Float32Array(DUST_COUNT * 3);
const dustSizes = new Float32Array(DUST_COUNT);
for (let i = 0; i < DUST_COUNT; i++) {
  dustPositions[i * 3] = (Math.random() - 0.5) * 10;
  dustPositions[i * 3 + 1] = Math.random() * 8 - 2;
  dustPositions[i * 3 + 2] = (Math.random() - 0.5) * 10;
  dustSizes[i] = Math.random() * 3 + 1;
}
dustGeo.setAttribute('position', new THREE.BufferAttribute(dustPositions, 3));
dustGeo.setAttribute('size', new THREE.BufferAttribute(dustSizes, 1));

const dustMat = new THREE.PointsMaterial({
  color: 0x8899aa,
  size: 0.03,
  transparent: true,
  opacity: 0.3,
  sizeAttenuation: true,
});
const dust = new THREE.Points(dustGeo, dustMat);
scene.add(dust);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const dt = clock.getDelta();

  // Sub-steps for stability
  const steps = 3;
  for (let s = 0; s < steps; s++) {
    simulate(dt / steps);
  }

  updateWhipMesh();

  // Animate dust
  const positions = dust.geometry.attributes.position.array;
  for (let i = 0; i < DUST_COUNT; i++) {
    positions[i * 3 + 1] += dt * 0.05;
    if (positions[i * 3 + 1] > 6) positions[i * 3 + 1] = -2;
  }
  dust.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What this does

- **Physics-based whip simulation** using Verlet integration with 60 chained segments and constraint solving — each segment follows the one before it with realistic lag and gravity.

- **Tapered geometry** — segments start thick near the handle (~0.045 radius) and shrink to nearly needle-thin (~0.003) at the tip, mimicking a real bullwhip's profile.

- **Animated handle** — the root point moves in a sweeping circular arc, sending waves of motion down the lash. The whip cracks as the wave accelerates toward the tip.

- **Tip spark & light** — a small glowing sphere and point light follow the whip tip, with intensity driven by the tip's velocity, creating a "sonic boom" visual at the crack.

- **Atmosphere** — fog, floating dust particles, rim lighting, and a dark ground plane give it a cinematic feel.

- **Orbit controls** — drag to rotate the camera around the scene.

