}
const treePositions=[[-8,6,1.2],[10,-4,0.9],[-6,-8,1.5],[12,8,1.1],[-14,2,1.3],[7,-10,0.8],[-10,-5,1.0],[15,3,1.4],[-5,12,1.1],[9,10,0.95],[-13,-10,1.35],[4,-14,1.05],[-8,14,1.2],[14,-8,1.15],[-16,0,1.3]];
treePositions.forEach(([x,z,s])=>scene.add(makeTree(x,z,s)));

