```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Wreath</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.015);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.05;

// --- Lighting ---
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-5, 2, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6644, 1.5, 20);
rimLight.position.set(0, -4, -5);
scene.add(rimLight);

// --- Wreath Group ---
const wreath = new THREE.Group();
scene.add(wreath);

const RING_RADIUS = 4;
const TUBE_RADIUS = 0.6;

// --- Main torus ring ---
const torusGeo = new THREE.TorusGeometry(RING_RADIUS, TUBE_RADIUS, 32, 80);
const torusMat = new THREE.MeshStandardMaterial({
  color: 0x2d5a27,
  roughness: 0.8,
  metalness: 0.0,
});
const torus = new THREE.Mesh(torusGeo, torusMat);
torus.rotation.x = Math.PI / 2;
torus.castShadow = true;
wreath.add(torus);

// --- Leaves (small cones arranged around the ring) ---
const leafGeo = new THREE.ConeGeometry(0.18, 0.5, 5);
const leafMats = [
  new THREE.MeshStandardMaterial({ color: 0x228B22, roughness: 0.7 }),
  new THREE.MeshStandardMaterial({ color: 0x2d8a2d, roughness: 0.7 }),
  new THREE.MeshStandardMaterial({ color: 0x1a6e1a, roughness: 0.7 }),
  new THREE.MeshStandardMaterial({ color: 0x33a033, roughness: 0.7 }),
  new THREE.MeshStandardMaterial({ color: 0x4a7a3a, roughness: 0.8 }),
];

const LEAF_COUNT = 300;
for (let i = 0; i < LEAF_COUNT; i++) {
  const angle = (i / LEAF_COUNT) * Math.PI * 2 + (Math.random() - 0.5) * 0.15;
  const mat = leafMats[Math.floor(Math.random() * leafMats.length)];
  const leaf = new THREE.Mesh(leafGeo, mat);

  const r = RING_RADIUS + (Math.random() - 0.5) * TUBE_RADIUS * 1.2;
  const spread = (Math.random() - 0.5) * TUBE_RADIUS * 0.8;

  leaf.position.set(
    Math.cos(angle) * r,
    spread,
    Math.sin(angle) * r
  );

  leaf.rotation.set(
    (Math.random() - 0.5) * 0.8,
    angle + Math.PI / 2 + (Math.random() - 0.5) * 0.5,
    (Math.random() - 0.5) * 0.6
  );

  const s = 0.6 + Math.random() * 0.8;
  leaf.scale.set(s, s * (0.7 + Math.random() * 0.6), s);
  leaf.castShadow = true;
  wreath.add(leaf);
}

// --- Pine needle clusters ---
const needleGeo = new THREE.SphereGeometry(0.25, 6, 5);
const needleMat = new THREE.MeshStandardMaterial({ color: 0x1e6b1e, roughness: 0.9 });

for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const cluster = new THREE.Mesh(needleGeo, needleMat);
  const r = RING_RADIUS + (Math.random() - 0.5) * 0.5;
  cluster.position.set(
    Math.cos(angle) * r,
    (Math.random() - 0.5) * 0.4,
    Math.sin(angle) * r
  );
  cluster.scale.set(
    0.8 + Math.random() * 0.6,
    0.5 + Math.random() * 0.4,
    0.8 + Math.random() * 0.6
  );
  cluster.castShadow = true;
  wreath.add(cluster);
}

// --- Red berries ---
const berryGeo = new THREE.SphereGeometry(0.1, 8, 8);
const berryMat = new THREE.MeshStandardMaterial({
  color: 0xcc2222,
  roughness: 0.3,
  metalness: 0.1,
  emissive: 0x330000,
});

for (let i = 0; i < 45; i++) {
  const angle = Math.random() * Math.PI * 2;
  const berry = new THREE.Mesh(berryGeo, berryMat);
  const r = RING_RADIUS + (Math.random() - 0.5) * TUBE_RADIUS * 0.6;
  berry.position.set(
    Math.cos(angle) * r,
    (Math.random() - 0.5) * TUBE_RADIUS * 0.5,
    Math.sin(angle) * r
  );
  const s = 0.6 + Math.random() * 0.8;
  berry.scale.setScalar(s);
  berry.castShadow = true;
  wreath.add(berry);
}

// --- Golden accents / small baubles ---
const goldGeo = new THREE.SphereGeometry(0.12, 8, 8);
const goldMat = new THREE.MeshStandardMaterial({
  color: 0xffd700,
  roughness: 0.2,
  metalness: 0.8,
  emissive: 0x443300,
});

for (let i = 0; i < 12; i++) {
  const angle = Math.random() * Math.PI * 2;
  const bauble = new THREE.Mesh(goldGeo, goldMat);
  const r = RING_RADIUS + (Math.random() - 0.5) * 0.3;
  bauble.position.set(
    Math.cos(angle) * r,
    (Math.random() - 0.5) * 0.3,
    Math.sin(angle) * r
  );
  bauble.scale.setScalar(0.8 + Math.random() * 0.5);
  bauble.castShadow = true;
  wreath.add(bauble);
}

// --- Ribbon bow at bottom ---
const ribbonMat = new THREE.MeshStandardMaterial({
  color: 0xcc1111,
  roughness: 0.5,
  metalness: 0.1,
});

function createBowLoop(side) {
  const shape = new THREE.Shape();
  shape.ellipse(0, 0, 0.5, 0.7, 0, Math.PI, 0, false);
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: 0.08, bevelEnabled: true, bevelSize: 0.03, bevelThickness: 0.02,
  });
  const mesh = new THREE.Mesh(geo, ribbonMat);
  mesh.position.set(side * 0.35, 0, 0.1);
  mesh.rotation.set(0.3, 0, side * 0.4);
  mesh.castShadow = true;
  return mesh;
}

wreath.add(createBowLoop(-1));
wreath.add(createBowLoop(1));

// Bow center knot
const knotGeo = new THREE.SphereGeometry(0.2, 8, 8);
const knot = new THREE.Mesh(knotGeo, ribbonMat);
knot.position.set(0, 0, 0.15);
knot.scale.set(1, 0.8, 0.6);
wreath.add(knot);

// Ribbon tails
for (let side of [-1, 1]) {
  const tailShape = new THREE.Shape();
  tailShape.moveTo(0, 0);
  tailShape.quadraticCurveTo(side * 0.15, -0.6, side * 0.08, -1.2);
  tailShape.lineTo(side * 0.25, -1.2);
  tailShape.quadraticCurveTo(side * 0.3, -0.6, 0.15, 0);
  tailShape.closePath();

  const tailGeo = new THREE.ExtrudeGeometry(tailShape, {
    depth: 0.05, bevelEnabled: false,
  });
  const tail = new THREE.Mesh(tailGeo, ribbonMat);
  tail.position.set(side * 0.15, 0, 0.1);
  tail.rotation.z = side * 0.15;
  tail.castShadow = true;
  wreath.add(tail);
}

// --- Holly leaves at bow ---
const hollyGeo = new THREE.SphereGeometry(0.22, 6, 4);
const hollyMat = new THREE.MeshStandardMaterial({ color: 0x1a7a1a, roughness: 0.6 });
for (let side of [-1, 1]) {
  const holly = new THREE.Mesh(hollyGeo, hollyMat);
  holly.position.set(side * 0.5, 0.15, 0.15);
  holly.scale.set(1.2, 0.6, 0.8);
  holly.rotation.z = side * 0.5;
  wreath.add(holly);
}

// --- Snowflakes (tiny particles) ---
const snowGeo = new THREE.BufferGeometry();
const snowCount = 400;
const snowPos = new Float32Array(snowCount * 3);
for (let i = 0; i < snowCount * 3; i += 3) {
  snowPos[i] = (Math.random() - 0.5) * 30;
  snowPos[i + 1] = (Math.random() - 0.5) * 20;
  snowPos[i + 2] = (Math.random() - 0.5) * 20;
}
snowGeo.setAttribute('position', new THREE.BufferAttribute(snowPos, 3));
const snowMat = new THREE.PointsMaterial({
  color: 0xffffff, size: 0.06, transparent: true, opacity: 0.7,
});
const snow = new THREE.Points(snowGeo, snowMat);
scene.add(snow);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  wreath.rotation.y = Math.sin(t * 0.3) * 0.15;
  wreath.position.y = Math.sin(t * 0.5) * 0.2;

  // Snow drift
  const positions = snow.geometry.attributes.position.array;
  for (let i = 1; i < positions.length; i += 3) {
    positions[i] -= 0.005;
    if (positions[i] < -10) positions[i] = 10;
  }
  snow.geometry.attributes.position.needsUpdate = true;
  snow.rotation.y = t * 0.02;

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
