</head>
<body>
  <div id="info">🔧 Drag to orbit &middot; Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──────────────────────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

    // ── Camera ─────────────────────────────────────────────
    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 5);

    // ── Renderer ───────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.target.set(0, 0, 0);

    // ── Lighting ───────────────────────────────────────────
    const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffffff, 2.5);
    dirLight.position.set(5, 8, 4);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    dirLight.shadow.camera.near = 1;
    dirLight.shadow.camera.far = 20;
    dirLight.shadow.camera.left = -5;
    dirLight.shadow.camera.right = 5;
    dirLight.shadow.camera.top = 5;
    dirLight.shadow.camera.bottom = -5;
    scene.add(dirLight);

    const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
    fillLight.position.set(-4, 2, -3);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xff6633, 1.0, 15);
    rimLight.position.set(-3, 1, 4);
    scene.add(rimLight);

    // ── Ground ─────────────────────────────────────────────
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(30, 30),
      new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 0.9 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -1.8;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Wrench Materials ──────────────────────────────────
    const steelMat = new THREE.MeshStandardMaterial({
      color: 0xaaaaaa,
      metalness: 0.9,
      roughness: 0.25,
    });

    const darkSteelMat = new THREE.MeshStandardMaterial({
      color: 0x666666,
      metalness: 0.95,
      roughness: 0.15,
    });

    // ── Build Wrench ──────────────────────────────────────
    const wrench = new THREE.Group();

    // --- Handle ---
    const handleGeo = new THREE.CylinderGeometry(0.14, 0.14, 3.2, 24);
    const handle = new THREE.Mesh(handleGeo, steelMat);
    handle.castShadow = true;
    wrench.add(handle);

    // Handle grip ridges
    for (let i = 0; i < 12; i++) {
      const ridgeGeo = new THREE.TorusGeometry(0.155, 0.012, 8, 24);
      const ridge = new THREE.Mesh(ridgeGeo, darkSteelMat);
      ridge.position.y = -1.2 + i * 0.2;
      ridge.rotation.x = Math.PI / 2;
      ridge.castShadow = true;
      wrench.add(ridge);
    }

    // Handle end cap (flat bottom)
    const capGeo = new THREE.CylinderGeometry(0.16, 0.14, 0.06, 24);
    const cap = new THREE.Mesh(capGeo, darkSteelMat);
    cap.position.y = -1.63;
    cap.castShadow = true;
    wrench.add(cap);

    // Ring at top of handle
    const ringGeo = new THREE.TorusGeometry(0.22, 0.035, 12, 24);
    const ring = new THREE.Mesh(ringGeo, darkSteelMat);
    ring.position.y = 1.65;
    ring.rotation.x = Math.PI / 2;
    ring.castShadow = true;
    wrench.add(ring);

    // --- Open Head (C-shape) ---
    const headY = 2.0;
    const jawLength = 0.9;
    const jawWidth = 0.12;
    const jawHeight = 0.18;
    const gapSize = 0.4;
    const crossbarWidth = 0.6;
    const crossbarThickness = 0.14;

    // Left jaw
    const jawGeo = new THREE.BoxGeometry(jawWidth, jawHeight, jawLength);
    const leftJaw = new THREE.Mesh(jawGeo, steelMat);
    leftJaw.position.set(-jawWidth / 2 - gapSize / 2, headY, -jawLength / 2 + 0.15);
    leftJaw.castShadow = true;
    wrench.add(leftJaw);

    // Right jaw
    const rightJaw = new THREE.Mesh(jawGeo, steelMat);
    rightJaw.position.set(jawWidth / 2 + gapSize / 2, headY, -jawLength / 2 + 0.15);
    rightJaw.castShadow = true;
    wrench.add(rightJaw);

    // Crossbar (connects jaws at back)
    const crossbarGeo = new THREE.BoxGeometry(crossbarWidth, crossbarThickness, jawLength - 0.1);
    const crossbar = new THREE.Mesh(crossbarGeo, steelMat);
    crossbar.position.set(0, headY, -jawLength / 2 + 0.15);
    crossbar.castShadow = true;
    wrench.add(crossbar);

    // Inner jaw faces (the gripping surfaces) — slightly darker
    const innerJawGeo = new THREE.BoxGeometry(0.02, jawHeight - 0.02, jawLength - 0.15);
    const innerMat = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.95, roughness: 0.1 });

    const leftInner = new THREE.Mesh(innerJawGeo, innerMat);
    leftInner.position.set(-gapSize / 2 + 0.01, headY, -jawLength / 2 + 0.15);
    wrench.add(leftInner);

    const rightInner = new THREE.Mesh(innerJawGeo, innerMat);
    rightInner.position.set(gapSize / 2 - 0.01, headY, -jawLength / 2 + 0.15);
    wrench.add(rightInner);

    // Outer back lip (the closed side of the C)
    const lipGeo = new THREE.BoxGeometry(crossbarWidth + 0.08, jawHeight + 0.04, 0.08);
    const lip = new THREE.Mesh(lipGeo, darkSteelMat);
    lip.position.set(0, headY, -jawLength + 0.25);
    lip.castShadow = true;
    wrench.add(lip);

    // Transition from handle to head (shoulder)
    const shoulderGeo = new THREE.CylinderGeometry(0.32, 0.14, 0.2, 24);
    const shoulder = new THREE.Mesh(shoulderGeo, darkSteelMat);
    shoulder.position.y = 1.7;
    shoulder.castShadow = true;
    wrench.add(shoulder);

    // --- Closed Head (box end) on the other side ---
    const boxEndY = -2.0;
    const boxSize = 0.38;

    // Hexagonal socket
    const hexGeo = new THREE.CylinderGeometry(boxSize, boxSize, 0.35, 6);
    const hexEnd = new THREE.Mesh(hexGeo, steelMat);
    hexEnd.position.y = boxEndY;
    hexEnd.castShadow = true;
    wrench.add(hexEnd);

    // Socket hole
    const holeGeo = new THREE.CylinderGeometry(boxSize * 0.55, boxSize * 0.55, 0.36, 6);
    const holeMat = new THREE.MeshStandardMaterial({ color: 0x222222, metalness: 0.5, roughness: 0.8 });
    const hole = new THREE.Mesh(holeGeo, holeMat);
    hole.position.y = boxEndY;
    wrench.add(hole);

    // Transition at bottom
    const bottomShoulderGeo = new THREE.CylinderGeometry(0.32, 0.14, 0.2, 24);
    const bottomShoulder = new THREE.Mesh(bottomShoulderGeo, darkSteelMat);
    bottomShoulder.position.y = -1.7;
    bottomShoulder.castShadow = true;
    wrench.add(bottomShoulder);

    // Center the wrench
    wrench.rotation.z = Math.PI / 2;
    scene.add(wrench);

    // ── Animation ─────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle floating rotation
      wrench.rotation.x = Math.sin(t * 0.5) * 0.15;
      wrench.rotation.z = Math.PI / 2 + Math.cos(t * 0.3) * 0.1;
      wrench.position.y = Math.sin(t * 0.8) * 0.15;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
