    camera.position.set(4, 3, 6);

    // ── Renderer ───────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.target.set(0, 1.5, 0);

    // ── Lights ─────────────────────────────────────────────
    const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    dirLight.position.set(5, 10, 7);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(1024, 1024);
    dirLight.shadow.camera.near = 1;
    dirLight.shadow.camera.far = 25;
    dirLight.shadow.camera.left = -6;
    dirLight.shadow.camera.right = 6;
    dirLight.shadow.camera.top = 6;
    dirLight.shadow.camera.bottom = -6;
    scene.add(dirLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 0.8);
    rimLight.position.set(-4, 3, -5);
    scene.add(rimLight);

    const pointLight = new THREE.PointLight(0xff6644, 1.5, 15);
    pointLight.position.set(-3, 5, 3);
    scene.add(pointLight);

    // ── Ground ─────────────────────────────────────────────
    const groundGeo = new THREE.PlaneGeometry(30, 30);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x22223a,
      roughness: 0.85,
      metalness: 0.1,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.01;
    ground.receiveShadow = true;
    scene.add(ground);

    // Grid helper
    const grid = new THREE.GridHelper(20, 40, 0x333355, 0x222244);
    grid.position.y = 0.005;
    scene.add(grid);

    // ── Yoyo Construction ──────────────────────────────────
    const yoyoGroup = new THREE.Group();
    scene.add(yoyoGroup);

    // Main body material
    const bodyMat = new THREE.MeshStandardMaterial({
      color: 0xcc2233,
      roughness: 0.25,
      metalness: 0.6,
    });

    const bodyMatDark = new THREE.MeshStandardMaterial({
      color: 0x881122,
      roughness: 0.3,
      metalness: 0.5,
    });

    const axleMat = new THREE.MeshStandardMaterial({
      color: 0xcccccc,
      roughness: 0.15,
      metalness: 0.9,
    });

    const ringMat = new THREE.MeshStandardMaterial({
      color: 0xffcc00,
      roughness: 0.2,
      metalness: 0.8,
    });

    const stringMat = new THREE.LineBasicMaterial({ color: 0xeeeeee });

    // Yoyo dimensions
    const discRadius = 0.7;
    const discHeight = 0.08;
    const axleRadius = 0.035;
    const axleLength = 0.22;

    // Two main discs
    const discGeo = new THREE.CylinderGeometry(discRadius, discRadius, discHeight, 48);
    const topDisc = new THREE.Mesh(discGeo, bodyMat);
    topDisc.position.y = discHeight / 2;
    topDisc.castShadow = true;
    yoyoGroup.add(topDisc);

    const bottomDisc = new THREE.Mesh(discGeo, bodyMat);
    bottomDisc.position.y = -discHeight / 2;
    bottomDisc.castShadow = true;
    yoyoGroup.add(bottomDisc);

    // Decorative rings on each disc face
    const ringGeo1 = new THREE.TorusGeometry(discRadius * 0.72, 0.012, 8, 48);
    const ring1 = new THREE.Mesh(ringGeo1, ringMat);
    ring1.rotation.x = Math.PI / 2;
    ring1.position.y = discHeight / 2 + 0.001;
    yoyoGroup.add(ring1);

    const ring2 = new THREE.Mesh(ringGeo1, ringMat);
    ring2.rotation.x = Math.PI / 2;
    ring2.position.y = -discHeight / 2 - 0.001;
    yoyoGroup.add(ring2);

    // Inner decorative ring
    const ringGeo2 = new THREE.TorusGeometry(discRadius * 0.42, 0.008, 8, 48);
    const ring3 = new THREE.Mesh(ringGeo2, ringMat);
    ring3.rotation.x = Math.PI / 2;
    ring3.position.y = discHeight / 2 + 0.001;
    yoyoGroup.add(ring3);

    const ring4 = new THREE.Mesh(ringGeo2, ringMat);
    ring4.rotation.x = Math.PI / 2;
    ring4.position.y = -discHeight / 2 - 0.001;
    yoyoGroup.add(ring4);

    // Center dot
    const dotGeo = new THREE.SphereGeometry(0.04, 16, 16);
    const dotMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.1, metalness: 0.3 });
    const dotTop = new THREE.Mesh(dotGeo, dotMat);
    dotTop.position.y = discHeight / 2 + 0.002;
    yoyoGroup.add(dotTop);
    const dotBot = new THREE.Mesh(dotGeo, dotMat);
    dotBot.position.y = -discHeight / 2 - 0.002;
    yoyoGroup.add(dotBot);

    // Groove between discs (dark band)
    const grooveGeo = new THREE.TorusGeometry(discRadius * 0.55, 0.018, 8, 48);
    const groove = new THREE.Mesh(grooveGeo, bodyMatDark);
    yoyoGroup.add(groove);

    // Axle
    const axleGeo = new THREE.CylinderGeometry(axleRadius, axleRadius, axleLength, 16);
    const axle = new THREE.Mesh(axleGeo, axleMat);
    axle.rotation.x = Math.PI / 2;
    yoyoGroup.add(axle);

    // String — we'll use a series of small segments so it can curve
    const stringSegments = 60;
    const stringLength = 6;
    const stringPoints = [];
    for (let i = 0; i <= stringSegments; i++) {
      const t = i / stringSegments;
      stringPoints.push(new THREE.Vector3(0, t * stringLength, 0));
    }
    const stringGeo = new THREE.BufferGeometry().setFromPoints(stringPoints);
    const stringLine = new THREE.Line(stringGeo, stringMat);
    yoyoGroup.add(stringLine);

    // Small loop at top of string
    const loopGeo = new THREE.TorusGeometry(0.06, 0.008, 8, 16);
    const loopMat = new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.5 });
    const loop = new THREE.Mesh(loopGeo, loopMat);
    loop.rotation.x = Math.PI / 2;
    loop.position.y = stringLength;
    yoyoGroup.add(loop);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Spin the yoyo
      yoyoGroup.rotation.z = t * 8;

      // Bob up and down the string
      const bobAmount = 1.8;
      const bobSpeed = 1.2;
      const yOffset = Math.sin(t * bobSpeed) * bobAmount + 2.5;

      yoyoGroup.position.y = yOffset;

      // Update string: top anchor is fixed, bottom follows yoyo
      const positions = stringLine.geometry.attributes.position.array;
      const anchorY = 8; // fixed top point
      const yoyoTopY = yOffset + discHeight / 2 + 0.06; // point where string meets yoyo

      for (let i = 0; i <= stringSegments; i++) {
        const u = i / stringSegments;
        const y = THREE.MathUtils.lerp(yoyoTopY, anchorY, u);

        // Add slight curve (catenary-like sag)
        const sag = Math.sin(u * Math.PI) * 0.08;
        positions[i * 3] = sag;     // x
        positions[i * 3 + 1] = y;   // y
        positions[i * 3 + 2] = 0;   // z
      }
      stringLine.geometry.attributes.position.needsUpdate = true;

      // Loop follows anchor
      loop.position.y = anchorY;

      // Subtle wobble
      yoyoGroup.rotation.x = Math.sin(t * 2.1) * 0.05;
      yoyoGroup.rotation.y = Math.cos(t * 1.7) * 0.05;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
