<div id="info">🏛 Ziggurat — drag to orbit · scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── Scene ── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1420);
scene.fog = new THREE.FogExp2(0x1a1420, 0.012);

/* ── Camera ── */
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(18, 14, 22);

/* ── Renderer ── */
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ── Controls ── */
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.target.set(0, 5, 0);
controls.minDistance = 8;
controls.maxDistance = 60;
controls.maxPolarAngle = Math.PI / 2.05;

/* ── Lights ── */
const ambient = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xffc87a, 2.5);
sun.position.set(15, 25, 10);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 60;
sun.shadow.camera.left = -20;
sun.shadow.camera.right = 20;
sun.shadow.camera.top = 20;
sun.shadow.camera.bottom = -20;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8899cc, 0.6);
fill.position.set(-10, 8, -12);
scene.add(fill);

const rim = new THREE.PointLight(0xff6633, 1.5, 40);
rim.position.set(-8, 3, -10);
scene.add(rim);

/* ── Materials ── */
const brickColors = [0xc4a87a, 0xb89a6a, 0xc9b08a, 0xb09060, 0xd4b88c, 0xa88858];

function makeBrickMat(color) {
  return new THREE.MeshStandardMaterial({
    color,
    roughness: 0.85,
    metalness: 0.05,
  });
}

/* ── Ziggurat tiers ── */
const tiers = [
  { w: 16, h: 2.4, d: 16 },
  { w: 13, h: 2.2, d: 13 },
  { w: 10, h: 2.0, d: 10 },
  { w: 7,  h: 1.8, d: 7  },
  { w: 4,  h: 1.6, d: 4  },
  { w: 2,  h: 1.4, d: 2  },
];

let y = 0;
const tierMeshes = [];

tiers.forEach((t, i) => {
  const geo = new THREE.BoxGeometry(t.w, t.h, t.d);
  const mat = makeBrickMat(brickColors[i % brickColors.length]);
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.y = y + t.h / 2;
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  scene.add(mesh);
  tierMeshes.push(mesh);

  /* thin vertical "brick line" edges for each tier */
  const edgeGeo = new THREE.EdgesGeometry(geo);
  const edgeMat = new THREE.LineBasicMaterial({ color: 0x3a2a18, transparent: true, opacity: 0.25 });
  const edges = new THREE.LineSegments(edgeGeo, edgeMat);
  mesh.add(edges);

  y += t.h;
});

/* ── Staircase on one face ── */
function addStaircase() {
  const stairWidth = 3;
  const steps = tiers.length;
  let sy = 0;

  tiers.forEach((t, i) => {
    const stepH = t.h;
    const stepD = (t.d - (tiers[i + 1]?.d ?? 0)) / 2;
    const geo = new THREE.BoxGeometry(stairWidth, stepH * 0.6, stepD);
    const mat = makeBrickMat(brickColors[i % brickColors.length]);
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.set(0, sy + stepH * 0.3, t.d / 2 - stepD / 2);
    mesh.castShadow = true;
    mesh.receiveShadow = true;
    scene.add(mesh);
    sy += stepH;
  });
}
addStaircase();

/* ── Ground ── */
const groundGeo = new THREE.CircleGeometry(50, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x3a3020, roughness: 1, metalness: 0 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* ── Small decorative pillars at base corners ── */
const pillarGeo = new THREE.CylinderGeometry(0.25, 0.3, 3, 8);
const pillarMat = makeBrickMat(0xb89a6a);
const baseW = tiers[0].w / 2;
const baseD = tiers[0].d / 2;
[[-1,-1],[1,-1],[1,1],[-1,1]].forEach(([sx, sz]) => {
  const p = new THREE.Mesh(pillarGeo, pillarMat);
  p.position.set(sx * (baseW + 1.2), 1.5, sz * (baseD + 1.2));
  p.castShadow = true;
  scene.add(p);
});

/* ── Stars (tiny points) ── */
const starCount = 600;
const starGeo = new THREE.BufferGeometry();
const starPos = new Float32Array(starCount * 3);
for (let i = 0; i < starCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.random() * Math.PI * 0.45;
  const r = 80 + Math.random() * 40;
  starPos[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
  starPos[i * 3 + 1] = r * Math.cos(phi) + 10;
  starPos[i * 3 + 2] = r * Math.sin(phi) * Math.sin(theta);
}
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
const starMat = new THREE.PointsMaterial({ color: 0xffeedd, size: 0.3, sizeAttenuation: true });
scene.add(new THREE.Points(starGeo, starMat));

/* ── Animate ── */
function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
