dir.position.set(3, 6, 4);
dir.castShadow = true;
dir.shadow.mapSize.set(1024, 1024);
scene.add(dir);
const rim = new THREE.DirectionalLight(0x4488ff, 1.0);
rim.position.set(-4, 2, -3);
scene.add(rim);

const ZIP_HEIGHT = 4;
const TOOTH_COUNT = 30;
const GAP = ZIP_HEIGHT / TOOTH_COUNT;
const FABRIC_W = 1.2;
const FABRIC_THICK = 0.04;

const fabricMat = new THREE.MeshStandardMaterial({ color: 0x2a3a5c, roughness: 0.7, metalness: 0.1 });
const toothMat = new THREE.MeshStandardMaterial({ color: 0xc0c0c0, roughness: 0.2, metalness: 0.9 });
const sliderMat = new THREE.MeshStandardMaterial({ color: 0xb0b0b0, roughness: 0.15, metalness: 0.95 });
const pullMat = new THREE.MeshStandardMaterial({ color: 0xd4a050, roughness: 0.4, metalness: 0.6 });

