const fabricGeo = new THREE.BoxGeometry(FABRIC_W, ZIP_HEIGHT + 0.6, FABRIC_THICK);

const leftFabric = new THREE.Mesh(fabricGeo, fabricMat);
leftFabric.position.set(-FABRIC_W / 2 - 0.08, 0, 0);
leftFabric.castShadow = true;
scene.add(leftFabric);

const rightFabric = new THREE.Mesh(fabricGeo, fabricMat);
rightFabric.position.set(FABRIC_W / 2 + 0.08, 0, 0);
rightFabric.castShadow = true;
scene.add(rightFabric);

