const toothGeo = new THREE.BoxGeometry(0.08, 0.06, 0.18);
const teethLeft = [], teethRight = [];

for (let i = 0; i < TOOTH_COUNT; i++) {
  const y = -ZIP_HEIGHT / 2 + (i + 0.5) * GAP;

  const tl = new THREE.Mesh(toothGeo, toothMat);
  tl.position.set(-0.12, y, 0);
  tl.castShadow = true;
  scene.add(tl);
  teethLeft.push(tl);

  const tr = new THREE.Mesh(toothGeo, toothMat);
  tr.position.set(0.12, y, 0);
  tr.castShadow = true;
  scene.add(tr);
  teethRight.push(tr);
}

// Slider assembly
const sliderGroup = new THREE.Group();

const sliderBody = new THREE.Mesh(
  new THREE.BoxGeometry(0.38, 0.22, 0.26),
  sliderMat
);
sliderBody.castShadow = true;
sliderGroup.add(sliderBody);

const sliderBottom = new THREE.Mesh(
  new THREE.BoxGeometry(0.30, 0.06, 0.20),
  sliderMat
);
sliderBottom.position.y = -0.14;
sliderGroup.add(sliderBottom);

const sliderTop = new THREE.Mesh(
  new THREE.BoxGeometry(0.30, 0.06, 0.20),
  sliderMat
);
sliderTop.position.y = 0.14;
sliderGroup.add(sliderTop);

// Pull tab loop
const pullGeo = new THREE.TorusGeometry(0.10, 0.02, 12, 20);
const pullTab = new THREE.Mesh(pullGeo, pullMat);
pullTab.position.set(0.22, 0.12, 0);
pullTab.rotation.y = Math.PI / 2;
sliderGroup.add(pullTab);

// Small ring connector
const ringGeo = new THREE.CylinderGeometry(0.025, 0.025, 0.08, 12);
const ring = new THREE.Mesh(ringGeo, sliderMat);
ring.position.set(0.18, 0.12, 0);
ring.rotation.z = Math.PI / 2;
sliderGroup.add(ring);

scene.add(sliderGroup);

// State
let sliderY = ZIP_HEIGHT / 2 + 0.3;
let targetY = ZIP_HEIGHT / 2 + 0.3;
let zipping = false;
let zipDirection = -1;

renderer.domElement.addEventListener('click', () => {
  if (sliderY > ZIP_HEIGHT / 2 - 0.3) {
    targetY = -ZIP_HEIGHT / 2 - 0.3;
    zipDirection = -1;
  } else {
    targetY = ZIP_HEIGHT / 2 + 0.3;
    zipDirection = 1;
  }
});

// Fabric deformation based on slider position
function updateFabric() {
  const closeProgress = THREE.MathUtils.clamp(
    1 - (sliderY + ZIP_HEIGHT / 2) / ZIP_HEIGHT, 0, 1
  );
  const bend = closeProgress * 0.15;

  for (let i = 0; i < TOOTH_COUNT; i++) {
    const t = i / TOOTH_COUNT;
    const toothY = -ZIP_HEIGHT / 2 + (i + 0.5) * GAP;
    const active = toothY < sliderY;
    const dist = Math.abs(toothY - sliderY);
    const pull = active && dist < 0.5 ? (1 - dist / 0.5) * 0.12 : 0;

    teethLeft[i].position.x = -0.12 + pull + bend * (1 - t) * 0.5;
    teethRight[i].position.x = 0.12 - pull - bend * (1 - t) * 0.5;
  }

  // Bend fabric strips
  leftFabric.position.x = -FABRIC_W / 2 - 0.08 + bend * 0.3;
  rightFabric.position.x = FABRIC_W / 2 + 0.08 - bend * 0.3;

  leftFabric.rotation.z = bend * 0.05;
  rightFabric.rotation.z = -bend * 0.05;
}

// Animate
function animate() {
  requestAnimationFrame(animate);

  sliderY += (targetY - sliderY) * 0.04;
  sliderGroup.position.y = sliderY;

  // Gentle idle sway
  sliderGroup.position.x = Math.sin(Date.now() * 0.001) * 0.005;
  sliderGroup.rotation.z = Math.sin(Date.now() * 0.0015) * 0.01;

  updateFabric();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This creates a fully interactive 3D zipper scene with:

- **Two fabric strips** (dark blue) on the left and right
- **30 interlocking metal teeth** along each strip that pull together as the slider passes
- **A metallic slider** with a body, top/bottom bars, and a gold pull ring
- **Click to zip/unzip** — the slider animates smoothly up and down
- **Fabric deformation** — teeth and fabric subtly bend and close together based on slider position
- **Cinematic lighting** with directional, ambient, and rim lights plus fog and ACES tone mapping
- **Idle sway** on the slider for a natural feel
